<?php
// Ensure clean output buffering for header() calls on this large file
if (!ob_get_level()) {
    ob_start();
}

// Configure session cookie for iframe compatibility (SameSite=Lax)
session_set_cookie_params([
    'lifetime' => 0,
    'path' => '/',
    'secure' => false,
    'httponly' => true,
    'samesite' => 'Lax'
]);
session_start();

// Prevent browser caching so JS changes take effect immediately
header('Cache-Control: no-store, no-cache, must-revalidate, max-age=0');
header('Pragma: no-cache');
header('Expires: 0');

// ============================================
// SUPER ADMIN AUTHENTICATION
// ============================================
define('ADMIN_PASSWORD', 'GL_Admin');

// Check for remember me cookie
if (!isset($_SESSION['admin_logged_in']) && isset($_COOKIE['admin_remember'])) {
    if ($_COOKIE['admin_remember'] === hash('sha256', ADMIN_PASSWORD . 'salt_key_2024')) {
        $_SESSION['admin_logged_in'] = true;
    }
}

// Handle login
if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['admin_login'])) {
    $inputPassword = $_POST['admin_password'] ?? '';
    
    if ($inputPassword === ADMIN_PASSWORD) {
        $_SESSION['admin_logged_in'] = true;
        
        // Set remember me cookie (30 days)
        if (isset($_POST['remember_me'])) {
            setcookie('admin_remember', hash('sha256', ADMIN_PASSWORD . 'salt_key_2024'), [
                'expires' => time() + (86400 * 30),
                'path' => '/',
                'secure' => false,
                'httponly' => true,
                'samesite' => 'Lax'
            ]);
        }
        
        header('Location: ' . $_SERVER['PHP_SELF']);
        exit;
    } else {
        $loginError = 'Invalid password. Please try again.';
    }
}

// Handle logout
if (isset($_GET['logout'])) {
    $_SESSION['admin_logged_in'] = false;
    setcookie('admin_remember', '', [
        'expires' => time() - 3600,
        'path' => '/',
        'secure' => false,
        'httponly' => true,
        'samesite' => 'Lax'
    ]);
    session_destroy();
    header('Location: ' . $_SERVER['PHP_SELF']);
    exit;
}

// Check if logged in
$isLoggedIn = isset($_SESSION['admin_logged_in']) && $_SESSION['admin_logged_in'] === true;

// Release session lock early so iframes/AJAX can access the session
// This is critical when Prompt Manager loads inside its own iframe
session_write_close();

// If not logged in, show login page
if (!$isLoggedIn) {
    showLoginPage($loginError ?? null);
    exit;
}

