    } catch(PDOException $e) {
        $dbError = $e->getMessage();
    }
}

// Handle AJAX requests
if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    header('Content-Type: application/json');
    
    $action = $_POST['action'] ?? '';
    
    // ============================================
    // BROWSE LOCALHOST DIRECTORIES - List subdirectories for folder picker
    // ============================================
    if ($action === 'browse_localhost_dirs') {
        $path = $_POST['path'] ?? '';
        
        // Default starting paths for Windows (Laragon)
        if (empty($path)) {
            $path = 'C:/laragon/www';
            if (!is_dir($path)) {
                $path = dirname(__FILE__);
            }
        }
        
        $realPath = realpath($path);
        if (!$realPath || !is_dir($realPath)) {
            echo json_encode(['success' => false, 'message' => 'Invalid directory path']);
            exit;
        }
        
        $realPath = str_replace('\\', '/', $realPath);
        $parent = str_replace('\\', '/', dirname($realPath));
        
        $dirs = [];
        $items = @scandir($realPath);
        if ($items !== false) {
            foreach ($items as $item) {
                if ($item === '.' || $item === '..') continue;
                $fullPath = $realPath . '/' . $item;
                if (is_dir($fullPath)) {
                    $dirs[] = [
                        'name' => $item,
                        'path' => str_replace('\\', '/', $fullPath)
                    ];
                }
            }
        }
        
        // Sort alphabetically
        usort($dirs, function($a, $b) { return strcasecmp($a['name'], $b['name']); });
        
        echo json_encode([
            'success' => true,
            'current' => $realPath,
            'parent' => ($parent !== $realPath) ? $parent : null,
            'dirs' => $dirs
        ]);
        exit;
    }

    // ============================================
    // DESIGN ENHANCER TOOL ORDER - Save
    // ============================================
    if ($action === 'save_tool_order') {
        $toolOrder = $_POST['tool_order'] ?? '';
        
        if ($pdo && $toolOrder) {
            try {
                // Clean up any duplicate rows first, keep only id=1
                $pdo->exec("DELETE FROM reporter_prompt_tool_order WHERE id != 1");
                
                // Use REPLACE INTO to reliably upsert the single row
                $stmt = $pdo->prepare("REPLACE INTO reporter_prompt_tool_order (id, tool_order) VALUES (1, ?)");
                $stmt->execute([$toolOrder]);
                
                echo json_encode(['success' => true, 'message' => 'Tool order saved']);
            } catch (PDOException $e) {
                echo json_encode(['success' => false, 'message' => $e->getMessage()]);
            }
        } else {
            echo json_encode(['success' => false, 'message' => 'Invalid data or no database connection']);
        }
        exit;
    }
    
    // ============================================
    // DESIGN ENHANCER TOOL ORDER - Load
    // ============================================
    if ($action === 'load_tool_order') {
        if ($pdo) {
            try {
                $stmt = $pdo->query("SELECT tool_order FROM reporter_prompt_tool_order WHERE id = 1 LIMIT 1");
                $row = $stmt->fetch();
                
                if ($row) {
                    echo json_encode(['success' => true, 'tool_order' => json_decode($row['tool_order'], true)]);
                } else {
                    // Return default order
                    echo json_encode(['success' => true, 'tool_order' => [
                        'fileUploadTool', 'exclusionTool', 'brandingTool', 'pagesCreatorTool',
                        'customInstructionsTool', 'styleTypesTool', 'designThemeTool', 'layoutTool',
