        }
        exit;
    }
    
    // Delete project
    if ($action === 'delete_project') {
        // Check database connection first
        if (!$pdo) {
            echo json_encode(['success' => false, 'message' => 'Database not connected. Please check your connection.']);
            exit;
        }
        
        $id = $_POST['id'] ?? '';
        
        if ($id) {
            try {
                $startTime = microtime(true);
                $stmt = $pdo->prepare("DELETE FROM reporter_prompt_projects WHERE id = ?");
                $stmt->execute([$id]);
                $operationTime = round((microtime(true) - $startTime) * 1000, 2);
                echo json_encode([
                    'success' => true,
                    'message' => 'Project deleted successfully!',
                    'operationTime' => $operationTime,
                    'operationType' => 'DELETE_PROJECT',
                    'connectionType' => $connectionType
                ]);
            } catch (Exception $e) {
                echo json_encode(['success' => false, 'message' => $e->getMessage()]);
            }
        } else {
            echo json_encode(['success' => false, 'message' => 'Project ID is required']);
        }
        exit;
    }
    
    // File upload
    if ($action === 'upload_files') {
        $uploadDir = 'uploads/';
        if (!is_dir($uploadDir)) {
            mkdir($uploadDir, 0777, true);
        }
        
        $uploadedFiles = [];
        
        if (isset($_FILES['files'])) {
            $files = $_FILES['files'];
            $fileCount = count($files['name']);
            
            for ($i = 0; $i < $fileCount; $i++) {
                if ($files['error'][$i] === UPLOAD_ERR_OK) {
                    $filename = basename($files['name'][$i]);
                    $filepath = $uploadDir . time() . '_' . $filename;
                    
                    if (move_uploaded_file($files['tmp_name'][$i], $filepath)) {
                        if ($pdo) {
                            $stmt = $pdo->prepare("INSERT INTO reporter_prompt_uploaded_files (filename, filepath, filesize, filetype) VALUES (?, ?, ?, ?)");
                            $stmt->execute([$filename, $filepath, $files['size'][$i], $files['type'][$i]]);
                        }
                        $uploadedFiles[] = [
                            'name' => $filename,
                            'path' => $filepath,
                            'size' => $files['size'][$i],
                            'type' => $files['type'][$i]
                        ];
                    }
                }
            }
        }
        
        echo json_encode(['success' => true, 'files' => $uploadedFiles]);
        exit;
    }
    
    // Static template file upload (Read the Application)
    if ($action === 'spt_upload_files') {
        $uploadDir = 'uploads/static_read/';
        if (!is_dir($uploadDir)) {
            mkdir($uploadDir, 0777, true);
        }
        
        $uploadedFiles = [];
        
        if (isset($_FILES['files'])) {
            $files = $_FILES['files'];
            $fileCount = count($files['name']);
            
            for ($i = 0; $i < $fileCount; $i++) {
                if ($files['error'][$i] === UPLOAD_ERR_OK) {
                    $filename = basename($files['name'][$i]);
                    $uniqueName = time() . '_' . mt_rand(1000, 9999) . '_' . $filename;
                    $filepath = $uploadDir . $uniqueName;
                    
                    if (move_uploaded_file($files['tmp_name'][$i], $filepath)) {
                        // Read file content for immediate use
                        $content = file_get_contents($filepath);
                        
                        $uploadedFiles[] = [
                            'name' => $filename,
                            'storedName' => $uniqueName,
                            'path' => $filepath,
                            'size' => $files['size'][$i],
                            'type' => $files['type'][$i],
                            'content' => $content
                        ];
                    }
                }
            }
        }
        
        echo json_encode(['success' => true, 'files' => $uploadedFiles]);
        exit;
    }
    
    // Get static template files
    if ($action === 'spt_get_files') {
        $uploadDir = 'uploads/static_read/';
        $files = [];
        
        if (is_dir($uploadDir)) {
            $items = scandir($uploadDir);
            foreach ($items as $item) {
                if ($item === '.' || $item === '..') continue;
                $filepath = $uploadDir . $item;
                if (is_file($filepath)) {
                    // Extract original filename (remove timestamp_rand_ prefix)
                    $originalName = preg_replace('/^\d+_\d+_/', '', $item);
                    $files[] = [
                        'name' => $originalName,
                        'storedName' => $item,
                        'path' => $filepath,
                        'size' => filesize($filepath),
                        'content' => file_get_contents($filepath)
                    ];
                }
            }
        }
        
        echo json_encode(['success' => true, 'files' => $files]);
        exit;
    }
    
    // Delete static template file
    if ($action === 'spt_delete_file') {
        $storedName = $_POST['storedName'] ?? '';
        $uploadDir = 'uploads/static_read/';
        $filepath = $uploadDir . basename($storedName);
        
        if ($storedName && file_exists($filepath)) {
            unlink($filepath);
            echo json_encode(['success' => true, 'message' => 'File removed']);
        } else {
            echo json_encode(['success' => false, 'message' => 'File not found']);
        }
        exit;
    }
    
    // Get uploaded files
    if ($action === 'get_files') {
        if ($pdo) {
            try {
                $stmt = $pdo->query("SELECT * FROM reporter_prompt_uploaded_files ORDER BY uploaded_at DESC");
                $files = $stmt->fetchAll();
                echo json_encode(['success' => true, 'files' => $files]);
            } catch (Exception $e) {
                echo json_encode(['success' => false, 'message' => $e->getMessage()]);
            }
        }
        exit;
    }
    
    // Delete file
    if ($action === 'delete_file') {
        $id = $_POST['id'] ?? '';
        
        if ($pdo && $id) {
            try {
                $startTime = microtime(true);
                $stmt = $pdo->prepare("SELECT filepath FROM reporter_prompt_uploaded_files WHERE id = ?");
                $stmt->execute([$id]);
                $file = $stmt->fetch();
                
                if ($file && file_exists($file['filepath'])) {
                    unlink($file['filepath']);
                }
                
                $stmt = $pdo->prepare("DELETE FROM reporter_prompt_uploaded_files WHERE id = ?");
                $stmt->execute([$id]);
                $operationTime = round((microtime(true) - $startTime) * 1000, 2);
                echo json_encode([
                    'success' => true, 
                    'message' => 'File deleted successfully!',
                    'operationTime' => $operationTime,
                    'operationType' => 'DELETE_FILE',
                    'connectionType' => $connectionType
                ]);
            } catch (Exception $e) {
                echo json_encode(['success' => false, 'message' => $e->getMessage()]);
            }
        }
        exit;
    }
    
    // ============================================
    // FOLDER BROWSER - List directories at a path (PHP server-side)
    // ============================================
    if ($action === 'list_folders') {
        $basePath = $_POST['path'] ?? '';
        
        // Default to common base paths if empty
        if (empty($basePath)) {
            $basePath = dirname(__FILE__); // Default to app directory
        }
        
        // Security: normalize and validate path
        $basePath = realpath($basePath);
        
        if (!$basePath || !is_dir($basePath)) {
            echo json_encode(['success' => false, 'message' => 'Invalid directory path']);
            exit;
        }
        
        $folders = [];
        $files_in_dir = [];
        
        try {
            $items = scandir($basePath);
            foreach ($items as $item) {
                if ($item === '.' || $item === '..') continue;
                
                $fullPath = $basePath . DIRECTORY_SEPARATOR . $item;
                
                if (is_dir($fullPath)) {
                    $folders[] = [
                        'name' => $item,
                        'path' => str_replace('\\', '/', $fullPath),
                        'hasSubdirs' => false // Will be checked lazily
                    ];
                }
            }
            
            // Sort folders alphabetically
            usort($folders, function($a, $b) {
                return strcasecmp($a['name'], $b['name']);
            });
            
            // Check which folders have subdirectories (for expand arrows)
            foreach ($folders as &$folder) {
                $subItems = @scandir($folder['path']);
                if ($subItems) {
                    foreach ($subItems as $sub) {
                        if ($sub !== '.' && $sub !== '..' && is_dir($folder['path'] . DIRECTORY_SEPARATOR . $sub)) {
                            $folder['hasSubdirs'] = true;
                            break;
                        }
                    }
                }
            }
            
            echo json_encode([
                'success' => true,
                'folders' => $folders,
                'currentPath' => str_replace('\\', '/', $basePath),
                'parentPath' => str_replace('\\', '/', dirname($basePath))
            ]);
        } catch (Exception $e) {
            echo json_encode(['success' => false, 'message' => $e->getMessage()]);
        }
        exit;
    }
    
    // ============================================
    // CLEAR PROMPT FILE - Clear prompt.txt on the server
    // ============================================
    if ($action === 'clear_prompt_file') {
        $promptFile = __DIR__ . '/prompt.txt';
        if (file_exists($promptFile)) {
            if (file_put_contents($promptFile, '') !== false) {
                echo json_encode(['success' => true, 'message' => 'prompt.txt cleared']);
            } else {
                echo json_encode(['success' => false, 'message' => 'Failed to write to prompt.txt']);
            }
        } else {
            // Create it empty if it doesn't exist
            file_put_contents($promptFile, '');
            echo json_encode(['success' => true, 'message' => 'prompt.txt created empty']);
        }
        exit;
    }

    // ============================================
    // RESOLVE FOLDER PATH - Find a folder by name in common locations
    // ============================================
    if ($action === 'resolve_folder_path') {
        $folderName = $_POST['folder_name'] ?? '';
        
        if (empty($folderName)) {
            echo json_encode(['success' => false, 'path' => '']);
            exit;
        }
        
        $appDir = dirname(__FILE__);
        
        // Common search locations (ordered by priority)
        $searchPaths = [
            $appDir . '/../' . $folderName,           // Sibling of app dir (e.g. C:/laragon/FolderName)
            $appDir . '/../../www/' . $folderName,     // Laragon www (e.g. C:/laragon/www/FolderName)
            $appDir . '/' . $folderName,               // Inside app dir
            'C:/laragon/www/' . $folderName,           // Absolute Laragon www
            'C:/laragon/' . $folderName,               // Absolute Laragon root
            'C:/Users/' . get_current_user() . '/Desktop/' . $folderName,
            'C:/Users/' . get_current_user() . '/Documents/' . $folderName,
        ];
        
        foreach ($searchPaths as $tryPath) {
            $resolved = realpath($tryPath);
            if ($resolved && is_dir($resolved)) {
                echo json_encode([
                    'success' => true,
                    'path' => str_replace('\\', '/', $resolved)
                ]);
                exit;
            }
        }
        
        echo json_encode(['success' => false, 'path' => '']);
        exit;
    }
    
    // ============================================
    // FOLDER TREE - Get full directory tree for a folder
    // ============================================
    if ($action === 'get_folder_tree') {
        $folderPath = $_POST['path'] ?? '';
        $maxDepth = intval($_POST['max_depth'] ?? 0); // 0 = unlimited depth (traverse all levels)
        
        if (empty($folderPath)) {
            echo json_encode(['success' => false, 'message' => 'No path provided']);
            exit;
        }
        
        $folderPath = realpath($folderPath);
        
        if (!$folderPath || !is_dir($folderPath)) {
            echo json_encode(['success' => false, 'message' => 'Invalid directory path']);
            exit;
        }
        
        // Recursive function to build tree
        function buildDirectoryTree($path, $depth = 0, $maxDepth = 0) {
            // maxDepth = 0 means unlimited; otherwise stop at maxDepth
            if ($maxDepth > 0 && $depth >= $maxDepth) {
                return [];
            }
            
            $tree = [];
            $items = @scandir($path);
            
            if (!$items) return $tree;
            
            $dirs = [];
            $files = [];
            
            foreach ($items as $item) {
                if ($item === '.' || $item === '..') continue;
                
                // Skip hidden files/folders and common ignore patterns
                if ($item[0] === '.' || $item === 'node_modules' || $item === 'vendor' || $item === '__pycache__') continue;
                
                $fullPath = $path . DIRECTORY_SEPARATOR . $item;
                
                if (is_dir($fullPath)) {
                    $dirs[] = $item;
                } else {
                    $files[] = $item;
                }
            }
            
            // Sort alphabetically
            sort($dirs, SORT_STRING | SORT_FLAG_CASE);
            sort($files, SORT_STRING | SORT_FLAG_CASE);
            
            // Add directories first (with their children)
            foreach ($dirs as $dir) {
                $children = buildDirectoryTree($path . DIRECTORY_SEPARATOR . $dir, $depth + 1, $maxDepth);
                $tree[] = [
                    'name' => $dir,
                    'type' => 'folder',
                    'children' => $children
                ];
            }
            
            // Then add files
            foreach ($files as $file) {
                $tree[] = [
                    'name' => $file,
                    'type' => 'file'
                ];
            }
            
            return $tree;
        }
        
        try {
            $tree = buildDirectoryTree($folderPath, 0, $maxDepth);
            $folderName = basename($folderPath);
            
            echo json_encode([
                'success' => true,
                'folderName' => $folderName,
                'folderPath' => str_replace('\\', '/', $folderPath),
                'tree' => $tree
            ]);
        } catch (Exception $e) {
            echo json_encode(['success' => false, 'message' => $e->getMessage()]);
        }
        exit;
    }
    
    // ============================================
    // READ FILE AS BASE64 — Serve local image files
    // ============================================
    if ($action === 'read_file_base64') {
        $filePath = $_POST['path'] ?? '';
        
        if (empty($filePath)) {
            echo json_encode(['success' => false, 'message' => 'No path provided']);
            exit;
        }
        
        $filePath = realpath($filePath);
        
        if (!$filePath || !is_file($filePath)) {
            echo json_encode(['success' => false, 'message' => 'File not found']);
            exit;
        }
        
        // Only allow image files
        $ext = strtolower(pathinfo($filePath, PATHINFO_EXTENSION));
        $allowedExts = ['png', 'jpg', 'jpeg', 'gif', 'svg', 'ico', 'webp', 'bmp'];
        
        if (!in_array($ext, $allowedExts)) {
            echo json_encode(['success' => false, 'message' => 'Not an image file']);
            exit;
        }
        
        $mimeTypes = [
            'png' => 'image/png', 'jpg' => 'image/jpeg', 'jpeg' => 'image/jpeg',
            'gif' => 'image/gif', 'svg' => 'image/svg+xml', 'ico' => 'image/x-icon',
            'webp' => 'image/webp', 'bmp' => 'image/bmp'
        ];
        
        try {
            $content = file_get_contents($filePath);
            $base64 = base64_encode($content);
            $mime = $mimeTypes[$ext] ?? 'image/png';
            $dataUrl = "data:{$mime};base64,{$base64}";
            
            echo json_encode([
                'success' => true,
                'dataUrl' => $dataUrl,
                'fileName' => basename($filePath),
                'mime' => $mime
            ]);
        } catch (Exception $e) {
            echo json_encode(['success' => false, 'message' => $e->getMessage()]);
        }
        exit;
    }
    
    // ============================================
    // READ TEXT FILE — Read a .txt file content from server
    // ============================================
    if ($action === 'read_file_text') {
        $filePath = $_POST['path'] ?? '';
        
        if (empty($filePath)) {
            echo json_encode(['success' => false, 'message' => 'No path provided']);
            exit;
        }
        
        $filePath = realpath($filePath);
        
        if (!$filePath || !is_file($filePath)) {
            echo json_encode(['success' => false, 'message' => 'File not found']);
            exit;
        }
        
        // Only allow text files
        $ext = strtolower(pathinfo($filePath, PATHINFO_EXTENSION));
        if ($ext !== 'txt') {
            echo json_encode(['success' => false, 'message' => 'Not a text file']);
            exit;
        }
        
        try {
            $content = file_get_contents($filePath);
            $size = filesize($filePath);
            
            echo json_encode([
                'success' => true,
                'content' => $content,
                'fileName' => basename($filePath),
                'size' => $size
            ]);
        } catch (Exception $e) {
            echo json_encode(['success' => false, 'message' => $e->getMessage()]);
        }
        exit;
    }
    
    // ============================================
    // ARABIC TTS PROXY — Fetch Google Translate audio server-side
    // ============================================
    if ($action === 'tts_ar_proxy') {
        $text = $_POST['text'] ?? '';
        
        if (empty($text)) {
            header('HTTP/1.1 400 Bad Request');
            echo 'No text provided';
            exit;
        }
        
        // Limit text length for safety
        $text = mb_substr($text, 0, 200);
        
        $url = 'https://translate.google.com/translate_tts?ie=UTF-8&tl=ar'
             . '&client=tw-ob&q=' . urlencode($text);
        
        $ch = curl_init();
        curl_setopt_array($ch, [
            CURLOPT_URL => $url,
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_FOLLOWLOCATION => true,
            CURLOPT_TIMEOUT => 15,
            CURLOPT_USERAGENT => 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
            CURLOPT_HTTPHEADER => [
                'Referer: https://translate.google.com/',
                'Accept: audio/mpeg, audio/*;q=0.9, */*;q=0.8'
            ],
            CURLOPT_SSL_VERIFYPEER => false
        ]);
        
        $audioData = curl_exec($ch);
        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        $error = curl_error($ch);
        curl_close($ch);
        
        if ($audioData && $httpCode === 200 && strlen($audioData) > 100) {
            header('Content-Type: audio/mpeg');
            header('Content-Length: ' . strlen($audioData));
            header('Cache-Control: public, max-age=86400');
            echo $audioData;
        } else {
            header('HTTP/1.1 502 Bad Gateway');
            echo 'TTS fetch failed: ' . ($error ?: "HTTP $httpCode");
        }
        exit;
    }
}
?>
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Prompt Manager - AI Prompt Generator</title>
    <link rel="icon" type="image/png" href="logoPM.png">
    <link href="https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600&family=Space+Grotesk:wght@400;500;600;700&family=Caveat:wght@400;500;600;700&display=swap" rel="stylesheet">
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">
    <style>
        :root {
            --bg-primary: #0a0a0f;
            --bg-secondary: #12121a;
            --bg-tertiary: #1a1a25;
            --bg-card: #15151f;
            --border-color: #2a2a3a;
            --border-glow: #4f46e5;
            --text-primary: #f0f0f5;
            --text-secondary: #a0a0b0;
            --text-muted: #606070;
            --accent-primary: #6366f1;
            --accent-secondary: #8b5cf6;
            --accent-tertiary: #a855f7;
            --success: #10b981;
            --warning: #f59e0b;
            --danger: #ef4444;
            --gradient-main: linear-gradient(135deg, #6366f1 0%, #8b5cf6 50%, #a855f7 100%);
            --gradient-dark: linear-gradient(180deg, #0a0a0f 0%, #12121a 100%);
            --shadow-glow: 0 0 40px rgba(99, 102, 241, 0.15);
            --shadow-card: 0 4px 24px rgba(0, 0, 0, 0.4);
        }

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Space Grotesk', sans-serif;
            background: var(--bg-primary);
            color: var(--text-primary);
            min-height: 100vh;
            overflow-x: hidden;
        }

        /* Background Effects */
        .bg-effects {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            pointer-events: none;
            z-index: 0;
            overflow: hidden;
        }

        .bg-effects::before {
            content: '';
            position: absolute;
            top: -50%;
            left: -50%;
            width: 200%;
            height: 200%;
            background: radial-gradient(circle at 30% 30%, rgba(99, 102, 241, 0.08) 0%, transparent 50%),
                        radial-gradient(circle at 70% 70%, rgba(139, 92, 246, 0.06) 0%, transparent 50%);
            animation: bgPulse 15s ease-in-out infinite;
        }

        @keyframes bgPulse {
            0%, 100% { transform: translate(0, 0) scale(1); }
            50% { transform: translate(-5%, -5%) scale(1.1); }
        }

        /* Main Layout */
        .app-container {
            display: flex;
            min-height: 100vh;
            position: relative;
            z-index: 1;
        }

        /* Sidebar */
        .sidebar {
            width: 320px;
            min-width: 320px;
            background: var(--bg-secondary);
            border-right: 1px solid var(--border-color);
            display: flex;
            flex-direction: column;
            height: 100vh;
            position: sticky;
            top: 0;
            overflow: hidden;
            transition: width 0.4s cubic-bezier(0.4, 0, 0.2, 1), min-width 0.4s cubic-bezier(0.4, 0, 0.2, 1);
        }
        
        /* Collapsed sidebar state - FULLY HIDDEN */
        .sidebar.collapsed {
            width: 0px;
            min-width: 0px;
            border-right: none;
        }
        
        .sidebar.collapsed .sidebar-header,
        .sidebar.collapsed .sidebar-content {
            opacity: 0;
            visibility: hidden;
            pointer-events: none;
        }
        
        /* ═══════════════════════════════════════════════════════════════════
           🎯 PANEL COLLAPSE BUTTONS - Artistic Design
           ═══════════════════════════════════════════════════════════════════ */
        .panel-collapse-btn {
            position: fixed;
            top: 50%;
            transform: translateY(-50%);
            width: 36px;
            height: 80px;
            background: linear-gradient(180deg, 
                rgba(99, 102, 241, 0.95) 0%, 
                rgba(139, 92, 246, 0.95) 50%,
                rgba(16, 185, 129, 0.95) 100%);
            border: none;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            z-index: 1000;
            color: white;
            font-size: 1rem;
            transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
            box-shadow: 0 4px 20px rgba(99, 102, 241, 0.5),
                        0 8px 40px rgba(139, 92, 246, 0.3);
            backdrop-filter: blur(10px);
        }
        
        .panel-collapse-btn::before {
            content: '';
            position: absolute;
            inset: 2px;
            background: linear-gradient(180deg, 
                rgba(255, 255, 255, 0.15) 0%, 
                transparent 50%,
                rgba(0, 0, 0, 0.1) 100%);
            pointer-events: none;
        }
        
        .panel-collapse-btn i {
            position: relative;
            z-index: 2;
            transition: transform 0.3s ease;
        }
        
        .panel-collapse-btn:hover {
            width: 44px;
            box-shadow: 0 6px 30px rgba(99, 102, 241, 0.7),
                        0 12px 60px rgba(139, 92, 246, 0.5);
        }
        
        .panel-collapse-btn:hover i {
            transform: scale(1.2);
        }
        
        .panel-collapse-btn:active {
            transform: translateY(-50%) scale(0.95);
        }
        
        /* Left Panel Collapse Button */
        .panel-collapse-btn.left {
            left: 320px;
            border-radius: 0 16px 16px 0;
            transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
        }
        
        .sidebar.collapsed ~ .main-content .panel-collapse-btn.left,
        .panel-collapse-btn.left.panel-hidden {
            left: 0;
        }
        
        .panel-collapse-btn.left.panel-hidden i {
            transform: rotate(180deg);
        }
        
        .panel-collapse-btn.left.panel-hidden:hover i {
            transform: rotate(180deg) scale(1.2);
        }
        
        /* Right Panel Collapse Button */
        .panel-collapse-btn.right {
            right: 400px;
            border-radius: 16px 0 0 16px;
            background: linear-gradient(180deg, 
                rgba(233, 30, 99, 0.95) 0%, 
                rgba(156, 39, 176, 0.95) 50%,
                rgba(103, 58, 183, 0.95) 100%);
            box-shadow: 0 4px 20px rgba(233, 30, 99, 0.5),
                        0 8px 40px rgba(156, 39, 176, 0.3);
            transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
        }
        
        .panel-collapse-btn.right:hover {
            box-shadow: 0 6px 30px rgba(233, 30, 99, 0.7),
                        0 12px 60px rgba(156, 39, 176, 0.5);
        }
        
        .right-panel.collapsed ~ .panel-collapse-btn.right,
        .panel-collapse-btn.right.panel-hidden {
            right: 0;
        }
        
        .panel-collapse-btn.right.panel-hidden i {
            transform: rotate(180deg);
        }
        
        .panel-collapse-btn.right.panel-hidden:hover i {
            transform: rotate(180deg) scale(1.2);
        }
        
        /* Tooltip for collapse buttons */
        .panel-collapse-btn .collapse-tooltip {
            position: absolute;
            top: 50%;
            transform: translateY(-50%);
            background: rgba(0, 0, 0, 0.9);
            color: white;
            padding: 6px 12px;
            border-radius: 8px;
            font-size: 0.75rem;
            font-weight: 600;
            white-space: nowrap;
            opacity: 0;
            pointer-events: none;
            transition: opacity 0.3s ease, transform 0.3s ease;
            z-index: 1001;
        }
        
        .panel-collapse-btn.left .collapse-tooltip {
            left: 100%;
            margin-left: 10px;
        }
        
        .panel-collapse-btn.right .collapse-tooltip {
            right: 100%;
            margin-right: 10px;
        }
        
        .panel-collapse-btn:hover .collapse-tooltip {
            opacity: 1;
        }
        
        .panel-collapse-btn.left:hover .collapse-tooltip {
            transform: translateY(-50%) translateX(5px);
        }
        
        .panel-collapse-btn.right:hover .collapse-tooltip {
            transform: translateY(-50%) translateX(-5px);
        }
        
        /* Pulse animation on load to draw attention */
        @keyframes panelBtnPulse {
            0%, 100% { box-shadow: 0 4px 20px rgba(99, 102, 241, 0.5), 0 8px 40px rgba(139, 92, 246, 0.3); }
            50% { box-shadow: 0 4px 30px rgba(99, 102, 241, 0.8), 0 12px 60px rgba(139, 92, 246, 0.5); }
        }
        
        @keyframes panelBtnPulseRight {
            0%, 100% { box-shadow: 0 4px 20px rgba(233, 30, 99, 0.5), 0 8px 40px rgba(156, 39, 176, 0.3); }
            50% { box-shadow: 0 4px 30px rgba(233, 30, 99, 0.8), 0 12px 60px rgba(156, 39, 176, 0.5); }
        }
        
        .panel-collapse-btn.left {
            animation: panelBtnPulse 3s ease-in-out infinite;
        }
        
        .panel-collapse-btn.right {
            animation: panelBtnPulseRight 3s ease-in-out infinite;
            animation-delay: 1.5s;
        }
        
        .panel-collapse-btn:hover {
            animation: none;
        }
        
        /* Glow ring effect */
        .panel-collapse-btn::after {
            content: '';
            position: absolute;
            inset: -3px;
            border-radius: inherit;
            background: linear-gradient(180deg, 
                rgba(255, 255, 255, 0.3) 0%, 
                transparent 50%,
                rgba(0, 0, 0, 0.2) 100%);
            opacity: 0;
            transition: opacity 0.3s ease;
            pointer-events: none;
        }
        
        .panel-collapse-btn:hover::after {
            opacity: 1;
        }

        .sidebar-header {
            position: relative;
            padding: 0.75rem 1rem;
            background: linear-gradient(135deg, rgba(99, 102, 241, 0.15) 0%, rgba(139, 92, 246, 0.1) 50%, rgba(6, 182, 212, 0.1) 100%);
            border-bottom: 1px solid rgba(99, 102, 241, 0.2);
            text-align: center;
            position: relative;
        }

        .sidebar-header::before {
            content: '';
            position: absolute;
            top: 0;
            left: 0;
            right: 0;
            height: 2px;
            background: linear-gradient(90deg, #6366f1, #8b5cf6, #06b6d4);
        }

        .sidebar-header img {
            max-width: 140px;
            height: auto;
            filter: drop-shadow(0 2px 8px rgba(99, 102, 241, 0.3));
            transition: transform 0.3s ease;
        }

        .sidebar-header img:hover {
            transform: scale(1.05);
        }

        .sidebar-content {
            flex: 1;
            overflow-y: auto;
            padding: 1rem;
        }

        .sidebar-content::-webkit-scrollbar {
            width: 6px;
        }

        .sidebar-content::-webkit-scrollbar-track {
            background: var(--bg-tertiary);
        }

        .sidebar-content::-webkit-scrollbar-thumb {
            background: var(--accent-primary);
            border-radius: 3px;
        }

        /* Section Titles */
        .section-title {
            font-size: 0.75rem;
            font-weight: 600;
            text-transform: uppercase;
            letter-spacing: 1px;
            color: var(--text-muted);
            margin-bottom: 0.75rem;
            display: flex;
            align-items: center;
            gap: 0.5rem;
        }

        .section-title i {
            color: var(--accent-primary);
        }

        /* File Mode Toggle - Big Visible Buttons */
        .file-mode-toggle {
            margin-bottom: 1rem;
            padding: 0.75rem;
            background: var(--bg-card);
            border: 1px solid var(--border-color);
            border-radius: 12px;
        }

        .toggle-header {
            font-size: 0.7rem;
            font-weight: 600;
            text-transform: uppercase;
            letter-spacing: 1px;
            color: var(--text-muted);
            margin-bottom: 0.5rem;
            display: flex;
            align-items: center;
            gap: 0.4rem;
        }

        .toggle-header i {
            color: var(--accent-secondary);
        }

        .toggle-buttons {
            display: flex;
            gap: 0.5rem;
        }

        .toggle-btn {
            flex: 1;
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 0.3rem;
            padding: 0.6rem 0.5rem;
            background: var(--bg-tertiary);
            border: 2px solid var(--border-color);
            border-radius: 10px;
            color: var(--text-muted);
            font-family: inherit;
            font-size: 0.7rem;
            font-weight: 600;
            cursor: pointer;
            transition: all 0.25s ease;
        }

        .toggle-btn i {
            font-size: 1.1rem;
        }

        .toggle-btn:hover {
            border-color: var(--accent-primary);
            color: var(--text-secondary);
            background: rgba(99, 102, 241, 0.1);
        }

        .toggle-btn.active {
            background: var(--gradient-main);
            border-color: var(--accent-primary);
            color: white;
            box-shadow: 0 4px 15px rgba(99, 102, 241, 0.4);
        }

        .toggle-btn.active i {
            color: white;
        }

        /* Reference button special styling when active */
        .toggle-btn#btnReference.active {
            background: linear-gradient(135deg, #f59e0b 0%, #d97706 100%);
            border-color: #f59e0b;
            box-shadow: 0 4px 15px rgba(245, 158, 11, 0.4);
        }

        /* Database Selector */
        .database-selector {
            margin-bottom: 1rem;
            padding: 0.75rem;
            background: linear-gradient(135deg, rgba(251, 191, 36, 0.08) 0%, rgba(245, 158, 11, 0.05) 100%);
            border: 1px solid rgba(251, 191, 36, 0.2);
            border-radius: 12px;
        }

        .db-selector-header {
            font-size: 0.7rem;
            font-weight: 600;
            display: flex;
            align-items: center;
            justify-content: space-between;
            text-transform: uppercase;
            letter-spacing: 1px;
            color: #fbbf24;
            margin-bottom: 0.5rem;
            display: flex;
            align-items: center;
            gap: 0.4rem;
        }

        .db-selector-header i {
            color: #fbbf24;
        }

        .db-manage-btn {
            width: 24px;
            height: 24px;
            border: none;
            border-radius: 6px;
            background: rgba(251, 191, 36, 0.15);
            color: #fbbf24;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.25s ease;
            font-size: 0.7rem;
        }

        .db-manage-btn:hover {
            background: rgba(251, 191, 36, 0.3);
            transform: rotate(90deg);
        }

        .db-manage-btn i {
            font-size: 0.7rem;
        }

        /* Database Refresh Button */
        .db-refresh-btn {
            width: 32px;
            height: 32px;
            border: none;
            border-radius: 8px;
            background: linear-gradient(135deg, rgba(0, 212, 170, 0.15) 0%, rgba(0, 184, 148, 0.1) 100%);
            color: #00d4aa;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.3s ease;
            flex-shrink: 0;
        }

        .db-refresh-btn:hover {
            background: linear-gradient(135deg, rgba(0, 212, 170, 0.3) 0%, rgba(0, 184, 148, 0.2) 100%);
            transform: rotate(180deg);
            box-shadow: 0 0 15px rgba(0, 212, 170, 0.3);
        }

        .db-refresh-btn:active {
            transform: rotate(360deg) scale(0.95);
        }

        .db-refresh-btn.spinning i {
            animation: dbRefreshSpin 0.8s linear infinite;
        }

        @keyframes dbRefreshSpin {
            from { transform: rotate(0deg); }
            to { transform: rotate(360deg); }
        }

        .db-refresh-btn i {
            font-size: 0.8rem;
            transition: transform 0.3s ease;
        }

        .db-selector-row {
            display: flex;
            align-items: center;
            gap: 0.5rem;
        }

        .db-checkbox-wrapper {
            flex-shrink: 0;
        }

        .db-checkbox-wrapper input {
            display: none;
        }

        .db-checkbox-box {
            width: 28px;
            height: 28px;
            border: 2px solid rgba(251, 191, 36, 0.3);
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.25s ease;
            background: var(--bg-tertiary);
        }

        .db-checkbox-box:hover {
            border-color: #fbbf24;
            background: rgba(251, 191, 36, 0.1);
        }

        .db-checkbox-box i {
            font-size: 0.8rem;
            color: white;
            opacity: 0;
            transform: scale(0);
            transition: all 0.2s ease;
        }

        .db-checkbox-wrapper input:checked + .db-checkbox-box {
            background: linear-gradient(135deg, #fbbf24, #f59e0b);
            border-color: #fbbf24;
            box-shadow: 0 3px 10px rgba(251, 191, 36, 0.4);
        }

        .db-checkbox-wrapper input:checked + .db-checkbox-box i {
            opacity: 1;
            transform: scale(1);
        }

        .db-dropdown-wrapper {
            flex: 1;
            position: relative;
        }

        .db-dropdown {
            width: 100%;
            padding: 0.6rem 2rem 0.6rem 0.75rem;
            background: var(--bg-tertiary);
            border: 1px solid var(--border-color);
            border-radius: 8px;
            color: var(--text-primary);
            font-family: inherit;
            font-size: 0.8rem;
            cursor: pointer;
            appearance: none;
            transition: all 0.2s ease;
        }

        .db-dropdown:hover {
            border-color: #fbbf24;
        }

        .db-dropdown:focus {
            outline: none;
            border-color: #fbbf24;
            box-shadow: 0 0 0 3px rgba(251, 191, 36, 0.15);
        }

        .db-dropdown option {
            background: var(--bg-secondary);
            color: var(--text-primary);
            padding: 8px;
        }

        .db-dropdown-arrow {
            position: absolute;
            right: 0.75rem;
            top: 50%;
            transform: translateY(-50%);
            color: #fbbf24;
            font-size: 0.7rem;
            pointer-events: none;
        }

        .db-no-connections {
            font-size: 0.75rem;
            color: var(--text-muted);
            text-align: center;
            padding: 0.5rem;
            font-style: italic;
        }

        .db-no-connections a {
            color: #fbbf24;
            text-decoration: none;
        }

        .db-no-connections a:hover {
            text-decoration: underline;
        }

        /* Database Dropdown Row */
        .db-dropdown-row {
            display: flex;
            align-items: center;
            gap: 0.5rem;
            margin-bottom: 0.6rem;
        }

        /* Credentials Checkboxes Row */
        .db-credentials-row {
            display: flex;
            gap: 0.5rem;
        }

        .db-cred-option {
            flex: 1;
            cursor: pointer;
        }

        .db-cred-option input {
            display: none;
        }

        .db-cred-box {
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 0.4rem;
            padding: 0.5rem 0.6rem;
            background: var(--bg-tertiary);
            border: 2px solid var(--border-color);
            border-radius: 8px;
            font-size: 0.7rem;
            font-weight: 600;
            color: var(--text-muted);
            transition: all 0.25s ease;
        }

        .db-cred-box i {
            font-size: 0.8rem;
        }

        .db-cred-option:hover .db-cred-box {
            border-color: rgba(251, 191, 36, 0.5);
            background: rgba(251, 191, 36, 0.08);
            color: var(--text-secondary);
        }

        /* Remote checkbox active state - Blue */
        .db-cred-option.remote input:checked + .db-cred-box {
            background: linear-gradient(135deg, #3b82f6 0%, #1e40af 100%);
            border-color: #3b82f6;
            color: white;
            box-shadow: 0 3px 12px rgba(59, 130, 246, 0.4);
        }

        .db-cred-option.remote input:checked + .db-cred-box i {
            color: white;
        }

        /* Localhost checkbox active state - Green */
        .db-cred-option.localhost input:checked + .db-cred-box {
            background: linear-gradient(135deg, #22c55e 0%, #16a34a 100%);
            border-color: #22c55e;
            color: white;
            box-shadow: 0 3px 12px rgba(34, 197, 94, 0.4);
        }

        .db-cred-option.localhost input:checked + .db-cred-box i {
            color: white;
        }

        /* File Upload Area */
        /* Two-Level File Picker */
        .file-picker-container {
            margin-bottom: 0.75rem;
        }

        /* Mini Drop Zone */
        .drop-zone-mini {
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 0.6rem;
            padding: 0.75rem;
            background: var(--bg-card);
            border: 2px dashed var(--border-color);
            border-radius: 10px;
            cursor: pointer;
            transition: all 0.2s;
        }

        .drop-zone-mini:hover,
        .drop-zone-mini.dragover {
            border-color: var(--accent-primary);
            background: rgba(99, 102, 241, 0.08);
            border-style: solid;
        }

        .drop-zone-mini.dragover {
            transform: scale(1.02);
            box-shadow: 0 0 20px rgba(99, 102, 241, 0.2);
        }

        .drop-zone-mini i {
            font-size: 1.1rem;
            color: var(--accent-primary);
        }

        .drop-zone-mini span {
            font-size: 0.8rem;
            color: var(--text-muted);
            font-weight: 500;
        }

        .drop-zone-mini:hover span {
            color: var(--accent-primary);
        }

        /* Folder Drop Zone - Distinct Style */
        .drop-zone-mini.folder-zone {
            border-color: rgba(251, 191, 36, 0.3);
        }

        .drop-zone-mini.folder-zone i {
            color: #fbbf24;
        }

        .drop-zone-mini.folder-zone:hover,
        .drop-zone-mini.folder-zone.dragover {
            border-color: #fbbf24;
            background: rgba(251, 191, 36, 0.08);
            border-style: solid;
        }

        .drop-zone-mini.folder-zone:hover span {
            color: #fbbf24;
        }

        .drop-zone-mini.folder-zone.dragover {
            transform: scale(1.02);
            box-shadow: 0 0 20px rgba(251, 191, 36, 0.2);
        }

        /* Folder Item in Files List */
        .file-item.folder-item {
            border-color: rgba(251, 191, 36, 0.25);
            background: rgba(251, 191, 36, 0.05);
        }

        .file-item.folder-item:hover {
            border-color: #fbbf24;
            background: rgba(251, 191, 36, 0.1);
        }

        .file-item.folder-item.checked {
            border-color: #fbbf24;
            background: rgba(251, 191, 36, 0.12);
        }

        .file-item.folder-item .file-item-icon {
            color: #fbbf24;
        }

        .file-item.folder-item.checked .file-item-checkbox .checkbox-box {
            background: linear-gradient(135deg, #fbbf24, #d97706);
            border-color: #fbbf24;
        }

        /* Uploaded Files Header */
        .uploaded-files-header {
            display: flex;
            align-items: center;
            justify-content: space-between;
        }

        .files-header-left {
            display: flex;
            align-items: center;
            gap: 0.75rem;
            padding: 0.5rem 0.75rem;
            background: var(--bg-tertiary);
            border: 1px solid var(--border-color);
            border-radius: 8px 8px 0 0;
            margin-bottom: 0;
        }

        .files-count {
            font-size: 0.75rem;
            font-weight: 600;
            color: var(--text-secondary);
            display: flex;
            align-items: center;
            gap: 0.4rem;
        }

        .files-count i {
            color: var(--accent-secondary);
        }

        .btn-delete-all {
            display: flex;
            align-items: center;
            gap: 0.4rem;
            padding: 0.35rem 0.7rem;
            background: linear-gradient(135deg, #ef4444 0%, #dc2626 100%);
            border: none;
            border-radius: 6px;
            color: white;
            font-family: inherit;
            font-size: 0.7rem;
            font-weight: 600;
            cursor: pointer;
            transition: all 0.2s ease;
        }

        .btn-delete-all:hover {
            transform: scale(1.05);
            box-shadow: 0 4px 12px rgba(239, 68, 68, 0.4);
        }

        .btn-delete-all i {
            font-size: 0.75rem;
        }

        /* Uploaded Files List */
        .uploaded-files {
            margin-bottom: 1.5rem;
        }

        .uploaded-files-header + .uploaded-files {
            border-top: none;
            border-radius: 0 0 8px 8px;
        }

        .file-item {
            background: var(--bg-card);
            border: 1px solid var(--border-color);
            border-radius: 8px;
            padding: 0.75rem;
            margin-bottom: 0.5rem;
            display: flex;
            align-items: center;
            gap: 0.75rem;
            transition: all 0.2s;
            position: relative;
        }

        .file-item:hover {
            border-color: var(--accent-primary);
            transform: translateX(3px);
            background: rgba(99, 102, 241, 0.05);
        }

        .file-item.checked {
            border-color: var(--success);
            background: rgba(16, 185, 129, 0.1);
        }

        .file-item-checkbox {
            flex-shrink: 0;
            cursor: pointer;
        }

        .file-item-checkbox input {
            display: none;
        }

        .file-item-checkbox .checkbox-box {
            width: 22px;
            height: 22px;
            border: 2px solid var(--border-color);
            border-radius: 6px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.2s;
            background: var(--bg-tertiary);
        }

        .file-item-checkbox .checkbox-box i {
            font-size: 0.7rem;
            color: white;
            opacity: 0;
            transform: scale(0);
            transition: all 0.2s;
        }

        .file-item.checked .file-item-checkbox .checkbox-box {
            background: linear-gradient(135deg, var(--success), #059669);
            border-color: var(--success);
        }

        .file-item.checked .file-item-checkbox .checkbox-box i {
            opacity: 1;
            transform: scale(1);
        }

        .file-item-icon {
            color: var(--accent-secondary);
            font-size: 1.25rem;
        }

        .file-info {
            flex: 1;
            min-width: 0;
        }

        .file-name {
            font-size: 0.85rem;
            font-weight: 500;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .file-size {
            font-size: 0.7rem;
            color: var(--text-muted);
        }

        .file-delete {
            background: none;
            border: none;
            color: var(--danger);
            cursor: pointer;
            padding: 0.25rem;
            opacity: 0.6;
            transition: opacity 0.2s;
        }

        .file-delete:hover {
            opacity: 1;
        }

        /* Prompt Search Box */
        .prompt-search-box {
            position: relative;
            margin-bottom: 0.75rem;
        }

        .prompt-search-box input {
            width: 100%;
            padding: 0.7rem 2.5rem 0.7rem 2.5rem;
            background: var(--bg-card);
            border: 1px solid var(--border-color);
            border-radius: 10px;
            color: var(--text-primary);
            font-family: inherit;
            font-size: 0.85rem;
            outline: none;
            transition: all 0.2s ease;
        }

        .prompt-search-box input:focus {
            border-color: var(--accent-primary);
            box-shadow: 0 0 0 3px rgba(99, 102, 241, 0.15);
        }

        .prompt-search-box input::placeholder {
            color: var(--text-muted);
        }

        .prompt-search-box > i {
            position: absolute;
            left: 0.9rem;
            top: 50%;
            transform: translateY(-50%);
            color: var(--text-muted);
            font-size: 0.85rem;
            pointer-events: none;
        }

        .prompt-search-clear {
            position: absolute;
            right: 0.5rem;
            top: 50%;
            transform: translateY(-50%);
            background: var(--bg-tertiary);
            border: none;
            color: var(--text-muted);
            width: 24px;
            height: 24px;
            border-radius: 50%;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
        }

        .prompt-search-clear:hover {
            background: var(--danger);
            color: white;
        }

        /* Prompt Actions (Select All / Deselect All) */
        .prompt-actions {
            display: flex;
            gap: 0.5rem;
            margin-bottom: 0.75rem;
            align-items: center;
        }

        .prompt-action-btn {
            flex: 1;
            padding: 0.45rem 0.5rem;
            background: var(--bg-card);
            border: 1px solid var(--border-color);
            border-radius: 8px;
            color: var(--text-muted);
            font-family: inherit;
            font-size: 0.7rem;
            font-weight: 600;
            cursor: pointer;
            transition: all 0.2s;
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 0.3rem;
        }

        .prompt-action-btn:hover {
            border-color: var(--accent-primary);
            color: var(--accent-primary);
            background: rgba(99, 102, 241, 0.1);
        }

        .prompt-action-btn i {
            font-size: 0.75rem;
        }

        .prompt-counter {
            font-size: 0.7rem;
            font-weight: 700;
            color: var(--accent-primary);
            background: rgba(99, 102, 241, 0.15);
            padding: 0.3rem 0.6rem;
            border-radius: 6px;
            white-space: nowrap;
        }

        /* Select All Checkbox Style */
        .select-all-checkbox {
            display: flex;
            align-items: center;
            gap: 0.5rem;
            cursor: pointer;
            padding: 0.4rem 0.75rem;
            background: var(--bg-card);
            border: 1px solid var(--border-color);
            border-radius: 8px;
            transition: all 0.2s ease;
            user-select: none;
        }

        .select-all-checkbox:hover {
            border-color: var(--accent-primary);
            background: rgba(99, 102, 241, 0.1);
        }

        .select-all-checkbox input[type="checkbox"] {
            display: none;
        }

        .select-all-checkbox .checkbox-custom {
            width: 18px;
            height: 18px;
            border: 2px solid var(--border-color);
            border-radius: 4px;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s ease;
            background: var(--bg-tertiary);
            flex-shrink: 0;
        }

        .select-all-checkbox .checkbox-custom::after {
            content: '✓';
            font-size: 12px;
            font-weight: bold;
            color: white;
            opacity: 0;
            transform: scale(0);
            transition: all 0.2s ease;
        }

        .select-all-checkbox input[type="checkbox"]:checked + .checkbox-custom {
            background: linear-gradient(135deg, var(--accent-primary), #818cf8);
            border-color: var(--accent-primary);
        }

        .select-all-checkbox input[type="checkbox"]:checked + .checkbox-custom::after {
            opacity: 1;
            transform: scale(1);
        }

        .select-all-checkbox .checkbox-label {
            font-size: 0.75rem;
            font-weight: 600;
            color: var(--text-muted);
            transition: color 0.2s;
        }

        .select-all-checkbox:hover .checkbox-label {
            color: var(--accent-primary);
        }

        .select-all-checkbox input[type="checkbox"]:checked ~ .checkbox-label {
            color: var(--accent-primary);
        }

        /* Indeterminate state (partial selection) */
        .select-all-checkbox input[type="checkbox"]:indeterminate + .checkbox-custom {
            background: linear-gradient(135deg, #f59e0b, #d97706);
            border-color: #f59e0b;
        }

        .select-all-checkbox input[type="checkbox"]:indeterminate + .checkbox-custom::after {
            content: '−';
            opacity: 1;
            transform: scale(1);
        }

        .select-all-checkbox input[type="checkbox"]:indeterminate ~ .checkbox-label {
            color: #f59e0b;
        }

        /* Prompt No Results */
        .prompt-no-results {
            text-align: center;
            padding: 1.5rem;
            color: var(--text-muted);
        }

        .prompt-no-results i {
            font-size: 2rem;
            margin-bottom: 0.75rem;
            opacity: 0.5;
            display: block;
        }

        .prompt-no-results p {
            font-size: 0.85rem;
        }

        /* Section Title Row */
        .section-title-row {
            display: flex;
            align-items: center;
            justify-content: space-between;
            margin-bottom: 0.75rem;
        }

        .section-title-row .section-title {
            margin-bottom: 0;
        }

        .btn-add-template {
            width: 32px;
            height: 32px;
            border-radius: 8px;
            background: linear-gradient(135deg, var(--accent-primary), var(--accent-secondary));
            border: none;
            color: white;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
            font-size: 0.9rem;
        }

        .btn-add-template:hover {
            transform: scale(1.1);
            box-shadow: 0 4px 15px rgba(99, 102, 241, 0.4);
        }

        /* Template Loading */
        .template-loading {
            text-align: center;
            padding: 1.5rem;
            color: var(--text-muted);
        }

        .template-loading i {
            font-size: 1.5rem;
            margin-right: 0.5rem;
            color: var(--accent-primary);
        }

        /* Prompt Checkboxes */
        .prompt-list {
            margin-top: 0;
            max-height: calc(100vh - 480px);
            min-height: 300px;
            overflow-y: auto;
        }

        /* Prompt Item with Actions */
        .prompt-item {
            display: flex;
            align-items: center;
            padding: 0.65rem 0.75rem;
            background: var(--bg-card);
            border: 1px solid var(--border-color);
            border-radius: 10px;
            margin-bottom: 0.5rem;
            transition: all 0.2s;
            gap: 0.5rem;
        }

        .prompt-item:hover {
            border-color: var(--accent-primary);
            background: rgba(99, 102, 241, 0.05);
        }

        .prompt-item.checked {
            border-color: var(--accent-primary);
            background: rgba(99, 102, 241, 0.1);
        }

        .prompt-item-checkbox {
            flex-shrink: 0;
        }

        .prompt-item-checkbox input {
            display: none;
        }

        .prompt-item-checkbox .checkbox-box {
            width: 22px;
            height: 22px;
            border: 2px solid var(--border-color);
            border-radius: 6px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.2s;
            background: var(--bg-tertiary);
        }

        .prompt-item-checkbox .checkbox-box i {
            font-size: 0.7rem;
            color: white;
            opacity: 0;
            transform: scale(0);
            transition: all 0.2s;
        }

        .prompt-item.checked .checkbox-box {
            background: linear-gradient(135deg, var(--accent-primary), var(--accent-secondary));
            border-color: var(--accent-primary);
        }

        .prompt-item.checked .checkbox-box i {
            opacity: 1;
            transform: scale(1);
        }

        .prompt-item-content {
            flex: 1;
            min-width: 0;
            cursor: pointer;
        }

        .prompt-item-name {
            font-size: 0.85rem;
            font-weight: 600;
            color: var(--text-primary);
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .prompt-item-preview {
            font-size: 0.7rem;
            color: var(--text-muted);
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
            margin-top: 2px;
        }

        .prompt-item-actions {
            display: flex;
            gap: 4px;
            flex-shrink: 0;
            opacity: 0.5;
            transition: opacity 0.2s;
        }

        .prompt-item:hover .prompt-item-actions {
            opacity: 1;
        }

        .prompt-action-icon {
            width: 26px;
            height: 26px;
            border-radius: 6px;
            border: none;
            background: var(--bg-tertiary);
            color: var(--text-muted);
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
            font-size: 0.7rem;
        }

        .prompt-action-icon:hover {
            transform: scale(1.1);
        }

        .prompt-action-icon.copy:hover {
            background: rgba(16, 185, 129, 0.2);
            color: var(--success);
        }

        .prompt-action-icon.edit:hover {
            background: rgba(99, 102, 241, 0.2);
            color: var(--accent-primary);
        }

        .prompt-action-icon.delete:hover {
            background: rgba(239, 68, 68, 0.2);
            color: var(--danger);
        }

        .prompt-action-icon.pull:hover {
            background: rgba(251, 191, 36, 0.2);
            color: #fbbf24;
        }

        .prompt-action-icon.push-right {
            position: relative;
            overflow: hidden;
        }
        .prompt-action-icon.push-right:hover {
            background: linear-gradient(135deg, rgba(59, 130, 246, 0.25), rgba(99, 102, 241, 0.18));
            color: #60a5fa;
            box-shadow: 0 0 8px rgba(59, 130, 246, 0.3);
        }
        .prompt-action-icon.push-right:hover i {
            animation: pushRightArrow 0.5s ease-in-out infinite alternate;
        }

        .prompt-action-icon.pull-left {
            position: relative;
            overflow: hidden;
        }
        .prompt-action-icon.pull-left:hover {
            background: linear-gradient(135deg, rgba(251, 191, 36, 0.25), rgba(245, 158, 11, 0.18));
            color: #fbbf24;
            box-shadow: 0 0 8px rgba(251, 191, 36, 0.3);
        }
        .prompt-action-icon.pull-left:hover i {
            animation: pullLeftArrow 0.5s ease-in-out infinite alternate;
        }

        @keyframes pushRightArrow {
            from { transform: translateX(-2px); }
            to   { transform: translateX(2px); }
        }
        @keyframes pullLeftArrow {
            from { transform: translateX(2px); }
            to   { transform: translateX(-2px); }
        }

        /* ═══════ Static Prompt Template (Read the Application) ═══════ */
        .spt-container {
            margin-bottom: 0.75rem;
            border-radius: 12px;
            background: linear-gradient(135deg, rgba(245, 158, 11, 0.06), rgba(217, 119, 6, 0.03));
            border: 1.5px solid rgba(245, 158, 11, 0.25);
            overflow: hidden;
            transition: all 0.3s ease;
            position: relative;
        }
        .spt-container::before {
            content: '';
            position: absolute;
            top: 0; left: 0; right: 0;
            height: 3px;
            background: linear-gradient(90deg, #f59e0b, #d97706, #b45309, #d97706, #f59e0b);
            background-size: 200% 100%;
            animation: sptShimmer 3s linear infinite;
        }
        @keyframes sptShimmer {
            0% { background-position: 200% 0; }
            100% { background-position: -200% 0; }
        }
        .spt-container:hover {
            border-color: rgba(245, 158, 11, 0.45);
            box-shadow: 0 2px 12px rgba(245, 158, 11, 0.1);
        }
        .spt-container.checked {
            border-color: rgba(245, 158, 11, 0.6);
            background: linear-gradient(135deg, rgba(245, 158, 11, 0.12), rgba(217, 119, 6, 0.06));
            box-shadow: 0 2px 16px rgba(245, 158, 11, 0.15);
        }

        .spt-main-row {
            display: flex;
            align-items: center;
            padding: 0.7rem 0.75rem;
            gap: 0.5rem;
        }

        .spt-checkbox {
            flex-shrink: 0;
            cursor: pointer;
        }
        .spt-checkbox input { display: none; }
        .spt-checkbox .checkbox-box {
            width: 22px; height: 22px;
            border: 2px solid rgba(245, 158, 11, 0.4);
            border-radius: 6px;
            display: flex; align-items: center; justify-content: center;
            transition: all 0.2s;
            background: var(--bg-tertiary);
        }
        .spt-checkbox .checkbox-box i {
            font-size: 0.7rem; color: white;
            opacity: 0; transform: scale(0);
            transition: all 0.2s;
        }
        .spt-container.checked .spt-checkbox .checkbox-box {
            background: linear-gradient(135deg, #f59e0b, #d97706);
            border-color: #f59e0b;
        }
        .spt-container.checked .spt-checkbox .checkbox-box i {
            opacity: 1; transform: scale(1);
        }

        .spt-content {
            flex: 1; min-width: 0;
            cursor: pointer;
        }
        .spt-badge {
            display: inline-flex; align-items: center; gap: 4px;
            font-size: 0.6rem; font-weight: 700;
            text-transform: uppercase; letter-spacing: 0.5px;
            color: #f59e0b;
            background: rgba(245, 158, 11, 0.12);
            padding: 1px 7px; border-radius: 4px;
            margin-bottom: 3px;
        }
        .spt-name {
            font-size: 0.85rem; font-weight: 600;
            color: var(--text-primary);
            white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
        }
        .spt-preview {
            font-size: 0.7rem; color: var(--text-muted);
            white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
            margin-top: 2px;
        }

        .spt-actions {
            display: flex; gap: 4px; flex-shrink: 0;
            opacity: 0.6; transition: opacity 0.2s;
        }
        .spt-container:hover .spt-actions { opacity: 1; }
        .spt-action-btn {
            width: 28px; height: 28px;
            border-radius: 6px; border: none;
            background: rgba(245, 158, 11, 0.1);
            color: var(--text-muted);
            cursor: pointer;
            display: flex; align-items: center; justify-content: center;
            transition: all 0.2s; font-size: 0.72rem;
            position: relative;
        }
        .spt-action-btn.copy:hover {
            background: rgba(16, 185, 129, 0.2); color: var(--success);
            transform: scale(1.1);
        }
        .spt-action-btn.files {
            position: relative;
        }
        .spt-action-btn.files:hover {
            background: rgba(245, 158, 11, 0.25); color: #f59e0b;
            transform: scale(1.1);
        }
        .spt-action-btn.files.has-files {
            color: #f59e0b;
            background: rgba(245, 158, 11, 0.18);
        }
        .spt-file-badge {
            position: absolute; top: -4px; right: -4px;
            background: linear-gradient(135deg, #f59e0b, #d97706);
            color: white; font-size: 0.55rem; font-weight: 700;
            min-width: 14px; height: 14px;
            border-radius: 7px;
            display: flex; align-items: center; justify-content: center;
            padding: 0 3px;
        }

        /* File upload section */
        .spt-files-section {
            border-top: 1px solid rgba(245, 158, 11, 0.15);
            padding: 0.6rem 0.75rem;
            background: rgba(0, 0, 0, 0.08);
            animation: sptSlideDown 0.25s ease;
        }
        @keyframes sptSlideDown {
            from { opacity: 0; max-height: 0; padding-top: 0; padding-bottom: 0; }
            to { opacity: 1; max-height: 500px; }
        }
        .spt-drop-zone {
            border: 2px dashed rgba(245, 158, 11, 0.3);
            border-radius: 8px;
            padding: 0.75rem;
            text-align: center;
            color: var(--text-muted);
            font-size: 0.75rem;
            cursor: pointer;
            transition: all 0.2s;
            background: rgba(245, 158, 11, 0.03);
        }
        .spt-drop-zone:hover, .spt-drop-zone.dragover {
            border-color: #f59e0b;
            background: rgba(245, 158, 11, 0.08);
            color: #f59e0b;
        }
        .spt-drop-zone i {
            font-size: 1.2rem; margin-bottom: 4px;
            display: block; color: rgba(245, 158, 11, 0.5);
        }
        .spt-browse {
            color: #f59e0b; cursor: pointer;
            text-decoration: underline; font-weight: 600;
        }
        .spt-browse:hover { color: #d97706; }

        .spt-file-list {
            margin-top: 0.5rem;
            display: flex; flex-direction: column; gap: 4px;
        }
        .spt-file-item {
            display: flex; align-items: center; gap: 6px;
            padding: 5px 8px;
            background: var(--bg-card);
            border: 1px solid var(--border-color);
            border-radius: 6px;
            font-size: 0.72rem;
            animation: sptFadeIn 0.2s ease;
        }
        @keyframes sptFadeIn {
            from { opacity: 0; transform: translateY(-4px); }
            to { opacity: 1; transform: translateY(0); }
        }
        .spt-file-item i.fa-file-code { color: #f59e0b; }
        .spt-file-item-name {
            flex: 1; overflow: hidden; text-overflow: ellipsis;
            white-space: nowrap; color: var(--text-primary);
        }
        .spt-file-item-size {
            color: var(--text-muted); font-size: 0.65rem;
        }
        .spt-file-item-remove {
            width: 18px; height: 18px;
            border-radius: 4px; border: none;
            background: transparent; color: var(--text-muted);
            cursor: pointer; display: flex;
            align-items: center; justify-content: center;
            font-size: 0.65rem; transition: all 0.2s;
        }
        .spt-file-item-remove:hover {
            background: rgba(239, 68, 68, 0.15); color: var(--danger);
        }
        .spt-file-mode {
            display: flex; align-items: center; gap: 6px;
            margin-bottom: 0.5rem; font-size: 0.7rem; color: var(--text-muted);
        }
        .spt-file-mode select {
            padding: 2px 6px; border-radius: 4px;
            border: 1px solid var(--border-color);
            background: var(--bg-card); color: var(--text-primary);
            font-size: 0.68rem; cursor: pointer;
        }

        /* ═══════ Static Template: Table Designer (TDT) ═══════ */
        .tdt-container {
            margin-bottom: 0.75rem;
            border-radius: 12px;
            background: linear-gradient(135deg, rgba(6, 182, 212, 0.06), rgba(8, 145, 178, 0.03));
            border: 1.5px solid rgba(6, 182, 212, 0.25);
            overflow: hidden;
            transition: all 0.3s ease;
            position: relative;
        }
        .tdt-container::before {
            content: '';
            position: absolute;
            top: 0; left: 0; right: 0;
            height: 3px;
            background: linear-gradient(90deg, #06b6d4, #0891b2, #0e7490, #0891b2, #06b6d4);
            background-size: 200% 100%;
            animation: tdtShimmer 3s linear infinite;
        }
        @keyframes tdtShimmer {
            0% { background-position: 200% 0; }
            100% { background-position: -200% 0; }
        }
        .tdt-container:hover {
            border-color: rgba(6, 182, 212, 0.45);
            box-shadow: 0 2px 12px rgba(6, 182, 212, 0.1);
        }
        .tdt-container.checked {
            border-color: rgba(6, 182, 212, 0.6);
            background: linear-gradient(135deg, rgba(6, 182, 212, 0.12), rgba(8, 145, 178, 0.06));
            box-shadow: 0 2px 16px rgba(6, 182, 212, 0.15);
        }
        .tdt-main-row {
            display: flex;
            align-items: center;
            padding: 0.7rem 0.75rem;
            gap: 0.5rem;
        }
        .tdt-checkbox {
            flex-shrink: 0;
            cursor: pointer;
        }
        .tdt-checkbox input { display: none; }
        .tdt-checkbox .checkbox-box {
            width: 22px; height: 22px;
            border: 2px solid rgba(6, 182, 212, 0.4);
            border-radius: 6px;
            display: flex; align-items: center; justify-content: center;
            transition: all 0.2s;
            background: var(--bg-tertiary);
        }
        .tdt-checkbox .checkbox-box i {
            font-size: 0.7rem; color: white;
            opacity: 0; transform: scale(0);
            transition: all 0.2s;
        }
        .tdt-container.checked .tdt-checkbox .checkbox-box {
            background: linear-gradient(135deg, #06b6d4, #0891b2);
            border-color: #06b6d4;
        }
        .tdt-container.checked .tdt-checkbox .checkbox-box i {
            opacity: 1; transform: scale(1);
        }
        .tdt-content {
            flex: 1; min-width: 0;
            cursor: pointer;
        }
        .tdt-badge {
            display: inline-flex; align-items: center; gap: 4px;
            font-size: 0.6rem; font-weight: 700;
            text-transform: uppercase; letter-spacing: 0.5px;
            color: #06b6d4;
            background: rgba(6, 182, 212, 0.12);
            padding: 1px 7px; border-radius: 4px;
            margin-bottom: 3px;
        }
        .tdt-name {
            font-size: 0.85rem; font-weight: 600;
            color: var(--text-primary);
            white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
        }
        .tdt-preview {
            font-size: 0.7rem; color: var(--text-muted);
            white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
            margin-top: 2px;
        }
        .tdt-actions {
            display: flex; gap: 4px; flex-shrink: 0;
            opacity: 0.6; transition: opacity 0.2s;
        }
        .tdt-container:hover .tdt-actions { opacity: 1; }
        .tdt-action-btn {
            width: 28px; height: 28px;
            border-radius: 6px; border: none;
            background: rgba(6, 182, 212, 0.1);
            color: var(--text-muted);
            cursor: pointer;
            display: flex; align-items: center; justify-content: center;
            transition: all 0.2s; font-size: 0.72rem;
        }
        .tdt-action-btn.design:hover {
            background: rgba(6, 182, 212, 0.25); color: #06b6d4;
            transform: scale(1.1);
        }
        .tdt-action-btn.copy:hover {
            background: rgba(16, 185, 129, 0.2); color: var(--success);
            transform: scale(1.1);
        }
        .tdt-saved-badge {
            display: inline-flex; align-items: center; gap: 3px;
            font-size: 0.55rem; font-weight: 600;
            color: #10b981; background: rgba(16, 185, 129, 0.1);
            padding: 1px 6px; border-radius: 4px;
            margin-left: 6px;
        }

        /* Table Designer Modal */
        .tdt-modal-overlay {
            position: fixed; top: 0; left: 0; right: 0; bottom: 0;
            background: rgba(0, 0, 0, 0.65);
            backdrop-filter: blur(6px);
            z-index: 10000;
            display: none; align-items: center; justify-content: center;
            animation: tdtFadeIn 0.25s ease;
        }
        .tdt-modal-overlay.active { display: flex; }
        @keyframes tdtFadeIn {
            from { opacity: 0; }
            to { opacity: 1; }
        }
        .tdt-modal {
            background: var(--bg-primary);
            border: 1px solid rgba(6, 182, 212, 0.3);
            border-radius: 16px;
            width: 720px; max-width: 95vw;
            max-height: 90vh;
            overflow: hidden;
            display: flex; flex-direction: column;
            box-shadow: 0 20px 60px rgba(0, 0, 0, 0.4), 0 0 40px rgba(6, 182, 212, 0.08);
            animation: tdtSlideUp 0.3s ease;
        }
        @keyframes tdtSlideUp {
            from { opacity: 0; transform: translateY(20px) scale(0.97); }
            to { opacity: 1; transform: translateY(0) scale(1); }
        }
        .tdt-modal-header {
            padding: 1rem 1.25rem;
            border-bottom: 1px solid rgba(6, 182, 212, 0.15);
            background: linear-gradient(135deg, rgba(6, 182, 212, 0.08), rgba(8, 145, 178, 0.04));
            display: flex; align-items: center; justify-content: space-between;
        }
        .tdt-modal-header h3 {
            margin: 0; font-size: 1rem; font-weight: 700;
            color: var(--text-primary);
            display: flex; align-items: center; gap: 8px;
        }
        .tdt-modal-header h3 i { color: #06b6d4; }
        .tdt-modal-close {
            width: 32px; height: 32px; border-radius: 8px;
            border: 1px solid var(--border-color);
            background: var(--bg-tertiary); color: var(--text-muted);
            cursor: pointer; display: flex; align-items: center; justify-content: center;
            transition: all 0.2s;
        }
        .tdt-modal-close:hover {
            background: rgba(239, 68, 68, 0.15); color: var(--danger);
            border-color: rgba(239, 68, 68, 0.3);
        }
        .tdt-modal-body {
            padding: 1rem 1.25rem;
            overflow-y: auto; flex: 1;
        }
        .tdt-modal-footer {
            padding: 0.75rem 1.25rem;
            border-top: 1px solid var(--border-color);
            display: flex; align-items: center; justify-content: space-between; gap: 8px;
            background: var(--bg-secondary);
        }
        /* Table info section */
        .tdt-info-grid {
            display: grid; grid-template-columns: 1fr 1fr;
            gap: 0.6rem; margin-bottom: 1rem;
        }
        .tdt-info-grid.three-col { grid-template-columns: 1fr 1fr 1fr; }
        .tdt-field-group {
            display: flex; flex-direction: column; gap: 4px;
        }
        .tdt-field-group.full-width { grid-column: 1 / -1; }
        .tdt-field-label {
            font-size: 0.7rem; font-weight: 600;
            color: var(--text-secondary);
            display: flex; align-items: center; gap: 4px;
        }
        .tdt-field-label i { color: #06b6d4; font-size: 0.65rem; }
        .tdt-input, .tdt-select {
            padding: 7px 10px; border-radius: 8px;
            border: 1px solid var(--border-color);
            background: var(--bg-tertiary);
            color: var(--text-primary);
            font-size: 0.78rem; font-family: 'JetBrains Mono', monospace;
            transition: all 0.2s;
        }
        .tdt-input:focus, .tdt-select:focus {
            outline: none;
            border-color: rgba(6, 182, 212, 0.5);
            box-shadow: 0 0 0 3px rgba(6, 182, 212, 0.1);
        }
        .tdt-input::placeholder { color: var(--text-muted); font-style: italic; }
        /* Columns section */
        .tdt-columns-header {
            display: flex; align-items: center; justify-content: space-between;
            margin-bottom: 0.5rem;
        }
        .tdt-columns-title {
            font-size: 0.8rem; font-weight: 700; color: var(--text-primary);
            display: flex; align-items: center; gap: 6px;
        }
        .tdt-columns-title i { color: #06b6d4; }
        .tdt-add-col-btn {
            padding: 5px 12px; border-radius: 8px;
            border: 1px dashed rgba(6, 182, 212, 0.4);
            background: rgba(6, 182, 212, 0.06);
            color: #06b6d4; cursor: pointer;
            font-size: 0.72rem; font-weight: 600;
            display: flex; align-items: center; gap: 4px;
            transition: all 0.2s;
        }
        .tdt-add-col-btn:hover {
            background: rgba(6, 182, 212, 0.15);
            border-color: #06b6d4;
            transform: translateY(-1px);
        }
        .tdt-columns-table {
            width: 100%; border-collapse: separate;
            border-spacing: 0; border-radius: 10px;
            overflow: hidden;
            border: 1px solid var(--border-color);
            margin-bottom: 0.75rem;
        }
        .tdt-columns-table thead th {
            padding: 6px 8px; font-size: 0.62rem;
            font-weight: 700; text-transform: uppercase;
            letter-spacing: 0.5px; color: #06b6d4;
            background: rgba(6, 182, 212, 0.06);
            border-bottom: 1px solid var(--border-color);
            text-align: left; white-space: nowrap;
        }
        .tdt-columns-table tbody tr {
            transition: background 0.15s;
        }
        .tdt-columns-table tbody tr:hover {
            background: rgba(6, 182, 212, 0.03);
        }
        .tdt-columns-table tbody td {
            padding: 4px 4px; border-bottom: 1px solid rgba(255,255,255,0.03);
            vertical-align: middle;
        }
        .tdt-columns-table tbody tr:last-child td { border-bottom: none; }
        .tdt-col-input {
            width: 100%; padding: 5px 7px; border-radius: 6px;
            border: 1px solid transparent;
            background: var(--bg-tertiary);
            color: var(--text-primary);
            font-size: 0.72rem; font-family: 'JetBrains Mono', monospace;
            transition: all 0.2s;
        }
        .tdt-col-input:focus {
            border-color: rgba(6, 182, 212, 0.4);
            background: var(--bg-primary);
            outline: none;
        }
        .tdt-col-select {
            width: 100%; padding: 5px 4px; border-radius: 6px;
            border: 1px solid transparent;
            background: var(--bg-tertiary);
            color: var(--text-primary);
            font-size: 0.7rem; cursor: pointer; transition: all 0.2s;
        }
        .tdt-col-select:focus {
            border-color: rgba(6, 182, 212, 0.4);
            outline: none;
        }
        .tdt-col-props {
            display: flex; flex-wrap: wrap; gap: 4px; align-items: center;
            padding: 2px 0;
        }
        .tdt-col-chip {
            display: inline-flex; align-items: center; gap: 2px;
            padding: 2px 7px; border-radius: 6px;
            font-size: 0.6rem; font-weight: 700; letter-spacing: 0.3px;
            cursor: pointer; user-select: none;
            border: 1.5px solid transparent;
            transition: all 0.2s ease;
            opacity: 0.35;
        }
        .tdt-col-chip:hover { opacity: 0.7; }
        .tdt-col-chip.active { opacity: 1; }
        .tdt-col-chip input { display: none; }

        .tdt-col-chip[data-prop="nullable"] {
            color: #a78bfa; border-color: rgba(167,139,250,0.3); background: rgba(167,139,250,0.05);
        }
        .tdt-col-chip[data-prop="nullable"].active {
            background: rgba(167,139,250,0.18); border-color: rgba(167,139,250,0.6);
            box-shadow: 0 0 8px rgba(167,139,250,0.2);
        }
        .tdt-col-chip[data-prop="pk"] {
            color: #f59e0b; border-color: rgba(245,158,11,0.3); background: rgba(245,158,11,0.05);
        }
        .tdt-col-chip[data-prop="pk"].active {
            background: rgba(245,158,11,0.18); border-color: rgba(245,158,11,0.6);
            box-shadow: 0 0 8px rgba(245,158,11,0.2);
        }
        .tdt-col-chip[data-prop="ai"] {
            color: #10b981; border-color: rgba(16,185,129,0.3); background: rgba(16,185,129,0.05);
        }
        .tdt-col-chip[data-prop="ai"].active {
            background: rgba(16,185,129,0.18); border-color: rgba(16,185,129,0.6);
            box-shadow: 0 0 8px rgba(16,185,129,0.2);
        }
        .tdt-col-chip[data-prop="unique"] {
            color: #06b6d4; border-color: rgba(6,182,212,0.3); background: rgba(6,182,212,0.05);
        }
        .tdt-col-chip[data-prop="unique"].active {
            background: rgba(6,182,212,0.18); border-color: rgba(6,182,212,0.6);
            box-shadow: 0 0 8px rgba(6,182,212,0.2);
        }
        .tdt-col-chip[data-prop="index"] {
            color: #f472b6; border-color: rgba(244,114,182,0.3); background: rgba(244,114,182,0.05);
        }
        .tdt-col-chip[data-prop="index"].active {
            background: rgba(244,114,182,0.18); border-color: rgba(244,114,182,0.6);
            box-shadow: 0 0 8px rgba(244,114,182,0.2);
        }
        .tdt-col-remove {
            width: 24px; height: 24px; border-radius: 6px;
            border: none; background: transparent;
            color: var(--text-muted); cursor: pointer;
            display: flex; align-items: center; justify-content: center;
            font-size: 0.65rem; transition: all 0.2s;
        }
        .tdt-col-remove:hover {
            background: rgba(239, 68, 68, 0.15); color: var(--danger);
        }
        /* Quick options */
        .tdt-quick-options {
            display: flex; flex-wrap: wrap; gap: 6px;
            margin-bottom: 0.75rem;
        }
        .tdt-quick-opt {
            padding: 4px 10px; border-radius: 20px;
            border: 1px solid var(--border-color);
            background: var(--bg-tertiary);
            color: var(--text-secondary);
            font-size: 0.68rem; cursor: pointer;
            transition: all 0.2s; display: flex;
            align-items: center; gap: 4px;
        }
        .tdt-quick-opt:hover {
            border-color: rgba(6, 182, 212, 0.4);
            color: #06b6d4;
        }
        .tdt-quick-opt.active {
            background: rgba(6, 182, 212, 0.12);
            border-color: rgba(6, 182, 212, 0.5);
            color: #06b6d4;
        }
        .tdt-quick-opt i { font-size: 0.6rem; }
        /* Saved tables list */
        .tdt-saved-list {
            margin-top: 0.5rem;
        }
        .tdt-saved-item {
            display: flex; align-items: center; gap: 6px;
            padding: 5px 8px; border-radius: 6px;
            background: rgba(6, 182, 212, 0.04);
            border: 1px solid rgba(6, 182, 212, 0.1);
            margin-bottom: 4px; font-size: 0.72rem;
            transition: all 0.2s;
        }
        .tdt-saved-item:hover {
            background: rgba(6, 182, 212, 0.08);
            border-color: rgba(6, 182, 212, 0.25);
        }
        .tdt-saved-item-name {
            flex: 1; font-weight: 600; color: var(--text-primary);
            font-family: 'JetBrains Mono', monospace;
        }
        .tdt-saved-item-cols {
            font-size: 0.62rem; color: var(--text-muted);
        }
        .tdt-saved-item-actions {
            display: flex; gap: 3px;
        }
        .tdt-saved-item-btn {
            width: 22px; height: 22px; border-radius: 4px;
            border: none; background: transparent;
            color: var(--text-muted); cursor: pointer;
            display: flex; align-items: center; justify-content: center;
            font-size: 0.6rem; transition: all 0.2s;
        }
        .tdt-saved-item-btn.edit:hover { background: rgba(6, 182, 212, 0.15); color: #06b6d4; }
        .tdt-saved-item-btn.delete:hover { background: rgba(239, 68, 68, 0.15); color: var(--danger); }
        /* Modal buttons */
        .tdt-btn {
            padding: 7px 16px; border-radius: 8px;
            border: none; cursor: pointer;
            font-size: 0.75rem; font-weight: 600;
            display: flex; align-items: center; gap: 5px;
            transition: all 0.2s;
        }
        .tdt-btn-primary {
            background: linear-gradient(135deg, #06b6d4, #0891b2);
            color: white;
        }
        .tdt-btn-primary:hover {
            box-shadow: 0 4px 15px rgba(6, 182, 212, 0.3);
            transform: translateY(-1px);
        }
        .tdt-btn-secondary {
            background: var(--bg-tertiary);
            color: var(--text-secondary);
            border: 1px solid var(--border-color);
        }
        .tdt-btn-secondary:hover { background: var(--bg-card); }
        .tdt-btn-danger {
            background: rgba(239, 68, 68, 0.1);
            color: var(--danger);
            border: 1px solid rgba(239, 68, 68, 0.2);
        }
        .tdt-btn-danger:hover { background: rgba(239, 68, 68, 0.2); }
        /* Autocomplete dropdown */
        .tdt-autocomplete {
            position: absolute;
            background: var(--bg-primary);
            border: 1px solid rgba(6, 182, 212, 0.3);
            border-radius: 8px;
            box-shadow: 0 8px 24px rgba(0,0,0,0.3);
            z-index: 10001;
            max-height: 180px; overflow-y: auto;
            display: none; min-width: 160px;
        }
        .tdt-autocomplete.show { display: block; }
        .tdt-ac-item {
            padding: 6px 10px; font-size: 0.72rem;
            cursor: pointer; transition: background 0.15s;
            font-family: 'JetBrains Mono', monospace;
            display: flex; align-items: center; justify-content: space-between;
        }
        .tdt-ac-item:hover, .tdt-ac-item.active {
            background: rgba(6, 182, 212, 0.1);
            color: #06b6d4;
        }
        .tdt-ac-item:first-child { border-radius: 8px 8px 0 0; }
        .tdt-ac-item:last-child { border-radius: 0 0 8px 8px; }
        .tdt-ac-hint {
            font-size: 0.58rem; color: var(--text-muted);
            font-family: inherit; font-style: italic;
        }
        /* Help tooltip button */
        .tdt-help-btn {
            display: inline-flex; align-items: center; justify-content: center;
            width: 16px; height: 16px; border-radius: 50%;
            border: 1.5px solid rgba(6, 182, 212, 0.35);
            background: rgba(6, 182, 212, 0.08);
            color: #06b6d4; font-size: 0.5rem; font-weight: 800;
            cursor: pointer; margin-left: 5px;
            transition: all 0.25s ease; position: relative;
            vertical-align: middle; line-height: 1;
            font-family: 'JetBrains Mono', monospace;
        }
        .tdt-help-btn:hover {
            background: rgba(6, 182, 212, 0.2);
            border-color: rgba(6, 182, 212, 0.6);
            box-shadow: 0 0 10px rgba(6, 182, 212, 0.25);
            transform: scale(1.15);
        }
        .tdt-help-popup {
            position: fixed;
            z-index: 10002;
            background: var(--bg-primary);
            border: 1.5px solid rgba(6, 182, 212, 0.35);
            border-radius: 12px;
            padding: 14px 16px;
            max-width: 310px; min-width: 240px;
            box-shadow: 0 12px 36px rgba(0, 0, 0, 0.4), 0 0 0 1px rgba(6, 182, 212, 0.08);
            animation: tdtHelpIn 0.2s ease;
            pointer-events: auto;
        }
        @keyframes tdtHelpIn {
            from { opacity: 0; transform: translateY(-6px) scale(0.96); }
            to   { opacity: 1; transform: translateY(0) scale(1); }
        }
        .tdt-help-popup::before {
            content: '';
            position: absolute; top: 0; left: 0; right: 0;
            height: 2.5px; border-radius: 12px 12px 0 0;
            background: linear-gradient(90deg, #06b6d4, #0891b2);
        }
        .tdt-help-title {
            font-size: 0.72rem; font-weight: 700;
            color: #06b6d4; margin-bottom: 6px;
            display: flex; align-items: center; gap: 5px;
        }
        .tdt-help-title i { font-size: 0.65rem; }
        .tdt-help-text {
            font-size: 0.68rem; color: var(--text-secondary);
            line-height: 1.55; margin: 0;
        }
        .tdt-help-text strong {
            color: var(--text-primary); font-weight: 600;
        }
        .tdt-help-text .tdt-help-recommend {
            display: inline-block; margin-top: 6px;
            padding: 3px 8px; border-radius: 6px;
            background: rgba(16, 185, 129, 0.1);
            border: 1px solid rgba(16, 185, 129, 0.25);
            color: #10b981; font-size: 0.62rem; font-weight: 700;
        }
        .tdt-help-overlay {
            position: fixed; top: 0; left: 0; right: 0; bottom: 0;
            z-index: 10001; background: transparent;
        }
        /* Section divider */
        .tdt-section-divider {
            height: 1px;
            background: linear-gradient(90deg, transparent, rgba(6, 182, 212, 0.2), transparent);
            margin: 0.75rem 0;
        }

        /* ═══════ Static Nodes Row Container ═══════ */
        .static-nodes-row {
            display: flex;
            flex-wrap: nowrap;
            gap: 6px;
            margin-bottom: 0.2rem;
            padding: 0.4rem 0.75rem;
            overflow-x: auto;
            overflow-y: hidden;
            scroll-behavior: smooth;
            -webkit-overflow-scrolling: touch;
            max-width: 100%;
            width: 100%;
            box-sizing: border-box;
            scrollbar-width: none;
            -ms-overflow-style: none;
        }
        .static-nodes-row::-webkit-scrollbar {
            display: none;
            width: 0;
            height: 0;
        }
        .static-nodes-row > .qst-container,
        .static-nodes-row > .ret-container,
        .static-nodes-row > .itc-container,
        .static-nodes-row > .spt-container,
        .static-nodes-row > .stg-container,
        .static-nodes-row > .exp-container {
            flex: 0 0 auto;
            min-width: 220px;
            margin-bottom: 0;
        }

        /* ═══════ Static Scrollbar Track ═══════ */
        .static-scrollbar-track {
            width: calc(100% - 1.5rem);
            height: 14px;
            background: rgba(99, 102, 241, 0.2);
            border: 1px solid rgba(99, 102, 241, 0.3);
            border-radius: 7px;
            margin: 0.5rem 0.75rem 0.25rem 0.75rem;
            position: relative;
            cursor: pointer;
            overflow: visible;
            box-sizing: border-box;
        }
        .static-scrollbar-thumb {
            position: absolute;
            top: 0;
            left: 0;
            height: 100%;
            width: 80px;
            min-width: 50px;
            background: linear-gradient(90deg, #6366f1, #8b5cf6);
            border-radius: 6px;
            cursor: grab;
            transition: background 0.2s, box-shadow 0.2s, left 0.1s ease-out;
            display: block !important;
            visibility: visible !important;
            opacity: 1 !important;
            z-index: 10;
            box-shadow: 0 2px 8px rgba(99, 102, 241, 0.4);
        }
        .static-scrollbar-thumb:hover {
            background: linear-gradient(90deg, #818cf8, #a78bfa);
            box-shadow: 0 0 12px rgba(99, 102, 241, 0.6);
            transform: scaleY(1.2);
        }
        .static-scrollbar-thumb:active,
        .static-scrollbar-thumb.dragging {
            cursor: grabbing;
            background: linear-gradient(90deg, #a5b4fc, #c4b5fd);
            box-shadow: 0 0 15px rgba(99, 102, 241, 0.7);
            transform: scaleY(1.3);
        }

        /* ═══════ Static Node: Quiz Question Generator (QST) ═══════ */
        .qst-container {
            margin-bottom: 0.6rem;
            border-radius: 10px;
            background: linear-gradient(135deg, rgba(99, 102, 241, 0.07), rgba(139, 92, 246, 0.04));
            border: 1.5px solid rgba(99, 102, 241, 0.22);
            overflow: hidden;
            transition: all 0.25s ease;
            position: relative;
            cursor: pointer;
        }
        .qst-glow-bar {
            position: absolute;
            top: 0; left: 0; right: 0;
            height: 2.5px;
            background: linear-gradient(90deg, #6366f1, #8b5cf6, #a78bfa, #8b5cf6, #6366f1);
            background-size: 200% 100%;
            animation: qstShimmer 3s linear infinite;
        }
        @keyframes qstShimmer {
            0% { background-position: 200% 0; }
            100% { background-position: -200% 0; }
        }
        .qst-container:hover {
            border-color: rgba(99, 102, 241, 0.42);
            box-shadow: 0 2px 14px rgba(99, 102, 241, 0.12);
            transform: translateY(-1px);
        }
        .qst-container.checked {
            border-color: rgba(99, 102, 241, 0.6);
            background: linear-gradient(135deg, rgba(99, 102, 241, 0.13), rgba(139, 92, 246, 0.07));
            box-shadow: 0 2px 18px rgba(99, 102, 241, 0.18);
        }
        .qst-inner {
            display: flex;
            align-items: center;
            padding: 0.55rem 0.7rem;
            gap: 0.45rem;
        }
        .qst-checkbox { flex-shrink: 0; cursor: pointer; }
        .qst-checkbox input { display: none; }
        .qst-check-box {
            width: 20px; height: 20px;
            border: 2px solid rgba(99, 102, 241, 0.35);
            border-radius: 5px;
            display: flex; align-items: center; justify-content: center;
            transition: all 0.2s;
            background: var(--bg-tertiary);
        }
        .qst-check-box i { font-size: 0.65rem; color: white; opacity: 0; transform: scale(0); transition: all 0.2s; }
        .qst-container.checked .qst-check-box {
            background: linear-gradient(135deg, #6366f1, #8b5cf6);
            border-color: #6366f1;
        }
        .qst-container.checked .qst-check-box i { opacity: 1; transform: scale(1); }
        .qst-body { flex: 1; min-width: 0; }
        .qst-badges {
            display: flex; align-items: center; gap: 4px;
            margin-bottom: 2px;
        }
        .qst-badge-static {
            display: inline-flex; align-items: center; gap: 3px;
            font-size: 0.57rem; font-weight: 700;
            text-transform: uppercase; letter-spacing: 0.4px;
            color: #a78bfa;
            background: rgba(139, 92, 246, 0.12);
            padding: 1px 6px; border-radius: 4px;
        }
        .qst-badge-type {
            display: inline-flex; align-items: center; gap: 3px;
            font-size: 0.57rem; font-weight: 700;
            text-transform: uppercase; letter-spacing: 0.4px;
            color: #818cf8;
            background: rgba(99, 102, 241, 0.1);
            padding: 1px 6px; border-radius: 4px;
        }
        .qst-name {
            font-size: 0.82rem; font-weight: 600;
            color: var(--text-primary);
            white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
        }
        .qst-preview {
            font-size: 0.67rem; color: var(--text-muted);
            white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
            margin-top: 1px;
        }
        .qst-actions {
            display: flex; gap: 4px; flex-shrink: 0;
            opacity: 0.55; transition: opacity 0.2s;
        }
        .qst-container:hover .qst-actions { opacity: 1; }
        .qst-action-btn {
            width: 26px; height: 26px;
            border-radius: 6px; border: none;
            background: rgba(99, 102, 241, 0.1);
            color: var(--text-muted);
            cursor: pointer;
            display: flex; align-items: center; justify-content: center;
            transition: all 0.2s; font-size: 0.7rem;
        }
        .qst-action-btn.qst-copy:hover {
            background: rgba(16, 185, 129, 0.18); color: var(--success);
            transform: scale(1.1);
        }
        .qst-action-btn.qst-push:hover {
            background: rgba(99, 102, 241, 0.22); color: #818cf8;
            transform: scale(1.1);
        }

        /* QST Answer Modal */
        .qst-modal-overlay {
            position: fixed; top: 0; left: 0; right: 0; bottom: 0;
            background: rgba(0, 0, 0, 0.6);
            backdrop-filter: blur(8px);
            z-index: 10500;
            display: none; align-items: center; justify-content: center;
        }
        .qst-modal-overlay.active { display: flex; }
        .qst-modal {
            background: var(--bg-primary);
            border: 1.5px solid rgba(99, 102, 241, 0.3);
            border-radius: 16px;
            width: 420px; max-width: 95vw;
            box-shadow: 0 24px 60px rgba(0,0,0,0.45), 0 0 0 1px rgba(99,102,241,0.08);
            animation: qstModalIn 0.25s ease;
            overflow: hidden;
        }
        @keyframes qstModalIn {
            from { opacity: 0; transform: translateY(16px) scale(0.97); }
            to   { opacity: 1; transform: translateY(0) scale(1); }
        }
        .qst-modal-header {
            padding: 0.9rem 1.1rem 0.75rem;
            border-bottom: 1px solid rgba(99, 102, 241, 0.12);
            background: linear-gradient(135deg, rgba(99,102,241,0.08), rgba(139,92,246,0.04));
            display: flex; align-items: center; justify-content: space-between;
        }
        .qst-modal-title {
            display: flex; align-items: center; gap: 7px;
            font-size: 0.92rem; font-weight: 700; color: var(--text-primary);
        }
        .qst-modal-title i { color: #818cf8; font-size: 0.9rem; }
        .qst-modal-close {
            width: 28px; height: 28px; border-radius: 7px;
            border: 1px solid var(--border-color);
            background: var(--bg-tertiary); color: var(--text-muted);
            cursor: pointer; display: flex; align-items: center; justify-content: center;
            font-size: 0.75rem; transition: all 0.2s;
        }
        .qst-modal-close:hover { background: rgba(239,68,68,0.15); color: var(--danger); border-color: rgba(239,68,68,0.3); }
        .qst-modal-body { padding: 1rem 1.1rem; }
        .qst-modal-hint {
            font-size: 0.75rem; color: var(--text-muted);
            line-height: 1.55; margin-bottom: 0.85rem;
            padding: 0.55rem 0.75rem;
            background: rgba(99,102,241,0.06);
            border-radius: 8px;
            border-left: 3px solid rgba(99,102,241,0.35);
        }
        .qst-modal-hint strong { color: var(--text-primary); }
        .qst-modal-hint code {
            font-family: 'JetBrains Mono', monospace;
            font-size: 0.68rem;
            background: rgba(99,102,241,0.12);
            padding: 1px 5px; border-radius: 4px;
            color: #a78bfa;
        }
        .qst-input-wrap { display: flex; flex-direction: column; gap: 5px; }
        .qst-input-label {
            font-size: 0.72rem; font-weight: 600;
            color: var(--text-secondary);
            display: flex; align-items: center; gap: 5px;
        }
        .qst-input-label i { color: #818cf8; }
        .qst-input {
            width: 100%; padding: 0.6rem 0.85rem;
            border-radius: 9px;
            border: 1.5px solid rgba(99,102,241,0.25);
            background: var(--bg-secondary);
            color: var(--text-primary);
            font-size: 0.82rem;
            font-family: 'JetBrains Mono', monospace;
            transition: all 0.2s;
            outline: none;
        }
        .qst-input:focus {
            border-color: rgba(99,102,241,0.55);
            box-shadow: 0 0 0 3px rgba(99,102,241,0.1);
        }
        .qst-modal-footer {
            padding: 0.7rem 1.1rem;
            border-top: 1px solid var(--border-color);
            background: var(--bg-secondary);
            display: flex; align-items: center; justify-content: flex-end; gap: 8px;
        }
        .qst-btn-cancel {
            padding: 0.45rem 1rem; border-radius: 7px;
            border: 1px solid var(--border-color);
            background: var(--bg-tertiary); color: var(--text-secondary);
            font-size: 0.78rem; font-weight: 600; cursor: pointer;
            display: flex; align-items: center; gap: 5px;
            transition: all 0.2s;
        }
        .qst-btn-cancel:hover { background: var(--bg-card); color: var(--text-primary); }
        .qst-btn-push {
            padding: 0.45rem 1.1rem; border-radius: 7px;
            border: none;
            background: linear-gradient(135deg, #6366f1, #8b5cf6);
            color: white;
            font-size: 0.78rem; font-weight: 600; cursor: pointer;
            display: flex; align-items: center; gap: 5px;
            transition: all 0.2s;
            box-shadow: 0 4px 14px rgba(99,102,241,0.3);
        }
        .qst-btn-push:hover {
            transform: translateY(-1px);
            box-shadow: 0 6px 18px rgba(99,102,241,0.45);
        }

        /* ═══════ Static Node: Reverse Engineer (RET) ═══════ */
        .ret-container {
            margin-bottom: 0.6rem;
            border-radius: 10px;
            background: linear-gradient(135deg, rgba(16, 185, 129, 0.07), rgba(5, 150, 105, 0.04));
            border: 1.5px solid rgba(16, 185, 129, 0.22);
            overflow: hidden;
            transition: all 0.25s ease;
            position: relative;
            cursor: pointer;
        }
        .ret-glow-bar {
            position: absolute;
            top: 0; left: 0; right: 0;
            height: 2.5px;
            background: linear-gradient(90deg, #10b981, #059669, #34d399, #059669, #10b981);
            background-size: 200% 100%;
            animation: retShimmer 3s linear infinite;
        }
        @keyframes retShimmer {
            0% { background-position: 200% 0; }
            100% { background-position: -200% 0; }
        }
        .ret-container:hover {
            border-color: rgba(16, 185, 129, 0.42);
            box-shadow: 0 2px 14px rgba(16, 185, 129, 0.12);
            transform: translateY(-1px);
        }
        .ret-container.checked {
            border-color: rgba(16, 185, 129, 0.6);
            background: linear-gradient(135deg, rgba(16, 185, 129, 0.13), rgba(5, 150, 105, 0.07));
            box-shadow: 0 2px 18px rgba(16, 185, 129, 0.18);
        }
        .ret-inner {
            display: flex;
            align-items: center;
            padding: 0.55rem 0.7rem;
            gap: 0.45rem;
        }
        .ret-checkbox { flex-shrink: 0; cursor: pointer; }
        .ret-checkbox input { display: none; }
        .ret-check-box {
            width: 20px; height: 20px;
            border: 2px solid rgba(16, 185, 129, 0.35);
            border-radius: 5px;
            display: flex; align-items: center; justify-content: center;
            transition: all 0.2s;
            background: var(--bg-tertiary);
        }
        .ret-check-box i { font-size: 0.65rem; color: white; opacity: 0; transform: scale(0); transition: all 0.2s; }
        .ret-container.checked .ret-check-box {
            background: linear-gradient(135deg, #10b981, #059669);
            border-color: #10b981;
        }
        .ret-container.checked .ret-check-box i { opacity: 1; transform: scale(1); }
        .ret-body { flex: 1; min-width: 0; }
        .ret-badges {
            display: flex; align-items: center; gap: 4px;
            margin-bottom: 2px;
        }
        .ret-badge-static {
            display: inline-flex; align-items: center; gap: 3px;
            font-size: 0.57rem; font-weight: 700;
            text-transform: uppercase; letter-spacing: 0.4px;
            color: #34d399;
            background: rgba(16, 185, 129, 0.12);
            padding: 1px 6px; border-radius: 4px;
        }
        .ret-badge-type {
            display: inline-flex; align-items: center; gap: 3px;
            font-size: 0.57rem; font-weight: 700;
            text-transform: uppercase; letter-spacing: 0.4px;
            color: #6ee7b7;
            background: rgba(16, 185, 129, 0.1);
            padding: 1px 6px; border-radius: 4px;
        }
        .ret-name {
            font-size: 0.82rem; font-weight: 600;
            color: var(--text-primary);
            white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
        }
        .ret-preview {
            font-size: 0.67rem; color: var(--text-muted);
            white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
            margin-top: 1px;
        }
        .ret-actions {
            display: flex; gap: 4px; flex-shrink: 0;
            opacity: 0.55; transition: opacity 0.2s;
        }
        .ret-container:hover .ret-actions { opacity: 1; }
        .ret-action-btn {
            width: 26px; height: 26px;
            border-radius: 6px; border: none;
            background: rgba(16, 185, 129, 0.1);
            color: var(--text-muted);
            cursor: pointer;
            display: flex; align-items: center; justify-content: center;
            transition: all 0.2s; font-size: 0.7rem;
        }
        .ret-action-btn.ret-copy:hover {
            background: rgba(16, 185, 129, 0.18); color: var(--success);
            transform: scale(1.1);
        }
        .ret-action-btn.ret-push:hover {
            background: rgba(16, 185, 129, 0.22); color: #34d399;
            transform: scale(1.1);
        }

        /* RET Code Modal */
        .ret-modal-overlay {
            position: fixed; top: 0; left: 0; right: 0; bottom: 0;
            background: rgba(0, 0, 0, 0.6);
            backdrop-filter: blur(8px);
            z-index: 10500;
            display: none; align-items: center; justify-content: center;
        }
        .ret-modal-overlay.active { display: flex; }
        .ret-modal {
            background: var(--bg-primary);
            border: 1.5px solid rgba(16, 185, 129, 0.3);
            border-radius: 16px;
            width: 520px; max-width: 95vw;
            box-shadow: 0 24px 60px rgba(0,0,0,0.45), 0 0 0 1px rgba(16,185,129,0.08);
            animation: retModalIn 0.25s ease;
            overflow: hidden;
        }
        @keyframes retModalIn {
            from { opacity: 0; transform: translateY(16px) scale(0.97); }
            to   { opacity: 1; transform: translateY(0) scale(1); }
        }
        .ret-modal-header {
            padding: 0.9rem 1.1rem 0.75rem;
            border-bottom: 1px solid rgba(16, 185, 129, 0.12);
            background: linear-gradient(135deg, rgba(16,185,129,0.08), rgba(5,150,105,0.04));
            display: flex; align-items: center; justify-content: space-between;
        }
        .ret-modal-title {
            display: flex; align-items: center; gap: 7px;
            font-size: 0.92rem; font-weight: 700; color: var(--text-primary);
        }
        .ret-modal-title i { color: #34d399; font-size: 0.9rem; }
        .ret-modal-close {
            width: 28px; height: 28px; border-radius: 7px;
            border: 1px solid var(--border-color);
            background: var(--bg-tertiary); color: var(--text-muted);
            cursor: pointer; display: flex; align-items: center; justify-content: center;
            font-size: 0.75rem; transition: all 0.2s;
        }
        .ret-modal-close:hover { background: rgba(239,68,68,0.15); color: var(--danger); border-color: rgba(239,68,68,0.3); }
        .ret-modal-body { padding: 1rem 1.1rem; }
        .ret-modal-hint {
            font-size: 0.75rem; color: var(--text-muted);
            line-height: 1.55; margin-bottom: 0.85rem;
            padding: 0.55rem 0.75rem;
            background: rgba(16,185,129,0.06);
            border-radius: 8px;
            border-left: 3px solid rgba(16,185,129,0.35);
        }
        .ret-modal-hint strong { color: var(--text-primary); }
        .ret-modal-hint code {
            font-family: 'JetBrains Mono', monospace;
            font-size: 0.68rem;
            background: rgba(16,185,129,0.12);
            padding: 1px 5px; border-radius: 4px;
            color: #34d399;
        }
        .ret-input-wrap { display: flex; flex-direction: column; gap: 5px; }
        .ret-input-label {
            font-size: 0.72rem; font-weight: 600;
            color: var(--text-secondary);
            display: flex; align-items: center; gap: 5px;
        }
        .ret-input-label i { color: #34d399; }
        .ret-textarea {
            width: 100%; padding: 0.6rem 0.85rem;
            border-radius: 9px;
            border: 1.5px solid rgba(16,185,129,0.25);
            background: var(--bg-secondary);
            color: var(--text-primary);
            font-size: 0.78rem;
            font-family: 'JetBrains Mono', monospace;
            transition: all 0.2s;
            outline: none;
            resize: vertical;
            min-height: 120px;
            max-height: 300px;
            line-height: 1.5;
        }
        .ret-textarea:focus {
            border-color: rgba(16,185,129,0.55);
            box-shadow: 0 0 0 3px rgba(16,185,129,0.1);
        }
        .ret-modal-footer {
            padding: 0.7rem 1.1rem;
            border-top: 1px solid var(--border-color);
            background: var(--bg-secondary);
            display: flex; align-items: center; justify-content: flex-end; gap: 8px;
        }
        .ret-btn-cancel {
            padding: 0.45rem 1rem; border-radius: 7px;
            border: 1px solid var(--border-color);
            background: var(--bg-tertiary); color: var(--text-secondary);
            font-size: 0.78rem; font-weight: 600; cursor: pointer;
            display: flex; align-items: center; gap: 5px;
            transition: all 0.2s;
        }
        .ret-btn-cancel:hover { background: var(--bg-card); color: var(--text-primary); }
        .ret-btn-push {
            padding: 0.45rem 1.1rem; border-radius: 7px;
            border: none;
            background: linear-gradient(135deg, #10b981, #059669);
            color: white;
            font-size: 0.78rem; font-weight: 600; cursor: pointer;
            display: flex; align-items: center; gap: 5px;
            transition: all 0.2s;
            box-shadow: 0 4px 14px rgba(16,185,129,0.3);
        }
        .ret-btn-push:hover {
            transform: translateY(-1px);
            box-shadow: 0 6px 18px rgba(16,185,129,0.45);
        }

        /* ═══════════════════════════════════════════════════════════
           IMAGE TO CODE (ITC) — Static Node
           ═══════════════════════════════════════════════════════════ */
        .itc-container {
            position: relative; border-radius: 10px; cursor: pointer;
            background: var(--bg-card);
            border: 1px solid var(--border-color);
            transition: all 0.3s ease; overflow: hidden;
        }
        .itc-container:hover {
            border-color: rgba(245,158,11,0.5);
            box-shadow: 0 4px 18px rgba(245,158,11,0.12);
            transform: translateY(-1px);
        }
        .itc-container.checked {
            border-color: rgba(245,158,11,0.6);
            box-shadow: 0 0 0 1px rgba(245,158,11,0.15), 0 4px 18px rgba(245,158,11,0.12);
        }
        .itc-glow-bar {
            position: absolute; top: 0; left: 0; right: 0; height: 2px;
            background: linear-gradient(90deg, #f59e0b, #d97706, #f59e0b);
            opacity: 0.7;
        }
        .itc-inner {
            display: flex; align-items: center; gap: 10px;
            padding: 10px 12px;
        }
        .itc-checkbox { flex-shrink: 0; }
        .itc-checkbox input { display: none; }
        .itc-check-box {
            width: 18px; height: 18px; border-radius: 5px;
            border: 2px solid var(--border-color);
            display: flex; align-items: center; justify-content: center;
            transition: all 0.25s; background: var(--bg-tertiary);
        }
        .itc-check-box i { font-size: 9px; color: transparent; transition: 0.2s; }
        .itc-container.checked .itc-check-box {
            background: linear-gradient(135deg, #f59e0b, #d97706);
            border-color: #f59e0b;
        }
        .itc-container.checked .itc-check-box i { color: white; }
        .itc-body { flex: 1; min-width: 0; }
        .itc-badges { display: flex; gap: 5px; margin-bottom: 3px; }
        .itc-badge-static {
            font-size: 0.6rem; padding: 1px 6px; border-radius: 4px;
            background: rgba(245,158,11,0.12); color: #f59e0b;
            font-weight: 700; display: flex; align-items: center; gap: 3px;
        }
        .itc-badge-type {
            font-size: 0.6rem; padding: 1px 6px; border-radius: 4px;
            background: rgba(217,119,6,0.1); color: #d97706;
            font-weight: 600; display: flex; align-items: center; gap: 3px;
        }
        .itc-name {
            font-size: 0.82rem; font-weight: 700;
            color: var(--text-primary); margin-bottom: 1px;
        }
        .itc-preview {
            font-size: 0.68rem; color: var(--text-muted);
            white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
        }
        .itc-actions { display: flex; gap: 4px; flex-shrink: 0; }
        .itc-action-btn {
            width: 28px; height: 28px; border-radius: 6px; border: none;
            display: flex; align-items: center; justify-content: center;
            cursor: pointer; transition: all 0.2s; font-size: 0.72rem;
        }
        .itc-copy {
            background: rgba(245,158,11,0.1); color: #f59e0b;
        }
        .itc-copy:hover {
            background: rgba(245,158,11,0.25); transform: scale(1.08);
        }
        .itc-push {
            background: linear-gradient(135deg, #f59e0b, #d97706); color: white;
        }
        .itc-push:hover {
            transform: scale(1.08);
            box-shadow: 0 3px 12px rgba(245,158,11,0.35);
        }

        /* ── ITC Modal ── */
        .itc-modal-overlay {
            position: fixed; top: 0; left: 0; width: 100%; height: 100%;
            background: rgba(0,0,0,0.6); backdrop-filter: blur(6px);
            z-index: 10001; display: flex; align-items: center; justify-content: center;
            opacity: 0; visibility: hidden; transition: all 0.3s;
        }
        .itc-modal-overlay.active { opacity: 1; visibility: visible; }
        .itc-modal {
            background: var(--bg-primary); border-radius: 14px;
            border: 1px solid var(--border-color);
            width: 520px; max-width: 92vw; max-height: 85vh; overflow-y: auto;
            box-shadow: 0 20px 60px rgba(0,0,0,0.4);
            transform: translateY(20px) scale(0.96);
            transition: all 0.3s;
        }
        .itc-modal-overlay.active .itc-modal {
            transform: translateY(0) scale(1);
        }
        .itc-modal-header {
            display: flex; align-items: center; justify-content: space-between;
            padding: 14px 18px; border-bottom: 1px solid var(--border-color);
            background: linear-gradient(135deg, rgba(245,158,11,0.08), transparent);
        }
        .itc-modal-title {
            display: flex; align-items: center; gap: 8px;
            font-weight: 700; font-size: 0.95rem; color: #f59e0b;
        }
        .itc-modal-close {
            width: 28px; height: 28px; border-radius: 6px; border: none;
            background: var(--bg-tertiary); color: var(--text-secondary);
            cursor: pointer; display: flex; align-items: center; justify-content: center;
            transition: all 0.2s;
        }
        .itc-modal-close:hover { background: rgba(239,68,68,0.15); color: #ef4444; }
        .itc-modal-body { padding: 16px 18px; }
        .itc-modal-hint {
            font-size: 0.78rem; color: var(--text-secondary);
            line-height: 1.5; margin-bottom: 14px;
            padding: 8px 10px; border-radius: 8px;
            background: rgba(245,158,11,0.06);
            border-left: 3px solid rgba(245,158,11,0.4);
        }
        .itc-input-wrap { margin-bottom: 12px; }
        .itc-input-label {
            display: flex; align-items: center; gap: 6px;
            font-size: 0.75rem; font-weight: 600; color: var(--text-secondary);
            margin-bottom: 6px;
        }
        .itc-file-zone {
            display: flex; flex-direction: column; align-items: center; justify-content: center;
            padding: 22px 16px; border-radius: 10px;
            border: 2px dashed rgba(245,158,11,0.35);
            background: rgba(245,158,11,0.04);
            cursor: pointer; transition: all 0.2s; gap: 6px;
        }
        .itc-file-zone:hover {
            border-color: rgba(245,158,11,0.6);
            background: rgba(245,158,11,0.08);
        }
        .itc-upload-icon { font-size: 1.5rem; color: #f59e0b; opacity: 0.7; }
        .itc-upload-text { font-size: 0.8rem; font-weight: 600; color: var(--text-secondary); }
        .itc-upload-sub { font-size: 0.67rem; color: var(--text-muted); }
        .itc-file-list { margin-top: 4px; }
        .itc-file-item {
            display: flex; align-items: center; justify-content: space-between;
            padding: 6px 10px; border-radius: 7px;
            background: var(--bg-tertiary); margin-bottom: 4px;
            border: 1px solid var(--border-color);
        }
        .itc-file-item-name {
            font-size: 0.75rem; color: var(--text-primary);
            font-family: 'JetBrains Mono', monospace;
            display: flex; align-items: center; gap: 6px;
        }
        .itc-file-item-name i { color: #f59e0b; font-size: 0.7rem; }
        .itc-file-remove {
            width: 20px; height: 20px; border-radius: 4px; border: none;
            background: rgba(239,68,68,0.1); color: #ef4444;
            cursor: pointer; display: flex; align-items: center; justify-content: center;
            font-size: 0.6rem; transition: all 0.2s;
        }
        .itc-file-remove:hover { background: rgba(239,68,68,0.25); }
        .itc-modal-footer {
            display: flex; align-items: center; justify-content: space-between;
            padding: 12px 18px; border-top: 1px solid var(--border-color);
        }
        .itc-file-count {
            font-size: 0.72rem; color: var(--text-muted); font-weight: 600;
        }
        .itc-modal-btns { display: flex; gap: 8px; }
        .itc-btn-cancel {
            padding: 0.45rem 1rem; border-radius: 7px;
            border: 1px solid var(--border-color);
            background: var(--bg-tertiary); color: var(--text-secondary);
            font-size: 0.78rem; font-weight: 600; cursor: pointer;
            display: flex; align-items: center; gap: 5px;
            transition: all 0.2s;
        }
        .itc-btn-cancel:hover { background: var(--bg-card); color: var(--text-primary); }
        .itc-btn-push {
            padding: 0.45rem 1.1rem; border-radius: 7px;
            border: none;
            background: linear-gradient(135deg, #f59e0b, #d97706);
            color: white;
            font-size: 0.78rem; font-weight: 600; cursor: pointer;
            display: flex; align-items: center; gap: 5px;
            transition: all 0.2s;
            box-shadow: 0 4px 14px rgba(245,158,11,0.3);
        }
        .itc-btn-push:hover {
            transform: translateY(-1px);
            box-shadow: 0 6px 18px rgba(245,158,11,0.45);
        }

        /* ═══════════════════════════════════════════════════════════
           SUPPORT TUTORIAL GENERATOR (STG) — Static Node
