        .stg-container.checked {
            border-color: rgba(6, 182, 212, 0.6);
            background: linear-gradient(135deg, rgba(6, 182, 212, 0.13), rgba(8, 145, 178, 0.07));
            box-shadow: 0 2px 18px rgba(6, 182, 212, 0.18);
        }
        .stg-glow-bar {
            position: absolute; top: 0; left: 0; right: 0; height: 2.5px;
            background: linear-gradient(90deg, #06b6d4, #0891b2, #22d3ee, #0891b2, #06b6d4);
            background-size: 200% 100%;
            animation: stgShimmer 3s linear infinite;
        }
        @keyframes stgShimmer {
            0% { background-position: 200% 0; }
            100% { background-position: -200% 0; }
        }
        .stg-inner {
            display: flex; align-items: center;
            padding: 0.55rem 0.7rem; gap: 0.45rem;
        }
        .stg-checkbox { flex-shrink: 0; cursor: pointer; }
        .stg-checkbox input { display: none; }
        .stg-check-box {
            width: 20px; height: 20px;
            border: 2px solid rgba(6, 182, 212, 0.35);
            border-radius: 5px;
            display: flex; align-items: center; justify-content: center;
            transition: all 0.2s;
            background: var(--bg-tertiary);
        }
        .stg-check-box i { font-size: 0.65rem; color: white; opacity: 0; transform: scale(0); transition: all 0.2s; }
        .stg-container.checked .stg-check-box {
            background: linear-gradient(135deg, #06b6d4, #0891b2);
            border-color: #06b6d4;
        }
        .stg-container.checked .stg-check-box i { opacity: 1; transform: scale(1); }
        .stg-body { flex: 1; min-width: 0; }
        .stg-badges {
            display: flex; align-items: center; gap: 4px;
            margin-bottom: 2px;
        }
        .stg-badge-static {
            display: inline-flex; align-items: center; gap: 3px;
            font-size: 0.57rem; font-weight: 700;
            text-transform: uppercase; letter-spacing: 0.4px;
            color: #22d3ee;
            background: rgba(6, 182, 212, 0.12);
            padding: 1px 6px; border-radius: 4px;
        }
        .stg-badge-type {
            display: inline-flex; align-items: center; gap: 3px;
            font-size: 0.57rem; font-weight: 700;
            text-transform: uppercase; letter-spacing: 0.4px;
            color: #67e8f9;
            background: rgba(6, 182, 212, 0.1);
            padding: 1px 6px; border-radius: 4px;
        }
        .stg-name {
            font-size: 0.82rem; font-weight: 600;
            color: var(--text-primary);
            white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
        }
        .stg-preview {
            font-size: 0.67rem; color: var(--text-muted);
            white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
            margin-top: 1px;
        }
        .stg-actions {
            display: flex; gap: 4px; flex-shrink: 0;
            opacity: 0.55; transition: opacity 0.2s;
        }
        .stg-container:hover .stg-actions { opacity: 1; }
        .stg-action-btn {
            width: 26px; height: 26px;
            border-radius: 6px; border: none;
            background: rgba(6, 182, 212, 0.1);
            color: var(--text-muted);
            cursor: pointer;
            display: flex; align-items: center; justify-content: center;
            transition: all 0.2s; font-size: 0.7rem;
        }
        .stg-action-btn.stg-copy:hover {
            background: rgba(6, 182, 212, 0.18); color: #22d3ee;
            transform: scale(1.1);
        }
        .stg-action-btn.stg-push:hover {
            background: rgba(6, 182, 212, 0.22); color: #67e8f9;
            transform: scale(1.1);
        }

        /* STG Filename Modal */
        .stg-modal-overlay {
            position: fixed; top: 0; left: 0; right: 0; bottom: 0;
            background: rgba(0, 0, 0, 0.6);
            backdrop-filter: blur(8px);
            z-index: 10500;
            display: none; align-items: center; justify-content: center;
        }
        .stg-modal-overlay.active { display: flex; }
        .stg-modal {
            background: var(--bg-primary);
            border: 1.5px solid rgba(6, 182, 212, 0.3);
            border-radius: 16px;
            width: 460px; max-width: 95vw;
            box-shadow: 0 24px 60px rgba(0,0,0,0.45), 0 0 0 1px rgba(6,182,212,0.08);
            animation: stgModalIn 0.25s ease;
            overflow: hidden;
        }
        @keyframes stgModalIn {
            from { opacity: 0; transform: translateY(16px) scale(0.97); }
            to   { opacity: 1; transform: translateY(0) scale(1); }
        }
        .stg-modal-header {
            padding: 0.9rem 1.1rem 0.75rem;
            border-bottom: 1px solid rgba(6, 182, 212, 0.12);
            background: linear-gradient(135deg, rgba(6,182,212,0.08), rgba(8,145,178,0.04));
            display: flex; align-items: center; justify-content: space-between;
        }
        .stg-modal-title {
            display: flex; align-items: center; gap: 7px;
            font-size: 0.92rem; font-weight: 700; color: var(--text-primary);
        }
        .stg-modal-title i { color: #22d3ee; font-size: 0.9rem; }
        .stg-modal-close {
            width: 28px; height: 28px; border-radius: 7px;
            border: 1px solid var(--border-color);
            background: var(--bg-tertiary); color: var(--text-muted);
            cursor: pointer; display: flex; align-items: center; justify-content: center;
            font-size: 0.75rem; transition: all 0.2s;
        }
        .stg-modal-close:hover { background: rgba(239,68,68,0.15); color: var(--danger); border-color: rgba(239,68,68,0.3); }
        .stg-modal-body { padding: 1rem 1.1rem; }
        .stg-modal-hint {
            font-size: 0.75rem; color: var(--text-muted);
            line-height: 1.55; margin-bottom: 0.85rem;
            padding: 0.55rem 0.75rem;
            background: rgba(6,182,212,0.06);
            border-radius: 8px;
            border-left: 3px solid rgba(6,182,212,0.35);
        }
        .stg-modal-hint strong { color: var(--text-primary); }
        .stg-modal-hint code {
            font-family: 'JetBrains Mono', monospace;
            font-size: 0.68rem;
            background: rgba(6,182,212,0.12);
            padding: 1px 5px; border-radius: 4px;
            color: #22d3ee;
        }
        .stg-input-wrap { display: flex; flex-direction: column; gap: 5px; }
        .stg-input-label {
            font-size: 0.72rem; font-weight: 600;
            color: var(--text-secondary);
            display: flex; align-items: center; gap: 5px;
        }
        .stg-input-label i { color: #22d3ee; }
        .stg-input-group {
            display: flex; align-items: center; gap: 0;
        }
        .stg-input {
            flex: 1; padding: 0.6rem 0.85rem;
            border-radius: 9px 0 0 9px;
            border: 1.5px solid rgba(6,182,212,0.25);
            border-right: none;
            background: var(--bg-secondary);
            color: var(--text-primary);
            font-size: 0.82rem;
            font-family: 'JetBrains Mono', monospace;
            transition: all 0.2s;
            outline: none;
        }
        .stg-input:focus {
            border-color: rgba(6,182,212,0.55);
            box-shadow: 0 0 0 3px rgba(6,182,212,0.1);
        }
        .stg-input-suffix {
            padding: 0.6rem 0.75rem;
            border-radius: 0 9px 9px 0;
            border: 1.5px solid rgba(6,182,212,0.25);
            border-left: none;
            background: rgba(6,182,212,0.08);
            color: #22d3ee;
            font-size: 0.78rem;
            font-family: 'JetBrains Mono', monospace;
            font-weight: 600;
            white-space: nowrap;
        }
        .stg-input:focus + .stg-input-suffix {
            border-color: rgba(6,182,212,0.55);
        }
        .stg-modal-footer {
            padding: 0.7rem 1.1rem;
            border-top: 1px solid var(--border-color);
            background: var(--bg-secondary);
            display: flex; align-items: center; justify-content: flex-end; gap: 8px;
        }
        .stg-btn-cancel {
            padding: 0.45rem 1rem; border-radius: 7px;
            border: 1px solid var(--border-color);
            background: var(--bg-tertiary); color: var(--text-secondary);
            font-size: 0.78rem; font-weight: 600; cursor: pointer;
            display: flex; align-items: center; gap: 5px;
            transition: all 0.2s;
        }
        .stg-btn-cancel:hover { background: var(--bg-card); color: var(--text-primary); }
        .stg-btn-push {
            padding: 0.45rem 1.1rem; border-radius: 7px;
            border: none;
            background: linear-gradient(135deg, #06b6d4, #0891b2);
            color: white;
            font-size: 0.78rem; font-weight: 600; cursor: pointer;
            display: flex; align-items: center; gap: 5px;
            transition: all 0.2s;
            box-shadow: 0 4px 14px rgba(6,182,212,0.3);
        }
        .stg-btn-push:hover {
            transform: translateY(-1px);
            box-shadow: 0 6px 18px rgba(6,182,212,0.45);
        }

        /* STG Phrase/Code Textarea */
        .stg-phrase-section {
            padding: 0.85rem 1.1rem 0.6rem;
            border-top: 1px solid rgba(6,182,212,0.1);
        }
        .stg-phrase-hint {
            font-size: 0.78rem;
            color: #94a3b8;
            margin: 0 0 8px;
            line-height: 1.4;
        }
        .stg-phrase-hint code {
            background: rgba(6,182,212,0.12);
            color: #67e8f9;
            padding: 1px 6px;
            border-radius: 4px;
            font-size: 0.76rem;
        }
        .stg-phrase-textarea {
            width: 100%;
            min-height: 100px;
            max-height: 260px;
            padding: 12px 14px;
            background: rgba(6,182,212,0.06);
            border: 1.5px solid rgba(6,182,212,0.2);
            border-radius: 10px;
            color: #e2e8f0;
            font-family: 'Fira Code', 'Cascadia Code', 'JetBrains Mono', monospace;
            font-size: 0.85rem;
            line-height: 1.55;
            resize: vertical;
            transition: border-color 0.25s, box-shadow 0.25s, background 0.25s;
            outline: none;
            box-sizing: border-box;
        }
        .stg-phrase-textarea::placeholder {
            color: rgba(148,163,184,0.45);
            font-style: italic;
        }
        .stg-phrase-textarea:focus {
            border-color: rgba(6,182,212,0.5);
            background: rgba(6,182,212,0.1);
            box-shadow: 0 0 0 3px rgba(6,182,212,0.1), 0 0 20px rgba(6,182,212,0.08);
        }
        .stg-phrase-textarea::-webkit-scrollbar {
            width: 6px;
        }
        .stg-phrase-textarea::-webkit-scrollbar-track {
            background: transparent;
        }
        .stg-phrase-textarea::-webkit-scrollbar-thumb {
            background: rgba(6,182,212,0.25);
            border-radius: 3px;
        }

        /* STG Image Picker */
        .stg-images-section {
            padding: 0.85rem 1.1rem 0.6rem;
            border-top: 1px solid rgba(6,182,212,0.1);
        }
        .stg-images-section .stg-input-label {
            margin-bottom: 4px;
        }
        .stg-optional-tag {
            font-size: 0.58rem; font-weight: 500;
            color: var(--text-muted); opacity: 0.7;
            text-transform: lowercase; letter-spacing: 0;
            margin-left: 4px;
        }
        .stg-images-hint {
            font-size: 0.68rem; color: var(--text-muted);
            margin-bottom: 0.55rem; line-height: 1.4;
        }
        .stg-drop-zone {
            border: 2px dashed rgba(6,182,212,0.28);
            border-radius: 10px;
            padding: 0.85rem;
            text-align: center;
            font-size: 0.72rem;
            color: var(--text-muted);
            cursor: pointer;
            transition: all 0.25s ease;
            background: rgba(6,182,212,0.03);
        }
        .stg-drop-zone:hover, .stg-drop-zone.dragover {
            border-color: #06b6d4;
            background: rgba(6,182,212,0.08);
            color: #22d3ee;
            transform: scale(1.01);
        }
        .stg-drop-zone i {
            font-size: 1.3rem; margin-bottom: 5px;
            display: block; color: rgba(6,182,212,0.45);
            transition: color 0.2s;
        }
        .stg-drop-zone:hover i { color: #22d3ee; }
        .stg-browse {
            color: #06b6d4; cursor: pointer;
            text-decoration: underline; font-weight: 600;
        }
        .stg-browse:hover { color: #22d3ee; }
        .stg-image-list {
            margin-top: 0.5rem;
            display: flex; flex-direction: column; gap: 4px;
            max-height: 180px; overflow-y: auto;
        }
        .stg-image-list::-webkit-scrollbar { width: 4px; }
        .stg-image-list::-webkit-scrollbar-thumb { background: rgba(6,182,212,0.25); border-radius: 3px; }
        .stg-image-item {
            display: flex; align-items: center; gap: 7px;
            padding: 5px 8px;
            background: var(--bg-card);
            border: 1px solid rgba(6,182,212,0.15);
            border-radius: 7px;
            font-size: 0.72rem;
            animation: stgImgFadeIn 0.2s ease;
        }
        @keyframes stgImgFadeIn {
            from { opacity: 0; transform: translateX(-6px); }
            to   { opacity: 1; transform: translateX(0); }
        }
        .stg-image-item i.fa-image { color: #22d3ee; font-size: 0.75rem; }
        .stg-image-item-name {
            flex: 1; overflow: hidden; text-overflow: ellipsis;
            white-space: nowrap; color: var(--text-primary);
            font-family: 'JetBrains Mono', monospace;
            font-size: 0.68rem;
        }
        .stg-image-item-remove {
            width: 20px; height: 20px; border-radius: 5px;
            border: none; background: rgba(239,68,68,0.1);
            color: var(--text-muted); cursor: pointer;
            display: flex; align-items: center; justify-content: center;
            font-size: 0.6rem; transition: all 0.2s;
            flex-shrink: 0;
        }
        .stg-image-item-remove:hover {
            background: rgba(239,68,68,0.2); color: #ef4444;
            transform: scale(1.1);
        }
        .stg-image-count {
            font-size: 0.65rem; color: #22d3ee;
            font-weight: 600; margin-top: 4px;
            display: flex; align-items: center; gap: 4px;
        }
        .stg-image-count i { font-size: 0.6rem; }
        .stg-clear-images {
            font-size: 0.62rem; color: var(--text-muted);
            cursor: pointer; margin-left: auto;
            background: none; border: none;
            text-decoration: underline;
            transition: color 0.2s;
        }
        .stg-clear-images:hover { color: #ef4444; }

        /* ═══════════════════════════════════════════════════════════
           EXPLAIN CODE (EXP) — Static Node
           ═══════════════════════════════════════════════════════════ */
        .exp-container {
            position: relative; border-radius: 10px; cursor: pointer;
            background: linear-gradient(135deg, rgba(139, 92, 246, 0.07), rgba(124, 58, 237, 0.04));
            border: 1.5px solid rgba(139, 92, 246, 0.22);
            overflow: hidden;
            transition: all 0.25s ease;
        }
        .exp-container:hover {
            border-color: rgba(139, 92, 246, 0.42);
            box-shadow: 0 2px 14px rgba(139, 92, 246, 0.12);
            transform: translateY(-1px);
        }
        .exp-container.checked {
            border-color: rgba(139, 92, 246, 0.6);
            background: linear-gradient(135deg, rgba(139, 92, 246, 0.13), rgba(124, 58, 237, 0.07));
            box-shadow: 0 2px 18px rgba(139, 92, 246, 0.18);
        }
        .exp-glow-bar {
            position: absolute; top: 0; left: 0; right: 0; height: 2.5px;
            background: linear-gradient(90deg, #8b5cf6, #7c3aed, #a78bfa, #7c3aed, #8b5cf6);
            background-size: 200% 100%;
            animation: expShimmer 3s linear infinite;
        }
        @keyframes expShimmer {
            0% { background-position: 200% 0; }
            100% { background-position: -200% 0; }
        }
        .exp-inner {
            display: flex; align-items: center;
            padding: 0.55rem 0.7rem; gap: 0.45rem;
        }
        .exp-checkbox { flex-shrink: 0; cursor: pointer; }
        .exp-checkbox input { display: none; }
        .exp-check-box {
            width: 20px; height: 20px;
            border: 2px solid rgba(139, 92, 246, 0.35);
            border-radius: 5px;
            display: flex; align-items: center; justify-content: center;
            transition: all 0.2s;
            background: var(--bg-tertiary);
        }
        .exp-check-box i { font-size: 0.65rem; color: white; opacity: 0; transform: scale(0); transition: all 0.2s; }
        .exp-container.checked .exp-check-box {
            background: linear-gradient(135deg, #8b5cf6, #7c3aed);
            border-color: #8b5cf6;
        }
        .exp-container.checked .exp-check-box i { opacity: 1; transform: scale(1); }
        .exp-body { flex: 1; min-width: 0; }
        .exp-badges {
            display: flex; align-items: center; gap: 4px;
            margin-bottom: 2px;
        }
        .exp-badge-static {
            display: inline-flex; align-items: center; gap: 3px;
            font-size: 0.57rem; font-weight: 700;
            text-transform: uppercase; letter-spacing: 0.4px;
            color: #a78bfa;
            background: rgba(139, 92, 246, 0.12);
            padding: 1px 6px; border-radius: 4px;
        }
        .exp-badge-type {
            display: inline-flex; align-items: center; gap: 3px;
            font-size: 0.57rem; font-weight: 700;
            text-transform: uppercase; letter-spacing: 0.4px;
            color: #c4b5fd;
            background: rgba(139, 92, 246, 0.1);
            padding: 1px 6px; border-radius: 4px;
        }
        .exp-name {
            font-size: 0.82rem; font-weight: 600;
            color: var(--text-primary);
            white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
        }
        .exp-preview {
            font-size: 0.67rem; color: var(--text-muted);
            white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
            margin-top: 1px;
        }
        .exp-actions {
            display: flex; gap: 4px; flex-shrink: 0;
            opacity: 0.55; transition: opacity 0.2s;
        }
        .exp-container:hover .exp-actions { opacity: 1; }
        .exp-action-btn {
            width: 26px; height: 26px;
            border-radius: 6px; border: none;
            background: rgba(139, 92, 246, 0.1);
