            border-radius: 8px;
            color: #fff;
            font-size: 12px;
            font-weight: 600;
            cursor: pointer;
            transition: all 0.3s ease;
            white-space: nowrap;
            box-shadow: 0 2px 8px rgba(99, 102, 241, 0.3);
        }
        .scalar-go-btn:hover {
            background: linear-gradient(135deg, #818cf8, #a78bfa);
            box-shadow: 0 4px 16px rgba(99, 102, 241, 0.4);
            transform: translateY(-1px);
        }
        .scalar-go-btn:active { transform: translateY(0); }

        .scalar-action-btn {
            display: flex;
            align-items: center;
            justify-content: center;
            width: 34px;
            height: 34px;
            background: rgba(99, 102, 241, 0.1);
            border: 1px solid rgba(99, 102, 241, 0.15);
            border-radius: 8px;
            color: #a5b4fc;
            font-size: 13px;
            cursor: pointer;
            transition: all 0.25s ease;
        }
        .scalar-action-btn:hover {
            background: rgba(99, 102, 241, 0.2);
            color: #c7d2fe;
            border-color: rgba(99, 102, 241, 0.3);
            transform: translateY(-1px);
        }
        .scalar-action-btn.active {
            background: rgba(99, 102, 241, 0.25);
            color: #e0e7ff;
            border-color: rgba(99, 102, 241, 0.4);
        }

        /* ── Device Bar ── */
        .scalar-device-bar {
            display: flex;
            flex-direction: column;
            gap: 8px;
            padding: 10px 14px;
            background: rgba(15, 15, 35, 0.5);
            border-bottom: 1px solid rgba(99, 102, 241, 0.08);
        }
        .scalar-category-filters {
            display: flex;
            gap: 6px;
            flex-wrap: wrap;
        }
        .scalar-cat-btn {
            display: flex;
            align-items: center;
            gap: 5px;
            padding: 5px 12px;
            background: rgba(99, 102, 241, 0.06);
            border: 1px solid rgba(99, 102, 241, 0.1);
            border-radius: 20px;
            color: #94a3b8;
            font-size: 11px;
            font-weight: 500;
            cursor: pointer;
            transition: all 0.25s ease;
        }
        .scalar-cat-btn:hover {
            background: rgba(99, 102, 241, 0.12);
            color: #c4b5fd;
            border-color: rgba(99, 102, 241, 0.2);
        }
        .scalar-cat-btn.active {
            background: linear-gradient(135deg, rgba(99, 102, 241, 0.2), rgba(139, 92, 246, 0.15));
            color: #c7d2fe;
            border-color: rgba(99, 102, 241, 0.35);
            box-shadow: 0 0 12px rgba(99, 102, 241, 0.1);
        }
        .scalar-cat-btn i { font-size: 11px; }

        .scalar-device-toggles {
            display: flex;
            gap: 5px;
            flex-wrap: wrap;
        }
        .scalar-dev-toggle {
            display: flex;
            align-items: center;
            gap: 5px;
            padding: 4px 10px;
            background: rgba(30, 30, 60, 0.5);
            border: 1px solid rgba(99, 102, 241, 0.08);
            border-radius: 6px;
            color: #64748b;
            font-size: 10px;
            font-weight: 500;
            cursor: pointer;
            transition: all 0.25s ease;
            user-select: none;
        }
        .scalar-dev-toggle:hover {
            background: rgba(99, 102, 241, 0.08);
            color: #94a3b8;
        }
        .scalar-dev-toggle.active {
            background: linear-gradient(135deg, rgba(99, 102, 241, 0.2), rgba(139, 92, 246, 0.15));
            color: #c7d2fe;
            border-color: rgba(99, 102, 241, 0.4);
            box-shadow: 0 0 12px rgba(99, 102, 241, 0.15), inset 0 0 8px rgba(99, 102, 241, 0.05);
        }
        .scalar-dev-dims { opacity: 0.6; font-size: 9px; }

        /* ── Preview Grid (single device, centered) ── */
        .scalar-grid {
            display: flex;
            justify-content: center;
            align-items: flex-start;
            padding: 20px;
            overflow: auto;
            max-height: calc(100vh - 250px);
            min-height: 300px;
        }

        /* Device Card */
        .scalar-device-card {
            display: flex;
            flex-direction: column;
            background: rgba(15, 15, 40, 0.6);
            border: 1px solid rgba(99, 102, 241, 0.12);
            border-radius: 14px;
            overflow: hidden;
            transition: all 0.35s ease;
            box-shadow: 0 4px 20px rgba(0, 0, 0, 0.2);
            animation: scalarCardIn 0.4s ease both;
        }
        .scalar-device-card:hover {
            border-color: rgba(99, 102, 241, 0.3);
            box-shadow: 0 8px 32px rgba(99, 102, 241, 0.1), 0 4px 20px rgba(0, 0, 0, 0.3);
            transform: translateY(-2px);
        }
        @keyframes scalarCardIn {
            from { opacity: 0; transform: translateY(16px) scale(0.97); }
            to   { opacity: 1; transform: translateY(0) scale(1); }
        }

        /* Device Card Header */
        .scalar-card-header {
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 8px 12px;
            background: linear-gradient(135deg, rgba(20, 20, 50, 0.9), rgba(25, 25, 55, 0.8));
            border-bottom: 1px solid rgba(99, 102, 241, 0.1);
        }
        .scalar-card-info {
            display: flex;
            align-items: center;
            gap: 8px;
        }
        .scalar-card-icon {
            width: 26px;
            height: 26px;
            display: flex;
            align-items: center;
            justify-content: center;
            border-radius: 6px;
            font-size: 12px;
        }
        .scalar-card-icon.phone {
            background: linear-gradient(135deg, rgba(59, 130, 246, 0.2), rgba(99, 102, 241, 0.15));
            color: #60a5fa;
        }
        .scalar-card-icon.tablet {
            background: linear-gradient(135deg, rgba(16, 185, 129, 0.2), rgba(52, 211, 153, 0.15));
            color: #34d399;
        }
        .scalar-card-icon.desktop {
            background: linear-gradient(135deg, rgba(245, 158, 11, 0.2), rgba(251, 191, 36, 0.15));
            color: #fbbf24;
        }
        .scalar-card-name {
            font-size: 11px;
            font-weight: 600;
            color: #e0e7ff;
            letter-spacing: 0.3px;
        }
        .scalar-card-size {
            font-size: 10px;
            color: #64748b;
            font-family: 'SF Mono', 'Consolas', monospace;
            background: rgba(15, 15, 35, 0.5);
            padding: 2px 8px;
            border-radius: 4px;
        }
        .scalar-card-actions {
            display: flex;
            gap: 4px;
        }
        .scalar-card-action {
            width: 24px;
            height: 24px;
            display: flex;
            align-items: center;
            justify-content: center;
            background: transparent;
            border: none;
            border-radius: 5px;
            color: #64748b;
            font-size: 11px;
            cursor: pointer;
            transition: all 0.2s;
        }
        .scalar-card-action:hover {
            background: rgba(99, 102, 241, 0.15);
            color: #a5b4fc;
        }

        /* Device Frame (bezel) */
        .scalar-device-frame {
            position: relative;
            overflow: hidden;
            background: #0a0a1a;
            margin: 0;
            scrollbar-width: none;
            -ms-overflow-style: none;
        }
        .scalar-device-frame::-webkit-scrollbar { display: none; }
        .scalar-device-frame iframe {
            display: block;
            border: none;
            transform-origin: top left;
            background: #fff;
        }

        /* Removed orient badge — orientation toggle now in card header */

        /* ── Empty State ── */
        .scalar-empty-state {
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            padding: 60px 20px;
            text-align: center;
        }
        .scalar-empty-icon {
            display: flex;
            gap: 16px;
            margin-bottom: 20px;
        }
        .scalar-empty-icon i {
