            width: 28px;
            height: 28px;
            display: flex;
            align-items: center;
            justify-content: center;
            background: rgba(239, 68, 68, 0.1);
            border: 1px solid rgba(239, 68, 68, 0.15);
            border-radius: 6px;
            color: #f87171;
            cursor: pointer;
            transition: all 0.2s;
        }
        .scalar-history-close:hover {
            background: rgba(239, 68, 68, 0.2);
        }
        .scalar-history-list {
            flex: 1;
            overflow-y: auto;
            padding: 8px;
        }
        .scalar-history-item {
            display: flex;
            align-items: center;
            gap: 10px;
            padding: 10px 12px;
            border-radius: 8px;
            cursor: pointer;
            transition: all 0.2s;
            margin-bottom: 2px;
        }
        .scalar-history-item:hover {
            background: rgba(99, 102, 241, 0.1);
        }
        .scalar-history-item i {
            color: rgba(139, 92, 246, 0.5);
            font-size: 11px;
            flex-shrink: 0;
        }
        .scalar-history-item-url {
            flex: 1;
            font-size: 11px;
            color: #a5b4fc;
            font-family: 'SF Mono', 'Consolas', monospace;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }
        .scalar-history-item-time {
            font-size: 9px;
            color: #475569;
            flex-shrink: 0;
        }
        .scalar-history-item-del {
            width: 20px;
            height: 20px;
            display: flex;
            align-items: center;
            justify-content: center;
            background: transparent;
            border: none;
            border-radius: 4px;
            color: #475569;
            font-size: 10px;
            cursor: pointer;
            opacity: 0;
            transition: all 0.2s;
            flex-shrink: 0;
        }
        .scalar-history-item:hover .scalar-history-item-del { opacity: 1; }
        .scalar-history-item-del:hover {
            background: rgba(239, 68, 68, 0.15);
            color: #f87171;
        }
        .scalar-clear-history {
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 6px;
            padding: 10px;
            margin: 8px;
            background: rgba(239, 68, 68, 0.06);
            border: 1px solid rgba(239, 68, 68, 0.1);
            border-radius: 8px;
            color: #94a3b8;
            font-size: 11px;
            cursor: pointer;
            transition: all 0.2s;
        }
        .scalar-clear-history:hover {
            background: rgba(239, 68, 68, 0.12);
            color: #f87171;
            border-color: rgba(239, 68, 68, 0.2);
        }

        /* ── Scrollbar for scalar panels ── */
        .scalar-grid::-webkit-scrollbar,
        .scalar-history-list::-webkit-scrollbar {
            width: 5px;
        }
        .scalar-grid::-webkit-scrollbar-track,
        .scalar-history-list::-webkit-scrollbar-track {
            background: transparent;
        }
        .scalar-grid::-webkit-scrollbar-thumb,
        .scalar-history-list::-webkit-scrollbar-thumb {
            background: rgba(99, 102, 241, 0.2);
            border-radius: 4px;
        }
        .scalar-grid::-webkit-scrollbar-thumb:hover,
        .scalar-history-list::-webkit-scrollbar-thumb:hover {
            background: rgba(99, 102, 241, 0.35);
        }

        /* ── Responsive adjustments ── */
        @media (max-width: 768px) {
            .scalar-header { flex-direction: column; }
            .scalar-grid { padding: 10px; gap: 10px; }
            .scalar-history-panel { width: 100%; }
            .scalar-go-btn span { display: none; }
        }
    </style>
