                                <div class="ds-resize-handle" data-section="frontendSection" title="Drag down to expand">
                                    <span class="ds-resize-handle-icon"></span>
                                </div>
                            </div>
                        </div>
                        
                        <!-- Folder Tree Template (displays picked folders visually) -->
                        <div class="folder-template-container" id="folderTemplateContainer">
                            <div class="folder-template-header">
                                <div class="ft-title">
                                    <i class="fas fa-sitemap"></i>
                                    <span>Project Folders</span>
                                    <span class="ft-badge" id="ftFolderCount">0</span>
                                </div>
                                <div class="ft-actions">
                                    <button onclick="ftCopyAllTrees()" title="Copy all trees to clipboard">
                                        <i class="fas fa-copy"></i> Copy
                                    </button>
                                    <button onclick="ftPushToProjectPrompts()" title="Push all folder trees to Project Prompts">
                                        <i class="fas fa-arrow-down"></i> Push
                                    </button>
                                    <button onclick="ftCollapseAll()" title="Collapse/Expand all folders">
                                        <i class="fas fa-compress-alt"></i>
                                    </button>
                                    <button class="ft-danger" onclick="ftClearAll()" title="Remove all folders">
                                        <i class="fas fa-trash-alt"></i>
                                    </button>
                                </div>
                            </div>
                            <div class="folder-template-body" id="ftFolderBody">
                            </div>
                            <div class="ft-resize-handle" id="ftResizeHandle" title="Drag to resize"></div>
                        </div>
                        
                        <!-- Project Prompts Section (Resizable) -->
                        <div class="project-notes-section" id="projectNotesSection">
                            <div class="project-notes-header">
                                <label class="dash-section-check notes-check" onclick="event.stopPropagation();" title="Include Project Prompts">
                                    <input type="checkbox" class="dash-sec-cb" data-section="prompts" checked onchange="onDashSectionCheckChange()">
                                    <span class="dash-check-box"><i class="fas fa-check"></i></span>
                                </label>
                                <div class="project-notes-title">
                                    <i class="fas fa-terminal"></i>
                                    <span>Project Prompts</span>
                                    
                                    <!-- Project Prompts Search Bar -->
                                    <div class="notes-search-bar" id="notesSearchBar">
                                        <i class="fas fa-search notes-search-icon"></i>
                                        <input type="text" 
                                               class="notes-search-input" 
                                               id="notesSearchInput" 
                                               placeholder="Search..." 
                                               autocomplete="off"
                                               spellcheck="false">
                                        <span class="notes-search-badge" id="notesSearchBadge">0 of 0</span>
                                        <div class="notes-search-nav">
                                            <button type="button" class="notes-search-nav-btn" onclick="notesSearchPrev()" title="Previous (Shift+Enter)">
                                                <i class="fas fa-chevron-up"></i>
                                            </button>
                                            <button type="button" class="notes-search-nav-btn" onclick="notesSearchNext()" title="Next (Enter)">
                                                <i class="fas fa-chevron-down"></i>
                                            </button>
                                        </div>
                                        <button type="button" class="notes-search-clear-btn" id="notesSearchClearBtn" onclick="clearNotesSearch()" title="Clear search (Esc)">
                                            <i class="fas fa-times" style="font-weight: 900;"></i>
                                        </button>
                                    </div>
                                </div>
                                
                                <!-- File Picker for Notes -->
                                <div class="notes-file-picker">
                                    <input type="file" 
                                           id="notesFilePicker" 
                                           multiple 
                                           onchange="onNotesFileSelect()" 
                                           style="display: none;">
                                    <button type="button" 
                                            class="notes-file-btn" 
                                            onclick="document.getElementById('notesFilePicker').click()" 
                                            title="Select files">
                                        <i class="fas fa-file-medical"></i>
                                    </button>
                                    <button type="button" class="notes-push-arrow" onclick="pushNotesToPrompt()" title="Push to Prompt Editor">
                                        <i class="fas fa-arrow-down"></i>
                                    </button>
                                    <div class="notes-selected-files" id="notesSelectedFiles"></div>
                                    <button type="button" 
                                            class="notes-push-btn" 
                                            id="notesPushBtn"
                                            onclick="pushFileNamesToNotes()" 
                                            title="Push file names to notes"
                                            style="display: none;">
                                        <i class="fas fa-arrow-down"></i>
                                    </button>
                                </div>
                                
                                <!-- Folder Path Indicator (between file picker and actions) -->
                                <div class="folder-path-indicator" id="folderPathIndicator">
                                    <i class="fas fa-link"></i>
                                    <span id="folderPathText">No folder selected</span>
                                </div>
                                
                                <div class="project-notes-actions">
                                    <button type="button" class="notes-btn send-to-file-btn" id="btnSendNotesToFile" onclick="sendNotesToPromptFile()" disabled title="Send to prompt.txt">
                                        <i class="fas fa-paper-plane"></i>
                                        <span>Send</span>
                                    </button>
                                    <button type="button" class="notes-btn push-to-prompt-btn" onclick="pushNotesToPrompt()" title="Push to Main Prompt Editor">
                                        <i class="fas fa-arrow-right"></i>
                                        <span>→ Editor</span>
                                    </button>
                                    <button type="button" class="notes-btn clear-notes-btn" onclick="clearProjectNotes()" title="Clear Notes">
                                        <i class="fas fa-times"></i>
                                        <span>Clear</span>
                                    </button>
                                    <button type="button" class="notes-btn collapse-notes-btn" onclick="toggleProjectNotes()" title="Collapse/Expand">
                                        <i class="fas fa-chevron-down" id="notesCollapseIcon"></i>
                                    </button>
                                </div>
                            </div>
                            <!-- Merged Project Management Bar -->
                            <div class="project-management-bar" id="projectManagementBar">
                                <div class="project-management-group">
                                    <div class="project-selector-wrap">
                                        <select class="project-selector" id="projectSelector" onchange="onProjectSelect()">
                                            <option value="">-- No Project --</option>
                                        </select>
                                        <i class="fas fa-chevron-down"></i>
                                    </div>
                                    <button type="button" class="project-btn new-btn" onclick="openNewProjectPopup()" title="New Project">
                                        <i class="fas fa-plus"></i>
                                        <span>New</span>
                                    </button>
                                    <button type="button" class="project-btn save-btn" onclick="saveCurrentProject()" title="Save Project">
                                        <i class="fas fa-save"></i>
                                        <span>Save</span>
                                    </button>
                                    <button type="button" class="project-btn save-new-btn" onclick="saveAsNewProject()" title="Save as New Project">
                                        <i class="fas fa-copy"></i>
                                        <span>Save New</span>
                                    </button>
                                    <button type="button" class="project-btn rename-btn" onclick="renameCurrentProject()" title="Rename Project">
                                        <i class="fas fa-pen"></i>
                                        <span>Rename</span>
                                    </button>
                                    <button type="button" class="project-btn load-btn" onclick="openLoadProjectPopup()" title="Load Project">
                                        <i class="fas fa-folder-open"></i>
                                        <span>Load</span>
                                    </button>
                                    <button type="button" class="project-btn delete-btn" onclick="deleteCurrentProject()" title="Delete Project">
                                        <i class="fas fa-trash"></i>
                                    </button>
                                    <button type="button" class="project-btn reset-btn" onclick="resetDashboardProject()" title="Reset Dashboard">
                                        <i class="fas fa-undo-alt"></i>
                                        <span>Reset</span>
                                    </button>
                                </div>
                                <div class="footer-divider"></div>
                                <div class="language-toggle-group" id="languageToggleGroup">
                                    <label class="dash-section-check lang-check" onclick="event.stopPropagation();" title="Include Language">
                                        <input type="checkbox" class="dash-sec-cb" data-section="language" onchange="onDashSectionCheckChange()">
                                        <span class="dash-check-box"><i class="fas fa-check"></i></span>
                                    </label>
                                    <div class="language-toggle-label">
                                        <i class="fas fa-language"></i>
                                        <span>Lang</span>
                                    </div>
                                    <div class="language-toggle-switch">
                                        <label class="lang-option arabic" onclick="setAppLanguage('arabic')">
                                            <span class="lang-flag">🇸🇦</span>
                                            <span>AR</span>
                                        </label>
                                        <label class="lang-option english active" onclick="setAppLanguage('english')">
                                            <span class="lang-flag">🇺🇸</span>
                                            <span>EN</span>
                                        </label>
                                        <label class="lang-option both" onclick="setAppLanguage('both')">
                                            <span class="lang-flag">🌐</span>
                                            <span>Both</span>
                                        </label>
                                        <label class="lang-option multi" onclick="setAppLanguage('multi')">
                                            <span class="lang-flag">🗺️</span>
                                            <span>Multi</span>
                                        </label>
                                    </div>
                                    <div class="default-lang-selector" id="defaultLangSelector">
                                        <span class="default-lang-label">Default:</span>
                                        <div class="default-lang-buttons">
                                            <button type="button" class="default-lang-btn" data-default="arabic" onclick="setDefaultLanguage('arabic')">
                                                <span class="btn-flag">🇸🇦</span> AR
                                            </button>
                                            <button type="button" class="default-lang-btn selected" data-default="english" onclick="setDefaultLanguage('english')">
                                                <span class="btn-flag">🇺🇸</span> EN
                                            </button>
                                        </div>
                                    </div>
                                    <div class="multi-lang-selector" id="multiLangSelector">
                                        <div class="multi-lang-header">
                                            <h4><i class="fas fa-globe"></i> Select Languages</h4>
                                            <button type="button" class="multi-lang-close" onclick="closeMultiLangSelector()">
                                                <i class="fas fa-times"></i>
                                            </button>
                                        </div>
                                        <div class="multi-lang-grid" id="multiLangGrid">
                                            <div class="multi-lang-item" data-lang="en" data-name="English" onclick="toggleMultiLang('en')"><span class="item-flag">🇺🇸</span><span class="item-code">EN</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="ar" data-name="Arabic" onclick="toggleMultiLang('ar')"><span class="item-flag">🇸🇦</span><span class="item-code">AR</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="fr" data-name="French" onclick="toggleMultiLang('fr')"><span class="item-flag">🇫🇷</span><span class="item-code">FR</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="es" data-name="Spanish" onclick="toggleMultiLang('es')"><span class="item-flag">🇪🇸</span><span class="item-code">ES</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="de" data-name="German" onclick="toggleMultiLang('de')"><span class="item-flag">🇩🇪</span><span class="item-code">DE</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="it" data-name="Italian" onclick="toggleMultiLang('it')"><span class="item-flag">🇮🇹</span><span class="item-code">IT</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="pt" data-name="Portuguese" onclick="toggleMultiLang('pt')"><span class="item-flag">🇵🇹</span><span class="item-code">PT</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="ru" data-name="Russian" onclick="toggleMultiLang('ru')"><span class="item-flag">🇷🇺</span><span class="item-code">RU</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="zh" data-name="Chinese" onclick="toggleMultiLang('zh')"><span class="item-flag">🇨🇳</span><span class="item-code">ZH</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="ja" data-name="Japanese" onclick="toggleMultiLang('ja')"><span class="item-flag">🇯🇵</span><span class="item-code">JA</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="ko" data-name="Korean" onclick="toggleMultiLang('ko')"><span class="item-flag">🇰🇷</span><span class="item-code">KO</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="hi" data-name="Hindi" onclick="toggleMultiLang('hi')"><span class="item-flag">🇮🇳</span><span class="item-code">HI</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="tr" data-name="Turkish" onclick="toggleMultiLang('tr')"><span class="item-flag">🇹🇷</span><span class="item-code">TR</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="nl" data-name="Dutch" onclick="toggleMultiLang('nl')"><span class="item-flag">🇳🇱</span><span class="item-code">NL</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="pl" data-name="Polish" onclick="toggleMultiLang('pl')"><span class="item-flag">🇵🇱</span><span class="item-code">PL</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="th" data-name="Thai" onclick="toggleMultiLang('th')"><span class="item-flag">🇹🇭</span><span class="item-code">TH</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="vi" data-name="Vietnamese" onclick="toggleMultiLang('vi')"><span class="item-flag">🇻🇳</span><span class="item-code">VI</span><i class="fas fa-check item-check"></i></div>
                                            <div class="multi-lang-item" data-lang="id" data-name="Indonesian" onclick="toggleMultiLang('id')"><span class="item-flag">🇮🇩</span><span class="item-code">ID</span><i class="fas fa-check item-check"></i></div>
                                        </div>
                                        <div class="multi-lang-default" id="multiLangDefault" style="display: none;">
                                            <div class="multi-lang-default-label">
                                                <i class="fas fa-star"></i> Default Language:
                                            </div>
                                            <div class="multi-lang-default-options" id="multiLangDefaultOptions"></div>
                                        </div>
                                        <div class="multi-lang-info">
                                            <i class="fas fa-info-circle"></i>
                                            <span id="multiLangCount">0 languages selected</span>
                                        </div>
                                    </div>
                                </div>
                                <div class="footer-divider"></div>
                                <div class="generate-group">
                                    <button type="button" class="dash-generate-btn" id="dashGenerateBtn" onclick="generateComprehensivePrompt()">
                                        <i class="fas fa-magic"></i>
                                        <span>Generate</span>
                                    </button>
                                </div>
                            </div>
                            <div class="project-notes-body collapsed" id="projectNotesBody">
                                <div class="notes-highlight-overlay" id="notesHighlightOverlay"></div>
                                <textarea class="project-notes-textarea" 
                                          id="projectNotesTextarea" 
                                          placeholder="Generated prompts will appear here. You can also add custom instructions..."
                                          oninput="onProjectNotesChange()"></textarea>
                                <div class="project-notes-resize-handle" id="notesResizeHandle">
                                    <i class="fas fa-grip-lines"></i>
                                </div>
                                <div class="notes-footer">
                                    <div class="notes-footer-voice-tools">
                                        <button class="nf-btn nf-btn-tts" id="btnTtsNotes" onclick="ttsNotesToggle()" title="Read aloud (British Female Voice)">
                                            <i class="fas fa-volume-up"></i> <span id="ttsNotesLabel">Read</span>
                                            <div class="tts-progress-mini" id="ttsNotesProgress"></div>
                                        </button>
                                        <button class="nf-btn nf-btn-tts-ar" id="btnTtsNotesAr" onclick="ttsNotesArToggle()" title="قراءة بصوت عربي أنثوي">
                                            <i class="fas fa-volume-up"></i> <span id="ttsNotesArLabel">اقرأ</span><span class="nf-ar-flag">AR</span>
                                            <div class="tts-progress-mini" id="ttsNotesArProgress"></div>
                                        </button>
                                        <button class="nf-btn nf-btn-stt" id="btnSttNotes" onclick="sttNotesToggle()" title="Voice dictation – speak to type">
                                            <i class="fas fa-microphone"></i> <span id="sttNotesLabel">Dictate</span>
                                            <span class="stt-dot-mini"></span>
                                        </button>
                                        <button class="nf-btn nf-btn-stt-ar" id="btnSttNotesAr" onclick="sttNotesArToggle()" title="إملاء عربي – تحدث بالعربية للكتابة">
                                            <i class="fas fa-microphone"></i> <span id="sttNotesArLabel">إملاء</span><span class="nf-ar-flag">AR</span>
                                            <span class="stt-ar-dot-mini"></span>
                                        </button>
                                        <button class="nf-btn nf-btn-copy" id="btnCopyNotes" onclick="copyNotesText()" title="Copy project prompts to clipboard">
                                            <i class="fas fa-copy"></i> <span id="copyNotesLabel">Copy</span>
                                        </button>
                                        <button class="nf-btn nf-btn-paste" id="btnPasteNotes" onclick="pasteNotesText()" title="Paste from clipboard into project prompts">
                                            <i class="fas fa-paste"></i> <span id="pasteNotesLabel">Paste</span>
                                        </button>
                                        <button class="nf-btn nf-btn-clear" id="btnClearNotes" onclick="clearNotesText()" title="Clear project prompts">
                                            <i class="fas fa-eraser"></i> <span id="clearNotesLabel">Clear</span>
                                        </button>
                                    </div>
                                    <button class="nf-btn-dir" id="btnNotesDirToggle" onclick="toggleNotesDir()" title="Toggle text direction (LTR / RTL)">
                                        <i class="fas fa-exchange-alt"></i>
                                        <span id="notesDirLabel">LTR</span>
                                    </button>
                                </div>
                            </div>
                        </div>
                        
                        <!-- Dashboard footer merged into project-notes-section above -->
                    </div>
                    
                    <div class="dash-db-empty" id="dbNoConnections" style="display: none;">
                        <span>No databases found</span>
                        <a href="javascript:void(0)" onclick="openDbManager()">+ Add</a>
                    </div>
                </div>
            </div>

            </div><!-- /mc-tab-panel workspace -->

            <!-- Unified: Saved Prompts + Prompt Editor -->
            <div class="unified-editor-section">
            <div class="saved-prompts-section">
                <!-- Unified Actions Bar: Title + Select All + Search -->
                <div class="saved-actions-bar">
                    <h3 class="saved-bar-title"><i class="fas fa-bookmark"></i> Saved Prompts</h3>
                    <label class="select-all-checkbox" title="Select/Deselect All Saved Prompts">
                        <input type="checkbox" id="selectAllSavedCheckbox" onchange="toggleAllSavedPrompts(this.checked)">
                        <span class="checkbox-custom"></span>
                        <span class="checkbox-label">Select All</span>
                    </label>
                    <span class="saved-counter" id="savedCounter">0/0</span>
                    <!-- Inline Steps Widget -->
                    <div class="distribution-section inline-steps-widget">
                        <div class="inline-steps-label" title="Work Distribution Steps">
                            <i class="fas fa-layer-group"></i>
                            <span>Steps</span>
                        </div>
                        <div class="inline-steps-slider">
                            <div class="slider-track">
                                <div class="slider-fill" id="sliderFill"></div>
                                <input type="range" min="1" max="30" value="1" class="slider-input" id="distributionSlider" oninput="updateDistribution(this.value)">
                            </div>
                        </div>
                        <div class="distribution-value" id="distributionValue">
                            <span class="value-number" id="valueNumber">1</span>
                            <span class="value-label">/ 30</span>
                        </div>
                        <label class="dist-append-check" id="distAppendCheck" onclick="toggleDistributionAppend(event)" title="Append steps to prompt">
                            <input type="checkbox" id="distributionEnabled">
                            <span class="check-box"><i class="fas fa-check"></i></span>
                        </label>
                    </div>
                    <div class="search-box saved-search-box">
                        <i class="fas fa-search"></i>
                        <input type="text" id="searchPrompts" placeholder="Search prompts...">
                        <button type="button" class="search-clear-btn" id="savedSearchClear" onclick="clearSavedSearch()" style="display: none;">
                            <i class="fas fa-times"></i>
                        </button>
                    </div>
                </div>
                
                <!-- Static Scrollbar (above static nodes) -->
                <div class="static-scrollbar-track" id="staticScrollbarTrack">
                    <div class="static-scrollbar-thumb" id="staticScrollbarThumb"></div>
                </div>
                
                <!-- Static Nodes Row: QST + RET -->
                <div class="static-nodes-row" id="staticNodesRow">
                    <!-- Static Node: Quiz Question Generator (QST) -->
                    <div class="qst-container" id="qstContainer" onclick="qstOpenModal()">
                        <div class="qst-glow-bar"></div>
                        <div class="qst-inner">
                            <div class="qst-checkbox" id="qstCheckboxWrap" onclick="event.stopPropagation(); qstToggleDirect()">
                                <input type="checkbox" id="qstCheckbox">
                                <div class="qst-check-box"><i class="fas fa-check"></i></div>
                            </div>
                            <div class="qst-body">
                                <div class="qst-badges">
                                    <span class="qst-badge-static"><i class="fas fa-thumbtack"></i> Static</span>
                                    <span class="qst-badge-type"><i class="fas fa-question-circle"></i> Quiz</span>
                                </div>
                                <div class="qst-name">Quiz Question Generator</div>
                                <div class="qst-preview">Generates a styled HTML quiz question — enter your answer to inject</div>
                            </div>
                            <div class="qst-actions" onclick="event.stopPropagation()">
                                <button type="button" class="qst-action-btn qst-copy" onclick="qstCopyPrompt()" title="Copy prompt">
                                    <i class="fas fa-copy"></i>
                                </button>
                                <button type="button" class="qst-action-btn qst-push" onclick="qstOpenModal()" title="Set answer & push">
                                    <i class="fas fa-bolt"></i>
                                </button>
                            </div>
                        </div>
                    </div>

                    <!-- Static Node: Reverse Engineer (RET) -->
                    <div class="ret-container" id="retContainer" onclick="retOpenModal()">
                        <div class="ret-glow-bar"></div>
                        <div class="ret-inner">
                            <div class="ret-checkbox" id="retCheckboxWrap" onclick="event.stopPropagation(); retToggleDirect()">
                                <input type="checkbox" id="retCheckbox">
                                <div class="ret-check-box"><i class="fas fa-check"></i></div>
                            </div>
                            <div class="ret-body">
                                <div class="ret-badges">
                                    <span class="ret-badge-static"><i class="fas fa-thumbtack"></i> Static</span>
                                    <span class="ret-badge-type"><i class="fas fa-sync-alt"></i> Reverse</span>
                                </div>
                                <div class="ret-name">Reverse Engineer</div>
                                <div class="ret-preview">Code → Prompt — paste code to generate a recreation prompt</div>
                            </div>
                            <div class="ret-actions" onclick="event.stopPropagation()">
                                <button type="button" class="ret-action-btn ret-copy" onclick="retCopyPrompt()" title="Copy prompt">
                                    <i class="fas fa-copy"></i>
                                </button>
                                <button type="button" class="ret-action-btn ret-push" onclick="retOpenModal()" title="Set code & push">
                                    <i class="fas fa-bolt"></i>
                                </button>
                            </div>
                        </div>
                    </div>

                    <!-- Static Node: Image to Code (ITC) -->
                    <div class="itc-container" id="itcContainer" onclick="itcOpenModal()">
                        <div class="itc-glow-bar"></div>
                        <div class="itc-inner">
                            <div class="itc-checkbox" id="itcCheckboxWrap" onclick="event.stopPropagation(); itcToggleDirect()">
                                <input type="checkbox" id="itcCheckbox">
                                <div class="itc-check-box"><i class="fas fa-check"></i></div>
                            </div>
                            <div class="itc-body">
                                <div class="itc-badges">
                                    <span class="itc-badge-static"><i class="fas fa-thumbtack"></i> Static</span>
                                    <span class="itc-badge-type"><i class="fas fa-image"></i> Image</span>
                                </div>
                                <div class="itc-name">Image to Code</div>
                                <div class="itc-preview">Image → HTML/CSS — select images to generate recreation prompt</div>
                            </div>
                            <div class="itc-actions" onclick="event.stopPropagation()">
                                <button type="button" class="itc-action-btn itc-copy" onclick="itcCopyPrompt()" title="Copy prompt">
                                    <i class="fas fa-copy"></i>
                                </button>
                                <button type="button" class="itc-action-btn itc-push" onclick="itcOpenModal()" title="Select images & push">
                                    <i class="fas fa-bolt"></i>
                                </button>
                            </div>
                        </div>
                    </div>

                    <!-- Static Node: Support Tutorial Generator (STG) -->
                    <div class="stg-container" id="stgContainer" onclick="stgOpenModal()">
                        <div class="stg-glow-bar"></div>
                        <div class="stg-inner">
                            <div class="stg-checkbox" id="stgCheckboxWrap" onclick="event.stopPropagation(); stgToggleDirect()">
                                <input type="checkbox" id="stgCheckbox">
                                <div class="stg-check-box"><i class="fas fa-check"></i></div>
                            </div>
                            <div class="stg-body">
                                <div class="stg-badges">
                                    <span class="stg-badge-static"><i class="fas fa-thumbtack"></i> Static</span>
                                    <span class="stg-badge-type"><i class="fas fa-graduation-cap"></i> Tutorial</span>
                                </div>
                                <div class="stg-name">Image Course</div>
                                <div class="stg-preview">Images → HTML tutorial — enter filename to generate course</div>
                            </div>
                            <div class="stg-actions" onclick="event.stopPropagation()">
                                <button type="button" class="stg-action-btn stg-copy" onclick="stgCopyPrompt()" title="Copy prompt">
                                    <i class="fas fa-copy"></i>
                                </button>
                                <button type="button" class="stg-action-btn stg-push" onclick="stgOpenModal()" title="Set filename & push">
                                    <i class="fas fa-bolt"></i>
                                </button>
                            </div>
                        </div>
                    </div>

                    <!-- Static Node: Explain Code (EXP) -->
                    <div class="exp-container" id="expContainer" onclick="expOpenModal()">
                        <div class="exp-glow-bar"></div>
                        <div class="exp-inner">
                            <div class="exp-checkbox" id="expCheckboxWrap" onclick="event.stopPropagation(); expToggleDirect()">
                                <input type="checkbox" id="expCheckbox">
                                <div class="exp-check-box"><i class="fas fa-check"></i></div>
                            </div>
                            <div class="exp-body">
                                <div class="exp-badges">
                                    <span class="exp-badge-static"><i class="fas fa-thumbtack"></i> Static</span>
                                    <span class="exp-badge-type"><i class="fas fa-book-open"></i> Course</span>
                                </div>
                                <div class="exp-name">Full Course</div>
                                <div class="exp-preview">Code/Phrase → HTML tutorial — enter filename to generate</div>
                            </div>
                            <div class="exp-actions" onclick="event.stopPropagation()">
                                <button type="button" class="exp-action-btn exp-copy" onclick="expCopyPrompt()" title="Copy prompt">
                                    <i class="fas fa-copy"></i>
                                </button>
                                <button type="button" class="exp-action-btn exp-push" onclick="expOpenModal()" title="Set filename & push">
                                    <i class="fas fa-bolt"></i>
                                </button>
                            </div>
                        </div>
                    </div>
                </div>

                <div class="saved-list" id="savedList">
                    <!-- Saved prompts will be loaded here -->
                </div>
                <div class="saved-scrollbar-track" id="savedScrollbarTrack">
                    <div class="saved-scrollbar-thumb" id="savedScrollbarThumb"></div>
                </div>
            </div>
            <!-- Editor (always visible – excluded from tab toggle) -->
            <div class="editor-container">
                <div class="editor-header">
                    <div class="editor-title">
                        <i class="fas fa-terminal"></i>
                        <span>Prompt Editor</span>
                        
                        <!-- Editor Search Bar -->
                        <div class="editor-search-bar" id="editorSearchBar">
                            <i class="fas fa-search search-icon"></i>
                            <input type="text" 
                                   class="editor-search-input" 
                                   id="editorSearchInput" 
                                   placeholder="Search..." 
                                   autocomplete="off"
                                   spellcheck="false">
                            <span class="search-results-badge" id="searchResultsBadge">0 of 0</span>
                            <div class="search-nav-btns">
                                <button type="button" class="search-nav-btn" onclick="editorSearchPrev()" title="Previous (Shift+Enter)">
                                    <i class="fas fa-chevron-up"></i>
                                </button>
                                <button type="button" class="search-nav-btn" onclick="editorSearchNext()" title="Next (Enter)">
                                    <i class="fas fa-chevron-down"></i>
                                </button>
                            </div>
                            <button type="button" class="search-clear-btn" id="searchClearBtn" onclick="clearEditorSearch()" title="Clear search (Esc)">
                                <i class="fas fa-times" style="font-weight: 900;"></i>
                            </button>
                        </div>
                        
                        <a href="?logout=1" class="logout-btn" title="Logout">
                            <i class="fas fa-sign-out-alt"></i>
                        </a>
                    </div>
                    
                    <!-- History Navigation (Undo/Redo) -->
                    <div class="history-navigation">
                        <button type="button" class="history-btn undo" id="btnUndo" onclick="historyUndo()" disabled title="Undo (Ctrl+Z)">
                            <i class="fas fa-arrow-left"></i>
                            <span class="history-badge" id="undoCount">0</span>
                        </button>
                        <div class="history-divider"></div>
                        <div class="history-info">
                            <span class="history-position" id="historyPosition">0/0</span>
                            <span class="history-label">History</span>
                        </div>
                        <div class="history-divider"></div>
                        <button type="button" class="history-btn redo" id="btnRedo" onclick="historyRedo()" disabled title="Redo (Ctrl+Y)">
                            <i class="fas fa-arrow-right"></i>
                            <span class="history-badge" id="redoCount">0</span>
                        </button>
                        <div class="history-divider"></div>
                        <button type="button" class="history-btn clear" id="btnClearHistory" onclick="resetHistory()" title="Clear History">
                            <i class="fas fa-times"></i>
                        </button>
                    </div>
                    
                    <div class="editor-actions">
                        <button class="btn btn-primary" onclick="copyPrompt()">
                            <i class="fas fa-copy"></i> Copy
                        </button>
                        <button class="btn btn-paste" onclick="pasteToEditor()">
                            <i class="fas fa-paste"></i> Paste
                        </button>
                        <button class="btn btn-success" onclick="openSaveModal()">
                            <i class="fas fa-save"></i> Save Prompt
                        </button>
                        <button class="btn btn-save-template" onclick="openSaveTemplateModal()">
                            <i class="fas fa-layer-group"></i> Save Template
                        </button>
                        
                        <!-- Folder Picker Group -->
                        <div class="folder-picker-group">
                            <button class="btn btn-folder" id="btnFolderPicker" onclick="selectPromptFolder()" title="Select folder for prompt.txt">
                                <i class="fas fa-folder-open"></i> Folder
                                <span class="folder-status"></span>
                            </button>
                            <button class="btn-clear-picker" id="btnClearFolder" onclick="clearFolderSelection()" title="Clear folder selection">
                                <i class="fas fa-times"></i>
                            </button>
                            <button class="btn btn-send" id="btnSendToFile" onclick="sendToPromptFile()" disabled title="Send to prompt.txt">
                                <i class="fas fa-paper-plane"></i> Send
                            </button>
                            <button class="btn btn-pull" id="btnPullFromFile" onclick="pullFromPromptFile()" disabled title="Pull from prompt.txt">
                                <i class="fas fa-download"></i> Pull
                            </button>
                        </div>
                        
                        <button class="btn btn-secondary" onclick="clearEditor()">
                            <i class="fas fa-eraser"></i> Clear
                        </button>
                    </div>
                </div>
                <div class="editor-body">
                    <div class="pull-success-banner" id="pullSuccessBanner" style="display:none;"></div>
                    <div class="editor-highlight-overlay" id="editorHighlightOverlay"></div>
                    <textarea id="promptEditor" placeholder="Your generated prompt will appear here...&#10;&#10;Check the prompt templates on the left to build your prompt, or type directly."></textarea>
                    <div class="resize-handle" id="resizeHandle" title="Drag to resize">
                        <i class="fas fa-grip-lines"></i>
                    </div>
                </div>
                
                <!-- File Transfer Section -->
                <div class="file-transfer-section">
                    <!-- Left File Group -->
                    <div class="file-transfer-group left">
                        <button class="file-picker-btn" id="filePickerLeft" onclick="selectTransferFile('left')" title="Select a file">
                            <i class="fas fa-file"></i>
                            <span class="file-name" id="fileNameLeft">Select File</span>
                        </button>
                        <button class="btn-clear-picker" id="btnClearLeft" onclick="clearFileSelection('left')" title="Clear file">
                            <i class="fas fa-times"></i>
                        </button>
                        <button class="btn-file-action btn-file-pull" id="btnPullLeft" onclick="pullFromTransferFile('left')" disabled title="Pull content from file">
                            <i class="fas fa-download"></i> Pull
                        </button>
                        <button class="btn-file-action btn-file-push" id="btnPushLeft" onclick="pushToTransferFile('left')" disabled title="Push content to file">
                            <i class="fas fa-upload"></i> Push
                        </button>
                    </div>
                    
                    <!-- Move Folder Tools -->
                    <div class="move-folder-group">
                        <button class="btn-move-folder" onclick="openMoveFolderModal()" title="Move folder to another location">
                            <i class="fas fa-folder-open"></i>
                            <i class="fas fa-arrow-right"></i>
                            <i class="fas fa-folder"></i>
                            Move
                        </button>
                    </div>
                    
                    <!-- File Management Buttons -->
                    <div class="file-management-group">
                        <button class="btn-file-manage btn-create" onclick="createNewFile()" title="Create new file">
                            <i class="fas fa-file-medical"></i>
                        </button>
                        <button class="btn-file-manage btn-delete" onclick="deleteSelectedFile()" title="Delete files">
                            <i class="fas fa-file-excel"></i>
                        </button>
                        <button class="btn-file-manage btn-folder" onclick="createNewFolder()" title="Create new folder">
                            <i class="fas fa-folder-plus"></i>
                        </button>
                        <button class="btn-file-manage btn-delete-folder" onclick="deleteFolderModal()" title="Delete folder">
                            <i class="fas fa-folder-minus"></i>
                        </button>
                        <button class="btn-file-manage btn-rename" onclick="renameSelectedFile()" title="Rename a file">
                            <i class="fas fa-edit"></i>
                        </button>
                    </div>
                    
                    <!-- Move Files Tools -->
                    <div class="move-folder-group">
                        <button class="btn-move-folder" style="color: #8b5cf6; border-color: rgba(139, 92, 246, 0.3);" onclick="openMoveFilesModal()" title="Move files to another folder">
                            <i class="fas fa-file"></i>
                            <i class="fas fa-arrow-right"></i>
                            <i class="fas fa-folder"></i>
                            Move
                        </button>
                    </div>
                    
                    <!-- Right File Group -->
                    <div class="file-transfer-group right">
                        <button class="btn-file-action btn-file-pull" id="btnPullRight" onclick="pullFromTransferFile('right')" disabled title="Pull content from file">
                            <i class="fas fa-download"></i> Pull
                        </button>
                        <button class="btn-file-action btn-file-push" id="btnPushRight" onclick="pushToTransferFile('right')" disabled title="Push content to file">
                            <i class="fas fa-upload"></i> Push
                        </button>
                        <button class="file-picker-btn" id="filePickerRight" onclick="selectTransferFile('right')" title="Select a file">
                            <i class="fas fa-file"></i>
                            <span class="file-name" id="fileNameRight">Select File</span>
                        </button>
                        <button class="btn-clear-picker" id="btnClearRight" onclick="clearFileSelection('right')" title="Clear file">
                            <i class="fas fa-times"></i>
                        </button>
                    </div>
                </div>
                
                <div class="editor-footer">
                    <div class="char-count">
                        <i class="fas fa-font"></i>
                        <span id="charCount">0</span> characters
                    </div>
                    
                    <div class="footer-voice-tools">
                        <button class="btn btn-tts" id="btnTtsRead" onclick="ttsToggleRead()" title="Read aloud (British Female Voice)">
                            <i class="fas fa-volume-up"></i> <span id="ttsLabel">Read</span>
                            <div class="tts-progress" id="ttsProgress"></div>
                        </button>
                        <button class="btn btn-tts-ar" id="btnTtsAr" onclick="ttsArToggle()" title="قراءة عربية – صوت أنثوي عالي الجودة">
                            <i class="fas fa-volume-up"></i> <span id="ttsArLabel">عربي</span><span class="ar-flag">AR</span>
                            <div class="tts-ar-progress" id="ttsArProgress"></div>
                        </button>
                        <button class="btn btn-stt" id="btnSttDictate" onclick="sttToggle()" title="Voice dictation – speak to type">
                            <i class="fas fa-microphone"></i> <span id="sttLabel">Dictate</span>
                            <span class="stt-dot"></span>
                        </button>
                        <button class="btn btn-stt-ar" id="btnSttAr" onclick="sttArToggle()" title="إملاء عربي – تحدث بالعربية للكتابة">
                            <i class="fas fa-microphone"></i> <span id="sttArLabel">إملاء</span><span class="stt-ar-flag">AR</span>
                            <span class="stt-ar-dot"></span>
                        </button>
                        <button class="btn btn-copy-editor" id="btnCopyEditor" onclick="copyEditorText()" title="Copy prompt to clipboard">
                            <i class="fas fa-copy"></i> <span id="copyEditorLabel">Copy</span>
                        </button>
                        <button class="btn btn-paste-editor" id="btnPasteEditor" onclick="pasteEditorText()" title="Paste from clipboard">
                            <i class="fas fa-paste"></i> <span id="pasteEditorLabel">Paste</span>
                        </button>
                        <button class="btn btn-clear-editor" id="btnClearEditor" onclick="clearEditorText()" title="Clear prompt editor">
                            <i class="fas fa-eraser"></i> <span id="clearEditorLabel">Clear</span>
                        </button>
                    </div>
                    
                    <button class="btn-dir-toggle" id="btnDirToggle" onclick="toggleEditorDir()" title="Toggle text direction (LTR / RTL)">
                        <i class="fas fa-exchange-alt"></i>
                        <span id="dirLabel">LTR</span>
                    </button>
                    
                    <div class="word-count">
                        <i class="fas fa-text-width"></i>
                        <span id="wordCount">0</span> words
                    </div>
                </div>
            </div>
            <!-- ═══ Analytics Textarea Section ═══ -->
            <div class="analytics-section" id="analyticsSection">
                <div class="analytics-header">
                    <div class="analytics-title">
                        <i class="fas fa-chart-line"></i>
                        <span>Analytics</span>
                        <span class="analytics-badge">Analyzer</span>
                    </div>

                    <!-- Analytics Search Bar -->
                    <div class="analytics-search-bar" id="analyticsSearchBar">
                        <i class="fas fa-search analytics-search-icon"></i>
                        <input type="text" class="analytics-search-input" id="analyticsSearchInput" placeholder="Search analytics..." autocomplete="off">
                        <span class="analytics-search-badge" id="analyticsSearchBadge">0 of 0</span>
                        <div class="analytics-search-nav">
                            <button class="analytics-search-nav-btn" onclick="analyticsSearchPrev()" title="Previous (Shift+Enter)"><i class="fas fa-chevron-up"></i></button>
                            <button class="analytics-search-nav-btn" onclick="analyticsSearchNext()" title="Next (Enter)"><i class="fas fa-chevron-down"></i></button>
                        </div>
                        <button class="analytics-search-clear-btn" onclick="clearAnalyticsSearch()" title="Clear search"><i class="fas fa-times"></i></button>
                    </div>

                    <div class="analytics-actions">
                        <button class="btn btn-send" id="btnSendAnalytics" onclick="sendAnalyticsToPromptFile()" disabled title="Send analytics to prompt.txt">
                            <i class="fas fa-paper-plane"></i> Send
                        </button>
                        <button class="btn btn-pull" id="btnPullToAnalytics" onclick="pullToAnalyticsFromPromptFile()" disabled title="Pull from prompt.txt into analytics">
                            <i class="fas fa-download"></i> Pull
                        </button>
                        <button class="analytics-btn analytics-copy-btn" onclick="copyAnalyticsContent()" title="Copy analytics content">
                            <i class="fas fa-copy"></i>
                            <span>Copy</span>
                        </button>
                        <button class="analytics-btn analytics-clear-btn" onclick="clearAnalyticsContent()" title="Clear analytics content">
                            <i class="fas fa-trash-alt"></i>
                            <span>Clear</span>
                        </button>
                        <button class="analytics-btn" id="analyticsCollapseBtn" onclick="toggleAnalyticsCollapse()" title="Collapse/Expand">
                            <i class="fas fa-chevron-up"></i>
                        </button>
                    </div>
                </div>

                <div class="analytics-body" id="analyticsBody">
                    <div class="analytics-highlight-overlay" id="analyticsHighlightOverlay"></div>
                    <textarea 
                        class="analytics-textarea" 
                        id="analyticsTextarea" 
                        placeholder="Analytics output will appear here. This area analyzes the relationship between the Prompt Editor and Project Prompts..."
                        oninput="onAnalyticsChange()"></textarea>
                    <div class="analytics-resize-handle" id="analyticsResizeHandle">
                        <i class="fas fa-grip-lines"></i>
                    </div>
                </div>

                <!-- Analytics Footer: Pull/Push to Editor & Project Prompts -->
                <div class="analytics-footer">
                    <div class="analytics-footer-group">
                        <span class="analytics-footer-label"><i class="fas fa-pen-fancy"></i> Editor</span>
                        <button class="analytics-footer-btn pull-btn" onclick="analyticsPullFromEditor()" title="Pull content from Prompt Editor into Analytics">
                            <i class="fas fa-download"></i> Pull
                        </button>
                        <button class="analytics-footer-btn push-btn" onclick="analyticsPushToEditor()" title="Push Analytics content to Prompt Editor">
                            <i class="fas fa-upload"></i> Push
                        </button>
                    </div>

                    <div class="analytics-footer-divider"></div>

                    <div class="analytics-footer-group">
                        <span class="analytics-footer-label"><i class="fas fa-project-diagram"></i> Project Prompts</span>
                        <button class="analytics-footer-btn pull-btn" onclick="analyticsPullFromProjectPrompts()" title="Pull content from Project Prompts into Analytics">
                            <i class="fas fa-download"></i> Pull
                        </button>
                        <button class="analytics-footer-btn push-btn" onclick="analyticsPushToProjectPrompts()" title="Push Analytics content to Project Prompts">
                            <i class="fas fa-upload"></i> Push
                        </button>
                    </div>
                </div>
            </div>

            </div><!-- /unified-editor-section -->

            <!-- Tab Panel: iFrame Scalar -->
            <div class="mc-tab-panel" id="mcPanelIframe" data-mc-panel="iframe">
                <div class="scalar-container">

                    <!-- Header: URL Bar + Actions -->
                    <div class="scalar-header">
                        <div class="scalar-brand">
                            <i class="fas fa-expand-arrows-alt"></i>
                            <span>iFrame Scalar</span>
                        </div>
                        <div class="scalar-url-section">
                            <div class="scalar-url-wrapper">
                                <i class="fas fa-globe scalar-url-icon"></i>
                                <input type="text" id="scalarUrlInput" class="scalar-url-input"
                                       placeholder="Enter URL to preview (e.g. https://myapp.com)"
                                       spellcheck="false" autocomplete="off"
                                       onkeydown="scalarUrlKeydown(event)" oninput="scalarUrlAutocomplete()">
                                <div class="scalar-url-dropdown" id="scalarUrlDropdown"></div>
                            </div>
                            <button class="scalar-go-btn" onclick="scalarLoadUrl()" title="Load URL in all devices">
                                <i class="fas fa-play"></i> <span>Preview</span>
                            </button>
                            <button class="scalar-action-btn" onclick="scalarRefreshAll()" title="Refresh all iframes">
                                <i class="fas fa-sync-alt"></i>
                            </button>
                            <button class="scalar-action-btn scalar-history-toggle" onclick="scalarToggleHistory()" title="URL History">
                                <i class="fas fa-history"></i>
                            </button>
                        </div>
                    </div>

                    <!-- Device Category Bar -->
                    <div class="scalar-device-bar">
                        <div class="scalar-category-filters">
                            <button class="scalar-cat-btn active" data-cat="all" onclick="scalarFilterCategory('all')">
                                <i class="fas fa-th"></i> All
                            </button>
                            <button class="scalar-cat-btn" data-cat="phone" onclick="scalarFilterCategory('phone')">
                                <i class="fas fa-mobile-alt"></i> Phones
                            </button>
                            <button class="scalar-cat-btn" data-cat="tablet" onclick="scalarFilterCategory('tablet')">
                                <i class="fas fa-tablet-alt"></i> Tablets
                            </button>
                            <button class="scalar-cat-btn" data-cat="desktop" onclick="scalarFilterCategory('desktop')">
                                <i class="fas fa-desktop"></i> Desktop
                            </button>
                        </div>
                        <div class="scalar-device-toggles" id="scalarDeviceToggles">
                            <!-- Generated by JS -->
                        </div>
                    </div>

                    <!-- Previews Grid -->
                    <div class="scalar-grid" id="scalarGrid">
                        <!-- Device preview cards generated by JS -->
                    </div>

                    <!-- Empty State -->
                    <div class="scalar-empty-state" id="scalarEmptyState">
                        <div class="scalar-empty-icon">
                            <i class="fas fa-mobile-alt"></i>
                            <i class="fas fa-tablet-alt"></i>
                            <i class="fas fa-desktop"></i>
                        </div>
                        <h3>Responsive Preview</h3>
                        <p>Enter a URL above to preview your app across different device sizes</p>
                        <div class="scalar-quick-links">
                            <button class="scalar-quick-btn" onclick="scalarQuickLoad('http://localhost')">
                                <i class="fas fa-server"></i> Localhost
                            </button>
                            <button class="scalar-quick-btn" onclick="scalarQuickLoad('http://localhost/phpmyadmin')">
                                <i class="fas fa-database"></i> phpMyAdmin
                            </button>
                        </div>
                    </div>

                    <!-- History Sidebar -->
                    <div class="scalar-history-panel" id="scalarHistoryPanel">
                        <div class="scalar-history-head">
                            <h3><i class="fas fa-history"></i> Recent URLs</h3>
                            <button class="scalar-history-close" onclick="scalarToggleHistory()"><i class="fas fa-times"></i></button>
                        </div>
                        <div class="scalar-history-list" id="scalarHistoryList">
                            <!-- History items generated by JS -->
                        </div>
                        <button class="scalar-clear-history" onclick="scalarClearHistory()">
                            <i class="fas fa-trash-alt"></i> Clear History
                        </button>
                    </div>

                </div>
            </div><!-- /mc-tab-panel iFrame Scalar -->
            
        </main>
        
        <!-- ═══════════════════════════════════════════════════════════════════
             🎨 RIGHT PANEL - Design Enhancer
             ═══════════════════════════════════════════════════════════════════ -->
        <aside class="right-panel">
            <div class="right-panel-content">
                <!-- Design Enhancer Header -->
                <header class="de-header">
                    <h2>🎨 Design Enhancer</h2>
                    <p class="de-subtitle">AI-Powered Web Design</p>
                </header>
                
                <!-- ═══════════════════════════════════════════════════════════════════
                     💾 DESIGN ENHANCER PRESETS - Save/Load Configurations
                     ═══════════════════════════════════════════════════════════════════ -->
                <div class="dep-container">
                    <div class="dep-row">
                        <div class="dep-select-wrapper">
                            <i class="fas fa-layer-group dep-select-icon"></i>
                            <select id="depSelect" onchange="depOnSelectChange()" title="Load a saved preset">
                                <option value="">-- No Preset --</option>
                            </select>
                            <i class="fas fa-chevron-down dep-arrow-icon"></i>
                        </div>
                        <button type="button" class="dep-btn dep-load" id="depLoadBtn" onclick="depLoad()" title="Re-load selected preset (restore saved state)" disabled>
                            <i class="fas fa-download"></i>
                        </button>
                        <div class="dep-actions">
                            <button type="button" class="dep-btn dep-save" id="depSaveBtn" onclick="depSave()" title="Save changes to current preset" disabled>
                                <i class="fas fa-save"></i>
                            </button>
                            <button type="button" class="dep-btn dep-save-as" onclick="depSaveAs()" title="Save as new preset">
                                <i class="fas fa-copy"></i>
                            </button>
                            <button type="button" class="dep-btn dep-rename" id="depRenameBtn" onclick="depRename()" title="Rename current preset" disabled>
                                <i class="fas fa-pen"></i>
                            </button>
                            <button type="button" class="dep-btn dep-delete" id="depDeleteBtn" onclick="depDelete()" title="Delete current preset" disabled>
                                <i class="fas fa-trash-alt"></i>
                            </button>
                        </div>
                    </div>
                </div>
                
                <!-- Design Enhancer Control Buttons -->
                <div class="de-control-buttons">
                    <button type="button" class="de-control-btn collapse-all" onclick="deCollapseAll()" title="Collapse All Groups">
                        <i class="fas fa-compress-alt"></i>
                        <span>Collapse</span>
                    </button>
                    <button type="button" class="de-control-btn uncollapse-all" onclick="deUncollapseAll()" title="Expand All Groups">
                        <i class="fas fa-expand-alt"></i>
                        <span>Expand</span>
                    </button>
                    <button type="button" class="de-control-btn reset-all" onclick="deResetAll()" title="Reset All to Default">
                        <i class="fas fa-undo"></i>
                        <span>Reset All</span>
                    </button>
                </div>
                
                <!-- General Push All Buttons -->
                <div class="de-push-all-wrapper">
