                                    <button type="button" class="uf-collapse-btn" onclick="ufCollapseAll()" title="Collapse All">
                                        <i class="fas fa-compress-alt"></i>
                                    </button>
                                </div>
                            </div>
                            <div class="uf-structure-tree" id="ufStructureTree">
