                            <div class="branding-options-header">
                                <i class="fas fa-cogs"></i>
                                <span>Application Options</span>
                            </div>
                            
                            <div class="branding-option-item" data-option="favicon" onclick="toggleBrandingOptionItem(this)">
                                <input type="checkbox" id="brandingFavicon">
                                <div class="branding-option-check"><i class="fas fa-check"></i></div>
                                <div class="branding-option-content">
                                    <strong><i class="fas fa-bookmark"></i> Favicon</strong>
                                    <p>Set logo as favicon for all pages</p>
                                </div>
                            </div>
                            
                            <div class="branding-option-item" data-option="logo-pages" onclick="toggleBrandingOptionItem(this)">
                                <input type="checkbox" id="brandingLogoPages">
                                <div class="branding-option-check"><i class="fas fa-check"></i></div>
                                <div class="branding-option-content">
                                    <strong><i class="fas fa-images"></i> Logo in Header</strong>
                                    <p>Add logo to every page header</p>
                                </div>
                            </div>
                            
                            <div class="branding-option-item" data-option="title-pages" onclick="toggleBrandingOptionItem(this)">
                                <input type="checkbox" id="brandingTitlePages">
                                <div class="branding-option-check"><i class="fas fa-check"></i></div>
                                <div class="branding-option-content">
                                    <strong><i class="fas fa-font"></i> Page Titles</strong>
                                    <p>Update &lt;title&gt; tag in all pages</p>
                                </div>
                            </div>
                        </div>
                        
                        <!-- Custom Instructions (always visible) -->
                        <div class="branding-custom-instructions" id="brandingCustomInstructions">
                            <div class="branding-custom-header">
                                <i class="fas fa-edit"></i>
                                <span>Custom Instructions</span>
                                <button type="button" class="branding-clear-btn" onclick="brandingClearAndReset()" title="Clear logo, check all options & clear instructions">
                                    <i class="fas fa-eraser"></i> Clear & Reset
                                </button>
                            </div>
                            <textarea id="brandingCustomPrompt" class="branding-custom-textarea" oninput="saveBrandingState()" placeholder="Specify custom instructions for unchecked options...&#10;&#10;Example:&#10;• Apply logo only to: index.html, about.html&#10;• Set favicon for homepage only&#10;• Use logo in footer instead of header"></textarea>
                        </div>
                        
                        <!-- Push to Project Prompts -->
                        <div class="branding-push-section">
                            <button type="button" class="branding-push-btn" onclick="pushBrandingToNotes()">
                                <i class="fas fa-arrow-down"></i>
                                <span>Push to Project Prompts</span>
                            </button>
                        </div>
                    </div>
                </div>
                
                <!-- ═══════════════════════════════════════════════════════════════════
                     📄 PAGES CREATOR TOOL
                     ═══════════════════════════════════════════════════════════════════ -->
                <div class="de-tool-section collapsed" id="pagesCreatorTool" draggable="true">
                    <div class="de-tool-header" onclick="toggleToolSection('pagesCreator')">
                        <div class="de-drag-handle" title="Drag to reorder">
                            <i class="fas fa-grip-vertical"></i>
