                            <div class="pc-custom-list" id="pcCustomPagesList"></div>
                            <button type="button" onclick="pcCustomPages=[];document.getElementById('pcCustomPagesList').innerHTML='';savePCState();updatePCCounts();pcUncheckAll();" title="Delete all custom pages" style="margin-top:4px;padding:3px 10px;font-size:0.6rem;color:#fb923c;background:rgba(249,115,22,0.1);border:1px solid rgba(249,115,22,0.3);border-radius:5px;cursor:pointer;">
