                                            <i class="fas fa-folder-open"></i>
                                            <span>Browse</span>
                                        </button>
                                        <button type="button" class="hp-clear-btn" id="hpExistingClearBtn" onclick="hpClearExistingFile()">
                                            <i class="fas fa-times"></i>
                                            <span>Clear</span>
                                        </button>
                                    </div>
                                </div>
                                
                                <div class="hp-info-tip hp-enhance-tip">
                                    <i class="fas fa-magic"></i>
