                                            <input type="radio" name="di_mode" value="integration" onchange="diSelectMode('integration')">
                                            <div class="di-mode-content" onclick="diSelectModeByClick('integration')">
                                                <strong><i class="fas fa-puzzle-piece merge-icon"></i> Integration (Smart Merge)</strong>
                                                <span>Integrate missing content AND create missing pages</span>
                                            </div>
                                        </label>
                                        
                                        <label class="di-mode-option checked" data-mode="ai-decision">
                                            <input type="radio" name="di_mode" value="ai-decision" checked onchange="diSelectMode('ai-decision')">
                                            <div class="di-mode-content" onclick="diSelectModeByClick('ai-decision')">
                                                <strong><i class="fas fa-robot ai-icon"></i> AI Decision (Recommended)</strong>
                                                <span>Let AI analyze and choose the best approach</span>
                                            </div>
                                        </label>
                                    </div>
                                </div>
                            </div>
                        </div>
                        
                        <!-- Info Tip -->
                        <div class="di-info-tip">
                            <i class="fas fa-info-circle"></i>
                            <div>
                                <strong>Supported formats:</strong> .txt, .md, .doc, .docx, .pdf, .html, .json<br>
                                Documentation guides AI in the enhancement process.
                            </div>
                        </div>
                        
                        <!-- Notes Textarea -->
                        <div class="di-notes-section">
                            <label class="di-notes-label">
                                <i class="fas fa-edit"></i>
                                <span>Additional Documentation Notes</span>
                            </label>
                            <textarea 
                                id="diNotesTextarea" 
                                class="di-notes-textarea" 
                                placeholder="Add specific instructions about how documentation should be integrated..."
                                oninput="diUpdateCharCount()"
                            ></textarea>
                            <div class="di-char-count" id="diCharCount">0 characters</div>
                        </div>
                        
                        <!-- Push to Project Prompts -->
                        <div class="di-push-section">
                            <button type="button" class="di-push-btn" onclick="diPushToNotes()" title="Push documentation settings to Project Prompts">
                                <i class="fas fa-arrow-down"></i>
                                <span>Push to Project Prompts</span>
                            </button>
                        </div>
                    </div>
                </div>
                
                <!-- ═══════════════════════════════════════════════════════════════════
                     🎨 DESIGN TEMPLATE TOOL
                     ═══════════════════════════════════════════════════════════════════ -->
                <div class="de-tool-section collapsed" id="designTemplateTool" draggable="true">
                    <div class="de-tool-header" onclick="toggleToolSection('designTemplate')">
                        <div class="de-drag-handle" title="Drag to reorder">
                            <i class="fas fa-grip-vertical"></i>
                        </div>
                        <div class="de-tool-check" onclick="event.stopPropagation(); deToggleToolCheck('designTemplateTool')">
                            <input type="checkbox" id="deCheck_designTemplateTool" checked>
                            <div class="de-check-visual"><i class="fas fa-check"></i></div>
                        </div>
                        <div class="de-tool-title">
                            <i class="fas fa-palette"></i>
                            <span>Design Templates</span>
                        </div>
                        <button type="button" class="de-tool-reset-btn" onclick="event.stopPropagation(); dtOpenAddModal();" title="Add new design template">
                            <i class="fas fa-plus"></i>
                        </button>
                        <div class="de-tool-badge dt-badge" id="dtBadge" style="display: none;">0</div>
                        <i class="fas fa-chevron-down de-tool-arrow" id="designTemplateArrow"></i>
                    </div>
                    <div class="de-tool-body" id="designTemplateBody">
                        <!-- Search -->
                        <div class="dt-search-box">
                            <i class="fas fa-search"></i>
                            <input type="text" id="dtSearchInput" placeholder="Search design templates..." oninput="dtFilterTemplates()">
                            <button type="button" class="dt-search-clear" id="dtSearchClear" onclick="dtClearSearch()" style="display: none;">
                                <i class="fas fa-times"></i>
                            </button>
                        </div>
                        
                        <!-- Actions Row -->
                        <div class="dt-actions-row">
                            <label class="dt-select-all" title="Select/Deselect All">
                                <input type="checkbox" id="dtSelectAllCheckbox" onchange="dtToggleAll(this.checked)">
                                <span class="dt-checkbox-custom"></span>
                                <span class="dt-checkbox-label">Select All</span>
                            </label>
                            <span class="dt-counter" id="dtCounter">0/0</span>
                        </div>
                        
                        <!-- Loading -->
                        <div class="dt-loading" id="dtLoading" style="display: none;">
                            <i class="fas fa-spinner fa-spin"></i>
                            <span>Loading templates...</span>
                        </div>
                        
                        <!-- Template List -->
                        <div class="dt-list" id="dtList"></div>
                        
                        <!-- No Results -->
                        <div class="dt-no-results" id="dtNoResults" style="display: none;">
                            <i class="fas fa-search"></i>
                            <p>No design templates found</p>
                        </div>
                        
                        <!-- Empty State -->
                        <div class="dt-empty" id="dtEmpty" style="display: none;">
                            <i class="fas fa-palette"></i>
                            <p>No design templates yet</p>
                            <button type="button" class="dt-empty-btn" onclick="dtOpenAddModal()">
                                <i class="fas fa-plus"></i> Add First Template
                            </button>
                        </div>
                        
                        <!-- Push to Project Prompts -->
                        <div class="dt-push-section">
                            <button type="button" class="dt-push-btn" onclick="dtTemplatePushToNotes()" title="Push selected design templates to Project Prompts">
                                <i class="fas fa-arrow-down"></i>
                                <span>Push to Project Prompts</span>
                            </button>
                        </div>
                    </div>
                </div>
                
                </div><!-- End of de-tools-container -->
                
                <!-- More tools can be added here -->
                <div class="de-tools-placeholder">
                    <i class="fas fa-puzzle-piece"></i>
                    <span>More tools coming soon...</span>
                </div>
            </div>
        </aside>
    </div>
    
    <!-- Design Enhancer Confirm Modal -->
    <div class="de-confirm-overlay" id="deConfirmOverlay">
        <div class="de-confirm-modal">
            <div class="de-confirm-header">
                <div class="de-confirm-icon">
                    <i class="fas fa-exclamation-triangle"></i>
                </div>
                <div class="de-confirm-header-text">
                    <h3 id="deConfirmTitle">Confirm Reset</h3>
                    <p id="deConfirmSubtitle">Design Enhancer</p>
                </div>
            </div>
            <div class="de-confirm-body">
                <p class="de-confirm-message" id="deConfirmMessage">Are you sure you want to reset?</p>
                <div class="de-confirm-warning">
                    <i class="fas fa-info-circle"></i>
                    <span id="deConfirmWarning">This action cannot be undone.</span>
                </div>
            </div>
            <div class="de-confirm-actions">
                <button type="button" class="de-confirm-btn cancel" onclick="deConfirmCancel()">
                    <i class="fas fa-times"></i>
                    Cancel
                </button>
                <button type="button" class="de-confirm-btn confirm" onclick="deConfirmAccept()">
                    <i class="fas fa-check"></i>
                    <span id="deConfirmBtnText">Reset</span>
                </button>
            </div>
        </div>
    </div>
    
    <!-- Design Enhancer Input Prompt Modal (replaces native prompt()) -->
    <div class="de-prompt-overlay" id="dePromptOverlay">
        <div class="de-prompt-modal">
            <div class="de-prompt-header">
                <div class="de-prompt-icon">
                    <i class="fas fa-pen-fancy" id="dePromptIcon"></i>
                </div>
                <div class="de-prompt-header-text">
                    <h3 id="dePromptTitle">Enter Name</h3>
                    <p id="dePromptSubtitle">Design Enhancer Presets</p>
                </div>
                <button type="button" class="de-prompt-close" onclick="dePromptCancel()" title="Close">
                    <i class="fas fa-times"></i>
                </button>
            </div>
            <div class="de-prompt-body">
                <p class="de-prompt-message" id="dePromptMessage">Enter a name for the preset:</p>
                <div class="de-prompt-input-wrapper">
                    <i class="fas fa-tag de-prompt-input-icon"></i>
                    <input type="text" id="dePromptInput" class="de-prompt-input" placeholder="Type here..." autocomplete="off" spellcheck="false">
                    <button type="button" class="de-prompt-input-clear" id="dePromptInputClear" onclick="document.getElementById('dePromptInput').value=''; document.getElementById('dePromptInput').focus();" title="Clear">
                        <i class="fas fa-times-circle"></i>
                    </button>
                </div>
                <div class="de-prompt-hint" id="dePromptHint" style="display:none;">
                    <i class="fas fa-info-circle"></i>
                    <span id="dePromptHintText"></span>
                </div>
            </div>
            <div class="de-prompt-actions">
                <button type="button" class="de-prompt-btn cancel" onclick="dePromptCancel()">
                    <i class="fas fa-times"></i>
                    Cancel
                </button>
                <button type="button" class="de-prompt-btn confirm" id="dePromptConfirmBtn" onclick="dePromptAccept()">
                    <i class="fas fa-check" id="dePromptConfirmIcon"></i>
                    <span id="dePromptConfirmText">Confirm</span>
                </button>
            </div>
        </div>
    </div>

    <!-- Theme Toggle Button -->
    <button class="theme-toggle-btn" onclick="toggleTheme()" title="Toggle Dark/Light Mode">
        <i class="fas fa-sun" id="themeIcon"></i>
    </button>
    
    <!-- Save Modal -->
    <div class="modal-overlay" id="saveModal">
        <div class="modal">
            <div class="modal-header">
                <h3><i class="fas fa-save"></i> Save Prompt</h3>
                <button class="modal-close" onclick="closeModal('saveModal')">&times;</button>
            </div>
            <div class="modal-body">
                <div class="form-group">
                    <label for="promptTitle">Prompt Title</label>
                    <input type="text" id="promptTitle" placeholder="Enter a title for your prompt...">
