        }
        
        // Generate unique ID
        function generateItemId() {
            return 'item_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
        }
        
        // Add new dynamic item
        function addDynamicItem(type, prefillName = '', prefillDesc = '') {
            const id = generateItemId();
            const item = {
                id: id,
                name: prefillName || '',
                prompt: prefillDesc || '',
                files: []
            };
            
            dynamicItems[type].push(item);
            renderDynamicItems(type);
            updateDynamicCount(type);
            saveDynamicItems();
            
            // Focus on the new item's name input only if not prefilled
            if (!prefillName) {
                setTimeout(() => {
                    const nameInput = document.querySelector(`#${type}ItemsGrid .dynamic-item[data-id="${id}"] .dynamic-item-name`);
                    if (nameInput) nameInput.focus();
                }, 50);
                
                showToast(`✅ New ${type} item added`, 'success');
            }
            
            return id;
        }
        
        // Add dynamic item with full data (used when loading from database)
        function addDynamicItemWithData(type, itemData) {
            const item = {
                id: itemData.id || generateItemId(),
                name: itemData.name || '',
                prompt: itemData.prompt || '',
                files: itemData.files || []
            };
            
            dynamicItems[type].push(item);
            renderDynamicItems(type);
            updateDynamicCount(type);
            saveDynamicItems();
            
            console.log(`📦 Added ${type} item from database:`, item.name, 'prompt:', item.prompt?.substring(0, 50));
            
            return item.id;
        }
        
        // Delete dynamic item
        function deleteDynamicItem(type, id) {
            const index = dynamicItems[type].findIndex(item => item.id === id);
            if (index !== -1) {
                dynamicItems[type].splice(index, 1);
                renderDynamicItems(type);
                updateDynamicCount(type);
                saveDynamicItems();
                showToast(`🗑️ ${type.charAt(0).toUpperCase() + type.slice(1)} item deleted`, 'info');
            }
        }
        
        // Duplicate dynamic item with all data
        function duplicateDynamicItem(type, id) {
            const originalItem = dynamicItems[type].find(item => item.id === id);
            if (!originalItem) return;
            
            // Create new item with copied data
            const newId = generateItemId();
            const duplicatedItem = {
                id: newId,
                name: originalItem.name ? `${originalItem.name} (Copy)` : '',
                prompt: originalItem.prompt || '',
                files: (originalItem.files || []).map(f => {
                    // Copy file info (not actual File objects)
                    if (f instanceof File) {
                        return { name: f.name, size: f.size, type: f.type };
                    }
                    return { ...f }; // Clone file info object
                })
            };
            
            // Insert after original item
            const originalIndex = dynamicItems[type].findIndex(item => item.id === id);
            dynamicItems[type].splice(originalIndex + 1, 0, duplicatedItem);
            
            renderDynamicItems(type);
            updateDynamicCount(type);
            saveDynamicItems();
            
            showToast(`📋 ${type.charAt(0).toUpperCase() + type.slice(1)} item duplicated`, 'success');
            
            return newId;
        }
        
        // Update dynamic item
        function updateDynamicItem(type, id, field, value) {
            const item = dynamicItems[type].find(item => item.id === id);
            if (item) {
                item[field] = value;
                saveDynamicItems();
                // Refresh TM button state when prompt changes
                if (field === 'prompt') {
                    const btn = document.getElementById('tmBtn_' + id);
                    if (btn) {
                        const has = tmDetectHierarchy(value);
                        btn.classList.toggle('tm-active', has);
                        btn.title = has ? 'Open Template Manager (hierarchy detected)' : 'Open Template Manager';
                    }
                }
            }
        }
        
        // Handle file selection for dynamic item
        function handleDynamicItemFiles(type, id, input) {
            const item = dynamicItems[type].find(item => item.id === id);
            if (item && input.files.length > 0) {
                item.files = Array.from(input.files);
                renderDynamicItems(type);
                saveDynamicItems();
            }
        }
        
        // Render dynamic items for a section
        function renderDynamicItems(type) {
            const grid = document.getElementById(`${type}ItemsGrid`);
            const emptyState = document.getElementById(`${type}EmptyState`);
            
            if (!grid) return;
            
            // Clear existing items (except empty state)
            const existingItems = grid.querySelectorAll('.dynamic-item');
            existingItems.forEach(item => item.remove());
            
            if (dynamicItems[type].length === 0) {
                if (emptyState) emptyState.style.display = 'flex';
                return;
            }
            
            if (emptyState) emptyState.style.display = 'none';
            
            // Render items
            dynamicItems[type].forEach((item, index) => {
                const itemEl = createDynamicItemElement(type, item, index + 1);
                grid.appendChild(itemEl);
            });
        }
        
        // Create dynamic item element
        function createDynamicItemElement(type, item, number) {
            const div = document.createElement('div');
            div.className = `dynamic-item ${type}-item`;
            div.dataset.id = item.id;
            
            // Get file count - works with both File objects and file info objects
            const fileCount = item.files ? item.files.length : 0;
            const hasFiles = fileCount > 0;
            
            // Debug log to verify prompt is being passed
            console.log(`Rendering ${type} item:`, item.id, 'name:', item.name, 'prompt:', item.prompt?.substring(0, 50));
            
            // Build file list HTML
            let filesListHtml = '';
            if (hasFiles) {
                const fileNames = item.files.map(f => {
                    const name = f.name || f.fileName || 'Unknown file';
                    return `<span class="file-tag" title="${escapeHtml(name)}"><i class="fas fa-file-code"></i> ${escapeHtml(name)}</span>`;
                }).join('');
                filesListHtml = `
                    <div class="dynamic-item-files-list has-files">
                        <div class="files-list-header">
                            <i class="fas fa-paperclip"></i> 
                            <span>${fileCount} file${fileCount > 1 ? 's' : ''} attached:</span>
                        </div>
                        <div class="files-tags-container">${fileNames}</div>
                    </div>`;
            }
            
            div.innerHTML = `
                <div class="dynamic-item-header">
                    <span class="dynamic-item-number">#${number}</span>
                    <input type="text" 
                           class="dynamic-item-name" 
                           placeholder="${type.charAt(0).toUpperCase() + type.slice(1)} name..." 
                           value="${escapeHtml(item.name || '')}"
                           onchange="updateDynamicItem('${type}', '${item.id}', 'name', this.value)"
                           oninput="updateDynamicItem('${type}', '${item.id}', 'name', this.value)">
                    <div class="dynamic-item-actions">
                        <button type="button"
                                class="dynamic-item-btn tm-btn ${tmDetectHierarchy(item.prompt) ? 'tm-active' : ''}"
                                id="tmBtn_${item.id}"
                                onclick="tmOpen('${type}', '${item.id}')"
                                title="${tmDetectHierarchy(item.prompt) ? 'Open Template Manager (hierarchy detected)' : 'Open Template Manager'}">
                            <i class="fas fa-microscope"></i>
                        </button>
                        <input type="file" 
                               class="dynamic-item-file-input" 
                               id="file_${item.id}" 
                               multiple 
                               accept="*/*"
                               onchange="handleDynamicItemFiles('${type}', '${item.id}', this)">
                        <button type="button" 
                                class="dynamic-item-btn file-btn ${hasFiles ? 'has-files' : ''}" 
                                onclick="document.getElementById('file_${item.id}').click()"
                                title="${hasFiles ? fileCount + ' file(s) selected' : 'Attach files'}">
                            <i class="fas fa-${hasFiles ? 'check-circle' : 'paperclip'}"></i>
                        </button>
                        <button type="button" 
                                class="dynamic-item-btn duplicate-btn" 
                                onclick="duplicateDynamicItem('${type}', '${item.id}')"
                                title="Duplicate this item">
                            <i class="fas fa-clone"></i>
                        </button>
                        <button type="button" 
                                class="dynamic-item-btn delete-btn" 
                                onclick="deleteDynamicItem('${type}', '${item.id}')"
                                title="Delete this item">
                            <i class="fas fa-trash-alt"></i>
                        </button>
                    </div>
                </div>
                <div class="dynamic-item-body">
                    <textarea class="dynamic-item-prompt" 
                              placeholder="Enter ${type} instructions or description..."
                              onchange="updateDynamicItem('${type}', '${item.id}', 'prompt', this.value)"
                              oninput="updateDynamicItem('${type}', '${item.id}', 'prompt', this.value)">${escapeHtml(item.prompt || '')}</textarea>
                    ${filesListHtml}
                </div>
            `;
            
            return div;
        }
        
        // Update dynamic count badge
        function updateDynamicCount(type) {
            const countEl = document.getElementById(`${type}Count`);
            if (countEl) {
                countEl.textContent = dynamicItems[type].length;
            }
        }
        
        // Save dynamic items to localStorage
        function saveDynamicItems() {
            // Convert files to file info (can't store actual File objects)
            const convertFiles = (files) => {
                if (!files || !Array.isArray(files)) return [];
                return files.map(f => {
                    // Handle both File objects and already-converted file info
                    if (f instanceof File) {
                        return { name: f.name, size: f.size, type: f.type };
                    }
                    return f; // Already file info
                });
            };
            
            const toSave = {
                backend: dynamicItems.backend.map(item => ({
                    id: item.id,
                    name: item.name || '',
                    prompt: item.prompt || '',
                    files: convertFiles(item.files)
                })),
                page: dynamicItems.page.map(item => ({
                    id: item.id,
                    name: item.name || '',
                    prompt: item.prompt || '',
                    files: convertFiles(item.files)
                })),
                frontend: dynamicItems.frontend.map(item => ({
                    id: item.id,
                    name: item.name || '',
                    prompt: item.prompt || '',
                    files: convertFiles(item.files)
                }))
            };
            localStorage.setItem(DYNAMIC_ITEMS_KEY, JSON.stringify(toSave));
            console.log('✅ Dynamic items saved to localStorage');
        }
        
        // Load dynamic items from localStorage
        function loadDynamicItems() {
            const saved = localStorage.getItem(DYNAMIC_ITEMS_KEY);
            if (!saved) return;
            
            try {
                const data = JSON.parse(saved);
                // Note: File objects can't be restored from localStorage, but file info is preserved
                ['backend', 'page', 'frontend'].forEach(type => {
                    if (data[type]) {
                        dynamicItems[type] = data[type].map(item => ({
                            id: item.id,
                            name: item.name || '',
                            prompt: item.prompt || '',
                            files: item.files || [] // Keep file info for display
                        }));
                        renderDynamicItems(type);
                        updateDynamicCount(type);
                    }
                });
                console.log('✅ Dynamic items loaded from localStorage');
            } catch (error) {
                console.error('Failed to load dynamic items:', error);
            }
        }
        
        // Reset all dynamic items
        function resetDynamicItems() {
            ['backend', 'page', 'frontend'].forEach(type => {
                dynamicItems[type] = [];
                renderDynamicItems(type);
                updateDynamicCount(type);
            });
            localStorage.removeItem(DYNAMIC_ITEMS_KEY);
        }
        
        // ════════════════════════════════════════════════════════════════
        // VERTICAL RESIZE HANDLE – Backend / Pages / Frontend
        // ════════════════════════════════════════════════════════════════
        (function initDsResize() {
            let activeHandle = null;
            let startY = 0;
            let startH = 0;
            let targetGrid = null;

            function onPointerDown(e) {
                const handle = e.target.closest('.ds-resize-handle');
                if (!handle) return;

                e.preventDefault();
                activeHandle = handle;
                const section = handle.closest('.dynamic-section');
                targetGrid = section ? section.querySelector('.dynamic-items-grid') : null;
                if (!targetGrid) return;

                // Mark section as expanded so CSS removes max-height
                section.classList.add('ds-expanded');
                handle.classList.add('ds-dragging');

                startY = e.clientY || (e.touches && e.touches[0].clientY) || 0;
                startH = targetGrid.getBoundingClientRect().height;

                // Set explicit height so dragging works from current rendered height
                targetGrid.style.height = startH + 'px';
                targetGrid.style.maxHeight = 'none';

                document.addEventListener('mousemove', onPointerMove, { passive: false });
                document.addEventListener('mouseup', onPointerUp);
                document.addEventListener('touchmove', onPointerMove, { passive: false });
                document.addEventListener('touchend', onPointerUp);

                // Prevent text selection while dragging
                document.body.style.userSelect = 'none';
                document.body.style.cursor = 'ns-resize';
            }

            function onPointerMove(e) {
                if (!activeHandle || !targetGrid) return;
                e.preventDefault();
                const clientY = e.clientY || (e.touches && e.touches[0].clientY) || 0;
                const delta = clientY - startY;
                const newH = Math.max(100, startH + delta); // min 100px
                targetGrid.style.height = newH + 'px';
            }

            function onPointerUp() {
                if (activeHandle) {
                    activeHandle.classList.remove('ds-dragging');
                    activeHandle = null;
                }
                targetGrid = null;
                document.removeEventListener('mousemove', onPointerMove);
                document.removeEventListener('mouseup', onPointerUp);
                document.removeEventListener('touchmove', onPointerMove);
                document.removeEventListener('touchend', onPointerUp);
                document.body.style.userSelect = '';
                document.body.style.cursor = '';
            }

            // Attach listeners to all resize handles
            document.addEventListener('DOMContentLoaded', function() {
                document.querySelectorAll('.ds-resize-handle').forEach(function(handle) {
                    handle.addEventListener('mousedown', onPointerDown);
                    handle.addEventListener('touchstart', onPointerDown, { passive: false });
                });
            });
        })();

        // ════════════════════════════════════════════════════════════════
        // TEMPLATE MANAGER – Full system
        // ════════════════════════════════════════════════════════════════
        
        // ── State ──
        let tmCurrentType = null;
        let tmCurrentItemId = null;
        let tmTreeData = [];          // Array of root nodes
        let tmModified = false;
        let tmIdCounter = 0;

        // ── Detection: does text contain file/folder hierarchy? ──
        function tmDetectHierarchy(text) {
            if (!text || typeof text !== 'string') return false;
            const t = text.trim();
            if (t.length < 10) return false;
            
            // Tree connector characters (├── └── │)
            const hasTreeConnectors = /[├└│]──|[├└│]\s/.test(t);
            // Folder emoji patterns
            const hasFolderEmoji = /📁|📂/.test(t);
            // File emojis in tree context
            const hasFileEmoji = /📄|📜|🐘|🎨|🌐|📋|📝|🖼|⚙|📦|🐍|🗃/.test(t);
            // Path-like patterns (folder/file)
            const hasPathPattern = /\w+\/(\w+\.\w+|\w+\/)/.test(t);
            // Indentation-based hierarchy (2+ lines with leading spaces)
            const lines = t.split('\n').filter(l => l.trim());
            const indentedLines = lines.filter(l => /^\s{2,}/.test(l) || /^[│├└\s]{2,}/.test(l));
            const hasIndentHierarchy = indentedLines.length >= 2;
            // Bullet-list file items (  • filename.ext)
            const hasBulletFiles = (t.match(/•\s+\S+\.\w+/g) || []).length >= 2;
            
            // Score-based — need at least 2 positive signals
            let score = 0;
            if (hasTreeConnectors) score += 2;
            if (hasFolderEmoji)    score += 2;
            if (hasFileEmoji)      score += 1;
            if (hasPathPattern)    score += 1;
            if (hasIndentHierarchy) score += 1;
            if (hasBulletFiles)    score += 1;
            
            return score >= 3;
        }

        // ── Parse ASCII tree text into JS node objects ──
        function tmParseTree(text) {
            if (!text) return [];
            const lines = text.split('\n');
            const roots = [];
            const stack = []; // { depth, node }
            tmIdCounter = 0;

            for (let i = 0; i < lines.length; i++) {
                const raw = lines[i];
                if (!raw.trim()) continue;

                // Detect if this is a tree-structured line
                const treeMatch = raw.match(/^([\s│]*)[├└]──\s*(.*)/);
                // Or a root folder line (📁 name/)
                const rootMatch = raw.match(/^(📁|📂)\s*(.+)/);
                // Or a bullet item (  • filename)
                const bulletMatch = raw.match(/^\s*•\s+(.+)/);
                // Or a header/info line
                const headerMatch = raw.match(/^(📂\s*Folder:|🐘|🌐|🎨|📜|🖼|📄)\s*(.*)/);

                let node = null;
                let depth = 0;

                if (treeMatch) {
                    // Calculate depth from prefix length
                    const prefix = treeMatch[1];
                    depth = Math.floor(prefix.replace(/[│]/g, ' ').length / 4) + 1;
                    const content = treeMatch[2].trim();
                    node = tmParseNodeContent(content);
                } else if (rootMatch && i <= 5) {
                    // Root folder — first few lines
                    const name = rootMatch[2].replace(/\/\s*$/, '').trim();
                    node = { id: 'tm_' + (++tmIdCounter), name: name, type: 'folder', desc: '', children: [] };
                    depth = 0;
                } else if (bulletMatch) {
                    // Bullet item — treat as file at depth 1
                    const name = bulletMatch[1].trim();
                    if (name.includes('.') || name.match(/^\S+$/)) {
                        node = { id: 'tm_' + (++tmIdCounter), name: name, type: 'file', desc: '', children: [] };
                        depth = stack.length > 0 ? stack[stack.length - 1].depth + 1 : 1;
                    }
                } else if (headerMatch && roots.length === 0) {
                    // Header line like "📂 Folder: myproject/" — becomes root
                    let name = headerMatch[2].replace(/\/\s*$/, '').trim();
                    // Remove "Folder: " prefix
                    name = name.replace(/^Folder:\s*/i, '');
                    node = { id: 'tm_' + (++tmIdCounter), name: name, type: 'folder', desc: '', children: [] };
                    depth = 0;
                }

                // Skip metadata lines (• N file(s), etc.)
                if (!node && raw.match(/^\s*•\s+\d+\s+(file|subfolder|folder)/)) continue;
                // Skip divider/header lines
                if (!node && raw.match(/^[━─═•\s]*$/) && raw.trim().length > 0) continue;
                if (!node) {
                    // Try to attach as description to the last node in stack
                    if (stack.length > 0) {
                        const last = stack[stack.length - 1].node;
                        const trimmed = raw.trim();
                        if (trimmed && !trimmed.match(/^(📂\s*Folder:|Total:|NOTE:|\*\*NOTE)/)) {
                            if (last.desc) last.desc += '\n' + trimmed;
                            else last.desc = trimmed;
                        }
                    }
                    continue;
                }

                // Place node in hierarchy
                // Pop stack to find parent
                while (stack.length > 0 && stack[stack.length - 1].depth >= depth) {
                    stack.pop();
                }

                if (stack.length === 0) {
                    roots.push(node);
                } else {
                    stack[stack.length - 1].node.children.push(node);
                }
                stack.push({ depth, node });
            }

            // If we ended up with no roots but have some content, create a virtual root
            if (roots.length === 0 && text.trim().length > 0) {
                roots.push({
                    id: 'tm_' + (++tmIdCounter),
                    name: 'Root',
                    type: 'folder',
                    desc: text.trim(),
                    children: []
                });
            }

            return roots;
        }

        // Parse a single node's content (after ├── or └──)
        function tmParseNodeContent(content) {
            // Remove leading emoji
            const emojiMatch = content.match(/^(📁|📂|📄|📜|🐘|🎨|🌐|📋|📝|🖼️?|⚙️?|📦|🐍|🗃️?)\s*(.*)/);
            let name, isFolder = false;
            if (emojiMatch) {
                const emoji = emojiMatch[1];
                name = emojiMatch[2].trim();
                isFolder = (emoji === '📁' || emoji === '📂');
            } else {
                name = content.trim();
            }
            // If name ends with /, it's a folder
            if (name.endsWith('/')) {
                isFolder = true;
                name = name.slice(0, -1);
            }
            // If no extension and not already flagged as file, treat as folder
            if (!isFolder && !name.includes('.')) {
                isFolder = true;
            }
            return {
                id: 'tm_' + (++tmIdCounter),
                name: name,
                type: isFolder ? 'folder' : 'file',
                desc: '',
                children: []
            };
        }

        // ── Serialize tree back to ASCII text ──
        function tmSerializeTree(nodes, itemName) {
            if (!nodes || nodes.length === 0) return '';
            let lines = [];

            function renderNodes(items, prefix) {
                if (!items) return;
                const sorted = [...items].sort((a, b) => {
                    const af = a.type === 'folder', bf = b.type === 'folder';
                    if (af !== bf) return af ? -1 : 1;
                    return a.name.localeCompare(b.name);
                });
                for (let i = 0; i < sorted.length; i++) {
                    const n = sorted[i];
                    const isLast = i === sorted.length - 1;
                    const connector = isLast ? '└── ' : '├── ';
                    const childPfx = isLast ? '    ' : '│   ';
                    const icon = n.type === 'folder' ? '📂' : tmFileIcon(n.name);
                    const slash = n.type === 'folder' ? '/' : '';
                    lines.push(prefix + connector + icon + ' ' + n.name + slash);
                    if (n.desc && n.desc.trim()) {
                        n.desc.trim().split('\n').forEach(d => {
                            lines.push(prefix + childPfx + '   💬 ' + d);
                        });
                    }
                    if (n.type === 'folder' && n.children && n.children.length > 0) {
                        renderNodes(n.children, prefix + childPfx);
                    }
                }
            }

            // If there's a single root folder, use it as the root
            if (nodes.length === 1 && nodes[0].type === 'folder') {
                const root = nodes[0];
                lines.push('📁 ' + root.name + '/');
                if (root.desc && root.desc.trim()) {
                    root.desc.trim().split('\n').forEach(d => {
                        lines.push('   💬 ' + d);
                    });
                }
                renderNodes(root.children, '');
            } else {
                // Multiple roots
                nodes.forEach(root => {
                    if (root.type === 'folder') {
                        lines.push('📁 ' + root.name + '/');
                        if (root.desc) root.desc.trim().split('\n').forEach(d => lines.push('   💬 ' + d));
                        renderNodes(root.children, '');
                    } else {
                        lines.push(tmFileIcon(root.name) + ' ' + root.name);
                        if (root.desc) root.desc.trim().split('\n').forEach(d => lines.push('   💬 ' + d));
                    }
                    lines.push('');
                });
            }

            return lines.join('\n');
        }

        // File icon helper
        function tmFileIcon(name) {
            const ext = (name || '').split('.').pop().toLowerCase();
            if (['php'].includes(ext)) return '🐘';
            if (['js','ts','jsx','tsx'].includes(ext)) return '📜';
            if (['css','scss','sass','less'].includes(ext)) return '🎨';
            if (['html','htm'].includes(ext)) return '🌐';
            if (['json','xml','yaml','yml'].includes(ext)) return '📋';
            if (['md','txt','log'].includes(ext)) return '📝';
            if (['jpg','jpeg','png','gif','svg','webp','ico'].includes(ext)) return '🖼️';
            if (['py'].includes(ext)) return '🐍';
            if (['sql','db','sqlite'].includes(ext)) return '🗃️';
            if (['zip','rar','tar','gz'].includes(ext)) return '📦';
            if (['env','gitignore','htaccess'].includes(ext) || (name || '').startsWith('.')) return '⚙️';
            return '📄';
        }

        // ── Node icon CSS class helper ──
        function tmIconClass(node) {
            if (node.type === 'folder') return 'tm-folder';
            const ext = (node.name || '').split('.').pop().toLowerCase();
            if (['php'].includes(ext)) return 'tm-file tm-file-php';
            if (['js','ts','jsx','tsx'].includes(ext)) return 'tm-file tm-file-js';
            if (['css','scss','sass','less'].includes(ext)) return 'tm-file tm-file-css';
            if (['html','htm'].includes(ext)) return 'tm-file tm-file-html';
            if (['jpg','jpeg','png','gif','svg','webp','ico'].includes(ext)) return 'tm-file tm-file-img';
            if (['json','xml','yaml','yml'].includes(ext)) return 'tm-file tm-file-json';
            if (['md','txt','log'].includes(ext)) return 'tm-file tm-file-md';
            return 'tm-file';
        }

        // FontAwesome icon for node
        function tmFaIcon(node) {
            if (node.type === 'folder') return 'fa-folder';
            const ext = (node.name || '').split('.').pop().toLowerCase();
            if (['php'].includes(ext)) return 'fa-code';
            if (['js','ts','jsx','tsx'].includes(ext)) return 'fa-file-code';
            if (['css','scss','sass','less'].includes(ext)) return 'fa-palette';
            if (['html','htm'].includes(ext)) return 'fa-globe';
            if (['jpg','jpeg','png','gif','svg','webp','ico'].includes(ext)) return 'fa-image';
            if (['json','xml','yaml','yml'].includes(ext)) return 'fa-database';
            if (['md','txt','log'].includes(ext)) return 'fa-file-alt';
            return 'fa-file';
        }

        // ── Open Template Manager ──
        let tmImportedPath = '';  // Track the imported folder path

        function tmOpen(type, itemId) {
            const item = dynamicItems[type]?.find(it => it.id === itemId);
            if (!item) return;

            tmCurrentType = type;
            tmCurrentItemId = itemId;
            tmModified = false;
            tmImportedPath = '';

            // Parse existing hierarchy if present
            const hasHierarchy = tmDetectHierarchy(item.prompt);
            tmTreeData = hasHierarchy ? tmParseTree(item.prompt) : [];

            // Ensure popup shell exists
            tmEnsurePopup();

            // Update title
            const titleEl = document.getElementById('tmTitleText');
            if (titleEl) {
                titleEl.innerHTML = `Template Manager <span class="tm-titlebar-sub">${escapeHtml(item.name || type)}</span>`;
            }

            // Show
            const overlay = document.getElementById('tmOverlay');
            const popup = document.getElementById('tmPopup');
            if (overlay) { overlay.classList.add('tm-visible'); }
            if (popup) { popup.classList.add('tm-visible'); }

            // Render — if no data, show import zone; otherwise show tree
            if (tmTreeData.length === 0) {
                tmShowImportZone();
            } else {
                tmRenderTree();
            }
            tmUpdateStats();
            tmUpdateModifiedState();

            // Clear search
            const searchEl = document.getElementById('tmSearch');
            if (searchEl) searchEl.value = '';

            // Update folder path badge
            tmUpdatePathBadge();
        }

        // ── Close ──
        function tmClose() {
            const overlay = document.getElementById('tmOverlay');
            const popup = document.getElementById('tmPopup');
            if (overlay) overlay.classList.remove('tm-visible');
            if (popup) popup.classList.remove('tm-visible');
            tmCurrentType = null;
            tmCurrentItemId = null;
            tmTreeData = [];
            tmModified = false;
        }

        // ── Ensure popup HTML shell exists ──
        function tmEnsurePopup() {
            if (document.getElementById('tmPopup')) return;
            const shell = document.createElement('div');
            shell.innerHTML = `
                <div class="tm-overlay" id="tmOverlay" onclick="tmClose()"></div>
                <div class="tm-popup" id="tmPopup">
                    <div class="tm-titlebar" id="tmTitlebar">
                        <div class="tm-titlebar-icon"><i class="fas fa-microscope"></i></div>
                        <div class="tm-titlebar-text" id="tmTitleText">Template Manager</div>
                        <div class="tm-titlebar-actions">
                            <button class="tm-titlebar-btn" onclick="tmExpandAll()" title="Expand All"><i class="fas fa-expand-alt"></i></button>
                            <button class="tm-titlebar-btn" onclick="tmCollapseAll()" title="Collapse All"><i class="fas fa-compress-alt"></i></button>
                            <button class="tm-titlebar-btn tm-close-btn" onclick="tmClose()" title="Close"><i class="fas fa-times"></i></button>
                        </div>
                    </div>
                    <div class="tm-toolbar">
                        <div class="tm-search-wrap">
                            <i class="fas fa-search"></i>
                            <input type="text" class="tm-search" id="tmSearch" placeholder="Search nodes..." oninput="tmFilterTree(this.value)">
                        </div>
                        <div class="tm-toolbar-divider"></div>
                        <button class="tm-toolbar-import" onclick="tmTriggerImport()" title="Import folder from your PC">
                            <i class="fas fa-folder-open"></i> Import Folder
                        </button>
                        <button class="tm-toolbar-import" onclick="tmTriggerImport(true)" title="Add a folder from your PC into the current tree">
                            <i class="fas fa-plus-circle"></i> Add Folder
                        </button>
                        <div class="tm-toolbar-divider"></div>
                        <button class="tm-toolbar-btn tm-add-btn" onclick="tmAddRootNode('folder')" title="Add Empty Folder"><i class="fas fa-folder-plus"></i> Folder</button>
                        <button class="tm-toolbar-btn tm-add-btn" onclick="tmAddRootNode('file')" title="Add Empty File"><i class="fas fa-file-medical"></i> File</button>
                        <input type="file" id="tmFolderPicker" webkitdirectory directory multiple style="display:none" onchange="tmHandleFolderPick(this)">
                    </div>
                    <div class="tm-stats" id="tmStats">
                        <div class="tm-stat"><i class="fas fa-folder"></i> <span class="tm-stat-val" id="tmStatFolders">0</span> folders</div>
                        <div class="tm-stat"><i class="fas fa-file"></i> <span class="tm-stat-val" id="tmStatFiles">0</span> files</div>
                        <div class="tm-stat"><i class="fas fa-layer-group"></i> Depth: <span class="tm-stat-val" id="tmStatDepth">0</span></div>
                        <span class="tm-folder-path" id="tmFolderPathBadge" style="display:none;" title=""><i class="fas fa-map-marker-alt"></i> <span id="tmFolderPathText"></span></span>
                        <div class="tm-breadcrumb" id="tmBreadcrumb"><span>Root</span></div>
                    </div>
                    <div class="tm-tree-container" id="tmTreeContainer"></div>
                    <div class="tm-footer">
                        <div class="tm-footer-info">
                            <span id="tmFooterStatus">Ready</span>
                            <span class="tm-modified" id="tmModifiedBadge" style="display:none;">● Modified</span>
                        </div>
                        <div class="tm-footer-actions">
                            <button class="tm-footer-btn tm-cancel" onclick="tmClose()">Cancel</button>
                            <button class="tm-footer-btn tm-save" onclick="tmSave()"><i class="fas fa-save"></i> Save</button>
                        </div>
                    </div>
                </div>`;
            document.body.appendChild(shell);
            tmInitDrag();
        }

        // ── Import Zone (shown when no hierarchy exists) ──
        let tmImportAddMode = false; // false = replace tree, true = add to existing tree

        function tmShowImportZone() {
            const container = document.getElementById('tmTreeContainer');
            if (!container) return;
            container.innerHTML = `
                <div class="tm-import-zone">
                    <div class="tm-import-icon"><i class="fas fa-folder-open"></i></div>
                    <h3>No File Hierarchy Found</h3>
                    <p>This item has no folder/file structure yet. Import a folder from your computer or start building manually.</p>
                    <div class="tm-import-actions">
                        <button class="tm-import-btn tm-import-primary" onclick="tmTriggerImport(false)">
                            <i class="fas fa-upload"></i>
                            <span>Import Folder</span>
                        </button>
                        <button class="tm-import-btn-empty" onclick="tmAddRootNode('folder'); tmRenderTree();">
                            <i class="fas fa-folder-plus"></i>
                            <span>Start Empty</span>
                        </button>
                    </div>
                </div>`;
        }

        function tmTriggerImport(addMode) {
            tmImportAddMode = !!addMode;
            const picker = document.getElementById('tmFolderPicker');
            if (picker) {
                picker.value = '';   // reset so same folder can be re-picked
                picker.click();
            }
        }

        function tmHandleFolderPick(input) {
            const files = input.files;
            if (!files || files.length === 0) return;

            // Show progress
            const container = document.getElementById('tmTreeContainer');
            if (container) {
                container.innerHTML = `
                    <div class="tm-import-progress">
                        <div class="tm-import-spinner"></div>
                        <p>Processing ${files.length} file${files.length > 1 ? 's' : ''}...</p>
                        <small>Building folder hierarchy</small>
                    </div>`;
            }

            // Use setTimeout so the UI updates before we process
            setTimeout(() => {
                const tree = tmBuildTreeFromFiles(files);

                if (tmImportAddMode && tmTreeData.length > 0) {
                    // Add mode — merge new tree roots into existing tree
                    tree.forEach(n => tmTreeData.push(n));
                } else {
                    // Replace mode
                    tmTreeData = tree;
                }

                // Extract root folder path for the badge
                if (files.length > 0) {
                    const firstPath = files[0].webkitRelativePath || files[0].name;
                    const rootFolder = firstPath.split('/')[0] || firstPath;
                    tmImportedPath = rootFolder;
                }

                tmModified = true;
                tmRenderTree();
                tmUpdateStats();
                tmUpdateModifiedState();
                tmUpdatePathBadge();

                const action = tmImportAddMode ? 'added to' : 'imported into';
                if (typeof showToast === 'function') {
                    showToast(`📂 Folder ${action} Template Manager (${files.length} files)`, 'success');
                }
            }, 80);
        }

        // Build a nested tree structure from the FileList (webkitdirectory)
        function tmBuildTreeFromFiles(fileList) {
            // Step 1: Build a nested object from relative paths
            const root = {};  // { [name]: { _files: [], _children: {} } }

            for (let i = 0; i < fileList.length; i++) {
                const f = fileList[i];
                const relPath = f.webkitRelativePath || f.name;
                const parts = relPath.split('/');

                let current = root;
                for (let p = 0; p < parts.length; p++) {
                    const part = parts[p];
                    if (p === parts.length - 1) {
                        // It's a file
                        if (!current._files) current._files = [];
                        current._files.push(part);
                    } else {
                        // It's a folder
                        if (!current._children) current._children = {};
                        if (!current._children[part]) current._children[part] = {};
                        current = current._children[part];
                    }
                }
            }

            // Step 2: Convert the nested object into tmTreeData format
            function convert(obj, folderName) {
                const node = {
                    id: 'tm_' + (++tmIdCounter),
                    name: folderName,
                    type: 'folder',
                    desc: '',
                    children: [],
                    _expanded: true
                };

                // Add sub-folders first
                if (obj._children) {
                    const sortedDirs = Object.keys(obj._children).sort((a, b) => a.localeCompare(b));
                    for (const dirName of sortedDirs) {
                        node.children.push(convert(obj._children[dirName], dirName));
                    }
                }

                // Add files
                if (obj._files) {
                    const sortedFiles = [...obj._files].sort((a, b) => a.localeCompare(b));
                    for (const fileName of sortedFiles) {
                        node.children.push({
                            id: 'tm_' + (++tmIdCounter),
                            name: fileName,
                            type: 'file',
                            desc: '',
                            children: []
                        });
                    }
                }

                return node;
            }

            // The top-level of root._children contains the root folder(s)
            const results = [];
            if (root._children) {
                const topFolders = Object.keys(root._children).sort((a, b) => a.localeCompare(b));
                for (const folder of topFolders) {
                    results.push(convert(root._children[folder], folder));
                }
            }
            // Top-level loose files (unlikely with webkitdirectory, but handle anyway)
            if (root._files) {
                for (const fileName of root._files) {
                    results.push({
                        id: 'tm_' + (++tmIdCounter),
                        name: fileName,
                        type: 'file',
                        desc: '',
                        children: []
                    });
                }
            }

            return results;
        }

        function tmUpdatePathBadge() {
            const badge = document.getElementById('tmFolderPathBadge');
            const text = document.getElementById('tmFolderPathText');
            if (!badge || !text) return;
            if (tmImportedPath) {
                text.textContent = tmImportedPath;
                badge.title = 'Imported from: ' + tmImportedPath;
                badge.style.display = 'inline-flex';
            } else {
                badge.style.display = 'none';
            }
        }

        // ── Render tree into container ──
        function tmRenderTree(filterTerm) {
            const container = document.getElementById('tmTreeContainer');
            if (!container) return;

            if (!tmTreeData || tmTreeData.length === 0) {
                container.innerHTML = `<div class="tm-tree-empty"><i class="fas fa-tree"></i><p>No hierarchy found</p><small>Add folders or files using the toolbar</small></div>`;
                return;
            }

            const filter = (filterTerm || '').toLowerCase().trim();
            container.innerHTML = '';
            tmTreeData.forEach(node => {
                const el = tmRenderNode(node, filter, 0);
                if (el) container.appendChild(el);
            });
        }

        // Render a single node + children recursively
        function tmRenderNode(node, filter, depth) {
            // Filter check
            const nameMatch = !filter || node.name.toLowerCase().includes(filter);
            const descMatch = !filter || (node.desc || '').toLowerCase().includes(filter);
            let childrenMatch = false;

            // Check if any children match
            const childEls = [];
            if (node.children && node.children.length > 0) {
                node.children.forEach(child => {
                    const el = tmRenderNode(child, filter, depth + 1);
                    if (el) { childEls.push(el); childrenMatch = true; }
                });
            }

            // If filter active and nothing matches, skip
            if (filter && !nameMatch && !descMatch && !childrenMatch) return null;

            const div = document.createElement('div');
            div.className = 'tm-node' + (filter && nameMatch ? ' tm-highlight' : '');
            div.dataset.id = node.id;

            const hasChildren = node.type === 'folder';
            const isExpanded = node._expanded !== false;

            const row = document.createElement('div');
            row.className = 'tm-node-row';
            row.innerHTML = `
                <button class="tm-node-toggle ${hasChildren ? (isExpanded ? 'tm-expanded' : '') : 'tm-leaf'}" 
                        onclick="tmToggleNode('${node.id}')" title="${hasChildren ? 'Toggle expand' : ''}">
                    <i class="fas fa-chevron-right"></i>
                </button>
                <div class="tm-node-icon ${tmIconClass(node)}"><i class="fas ${tmFaIcon(node)}"></i></div>
                <div class="tm-node-info">
                    <div class="tm-node-name-row">
                        <input type="text" class="tm-node-name ${node.type === 'folder' ? 'tm-folder-name' : ''}" 
                               value="${escapeHtml(node.name)}" 
                               onchange="tmUpdateNode('${node.id}','name',this.value)"
                               oninput="tmUpdateNode('${node.id}','name',this.value)"
                               placeholder="Node name...">
                    </div>
                    <textarea class="tm-node-desc" placeholder="Add description..." 
                              onchange="tmUpdateNode('${node.id}','desc',this.value)"
                              oninput="tmUpdateNode('${node.id}','desc',this.value)">${escapeHtml(node.desc || '')}</textarea>
                </div>
                <div class="tm-node-actions">
                    ${hasChildren ? `<button class="tm-node-action tm-add-child" onclick="tmAddChild('${node.id}','folder')" title="Add subfolder"><i class="fas fa-folder-plus"></i></button>
                    <button class="tm-node-action tm-add-child" onclick="tmAddChild('${node.id}','file')" title="Add file"><i class="fas fa-file-medical"></i></button>` : ''}
                    <button class="tm-node-action tm-del" onclick="tmDeleteNode('${node.id}')" title="Delete"><i class="fas fa-trash-alt"></i></button>
                </div>`;
            div.appendChild(row);

            // Children container
            if (hasChildren) {
                const childrenDiv = document.createElement('div');
                childrenDiv.className = 'tm-node-children' + (isExpanded ? '' : ' tm-collapsed');
                childEls.forEach(c => childrenDiv.appendChild(c));
                div.appendChild(childrenDiv);
            }

            return div;
        }

        // ── Node operations ──
        function tmFindNode(id, nodes) {
            nodes = nodes || tmTreeData;
            for (const n of nodes) {
                if (n.id === id) return n;
                if (n.children) {
                    const found = tmFindNode(id, n.children);
                    if (found) return found;
                }
            }
            return null;
        }

        function tmFindParent(id, nodes, parent) {
            nodes = nodes || tmTreeData;
            for (const n of nodes) {
                if (n.id === id) return { parent, siblings: nodes };
                if (n.children) {
                    const found = tmFindParent(id, n.children, n);
                    if (found) return found;
                }
            }
            return null;
        }

        function tmToggleNode(id) {
            const node = tmFindNode(id);
            if (!node) return;
            node._expanded = node._expanded === false ? true : false;
            // Toggle in DOM without full re-render
            const nodeEl = document.querySelector(`.tm-node[data-id="${id}"]`);
            if (nodeEl) {
                const toggle = nodeEl.querySelector(':scope > .tm-node-row .tm-node-toggle');
                const children = nodeEl.querySelector(':scope > .tm-node-children');
                if (toggle) toggle.classList.toggle('tm-expanded', node._expanded);
                if (children) children.classList.toggle('tm-collapsed', !node._expanded);
            }
        }

        function tmUpdateNode(id, field, value) {
            const node = tmFindNode(id);
            if (!node) return;
            node[field] = value;
            tmModified = true;
            tmUpdateModifiedState();
        }

        function tmDeleteNode(id) {
            const info = tmFindParent(id);
            if (!info) return;
            const idx = info.siblings.findIndex(n => n.id === id);
            if (idx !== -1) {
                info.siblings.splice(idx, 1);
                tmModified = true;
                tmRenderTree(document.getElementById('tmSearch')?.value);
                tmUpdateStats();
                tmUpdateModifiedState();
            }
        }

        function tmAddChild(parentId, type) {
            const parent = tmFindNode(parentId);
            if (!parent) return;
            if (!parent.children) parent.children = [];
            const newNode = {
                id: 'tm_' + (++tmIdCounter),
                name: type === 'folder' ? 'new-folder' : 'new-file.txt',
                type: type,
                desc: '',
                children: []
            };
            parent.children.push(newNode);
            parent._expanded = true;
            tmModified = true;
            tmRenderTree(document.getElementById('tmSearch')?.value);
            tmUpdateStats();
            tmUpdateModifiedState();
            // Focus the new node name
            setTimeout(() => {
                const el = document.querySelector(`.tm-node[data-id="${newNode.id}"] .tm-node-name`);
                if (el) { el.focus(); el.select(); }
            }, 50);
        }

        function tmAddRootNode(type) {
            const newNode = {
                id: 'tm_' + (++tmIdCounter),
                name: type === 'folder' ? 'new-folder' : 'new-file.txt',
                type: type,
                desc: '',
                children: []
            };
            tmTreeData.push(newNode);
            tmModified = true;
            tmRenderTree(document.getElementById('tmSearch')?.value);
            tmUpdateStats();
            tmUpdateModifiedState();
            setTimeout(() => {
                const el = document.querySelector(`.tm-node[data-id="${newNode.id}"] .tm-node-name`);
                if (el) { el.focus(); el.select(); }
            }, 50);
        }

        // ── Expand / Collapse all ──
        function tmSetExpandAll(nodes, val) {
            if (!nodes) return;
            nodes.forEach(n => {
                if (n.type === 'folder') {
                    n._expanded = val;
                    tmSetExpandAll(n.children, val);
                }
            });
        }
        function tmExpandAll() {
            tmSetExpandAll(tmTreeData, true);
            tmRenderTree(document.getElementById('tmSearch')?.value);
        }
        function tmCollapseAll() {
            tmSetExpandAll(tmTreeData, false);
            tmRenderTree(document.getElementById('tmSearch')?.value);
        }

        // ── Search/filter ──
        function tmFilterTree(term) {
            tmRenderTree(term);
        }

        // ── Stats ──
        function tmCountNodes(nodes, stats) {
            stats = stats || { folders: 0, files: 0, maxDepth: 0 };
            if (!nodes) return stats;
            nodes.forEach(n => {
                if (n.type === 'folder') stats.folders++;
                else stats.files++;
                if (n.children && n.children.length > 0) {
                    const sub = tmCountNodes(n.children, { folders: stats.folders, files: stats.files, maxDepth: stats.maxDepth + 1 });
                    stats.folders = sub.folders;
                    stats.files = sub.files;
                    if (sub.maxDepth > stats.maxDepth) stats.maxDepth = sub.maxDepth;
                }
            });
            return stats;
        }
        function tmUpdateStats() {
            const s = tmCountNodes(tmTreeData, { folders: 0, files: 0, maxDepth: 0 });
            const fEl = document.getElementById('tmStatFolders');
            const fiEl = document.getElementById('tmStatFiles');
            const dEl = document.getElementById('tmStatDepth');
            if (fEl) fEl.textContent = s.folders;
            if (fiEl) fiEl.textContent = s.files;
            if (dEl) dEl.textContent = s.maxDepth;
        }

        function tmUpdateModifiedState() {
            const badge = document.getElementById('tmModifiedBadge');
            const status = document.getElementById('tmFooterStatus');
            if (badge) badge.style.display = tmModified ? 'inline' : 'none';
            if (status) status.textContent = tmModified ? 'Unsaved changes' : 'Ready';
        }

        // ── Save ──
        function tmSave() {
            if (!tmCurrentType || !tmCurrentItemId) return;
            const item = dynamicItems[tmCurrentType]?.find(it => it.id === tmCurrentItemId);
            if (!item) return;

            // Serialize tree back to text
            const newText = tmSerializeTree(tmTreeData, item.name);

            // Update item prompt
            item.prompt = newText;
            saveDynamicItems();
            renderDynamicItems(tmCurrentType);

            tmModified = false;
            tmUpdateModifiedState();

            if (typeof showToast === 'function') {
                const s = tmCountNodes(tmTreeData);
                showToast(`✅ Template saved — ${s.folders} folder(s), ${s.files} file(s)`, 'success');
            }

            tmClose();
        }

        // ── Popup dragging ──
        function tmInitDrag() {
            const titlebar = document.getElementById('tmTitlebar');
            const popup = document.getElementById('tmPopup');
            if (!titlebar || !popup) return;

            let dragging = false, offX = 0, offY = 0;

            titlebar.addEventListener('mousedown', function(e) {
                // Don't drag on buttons
                if (e.target.closest('.tm-titlebar-btn') || e.target.closest('.tm-titlebar-actions')) return;
                dragging = true;
                popup.classList.add('tm-dragging');
                const rect = popup.getBoundingClientRect();
                offX = e.clientX - rect.left;
                offY = e.clientY - rect.top;
                document.body.style.userSelect = 'none';
            });

            document.addEventListener('mousemove', function(e) {
                if (!dragging) return;
                e.preventDefault();
                const x = e.clientX - offX;
                const y = e.clientY - offY;
                popup.style.left = x + 'px';
                popup.style.top = y + 'px';
                popup.style.transform = 'none';
            });

            document.addEventListener('mouseup', function() {
                if (dragging) {
                    dragging = false;
                    popup.classList.remove('tm-dragging');
                    document.body.style.userSelect = '';
                }
            });
        }
        
        // Auto-save on changes
        function initDashboardAutoSave() {
            // Checkboxes
            ['dbMainCheckbox', 'dbCredentialsCheckbox', 'dbLocalhostCheckbox'].forEach(id => {
                const el = document.getElementById(id);
                if (el) el.addEventListener('change', saveDashboardSettings);
            });
            
            // Dropdown
            const dbDropdown = document.getElementById('dbDropdown');
            if (dbDropdown) dbDropdown.addEventListener('change', saveDashboardSettings);
        }

        // Handle file picker change
        document.addEventListener('DOMContentLoaded', function() {
            // Load saved settings
            loadDashboardSettings();
            
            // Load dynamic items
            loadDynamicItems();
            
            // Load language settings
            loadLanguageSettings();
            
            // Initialize auto-save
            initDashboardAutoSave();
        });

        // Handle database selection change
        function onDatabaseSelect() {
            const dropdown = document.getElementById('dbDropdown');
            const remoteCheckbox = document.getElementById('dbCredentialsCheckbox');
            const localhostCheckbox = document.getElementById('dbLocalhostCheckbox');
            const selectedOption = dropdown.options[dropdown.selectedIndex];
            
            // Reset connection check button
            resetDbConnCheckBtn();
            
            if (dropdown.value && selectedOption.dataset) {
                selectedDatabaseConnection = {
                    id: dropdown.value,
                    name: selectedOption.textContent,
                    host: selectedOption.dataset.host,
                    dbName: selectedOption.dataset.dbname,
                    username: selectedOption.dataset.username,
                    password: selectedOption.dataset.password,
                    port: selectedOption.dataset.port,
                    type: selectedOption.dataset.type
                };
                
                // If remote checkbox is checked and dropdown changed, append new remote credentials
                if (remoteCheckbox.checked) {
                    appendCredentialsToEditor('remote');
                }
                // If localhost checkbox is checked and dropdown changed, append new localhost credentials
                if (localhostCheckbox.checked) {
                    appendCredentialsToEditor('localhost');
                }
                
                // Auto-test connection when selected
                testSelectedConnection();
                // Sync DB tree checkbox state for the newly selected database
                ftSyncDbCheckbox();
            } else {
                selectedDatabaseConnection = null;
                ftSyncDbCheckbox();
            }
        }
        
        // ─── Database Tree Checkbox Handler (supports multiple DBs) ───
        if (!window._dbTreeFolderNames) window._dbTreeFolderNames = new Set();

        function ftSyncDbCheckbox() {
            const checkbox = document.getElementById('dbTreeCheckbox');
            if (!checkbox) return;
            const conn = selectedDatabaseConnection;
            if (conn && conn.dbName) {
                const dbFolderName = '🗄️ DB: ' + conn.dbName;
                checkbox.checked = window._dbTreeFolderNames.has(dbFolderName);
            } else {
                checkbox.checked = false;
            }
        }

        // Progress helper for DB tree loading
        function dbTreeProgress(percent, text) {
            const bar = document.getElementById('dbTreeStatusBar');
            const fill = document.getElementById('dbTreeStatusFill');
            const txt = document.getElementById('dbTreeStatusText');
            if (!bar) return;
            bar.classList.add('active');
            bar.classList.remove('done');
            if (fill) fill.style.width = percent + '%';
            if (txt) txt.textContent = text;
        }
        function dbTreeProgressDone(text) {
            const bar = document.getElementById('dbTreeStatusBar');
            const fill = document.getElementById('dbTreeStatusFill');
            const txt = document.getElementById('dbTreeStatusText');
            if (!bar) return;
            bar.classList.add('done');
            if (fill) fill.style.width = '100%';
            if (txt) txt.textContent = text || 'Done!';
            setTimeout(() => {
                bar.classList.remove('active', 'done');
                if (fill) fill.style.width = '0%';
                if (txt) txt.textContent = '';
            }, 2500);
        }
        function dbTreeProgressHide() {
            const bar = document.getElementById('dbTreeStatusBar');
            const fill = document.getElementById('dbTreeStatusFill');
            const txt = document.getElementById('dbTreeStatusText');
            if (!bar) return;
            bar.classList.remove('active', 'done');
            if (fill) fill.style.width = '0%';
            if (txt) txt.textContent = '';
        }

        async function onDbTreeCheckboxChange() {
            const checkbox = document.getElementById('dbTreeCheckbox');
            const label = checkbox.closest('.db-tree-checkbox');

            const dropdown = document.getElementById('dbDropdown');
            if (!dropdown.value || !selectedDatabaseConnection) {
                showToast('⚠️ Please select a database first', 'warning');
                checkbox.checked = false;
                return;
            }

            const conn = selectedDatabaseConnection;
            const dbFolderName = '🗄️ DB: ' + conn.dbName;

            if (!checkbox.checked) {
                // Unchecked — remove only this DB's tree
                if (window._dbTreeFolderNames.has(dbFolderName)) {
                    const sid = ftGetSafeId(dbFolderName);
                    ftClearNodeMapForSid(sid);
                    ftFolderStore.delete(dbFolderName);
                    ftIdToName.delete(sid);
                    knownFolders.delete(dbFolderName);
                    const el = document.getElementById('ftCard_' + sid);
                    if (el) el.remove();
                    window._dbTreeFolderNames.delete(dbFolderName);
                    ftUpdateContainer();
                    showToast('🗑️ Database tree removed: ' + conn.dbName, 'info');
                }
                return;
            }

            // Checked — already exists? skip
            if (window._dbTreeFolderNames.has(dbFolderName)) {
                showToast('ℹ️ Database already in project folders', 'info');
                return;
            }

            // ── Start loading animation ──
            label.classList.add('loading');
            dbTreeProgress(5, 'Connecting...');

            try {
                // Step 1: Prepare request
                await new Promise(r => setTimeout(r, 150));
                dbTreeProgress(15, 'Connecting to ' + conn.dbName + '...');

                const formData = new FormData();
                formData.append('action', 'get_db_tree');
                formData.append('host', conn.host || 'localhost');
                formData.append('port', conn.port || '3306');
                formData.append('dbName', conn.dbName || '');
                formData.append('username', conn.username || 'root');
                formData.append('password', conn.password || '');

                // Step 2: Fetch tables
                dbTreeProgress(25, 'Fetching tables...');
                const resp = await fetch('', { method: 'POST', body: formData });

                dbTreeProgress(50, 'Reading response...');
                const data = await resp.json();

                if (!data.success) {
                    showToast('❌ ' + (data.message || 'Failed to fetch tables'), 'error');
                    checkbox.checked = false;
                    label.classList.remove('loading');
                    dbTreeProgressHide();
                    return;
                }

                // Step 3: Analyze relationships
                const tableCount = data.tables ? data.tables.length : 0;
                dbTreeProgress(65, 'Analyzing ' + tableCount + ' tables...');
                await new Promise(r => setTimeout(r, 200));

                // Step 4: Build tree
                dbTreeProgress(75, 'Building relational tree...');
                const treeData = buildDbRelationalTree(data.database, data.tables, data.relationships || []);
                await new Promise(r => setTimeout(r, 150));

                // Track this DB
                window._dbTreeFolderNames.add(dbFolderName);

                // Store in ftFolderStore — same format as folder tree
                const treeText = buildTreeDiagram(dbFolderName, treeData);
                ftFolderStore.set(dbFolderName, {
                    path: conn.host + '/' + data.database,
                    treeText: treeText,
                    treeData: treeData,
                    notes: '',
                    addedAt: Date.now(),
                    _dirty: false
                });
                knownFolders.set(dbFolderName, { addedAt: Date.now(), path: conn.host + '/' + data.database });

                // Step 5: Render
                dbTreeProgress(90, 'Rendering tree...');
                const sid = ftGetSafeId(dbFolderName);
                const existingCard = document.getElementById('ftCard_' + sid);
                if (existingCard) {
                    ftClearNodeMapForSid(sid);
                    existingCard.outerHTML = ftRenderCard(dbFolderName);
                    requestAnimationFrame(() => ftInitAutoResize(sid));
                } else {
                    ftAddFolderCard(dbFolderName);
                }
                // Collapse all nodes by default for DB trees
                requestAnimationFrame(() => ftCollapseAllNodes(sid));
                ftUpdateContainer();

                // Step 6: Done
                const relCount = data.relationships ? data.relationships.length : 0;
                dbTreeProgressDone(tableCount + ' tables · ' + relCount + ' relations ✓');
                showToast(`✅ Database tree: ${tableCount} tables, ${relCount} relationships`, 'success');

            } catch (err) {
                console.error('DB Tree error:', err);
                showToast('❌ Error fetching database tree', 'error');
                checkbox.checked = false;
                dbTreeProgressHide();
            } finally {
                label.classList.remove('loading');
            }
        }

        // Build a relational tree structure from flat tables + foreign key relationships
        function buildDbRelationalTree(dbName, tables, relationships) {
            if (!tables || tables.length === 0) return [];

            // Map: tableName → table data
            const tableMap = new Map();
            tables.forEach(t => tableMap.set(t.name, t));

            // Map: parentTable → [childTables] based on FK (child has FK pointing to parent)
            const childrenOf = new Map();
            const hasParent = new Set();

            // 1. Use actual foreign keys
            for (const rel of relationships) {
                const parent = rel.to_table;   // referenced table = parent
                const child = rel.from_table;   // table with FK = child
                if (parent === child) continue;  // self-referencing — skip
                if (!tableMap.has(parent) || !tableMap.has(child)) continue;
                if (!childrenOf.has(parent)) childrenOf.set(parent, new Set());
                childrenOf.get(parent).add(child);
                hasParent.add(child);
            }

            // 2. Heuristic: detect implied relationships by naming convention
            //    e.g. "user_id" column in "orders" → orders is child of users
            const tableNames = Array.from(tableMap.keys());
            for (const t of tables) {
                for (const col of (t.columns || [])) {
                    if (!col.name.endsWith('_id')) continue;
                    const baseName = col.name.slice(0, -3); // remove _id
                    // Try to find parent table: exact match, plural, or with 's'
                    let parentName = null;
                    const candidates = [baseName, baseName + 's', baseName + 'es', baseName.replace(/ie$/, 'y') + 's'];
                    for (const c of candidates) {
                        if (tableMap.has(c) && c !== t.name) { parentName = c; break; }
                    }
                    if (parentName && !hasParent.has(t.name)) {
                        if (!childrenOf.has(parentName)) childrenOf.set(parentName, new Set());
                        if (!childrenOf.get(parentName).has(t.name)) {
                            childrenOf.get(parentName).add(t.name);
                            hasParent.add(t.name);
                        }
                    }
                }
            }

            // 3. Build tree recursively
            const visited = new Set();
            function buildNode(tableName) {
                if (visited.has(tableName)) return null;
                visited.add(tableName);
                const tbl = tableMap.get(tableName);
                if (!tbl) return null;

                const kids = childrenOf.get(tableName);
                const children = [];
                if (kids) {
                    const sorted = Array.from(kids).sort();
                    for (const kidName of sorted) {
                        const kidNode = buildNode(kidName);
                        if (kidNode) children.push(kidNode);
                    }
                }

                // Each table is a "folder" so it can have children (sub-tables)
                // Columns become "file" children with description = type info
                const colChildren = (tbl.columns || []).map(col => {
                    let desc = col.type;
                    if (col.key === 'PRI') desc += ' | PRIMARY KEY';
                    else if (col.key === 'MUL') desc += ' | FOREIGN KEY';
                    else if (col.key === 'UNI') desc += ' | UNIQUE';
                    if (col.nullable) desc += ' | NULL';
                    if (col.extra) desc += ' | ' + col.extra;
                    return {
                        name: col.name,
                        type: 'file',
                        description: desc,
                        children: []
                    };
                });

                return {
                    name: tableName,
                    type: 'folder',
                    description: `${tbl.rowCount || 0} rows` + (tbl.primaryKey ? ` | PK: ${tbl.primaryKey}` : ''),
                    children: [...children, ...colChildren]
                };
            }

            // Root tables = tables that have no parent
            const rootTables = tableNames.filter(t => !hasParent.has(t)).sort();
            // Also add orphan tables that were skipped
            const orphans = tableNames.filter(t => hasParent.has(t) && !visited.has(t));

            const tree = [];
            for (const rt of rootTables) {
                const node = buildNode(rt);
                if (node) tree.push(node);
            }
            // Add any remaining orphans (circular refs etc.)
            for (const t of tableNames) {
                if (!visited.has(t)) {
                    const node = buildNode(t);
                    if (node) tree.push(node);
                }
            }

            return tree;
        }

