        // Toggle database credentials in editor
        function toggleDatabaseCredentials(mode = 'remote') {
            const checkbox = mode === 'localhost' 
                ? document.getElementById('dbLocalhostCheckbox')
                : document.getElementById('dbCredentialsCheckbox');
            const dropdown = document.getElementById('dbDropdown');
            
            if (checkbox.checked) {
                if (!dropdown.value) {
                    showToast('⚠️ Please select a database first', 'warning');
                    checkbox.checked = false;
                    return;
                }
                appendCredentialsToEditor(mode);
            } else {
                // Remove only the last added credentials for this mode when unchecking
                if (mode === 'localhost' && lastAddedLocalhostCredId) {
                    removeCredentialsByIdFromEditor(lastAddedLocalhostCredId);
                    lastAddedLocalhostCredId = null;
                } else if (mode === 'remote' && lastAddedRemoteCredId) {
                    removeCredentialsByIdFromEditor(lastAddedRemoteCredId);
                    lastAddedRemoteCredId = null;
                }
            }
        }

        // Append credentials to the END of prompt editor (always append, never replace)
        function appendCredentialsToEditor(mode = 'remote') {
            if (!selectedDatabaseConnection) return;
            
            const editor = document.getElementById('promptEditor');
            const conn = selectedDatabaseConnection;
            
            // Determine host based on mode
            const host = mode === 'localhost' ? 'localhost' : conn.host;
            const modeLabel = mode === 'localhost' ? 'LOCALHOST (ON-SERVER)' : 'REMOTE CONNECTION';
            const modeIcon = mode === 'localhost' ? '🖥️' : '🌐';
            
            // Create unique ID for this credentials block
            const credId = `DB_${mode}_${conn.id}_${Date.now()}`;
            
            // Track the credential ID based on mode
            if (mode === 'localhost') {
                lastAddedLocalhostCredId = credId;
            } else {
                lastAddedRemoteCredId = credId;
            }
            
            // Create credentials block with ID marker
            const credentialsBlock = `
<!-- CRED:${credId} -->
╔══════════════════════════════════════════════════════════════╗
║  ${modeIcon}  DATABASE CREDENTIALS - ${modeLabel.padEnd(30)}║
╠══════════════════════════════════════════════════════════════╣
║  Name:     ${conn.name.padEnd(48)}║
║  Host:     ${host.padEnd(48)}║
║  Database: ${conn.dbName.padEnd(48)}║
║  Username: ${conn.username.padEnd(48)}║
║  Password: ${conn.password.padEnd(48)}║
║  Port:     ${conn.port.padEnd(48)}║
║  Type:     ${(conn.type === 'vps' ? 'VPS' : 'Shared Hosting').padEnd(48)}║
╚══════════════════════════════════════════════════════════════╝
<!-- /CRED:${credId} -->`.trim();
            
            // APPEND to the end (not prepend)
            if (editor.value.trim()) {
                editor.value = editor.value.trimEnd() + '\n\n' + credentialsBlock;
            } else {
                editor.value = credentialsBlock;
            }
            
            updateCounts();
            recordHistoryState(true);
            
            const toastMsg = mode === 'localhost' 
                ? `🖥️ Localhost credentials appended` 
                : `🌐 Remote credentials appended`;
            showToast(toastMsg, 'success');
        }

        // Remove specific credentials block by ID
        function removeCredentialsByIdFromEditor(credId) {
            const editor = document.getElementById('promptEditor');
            const startMarker = `<!-- CRED:${credId} -->`;
            const endMarker = `<!-- /CRED:${credId} -->`;
            
            let content = editor.value;
            const startIdx = content.indexOf(startMarker);
            
            if (startIdx !== -1) {
                const endIdx = content.indexOf(endMarker, startIdx);
                if (endIdx !== -1) {
                    const before = content.substring(0, startIdx).trimEnd();
                    const after = content.substring(endIdx + endMarker.length).trimStart();
                    editor.value = before + (before && after ? '\n\n' : '') + after;
                    
                    updateCounts();
                    recordHistoryState(true);
                    showToast('🗑️ Credentials removed', 'info');
                }
            }
        }

        // Remove ALL credentials blocks from the editor (legacy function - not used anymore)
        function removeCredentialsFromEditor() {
            const editor = document.getElementById('promptEditor');
            // Remove all credential blocks using regex
            let content = editor.value;
            const regex = /<!-- CRED:[^>]+-->[\s\S]*?<!-- \/CRED:[^>]+-->\n*/g;
            const newContent = content.replace(regex, '').trim();
            
            if (newContent !== content.trim()) {
                editor.value = newContent;
                updateCounts();
                recordHistoryState(true);
                showToast('🗑️ Credentials removed', 'info');
            }
        }

        // Refresh databases when window gains focus (syncs with Database Hub)
        window.addEventListener('focus', async () => {
            try {
                const currentCount = document.getElementById('dbDropdown').options.length - 1;
                const response = await fetch(DATABASE_HUB_API);
                const data = await response.json();
                
                // Only reload if count changed
                if (data.success && data.connections.length !== currentCount) {
                    await loadHostingerDatabases();
                    console.log('🔄 Database list refreshed from Database Hub');
                }
            } catch (e) {
                console.log('⚠️ Could not check for new connections');
            }
        });

        // Initialize
        document.addEventListener('DOMContentLoaded', async () => {
            loadPromptTemplates(); // Load from database
            loadSavedPrompts();
            loadUploadedFiles();
            setupEventListeners();
            initDistributionSlider(); // Initialize distribution slider
            initHistory(); // Initialize history system
            setupHistoryKeyboardShortcuts(); // Setup keyboard shortcuts
            sptLoadFiles(); // Load static template files
            await loadHostingerDatabases(); // Load database connections from Hub
        });
        
        // Load templates from database
        async function loadPromptTemplates() {
            const loading = document.getElementById('templateLoading');
            const promptList = document.getElementById('promptList');
            
            loading.style.display = 'block';
            promptList.innerHTML = '';
            
            try {
                const formData = new FormData();
                formData.append('action', 'get_templates');
                
                const response = await fetch(window.location.href, {
                    method: 'POST',
                    body: formData
                });
                
                const data = await response.json();
                
                if (data.success) {
                    promptTemplates = data.templates.map(t => ({
                        id: parseInt(t.id),
                        name: t.name,
                        content: t.content
                    }));
                    renderPromptList();
                } else {
                    showToast('Failed to load templates: ' + data.message, 'error');
                }
            } catch (error) {
                console.error('Error loading templates:', error);
                showToast('Error loading templates', 'error');
            } finally {
                loading.style.display = 'none';
            }
        }

        // Render prompt checkboxes
        function renderPromptList(searchTerm = '') {
            const container = document.getElementById('promptList');
            const noResults = document.getElementById('promptNoResults');
            const searchLower = searchTerm.toLowerCase().trim();
            
            // Filter templates based on search
            const filteredTemplates = searchLower 
                ? promptTemplates.filter(p => 
                    p.name.toLowerCase().includes(searchLower) || 
                    p.content.toLowerCase().includes(searchLower) ||
                    `#${p.id}`.includes(searchLower)
                )
                : promptTemplates;
            
            if (filteredTemplates.length === 0) {
                container.innerHTML = '';
                noResults.style.display = 'block';
                return;
            }
            
            noResults.style.display = 'none';
            
            container.innerHTML = filteredTemplates.map(prompt => {
                const isChecked = activePrompts.has(prompt.id);
                const highlightedName = searchLower 
                    ? highlightText(prompt.name, searchLower)
                    : prompt.name;
                const contentPreview = prompt.content.replace(/\n/g, ' ').substring(0, 50) + '...';
                
                return `
                    <div class="prompt-item ${isChecked ? 'checked' : ''}" data-id="${prompt.id}">
                        <div class="prompt-item-checkbox" onclick="togglePrompt(${prompt.id})">
                            <input type="checkbox" ${isChecked ? 'checked' : ''}>
                            <div class="checkbox-box"><i class="fas fa-check"></i></div>
                        </div>
                        <div class="prompt-item-content" onclick="openTemplatePreview(${prompt.id})">
                            <div class="prompt-item-name">${highlightedName}</div>
                            <div class="prompt-item-preview">${escapeHtml(contentPreview)}</div>
                        </div>
                        <div class="prompt-item-actions">
                            <button type="button" class="prompt-action-icon copy" onclick="copyTemplate(${prompt.id})" title="Copy">
                                <i class="fas fa-copy"></i>
                            </button>
                            <button type="button" class="prompt-action-icon push-right" onclick="pushTemplateToEditor(${prompt.id})" title="Push to Editor">
                                <i class="fas fa-arrow-right"></i>
                            </button>
                            <button type="button" class="prompt-action-icon pull-left" onclick="pullToTemplate(${prompt.id})" title="Pull from Editor">
                                <i class="fas fa-arrow-left"></i>
                            </button>
                            <button type="button" class="prompt-action-icon edit" onclick="openEditTemplateModal(${prompt.id})" title="Edit">
                                <i class="fas fa-edit"></i>
                            </button>
                            <button type="button" class="prompt-action-icon delete" onclick="confirmDeleteTemplate(${prompt.id})" title="Delete">
                                <i class="fas fa-trash"></i>
                            </button>
                        </div>
                    </div>
                `;
            }).join('');
            
            updatePromptCounter();
        }
        
        // Escape HTML for safe display
        function escapeHtml(text) {
            const div = document.createElement('div');
            div.textContent = text;
            return div.innerHTML;
        }
        
        // Highlight search text
        function highlightText(text, search) {
            if (!search) return text;
            const regex = new RegExp(`(${escapeRegex(search)})`, 'gi');
            return text.replace(regex, '<span class="highlight">$1</span>');
        }
        
        // Escape regex special characters
        function escapeRegex(string) {
            return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        }
        
        // Filter prompt templates (called on input)
        function filterPromptTemplates() {
            const searchInput = document.getElementById('promptSearchInput');
            const clearBtn = document.getElementById('promptSearchClear');
            const searchTerm = searchInput.value;
            
            // Show/hide clear button
            clearBtn.style.display = searchTerm ? 'flex' : 'none';
            
            renderPromptList(searchTerm);
        }
        
        // Clear prompt search
        function clearPromptSearch() {
            const searchInput = document.getElementById('promptSearchInput');
            const clearBtn = document.getElementById('promptSearchClear');
            
            searchInput.value = '';
            clearBtn.style.display = 'none';
            renderPromptList();
            searchInput.focus();
        }
        
        // Select all visible prompts
        function selectAllPrompts() {
            const searchTerm = document.getElementById('promptSearchInput').value.toLowerCase().trim();
            const templatesToSelect = searchTerm 
                ? promptTemplates.filter(p => 
                    p.name.toLowerCase().includes(searchTerm) || 
                    p.content.toLowerCase().includes(searchTerm)
                )
                : promptTemplates;
            
            const editor = document.getElementById('promptEditor');
            let addedCount = 0;
            
            templatesToSelect.forEach(prompt => {
                if (!activePrompts.has(prompt.id)) {
                    activePrompts.add(prompt.id);
                    
                    // Append to editor
                    if (editor.value.trim()) {
                        editor.value += '\n\n';
                    }
                    editor.value += prompt.content;
                    addedCount++;
                }
            });
            
            renderPromptList(searchTerm);
            updateCounts();
            updateSelectAllTemplatesCheckbox();
            
            if (addedCount > 0) {
                showToast(`✅ ${addedCount} template(s) added to editor`, 'success');
            } else {
                showToast('All visible templates already selected', 'info');
            }
        }
        
        // Deselect all visible prompts
        function deselectAllPrompts() {
            const searchTerm = document.getElementById('promptSearchInput').value.toLowerCase().trim();
            const templatesToDeselect = searchTerm 
                ? promptTemplates.filter(p => 
                    p.name.toLowerCase().includes(searchTerm) || 
                    p.content.toLowerCase().includes(searchTerm)
                )
                : promptTemplates;
            
            let removedCount = 0;
            
            templatesToDeselect.forEach(prompt => {
                if (activePrompts.has(prompt.id)) {
                    activePrompts.delete(prompt.id);
                    removedCount++;
                }
            });
            
            rebuildEditor();
            renderPromptList(searchTerm);
            updateCounts();
            
            if (removedCount > 0) {
                showToast(`🗑️ ${removedCount} template(s) removed from editor`, 'info');
            } else {
                showToast('No templates to deselect', 'info');
            }
            
            // Update checkbox state
            updateSelectAllTemplatesCheckbox();
        }
        
        // Toggle all templates (checkbox handler)
        function toggleAllTemplates(checked) {
            if (checked) {
                selectAllPrompts();
            } else {
                deselectAllPrompts();
            }
        }
        
        // Update the "Select All" checkbox based on current selection
        function updateSelectAllTemplatesCheckbox() {
            const checkbox = document.getElementById('selectAllTemplatesCheckbox');
            if (!checkbox) return;
            
            const searchTerm = document.getElementById('promptSearchInput')?.value.toLowerCase().trim() || '';
            const visibleTemplates = searchTerm 
                ? promptTemplates.filter(p => 
                    p.name.toLowerCase().includes(searchTerm) || 
                    p.content.toLowerCase().includes(searchTerm)
                )
                : promptTemplates;
            
            if (visibleTemplates.length === 0) {
                checkbox.checked = false;
                checkbox.indeterminate = false;
            } else {
                const selectedCount = visibleTemplates.filter(p => activePrompts.has(p.id)).length;
                
                if (selectedCount === 0) {
                    checkbox.checked = false;
                    checkbox.indeterminate = false;
                } else if (selectedCount === visibleTemplates.length) {
                    checkbox.checked = true;
                    checkbox.indeterminate = false;
                } else {
                    checkbox.checked = false;
                    checkbox.indeterminate = true;
                }
            }
        }
        
        // Update prompt counter (includes static template)
        function updatePromptCounter() {
            const counter = document.getElementById('promptCounter');
            const total = promptTemplates.length + 4; // +4 for static "Read the Application" + "Table Designer" + "Reverse Engineer" + "Image to Code"
            const selected = activePrompts.size + (sptActive ? 1 : 0) + (typeof tdtActive !== 'undefined' && tdtActive ? 1 : 0) + (typeof retActive !== 'undefined' && retActive ? 1 : 0) + (typeof itcActive !== 'undefined' && itcActive ? 1 : 0);
            counter.textContent = `${selected}/${total}`;
            
            // Change color based on selection
            if (selected === 0) {
                counter.style.background = 'rgba(100, 100, 100, 0.15)';
                counter.style.color = 'var(--text-muted)';
            } else if (selected === total) {
                counter.style.background = 'rgba(16, 185, 129, 0.15)';
                counter.style.color = 'var(--success)';
            } else {
                counter.style.background = 'rgba(99, 102, 241, 0.15)';
                counter.style.color = 'var(--accent-primary)';
            }
        }
        
        // ============ TEMPLATE CRUD OPERATIONS ============
        
        // Open Add Template Modal
        function openAddTemplateModal() {
            const modal = document.getElementById('templateModal');
            const title = document.getElementById('templateModalTitle');
            const saveText = document.getElementById('templateSaveText');
            const nameInput = document.getElementById('templateNameInput');
            const contentInput = document.getElementById('templateContentInput');
            const editId = document.getElementById('templateEditId');
            
            title.innerHTML = '<i class="fas fa-plus-circle"></i> <span>Add New Template</span>';
            saveText.textContent = 'Add Template';
            nameInput.value = '';
            contentInput.value = '';
            editId.value = '';
            
            modal.classList.add('active');
            nameInput.focus();
        }
        
        // Open Edit Template Modal
        function openEditTemplateModal(id) {
            const template = promptTemplates.find(t => t.id === id);
            if (!template) return;
            
            const modal = document.getElementById('templateModal');
            const title = document.getElementById('templateModalTitle');
            const saveText = document.getElementById('templateSaveText');
            const nameInput = document.getElementById('templateNameInput');
            const contentInput = document.getElementById('templateContentInput');
            const editId = document.getElementById('templateEditId');
            
            title.innerHTML = '<i class="fas fa-edit"></i> <span>Edit Template</span>';
            saveText.textContent = 'Save Changes';
            nameInput.value = template.name;
            contentInput.value = template.content;
            editId.value = id;
            
            modal.classList.add('active');
            nameInput.focus();
        }
        
        // Close Template Modal
        function closeTemplateModal() {
            const modal = document.getElementById('templateModal');
            modal.classList.remove('active');
        }
        
        // Save Template (Add or Update)
        async function saveTemplate() {
            const nameInput = document.getElementById('templateNameInput');
            const contentInput = document.getElementById('templateContentInput');
            const editId = document.getElementById('templateEditId');
            
            const name = nameInput.value.trim();
            const content = contentInput.value.trim();
            const id = editId.value;
            
            if (!name || !content) {
                showToast('Please fill in both name and content', 'error');
                return;
            }
            
            const formData = new FormData();
            formData.append('name', name);
            formData.append('content', content);
            
            if (id) {
                formData.append('action', 'update_template');
                formData.append('id', id);
            } else {
                formData.append('action', 'add_template');
            }
            
            try {
                const response = await fetch(window.location.href, {
                    method: 'POST',
                    body: formData
                });
                
                const data = await response.json();
                
                if (data.success) {
                    // Record operation speed
                    if (data.operationTime) {
                        addSpeedEntry({
                            time: data.operationTime,
                            type: data.operationType || (id ? 'UPDATE_TEMPLATE' : 'ADD_TEMPLATE'),
                            connection: data.connectionType || currentConnectionType,
                            timestamp: Date.now()
                        });
                        updateSpeedMonitor();
                    }
                    showToast(`${data.message} ⏱️ ${data.operationTime}ms`, 'success');
                    closeTemplateModal();
                    await loadPromptTemplates();
                } else {
                    showToast(data.message, 'error');
                }
            } catch (error) {
                console.error('Error saving template:', error);
                showToast('Error saving template', 'error');
            }
        }
        
        // Confirm Delete Template
        function confirmDeleteTemplate(id) {
            const template = promptTemplates.find(t => t.id === id);
            if (!template) return;
            
            showConfirmModal({
                title: 'Delete Template?',
                message: `Are you sure you want to delete "${template.name}"?`,
                icon: 'fa-trash-alt',
                type: 'warning',
                confirmText: 'Delete',
                confirmIcon: 'fa-trash-alt',
                details: `<div style="background: var(--bg-tertiary); padding: 0.75rem; border-radius: 8px; font-size: 0.8rem; color: var(--text-muted); margin-top: 0.5rem;">
                    <strong>${template.name}</strong><br>
                    ${escapeHtml(template.content.substring(0, 100))}...
                </div>`,
                onConfirm: () => deleteTemplate(id)
            });
        }
        
        // Delete Template
        async function deleteTemplate(id) {
            const formData = new FormData();
            formData.append('action', 'delete_template');
            formData.append('id', id);
            
            try {
                const response = await fetch(window.location.href, {
                    method: 'POST',
                    body: formData
                });
                
                const data = await response.json();
                
                if (data.success) {
                    // Record operation speed
                    if (data.operationTime) {
                        addSpeedEntry({
                            time: data.operationTime,
                            type: data.operationType || 'DELETE_TEMPLATE',
                            connection: data.connectionType || currentConnectionType,
                            timestamp: Date.now()
                        });
                        updateSpeedMonitor();
                    }
                    
                    // Remove from active prompts if selected
                    if (activePrompts.has(id)) {
                        activePrompts.delete(id);
                        rebuildEditor();
                    }
                    
                    showToast(`${data.message} ⏱️ ${data.operationTime}ms`, 'success');
                    await loadPromptTemplates();
                } else {
                    showToast(data.message, 'error');
                }
            } catch (error) {
                console.error('Error deleting template:', error);
                showToast('Error deleting template', 'error');
            }
        }
        
        // Copy Template Content
        function copyTemplate(id) {
            const template = promptTemplates.find(t => t.id === id);
            if (!template) return;
            
            navigator.clipboard.writeText(template.content).then(() => {
                showToast(`"${template.name}" copied to clipboard!`, 'success');
            }).catch(err => {
                console.error('Failed to copy:', err);
                showToast('Failed to copy template', 'error');
            });
        }
        
        // Push template content to the prompt editor
        function pushTemplateToEditor(id) {
            const template = promptTemplates.find(t => t.id === id);
            if (!template) return;
            
            const editor = document.getElementById('promptEditor');
            editor.value = template.content;
            editor.dispatchEvent(new Event('input'));
            showToast(`➡️ "${template.name}" pushed to editor!`, 'success');
        }
        
        // Pull editor content to Template (overwrite template with editor content)
        function pullToTemplate(id) {
            const template = promptTemplates.find(t => t.id === id);
            if (!template) return;
            
            const editor = document.getElementById('promptEditor');
            const editorContent = editor.value.trim();
            
            if (!editorContent) {
                showToast('Editor is empty! Nothing to pull.', 'warning');
                return;
            }
            
            // Send update to server immediately
            const formData = new FormData();
            formData.append('action', 'update_template');
            formData.append('id', id);
            formData.append('name', template.name);
            formData.append('content', editorContent);
            
            fetch(window.location.href, {
                method: 'POST',
                body: formData
            })
            .then(res => res.json())
            .then(data => {
                if (data.success) {
                    // Update local array
                    template.content = editorContent;
                    showToast(`⬅️ "${template.name}" updated with editor content!`, 'success');
                    // Show inline banner above editor
                    showPullBanner(`⬅️ Pulled successfully to "${template.name}"`);
                } else {
                    showToast(data.message || 'Failed to update template', 'error');
                }
            })
            .catch(err => {
                console.error('Error:', err);
                showToast('Failed to update template', 'error');
            });
        }
        
        // ════════════════════════════════════════════════════════════
        // STATIC TEMPLATE: Read the Application (SPT)
        // ════════════════════════════════════════════════════════════
        
        const SPT_PROMPT_TEXT = `Please take the time to carefully and thoroughly review this particular application in order to gain a comprehensive understanding of its main objectives, core functionality, key features, and the intended goals it aims to achieve. Additionally, make sure to read through all of the related files that are associated with this application, which include JavaScript files, PHP files, CSS files, and HTML files. Once you have completed your thorough and comprehensive review of the application and all of its associated files, please return to provide your findings and insights.`;
        
        let sptActive = false;
        let sptFiles = []; // {name, storedName, size, content}
        let sptFilesOpen = false;
        const SPT_MARKER_START = '<!-- SPT:READ_APP -->';
        const SPT_MARKER_END = '<!-- /SPT:READ_APP -->';
        
        // Build the full content (prompt + files)
        function sptBuildContent() {
            let content = SPT_PROMPT_TEXT;
            
            if (sptFiles.length > 0) {
                const mode = document.getElementById('sptFileMode')?.value || 'reference';
                content += '\n\n────────────────────────────────────\n';
                content += `📎 ATTACHED FILES (${sptFiles.length})\n`;
                content += '────────────────────────────────────\n';
                
                sptFiles.forEach((f, i) => {
                    if (mode === 'content' && f.content) {
                        content += `\n── 📄 FILE #${i + 1}: ${f.name} ──\n`;
                        content += f.content;
                        content += '\n';
                    } else {
                        content += `  📄 ${f.name}`;
                        if (f.size) content += ` (${sptFormatSize(f.size)})`;
                        content += '\n';
                    }
                });
            }
            
            return content;
        }
        
        // Toggle static template on/off
        function sptToggle() {
            const container = document.getElementById('sptContainer');
            const editor = document.getElementById('promptEditor');
            
            sptActive = !sptActive;
            container.classList.toggle('checked', sptActive);
            
            if (sptActive) {
                // Append marked content to editor
                const fullContent = sptBuildContent();
                const markedContent = `${SPT_MARKER_START}\n${fullContent}\n${SPT_MARKER_END}`;
                
                if (editor.value.trim()) {
                    editor.value = editor.value.trimEnd() + '\n\n' + markedContent;
                } else {
                    editor.value = markedContent;
                }
                
                showToast('📖 "Read the Application" pushed to editor', 'success');
            } else {
                // Remove marked content from editor
                sptRemoveFromEditor();
                showToast('📖 "Read the Application" removed from editor', 'info');
            }
            
            updateCounts();
            updatePromptCounter();
            recordHistoryState(true);
        }
        
        // Remove SPT content from editor
        function sptRemoveFromEditor() {
            const editor = document.getElementById('promptEditor');
            const content = editor.value;
            const startIdx = content.indexOf(SPT_MARKER_START);
            
            if (startIdx !== -1) {
                const endIdx = content.indexOf(SPT_MARKER_END, startIdx);
                if (endIdx !== -1) {
                    const before = content.substring(0, startIdx).trimEnd();
                    const after = content.substring(endIdx + SPT_MARKER_END.length).trimStart();
                    editor.value = before + (before && after ? '\n\n' : '') + after;
                }
            }
        }
        
        // Refresh editor content when files change (only if active)
        function sptRefreshEditor() {
            if (!sptActive) return;
            sptRemoveFromEditor();
            
            const editor = document.getElementById('promptEditor');
            const fullContent = sptBuildContent();
            const markedContent = `${SPT_MARKER_START}\n${fullContent}\n${SPT_MARKER_END}`;
            
            if (editor.value.trim()) {
                editor.value = editor.value.trimEnd() + '\n\n' + markedContent;
            } else {
                editor.value = markedContent;
            }
            
            updateCounts();
            recordHistoryState(true);
        }
        
        // Copy static template content
        function sptCopy() {
            const content = sptBuildContent();
            navigator.clipboard.writeText(content).then(() => {
                showToast('📖 "Read the Application" copied!', 'success');
            }).catch(() => {
                showToast('Failed to copy', 'error');
            });
        }
        
        // Preview static template
        function sptPreview() {
            const modal = document.getElementById('templatePreviewModal');
            const previewName = document.getElementById('previewName');
            const previewContent = document.getElementById('previewContent');
            
            if (!modal || !previewName || !previewContent) return;
            
            previewName.textContent = '📌 Read the Application (Static)';
            previewContent.textContent = sptBuildContent();
            
            // Hide edit/use buttons for static template
            const editBtn = document.getElementById('previewEditBtn');
            const useBtn = document.getElementById('previewUseBtn');
            if (editBtn) editBtn.style.display = 'none';
            if (useBtn) useBtn.style.display = 'none';
            
            modal.classList.add('active');
        }
        
        // ═══════ Editor Direction Toggle (LTR ↔ RTL) ═══════
        function toggleEditorDir() {
            const editor = document.getElementById('promptEditor');
            const btn    = document.getElementById('btnDirToggle');
            const label  = document.getElementById('dirLabel');
            if (!editor || !btn || !label) return;

            const isRtl = editor.style.direction === 'rtl';
            editor.style.direction = isRtl ? 'ltr' : 'rtl';
            editor.style.textAlign = isRtl ? 'left' : 'right';
            label.textContent      = isRtl ? 'LTR' : 'RTL';
            btn.classList.toggle('rtl-active', !isRtl);
            editor.placeholder = isRtl
                ? "Your generated prompt will appear here...\n\nCheck the prompt templates on the left to build your prompt, or type directly."
                : "سيظهر الأمر الذي تم إنشاؤه هنا...\n\nاختر قوالب الأوامر من اليسار لبناء الأمر، أو اكتب مباشرة.";
        }

        // Toggle file upload section
        function sptToggleFiles() {
            sptFilesOpen = !sptFilesOpen;
            document.getElementById('sptFilesSection').style.display = sptFilesOpen ? 'block' : 'none';
        }
        
        // Handle file upload via PHP
        async function sptHandleFiles(fileList) {
            if (!fileList || fileList.length === 0) return;
            
            const dropZone = document.getElementById('sptDropZone');
            dropZone.innerHTML = '<i class="fas fa-spinner fa-spin"></i><span>Uploading...</span>';
            
            try {
                const formData = new FormData();
                formData.append('action', 'spt_upload_files');
                for (const file of Array.from(fileList)) {
                    formData.append('files[]', file);
                }
                
                const response = await fetch(window.location.href, {
                    method: 'POST',
                    body: formData
                });
                const data = await response.json();
                
                if (data.success && data.files.length > 0) {
                    data.files.forEach(f => {
                        sptFiles.push({
                            name: f.name,
                            storedName: f.storedName,
                            size: f.size,
                            content: f.content || ''
                        });
                    });
                    
                    sptRenderFileList();
                    sptUpdateFileBadge();
                    sptRefreshEditor();
                    showToast(`📎 ${data.files.length} file(s) attached`, 'success');
                } else {
                    showToast('Failed to upload files', 'error');
                }
            } catch (err) {
                console.error('SPT upload error:', err);
                showToast('Upload failed', 'error');
            }
            
            // Restore drop zone
            dropZone.innerHTML = '<i class="fas fa-cloud-upload-alt"></i><span>Drop files here or <span class="spt-browse">browse</span></span>';
        }
        
        // Remove a file
        async function sptRemoveFile(index) {
            const file = sptFiles[index];
            if (!file) return;
            
            // Delete from server
            try {
                const formData = new FormData();
                formData.append('action', 'spt_delete_file');
                formData.append('storedName', file.storedName);
                await fetch(window.location.href, { method: 'POST', body: formData });
            } catch (e) {
                console.warn('Failed to delete from server:', e);
            }
            
            sptFiles.splice(index, 1);
            sptRenderFileList();
            sptUpdateFileBadge();
            sptRefreshEditor();
            showToast(`📄 ${file.name} removed`, 'info');
        }
        
        // Render file list UI
        function sptRenderFileList() {
            const container = document.getElementById('sptFileList');
            if (sptFiles.length === 0) {
                container.innerHTML = '';
                return;
            }
            
            container.innerHTML = sptFiles.map((f, i) => `
                <div class="spt-file-item">
                    <i class="fas fa-file-code"></i>
                    <span class="spt-file-item-name" title="${f.name}">${f.name}</span>
                    <span class="spt-file-item-size">${sptFormatSize(f.size)}</span>
                    <button class="spt-file-item-remove" onclick="sptRemoveFile(${i})" title="Remove">
                        <i class="fas fa-times"></i>
                    </button>
                </div>
            `).join('');
        }
        
        // Update file badge count
        function sptUpdateFileBadge() {
            const badge = document.getElementById('sptFileBadge');
            const btn = document.getElementById('sptFilesBtn');
            
            if (sptFiles.length > 0) {
                badge.textContent = sptFiles.length;
                badge.style.display = 'flex';
                btn.classList.add('has-files');
            } else {
                badge.style.display = 'none';
                btn.classList.remove('has-files');
            }
        }
        
        // Format file size
        function sptFormatSize(bytes) {
            if (!bytes || bytes === 0) return '0 B';
            const k = 1024;
            const sizes = ['B', 'KB', 'MB'];
            const i = Math.floor(Math.log(bytes) / Math.log(k));
            return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
        }
        
        // Save file mode preference
        function sptSaveFileMode() {
            const mode = document.getElementById('sptFileMode').value;
            localStorage.setItem('sptFileMode', mode);
            sptRefreshEditor();
        }
        
        // Update prompt counter to include static template
        function sptUpdateCounter() {
            const counter = document.getElementById('promptCounter');
            const total = promptTemplates.length + 1; // +1 for static
            const selected = activePrompts.size + (sptActive ? 1 : 0);
            counter.textContent = `${selected}/${total}`;
            
            if (selected === 0) {
                counter.style.background = 'rgba(100, 100, 100, 0.15)';
                counter.style.color = 'var(--text-muted)';
            } else if (selected === total) {
                counter.style.background = 'rgba(16, 185, 129, 0.15)';
                counter.style.color = 'var(--success)';
            } else {
                counter.style.background = 'rgba(99, 102, 241, 0.15)';
                counter.style.color = 'var(--accent-primary)';
            }
        }
        
        // Load existing files from server on page load
        async function sptLoadFiles() {
            try {
                const formData = new FormData();
                formData.append('action', 'spt_get_files');
                const response = await fetch(window.location.href, {
                    method: 'POST',
                    body: formData
                });
                const data = await response.json();
                
                if (data.success && data.files.length > 0) {
                    sptFiles = data.files.map(f => ({
                        name: f.name,
                        storedName: f.storedName,
                        size: f.size,
                        content: f.content || ''
                    }));
                    sptRenderFileList();
                    sptUpdateFileBadge();
                }
            } catch (e) {
                console.warn('Failed to load SPT files:', e);
            }
            
            // Restore file mode
            const savedMode = localStorage.getItem('sptFileMode');
            if (savedMode) {
                const modeSelect = document.getElementById('sptFileMode');
                if (modeSelect) modeSelect.value = savedMode;
            }
        }
        
        // ════════════════════════════════════════════════════════════
        
        // Open Template Preview Modal
        function openTemplatePreview(id) {
            const template = promptTemplates.find(t => t.id === id);
            if (!template) return;
            
            currentPreviewTemplate = template;
            
            const modal = document.getElementById('templatePreviewModal');
            const previewName = document.getElementById('previewName');
            const previewContent = document.getElementById('previewContent');
            const editBtn = document.getElementById('previewEditBtn');
            const useBtn = document.getElementById('previewUseBtn');
            
            previewName.textContent = template.name;
            previewContent.textContent = template.content;
            
            editBtn.onclick = () => {
                closeTemplatePreview();
                openEditTemplateModal(id);
            };
            
            useBtn.onclick = () => {
                if (!activePrompts.has(id)) {
                    togglePrompt(id);
                }
                closeTemplatePreview();
            };
            
            modal.classList.add('active');
        }
        
        // Close Template Preview
        function closeTemplatePreview() {
            const modal = document.getElementById('templatePreviewModal');
            modal.classList.remove('active');
            currentPreviewTemplate = null;
        }
        
        // Copy template content from preview
        function copyTemplateContent() {
            if (!currentPreviewTemplate) return;
            
            navigator.clipboard.writeText(currentPreviewTemplate.content).then(() => {
                showToast('Content copied to clipboard!', 'success');
            }).catch(err => {
                console.error('Failed to copy:', err);
                showToast('Failed to copy content', 'error');
            });
        }

        // Pull editor content to Template from preview modal
        async function pullTemplateContent() {
            if (!currentPreviewTemplate) return;
            
            const editor = document.getElementById('promptEditor');
            const editorContent = editor.value.trim();
            
            if (!editorContent) {
                showToast('Editor is empty! Nothing to pull.', 'warning');
                return;
            }
            
            // Confirm before overwriting
            const confirmed = typeof deConfirm === 'function'
                ? await deConfirm({ title: 'Overwrite Template', subtitle: currentPreviewTemplate.name, message: `Are you sure you want to overwrite "${currentPreviewTemplate.name}" with the current editor content?`, confirmText: 'Yes, Overwrite', cancelText: 'Cancel' })
                : confirm(`Are you sure you want to overwrite "${currentPreviewTemplate.name}" with the current editor content?`);
            if (!confirmed) return;
            
            // Send update to server
            const formData = new FormData();
            formData.append('action', 'update_template');
            formData.append('id', currentPreviewTemplate.id);
            formData.append('name', currentPreviewTemplate.name);
            formData.append('content', editorContent);
            
            fetch(window.location.href, {
                method: 'POST',
                body: formData
            })
            .then(res => res.json())
            .then(data => {
                if (data.success) {
                    // Update local array and preview
                    currentPreviewTemplate.content = editorContent;
                    document.getElementById('previewContent').textContent = editorContent;
                    showToast(`✅ "${currentPreviewTemplate.name}" updated with editor content!`, 'success');
                } else {
                    showToast(data.message || 'Failed to update template', 'error');
                }
            })
            .catch(err => {
                console.error('Error:', err);
                showToast('Failed to update template', 'error');
            });
        }

        // Toggle prompt in editor
        function togglePrompt(id) {
            const prompt = promptTemplates.find(p => p.id === id);
            if (!prompt) return;
            
            const promptItem = document.querySelector(`.prompt-item[data-id="${id}"]`);
            const editor = document.getElementById('promptEditor');
            
            if (activePrompts.has(id)) {
                activePrompts.delete(id);
                if (promptItem) {
                    promptItem.classList.remove('checked');
                    const checkbox = promptItem.querySelector('input[type="checkbox"]');
                    if (checkbox) checkbox.checked = false;
                }
                rebuildEditor();
                showToast(`${prompt.name} removed`, 'info');
            } else {
                activePrompts.add(id);
                if (promptItem) {
                    promptItem.classList.add('checked');
                    const checkbox = promptItem.querySelector('input[type="checkbox"]');
                    if (checkbox) checkbox.checked = true;
                }
                
                // Append to editor
                if (editor.value.trim()) {
                    editor.value += '\n\n' + prompt.content;
                } else {
                    editor.value = prompt.content;
                }
                
                showToast(`${prompt.name} added`, 'success');
            }
            
            updateCounts();
            updatePromptCounter();
            updateSelectAllTemplatesCheckbox();
            recordHistoryState(true); // Record template toggle in history
        }

        // Rebuild editor content from active prompts
        function rebuildEditor() {
            const editor = document.getElementById('promptEditor');
            const contents = [];
            
            promptTemplates.forEach(prompt => {
                if (activePrompts.has(prompt.id)) {
                    contents.push(prompt.content);
                }
            });
            
            // Preserve SPT static template content if active
            if (sptActive) {
                const sptContent = sptBuildContent();
                contents.push(`${SPT_MARKER_START}\n${sptContent}\n${SPT_MARKER_END}`);
            }
            
            editor.value = contents.join('\n\n');
            updateCounts();
            recordHistoryState(true); // Record rebuild in history
        }

        // Clear editor
        function clearEditor() {
            document.getElementById('promptEditor').value = '';
            activePrompts.clear();
            activeSavedPrompts.clear(); // Also clear saved prompts
            editorFiles.clear(); // Also clear file references
            
            // Reset template checkboxes
            document.querySelectorAll('.prompt-item').forEach(item => {
                item.classList.remove('checked');
                const checkbox = item.querySelector('input[type="checkbox"]');
                if (checkbox) checkbox.checked = false;
            });
            
            // Reset saved prompts checkboxes
            document.querySelectorAll('.saved-item').forEach(item => {
                item.classList.remove('checked');
                const checkbox = item.querySelector('input[type="checkbox"]');
                if (checkbox) checkbox.checked = false;
            });
            
            // Reset file checkboxes
            document.querySelectorAll('.file-item').forEach(item => {
                item.classList.remove('checked');
                const checkbox = item.querySelector('input[type="checkbox"]');
                if (checkbox) checkbox.checked = false;
            });
            
            // Reset static template (Read the Application)
            sptActive = false;
            const sptEl = document.getElementById('sptContainer');
            if (sptEl) sptEl.classList.remove('checked');
            
            // Reset static template (Table Designer)
            if (typeof tdtActive !== 'undefined') {
                tdtActive = false;
                const tdtEl = document.getElementById('tdtContainer');
                if (tdtEl) tdtEl.classList.remove('checked');
                const tdtCb = document.getElementById('tdtCheckbox');
                if (tdtCb) tdtCb.checked = false;
                localStorage.setItem(TDT_ACTIVE_KEY, '0');
                if (typeof tdtRemoveFromEditor === 'function') tdtRemoveFromEditor();
            }

            // Reset static node (Quiz Question Generator)
            const qstEl = document.getElementById('qstContainer');
            if (qstEl) qstEl.classList.remove('checked');
            const qstCb = document.getElementById('qstCheckbox');
            if (qstCb) qstCb.checked = false;

            // Reset static node (Reverse Engineer)
            if (typeof retActive !== 'undefined') retActive = false;
            const retEl = document.getElementById('retContainer');
            if (retEl) retEl.classList.remove('checked');
            const retCb = document.getElementById('retCheckbox');
            if (retCb) retCb.checked = false;
            if (typeof retRemoveFromEditor === 'function') retRemoveFromEditor();

            // Reset static node (Image to Code)
            if (typeof itcActive !== 'undefined') itcActive = false;
            const itcEl = document.getElementById('itcContainer');
            if (itcEl) itcEl.classList.remove('checked');
            const itcCb = document.getElementById('itcCheckbox');
            if (itcCb) itcCb.checked = false;
            if (typeof itcRemoveFromEditor === 'function') itcRemoveFromEditor();
            
            updateCounts();
            updatePromptCounter();
            updateSavedCounter();
            recordHistoryState(true); // Record clear action in history
            showToast('Editor cleared', 'info');
        }

        // Copy prompt
        async function copyPrompt() {
            const editor = document.getElementById('promptEditor');
            const text = editor.value;
            
            if (!text.trim()) {
                showToast('Nothing to copy!', 'error');
                return;
            }
            
            try {
                await navigator.clipboard.writeText(text);
                showToast('Copied to clipboard!', 'success');
            } catch (err) {
                // Fallback
                editor.select();
                document.execCommand('copy');
                showToast('Copied to clipboard!', 'success');
            }
        }
        
        // ═══════ TTS Reader (British Female Voice) ═══════
        let _ttsUtterance = null;
        let _ttsSpeaking = false;
        let _ttsProgressTimer = null;

        function _ttsGetBritishFemaleVoice() {
            const voices = speechSynthesis.getVoices();
            // Priority: en-GB female voices
            const priorities = [
                v => /en.GB/i.test(v.lang) && /female|Google UK English Female|Hazel|Kate|Serena|Amy/i.test(v.name),
                v => /en.GB/i.test(v.lang) && !/male/i.test(v.name),
                v => /en.GB/i.test(v.lang),
                v => /en/i.test(v.lang) && /female|Samantha|Fiona|Karen|Moira|Zira/i.test(v.name),
                v => /en/i.test(v.lang)
            ];
            for (const test of priorities) {
                const found = voices.find(test);
                if (found) return found;
            }
            return voices[0] || null;
        }

        function ttsToggleRead() {
            if (_ttsSpeaking) {
                ttsStop();
                return;
            }
            const text = document.getElementById('promptEditor').value.trim();
            if (!text) {
                showToast('Nothing to read — the editor is empty!', 'error');
                return;
            }
            ttsSpeak(text);
        }

        function ttsSpeak(text) {
            ttsStop();
            const btn = document.getElementById('btnTtsRead');
            const label = document.getElementById('ttsLabel');
            const progress = document.getElementById('ttsProgress');

            // Ensure voices are loaded
            const voices = speechSynthesis.getVoices();
            if (!voices.length) {
                speechSynthesis.onvoiceschanged = () => ttsSpeak(text);
                return;
            }

            _ttsUtterance = new SpeechSynthesisUtterance(text);
            const voice = _ttsGetBritishFemaleVoice();
            if (voice) _ttsUtterance.voice = voice;
            _ttsUtterance.lang = 'en-GB';
            _ttsUtterance.rate = 1.0;
            _ttsUtterance.pitch = 1.05;

            _ttsUtterance.onstart = () => {
                _ttsSpeaking = true;
                btn.classList.add('speaking');
                btn.querySelector('i').className = 'fas fa-stop';
                label.textContent = 'Stop';
                btn.title = 'Stop reading';
                // Estimate progress (chars / rate)
                const estimatedMs = (text.length / 14) * 1000; // ~14 chars/sec
                let elapsed = 0;
                const tick = 200;
                _ttsProgressTimer = setInterval(() => {
                    elapsed += tick;
                    const pct = Math.min((elapsed / estimatedMs) * 100, 98);
                    progress.style.width = pct + '%';
                }, tick);
            };

            _ttsUtterance.onend = () => _ttsReset();
            _ttsUtterance.onerror = (e) => {
                if (e.error !== 'canceled') showToast('TTS error: ' + e.error, 'error');
                _ttsReset();
            };

            speechSynthesis.speak(_ttsUtterance);
        }

        function ttsStop() {
            speechSynthesis.cancel();
            _ttsReset();
        }

        function _ttsReset() {
            _ttsSpeaking = false;
            if (_ttsProgressTimer) { clearInterval(_ttsProgressTimer); _ttsProgressTimer = null; }
            const btn = document.getElementById('btnTtsRead');
            const label = document.getElementById('ttsLabel');
            const progress = document.getElementById('ttsProgress');
            if (btn) {
                btn.classList.remove('speaking');
                btn.querySelector('i').className = 'fas fa-volume-up';
                btn.title = 'Read aloud (British Female Voice)';
            }
            if (label) label.textContent = 'Read';
            if (progress) progress.style.width = '0';
        }

        // Pre-load voices
        if (typeof speechSynthesis !== 'undefined') {
            speechSynthesis.getVoices();
            if (speechSynthesis.onvoiceschanged !== undefined) {
                speechSynthesis.onvoiceschanged = () => speechSynthesis.getVoices();
            }
        }
        // ═══════ End TTS Reader ═══════

        // ═══════ Arabic TTS Reader (Google Translate Audio via PHP Proxy) ═══════
        let _ttsArSpeaking = false;
        let _ttsArProgressTimer = null;
        let _ttsArChunks = [];
        let _ttsArChunkIndex = 0;
        let _ttsArAudio = null;       // currently-playing Audio element
        let _ttsArNextBlob = null;    // pre-fetched blob URL for next chunk
        let _ttsArUnlocked = false;   // true after first AudioContext unlock

        // Permanently unlock autoplay via AudioContext (call inside user gesture)
        function _ttsArUnlockAudio() {
            if (_ttsArUnlocked) return;
            try {
                const ctx = new (window.AudioContext || window.webkitAudioContext)();
                // Create a tiny silent buffer and play it to satisfy autoplay policy
                const buf = ctx.createBuffer(1, 1, 22050);
                const src = ctx.createBufferSource();
                src.buffer = buf;
                src.connect(ctx.destination);
                src.start(0);
                ctx.resume().then(() => { setTimeout(() => ctx.close(), 100); });
                _ttsArUnlocked = true;
            } catch (e) { /* AudioContext unavailable – Audio.play() may still work */ }
        }

        function _ttsArFetchAudio(text) {
            const fd = new FormData();
            fd.append('action', 'tts_ar_proxy');
            fd.append('text', text);
            return fetch(window.location.pathname, { method: 'POST', body: fd })
                .then(r => {
                    if (!r.ok) throw new Error('TTS proxy HTTP ' + r.status);
                    return r.blob();
                })
                .then(blob => URL.createObjectURL(blob));
        }

        function _ttsArSplitText(text, maxLen) {
            const chunks = [];
            const sentences = text.split(/(?<=[.!?،؛:\n])\s*/);
            let current = '';
            for (const s of sentences) {
                if ((current + ' ' + s).trim().length > maxLen && current.trim()) {
                    chunks.push(current.trim());
                    current = s;
                } else {
                    current += (current ? ' ' : '') + s;
                }
            }
            if (current.trim()) chunks.push(current.trim());
            const result = [];
            for (const c of chunks) {
                if (c.length <= maxLen) { result.push(c); continue; }
                const words = c.split(/\s+/);
                let part = '';
                for (const w of words) {
                    if ((part + ' ' + w).trim().length > maxLen && part.trim()) {
                        result.push(part.trim());
                        part = w;
                    } else {
                        part += (part ? ' ' : '') + w;
                    }
                }
                if (part.trim()) result.push(part.trim());
            }
            return result.length ? result : [text];
        }

        function ttsArToggle() {
            if (_ttsArSpeaking) { ttsArStop(); return; }
            const text = document.getElementById('promptEditor').value.trim();
            if (!text) {
                showToast('المحرر فارغ – لا يوجد نص للقراءة!', 'error');
                return;
            }
            if (_ttsSpeaking) ttsStop();

            // Unlock autoplay SYNCHRONOUSLY inside user-gesture – one-time, permanent
            _ttsArUnlockAudio();

            ttsArSpeak(text);
        }

        function ttsArSpeak(text) {
            ttsArStop();
            const btn = document.getElementById('btnTtsAr');
            const label = document.getElementById('ttsArLabel');
            const progress = document.getElementById('ttsArProgress');

            _ttsArChunks = _ttsArSplitText(text, 190);
            _ttsArChunkIndex = 0;
            _ttsArNextBlob = null;
            const totalChunks = _ttsArChunks.length;

            // UI → loading spinner
            _ttsArSpeaking = true;
            if (btn) {
                btn.classList.add('speaking');
                btn.querySelector('i').className = 'fas fa-spinner fa-spin';
                btn.title = 'جارٍ تحميل الصوت...';
            }
            if (label) label.textContent = 'تحميل...';

            // Pre-fetch the very first chunk immediately (overlap with UI feedback)
            const firstFetch = _ttsArFetchAudio(_ttsArChunks[0]);

            async function playNext(prefetchedUrl) {
                if (!_ttsArSpeaking || _ttsArChunkIndex >= _ttsArChunks.length) {
                    _ttsArReset();
                    return;
                }

                try {
                    // Use pre-fetched URL if available, otherwise fetch now
                    const audioUrl = prefetchedUrl || await _ttsArFetchAudio(_ttsArChunks[_ttsArChunkIndex]);
                    if (!_ttsArSpeaking) { URL.revokeObjectURL(audioUrl); return; }

                    // Switch UI from loading → playing (first chunk only)
                    if (_ttsArChunkIndex === 0 && btn) {
                        btn.querySelector('i').className = 'fas fa-stop';
                        btn.title = 'إيقاف القراءة العربية';
                        if (label) label.textContent = 'إيقاف';
                    }

                    // Start pre-fetching NEXT chunk while current one plays
                    const nextIdx = _ttsArChunkIndex + 1;
                    let nextFetchPromise = null;
                    if (nextIdx < _ttsArChunks.length) {
                        nextFetchPromise = _ttsArFetchAudio(_ttsArChunks[nextIdx]);
                    }

                    // Create a fresh Audio element every time (no shared state)
                    _ttsArAudio = new Audio(audioUrl);
                    _ttsArAudio.playbackRate = 1.0;

                    _ttsArAudio.onplay = () => {
                        if (progress) {
                            progress.style.width = ((_ttsArChunkIndex) / totalChunks * 100) + '%';
                        }
                    };

                    _ttsArAudio.ontimeupdate = () => {
                        if (_ttsArAudio && _ttsArAudio.duration && progress) {
                            const chunkPct = _ttsArAudio.currentTime / _ttsArAudio.duration;
                            const overallPct = ((_ttsArChunkIndex + chunkPct) / totalChunks) * 100;
                            progress.style.width = Math.min(overallPct, 99) + '%';
                        }
                    };

                    _ttsArAudio.onended = async () => {
                        URL.revokeObjectURL(audioUrl);
                        _ttsArChunkIndex++;
                        if (!_ttsArSpeaking) return;
                        // Use pre-fetched next chunk for seamless playback
                        const nextUrl = nextFetchPromise ? await nextFetchPromise.catch(() => null) : null;
                        playNext(nextUrl);
                    };

                    _ttsArAudio.onerror = () => {
                        URL.revokeObjectURL(audioUrl);
                        showToast('خطأ في تشغيل الصوت العربي.', 'error');
                        _ttsArReset();
                    };

                    await _ttsArAudio.play();
                } catch (err) {
                    console.warn('TTS-AR error:', err);
                    showToast('خطأ في تحميل الصوت العربي. تأكد من اتصالك بالإنترنت.', 'error');
                    _ttsArReset();
                }
            }

            // Wait for the pre-fetched first chunk, then start playback
            firstFetch.then(url => playNext(url)).catch(() => {
                showToast('خطأ في تحميل الصوت العربي. تأكد من اتصالك بالإنترنت.', 'error');
                _ttsArReset();
            });
        }

        function ttsArStop() {
            _ttsArSpeaking = false;
            if (_ttsArAudio) {
                // Remove all handlers FIRST to prevent ghost error events
                _ttsArAudio.onplay = null;
                _ttsArAudio.ontimeupdate = null;
                _ttsArAudio.onended = null;
                _ttsArAudio.onerror = null;
                _ttsArAudio.pause();
                _ttsArAudio.removeAttribute('src');
                _ttsArAudio.load();
                _ttsArAudio = null;
            }
            _ttsArNextBlob = null;
            _ttsArChunks = [];
            _ttsArChunkIndex = 0;
            _ttsArReset();
        }

        function _ttsArReset() {
            _ttsArSpeaking = false;
            if (_ttsArProgressTimer) { clearInterval(_ttsArProgressTimer); _ttsArProgressTimer = null; }
            const btn = document.getElementById('btnTtsAr');
            const label = document.getElementById('ttsArLabel');
            const progress = document.getElementById('ttsArProgress');
            // Clean up any lingering audio reference from finished playback
            if (_ttsArAudio) {
                _ttsArAudio.onplay = null;
                _ttsArAudio.ontimeupdate = null;
                _ttsArAudio.onended = null;
                _ttsArAudio.onerror = null;
                _ttsArAudio = null;
            }
            if (btn) {
                btn.classList.remove('speaking');
                btn.querySelector('i').className = 'fas fa-volume-up';
                btn.title = 'قراءة عربية – صوت طبيعي عالي الجودة';
            }
            if (label) label.textContent = 'عربي';
            if (progress) progress.style.width = '0';
        }
        // ═══════ End Arabic TTS Reader ═══════

        // ═══════ TTS Reader – Project Prompts ═══════
        let _ttsNotesUtterance = null;
        let _ttsNotesSpeaking = false;
        let _ttsNotesTimer = null;

        function ttsNotesToggle() {
            if (_ttsNotesSpeaking) { ttsNotesStop(); return; }
            const text = (document.getElementById('projectNotesTextarea') || {}).value || '';
            if (!text.trim()) { showToast('Project Prompts is empty — nothing to read!', 'error'); return; }
            ttsNotesSpeak(text);
        }

        function ttsNotesSpeak(text) {
            ttsNotesStop();
            const btn = document.getElementById('btnTtsNotes');
            const label = document.getElementById('ttsNotesLabel');
            const progress = document.getElementById('ttsNotesProgress');
            const voices = speechSynthesis.getVoices();
            if (!voices.length) { speechSynthesis.onvoiceschanged = () => ttsNotesSpeak(text); return; }

            _ttsNotesUtterance = new SpeechSynthesisUtterance(text);
            const voice = _ttsGetBritishFemaleVoice();
            if (voice) _ttsNotesUtterance.voice = voice;
            _ttsNotesUtterance.lang = 'en-GB';
            _ttsNotesUtterance.rate = 1.0;
            _ttsNotesUtterance.pitch = 1.05;

            _ttsNotesUtterance.onstart = () => {
                _ttsNotesSpeaking = true;
                if (btn) { btn.classList.add('speaking'); btn.querySelector('i').className = 'fas fa-stop'; }
                if (label) label.textContent = 'Stop';
                if (btn) btn.title = 'Stop reading';
                const estimatedMs = (text.length / 14) * 1000;
                let elapsed = 0;
                const tick = 200;
                _ttsNotesTimer = setInterval(() => {
                    elapsed += tick;
                    const pct = Math.min((elapsed / estimatedMs) * 100, 98);
                    if (progress) progress.style.width = pct + '%';
                }, tick);
            };
            _ttsNotesUtterance.onend = () => _ttsNotesReset();
            _ttsNotesUtterance.onerror = (e) => {
                if (e.error !== 'canceled') showToast('TTS error: ' + e.error, 'error');
                _ttsNotesReset();
            };
            speechSynthesis.speak(_ttsNotesUtterance);
        }

        function ttsNotesStop() { speechSynthesis.cancel(); _ttsNotesReset(); }

        function _ttsNotesReset() {
            _ttsNotesSpeaking = false;
            if (_ttsNotesTimer) { clearInterval(_ttsNotesTimer); _ttsNotesTimer = null; }
            const btn = document.getElementById('btnTtsNotes');
            const label = document.getElementById('ttsNotesLabel');
            const progress = document.getElementById('ttsNotesProgress');
            if (btn) { btn.classList.remove('speaking'); btn.querySelector('i').className = 'fas fa-volume-up'; btn.title = 'Read aloud (British Female Voice)'; }
            if (label) label.textContent = 'Read';
            if (progress) progress.style.width = '0';
        }
        // ═══════ End TTS – Project Prompts ═══════

        // ═══════ TTS Arabic – Project Prompts (Google Translate Proxy) ═══════
        let _ttsNotesArSpeaking = false;
        let _ttsNotesArAudio = null;
        let _ttsNotesArChunks = [];
        let _ttsNotesArChunkIndex = 0;

        function ttsNotesArToggle() {
            if (_ttsNotesArSpeaking) { ttsNotesArStop(); return; }
            const text = (document.getElementById('projectNotesTextarea') || {}).value || '';
            if (!text.trim()) { showToast('Project Prompts is empty — nothing to read!', 'error'); return; }
            // Stop English TTS if playing
            if (_ttsNotesSpeaking) ttsNotesStop();
            // Unlock autoplay inside user gesture
            _ttsArUnlockAudio();
            ttsNotesArSpeak(text);
        }

        function ttsNotesArSpeak(text) {
            ttsNotesArStop();
            const btn = document.getElementById('btnTtsNotesAr');
            const label = document.getElementById('ttsNotesArLabel');
            const progress = document.getElementById('ttsNotesArProgress');

            _ttsNotesArChunks = _ttsArSplitText(text, 190);
            _ttsNotesArChunkIndex = 0;
            const totalChunks = _ttsNotesArChunks.length;

            // UI → loading spinner
            _ttsNotesArSpeaking = true;
            if (btn) {
                btn.classList.add('speaking');
                btn.querySelector('i').className = 'fas fa-spinner fa-spin';
                btn.title = 'جارٍ تحميل الصوت...';
            }
            if (label) label.textContent = 'تحميل...';

            // Pre-fetch first chunk
            const firstFetch = _ttsArFetchAudio(_ttsNotesArChunks[0]);

            async function playNext(prefetchedUrl) {
                if (!_ttsNotesArSpeaking || _ttsNotesArChunkIndex >= _ttsNotesArChunks.length) {
                    _ttsNotesArReset();
                    return;
                }
                try {
                    const audioUrl = prefetchedUrl || await _ttsArFetchAudio(_ttsNotesArChunks[_ttsNotesArChunkIndex]);
                    if (!_ttsNotesArSpeaking) { URL.revokeObjectURL(audioUrl); return; }

                    // Switch UI from loading → playing (first chunk only)
                    if (_ttsNotesArChunkIndex === 0 && btn) {
                        btn.querySelector('i').className = 'fas fa-stop';
                        btn.title = 'إيقاف القراءة العربية';
                        if (label) label.textContent = 'إيقاف';
                    }

                    // Pre-fetch next chunk while current plays
                    const nextIdx = _ttsNotesArChunkIndex + 1;
                    let nextFetchPromise = null;
                    if (nextIdx < _ttsNotesArChunks.length) {
                        nextFetchPromise = _ttsArFetchAudio(_ttsNotesArChunks[nextIdx]);
                    }

                    _ttsNotesArAudio = new Audio(audioUrl);
                    _ttsNotesArAudio.playbackRate = 1.0;

                    _ttsNotesArAudio.onplay = () => {
                        if (progress) progress.style.width = ((_ttsNotesArChunkIndex) / totalChunks * 100) + '%';
                    };
                    _ttsNotesArAudio.ontimeupdate = () => {
                        if (_ttsNotesArAudio && _ttsNotesArAudio.duration && progress) {
                            const chunkPct = _ttsNotesArAudio.currentTime / _ttsNotesArAudio.duration;
                            const overallPct = ((_ttsNotesArChunkIndex + chunkPct) / totalChunks) * 100;
                            progress.style.width = Math.min(overallPct, 99) + '%';
                        }
                    };
                    _ttsNotesArAudio.onended = async () => {
                        URL.revokeObjectURL(audioUrl);
                        _ttsNotesArChunkIndex++;
                        if (!_ttsNotesArSpeaking) return;
                        const nextUrl = nextFetchPromise ? await nextFetchPromise.catch(() => null) : null;
                        playNext(nextUrl);
                    };
                    _ttsNotesArAudio.onerror = () => {
                        URL.revokeObjectURL(audioUrl);
                        showToast('خطأ في تشغيل الصوت العربي.', 'error');
                        _ttsNotesArReset();
                    };
                    await _ttsNotesArAudio.play();
                } catch (err) {
                    console.warn('TTS-AR Notes error:', err);
                    showToast('خطأ في تحميل الصوت العربي. تأكد من اتصالك بالإنترنت.', 'error');
                    _ttsNotesArReset();
                }
            }

            firstFetch.then(url => playNext(url)).catch(() => {
                showToast('خطأ في تحميل الصوت العربي. تأكد من اتصالك بالإنترنت.', 'error');
                _ttsNotesArReset();
            });
        }

        function ttsNotesArStop() {
            _ttsNotesArSpeaking = false;
            if (_ttsNotesArAudio) {
                _ttsNotesArAudio.onplay = null;
                _ttsNotesArAudio.ontimeupdate = null;
                _ttsNotesArAudio.onended = null;
                _ttsNotesArAudio.onerror = null;
                _ttsNotesArAudio.pause();
                _ttsNotesArAudio.removeAttribute('src');
                _ttsNotesArAudio.load();
                _ttsNotesArAudio = null;
            }
            _ttsNotesArChunks = [];
            _ttsNotesArChunkIndex = 0;
            _ttsNotesArReset();
        }

        function _ttsNotesArReset() {
            _ttsNotesArSpeaking = false;
            if (_ttsNotesArAudio) {
                _ttsNotesArAudio.onplay = null;
                _ttsNotesArAudio.ontimeupdate = null;
                _ttsNotesArAudio.onended = null;
                _ttsNotesArAudio.onerror = null;
