            _sttNotesArRecognition.interimResults = true;
            _sttNotesArRecognition.maxAlternatives = 1;

            _sttNotesArFinalTranscript = '';
            _sttNotesArInsertedLength = 0;

            _sttNotesArRecognition.onstart = () => {
                _sttNotesArListening = true;
                const btn = document.getElementById('btnSttNotesAr');
                const label = document.getElementById('sttNotesArLabel');
                if (btn) { btn.classList.add('listening'); btn.querySelector('i').className = 'fas fa-microphone-slash'; btn.title = 'إيقاف الإملاء'; }
                if (label) label.textContent = 'إيقاف';
                showToast('🎤 جارٍ الاستماع… تحدث بالعربية!', 'success');
            };

            _sttNotesArRecognition.onresult = (event) => {
                const editor = document.getElementById('projectNotesTextarea');
                if (!editor) return;
                for (let i = event.resultIndex; i < event.results.length; i++) {
                    const transcript = event.results[i][0].transcript;
                    if (event.results[i].isFinal) {
                        let finalText = transcript.trim();
                        if (_sttNotesArFinalTranscript.length > 0 && !/\s$/.test(_sttNotesArFinalTranscript)) {
                            _sttNotesArFinalTranscript += ' ';
                        }
                        _sttNotesArFinalTranscript += finalText;
                        _sttNotesArInsertText(editor, finalText);
                    }
                }
            };

            _sttNotesArRecognition.onerror = (event) => {
                if (event.error === 'no-speech') { showToast('لم يُكتشف كلام. حاول مرة أخرى.', 'error'); }
                else if (event.error === 'audio-capture') { showToast('لم يُعثر على ميكروفون.', 'error'); }
                else if (event.error === 'not-allowed') { showToast('تم رفض الوصول إلى الميكروفون.', 'error'); }
                else if (event.error !== 'aborted') { showToast('خطأ في التعرف على الكلام: ' + event.error, 'error'); }
                sttNotesArReset();
            };

            _sttNotesArRecognition.onend = () => {
                if (_sttNotesArListening) {
                    try { _sttNotesArRecognition.start(); } catch(e) { sttNotesArReset(); }
                } else { sttNotesArReset(); }
            };

            try { _sttNotesArRecognition.start(); } catch(e) { showToast('تعذر بدء التعرف: ' + e.message, 'error'); sttNotesArReset(); }
        }

        function sttNotesArStop() {
            _sttNotesArListening = false;
            if (_sttNotesArRecognition) { try { _sttNotesArRecognition.stop(); } catch(e) {} }
            if (_sttNotesArFinalTranscript.trim()) {
                saveProjectNotesToStorage();
                showToast('✅ تم حفظ الإملاء! (' + _sttNotesArFinalTranscript.trim().split(/\s+/).length + ' كلمة)', 'success');
            } else { showToast('تم إيقاف الإملاء.', 'info'); }
            _sttNotesArFinalTranscript = '';
            _sttNotesArInsertedLength = 0;
            sttNotesArReset();
        }

        function sttNotesArReset() {
            _sttNotesArListening = false;
            _sttNotesArInsertedLength = 0;
            const btn = document.getElementById('btnSttNotesAr');
            const label = document.getElementById('sttNotesArLabel');
            if (btn) { btn.classList.remove('listening'); btn.querySelector('i').className = 'fas fa-microphone'; btn.title = 'إملاء عربي – تحدث بالعربية للكتابة'; }
            if (label) label.textContent = 'إملاء';
        }

        function _sttNotesArInsertText(editor, text) {
            if (!text.trim()) return;
            const curVal = editor.value;
            const cursorPos = editor.selectionStart;
            if (_sttNotesArInsertedLength === 0) {
                let prefix = '';
                if (curVal.trim().length > 0) {
                    prefix = (cursorPos >= curVal.length) ? (curVal.endsWith('\n') ? '' : '\n') : ' ';
                }
                const ins = prefix + text;
                editor.value = curVal.substring(0, cursorPos) + ins + curVal.substring(cursorPos);
                const np = cursorPos + ins.length;
                editor.setSelectionRange(np, np);
                _sttNotesArInsertedLength = ins.length;
            } else {
                const ins = ' ' + text;
                editor.value = curVal.substring(0, cursorPos) + ins + curVal.substring(cursorPos);
                const np = cursorPos + ins.length;
                editor.setSelectionRange(np, np);
                _sttNotesArInsertedLength += ins.length;
            }
            editor.focus();
            editor.scrollTop = editor.scrollHeight;
        }
        // ═══════ End STT Arabic – Project Prompts ═══════

        // ═══════ Global Dictation (Steps Header) ═══════
        // Tracks the last focused textarea/input so dictation goes to any field
        let _gdLastTarget = null;
        let _gdEnRecognition = null;
        let _gdEnListening = false;
        let _gdEnFinalTranscript = '';
        let _gdEnInsertedLength = 0;
        let _gdArRecognition = null;
        let _gdArListening = false;
        let _gdArFinalTranscript = '';
        let _gdArInsertedLength = 0;

        // Track focus on any textarea or input[type=text] across the page
        document.addEventListener('focusin', (e) => {
            const t = e.target;
            if (t && (t.tagName === 'TEXTAREA' || (t.tagName === 'INPUT' && (t.type === 'text' || t.type === 'search' || t.type === '')))) {
                _gdLastTarget = t;
            }
        });

        // ── Generic insert into any target element ──
        function _gdInsertText(target, text, insertedRef) {
            if (!target || !text.trim()) return 0;
            const curVal = target.value;
            const cursorPos = target.selectionStart;

            if (insertedRef.len === 0) {
                let prefix = '';
                if (curVal.trim().length > 0) {
                    if (cursorPos >= curVal.length) {
                        prefix = curVal.endsWith('\n') ? '' : '\n';
                    } else {
                        prefix = ' ';
                    }
                }
                const ins = prefix + text;
                target.value = curVal.substring(0, cursorPos) + ins + curVal.substring(cursorPos);
                const np = cursorPos + ins.length;
                target.setSelectionRange(np, np);
                insertedRef.len = ins.length;
                target.focus();
                return ins.length;
            } else {
                const ins = ' ' + text;
                target.value = curVal.substring(0, cursorPos) + ins + curVal.substring(cursorPos);
                const np = cursorPos + ins.length;
                target.setSelectionRange(np, np);
                insertedRef.len += ins.length;
                target.focus();
                return ins.length;
            }
        }

        // ── Main Content Tab Switching ──
        function mcSwitchTab(tabName) {
            document.querySelectorAll('.mc-tab').forEach(t => t.classList.remove('active'));
            document.querySelectorAll('.mc-tab-panel').forEach(p => p.classList.remove('active'));
            const tab = document.querySelector(`.mc-tab[data-mc-tab="${tabName}"]`);
            const panel = document.querySelector(`.mc-tab-panel[data-mc-panel="${tabName}"]`);
            if (tab) tab.classList.add('active');
            if (panel) {
                panel.classList.add('active');
                panel.style.animation = 'none';
                panel.offsetHeight;
                panel.style.animation = '';
            }
        }

        // ═══════ Iframe Workspace ═══════
        const _iframeHistory = [];
        let _iframeHistoryIdx = -1;
        let _iframeBookmarks = JSON.parse(localStorage.getItem('iframeBookmarks') || '[]');
        var _iframeNavByCode = false; // flag: true when navigation triggered by our code
        var _iframeListenerAttached = false;

        function _iframeEl() { return document.getElementById('iframeViewer'); }
        function _iframeStatusBar() { return document.getElementById('iframeStatusBar'); }

        // Detect if a URL targets localhost while parent is on a different origin (cross-origin)
        function _iframeIsCrossOriginLocalhost(url) {
            if (/^localhost$/i.test(window.location.hostname) || /^127\.0\.0\.1$/.test(window.location.hostname)) return false;
            try {
                var parsed = new URL(url);
                return /^localhost$/i.test(parsed.hostname) || /^127\.0\.0\.1$/.test(parsed.hostname);
            } catch(e) { return false; }
        }


        // Auto-adapt localhost URLs to current host when on external server (same-origin = URL tracking works)
        function _iframeAdaptUrl(url) {
            if (/^localhost$/i.test(window.location.hostname)) return url;
            try {
                var parsed = new URL(url);
                if (/^localhost$/i.test(parsed.hostname) && (!parsed.port || parsed.port === '80' || parsed.port === '443')) {
                    var adapted = window.location.origin + parsed.pathname + parsed.search + parsed.hash;
                    return adapted;
                }
            } catch(e) {}
            return url;
        }

        // Update the path display text box with the current iframe URL
        function _iframeUpdatePathBox(url) {
            var box = document.getElementById('iframePathBox');
            var txt = document.getElementById('iframePathText');
            if (!box || !txt) return;
            if (!url || url === 'about:blank') {
                box.classList.remove('visible', 'path-updated');
                txt.value = '';
                return;
            }
            try {
                var parsed = new URL(url);
                var path = decodeURIComponent(parsed.pathname + parsed.search + parsed.hash);
                // Show origin + path for clarity
                txt.value = parsed.origin + path;
            } catch(e) {
                txt.value = url;
            }
            box.classList.add('visible');
            // Flash effect on update
            box.classList.add('path-updated');
            setTimeout(function() { box.classList.remove('path-updated'); }, 1200);
        }

        // ── DISABLED: No longer pushes iframe navigation paths to Prompt Editor ──
        function _iframeShowNavPopup(url) { /* disabled */ }

        // Attach a permanent load listener to catch ALL iframe navigations (including internal link clicks)
        function _iframeAttachLoadListener() {
            if (_iframeListenerAttached) return;
            var iframe = _iframeEl();
            if (!iframe) return;
            _iframeListenerAttached = true;
            iframe.addEventListener('load', function() {
                if (_iframeNavByCode) return; // Skip — handled by iframeLoadUrl/GoBack/GoForward/Reload
                // Internal navigation (user clicked a link inside the iframe)
                var urlInput = document.getElementById('iframeUrlInput');
                var statusBar = _iframeStatusBar();
                var statusText = document.getElementById('iframeStatusText');
                if (!urlInput) return;
                var resolvedUrl = urlInput.value;
                var isCrossOrigin = false;
                try {
                    var loc = iframe.contentWindow.location;
                    if (loc && loc.href && loc.href !== 'about:blank') {
                        resolvedUrl = _iframeCleanUrl(loc.href);
                    }
                } catch(e) { isCrossOrigin = true; }

                if (!isCrossOrigin) {
                    // Same-origin: full tracking
                    urlInput.value = resolvedUrl;
                    if (statusText) statusText.textContent = resolvedUrl.replace(/^https?:\/\//, '').split('/')[0];
                    if (statusBar) statusBar.className = 'iframe-status-bar loaded';
                    if (_iframeHistory[_iframeHistoryIdx] !== resolvedUrl) {
                        if (_iframeHistoryIdx < _iframeHistory.length - 1) {
                            _iframeHistory.splice(_iframeHistoryIdx + 1);
                        }
                        _iframeHistory.push(resolvedUrl);
                        _iframeHistoryIdx = _iframeHistory.length - 1;
                        _iframeUpdateNavBtns();
                    }
                    _iframeUpdateBookmarkIcon();
                    _iframeUpdateBreadcrumb(resolvedUrl);
                    _docrootUpdateFromIframe(resolvedUrl);
                    _iframeUpdatePathBox(resolvedUrl);
                } else {
                    // Cross-origin: can't read URL directly
                    // Bridge proxy + postMessage will provide the real URL — don't push stale data
                    if (statusBar) statusBar.className = 'iframe-status-bar loaded';
                    if (statusText) statusText.textContent = 'Waiting for bridge...';
                    var ghost = document.getElementById('docrootGhost');
                    if (ghost) {
                        ghost.classList.add('navigated-pulse');
                        setTimeout(function() { ghost.classList.remove('navigated-pulse'); }, 2500);
                    }
                }
            });
        }

        // Listen for postMessage from iframe content (cross-origin URL bridge)
        window.addEventListener('message', function(e) {
            if (!e.data || e.data.type !== 'pm_iframe_nav' || !e.data.url) return;
            var url = e.data.url;
            var cleanUrl = _iframeCleanUrl(url);
            var urlInput = document.getElementById('iframeUrlInput');
            var statusBar = _iframeStatusBar();
            var statusText = document.getElementById('iframeStatusText');

            // Update URL bar
            if (urlInput) urlInput.value = cleanUrl;

            // Update status
            if (statusBar) statusBar.className = 'iframe-status-bar loaded';
            if (statusText) statusText.textContent = cleanUrl.replace(/^https?:\/\//, '').split('/')[0];

            // Update history
            if (_iframeHistory[_iframeHistoryIdx] !== cleanUrl) {
                if (_iframeHistoryIdx < _iframeHistory.length - 1) {
                    _iframeHistory.splice(_iframeHistoryIdx + 1);
                }
                _iframeHistory.push(cleanUrl);
                _iframeHistoryIdx = _iframeHistory.length - 1;
                _iframeUpdateNavBtns();
            }

            // Update breadcrumb, docroot, bookmarks, path box
            _iframeUpdateBookmarkIcon();
            _iframeUpdateBreadcrumb(cleanUrl);
            _docrootUpdateFromIframe(cleanUrl);
            _iframeUpdatePathBox(cleanUrl);

            // Remove pulse if active (postMessage arrived with real URL)
            var ghost = document.getElementById('docrootGhost');
            if (ghost) ghost.classList.remove('navigated-pulse');
        });

        // Build bridge URL for cross-origin localhost proxying
        function _iframeBridgeUrl(originalUrl) {
            try {
                var parsed = new URL(originalUrl);
                if (/^(localhost|127\.0\.0\.1)$/i.test(parsed.hostname)) {
                    // Route through the bridge on localhost
                    var bridgeBase = parsed.protocol + '//' + parsed.host;
                    // Find the Prompt-Manager path on localhost
                    var pmPath = '/Prompt-Manager/iframe-bridge.php';
                    return bridgeBase + pmPath + '?url=' + encodeURIComponent(originalUrl);
                }
            } catch(e) {}
            return originalUrl;
        }

        function iframeNavigate() {
            let url = document.getElementById('iframeUrlInput').value.trim();
            if (!url) return;
            if (!/^https?:\/\//i.test(url) && !/^about:/i.test(url)) {
                url = 'http://' + url;
            }
            if (_iframeIsCrossOriginLocalhost(url)) {
                // Cross-origin localhost: route through bridge proxy for URL tracking
                var bridgeUrl = _iframeBridgeUrl(url);
                document.getElementById('iframeUrlInput').value = url; // Show original URL in bar
                iframeLoadUrl(url, bridgeUrl); // Pass both: display URL + actual src
            } else {
                // Same-origin: adapt localhost URLs to current host
                var adapted = _iframeAdaptUrl(url);
                if (adapted !== url) {
                    url = adapted;
                    if (typeof showToast === 'function') {
                        showToast('Auto-adapted to current host for URL tracking', 'info');
                    }
                }
                document.getElementById('iframeUrlInput').value = url;
                iframeLoadUrl(url);
            }
        }

        // Cache-busting: strip any existing _cb param and add a fresh timestamp
        function _iframeCacheBust(url) {
            try {
                var u = new URL(url, window.location.origin);
                u.searchParams.delete('_cb');
                u.searchParams.set('_cb', Date.now());
                return u.toString();
            } catch(e) {
                // Fallback for malformed URLs
                var sep = url.indexOf('?') === -1 ? '?' : '&';
                return url.replace(/[?&]_cb=\d+/g, '') + sep + '_cb=' + Date.now();
            }
        }

        // Get clean URL (without cache-bust param) for display/history
        function _iframeCleanUrl(url) {
            try {
                var u = new URL(url, window.location.origin);
                u.searchParams.delete('_cb');
                var clean = u.toString();
                // Remove trailing '?' if no params left
                if (clean.endsWith('?')) clean = clean.slice(0, -1);
                return clean;
            } catch(e) {
                return url.replace(/[?&]_cb=\d+/g, '');
            }
        }

        function iframeLoadUrl(url, bridgeSrc) {
            const iframe = _iframeEl();
            const emptyState = document.getElementById('iframeEmptyState');
            const statusBar = _iframeStatusBar();
            const statusText = document.getElementById('iframeStatusText');
            const urlInput = document.getElementById('iframeUrlInput');

            if (!iframe) return;

            // Attach permanent load listener for internal navigation tracking
            _iframeAttachLoadListener();

            // Store the clean URL for display and history
            var cleanUrl = _iframeCleanUrl(url);
            urlInput.value = cleanUrl;

            // Update status
            statusBar.className = 'iframe-status-bar loading';
            statusText.textContent = 'Loading...';

            // Hide empty state, show iframe
            if (emptyState) emptyState.style.display = 'none';
            iframe.classList.add('active');

            // Push to history (store clean URL)
            if (_iframeHistoryIdx < _iframeHistory.length - 1) {
                _iframeHistory.splice(_iframeHistoryIdx + 1);
            }
            _iframeHistory.push(cleanUrl);
            _iframeHistoryIdx = _iframeHistory.length - 1;
            _iframeUpdateNavBtns();
            _iframeUpdateBookmarkIcon();

            // Use bridge URL if provided (cross-origin proxy), otherwise load directly
            var actualSrc = bridgeSrc ? _iframeCacheBust(bridgeSrc) : _iframeCacheBust(cleanUrl);
            _iframeNavByCode = true;
            iframe.src = actualSrc;

            iframe.onload = function() {
                _iframeNavByCode = false;
                statusBar.className = 'iframe-status-bar loaded';
                // Try to read the actual resolved URL from the iframe (same-origin only)
                var resolvedUrl = cleanUrl;
                try {
                    var loc = iframe.contentWindow.location;
                    if (loc && loc.href && loc.href !== 'about:blank') {
                        resolvedUrl = _iframeCleanUrl(loc.href);
                    }
                } catch(e) { /* cross-origin: postMessage listener will update URL */ }

                // Update URL bar with the resolved path
                urlInput.value = resolvedUrl;
                statusText.textContent = resolvedUrl.replace(/^https?:\/\//, '').split('/')[0];

                // Update history entry with actual resolved URL
                if (_iframeHistory[_iframeHistoryIdx] !== resolvedUrl) {
                    _iframeHistory[_iframeHistoryIdx] = resolvedUrl;
                }
                _iframeUpdateBookmarkIcon();
                _iframeUpdateBreadcrumb(resolvedUrl);
                _docrootUpdateFromIframe(resolvedUrl);
                _iframeUpdatePathBox(resolvedUrl);
            };
            iframe.onerror = function() {
                statusBar.className = 'iframe-status-bar error';
                statusText.textContent = 'Failed to load';
                _iframeUpdateBreadcrumb('');
            };
        }

        // Helper: read actual URL from iframe (same-origin) and update URL bar + history + breadcrumb
        function _iframeResolveAndUpdate(iframe) {
            var urlInput = document.getElementById('iframeUrlInput');
            var statusText = document.getElementById('iframeStatusText');
            var currentUrl = urlInput.value;
            var resolvedUrl = currentUrl;
            try {
                var loc = iframe.contentWindow.location;
                if (loc && loc.href && loc.href !== 'about:blank') {
                    resolvedUrl = _iframeCleanUrl(loc.href);
                }
            } catch(e) { /* cross-origin, keep original */ }
            urlInput.value = resolvedUrl;
            statusText.textContent = resolvedUrl.replace(/^https?:\/\//, '').split('/')[0];
            if (_iframeHistory[_iframeHistoryIdx] !== resolvedUrl) {
                _iframeHistory[_iframeHistoryIdx] = resolvedUrl;
            }
            _iframeUpdateBookmarkIcon();
            _iframeUpdateBreadcrumb(resolvedUrl);
            _docrootUpdateFromIframe(resolvedUrl);
        }

        function iframeGoBack() {
            if (_iframeHistoryIdx > 0) {
                _iframeHistoryIdx--;
                const url = _iframeHistory[_iframeHistoryIdx];
                document.getElementById('iframeUrlInput').value = url;
                var iframe = _iframeEl();
                _iframeNavByCode = true;
                iframe.src = _iframeCacheBust(url);
                iframe.onload = function() { _iframeNavByCode = false; _iframeResolveAndUpdate(iframe); };
                _iframeUpdateNavBtns();
                _iframeUpdateBookmarkIcon();
            }
        }

        function iframeGoForward() {
            if (_iframeHistoryIdx < _iframeHistory.length - 1) {
                _iframeHistoryIdx++;
                const url = _iframeHistory[_iframeHistoryIdx];
                document.getElementById('iframeUrlInput').value = url;
                var iframe = _iframeEl();
                _iframeNavByCode = true;
                iframe.src = _iframeCacheBust(url);
                iframe.onload = function() { _iframeNavByCode = false; _iframeResolveAndUpdate(iframe); };
                _iframeUpdateNavBtns();
                _iframeUpdateBookmarkIcon();
            }
        }

        function iframeReload() {
            const iframe = _iframeEl();
            if (iframe && iframe.src && iframe.src !== 'about:blank') {
                const statusBar = _iframeStatusBar();
                const statusText = document.getElementById('iframeStatusText');
                statusBar.className = 'iframe-status-bar loading';
                statusText.textContent = 'Refreshing...';
                // Force fresh load with new cache-bust parameter
                var cleanSrc = _iframeCleanUrl(iframe.src);
                iframe.src = 'about:blank';
                setTimeout(function() {
                    _iframeNavByCode = true;
                    iframe.src = _iframeCacheBust(cleanSrc);
                    iframe.onload = function() {
                        _iframeNavByCode = false;
                        statusBar.className = 'iframe-status-bar loaded';
                        _iframeResolveAndUpdate(iframe);
                    };
                }, 50);
            }
        }

        /* ── Localhost Path Config ── */
        var _docrootKey = 'pm_localhost_path';

        function _docrootLoad() {
            var saved = localStorage.getItem(_docrootKey) || '';
            var txt = document.getElementById('docrootText');
            var ghost = document.getElementById('docrootGhost');
            var icon = document.getElementById('docrootIcon');
            if (!txt || !ghost) return;

            var isLocal = /^localhost$/i.test(window.location.hostname);

            if (saved) {
                // Display only the folder name, not the full path
                var parts = saved.replace(/\\/g, '/').replace(/\/+$/, '').split('/');
                var folderName = parts[parts.length - 1] || saved;
                txt.textContent = folderName;
                txt.style.display = '';
                txt.classList.remove('not-set');
                ghost.title = (isLocal ? 'localhost' : window.location.hostname) + ' – ' + folderName;
                if (icon) icon.className = isLocal ? 'fas fa-server' : 'fas fa-globe';
            } else {
                // Auto-detect path from current URL
                var basePath = window.location.origin + window.location.pathname.replace(/\/[^\/]*$/, '') + '/';
                var hostLabel = isLocal ? 'localhost' : window.location.hostname.replace(/^www\./i, '');
                var pathSegments = window.location.pathname.replace(/^\/+/, '').replace(/\/+$/, '').split('/').filter(Boolean);
                var displayName = pathSegments.length > 0 ? pathSegments[0] : hostLabel;

                txt.textContent = displayName;
                txt.style.display = '';
                txt.classList.remove('not-set');
                ghost.title = hostLabel + ' – ' + basePath;
                if (icon) icon.className = isLocal ? 'fas fa-server' : 'fas fa-globe';
            }
        }

        function toggleDocrootEdit() {
            var ghost = document.getElementById('docrootGhost');
            var txt = document.getElementById('docrootText');
            var inp = document.getElementById('docrootInput');
            var cfg = document.getElementById('docrootConfigBtn');
            var sav = document.getElementById('docrootSaveBtn');
            var can = document.getElementById('docrootCancelBtn');
            ghost.classList.add('editing');
            txt.style.display = 'none';
            inp.style.display = '';
            inp.value = localStorage.getItem(_docrootKey) || '';
            cfg.style.display = 'none';
            sav.style.display = '';
            can.style.display = '';
            inp.focus();
            inp.select();
        }

        function saveDocrootPath() {
            var inp = document.getElementById('docrootInput');
            var val = inp.value.trim();
            if (val) {
                localStorage.setItem(_docrootKey, val);
            } else {
                localStorage.removeItem(_docrootKey);
            }
            _docrootExitEdit();
            _docrootLoad();
            if (typeof showToast === 'function') {
                showToast(val ? 'Localhost path saved!' : 'Localhost path cleared.', 'success');
            }
            // Reload iframe to reflect the new docroot (cache-busted)
            var iframe = _iframeEl();
            if (iframe && iframe.src && iframe.src !== 'about:blank') {
                iframeReload();
            }
        }

        function cancelDocrootEdit() {
            _docrootExitEdit();
        }

        function _docrootExitEdit() {
            var ghost = document.getElementById('docrootGhost');
            var txt = document.getElementById('docrootText');
            var inp = document.getElementById('docrootInput');
            var cfg = document.getElementById('docrootConfigBtn');
            var sav = document.getElementById('docrootSaveBtn');
            var can = document.getElementById('docrootCancelBtn');
            ghost.classList.remove('editing');
            txt.style.display = '';
            inp.style.display = 'none';
            cfg.style.display = '';
            sav.style.display = 'none';
            can.style.display = 'none';
        }

        // Enter to save, Esc to cancel in the docroot input
        document.addEventListener('DOMContentLoaded', function() {
            _docrootLoad();
            var inp = document.getElementById('docrootInput');
            if (inp) {
                inp.addEventListener('keydown', function(e) {
                    if (e.key === 'Enter') { e.preventDefault(); saveDocrootPath(); }
                    if (e.key === 'Escape') { e.preventDefault(); cancelDocrootEdit(); }
                });
            }
        });

        // Update docroot ghost path based on iframe navigation
        function _docrootUpdateFromIframe(iframeUrl) {
            var txt = document.getElementById('docrootText');
            var ghost = document.getElementById('docrootGhost');
            var navInput = document.getElementById('docrootNavInput');
            if (!ghost || ghost.classList.contains('editing')) return;

            if (!iframeUrl || iframeUrl === 'about:blank') {
                // Reset: show docrootText, clear navInput
                if (navInput) navInput.value = '';
                if (txt) txt.style.display = '';
                _docrootLoad();
                return;
            }

            try {
                var iframeU = new URL(iframeUrl);
                var iframePath = decodeURIComponent(iframeU.pathname);

                // Get the docroot base path
                var saved = localStorage.getItem(_docrootKey) || '';
                var basePath = '';

                if (saved) {
                    try {
                        var savedU = new URL(saved);
                        basePath = savedU.pathname;
                    } catch(e) {
                        basePath = saved.replace(/\\/g, '/');
                    }
                } else {
                    basePath = window.location.pathname.replace(/\/[^\/]*$/, '');
                }

                // Normalize
                basePath = basePath.replace(/\/+$/, '');
                iframePath = iframePath.replace(/\/+$/, '');

                // Relative path from docroot (strip localhost base, show only subpath)
                var relativePath = '';
                if (iframePath.toLowerCase().indexOf(basePath.toLowerCase()) === 0) {
                    relativePath = iframePath.substring(basePath.length);
                } else {
                    relativePath = iframePath;
                }

                // Build the display path for the input
                var displayPath = relativePath || '/';
                if (displayPath.charAt(0) !== '/') displayPath = '/' + displayPath;

                // HIDE docrootText — navInput takes over the space
                if (txt) txt.style.display = 'none';

                // Write path into the nav input with flash feedback
                if (navInput) {
                    navInput.value = displayPath;
                    navInput.classList.add('nav-flash');
                    clearTimeout(navInput._flashTimer);
                    navInput._flashTimer = setTimeout(function() { navInput.classList.remove('nav-flash'); }, 1200);
                }

                var icon = document.getElementById('docrootIcon');
                var isLocal = /^localhost$/i.test(iframeU.hostname) || /^127\.0\.0\.1$/.test(iframeU.hostname);
                if (icon) icon.className = isLocal ? 'fas fa-server' : 'fas fa-globe';

                ghost.title = iframeUrl;
            } catch(e) {
                // Fallback: show raw URL in nav input
                if (txt) txt.style.display = 'none';
                if (navInput) navInput.value = iframeUrl;
            }
        }

        function _docrootEsc(s) {
            var d = document.createElement('div');
            d.textContent = s;
            return d.innerHTML;
        }

        /* ══════════════════════════════════════════
           URL Autocomplete – Ghost Text + Dropdown
           ══════════════════════════════════════════ */
        var _acDebounceTimer = null;
        var _acItems = [];          // current suggestion list
        var _acActiveIdx = -1;      // highlighted dropdown index (-1 = none / ghost only)
        var _acGhostSuggestion = ''; // the text appended as ghost
        var _acOpen = false;
        var _acLastQuery = '';

        /**
         * Extract the "path after localhost" from the input value.
         * Returns { base, partial, trigger } or null if autocomplete should not fire.
         *   base    = "localhost/" or "localhost/folder/"
         *   partial = typed partial filename/folder after last slash
         *   trigger = true when the URL ends with / (list whole dir)
         */
        function _acParseInput(val) {
            // Match: localhost/ or localhost:port/ or http://localhost/ etc.
            var m = val.match(/^(https?:\/\/)?localhost(:\d+)?(\/.*)?$/i);
            if (!m) return null;
            var path = m[3] || '';           // everything after localhost[:port]
            if (path === '') return null;     // no slash typed yet — don't trigger
            // path starts with /
            // Separate directory part from partial filename
            var lastSlash = path.lastIndexOf('/');
            var dir = path.substring(1, lastSlash + 1); // after leading /
            var partial = path.substring(lastSlash + 1);
            return {
                dir: dir,           // e.g. "Fusion Viewer/" or ""
                partial: partial,   // e.g. "found" (partial) or "" (list all)
                trigger: true
            };
        }

        /** Called on every input event */
        function iframeUrlAutocomplete() {
            clearTimeout(_acDebounceTimer);
            _acDebounceTimer = setTimeout(_acFetch, 180);
        }

        function _acFetch() {
            var input = document.getElementById('iframeUrlInput');
            var val = input.value;
            var parsed = _acParseInput(val);
            if (!parsed) {
                _acClose();
                return;
            }
            var q = parsed.dir + parsed.partial;
            if (q === _acLastQuery && _acOpen) return; // same query, skip
            _acLastQuery = q;

            // Build query for the PHP endpoint, include custom root if configured
            var rootPath = localStorage.getItem('pm_localhost_path') || '';
            var endpoint = 'url_suggest.php?q=' + encodeURIComponent(q)
                         + (rootPath ? '&root=' + encodeURIComponent(rootPath) : '');
            fetch(endpoint)
                .then(function(r) { return r.json(); })
                .then(function(data) {
                    if (!data.items || data.items.length === 0) {
                        _acClose();
                        return;
                    }
                    _acItems = data.items;
                    _acActiveIdx = -1;
                    _acRenderDropdown(parsed);
                    _acUpdateGhost(parsed);
                    _acShow();
                })
                .catch(function() { _acClose(); });
        }

        /** Render the dropdown */
        function _acRenderDropdown(parsed) {
            var dd = document.getElementById('iframeUrlDropdown');
            var html = '';
            // Header
            var displayDir = parsed.dir || '/';
            html += '<div class="iframe-ac-header"><i class="fas fa-folder-open"></i> ' + _acEsc(displayDir) + '</div>';

            for (var i = 0; i < _acItems.length; i++) {
                var it = _acItems[i];
                var iconClass = it.type === 'dir' ? 'ac-icon-dir' : (it.icon === 'php' ? 'ac-icon-php' : 'ac-icon-html');
                var iconFa = it.type === 'dir' ? 'fa-folder' : (it.icon === 'php' ? 'fa-file-code' : 'fa-file-alt');
                var badge = it.type === 'dir' ? 'DIR' : (it.ext || 'html').toUpperCase();
                var badgeClass = it.type === 'dir' ? 'badge-dir' : (it.icon === 'php' ? 'badge-php' : 'badge-html');
                html += '<div class="iframe-ac-item' + (i === _acActiveIdx ? ' active' : '') + '" data-idx="' + i + '" '
                      + 'onmouseenter="_acHover(' + i + ')" onclick="_acSelect(' + i + ')">'
                      + '<div class="ac-icon ' + iconClass + '"><i class="fas ' + iconFa + '"></i></div>'
                      + '<span class="ac-name">' + _acHighlight(it.name, parsed.partial) + '</span>'
                      + '<span class="ac-badge ' + badgeClass + '">' + badge + '</span>'
                      + '</div>';
            }
            dd.innerHTML = html;
        }

        /** Highlight the matching portion in the name */
        function _acHighlight(name, partial) {
            if (!partial) return _acEsc(name);
            var idx = name.toLowerCase().indexOf(partial.toLowerCase());
            if (idx === -1) return _acEsc(name);
            return _acEsc(name.substring(0, idx))
                 + '<span style="color:#a78bfa;font-weight:600;">' + _acEsc(name.substring(idx, idx + partial.length)) + '</span>'
                 + _acEsc(name.substring(idx + partial.length));
        }

        function _acEsc(s) { var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }

        /** Update ghost text */
        function _acUpdateGhost(parsed) {
            var ghost = document.getElementById('iframeUrlGhost');
            var input = document.getElementById('iframeUrlInput');
            var val = input.value;

            // Pick the suggestion to show as ghost
            var idx = _acActiveIdx >= 0 ? _acActiveIdx : 0;
            if (idx >= _acItems.length) { ghost.innerHTML = ''; _acGhostSuggestion = ''; return; }

            var suggestion = _acItems[idx].name;
            // The ghost completion = the part of the suggestion not yet typed
            var completion = '';
            if (parsed.partial && suggestion.toLowerCase().indexOf(parsed.partial.toLowerCase()) === 0) {
                completion = suggestion.substring(parsed.partial.length);
            } else if (!parsed.partial) {
                completion = suggestion;
            }

            _acGhostSuggestion = completion;

            if (!completion) {
                ghost.innerHTML = '';
                return;
            }

            // Build ghost: invisible typed part + visible suggestion part
            ghost.innerHTML = '<span class="ghost-typed">' + _acEsc(val) + '</span>'
                            + '<span class="ghost-suggestion">' + _acEsc(completion) + '</span>';
        }

        function _acShow() {
            var dd = document.getElementById('iframeUrlDropdown');
            dd.classList.add('visible');
            _acOpen = true;
        }

        function _acClose() {
            var dd = document.getElementById('iframeUrlDropdown');
            var ghost = document.getElementById('iframeUrlGhost');
            dd.classList.remove('visible');
            dd.innerHTML = '';
            ghost.innerHTML = '';
            _acItems = [];
            _acActiveIdx = -1;
            _acGhostSuggestion = '';
            _acOpen = false;
            _acLastQuery = '';
        }

        function _acHover(idx) {
            _acActiveIdx = idx;
            _acRefreshActive();
            var parsed = _acParseInput(document.getElementById('iframeUrlInput').value);
            if (parsed) _acUpdateGhost(parsed);
        }

        function _acRefreshActive() {
            var dd = document.getElementById('iframeUrlDropdown');
            var items = dd.querySelectorAll('.iframe-ac-item');
            for (var i = 0; i < items.length; i++) {
                items[i].classList.toggle('active', i === _acActiveIdx);
            }
            // Scroll into view
            if (_acActiveIdx >= 0 && items[_acActiveIdx]) {
                items[_acActiveIdx].scrollIntoView({ block: 'nearest' });
            }
        }

        /** Accept the current suggestion (ghost text or active dropdown item) */
        function _acAccept() {
            var input = document.getElementById('iframeUrlInput');
            if (_acGhostSuggestion) {
                input.value += _acGhostSuggestion;
                _acGhostSuggestion = '';
                document.getElementById('iframeUrlGhost').innerHTML = '';
                // If we accepted a directory, immediately trigger new autocomplete
                if (input.value.endsWith('/')) {
                    _acLastQuery = '';
                    iframeUrlAutocomplete();
                } else {
                    _acClose();
                }
                return true;
            }
            return false;
        }

        function _acSelect(idx) {
            if (idx < 0 || idx >= _acItems.length) return;
            _acActiveIdx = idx;
            var parsed = _acParseInput(document.getElementById('iframeUrlInput').value);
            if (parsed) _acUpdateGhost(parsed);
            _acAccept();
            document.getElementById('iframeUrlInput').focus();
        }

        /** Main keydown handler for the URL input */
        function iframeUrlKeydown(event) {
            if (event.key === 'Tab' && _acOpen && _acGhostSuggestion) {
                event.preventDefault();
                _acAccept();
                return;
            }
            if (event.key === 'Escape') {
                if (_acOpen) {
                    event.preventDefault();
                    event.stopPropagation();
                    _acClose();
                    return;
                }
            }
            if (event.key === 'ArrowDown' && _acOpen) {
                event.preventDefault();
                _acActiveIdx = Math.min(_acActiveIdx + 1, _acItems.length - 1);
                _acRefreshActive();
                var parsed = _acParseInput(document.getElementById('iframeUrlInput').value);
                if (parsed) _acUpdateGhost(parsed);
                return;
            }
            if (event.key === 'ArrowUp' && _acOpen) {
                event.preventDefault();
                _acActiveIdx = Math.max(_acActiveIdx - 1, 0);
                _acRefreshActive();
                var parsed = _acParseInput(document.getElementById('iframeUrlInput').value);
                if (parsed) _acUpdateGhost(parsed);
                return;
            }
            if (event.key === 'Enter') {
                if (_acOpen && _acActiveIdx >= 0) {
                    event.preventDefault();
                    _acSelect(_acActiveIdx);
                    return;
                }
                // If no dropdown selection, navigate normally
                _acClose();
                iframeNavigate();
                return;
            }
        }

        // Close autocomplete when clicking outside
        document.addEventListener('click', function(e) {
            var wrapper = document.querySelector('.iframe-url-input-wrapper');
            if (wrapper && !wrapper.contains(e.target)) {
                _acClose();
            }
        });

        // Also close when the iframe tab loses visibility
        document.addEventListener('visibilitychange', function() {
            if (document.hidden) _acClose();
        });

        /* ── Localhost Folder Picker (Browse) ── */
        var _lfpCurrentPath = '';
        var _lfpSelectedPath = '';
        var _lfpAllDirs = [];

        // Client-mode state (File System Access API for remote hosts)
        var _lfpClientMode = false;
        var _lfpClientHandles = new Map();
        var _lfpClientNavStack = []; // [{handle, name}]
        var _lfpCurrentHandle = null;
        var _lfpClientSelectedName = '';

        function _lfpIsLocalhost() {
            var h = window.location.hostname;
            return h === 'localhost' || h === '127.0.0.1' || h === '::1' || h.endsWith('.local') || h.endsWith('.test');
        }

        function openLocalhostFolderPicker() {
            var modal = document.getElementById('localhostFolderPickerModal');
            if (!modal) return;

            _lfpSelectedPath = '';
            _lfpClientSelectedName = '';
            _lfpUpdateSelectBtn();
            document.getElementById('lfpSelectedPathText').textContent = 'No folder selected';
            document.getElementById('lfpSelectedPath').classList.remove('has-selection');
            var searchInp = document.getElementById('lfpSearchInput');
            if (searchInp) { searchInp.value = ''; }
            document.getElementById('lfpSearchClear').style.display = 'none';

            var titleText = document.getElementById('lfpTitleText');
            var titleIcon = document.getElementById('lfpTitleIcon');

            if (_lfpIsLocalhost()) {
                // PHP mode — browse server filesystem (same machine as user)
                _lfpClientMode = false;
                if (titleText) titleText.textContent = 'Select Localhost Folder';
                if (titleIcon) titleIcon.className = 'fas fa-folder-open';
                modal.classList.add('active');
                _lfpNavigate('');
            } else {
                // Client mode — use File System Access API to browse user's PC
                _lfpClientMode = true;
                if (titleText) titleText.textContent = 'Select Folder from Your PC';
                if (titleIcon) titleIcon.className = 'fas fa-laptop';

                if (!window.showDirectoryPicker) {
                    showToast('Your browser does not support folder browsing. Please use Chrome or Edge, or configure the path manually using the gear icon.', 'error');
                    return;
                }

                window.showDirectoryPicker({ mode: 'read' }).then(function(handle) {
                    _lfpCurrentHandle = handle;
                    _lfpClientNavStack = [];
                    _lfpClientHandles = new Map();
                    modal.classList.add('active');
                    _lfpNavigateClient(handle, handle.name);
                }).catch(function(err) {
                    if (err.name !== 'AbortError') {
                        console.error('Folder picker error:', err);
                        showToast('Could not open folder picker: ' + err.message, 'error');
                    }
                    _lfpClientMode = false;
                });
            }
        }

        function closeLocalhostFolderPicker() {
            var modal = document.getElementById('localhostFolderPickerModal');
            if (modal) modal.classList.remove('active');
            // Reset client-mode state
            _lfpClientHandles = new Map();
            _lfpClientNavStack = [];
            _lfpCurrentHandle = null;
            _lfpClientSelectedName = '';
        }

        function _lfpNavigate(path) {
            var body = document.getElementById('lfpBody');
            body.innerHTML = '<div class="lfp-loading"><i class="fas fa-spinner fa-spin"></i> Loading directories...</div>';
            
            var fd = new FormData();
            fd.append('action', 'browse_localhost_dirs');
            if (path) fd.append('path', path);
            
            fetch(window.location.href, { method: 'POST', body: fd })
                .then(function(r) { return r.json(); })
                .then(function(data) {
                    if (!data.success) {
                        body.innerHTML = '<div class="lfp-empty"><i class="fas fa-exclamation-triangle"></i><span>' + (data.message || 'Error loading') + '</span></div>';
                        return;
                    }
                    _lfpCurrentPath = data.current;
                    _lfpAllDirs = data.dirs || [];
                    _lfpRenderBreadcrumb(data.current);
                    _lfpRenderFolders(_lfpAllDirs, data.parent);
                    // Clear search
                    var searchInp = document.getElementById('lfpSearchInput');
                    if (searchInp) searchInp.value = '';
                    document.getElementById('lfpSearchClear').style.display = 'none';
                })
                .catch(function(err) {
                    body.innerHTML = '<div class="lfp-empty"><i class="fas fa-exclamation-triangle"></i><span>Network error</span></div>';
                });
        }

        function _lfpRenderBreadcrumb(fullPath) {
            var bc = document.getElementById('lfpBreadcrumb');
            if (!bc) return;
            // Split path into segments
            var parts = fullPath.replace(/\\/g, '/').split('/').filter(Boolean);
            var html = '';
            var accumulated = '';
            
            for (var i = 0; i < parts.length; i++) {
                if (i === 0 && parts[i].indexOf(':') !== -1) {
                    // Drive letter (e.g., C:)
                    accumulated = parts[i];
                } else {
                    accumulated += '/' + parts[i];
                }
                var isLast = (i === parts.length - 1);
                if (isLast) {
                    html += '<span class="lfp-crumb active">' + _lfpEsc(parts[i]) + '</span>';
                } else {
                    html += '<span class="lfp-crumb" onclick="_lfpNavigate(\'' + _lfpEscAttr(accumulated) + '\')">' + _lfpEsc(parts[i]) + '</span>';
                    html += '<span class="lfp-crumb-sep"><i class="fas fa-chevron-right"></i></span>';
                }
            }
            bc.innerHTML = html;
        }

        function _lfpRenderFolders(dirs, parentPath) {
            var body = document.getElementById('lfpBody');
            if (!body) return;
            var html = '';
            
            // Parent (..) link
            if (parentPath) {
                html += '<div class="lfp-up-item" onclick="_lfpNavigate(\'' + _lfpEscAttr(parentPath) + '\')">';
                html += '<i class="fas fa-level-up-alt"></i>';
                html += '<span>.. (parent directory)</span>';
                html += '</div>';
            }
            
            if (dirs.length === 0) {
                html += '<div class="lfp-empty"><i class="fas fa-folder-open"></i><span>No subdirectories</span></div>';
            } else {
                for (var i = 0; i < dirs.length; i++) {
                    var d = dirs[i];
                    var isSelected = (_lfpSelectedPath === d.path);
                    html += '<div class="lfp-folder-item' + (isSelected ? ' selected' : '') + '" ';
                    html += 'onclick="_lfpSelectFolder(\'' + _lfpEscAttr(d.path) + '\', \'' + _lfpEscAttr(d.name) + '\')" ';
                    html += 'ondblclick="_lfpNavigate(\'' + _lfpEscAttr(d.path) + '\')">';
                    html += '<i class="fas fa-folder lfp-folder-icon"></i>';
                    html += '<span class="lfp-folder-name">' + _lfpEsc(d.name) + '</span>';
                    html += '<span class="lfp-folder-enter" onclick="event.stopPropagation(); _lfpNavigate(\'' + _lfpEscAttr(d.path) + '\')">Open <i class="fas fa-arrow-right"></i></span>';
                    html += '</div>';
                }
            }
            body.innerHTML = html;
        }

        function _lfpSelectFolder(path, name) {
            _lfpSelectedPath = path;
            // Update UI
            var pathEl = document.getElementById('lfpSelectedPath');
            var textEl = document.getElementById('lfpSelectedPathText');
            textEl.textContent = path;
            pathEl.classList.add('has-selection');
            _lfpUpdateSelectBtn();
            // Re-render to show selection highlight
            var items = document.querySelectorAll('.lfp-folder-item');
            items.forEach(function(el) {
                el.classList.remove('selected');
            });
            // Find and highlight the selected one
            items.forEach(function(el) {
                var itemPath = el.getAttribute('onclick');
                if (itemPath && itemPath.indexOf(_lfpEscAttr(path)) !== -1) {
                    el.classList.add('selected');
                }
            });
        }

        // ── CLIENT MODE — Navigate via File System Access API (remote host) ──

        async function _lfpNavigateClient(dirHandle, pathLabel) {
            var body = document.getElementById('lfpBody');
            body.innerHTML = '<div class="lfp-loading"><i class="fas fa-spinner fa-spin"></i> Reading folder...</div>';

            _lfpCurrentHandle = dirHandle;
            _lfpClientHandles = new Map();
            _lfpAllDirs = [];

            // Update breadcrumb for client mode
            _lfpRenderClientBreadcrumb(pathLabel);

            try {
                var subdirs = [];
                var skipDirs = ['node_modules', 'vendor', '__pycache__', '.git', '.svn', 'dist', 'build', '.next', '.nuxt', '.cache', '.output', '.idea', '.vscode'];
                for await (var entry of dirHandle.values()) {
                    if (entry.name.startsWith('.')) continue;
                    if (entry.kind === 'directory' && skipDirs.indexOf(entry.name) === -1) {
                        subdirs.push(entry);
                        _lfpClientHandles.set(entry.name, entry);
                    }
                }

                subdirs.sort(function(a, b) { return a.name.localeCompare(b.name, undefined, { sensitivity: 'base' }); });

                _lfpAllDirs = subdirs.map(function(entry) {
                    return { name: entry.name, path: entry.name };
                });

                _lfpRenderClientFolders(subdirs);
            } catch (err) {
                body.innerHTML = '<div class="lfp-empty"><i class="fas fa-exclamation-triangle"></i><span>Cannot read directory. Permission may have been revoked.</span></div>';
                console.error('Client folder read error:', err);
            }
        }

        function _lfpEnterClientFolder(folderName) {
            var handle = _lfpClientHandles.get(folderName);
            if (!handle) return;

            // Push current directory onto nav stack
            _lfpClientNavStack.push({ handle: _lfpCurrentHandle, name: _lfpCurrentHandle.name });

            // Build path label from stack
            var pathLabel = _lfpClientNavStack.map(function(p) { return p.name; }).join(' / ') + ' / ' + folderName;
            _lfpNavigateClient(handle, pathLabel);
        }

        function _lfpClientGoUp() {
            if (_lfpClientNavStack.length > 0) {
                var parent = _lfpClientNavStack.pop();
                var pathLabel = _lfpClientNavStack.length > 0
                    ? _lfpClientNavStack.map(function(p) { return p.name; }).join(' / ') + ' / ' + parent.name
                    : parent.name;
                _lfpNavigateClient(parent.handle, pathLabel);
            }
        }

        function _lfpRenderClientBreadcrumb(pathLabel) {
            var bc = document.getElementById('lfpBreadcrumb');
            if (!bc) return;

            var parts = pathLabel.split(' / ').filter(Boolean);
            var html = '<span class="lfp-crumb" style="opacity:0.6;cursor:default;"><i class="fas fa-laptop" style="margin-right:4px;"></i> Your PC</span>';

            for (var i = 0; i < parts.length; i++) {
                html += '<span class="lfp-crumb-sep"><i class="fas fa-chevron-right"></i></span>';
                var isLast = (i === parts.length - 1);
                if (isLast) {
                    html += '<span class="lfp-crumb active">' + _lfpEsc(parts[i]) + '</span>';
                } else {
                    html += '<span class="lfp-crumb" style="opacity:0.7;cursor:default;">' + _lfpEsc(parts[i]) + '</span>';
                }
            }
            bc.innerHTML = html;
        }

        function _lfpRenderClientFolders(subdirs) {
            var body = document.getElementById('lfpBody');
            if (!body) return;
            var html = '';

            // "Use this folder" — select the current directory itself
            if (_lfpCurrentHandle) {
                var curPath = _lfpClientNavStack.map(function(p) { return p.name; }).concat([_lfpCurrentHandle.name]).join('/');
                var isCurSel = (_lfpSelectedPath === curPath);
                html += '<div class="lfp-current-dir' + (isCurSel ? ' selected' : '') + '" data-lfp-action="select-current">';
                html += '<i class="fas fa-check-circle"></i>';
                html += '<span>Use this folder: <strong>' + _lfpEsc(_lfpCurrentHandle.name) + '</strong></span>';
                html += '</div>';
            }

            // Parent (..) link if we have nav stack
            if (_lfpClientNavStack.length > 0) {
                html += '<div class="lfp-up-item" data-lfp-action="go-up">';
                html += '<i class="fas fa-level-up-alt"></i>';
                html += '<span>.. (parent directory)</span>';
                html += '</div>';
            }

            if (subdirs.length === 0) {
                html += '<div class="lfp-empty"><i class="fas fa-folder-open"></i><span>No subdirectories</span></div>';
            } else {
                for (var i = 0; i < subdirs.length; i++) {
                    var entry = subdirs[i];
                    var isSelected = (_lfpClientSelectedName === entry.name);
                    html += '<div class="lfp-folder-item' + (isSelected ? ' selected' : '') + '" data-lfp-action="select" data-lfp-name="' + _lfpEsc(entry.name).replace(/"/g, '&quot;') + '">';
                    html += '<i class="fas fa-folder lfp-folder-icon"></i>';
                    html += '<span class="lfp-folder-name">' + _lfpEsc(entry.name) + '</span>';
                    html += '<span class="lfp-folder-enter" data-lfp-action="enter" data-lfp-name="' + _lfpEsc(entry.name).replace(/"/g, '&quot;') + '">Open <i class="fas fa-arrow-right"></i></span>';
                    html += '</div>';
                }
            }
            body.innerHTML = html;
        }

        function _lfpSelectClientFolder(name) {
            try {
                _lfpClientSelectedName = name;

                // Build full display path from nav stack
                var pathParts = _lfpClientNavStack.map(function(p) { return p.name; });
                if (_lfpCurrentHandle) pathParts.push(_lfpCurrentHandle.name);
                pathParts.push(name);
                _lfpSelectedPath = pathParts.join('/');

                // Update selected path display
                var pathEl = document.getElementById('lfpSelectedPath');
                var textEl = document.getElementById('lfpSelectedPathText');
                if (textEl) textEl.textContent = _lfpSelectedPath;
                if (pathEl) pathEl.classList.add('has-selection');

                // Force-enable the select button
                var btn = document.getElementById('lfpSelectBtn');
                if (btn) { btn.disabled = false; btn.removeAttribute('disabled'); }

                // Update selection highlights
                document.querySelectorAll('.lfp-current-dir').forEach(function(el) { el.classList.remove('selected'); });
                document.querySelectorAll('.lfp-folder-item').forEach(function(el) { el.classList.remove('selected'); });
                document.querySelectorAll('.lfp-folder-item').forEach(function(el) {
                    if (el.getAttribute('data-lfp-name') === name) {
                        el.classList.add('selected');
                    }
                });
            } catch(e) {
                console.error('_lfpSelectClientFolder error:', e);
            }
        }

        function _lfpSelectCurrentDir() {
            try {
                if (!_lfpCurrentHandle) return;
                _lfpClientSelectedName = '';

                // Path = nav stack names + current handle name
                var pathParts = _lfpClientNavStack.map(function(p) { return p.name; });
                pathParts.push(_lfpCurrentHandle.name);
                _lfpSelectedPath = pathParts.join('/');

                // Update selected path display
                var pathEl = document.getElementById('lfpSelectedPath');
                var textEl = document.getElementById('lfpSelectedPathText');
                if (textEl) textEl.textContent = _lfpSelectedPath;
                if (pathEl) pathEl.classList.add('has-selection');

                // Force-enable the select button
                var btn = document.getElementById('lfpSelectBtn');
                if (btn) { btn.disabled = false; btn.removeAttribute('disabled'); }

                // Update highlights
                document.querySelectorAll('.lfp-folder-item').forEach(function(el) { el.classList.remove('selected'); });
                document.querySelectorAll('.lfp-current-dir').forEach(function(el) { el.classList.add('selected'); });
            } catch(e) {
                console.error('_lfpSelectCurrentDir error:', e);
            }
        }

        function _lfpUpdateSelectBtn() {
            var btn = document.getElementById('lfpSelectBtn');
            if (btn) {
                btn.disabled = !_lfpSelectedPath;
                if (_lfpSelectedPath) btn.removeAttribute('disabled');
            }
        }

        function confirmLocalhostFolder() {
            if (!_lfpSelectedPath) return;
            var wasClientMode = _lfpClientMode;
            var fsPath = _lfpSelectedPath.replace(/\\/g, '/');
            
            // Save the filesystem path
            localStorage.setItem(_docrootKey, fsPath);
            
            // Update docroot display — call _docrootLoad plus direct fallback
            _docrootLoad();
            
            // Direct DOM update as safety fallback
            var txt = document.getElementById('docrootText');
            var ghost = document.getElementById('docrootGhost');
            var inp = document.getElementById('docrootInput');
            if (txt) {
                var parts = fsPath.replace(/\/+$/, '').split('/');
                var folderName = parts[parts.length - 1] || fsPath;
                txt.textContent = folderName;
                txt.style.display = '';
                txt.classList.remove('not-set');
            }
            if (ghost) {
                ghost.classList.remove('editing');
                ghost.title = 'Document root: ' + fsPath;
            }
            // Make sure edit input is hidden
            if (inp) inp.style.display = 'none';
            
            closeLocalhostFolderPicker();
            showToast('Document root set to: ' + fsPath, 'success');
            
            // Reload iframe to reflect the new docroot
            // In both modes, http://localhost points to the user's local machine
            var iframe = _iframeEl();
            if (iframe && iframe.src && iframe.src !== 'about:blank') {
                // If already viewing localhost, force reload with cache-bust
                var currentClean = _iframeCleanUrl(iframe.src);
                if (currentClean.indexOf('localhost') !== -1) {
                    iframeReload();
                }
            } else if (!wasClientMode) {
                // First time — auto-navigate to localhost
                if (typeof iframeLoadUrl === 'function') {
                    iframeLoadUrl('http://localhost');
                }
            }
        }

        function lfpClearSearch() {
            var inp = document.getElementById('lfpSearchInput');
            if (inp) inp.value = '';
            document.getElementById('lfpSearchClear').style.display = 'none';
            // Re-render all — use correct renderer based on mode
            if (_lfpClientMode) {
                var entries = [];
                _lfpClientHandles.forEach(function(handle, name) { entries.push(handle); });
                _lfpRenderClientFolders(entries);
            } else {
                _lfpRenderFolders(_lfpAllDirs, _lfpCurrentPath ? _getParentPath(_lfpCurrentPath) : null);
            }
        }

        function _getParentPath(p) {
            var parts = p.replace(/\\/g, '/').split('/').filter(Boolean);
            if (parts.length <= 1) return null;
            parts.pop();
            var result = parts.join('/');
            // Ensure drive letter format
            if (parts.length === 1 && parts[0].indexOf(':') !== -1) {
                result = parts[0] + '/';
            }
            return result;
        }

        // Search filter listener
        document.addEventListener('DOMContentLoaded', function() {
            var searchInp = document.getElementById('lfpSearchInput');
            if (searchInp) {
                searchInp.addEventListener('input', function() {
                    var val = this.value.trim().toLowerCase();
                    var clearBtn = document.getElementById('lfpSearchClear');
                    clearBtn.style.display = val ? '' : 'none';
                    
                    if (_lfpClientMode) {
                        // Client mode filtering
                        var allEntries = [];
                        _lfpClientHandles.forEach(function(handle, name) { allEntries.push(handle); });
                        if (!val) {
                            _lfpRenderClientFolders(allEntries);
                            return;
                        }
                        var filtered = allEntries.filter(function(e) {
                            return e.name.toLowerCase().indexOf(val) !== -1;
                        });
                        _lfpRenderClientFolders(filtered);
                    } else {
                        // PHP mode filtering
                        if (!val) {
                            _lfpRenderFolders(_lfpAllDirs, _getParentPath(_lfpCurrentPath));
                            return;
                        }
                        var filtered = _lfpAllDirs.filter(function(d) {
                            return d.name.toLowerCase().indexOf(val) !== -1;
                        });
                        _lfpRenderFolders(filtered, null);
                    }
                });
                searchInp.addEventListener('keydown', function(e) {
                    if (e.key === 'Escape') { lfpClearSearch(); }
                });
            }
            
            // Event delegation for client-mode folder picker actions
            var lfpBody = document.getElementById('lfpBody');
            if (lfpBody) {
                lfpBody.addEventListener('click', function(e) {
                    if (!_lfpClientMode) return;
                    var target = e.target;
                    // Walk up from the clicked element to find the action attribute
                    var actionEl = target.closest('[data-lfp-action]');
                    if (!actionEl) return;
                    var action = actionEl.getAttribute('data-lfp-action');
                    var name = actionEl.getAttribute('data-lfp-name');

                    e.preventDefault();
                    e.stopPropagation();

                    if (action === 'select-current') {
                        _lfpSelectCurrentDir();
                    } else if (action === 'go-up') {
                        _lfpClientGoUp();
                    } else if (action === 'select') {
                        if (name) _lfpSelectClientFolder(name);
                    } else if (action === 'enter') {
                        if (name) _lfpEnterClientFolder(name);
                    }
                });

                // Double-click to enter folder in client mode
                lfpBody.addEventListener('dblclick', function(e) {
                    if (!_lfpClientMode) return;
                    var target = e.target;
                    var folderItem = target.closest('.lfp-folder-item[data-lfp-name]');
                    if (!folderItem) return;
                    var name = folderItem.getAttribute('data-lfp-name');
                    if (name) _lfpEnterClientFolder(name);
                });
            }

            // Close modal on overlay click
            var modal = document.getElementById('localhostFolderPickerModal');
            if (modal) {
                modal.addEventListener('click', function(e) {
                    if (e.target === modal) closeLocalhostFolderPicker();
                });
            }
        });

        function _lfpEsc(str) {
            var div = document.createElement('div');
            div.textContent = str;
            return div.innerHTML;
        }

        function _lfpEscAttr(str) {
            return str.replace(/\\/g, '/').replace(/'/g, "\\'");
        }

        function iframeGoHome() {
            iframeLoadUrl('http://localhost');
        }

        function iframeOpenExternal() {
            const url = document.getElementById('iframeUrlInput').value.trim();
            if (url && url !== 'about:blank') {
                window.open(url, '_blank');
            }
        }

        function iframeToggleFullscreen() {
            const workspace = document.querySelector('.iframe-workspace');
            const btn = document.getElementById('iframeFullscreen');
            if (!workspace) return;
            workspace.classList.toggle('fullscreen');
            const isFs = workspace.classList.contains('fullscreen');
            btn.querySelector('i').className = isFs ? 'fas fa-compress' : 'fas fa-expand';
            btn.title = isFs ? 'Exit Fullscreen' : 'Fullscreen';
        }

        function _iframeUpdateNavBtns() {
            const backBtn = document.getElementById('iframeBack');
            const fwdBtn = document.getElementById('iframeForward');
            if (backBtn) backBtn.disabled = (_iframeHistoryIdx <= 0);
            if (fwdBtn) fwdBtn.disabled = (_iframeHistoryIdx >= _iframeHistory.length - 1);
        }

        // ── Breadcrumb Path ──
        function _iframeUpdateBreadcrumb(url) {
            var bar = document.getElementById('iframeBreadcrumbBar');
            if (!bar) return;

            if (!url || url === 'about:blank') {
                bar.classList.remove('visible');
                bar.innerHTML = '';
                return;
            }

            try {
                var u = new URL(url);
                var isLocal = /^localhost$/i.test(u.hostname);
                var hostLabel = isLocal ? 'localhost' : u.hostname.replace(/^www\./i, '');
                var hostIcon = isLocal ? 'fa-server' : 'fa-globe';
                var pathname = u.pathname;
                var segments = pathname.replace(/^\/+/, '').replace(/\/+$/, '').split('/').filter(Boolean);

                if (segments.length === 0) {
                    bar.innerHTML = '<span class="iframe-breadcrumb-item bc-root bc-active" title="' + _bcEscAttr(u.origin) + '"><i class="fas ' + hostIcon + '"></i> ' + _bcEscHtml(hostLabel) + '</span>';
                    bar.classList.add('visible');
                    return;
                }

                var mainDir = segments[0];
                var html = '';

                // Root item: show hostname
                var rootUrl = u.origin + '/' + mainDir + '/';
                html += '<span class="iframe-breadcrumb-item bc-root' + (segments.length === 1 ? ' bc-active' : '') + '" '
                      + 'onclick="iframeLoadUrl(\'' + _bcEscAttr(rootUrl) + '\')" '
                      + 'title="' + _bcEscAttr(mainDir) + '">'
                      + '<i class="fas ' + hostIcon + '"></i> ' + _bcEscHtml(hostLabel) + '</span>';

                // Sub-segments
                for (var i = 1; i < segments.length; i++) {
                    var seg = segments[i];
                    var isLast = (i === segments.length - 1);
                    var isFile = isLast && seg.indexOf('.') !== -1;

                    var partialPath = u.origin + '/' + segments.slice(0, i + 1).join('/') + (isFile ? '' : '/');

                    html += '<span class="iframe-breadcrumb-sep"><i class="fas fa-chevron-right"></i></span>';

                    var iconClass = isFile ? 'fa-file-code' : 'fa-folder';
                    var typeClass = isFile ? 'bc-file' : 'bc-dir';

                    html += '<span class="iframe-breadcrumb-item ' + typeClass + (isLast ? ' bc-active' : '') + '" '
                          + (isLast ? '' : 'onclick="iframeLoadUrl(\'' + _bcEscAttr(partialPath) + '\')" ')
                          + 'title="' + _bcEscAttr(seg) + '">'
                          + '<i class="fas ' + iconClass + ' bc-icon"></i> '
                          + _bcEscHtml(seg) + '</span>';
                }

                bar.innerHTML = html;
                bar.classList.add('visible');

                // Auto-scroll to end
                bar.scrollLeft = bar.scrollWidth;
            } catch(e) {
                bar.classList.remove('visible');
                bar.innerHTML = '';
            }
        }

        function _bcEscHtml(s) {
            var d = document.createElement('div');
            d.textContent = s;
            return d.innerHTML;
        }
        function _bcEscAttr(s) {
            return s.replace(/'/g, "\\'").replace(/"/g, '&quot;');
        }

        // ── Bookmarks ──
        function iframeAddBookmark() {
            const url = document.getElementById('iframeUrlInput').value.trim();
            if (!url || url === 'about:blank') return;

            const idx = _iframeBookmarks.indexOf(url);
            if (idx !== -1) {
                _iframeBookmarks.splice(idx, 1);
            } else {
                _iframeBookmarks.push(url);
            }
            localStorage.setItem('iframeBookmarks', JSON.stringify(_iframeBookmarks));
            _iframeRenderBookmarks();
            _iframeUpdateBookmarkIcon();
        }

        function _iframeUpdateBookmarkIcon() {
            const url = document.getElementById('iframeUrlInput').value.trim();
            const icon = document.getElementById('iframeBookmarkIcon');
            const btn = icon ? icon.closest('.iframe-bookmark-btn') : null;
            if (!icon) return;
            const isBookmarked = _iframeBookmarks.includes(url);
            icon.className = isBookmarked ? 'fas fa-star' : 'far fa-star';
            if (btn) btn.classList.toggle('bookmarked', isBookmarked);
        }

        function _iframeRenderBookmarks() {
            const list = document.getElementById('iframeBookmarkList');
            if (!list) return;
            list.innerHTML = '';
            _iframeBookmarks.forEach((url, i) => {
                const chip = document.createElement('span');
                chip.className = 'iframe-bookmark-chip';
                const label = url.replace(/^https?:\/\//, '').split('/')[0];
                chip.innerHTML = `<span onclick="iframeLoadUrl('${url.replace(/'/g, "\\'")}')">${label}</span><span class="remove-bookmark" onclick="event.stopPropagation();_iframeRemoveBookmark(${i})">×</span>`;
                list.appendChild(chip);
            });
        }

        function _iframeRemoveBookmark(idx) {
            _iframeBookmarks.splice(idx, 1);
            localStorage.setItem('iframeBookmarks', JSON.stringify(_iframeBookmarks));
            _iframeRenderBookmarks();
            _iframeUpdateBookmarkIcon();
        }

        // Init bookmarks on load
        document.addEventListener('DOMContentLoaded', function() {
            _iframeRenderBookmarks();
        });

        // ── English Global Dictation ──
        function gdToggleEn() {
            if (_gdEnListening) { gdStopEn(); return; }
            gdStartEn();
        }

        function gdStartEn() {
            const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
            if (!SR) { showToast('Speech recognition not supported. Use Chrome or Edge.', 'error'); return; }

            // Stop other dictations
            if (_gdArListening) gdStopAr();
            if (_sttListening && typeof sttStop === 'function') sttStop();
            if (_sttArListening && typeof sttArStop === 'function') sttArStop();
            if (typeof _sttNotesListening !== 'undefined' && _sttNotesListening && typeof sttNotesStop === 'function') sttNotesStop();
            if (typeof _sttNotesArListening !== 'undefined' && _sttNotesArListening && typeof sttNotesArStop === 'function') sttNotesArStop();

            // Capture current focus target before button click changes it
            const target = _gdLastTarget;
            if (!target) {
                showToast('Click on a text field first, then dictate.', 'error');
                return;
            }

            _gdEnRecognition = new SR();
            _gdEnRecognition.lang = 'en-US';
            _gdEnRecognition.continuous = true;
            _gdEnRecognition.interimResults = true;
            _gdEnRecognition.maxAlternatives = 1;
            _gdEnFinalTranscript = '';
            _gdEnInsertedLength = 0;
            const insertRef = { len: 0 };

            _gdEnRecognition.onstart = () => {
                _gdEnListening = true;
                const btn = document.getElementById('gdBtnEn');
                const label = document.getElementById('gdLabelEn');
                if (btn) { btn.classList.add('listening'); btn.querySelector('i').className = 'fas fa-microphone-slash'; }
                if (label) label.textContent = 'Stop';
                showToast('🎤 Global Dictation – Speak now! (EN)', 'success');
            };

            _gdEnRecognition.onresult = (event) => {
                if (!_gdLastTarget) return;
                for (let i = event.resultIndex; i < event.results.length; i++) {
                    const transcript = event.results[i][0].transcript;
                    if (event.results[i].isFinal) {
                        let finalText = transcript.trim();
                        if (_gdEnFinalTranscript === '' || /[.!?]\s*$/.test(_gdEnFinalTranscript)) {
                            finalText = finalText.charAt(0).toUpperCase() + finalText.slice(1);
                        }
                        if (_gdEnFinalTranscript.length > 0 && !/\s$/.test(_gdEnFinalTranscript)) {
                            _gdEnFinalTranscript += ' ';
                        }
                        _gdEnFinalTranscript += finalText;
                        _gdInsertText(_gdLastTarget, finalText, insertRef);
                    }
                }
            };

            _gdEnRecognition.onerror = (event) => {
                if (event.error === 'no-speech') {
                    showToast('No speech detected. Try again.', 'error');
                } else if (event.error === 'audio-capture') {
                    showToast('No microphone found.', 'error');
                } else if (event.error === 'not-allowed') {
                    showToast('Microphone access denied.', 'error');
                } else if (event.error !== 'aborted') {
                    showToast('Speech error: ' + event.error, 'error');
                }
                gdResetEn();
            };

            _gdEnRecognition.onend = () => {
                if (_gdEnListening) {
                    try { _gdEnRecognition.start(); } catch (e) { gdResetEn(); }
                } else {
                    gdResetEn();
                }
            };

            try { _gdEnRecognition.start(); } catch (e) {
                showToast('Could not start recognition: ' + e.message, 'error');
                gdResetEn();
            }
        }

        function gdStopEn() {
            _gdEnListening = false;
            if (_gdEnRecognition) { try { _gdEnRecognition.stop(); } catch (e) {} }
            if (_gdEnFinalTranscript.trim()) {
                const wc = _gdEnFinalTranscript.trim().split(/\s+/).length;
                showToast('✅ Global dictation saved! (' + wc + ' words)', 'success');
            } else {
                showToast('Dictation stopped.', 'info');
            }
            _gdEnFinalTranscript = '';
            gdResetEn();
        }

        function gdResetEn() {
            _gdEnListening = false;
            const btn = document.getElementById('gdBtnEn');
            const label = document.getElementById('gdLabelEn');
            if (btn) { btn.classList.remove('listening'); btn.querySelector('i').className = 'fas fa-microphone'; }
            if (label) label.textContent = 'Dictate';
        }

        // ── Arabic Global Dictation ──
        function gdToggleAr() {
            if (_gdArListening) { gdStopAr(); return; }
            gdStartAr();
        }

        function gdStartAr() {
            const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
            if (!SR) { showToast('التعرّف على الكلام غير مدعوم. استخدم Chrome أو Edge.', 'error'); return; }

            // Stop other dictations
            if (_gdEnListening) gdStopEn();
            if (_sttListening && typeof sttStop === 'function') sttStop();
            if (_sttArListening && typeof sttArStop === 'function') sttArStop();
            if (typeof _sttNotesListening !== 'undefined' && _sttNotesListening && typeof sttNotesStop === 'function') sttNotesStop();
            if (typeof _sttNotesArListening !== 'undefined' && _sttNotesArListening && typeof sttNotesArStop === 'function') sttNotesArStop();

            const target = _gdLastTarget;
            if (!target) {
                showToast('اضغط على حقل نص أولاً ثم ابدأ الإملاء.', 'error');
                return;
            }

            _gdArRecognition = new SR();
            _gdArRecognition.lang = 'ar-SA';
            _gdArRecognition.continuous = true;
            _gdArRecognition.interimResults = true;
            _gdArRecognition.maxAlternatives = 1;
            _gdArFinalTranscript = '';
            _gdArInsertedLength = 0;
            const insertRef = { len: 0 };

            _gdArRecognition.onstart = () => {
                _gdArListening = true;
                const btn = document.getElementById('gdBtnAr');
                const label = document.getElementById('gdLabelAr');
                if (btn) { btn.classList.add('listening'); btn.querySelector('i').className = 'fas fa-microphone-slash'; }
                if (label) label.textContent = 'إيقاف';
                showToast('🎤 إملاء عام – تحدّث بالعربية الآن!', 'success');
            };

            _gdArRecognition.onresult = (event) => {
                if (!_gdLastTarget) return;
                for (let i = event.resultIndex; i < event.results.length; i++) {
                    const transcript = event.results[i][0].transcript;
                    if (event.results[i].isFinal) {
                        let finalText = transcript.trim();
                        if (_gdArFinalTranscript.length > 0 && !/\s$/.test(_gdArFinalTranscript)) {
                            _gdArFinalTranscript += ' ';
                        }
                        _gdArFinalTranscript += finalText;
                        _gdInsertText(_gdLastTarget, finalText, insertRef);
                    }
                }
            };

            _gdArRecognition.onerror = (event) => {
                if (event.error === 'no-speech') {
                    showToast('لم يتم اكتشاف كلام. حاول مرة أخرى.', 'error');
                } else if (event.error === 'audio-capture') {
                    showToast('لم يتم العثور على ميكروفون.', 'error');
                } else if (event.error === 'not-allowed') {
                    showToast('تم رفض الوصول للميكروفون.', 'error');
                } else if (event.error !== 'aborted') {
                    showToast('خطأ: ' + event.error, 'error');
                }
                gdResetAr();
            };

            _gdArRecognition.onend = () => {
                if (_gdArListening) {
                    try { _gdArRecognition.start(); } catch (e) { gdResetAr(); }
                } else {
                    gdResetAr();
                }
            };

            try { _gdArRecognition.start(); } catch (e) {
                showToast('تعذّر بدء التعرّف: ' + e.message, 'error');
                gdResetAr();
            }
        }

        function gdStopAr() {
            _gdArListening = false;
            if (_gdArRecognition) { try { _gdArRecognition.stop(); } catch (e) {} }
            if (_gdArFinalTranscript.trim()) {
                const wc = _gdArFinalTranscript.trim().split(/\s+/).length;
                showToast('✅ تم حفظ الإملاء! (' + wc + ' كلمة)', 'success');
            } else {
                showToast('تم إيقاف الإملاء.', 'info');
            }
            _gdArFinalTranscript = '';
            gdResetAr();
        }

        function gdResetAr() {
            _gdArListening = false;
            const btn = document.getElementById('gdBtnAr');
            const label = document.getElementById('gdLabelAr');
            if (btn) { btn.classList.remove('listening'); btn.querySelector('i').className = 'fas fa-microphone'; }
            if (label) label.textContent = 'إملاء';
        }
        // ── Keyboard Shortcuts: Shift+E (EN) / Shift+A (AR) ──
        document.addEventListener('keydown', (e) => {
            if (!e.shiftKey || e.ctrlKey || e.altKey || e.metaKey) return;

            const tag = (document.activeElement || {}).tagName;
            const isTyping = (tag === 'TEXTAREA' || tag === 'INPUT' || (document.activeElement && document.activeElement.isContentEditable));

            // If dictation is already active, allow stopping from anywhere
            if (e.key === 'E' || e.key === 'e') {
                if (_gdEnListening) { e.preventDefault(); gdStopEn(); return; }
                if (!isTyping) { e.preventDefault(); gdToggleEn(); return; }
            }
            if (e.key === 'A' || e.key === 'a') {
                if (_gdArListening) { e.preventDefault(); gdStopAr(); return; }
                if (!isTyping) { e.preventDefault(); gdToggleAr(); return; }
            }
        });
        // ═══════ End Global Dictation ═══════

        // ═══════ Copy / Paste / Clear – Prompt Editor ═══════
        function copyEditorText() {
            const ta = document.getElementById('promptEditor');
            const btn = document.getElementById('btnCopyEditor');
            const label = document.getElementById('copyEditorLabel');
            if (!ta || !ta.value.trim()) return;
            navigator.clipboard.writeText(ta.value).then(() => {
                if (btn) btn.classList.add('copied');
                if (label) label.textContent = 'Copied!';
                const icon = btn ? btn.querySelector('i') : null;
                if (icon) icon.className = 'fas fa-check';
                setTimeout(() => {
                    if (btn) btn.classList.remove('copied');
                    if (label) label.textContent = 'Copy';
                    if (icon) icon.className = 'fas fa-copy';
                }, 1800);
            }).catch(() => {
                ta.select(); document.execCommand('copy');
                if (label) label.textContent = 'Copied!';
                setTimeout(() => { if (label) label.textContent = 'Copy'; }, 1800);
            });
        }

        function pasteEditorText() {
            const ta = document.getElementById('promptEditor');
            const btn = document.getElementById('btnPasteEditor');
            const label = document.getElementById('pasteEditorLabel');
            if (!ta) return;
            navigator.clipboard.readText().then(text => {
                if (!text) return;
                const start = ta.selectionStart;
                const end = ta.selectionEnd;
                ta.value = ta.value.substring(0, start) + text + ta.value.substring(end);
                ta.selectionStart = ta.selectionEnd = start + text.length;
                ta.dispatchEvent(new Event('input', { bubbles: true }));
                ta.focus();
                if (btn) btn.classList.add('pasted');
                if (label) label.textContent = 'Pasted!';
                const icon = btn ? btn.querySelector('i') : null;
                if (icon) icon.className = 'fas fa-check';
                setTimeout(() => {
                    if (btn) btn.classList.remove('pasted');
                    if (label) label.textContent = 'Paste';
                    if (icon) icon.className = 'fas fa-paste';
                }, 1800);
            }).catch(() => { ta.focus(); document.execCommand('paste'); });
        }

        async function clearEditorText() {
            const ta = document.getElementById('promptEditor');
            const btn = document.getElementById('btnClearEditor');
            const label = document.getElementById('clearEditorLabel');
            if (!ta || !ta.value.trim()) return;
            ta.value = '';
            ta.dispatchEvent(new Event('input', { bubbles: true }));
            ta.focus();

            // Clear the server-side prompt.txt via AJAX
            let serverClearOk = false;
            try {
                const fd = new FormData();
                fd.append('action', 'clear_prompt_file');
                const resp = await fetch('', { method: 'POST', body: fd });
                const data = await resp.json();
                serverClearOk = !!data.success;
            } catch (err) {
                console.error('Error clearing server prompt.txt:', err);
            }

            // Also clear the local File System Access handle if connected
            if (promptFileHandle) {
                try {
                    const writable = await promptFileHandle.createWritable();
                    await writable.write('');
                    await writable.close();
                } catch (err) {
                    console.error('Error clearing local prompt.txt:', err);
                }
            }

            if (btn) btn.classList.add('cleared');
            const icon = btn ? btn.querySelector('i') : null;
            if (icon) icon.className = 'fas fa-check';

            if (serverClearOk) {
                if (label) label.textContent = 'Both Cleared!';
                showToast('🧹 Editor & prompt.txt cleared', 'success');
            } else {
                if (label) label.textContent = 'Editor Only';
                showToast('⚠️ Editor cleared but prompt.txt failed', 'warning');
            }

            setTimeout(() => {
                if (btn) btn.classList.remove('cleared');
                if (label) label.textContent = 'Clear';
                if (icon) icon.className = 'fas fa-eraser';
            }, 2200);
        }

        // ═══════ Copy – Project Prompts ═══════
        function copyNotesText() {
            const ta = document.getElementById('projectNotesTextarea');
            const btn = document.getElementById('btnCopyNotes');
            const label = document.getElementById('copyNotesLabel');
            if (!ta || !ta.value.trim()) return;
            navigator.clipboard.writeText(ta.value).then(() => {
                if (btn) btn.classList.add('copied');
                if (label) label.textContent = 'Copied!';
                const icon = btn ? btn.querySelector('i') : null;
                if (icon) { icon.className = 'fas fa-check'; }
                setTimeout(() => {
                    if (btn) btn.classList.remove('copied');
                    if (label) label.textContent = 'Copy';
                    if (icon) { icon.className = 'fas fa-copy'; }
                }, 1800);
            }).catch(() => {
                ta.select();
                document.execCommand('copy');
                if (label) label.textContent = 'Copied!';
                setTimeout(() => { if (label) label.textContent = 'Copy'; }, 1800);
            });
        }

        // ═══════ Paste – Project Prompts ═══════
        function pasteNotesText() {
            const ta = document.getElementById('projectNotesTextarea');
            const btn = document.getElementById('btnPasteNotes');
            const label = document.getElementById('pasteNotesLabel');
            if (!ta) return;
            navigator.clipboard.readText().then(text => {
                if (!text) return;
                const start = ta.selectionStart;
                const end = ta.selectionEnd;
                ta.value = ta.value.substring(0, start) + text + ta.value.substring(end);
                ta.selectionStart = ta.selectionEnd = start + text.length;
                ta.dispatchEvent(new Event('input', { bubbles: true }));
                ta.focus();
                if (btn) btn.classList.add('pasted');
                if (label) label.textContent = 'Pasted!';
                const icon = btn ? btn.querySelector('i') : null;
                if (icon) icon.className = 'fas fa-check';
                setTimeout(() => {
                    if (btn) btn.classList.remove('pasted');
                    if (label) label.textContent = 'Paste';
                    if (icon) icon.className = 'fas fa-paste';
                }, 1800);
            }).catch(() => {
                ta.focus();
                document.execCommand('paste');
            });
        }

