        // Confirm and rename the file
        async function confirmRenameFile() {
            if (!fileManagement.renameFolder || !fileManagement.renameSelectedFile) {
                showToast('❌ Please select a file to rename', 'error');
                return;
            }
            
            const newName = document.getElementById('renameNewName').value.trim();
            if (!newName) {
                showToast('❌ Please enter a new file name', 'error');
                return;
            }
            
            if (newName === fileManagement.renameSelectedFile) {
                showToast('❌ New name is the same as the old name', 'error');
                return;
            }
            
            try {
                // Check if new name exists
                try {
                    await fileManagement.renameFolder.getFileHandle(newName);
                    showToast('❌ A file with that name already exists', 'error');
                    return;
                } catch (e) {
                    // Good, doesn't exist
                }
                
                // Read old file
                const oldHandle = await fileManagement.renameFolder.getFileHandle(fileManagement.renameSelectedFile);
                const oldFile = await oldHandle.getFile();
                const content = await oldFile.text();
                
                // Create new file
                const newHandle = await fileManagement.renameFolder.getFileHandle(newName, { create: true });
                const writable = await newHandle.createWritable();
                await writable.write(content);
                await writable.close();
                
                // Delete old file
                await fileManagement.renameFolder.removeEntry(fileManagement.renameSelectedFile);
                
                closeModal('renameFileModal');
                showToast(`✅ Renamed: ${fileManagement.renameSelectedFile} → ${newName}`, 'success');
                
            } catch (err) {
                showToast('❌ Error renaming file: ' + err.message, 'error');
            }
        }
        
        // Open modal helper
        function openModal(modalId) {
            document.getElementById(modalId).classList.add('active');
        }
        
        // Initialize folder connection on page load
        document.addEventListener('DOMContentLoaded', () => {
            initFolderConnection();
            initSavedFileNames();
        });

        // Update character and word counts
        function updateCounts() {
            const text = document.getElementById('promptEditor').value;
            document.getElementById('charCount').textContent = text.length;
            document.getElementById('wordCount').textContent = text.trim() ? text.trim().split(/\s+/).length : 0;
        }

        // Setup event listeners
        function setupEventListeners() {
            // Editor input - update counts and record history
            document.getElementById('promptEditor').addEventListener('input', () => {
                updateCounts();
                recordHistoryDebounced(); // Record state after typing stops
            });
            
            // File upload - Drop Zone
            const dropZone = document.getElementById('dropZone');
            const fileInput = document.getElementById('fileInput');
            
            // Drop zone click - opens file picker
            dropZone.addEventListener('click', () => fileInput.click());
            
            dropZone.addEventListener('dragover', (e) => {
                e.preventDefault();
                dropZone.classList.add('dragover');
            });
            
            dropZone.addEventListener('dragleave', () => {
                dropZone.classList.remove('dragover');
            });
            
            dropZone.addEventListener('drop', (e) => {
                e.preventDefault();
                e.stopPropagation();
                dropZone.classList.remove('dragover');
                console.log('📁 Files dropped:', e.dataTransfer.files.length);
                if (e.dataTransfer.files.length > 0) {
                    handleFiles(e.dataTransfer.files);
                }
            });
            
            // Single/Multiple file input
            fileInput.addEventListener('change', (e) => {
                console.log('📁 Files selected via file picker:', e.target.files.length);
                if (e.target.files.length > 0) {
                    handleFiles(e.target.files);
                    fileInput.value = ''; // Reset for next selection
                }
            });

            // Folder Picker - Drop Zone (opens PHP-powered folder browser)
            const folderDropZone = document.getElementById('folderDropZone');
            
            // Folder zone click is handled via inline onclick on the HTML element
            // (more reliable — doesn't depend on setupEventListeners() completing)
            
            // Also support drag & drop of folders onto the zone
            folderDropZone.addEventListener('dragover', (e) => {
                e.preventDefault();
                folderDropZone.classList.add('dragover');
            });
            
            folderDropZone.addEventListener('dragleave', () => {
                folderDropZone.classList.remove('dragover');
            });
            
            folderDropZone.addEventListener('drop', (e) => {
                e.preventDefault();
                e.stopPropagation();
                folderDropZone.classList.remove('dragover');
                
                // Extract folder names from dropped items
                const items = e.dataTransfer.items;
                if (items) {
                    const folderNames = new Set();
                    for (let i = 0; i < items.length; i++) {
                        const entry = items[i].webkitGetAsEntry ? items[i].webkitGetAsEntry() : null;
                        if (entry && entry.isDirectory) {
                            folderNames.add(entry.name);
                        }
                    }
                    if (folderNames.size > 0) {
                        handleFolders(Array.from(folderNames));
                    } else {
                        showToast('⚠️ No folders detected. Please drop folders, not files.', 'warning');
                    }
                }
            });

            // Search saved prompts
            document.getElementById('searchPrompts').addEventListener('input', (e) => {
                const searchTerm = e.target.value;
                const clearBtn = document.getElementById('savedSearchClear');
                
                // Show/hide clear button
                if (clearBtn) {
                    clearBtn.style.display = searchTerm ? 'flex' : 'none';
                }
                
                // Re-render with filter (if prompts already loaded)
                if (savedPromptsList.length > 0) {
                    renderSavedPrompts(searchTerm);
                } else {
                    loadSavedPrompts(searchTerm);
                }
            });
        }

        // Track files added to editor
        let editorFiles = new Map(); // filename -> {id, content, marker, isReference}
        
        // Track folders added (name only, no upload)
        let editorFolders = new Map(); // foldername -> {marker, addedAt} — folders active in editor
        let knownFolders = new Map(); // foldername -> {addedAt} — all folders in display list (persists)
        
        // Client-side folder caches (for user's local PC browsing via File System Access API)
        // Exposed on window so Folder Browser IIFE (separate script block) can populate them
        if (!window.clientTreeCache) window.clientTreeCache = new Map();
        if (!window.clientHandleCache) window.clientHandleCache = new Map();
        const clientTreeCache = window.clientTreeCache; // folderName → treeData (built client-side)
        const clientHandleCache = window.clientHandleCache; // folderName → FileSystemDirectoryHandle (for refresh)
        
        // Current file mode: 'content' or 'reference'
        let currentFileMode = 'reference';

        // Check if we should send full content or just reference
        function shouldSendFullContent() {
            return currentFileMode === 'content';
        }
        
        // ════════════════════════════════════════════════════════════════
        // PANEL COLLAPSE/EXPAND FUNCTIONALITY
        // ════════════════════════════════════════════════════════════════
        
        const LEFT_PANEL_COLLAPSED_KEY = 'leftPanelCollapsed';
        const RIGHT_PANEL_COLLAPSED_KEY = 'rightPanelCollapsed';
        
        // Toggle Left Panel (Sidebar)
        function toggleLeftPanel() {
            const sidebar = document.getElementById('mainSidebar');
            const btn = document.getElementById('leftCollapseBtn');
            const mainContent = document.querySelector('.main-content');
            const tooltip = btn.querySelector('.collapse-tooltip');
            
            if (!sidebar || !btn) return;
            
            const isCollapsed = sidebar.classList.toggle('collapsed');
            btn.classList.toggle('panel-hidden', isCollapsed);
            
            // Update tooltip text
            if (tooltip) {
                tooltip.textContent = isCollapsed ? 'Show Sidebar' : 'Hide Sidebar';
            }
            
            // Update button position
            btn.style.left = isCollapsed ? '0' : '320px';
            
            // Save state to localStorage
            localStorage.setItem(LEFT_PANEL_COLLAPSED_KEY, isCollapsed ? 'true' : 'false');
            
            console.log('📌 Left Panel ' + (isCollapsed ? 'collapsed' : 'expanded'));
        }
        
        // Toggle Right Panel (Design Enhancer)
        function toggleRightPanel() {
            const rightPanel = document.querySelector('.right-panel');
            const btn = document.getElementById('rightCollapseBtn');
            const mainContent = document.querySelector('.main-content');
            const tooltip = btn.querySelector('.collapse-tooltip');
            
            if (!rightPanel || !btn) return;
            
            const isCollapsed = rightPanel.classList.toggle('collapsed');
            btn.classList.toggle('panel-hidden', isCollapsed);
            mainContent.classList.toggle('right-collapsed', isCollapsed);
            
            // Update tooltip text
            if (tooltip) {
                tooltip.textContent = isCollapsed ? 'Show Design Panel' : 'Hide Design Panel';
            }
            
            // Update button position
            btn.style.right = isCollapsed ? '0' : '400px';
            
            // Save state to localStorage
            localStorage.setItem(RIGHT_PANEL_COLLAPSED_KEY, isCollapsed ? 'true' : 'false');
            
            console.log('🎨 Right Panel ' + (isCollapsed ? 'collapsed' : 'expanded'));
        }
        
        // Legacy function for backward compatibility
        function toggleSidebar() {
            toggleLeftPanel();
        }
        
        // Load panel states on page load
        function loadPanelStates() {
            const sidebar = document.getElementById('mainSidebar');
            const rightPanel = document.querySelector('.right-panel');
            const leftBtn = document.getElementById('leftCollapseBtn');
            const rightBtn = document.getElementById('rightCollapseBtn');
            const mainContent = document.querySelector('.main-content');
            
            // Load left panel state
            if (sidebar && leftBtn) {
                const leftCollapsed = localStorage.getItem(LEFT_PANEL_COLLAPSED_KEY) === 'true';
                if (leftCollapsed) {
                    sidebar.classList.add('collapsed');
                    leftBtn.classList.add('panel-hidden');
                    leftBtn.style.left = '0';
                    const tooltip = leftBtn.querySelector('.collapse-tooltip');
                    if (tooltip) tooltip.textContent = 'Show Sidebar';
                }
            }
            
            // Load right panel state
            if (rightPanel && rightBtn && mainContent) {
                const rightCollapsed = localStorage.getItem(RIGHT_PANEL_COLLAPSED_KEY) === 'true';
                if (rightCollapsed) {
                    rightPanel.classList.add('collapsed');
                    rightBtn.classList.add('panel-hidden');
                    rightBtn.style.right = '0';
                    mainContent.classList.add('right-collapsed');
                    const tooltip = rightBtn.querySelector('.collapse-tooltip');
                    if (tooltip) tooltip.textContent = 'Show Design Panel';
                }
            }
        }
        
        // Initialize panel states
        document.addEventListener('DOMContentLoaded', loadPanelStates);
        
        // Set file mode (called by toggle buttons)
        function setFileMode(mode) {
            currentFileMode = mode;
            document.getElementById('fileContentToggle').value = mode;
            
            // Update button states
            const btnContent = document.getElementById('btnFullContent');
            const btnReference = document.getElementById('btnReference');
            
            if (mode === 'content') {
                btnContent.classList.add('active');
                btnReference.classList.remove('active');
                showToast('📄 Mode: Full Content - Files will be added with full content', 'info');
            } else {
                btnContent.classList.remove('active');
                btnReference.classList.add('active');
                showToast('🔗 Mode: Reference Only - Files will be added as references', 'info');
            }
            
            console.log('📁 File mode changed to:', mode);
        }
        
        // Handle file upload - IMMEDIATELY reads and appends to editor
        async function handleFiles(files) {
            console.log('📂 handleFiles called with', files.length, 'files');
            
            if (!files || files.length === 0) {
                console.log('No files to process');
                return;
            }
            
            const editor = document.getElementById('promptEditor');
            const dropZone = document.getElementById('dropZone');
            let filesProcessed = 0;
            
            // Show processing state
            dropZone.innerHTML = '<i class="fas fa-spinner fa-spin"></i><p>Processing files...</p>';
            
            // Process each file immediately
            for (const file of Array.from(files)) {
                console.log('📄 Processing file:', file.name, 'Type:', file.type, 'Size:', file.size);
                
                try {
                    const sendFullContent = shouldSendFullContent();
                    let content = '';
                    let isReference = false;
                    
                    if (sendFullContent) {
                        // Read file content immediately
                        content = await readFileAsText(file);
                        console.log('✅ File read successfully, content length:', content.length);
                    } else {
                        // Just create a reference - simple format
                        content = `[📎 ${file.name}]`;
                        isReference = true;
                        console.log('✅ File reference created:', file.name);
                    }
                    
                    // Create simple marker without timestamp
                    const marker = `<!-- FILE:${file.name} -->`;
                    
                    // Append to editor with spacing
                    let textToAdd = '';
                    if (editor.value.trim()) {
                        textToAdd = '\n\n';
                    }
                    
                    if (isReference) {
                        textToAdd += `${marker}\n${content}\n${marker.replace('<!--', '<!-- /END ')}`;
                    } else {
                        textToAdd += `${marker}\n## 📄 ${file.name}\n${content}\n${marker.replace('<!--', '<!-- /END ')}`;
                    }
                    
                    editor.value += textToAdd;
                    
                    // Track this file
                    editorFiles.set(file.name, {
                        marker: marker,
                        content: content,
                        isReference: isReference,
                        addedAt: Date.now()
                    });
                    
                    filesProcessed++;
                    
                } catch (err) {
                    console.error('❌ Error reading file:', file.name, err);
                    showToast(`Error reading ${file.name}`, 'error');
                }
            }
            
            // Restore drop zone
            dropZone.innerHTML = '<i class="fas fa-cloud-arrow-up"></i><span>Drop files here</span>';
            
            if (filesProcessed > 0) {
                updateCounts();
                recordHistoryState(true); // Record file upload in history
                const modeText = shouldSendFullContent() ? 'with full content' : 'as references';
                showToast(`✅ ${filesProcessed} file(s) added ${modeText}!`, 'success');
                
                // Save to server in background
                saveFilesToServer(files);
            } else {
                showToast('No files were processed', 'error');
            }
            
            // Reset file input so same file can be selected again
            document.getElementById('fileInput').value = '';
        }
        
        // Read file as text - simple and direct
        function readFileAsText(file) {
            return new Promise((resolve, reject) => {
                const reader = new FileReader();
                
                reader.onload = function(e) {
                    console.log('FileReader onload triggered');
                    resolve(e.target.result);
                };
                
                reader.onerror = function(e) {
                    console.error('FileReader error:', e);
                    reject(new Error('Failed to read file'));
                };
                
                // Always try to read as text first
                console.log('Starting to read file as text...');
                reader.readAsText(file);
            });
        }
        
        // Save files to server (background)
        async function saveFilesToServer(files) {
            const formData = new FormData();
            formData.append('action', 'upload_files');
            
            for (const file of Array.from(files)) {
                formData.append('files[]', file);
            }
            
            try {
                const response = await fetch('', {
                    method: 'POST',
                    body: formData
                });
                
                const data = await response.json();
                if (data.success) {
                    loadUploadedFiles();
                }
            } catch (err) {
                console.error('Server upload error:', err);
            }
        }
        
        // Remove file content from editor
        function removeFileFromEditor(filename) {
            const editor = document.getElementById('promptEditor');
            const fileData = editorFiles.get(filename);
            
            if (fileData) {
                // Remove the file section from editor
                const startMarker = fileData.marker;
                const endMarker = startMarker.replace('<!--', '<!-- /END ');
                
                const startIdx = editor.value.indexOf(startMarker);
                if (startIdx !== -1) {
                    const endIdx = editor.value.indexOf(endMarker);
                    if (endIdx !== -1) {
                        // Remove from start marker to end marker (including markers)
                        const before = editor.value.substring(0, startIdx);
                        const after = editor.value.substring(endIdx + endMarker.length);
                        editor.value = (before + after).replace(/\n{3,}/g, '\n\n').trim();
                    }
                }
                
                editorFiles.delete(filename);
                updateCounts();
                showToast(`📄 ${filename} removed from editor`, 'info');
            }
        }

        // ============================================
        // FOLDER HANDLING (Name/Label only, no upload)
        // ============================================
        
        // Handle folder selection — accepts array of {name, path} objects or plain strings (drag & drop)
        async function handleFolders(folderInfos) {
            console.log('📂 handleFolders called with', folderInfos.length, 'folders');
            
            if (!folderInfos || folderInfos.length === 0) {
                console.log('No folders to process');
                return;
            }
            
            const folderDropZone = document.getElementById('folderDropZone');
            let foldersProcessed = 0;
            
            // Show processing state
            folderDropZone.innerHTML = '<i class="fas fa-spinner fa-spin"></i><span>Processing folders...</span>';
            
            for (const info of folderInfos) {
                // Support both {name, path} objects and plain strings (backward compat for drag & drop)
                const folderName = typeof info === 'string' ? info : info.name;
                const folderPath = typeof info === 'string' ? '' : (info.path || '');
                
                // Skip if already known (already in the display list)
                if (knownFolders.has(folderName)) {
                    showToast(`📁 ${folderName} is already in the list`, 'info');
                    continue;
                }
                
                const marker = `<!-- FOLDER:${folderName} -->`;
                
                // Register in knownFolders (persists in display list) — store path for tree generation
                knownFolders.set(folderName, {
                    addedAt: Date.now(),
                    path: folderPath
                });
                
                // Also add to editor (checked by default) — async: will fetch tree if path available
                await addFolderToEditor(folderName, marker, folderPath);
                
                foldersProcessed++;
            }
            
            // Restore folder drop zone
            folderDropZone.innerHTML = '<i class="fas fa-folder-plus"></i><span>Pick folders here</span>';
            
            if (foldersProcessed > 0) {
                updateCounts();
                recordHistoryState(true);
                showToast(`✅ ${foldersProcessed} folder(s) added with directory tree!`, 'success');
                
                // Re-render the file list to include folders
                loadUploadedFiles();
            }
        }
        
        // Build directory tree client-side from FileSystemDirectoryHandle (user's local PC)
        // Also exposed on window for Folder Browser IIFE access
        window.buildClientSideTree = buildClientSideTree;
        async function buildClientSideTree(dirHandle, depth = 0, maxDepth = 0) {
            if (maxDepth > 0 && depth >= maxDepth) return [];
            
            const tree = [];
            const dirs = [];
            const files = [];
            const skipDirs = new Set(['.git', 'node_modules', 'vendor', '__pycache__', '.next', '.nuxt', 'dist', 'build', '.svn', '.idea', '.vscode']);
            
            try {
                for await (const entry of dirHandle.values()) {
                    // Skip hidden files/folders (except .env, .htaccess)
                    if (entry.name.startsWith('.') && entry.name !== '.env' && entry.name !== '.htaccess') continue;
                    if (entry.kind === 'directory' && skipDirs.has(entry.name)) continue;
                    
                    if (entry.kind === 'directory') {
                        dirs.push(entry);
                    } else {
                        files.push(entry);
                    }
                }
            } catch (e) {
                console.warn('Cannot read directory:', e.message);
                return tree;
            }
            
            // Sort alphabetically
            dirs.sort((a, b) => a.name.localeCompare(b.name, undefined, { sensitivity: 'base' }));
            files.sort((a, b) => a.name.localeCompare(b.name, undefined, { sensitivity: 'base' }));
            
            // Add directories first (with their children)
            for (const dir of dirs) {
                const children = await buildClientSideTree(dir, depth + 1, maxDepth);
                tree.push({
                    name: dir.name,
                    type: 'folder',
                    children: children
                });
            }
            
            // Then add files
            for (const file of files) {
                tree.push({
                    name: file.name,
                    type: 'file'
                });
            }
            
            return tree;
        }
        
        // Fetch folder tree from PHP server (fallback for localhost)
        async function fetchFolderTree(folderPath) {
            if (!folderPath) return null;
            
            try {
                const formData = new FormData();
                formData.append('action', 'get_folder_tree');
                formData.append('path', folderPath);
                formData.append('max_depth', '0'); // 0 = unlimited depth — traverse all levels
                
                const response = await fetch('', {
                    method: 'POST',
                    body: formData
                });
                
                const data = await response.json();
                return data.success ? data.tree : null;
            } catch (err) {
                console.error('Error fetching folder tree:', err);
                return null;
            }
        }
        
        // Build a beautiful ASCII tree diagram from the tree data
        function buildTreeDiagram(folderName, treeData) {
            const isDb = folderName.startsWith('🗄️ DB: ');
            if (!treeData || treeData.length === 0) {
                return isDb
                    ? `🗄️ ${folderName}\n    (no tables)`
                    : `📁 ${folderName}/\n    (empty folder)`;
            }
            
            let lines = [isDb ? `🗄️ ${folderName}` : `📁 ${folderName}/`];
            
            function renderNode(items, prefix) {
                for (let i = 0; i < items.length; i++) {
                    const item = items[i];
                    const isLast = (i === items.length - 1);
                    const connector = isLast ? '└── ' : '├── ';
                    const childPrefix = isLast ? '    ' : '│   ';
                    
                    if (item.type === 'folder') {
                        lines.push(prefix + connector + (isDb ? '📊 ' : '📂 ') + item.name + (isDb ? '' : '/'));
                        if (item.children && Array.isArray(item.children) && item.children.length > 0) {
                            renderNode(item.children, prefix + childPrefix);
                        }
                    } else {
                        let icon;
                        if (isDb) {
                            icon = '🔤';
                        } else {
                            // File — pick icon based on extension
                            const ext = item.name.split('.').pop().toLowerCase();
                            icon = '📄';
                            if (['jpg','jpeg','png','gif','svg','webp','ico'].includes(ext)) icon = '🖼️';
                            else if (['js','ts','jsx','tsx'].includes(ext)) icon = '📜';
                            else if (['php'].includes(ext)) icon = '🐘';
                            else if (['css','scss','sass','less'].includes(ext)) icon = '🎨';
                            else if (['html','htm'].includes(ext)) icon = '🌐';
                            else if (['json','xml','yaml','yml'].includes(ext)) icon = '📋';
                            else if (['md','txt','log'].includes(ext)) icon = '📝';
                            else if (['py'].includes(ext)) icon = '🐍';
                            else if (['sql','db','sqlite'].includes(ext)) icon = '🗃️';
                            else if (['zip','rar','tar','gz'].includes(ext)) icon = '📦';
                            else if (['env','gitignore','htaccess'].includes(ext) || item.name.startsWith('.')) icon = '⚙️';
                        }
                        
                        lines.push(prefix + connector + icon + ' ' + item.name);
                    }
                }
            }
            
            renderNode(treeData, '');
            return lines.join('\n');
        }
        
        // ============================================
        // FOLDER TREE TEMPLATE — Visual display in Development Dashboard
        // ============================================
        const ftFolderStore = new Map(); // folderName → { path, treeText, treeData, addedAt }
        const ftIdToName = new Map(); // safeId → folderName (reverse lookup)

        function ftUpdateContainer() {
            const container = document.getElementById('folderTemplateContainer');
            const badge = document.getElementById('ftFolderCount');
            const count = ftFolderStore.size;
            badge.textContent = count;
            if (count > 0) {
                container.classList.add('has-folders');
            } else {
                container.classList.remove('has-folders');
            }
        }

        function ftCountTreeStats(treeText) {
            let folders = 0, files = 0;
            const lines = treeText.split('\n');
            for (const line of lines) {
                if (line.includes('📂') || (line.includes('📁') && line.endsWith('/'))) folders++;
                else if (line.match(/[📄🖼️📜🐘🎨🌐📋📝🐍🗃️📦⚙️]/)) files++;
            }
            return { folders, files };
        }

        function ftEscapeAttr(str) {
            return str.replace(/&/g,'&amp;').replace(/'/g,'&#39;').replace(/"/g,'&quot;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
        }
        function ftEscapeHtml(str) {
            return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
        }

        function ftGetSafeId(folderName) {
            return folderName.replace(/[^a-zA-Z0-9_-]/g, '_');
        }

        // ─── Interactive Tree Node System ───
        let ftNodeIdCounter = 0;
        const ftNodeMap = new Map();
        const ftTreeRoots = new Map();

        function ftNextNodeId() { return 'ftn_' + (++ftNodeIdCounter); }

        function ftBuildNodeMap(items, sid, parentId) {
            const ids = [];
            if (!items || !Array.isArray(items)) return ids;
            for (const item of items) {
                const nid = ftNextNodeId();
                const node = {
                    id: nid, name: item.name || '', type: item.type || 'file',
                    description: item.description || '', parentId: parentId, sid: sid, childIds: []
                };
                if (node.type === 'folder' && item.children) {
                    node.childIds = ftBuildNodeMap(item.children, sid, nid);
                }
                ftNodeMap.set(nid, node);
                ids.push(nid);
            }
            return ids;
        }

        function ftClearNodeMapForSid(sid) {
            const rootIds = ftTreeRoots.get(sid);
            if (!rootIds) return;
            function removeR(nid) {
                const n = ftNodeMap.get(nid);
                if (!n) return;
                if (n.childIds) n.childIds.forEach(c => removeR(c));
                ftNodeMap.delete(nid);
            }
            rootIds.forEach(nid => removeR(nid));
            ftTreeRoots.delete(sid);
        }

        function ftCountTreeStatsFromData(items) {
            let folders = 0, files = 0;
            function count(arr) {
                if (!arr) return;
                for (const it of arr) {
                    if (it.type === 'folder') { folders++; if (it.children) count(it.children); }
                    else files++;
                }
            }
            count(items);
            return { folders, files };
        }

        function ftIsDbTreeNode(sid) {
            const folderName = ftIdToName.get(sid);
            return folderName && folderName.startsWith('🗄️ DB: ');
        }

        function ftGetNodeIcon(name, type, sid) {
            if (sid && ftIsDbTreeNode(sid)) {
                if (type === 'folder') return 'fas fa-table';
                return 'fas fa-columns';
            }
            if (type === 'folder') return 'fas fa-folder';
            const ext = (name.split('.').pop() || '').toLowerCase();
            const m = {
                html:'fab fa-html5', htm:'fab fa-html5', css:'fab fa-css3-alt', scss:'fab fa-css3-alt',
                js:'fab fa-js-square', ts:'fab fa-js-square', jsx:'fab fa-react', tsx:'fab fa-react',
                vue:'fab fa-vuejs', php:'fab fa-php', py:'fab fa-python',
                json:'fas fa-cog', xml:'fas fa-code', md:'fab fa-markdown', txt:'fas fa-file-alt',
                png:'fas fa-image', jpg:'fas fa-image', jpeg:'fas fa-image', gif:'fas fa-image',
                svg:'fas fa-bezier-curve', webp:'fas fa-image', ico:'fas fa-image',
                pdf:'fas fa-file-pdf', zip:'fas fa-file-archive', rar:'fas fa-file-archive',
                sql:'fas fa-database', env:'fas fa-key', sh:'fas fa-terminal',
                yml:'fas fa-cog', yaml:'fas fa-cog'
            };
            return m[ext] || 'fas fa-file';
        }

        function ftGetNodeIconColor(name, type, sid) {
            if (sid && ftIsDbTreeNode(sid)) {
                if (type === 'folder') return '#06b6d4';
                return '#a78bfa';
            }
            if (type === 'folder') return '#fbbf24';
            const ext = (name.split('.').pop() || '').toLowerCase();
            const m = {
                html:'#e44d26', htm:'#e44d26', css:'#264de4', scss:'#264de4',
                js:'#f7df1e', ts:'#3178c6', jsx:'#61dafb', tsx:'#61dafb',
                vue:'#42b883', php:'#777bb3', py:'#3776ab',
                json:'#fbbf24', xml:'#f97316', md:'#cbd5e1', txt:'#9ca3af',
                png:'#10b981', jpg:'#10b981', jpeg:'#10b981', gif:'#10b981',
                svg:'#ff6b9d', webp:'#10b981', ico:'#10b981',
                pdf:'#ef4444', zip:'#a855f7', rar:'#a855f7',
                sql:'#06b6d4', env:'#fbbf24', sh:'#22c55e',
                yml:'#f97316', yaml:'#f97316'
            };
            return m[ext] || '#6b7280';
        }

        function ftRenderNode(nid) {
            const node = ftNodeMap.get(nid);
            if (!node) return '';
            const isFolder = node.type === 'folder';
            const isDbTree = ftIsDbTreeNode(node.sid);
            const iconCls = ftGetNodeIcon(node.name, node.type, node.sid);
            const iconColor = ftGetNodeIconColor(node.name, node.type, node.sid);
            const iconType = isFolder ? 'folder' : 'file';

            const toggleHtml = isFolder
                ? `<button class="ft-inode-toggle" id="ftToggle_${nid}" onclick="event.stopPropagation();ftNodeToggle('${nid}')" title="Collapse/Expand"><i class="fas fa-chevron-down"></i></button>`
                : `<div class="ft-inode-toggle-spacer"></div>`;

            const escapedName = ftEscapeHtml(node.name);
            const escapedDesc = ftEscapeHtml(node.description || '');
            const hasDesc = (node.description || '').trim().length > 0;

            let acts = '<div class="ft-inode-actions">';
            if (isFolder) {
                if (isDbTree) {
                    acts += `<button onclick="event.stopPropagation();ftAddChild('${nid}','folder')" title="Add subtable"><i class="fas fa-table"></i></button>`;
                    acts += `<button onclick="event.stopPropagation();ftAddChild('${nid}','file')" title="Add field"><i class="fas fa-columns"></i></button>`;
                } else {
                    acts += `<button onclick="event.stopPropagation();ftAddChild('${nid}','folder')" title="Add subfolder"><i class="fas fa-folder-plus"></i></button>`;
                    acts += `<button onclick="event.stopPropagation();ftAddChild('${nid}','file')" title="Add file"><i class="fas fa-plus"></i></button>`;
                }
            }
            acts += `<button class="ft-del" onclick="event.stopPropagation();ftDeleteNode('${nid}')" title="Remove"><i class="fas fa-trash-alt"></i></button>`;
            acts += '</div>';

            let childrenHtml = '';
            if (isFolder) {
                childrenHtml = `<div class="ft-inode-children" id="ftChildren_${nid}">`;
                for (const cid of node.childIds) childrenHtml += ftRenderNode(cid);
                childrenHtml += '</div>';
            }

            return `<div class="ft-inode" id="ftNode_${nid}" data-nid="${nid}" draggable="true"
                        ondragstart="ftDragStart(event,'${nid}')"
                        ondragend="ftDragEnd(event,'${nid}')">
                <div class="ft-inode-row" id="ftRow_${nid}"
                     ondragover="ftDragOver(event,'${nid}')"
                     ondragleave="ftDragLeave(event,'${nid}')"
                     ondrop="ftDrop(event,'${nid}')">
                    <div class="ft-inode-grip" title="Drag to reorder"><i class="fas fa-grip-vertical"></i></div>
                    ${toggleHtml}
                    <div class="ft-inode-icon ${iconType}" style="color:${iconColor}"><i class="${iconCls}"></i></div>
                    <div class="ft-inode-body">
                        <input type="text" class="ft-inode-title" value="${escapedName}" spellcheck="false"
                               data-nid="${nid}" data-field="title"
                               oninput="ftNodeTitleChanged('${nid}',this)"
                               onfocus="ftNodeFocus('${nid}')" onblur="ftNodeBlur('${nid}')">
                        <div class="ft-inode-desc-wrap${hasDesc ? ' has-content' : ''}" id="ftDescWrap_${nid}">
                            <textarea class="ft-inode-desc" rows="1" spellcheck="false" placeholder="Add description..."
                                      data-nid="${nid}" data-field="desc"
                                      oninput="ftAutoResize(this);ftNodeDescChanged('${nid}',this)"
                                      onfocus="ftNodeFocus('${nid}')" onblur="ftNodeBlur('${nid}')">${escapedDesc}</textarea>
                        </div>
                    </div>
                    ${acts}
                </div>
                ${childrenHtml}
            </div>`;
        }

        function ftRenderInteractiveTree(sid) {
            const rootIds = ftTreeRoots.get(sid);
            if (!rootIds || rootIds.length === 0) {
                return '<div class="ft-itree"><div style="padding:10px;color:var(--text-muted);font-size:0.8rem;text-align:center;">Empty tree</div></div>';
            }
            const isDb = ftIsDbTreeNode(sid);
            let html = `<div class="ft-itree-toolbar">
                <button onclick="ftExpandAllNodes('${sid}')" title="Expand all"><i class="fas fa-expand-alt"></i> Expand</button>
                <button onclick="ftCollapseAllNodes('${sid}')" title="Collapse all"><i class="fas fa-compress-alt"></i> Collapse</button>
                <button onclick="ftAddRootChild('${sid}','folder')" title="${isDb ? 'Add root table' : 'Add root folder'}"><i class="fas ${isDb ? 'fa-table' : 'fa-folder-plus'}"></i></button>
                <button onclick="ftAddRootChild('${sid}','file')" title="${isDb ? 'Add root field' : 'Add root file'}"><i class="fas ${isDb ? 'fa-columns' : 'fa-plus'}"></i></button>
            </div>`;
            html += '<div class="ft-itree" id="ftITree_' + sid + '">';
            for (const nid of rootIds) html += ftRenderNode(nid);
            html += '</div>';
            return html;
        }

        function ftNodeToggle(nid) {
            const toggle = document.getElementById('ftToggle_' + nid);
            const children = document.getElementById('ftChildren_' + nid);
            if (!toggle || !children) return;
            toggle.classList.toggle('collapsed');
            children.classList.toggle('collapsed');
        }

        function ftAutoResize(el) {
            el.style.height = 'auto';
            el.style.height = Math.min(el.scrollHeight, 200) + 'px';
        }

        function ftInitAutoResize(sid) {
            const card = document.getElementById('ftCard_' + sid);
            if (!card) return;
            card.querySelectorAll('.ft-inode-desc').forEach(ta => ftAutoResize(ta));
        }

        function ftMarkDirty(nid) {
            const node = ftNodeMap.get(nid);
            if (!node) return;
            const folderName = ftIdToName.get(node.sid);
            if (folderName) { const d = ftFolderStore.get(folderName); if (d) d._dirty = true; }
        }

        function ftNodeTitleChanged(nid, el) {
            const node = ftNodeMap.get(nid);
            if (!node) return;
            node.name = el.value;
            ftMarkDirty(nid);
        }

        function ftNodeDescChanged(nid, el) {
            const node = ftNodeMap.get(nid);
            if (!node) return;
            node.description = el.value;
            const wrap = document.getElementById('ftDescWrap_' + nid);
            if (wrap) {
                if (el.value.trim()) wrap.classList.add('has-content');
                else wrap.classList.remove('has-content');
            }
            ftMarkDirty(nid);
        }

        function ftNodeFocus(nid) {
            const wrap = document.getElementById('ftDescWrap_' + nid);
            if (wrap) wrap.classList.add('expanded');
            const desc = wrap ? wrap.querySelector('.ft-inode-desc') : null;
            if (desc) setTimeout(() => ftAutoResize(desc), 50);
        }

        function ftNodeBlur(nid) {
            setTimeout(() => {
                const nodeEl = document.getElementById('ftNode_' + nid);
                if (!nodeEl) return;
                const active = document.activeElement;
                if (nodeEl.contains(active)) return;
                const wrap = document.getElementById('ftDescWrap_' + nid);
                if (wrap && !wrap.classList.contains('has-content')) {
                    wrap.classList.remove('expanded');
                }
            }, 150);
        }

        // ─── Drag-and-Drop State ───
        let ftDragNid = null;
        let ftDropMode = null; // 'before' | 'after' | 'inside'

        function ftDragStart(e, nid) {
            ftDragNid = nid;
            const nodeEl = document.getElementById('ftNode_' + nid);
            if (nodeEl) nodeEl.classList.add('ft-dragging');
            e.dataTransfer.effectAllowed = 'move';
            e.dataTransfer.setData('text/plain', nid);
            // Prevent parent .ft-inode from also firing dragstart
            e.stopPropagation();
        }

        function ftDragEnd(e, nid) {
            ftDragNid = null;
            ftDropMode = null;
            const nodeEl = document.getElementById('ftNode_' + nid);
            if (nodeEl) nodeEl.classList.remove('ft-dragging');
            // Clean all drop indicators
            document.querySelectorAll('.ft-drop-before,.ft-drop-after,.ft-drop-inside').forEach(el => {
                el.classList.remove('ft-drop-before', 'ft-drop-after', 'ft-drop-inside');
            });
            e.stopPropagation();
        }

        function ftDragOver(e, targetNid) {
            e.preventDefault();
            e.stopPropagation();
            if (!ftDragNid || ftDragNid === targetNid) return;

            // Don't allow dropping onto own descendants
            if (ftIsDescendant(targetNid, ftDragNid)) return;

            const row = document.getElementById('ftRow_' + targetNid);
            if (!row) return;
            const rect = row.getBoundingClientRect();
            const y = e.clientY - rect.top;
            const h = rect.height;
            const targetNode = ftNodeMap.get(targetNid);

            // Clear previous indicators on this row
            row.classList.remove('ft-drop-before', 'ft-drop-after', 'ft-drop-inside');

            if (targetNode && targetNode.type === 'folder') {
                // Folder: top 25% = before, middle 50% = inside, bottom 25% = after
                if (y < h * 0.25) {
                    row.classList.add('ft-drop-before');
                    ftDropMode = 'before';
                } else if (y > h * 0.75) {
                    row.classList.add('ft-drop-after');
                    ftDropMode = 'after';
                } else {
                    row.classList.add('ft-drop-inside');
                    ftDropMode = 'inside';
                }
            } else {
                // File: top half = before, bottom half = after
                if (y < h * 0.5) {
                    row.classList.add('ft-drop-before');
                    ftDropMode = 'before';
                } else {
                    row.classList.add('ft-drop-after');
                    ftDropMode = 'after';
                }
            }
            e.dataTransfer.dropEffect = 'move';
        }

        function ftDragLeave(e, targetNid) {
            e.stopPropagation();
            const row = document.getElementById('ftRow_' + targetNid);
            if (row) row.classList.remove('ft-drop-before', 'ft-drop-after', 'ft-drop-inside');
        }

        function ftDrop(e, targetNid) {
            e.preventDefault();
            e.stopPropagation();
            if (!ftDragNid || ftDragNid === targetNid || !ftDropMode) { ftDragEnd(e, ftDragNid); return; }
            if (ftIsDescendant(targetNid, ftDragNid)) { ftDragEnd(e, ftDragNid); return; }

            const dragNode = ftNodeMap.get(ftDragNid);
            const targetNode = ftNodeMap.get(targetNid);
            if (!dragNode || !targetNode) { ftDragEnd(e, ftDragNid); return; }

            // 1. Detach dragged node from its current parent/root
            ftDetachNode(ftDragNid);

            // 2. Insert at new position
            if (ftDropMode === 'inside' && targetNode.type === 'folder') {
                // Insert as last child of target folder
                dragNode.parentId = targetNid;
                dragNode.sid = targetNode.sid;
                targetNode.childIds.push(ftDragNid);
            } else {
                // Insert before or after target in its parent's child list
                const parentId = targetNode.parentId;
                const list = parentId ? ftNodeMap.get(parentId).childIds : ftTreeRoots.get(targetNode.sid);
                if (!list) { ftDragEnd(e, ftDragNid); return; }
                const idx = list.indexOf(targetNid);
                const insertIdx = ftDropMode === 'before' ? idx : idx + 1;
                list.splice(insertIdx, 0, ftDragNid);
                dragNode.parentId = parentId;
                dragNode.sid = targetNode.sid;
            }

            // Update sid recursively if moved to different tree
            ftUpdateSidRecursive(ftDragNid, dragNode.sid);

            // 3. Re-render the affected tree
            const sid = dragNode.sid;
            ftReRenderTree(sid);
            ftMarkDirty(ftDragNid);

            // Clean up drag state
            ftDragNid = null;
            ftDropMode = null;
            document.querySelectorAll('.ft-drop-before,.ft-drop-after,.ft-drop-inside,.ft-dragging').forEach(el => {
                el.classList.remove('ft-drop-before', 'ft-drop-after', 'ft-drop-inside', 'ft-dragging');
            });
        }

        function ftIsDescendant(nid, potentialAncestorNid) {
            const node = ftNodeMap.get(nid);
            if (!node) return false;
            let cur = node.parentId;
            while (cur) {
                if (cur === potentialAncestorNid) return true;
                const p = ftNodeMap.get(cur);
                cur = p ? p.parentId : null;
            }
            return false;
        }

        function ftDetachNode(nid) {
            const node = ftNodeMap.get(nid);
            if (!node) return;
            if (node.parentId) {
                const parent = ftNodeMap.get(node.parentId);
                if (parent) parent.childIds = parent.childIds.filter(id => id !== nid);
            } else {
                const rootIds = ftTreeRoots.get(node.sid);
                if (rootIds) {
                    const idx = rootIds.indexOf(nid);
                    if (idx > -1) rootIds.splice(idx, 1);
                }
            }
            node.parentId = null;
        }

        function ftUpdateSidRecursive(nid, sid) {
            const node = ftNodeMap.get(nid);
            if (!node) return;
            node.sid = sid;
            if (node.childIds) node.childIds.forEach(cid => ftUpdateSidRecursive(cid, sid));
        }

        function ftReRenderTree(sid) {
            const treeEl = document.getElementById('ftITree_' + sid);
            if (!treeEl) return;
            const rootIds = ftTreeRoots.get(sid);
            if (!rootIds) return;
            let html = '';
            for (const nid of rootIds) html += ftRenderNode(nid);
            treeEl.innerHTML = html;
            ftInitAutoResize(sid);
        }

        function ftAddChild(parentNid, type) {
            const parent = ftNodeMap.get(parentNid);
            if (!parent || parent.type !== 'folder') return;
            const nid = ftNextNodeId();
            const isDb = ftIsDbTreeNode(parent.sid);
            const name = type === 'folder' ? (isDb ? 'new_table' : 'new-folder') : (isDb ? 'new_field' : 'new-file.txt');
            ftNodeMap.set(nid, { id: nid, name, type, description: '', parentId: parentNid, sid: parent.sid, childIds: [] });
            parent.childIds.push(nid);

            const childrenEl = document.getElementById('ftChildren_' + parentNid);
            if (childrenEl) {
                childrenEl.classList.remove('collapsed');
                const toggleEl = document.getElementById('ftToggle_' + parentNid);
                if (toggleEl) toggleEl.classList.remove('collapsed');
                childrenEl.insertAdjacentHTML('beforeend', ftRenderNode(nid));
                const newNode = document.getElementById('ftNode_' + nid);
                if (newNode) {
                    const inp = newNode.querySelector('.ft-inode-title');
                    if (inp) { inp.focus(); inp.select(); }
                }
            }
            const folderName = ftIdToName.get(parent.sid);
            if (folderName) { const d = ftFolderStore.get(folderName); if (d) d._dirty = true; }
        }

        function ftAddRootChild(sid, type) {
            const rootIds = ftTreeRoots.get(sid);
            if (!rootIds) return;
            const nid = ftNextNodeId();
            const isDb = ftIsDbTreeNode(sid);
            const name = type === 'folder' ? (isDb ? 'new_table' : 'new-folder') : (isDb ? 'new_field' : 'new-file.txt');
            ftNodeMap.set(nid, { id: nid, name, type, description: '', parentId: null, sid, childIds: [] });
            rootIds.push(nid);

            const treeEl = document.getElementById('ftITree_' + sid);
            if (treeEl) {
                treeEl.insertAdjacentHTML('beforeend', ftRenderNode(nid));
                const newNode = document.getElementById('ftNode_' + nid);
                if (newNode) {
                    const inp = newNode.querySelector('.ft-inode-title');
                    if (inp) { inp.focus(); inp.select(); }
                }
            }
            const folderName = ftIdToName.get(sid);
            if (folderName) { const d = ftFolderStore.get(folderName); if (d) d._dirty = true; }
        }

        function ftDeleteNode(nid) {
            const node = ftNodeMap.get(nid);
            if (!node) return;
            if (node.parentId) {
                const parent = ftNodeMap.get(node.parentId);
                if (parent) parent.childIds = parent.childIds.filter(id => id !== nid);
            } else {
                const rootIds = ftTreeRoots.get(node.sid);
                if (rootIds) { const idx = rootIds.indexOf(nid); if (idx > -1) rootIds.splice(idx, 1); }
            }
            function removeR(id) {
                const n = ftNodeMap.get(id);
                if (!n) return;
                if (n.childIds) n.childIds.forEach(c => removeR(c));
                ftNodeMap.delete(id);
            }
            removeR(nid);
            const el = document.getElementById('ftNode_' + nid);
            if (el) {
                el.style.transition = 'all 0.2s ease';
                el.style.opacity = '0';
                el.style.transform = 'translateX(10px)';
                setTimeout(() => el.remove(), 210);
            }
            const folderName = ftIdToName.get(node.sid);
            if (folderName) { const d = ftFolderStore.get(folderName); if (d) d._dirty = true; }
        }

        function ftExpandAllNodes(sid) {
            const card = document.getElementById('ftCard_' + sid);
            if (!card) return;
            card.querySelectorAll('.ft-inode-children').forEach(el => el.classList.remove('collapsed'));
            card.querySelectorAll('.ft-inode-toggle').forEach(el => el.classList.remove('collapsed'));
        }

        function ftCollapseAllNodes(sid) {
            const card = document.getElementById('ftCard_' + sid);
            if (!card) return;
            card.querySelectorAll('.ft-inode-children').forEach(el => el.classList.add('collapsed'));
            card.querySelectorAll('.ft-inode-toggle').forEach(el => el.classList.add('collapsed'));
        }

        function ftSerializeTreeText(sid) {
            const rootIds = ftTreeRoots.get(sid);
            const folderName = ftIdToName.get(sid);
            if (!rootIds || !folderName) return '';
            const isDb = ftIsDbTreeNode(sid);
            let lines = [(isDb ? '🗄️ ' : '📁 ') + folderName + (isDb ? '' : '/')];
            function renderN(nids, prefix) {
                for (let i = 0; i < nids.length; i++) {
                    const nd = ftNodeMap.get(nids[i]);
                    if (!nd) continue;
                    const isLast = (i === nids.length - 1);
                    const conn = isLast ? '└── ' : '├── ';
                    const childPfx = isLast ? '    ' : '│   ';
                    if (nd.type === 'folder') {
                        let lbl = (isDb ? '📊 ' : '📂 ') + nd.name + (isDb ? '' : '/');
                        if (nd.description) lbl += ' — ' + nd.description;
                        lines.push(prefix + conn + lbl);
                        if (nd.childIds.length > 0) renderN(nd.childIds, prefix + childPfx);
                    } else {
                        let icon;
                        if (isDb) {
                            icon = '🔤';
                        } else {
                            const ext = (nd.name.split('.').pop() || '').toLowerCase();
                            icon = '📄';
                            if (['jpg','jpeg','png','gif','svg','webp','ico'].includes(ext)) icon = '🖼️';
                            else if (['js','ts','jsx','tsx'].includes(ext)) icon = '📜';
                            else if (['php'].includes(ext)) icon = '🐘';
                            else if (['css','scss','sass','less'].includes(ext)) icon = '🎨';
                            else if (['html','htm'].includes(ext)) icon = '🌐';
                            else if (['json','xml','yaml','yml'].includes(ext)) icon = '📋';
                            else if (['md','txt','log'].includes(ext)) icon = '📝';
                            else if (['py'].includes(ext)) icon = '🐍';
                            else if (['sql','db','sqlite'].includes(ext)) icon = '🗃️';
                            else if (['zip','rar','tar','gz'].includes(ext)) icon = '📦';
                            else if (['env','gitignore','htaccess'].includes(ext) || nd.name.startsWith('.')) icon = '⚙️';
                        }
                        let lbl = icon + ' ' + nd.name;
                        if (nd.description) lbl += ' — ' + nd.description;
                        lines.push(prefix + conn + lbl);
                    }
                }
            }
            renderN(rootIds, '');
            return lines.join('\n');
        }

        function ftRenderCard(folderName) {
            const data = ftFolderStore.get(folderName);
            if (!data) return '';
            const sid = ftGetSafeId(folderName);
            ftIdToName.set(sid, folderName);
            const escHtml = ftEscapeHtml(folderName);
            const escPath = ftEscapeHtml(data.path || 'No path');

            // Build interactive node map from treeData if available
            let treeBodyHtml = '';
            let stats = { folders: 0, files: 0 };
            if (data.treeData && Array.isArray(data.treeData) && data.treeData.length > 0) {
                ftClearNodeMapForSid(sid);
                const rootIds = ftBuildNodeMap(data.treeData, sid, null);
                ftTreeRoots.set(sid, rootIds);
                treeBodyHtml = ftRenderInteractiveTree(sid);
                stats = ftCountTreeStatsFromData(data.treeData);
            } else {
                treeBodyHtml = `<div class="ft-tree-content" contenteditable="true" spellcheck="false"
                     id="ftTree_${sid}"
                     oninput="ftOnTreeEdit('${sid}', this)">${ftEscapeHtml(data.treeText).replace(/\n/g, '<br>')}</div>`;
                stats = ftCountTreeStats(data.treeText);
            }

            const isDbCard = folderName.startsWith('\ud83d\uddc4\ufe0f DB: ');
            const cardIcon = isDbCard ? 'fas fa-database' : 'fas fa-folder-tree';
            const statIcon1 = isDbCard ? 'fas fa-table' : 'fas fa-folder';
            const statIcon2 = isDbCard ? 'fas fa-columns' : 'fas fa-file';
            const cardIconColor = isDbCard ? 'style="color:#06b6d4"' : '';

            return `
                <div class="ft-folder-card ft-new" id="ftCard_${sid}" data-sid="${sid}">
                    <div class="ft-folder-card-header" onclick="ftToggleCard('${sid}')">
                        <div class="ft-folder-info">
                            <i class="fas fa-chevron-down ft-chevron" id="ftChev_${sid}"></i>
                            <div class="ft-folder-icon" ${cardIconColor}><i class="${cardIcon}"></i></div>
                            <div>
                                <div class="ft-folder-name">${escHtml}</div>
                                <div class="ft-folder-path">${escPath}</div>
                            </div>
                        </div>
                        <div class="ft-folder-stats">
                            <span><i class="${statIcon1}"></i> ${stats.folders}</span>
                            <span><i class="${statIcon2}"></i> ${stats.files}</span>
                        </div>
                        <div class="ft-card-actions">
                            <button onclick="event.stopPropagation();ftCopyTree('${sid}')" title="Copy tree">
                                <i class="fas fa-copy"></i>
                            </button>
                            <button onclick="event.stopPropagation();ftRefreshTree('${sid}')" title="Refresh tree">
                                <i class="fas fa-sync-alt"></i>
                            </button>
                            <button class="ft-remove" onclick="event.stopPropagation();ftRemoveFolder('${sid}')" title="Remove folder">
                                <i class="fas fa-times"></i>
                            </button>
                        </div>
                    </div>
                    <div class="ft-card-notes-wrap">
                        <textarea class="ft-card-notes" id="ftNotes_${sid}"
                            placeholder="Write your prompt or notes for this ${isDbCard ? 'database' : 'folder'}..."
                            oninput="ftOnCardNotesChange('${sid}', this)">${ftEscapeHtml(data.notes || '')}</textarea>
                    </div>
                    <div class="ft-folder-tree-wrap">
                        ${treeBodyHtml}
                    </div>
                </div>`;
        }

        function ftRenderAll() {
            const body = document.getElementById('ftFolderBody');
            if (ftFolderStore.size === 0) {
                body.innerHTML = '';
                ftUpdateContainer();
                return;
            }
            let html = '';
            ftFolderStore.forEach((_, name) => {
                html += ftRenderCard(name);
            });
            body.innerHTML = html;
            ftUpdateContainer();
            // Init auto-resize for all interactive tree textareas
            ftFolderStore.forEach((_, name) => {
                ftInitAutoResize(ftGetSafeId(name));
            });
            setTimeout(() => {
                body.querySelectorAll('.ft-new').forEach(el => el.classList.remove('ft-new'));
            }, 400);
        }

        function ftAddFolderCard(folderName) {
            const body = document.getElementById('ftFolderBody');
            body.insertAdjacentHTML('beforeend', ftRenderCard(folderName));
            ftUpdateContainer();
            const sid = ftGetSafeId(folderName);
            // Init auto-resize for interactive tree textareas after DOM insertion
            requestAnimationFrame(() => ftInitAutoResize(sid));
            setTimeout(() => {
                const card = document.getElementById('ftCard_' + sid);
                if (card) card.classList.remove('ft-new');
            }, 400);
        }

        function ftToggleCard(safeId) {
            const card = document.getElementById('ftCard_' + safeId);
            if (card) card.classList.toggle('collapsed');
        }

        function ftOnCardNotesChange(sid, el) {
            const folderName = ftIdToName.get(sid);
            if (!folderName) return;
            const data = ftFolderStore.get(folderName);
            if (data) {
                data.notes = el.value;
            }
        }

        function ftOnTreeEdit(sid, el) {
            const folderName = ftIdToName.get(sid);
            if (!folderName) return;
            const data = ftFolderStore.get(folderName);
            if (data) {
                data.treeText = el.innerText;
            }
        }

        function ftRemoveFolder(sid) {
            const folderName = ftIdToName.get(sid);
            if (!folderName) return;
            const isDbCard = folderName.startsWith('🗄️ DB: ');
            ftClearNodeMapForSid(sid);
            ftFolderStore.delete(folderName);
            ftIdToName.delete(sid);
            const card = document.getElementById('ftCard_' + sid);
            if (card) {
                card.style.transition = 'all 0.3s ease';
                card.style.opacity = '0';
                card.style.transform = 'translateX(20px)';
                setTimeout(() => {
                    card.remove();
                    ftUpdateContainer();
                }, 310);
            } else {
                ftUpdateContainer();
            }
            if (editorFolders.has(folderName)) editorFolders.delete(folderName);
            if (knownFolders.has(folderName)) knownFolders.delete(folderName);
            // Clean up DB tree tracking and sync checkbox
            if (isDbCard && window._dbTreeFolderNames) {
                window._dbTreeFolderNames.delete(folderName);
                ftSyncDbCheckbox();
            }
            updateCounts();
            loadUploadedFiles();
            showToast(`${isDbCard ? '🗄️' : '📁'} ${folderName} removed`, 'info');
        }

        function ftCopyTree(sid) {
            const folderName = ftIdToName.get(sid);
            if (!folderName) return;
            const data = ftFolderStore.get(folderName);
            if (!data) return;
            // Use interactive tree serialization if available
            let text = data.treeText;
            if (ftTreeRoots.has(sid)) {
                text = ftSerializeTreeText(sid);
                data.treeText = text;
                data._dirty = false;
            }
            navigator.clipboard.writeText(text).then(() => {
                showToast(`📋 ${folderName} tree copied!`, 'success');
            });
        }

        async function ftRefreshTree(sid) {
            const folderName = ftIdToName.get(sid);
            if (!folderName) return;
            const data = ftFolderStore.get(folderName);
            if (!data) return;
            
            let treeData = null;
            
            // Try client-side refresh first (FileSystemDirectoryHandle cached from user's PC)
            if (clientHandleCache.has(folderName)) {
                try {
                    treeData = await buildClientSideTree(clientHandleCache.get(folderName));
                } catch (e) {
                    console.warn('Client-side refresh failed:', e.message);
                }
            }
            
            // Fallback to PHP server-side refresh (for localhost)
            if (!treeData && data.path) {
                treeData = await fetchFolderTree(data.path);
            }
            
            if (treeData) {
                data.treeText = buildTreeDiagram(folderName, treeData);
                data.treeData = treeData;
                data._dirty = false;
                // Rebuild interactive tree in the card
                if (ftTreeRoots.has(sid)) {
                    ftClearNodeMapForSid(sid);
                    const rootIds = ftBuildNodeMap(treeData, sid, null);
                    ftTreeRoots.set(sid, rootIds);
                    const wrapEl = document.querySelector('#ftCard_' + sid + ' .ft-folder-tree-wrap');
                    if (wrapEl) {
                        wrapEl.innerHTML = ftRenderInteractiveTree(sid);
                        requestAnimationFrame(() => ftInitAutoResize(sid));
                    }
                    // Update stats in header
                    const statsFromData = ftCountTreeStatsFromData(treeData);
                    const statsEl = document.querySelector('#ftCard_' + sid + ' .ft-folder-stats');
                    if (statsEl) {
                        statsEl.innerHTML = `<span><i class="fas fa-folder"></i> ${statsFromData.folders}</span><span><i class="fas fa-file"></i> ${statsFromData.files}</span>`;
                    }
                } else {
                    const treeEl = document.getElementById('ftTree_' + sid);
                    if (treeEl) treeEl.innerText = data.treeText;
                }
                showToast(`🔄 ${folderName} refreshed!`, 'success');
            } else {
                showToast('Could not refresh — folder handle expired. Re-pick the folder.', 'warning');
            }
        }

        function ftCopyAllTrees() {
            if (ftFolderStore.size === 0) {
                showToast('No folders to copy', 'info');
                return;
            }
            let allText = '';
            ftFolderStore.forEach((data, name) => {
                if (allText) allText += '\n\n';
                const sid = ftGetSafeId(name);
                if (ftTreeRoots.has(sid)) {
                    const serialized = ftSerializeTreeText(sid);
                    data.treeText = serialized;
                    data._dirty = false;
                    allText += serialized;
                } else {
                    allText += data.treeText;
                }
            });
            navigator.clipboard.writeText(allText).then(() => {
                showToast(`📋 All folder trees copied!`, 'success');
            });
        }

        function ftPushToProjectPrompts() {
            if (ftFolderStore.size === 0) {
                showToast('No folders to push', 'info');
                return;
            }
            const textarea = document.getElementById('projectNotesTextarea');
            if (!textarea) {
                showToast('Project Prompts textarea not found', 'warning');
                return;
            }
            let allText = '';
            ftFolderStore.forEach((data, name) => {
                if (allText) allText += '\n\n';
                // Include notes if present
                if (data.notes && data.notes.trim()) {
                    allText += '/* Notes: ' + data.notes.trim() + ' */\n';
                }
                const sid = ftGetSafeId(name);
                if (ftTreeRoots.has(sid)) {
                    const serialized = ftSerializeTreeText(sid);
                    data.treeText = serialized;
                    data._dirty = false;
                    allText += serialized;
                } else {
                    allText += data.treeText;
                }
            });
            if (textarea.value.trim()) {
                textarea.value += '\n\n' + allText;
            } else {
                textarea.value = allText;
            }
            // Auto-expand textarea
            textarea.style.height = 'auto';
            textarea.style.height = textarea.scrollHeight + 'px';
            // Trigger change event for any listeners
            textarea.dispatchEvent(new Event('input', { bubbles: true }));
            showToast(`📝 ${ftFolderStore.size} folder tree(s) pushed to Project Prompts!`, 'success');
        }

        function ftCollapseAll() {
            const cards = document.querySelectorAll('.ft-folder-card');
            const allCollapsed = Array.from(cards).every(c => c.classList.contains('collapsed'));
            cards.forEach(c => {
                if (allCollapsed) {
                    c.classList.remove('collapsed');
                } else {
                    c.classList.add('collapsed');
                }
            });
        }

        async function ftClearAll() {
            if (ftFolderStore.size === 0) return;
            const confirmed = typeof deConfirm === 'function'
                ? await deConfirm({ title: 'Clear All Folders', subtitle: 'Folder Template', message: 'Remove all folders from the template?', confirmText: 'Yes, Remove All', cancelText: 'Cancel' })
                : confirm('Remove all folders from the template?');
            if (!confirmed) return;
            ftFolderStore.forEach((_, name) => {
                const sid = ftGetSafeId(name);
                ftClearNodeMapForSid(sid);
                if (editorFolders.has(name)) editorFolders.delete(name);
                if (knownFolders.has(name)) knownFolders.delete(name);
            });
            ftFolderStore.clear();
            ftIdToName.clear();
            ftNodeMap.clear();
            ftTreeRoots.clear();
            if (window._dbTreeFolderNames) window._dbTreeFolderNames.clear();
            ftSyncDbCheckbox();
            ftRenderAll();
            updateCounts();
            loadUploadedFiles();
            showToast('All folders cleared', 'info');
        }

        // Serialize ftFolderStore to JSON string for saving to database
        function ftSerializeFolderStore() {
            if (ftFolderStore.size === 0) return '[]';
            const arr = [];
            ftFolderStore.forEach((data, name) => {
                const sid = ftGetSafeId(name);
                // Sync treeText from interactive tree if dirty
                if (ftTreeRoots.has(sid) && data._dirty) {
                    data.treeText = ftSerializeTreeText(sid);
                    data._dirty = false;
                }
                arr.push({
                    name: name,
                    path: data.path || '',
                    treeText: data.treeText || '',
                    treeData: data.treeData || null,
                    notes: data.notes || '',
                    added: data.addedAt || data.added || Date.now()
                });
            });
            return JSON.stringify(arr);
        }

        // Deserialize JSON string back into ftFolderStore and render
        function ftDeserializeFolderStore(jsonStr) {
            // Clear existing data including interactive node maps
            ftNodeMap.clear();
            ftTreeRoots.clear();
            ftFolderStore.clear();
            ftIdToName.clear();
            
            if (!jsonStr || jsonStr === '[]' || jsonStr === 'null') {
                ftRenderAll();
                return;
            }
            
            try {
                let arr = jsonStr;
                if (typeof arr === 'string') {
                    arr = JSON.parse(arr);
                }
                if (!Array.isArray(arr) || arr.length === 0) {
                    ftRenderAll();
                    return;
                }
                
                if (!window._dbTreeFolderNames) window._dbTreeFolderNames = new Set();
                window._dbTreeFolderNames.clear();

                arr.forEach(item => {
                    const name = item.name;
                    const safeId = name.replace(/[^a-zA-Z0-9_-]/g, '_');
                    
                    ftFolderStore.set(name, {
                        path: item.path || '',
                        treeText: item.treeText || '',
                        treeData: item.treeData || null,
                        notes: item.notes || '',
                        addedAt: item.added || item.addedAt || Date.now()
                    });
                    ftIdToName.set(safeId, name);
                    
                    // Restore DB tree tracking
                    if (name.startsWith('🗄️ DB: ')) {
                        window._dbTreeFolderNames.add(name);
                    }
                    
                    // Also register in editorFolders and knownFolders for checkbox sync
                    if (!editorFolders.has(name)) {
                        editorFolders.set(name, `<!-- FOLDER:${name} -->`);
                    }
                    if (!knownFolders.has(name)) {
                        knownFolders.set(name, { path: item.path || '' });
                    }
                });
                
                ftRenderAll();
                // Sync DB checkbox after restore
                if (typeof ftSyncDbCheckbox === 'function') ftSyncDbCheckbox();
                console.log(`📂 Restored ${arr.length} folder(s) from project data`);
            } catch (e) {
                console.warn('Could not deserialize folder data:', e);
                ftRenderAll();
            }
        }

        // Resize handle for folder template
        (function() {
            const handle = document.getElementById('ftResizeHandle');
            const container = document.getElementById('folderTemplateContainer');
            if (!handle || !container) return;
            let startY, startH;
            handle.addEventListener('mousedown', (e) => {
                e.preventDefault();
                startY = e.clientY;
                startH = container.offsetHeight;
                document.addEventListener('mousemove', onDrag);
                document.addEventListener('mouseup', onUp);
            });
            function onDrag(e) {
                const newH = startH + (e.clientY - startY);
                container.style.maxHeight = Math.max(80, newH) + 'px';
            }
            function onUp() {
                document.removeEventListener('mousemove', onDrag);
                document.removeEventListener('mouseup', onUp);
            }
        })();

        // Add a folder's reference + tree diagram to the TEMPLATE (makes it "checked")
        async function addFolderToEditor(folderName, marker, folderPath) {
            if (!marker) {
                marker = `<!-- FOLDER:${folderName} -->`;
            }
            
            // Try to get the folder path from knownFolders if not provided
            if (!folderPath && knownFolders.has(folderName)) {
                folderPath = knownFolders.get(folderName).path || '';
            }
            
            // Build tree: check client-side cache first (user's local PC), then PHP server fallback
            let treeText = '';
            let treeData = null;
            if (clientTreeCache.has(folderName)) {
                // Use client-side built tree (from File System Access API)
                treeData = clientTreeCache.get(folderName);
                clientTreeCache.delete(folderName);
                treeText = buildTreeDiagram(folderName, treeData);
            } else if (folderPath) {
                // Fallback: fetch tree from PHP server (works on localhost)
                treeData = await fetchFolderTree(folderPath);
                if (treeData) {
                    treeText = buildTreeDiagram(folderName, treeData);
                } else {
                    treeText = `📁 ${folderName}/\n    (could not read directory contents)`;
                }
            } else {
                treeText = `[📁 ${folderName}]`;
            }
            
            // Store in folder template
            ftFolderStore.set(folderName, {
                path: folderPath,
                treeText: treeText,
                treeData: treeData,
                addedAt: Date.now()
            });
            
            // Add card to template UI
            ftAddFolderCard(folderName);
            
            // Track in editorFolders (active)
            editorFolders.set(folderName, {
                marker: marker,
                addedAt: Date.now()
            });
        }
        
        // Remove folder content from template + editor (folder stays in display list)
        function removeFolderFromEditor(folderName) {
            const editor = document.getElementById('promptEditor');
            const folderData = editorFolders.get(folderName);
            
            if (folderData) {
                const startMarker = folderData.marker;
                const endMarker = startMarker.replace('<!--', '<!-- /END ');
                
                const startIdx = editor.value.indexOf(startMarker);
                if (startIdx !== -1) {
                    const endIdx = editor.value.indexOf(endMarker);
                    if (endIdx !== -1) {
                        const before = editor.value.substring(0, startIdx);
                        const after = editor.value.substring(endIdx + endMarker.length);
                        editor.value = (before + after).replace(/\n{3,}/g, '\n\n').trim();
                    }
                }
                
                // Remove from editorFolders only — folder stays in knownFolders (display list)
                editorFolders.delete(folderName);
                updateCounts();
            }
            
            // Also remove from folder template UI
            if (ftFolderStore.has(folderName)) {
                const sid = ftGetSafeId(folderName);
                ftFolderStore.delete(folderName);
                ftIdToName.delete(sid);
                const card = document.getElementById('ftCard_' + sid);
                if (card) card.remove();
                ftUpdateContainer();
            }
        }
        
        // Toggle folder checkbox — adds/removes from editor, folder stays in display list
        async function toggleFolderCheckbox(folderName) {
            if (editorFolders.has(folderName)) {
                // Folder is in editor — remove from editor (uncheck)
                removeFolderFromEditor(folderName);
                showToast(`📁 ${folderName} removed from template`, 'info');
            } else {
                // Folder not in editor — add back to editor (check) with tree
                const marker = `<!-- FOLDER:${folderName} -->`;
                const folderPath = knownFolders.has(folderName) ? (knownFolders.get(folderName).path || '') : '';
                await addFolderToEditor(folderName, marker, folderPath);
                updateCounts();
                recordHistoryState(true);
                showToast(`📁 ${folderName} added to template`, 'success');
            }
            // Re-render display to update checkbox state
            loadUploadedFiles();
        }
        
        // Delete folder completely (remove from display list, editor, AND template)
        function deleteFolder(folderName) {
            // Remove from editor if active
            if (editorFolders.has(folderName)) {
                removeFolderFromEditor(folderName);
            }
            // Remove from template if present
            if (ftFolderStore.has(folderName)) {
                const sid = ftGetSafeId(folderName);
                ftFolderStore.delete(folderName);
                ftIdToName.delete(sid);
                const card = document.getElementById('ftCard_' + sid);
                if (card) card.remove();
                ftUpdateContainer();
            }
            // Remove from display list
            knownFolders.delete(folderName);
            showToast(`📁 ${folderName} deleted`, 'info');
            // Re-render
            loadUploadedFiles();
        }

        // Load uploaded files
        async function loadUploadedFiles() {
            try {
                const formData = new FormData();
                formData.append('action', 'get_files');
                
                const response = await fetch('', {
                    method: 'POST',
                    body: formData
                });
                
                const data = await response.json();
                const container = document.getElementById('uploadedFiles');
                const header = document.getElementById('uploadedFilesHeader');
                const countSpan = document.getElementById('filesCount');
                
                const hasFiles = data.success && data.files.length > 0;
                const hasFolders = knownFolders.size > 0;
                const totalItems = (hasFiles ? data.files.length : 0) + knownFolders.size;
                
                if (hasFiles || hasFolders) {
                    // Show header and update count
                    header.style.display = 'flex';
                    countSpan.textContent = totalItems;
                    
                    let html = '';
                    
                    // 1. Render FOLDERS first (before files) — from knownFolders (persisted list)
                    if (hasFolders) {
                        knownFolders.forEach((folderData, folderName) => {
                            const isChecked = editorFolders.has(folderName);
                            const escapedName = escapeHtml(folderName);
                            html += `
                            <div class="file-item folder-item ${isChecked ? 'checked' : ''}" data-foldername="${escapedName}">
                                <div class="file-item-checkbox" onclick="toggleFolderCheckbox('${escapedName}')">
                                    <input type="checkbox" ${isChecked ? 'checked' : ''}>
                                    <div class="checkbox-box"><i class="fas fa-check"></i></div>
                                </div>
                                <i class="fas fa-folder file-item-icon"></i>
                                <div class="file-info">
                                    <div class="file-name">${escapedName}</div>
                                    <div class="file-size">Folder</div>
                                </div>
                                <button class="file-delete" onclick="event.stopPropagation(); deleteFolder('${escapedName}')" title="Remove folder">
                                    <i class="fas fa-trash"></i>
                                </button>
                            </div>
                            `;
                        });
                    }
                    
                    // 2. Render FILES after folders
                    if (hasFiles) {
                        html += data.files.map(file => {
                            const isChecked = editorFiles.has(file.filename);
                            return `
                            <div class="file-item ${isChecked ? 'checked' : ''}" data-filename="${escapeHtml(file.filename)}" data-filepath="${escapeHtml(file.filepath)}" data-fileid="${file.id}">
                                <div class="file-item-checkbox" onclick="toggleFileCheckbox('${escapeHtml(file.filepath)}', '${escapeHtml(file.filename)}', ${file.filesize || 0})">
                                    <input type="checkbox" ${isChecked ? 'checked' : ''}>
                                    <div class="checkbox-box"><i class="fas fa-check"></i></div>
                                </div>
                                <i class="fas fa-file-alt file-item-icon"></i>
                                <div class="file-info">
                                    <div class="file-name">${escapeHtml(file.filename)}</div>
                                    <div class="file-size">${formatFileSize(file.filesize)}</div>
                                </div>
                                <button class="file-delete" onclick="event.stopPropagation(); deleteFile(${file.id}, '${escapeHtml(file.filename)}')" title="Delete file">
                                    <i class="fas fa-trash"></i>
                                </button>
                            </div>
                            `;
                        }).join('');
                    }
                    
                    container.innerHTML = html;
                    
                    // Update Select All checkbox state
                    updateSelectAllFilesCheckbox();
                } else {
                    // Hide header when no files and no folders
                    header.style.display = 'none';
                    container.innerHTML = '';
                    updateSelectAllFilesCheckbox();
                }
            } catch (err) {
                console.error('Error loading files:', err);
            }
        }

        // Load file content to editor (for previously uploaded files)
        async function loadFileToEditor(filepath, filename, filesize = 0) {
            console.log('📂 Loading file from server:', filename, filepath);
            
            // Check if already in editor
            if (editorFiles.has(filename)) {
                showToast(`${filename} is already in editor`, 'info');
                return;
            }
            
            const sendFullContent = shouldSendFullContent();
            const editor = document.getElementById('promptEditor');
            
            try {
                let content = '';
                let isReference = false;
                
                if (sendFullContent) {
                    const response = await fetch(filepath);
                    
                    if (response.ok) {
                        content = await response.text();
                    } else {
                        showToast('Could not load file content', 'error');
                        return;
                    }
                } else {
                    // Just create a reference - extract direct parent folder from path
                    const folderMatch = filepath.match(/\/([^\/]+)\/[^\/]+$/);
                    const folder = folderMatch ? folderMatch[1] : 'root';
                    content = `[📎 ${filename} | Folder: ${folder}]`;
                    isReference = true;
                }
                
                // Create simple marker without timestamp
                const marker = `<!-- FILE:${filename} -->`;
                
                // Append with spacing
                let textToAdd = '';
                if (editor.value.trim()) {
                    textToAdd = '\n\n';
                }
                
                if (isReference) {
                    textToAdd += `${marker}\n${content}\n${marker.replace('<!--', '<!-- /END ')}`;
                } else {
                    textToAdd += `${marker}\n## 📄 ${filename}\n${content}\n${marker.replace('<!--', '<!-- /END ')}`;
                }
                
                editor.value += textToAdd;
                
                // Track this file
                editorFiles.set(filename, {
                    marker: marker,
                    content: content,
                    isReference: isReference,
                    addedAt: Date.now()
                });
                
                updateCounts();
                const modeText = isReference ? '(reference)' : '(full content)';
                showToast(`✅ ${filename} added ${modeText}!`, 'success');
                
            } catch (err) {
                showToast('Error loading file', 'error');
                console.error(err);
            }
        }

        // Toggle file checkbox - adds or removes file from editor
        async function toggleFileCheckbox(filepath, filename, filesize = 0) {
            const fileItem = document.querySelector(`.file-item[data-filename="${filename}"]`);
            const editor = document.getElementById('promptEditor');
            
            if (editorFiles.has(filename)) {
                // File is in editor - remove it
                removeFileFromEditor(filename);
                
                if (fileItem) {
                    fileItem.classList.remove('checked');
                    const checkbox = fileItem.querySelector('input[type="checkbox"]');
                    if (checkbox) checkbox.checked = false;
                }
                
                showToast(`📄 ${filename} removed from editor`, 'info');
            } else {
                // File not in editor - add it
                const sendFullContent = shouldSendFullContent();
                
                try {
                    let content = '';
                    let isReference = false;
                    
                    if (sendFullContent) {
                        const response = await fetch(filepath);
                        
                        if (response.ok) {
                            content = await response.text();
                        } else {
                            showToast('Could not load file content', 'error');
                            return;
                        }
                    } else {
                        // Just create a reference - extract direct parent folder from path
                        const folderMatch = filepath.match(/\/([^\/]+)\/[^\/]+$/);
                        const folder = folderMatch ? folderMatch[1] : 'root';
                        content = `[📎 ${filename} | Folder: ${folder}]`;
                        isReference = true;
                    }
                    
                    // Create simple marker without timestamp
                    const marker = `<!-- FILE:${filename} -->`;
                    
                    // Append with spacing
                    let textToAdd = '';
                    if (editor.value.trim()) {
                        textToAdd = '\n\n';
                    }
                    
                    if (isReference) {
                        textToAdd += `${marker}\n${content}\n${marker.replace('<!--', '<!-- /END ')}`;
                    } else {
                        textToAdd += `${marker}\n## 📄 ${filename}\n${content}\n${marker.replace('<!--', '<!-- /END ')}`;
                    }
                    
                    editor.value += textToAdd;
                    
                    // Track this file
                    editorFiles.set(filename, {
                        marker: marker,
                        content: content,
                        isReference: isReference,
                        addedAt: Date.now()
                    });
                    
                    if (fileItem) {
                        fileItem.classList.add('checked');
                        const checkbox = fileItem.querySelector('input[type="checkbox"]');
                        if (checkbox) checkbox.checked = true;
                    }
                    
                    updateCounts();
                    const modeText = isReference ? '(reference)' : '(full content)';
                    showToast(`✅ ${filename} added ${modeText}!`, 'success');
                    
                } catch (err) {
                    showToast('Error loading file', 'error');
                    console.error(err);
                }
            }
            
            updateCounts();
            updateSelectAllFilesCheckbox();
        }

        // Toggle all uploaded files (Select All checkbox handler)
        async function toggleAllUploadedFiles(checked) {
            const fileItems = document.querySelectorAll('.file-item');
            
            if (fileItems.length === 0) {
                showToast('No items to select', 'info');
                return;
            }
            
            let processedCount = 0;
            const sendFullContent = shouldSendFullContent();
            
            for (const fileItem of fileItems) {
                // Check if this is a folder item
                const isFolder = fileItem.classList.contains('folder-item');
                
                if (isFolder) {
                    const folderName = fileItem.dataset.foldername;
                    const isFolderChecked = editorFolders.has(folderName);
                    
                    if (checked && !isFolderChecked) {
                        // Add folder to editor with tree (it's already in knownFolders)
                        const marker = `<!-- FOLDER:${folderName} -->`;
                        const folderPath = knownFolders.has(folderName) ? (knownFolders.get(folderName).path || '') : '';
                        await addFolderToEditor(folderName, marker, folderPath);
                        processedCount++;
                    } else if (!checked && isFolderChecked) {
                        removeFolderFromEditor(folderName);
                        processedCount++;
                    }
                } else {
                    // Regular file item
                    const filename = fileItem.dataset.filename;
                    const filepath = fileItem.dataset.filepath;
                    const isCurrentlyChecked = editorFiles.has(filename);
                    
                    if (checked && !isCurrentlyChecked) {
                        // Add file to editor
                        try {
                            let content = '';
                            let isReference = false;
                            
                            if (sendFullContent) {
                                const response = await fetch(filepath);
                                if (response.ok) {
                                    content = await response.text();
                                } else {
                                    continue;
                                }
                            } else {
                                // Just create a reference - extract direct parent folder from path
                                const folderMatch = filepath.match(/\/([^\/]+)\/[^\/]+$/);
                                const folder = folderMatch ? folderMatch[1] : 'root';
                                content = `[📎 ${filename} | Folder: ${folder}]`;
                                isReference = true;
                            }
                            
                            const marker = `<!-- FILE:${filename} -->`;
                            const endMarker = `<!-- /END  FILE:${filename} -->`;
                            const editor = document.getElementById('promptEditor');
                            
                            // Add to editor
                            const currentContent = editor.value;
                            const newContent = currentContent 
                                ? currentContent + '\n\n' + marker + '\n' + content + '\n' + endMarker
                                : marker + '\n' + content + '\n' + endMarker;
                            editor.value = newContent;
                            
                            // Track the file
                            editorFiles.set(filename, {
                                id: Date.now(),
                                content: content,
                                marker: marker,
                                isReference: isReference,
                                addedAt: Date.now()
                            });
                            
                            fileItem.classList.add('checked');
                            const checkbox = fileItem.querySelector('input[type="checkbox"]');
                            if (checkbox) checkbox.checked = true;
                            
                            processedCount++;
                        } catch (err) {
                            console.error('Error adding file:', filename, err);
                        }
                    } else if (!checked && isCurrentlyChecked) {
                        // Remove file from editor
                        removeFileFromEditor(filename);
                        fileItem.classList.remove('checked');
                        const checkbox = fileItem.querySelector('input[type="checkbox"]');
                        if (checkbox) checkbox.checked = false;
                        processedCount++;
                    }
                }
            }
            
            updateCounts();
            loadUploadedFiles(); // Re-render to update folder states
            
            if (checked) {
                const modeText = sendFullContent ? 'with full content' : 'as references';
                showToast(`✅ ${processedCount} item(s) added ${modeText}!`, 'success');
            } else {
                showToast(`📄 ${processedCount} item(s) removed from editor`, 'info');
            }
        }
        
        // Update the "Select All Files" checkbox based on current selection
        function updateSelectAllFilesCheckbox() {
            const checkbox = document.getElementById('selectAllFilesCheckbox');
            if (!checkbox) return;
            
            const fileItems = document.querySelectorAll('.file-item');
            const totalFiles = fileItems.length;
            
            if (totalFiles === 0) {
                checkbox.checked = false;
                checkbox.indeterminate = false;
                return;
            }
            
            let checkedCount = 0;
            fileItems.forEach(item => {
                if (item.classList.contains('checked')) {
                    checkedCount++;
                }
            });
            
            if (checkedCount === 0) {
                checkbox.checked = false;
                checkbox.indeterminate = false;
            } else if (checkedCount === totalFiles) {
                checkbox.checked = true;
                checkbox.indeterminate = false;
            } else {
                checkbox.checked = false;
                checkbox.indeterminate = true;
            }
        }

        // Delete file - removes from server AND from editor
        function deleteFile(id, filename) {
            showConfirmModal({
                title: 'Delete File?',
                message: `Are you sure you want to delete "${filename}"?`,
                details: `<span class="file-count">1</span> file will be removed from the list and editor`,
                icon: 'fa-file-times',
                type: 'warning',
                confirmText: 'Delete File',
                confirmIcon: 'fa-trash-alt',
                onConfirm: async () => {
                    // Remove from editor first (instant feedback)
                    removeFileFromEditor(filename);
                    
                    // Then delete from server
                    try {
                        const formData = new FormData();
                        formData.append('action', 'delete_file');
                        formData.append('id', id);
                        
                        const response = await fetch('', {
                            method: 'POST',
                            body: formData
                        });
                        
                        const data = await response.json();
                        
                        if (data.success) {
                            showToast('✅ File deleted!', 'success');
                            loadUploadedFiles();
                        }
                    } catch (err) {
                        showToast('Delete from server failed!', 'error');
                    }
                }
            });
        }
        
        // Delete ALL files - removes all from server AND from editor
        async function deleteAllFiles() {
            // Get file count from the displayed list
            const filesCountEl = document.getElementById('filesCount');
            const displayedCount = parseInt(filesCountEl?.textContent || '0');
            const editorCount = editorFiles.size;
            const folderCount = knownFolders.size;
            const totalCount = Math.max(displayedCount, editorCount + folderCount);
            
            if (totalCount === 0) {
                showToast('No files or folders to delete', 'info');
                return;
            }
            
            showConfirmModal({
                title: 'Delete All Files & Folders?',
                message: 'This action cannot be undone. All files and folders will be permanently removed.',
                details: `<span class="file-count">${totalCount}</span> item(s) will be deleted from the list<br>and their content removed from the editor`,
                icon: 'fa-trash-alt',
                type: 'danger',
                confirmText: 'Delete All',
                confirmIcon: 'fa-trash-alt',
                onConfirm: async () => {
                    // Remove all folders from editor first
                    const folderNames = Array.from(editorFolders.keys());
                    for (const folderName of folderNames) {
                        removeFolderFromEditor(folderName);
                    }
                    editorFolders.clear();
                    knownFolders.clear();
                    
                    // Remove all files from editor (instant feedback)
                    const filenames = Array.from(editorFiles.keys());
                    for (const filename of filenames) {
                        removeFileFromEditor(filename);
                    }
                    
                    // Clear the editorFiles map
                    editorFiles.clear();
                    
                    // Delete all from server
                    try {
                        const formData = new FormData();
                        formData.append('action', 'get_files');
                        
                        const response = await fetch('', {
                            method: 'POST',
                            body: formData
                        });
                        
                        const data = await response.json();
                        
                        if (data.success && data.files) {
                            // Delete each file from server
                            for (const file of data.files) {
                                const deleteForm = new FormData();
                                deleteForm.append('action', 'delete_file');
                                deleteForm.append('id', file.id);
                                await fetch('', { method: 'POST', body: deleteForm });
                            }
                        }
                        
                        showToast(`✅ All ${totalCount} file(s) deleted!`, 'success');
                        loadUploadedFiles();
                        
                    } catch (err) {
                        console.error('Delete all error:', err);
                        showToast('Some files may not have been deleted from server', 'error');
                        loadUploadedFiles();
                    }
                }
            });
        }

        // Format file size
        function formatFileSize(bytes) {
            if (bytes === 0) return '0 Bytes';
            const k = 1024;
            const sizes = ['Bytes', 'KB', 'MB', 'GB'];
            const i = Math.floor(Math.log(bytes) / Math.log(k));
            return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
        }

        // Open save modal
        function openSaveModal(id = null, title = '', content = null) {
            const modal = document.getElementById('saveModal');
            const titleInput = document.getElementById('promptTitle');
            const contentInput = document.getElementById('promptContent');
            const editIdInput = document.getElementById('editPromptId');
            
            if (id) {
                editIdInput.value = id;
                titleInput.value = title;
                contentInput.value = content;
                document.querySelector('#saveModal h3').innerHTML = '<i class="fas fa-edit"></i> Edit Prompt';
            } else {
                editIdInput.value = '';
                titleInput.value = '';
                contentInput.value = document.getElementById('promptEditor').value;
                document.querySelector('#saveModal h3').innerHTML = '<i class="fas fa-save"></i> Save Prompt';
            }
            
            modal.classList.add('active');
        }

        // Close modal
        function closeModal(id) {
            document.getElementById(id).classList.remove('active');
        }

        // Save prompt
        async function savePrompt() {
            const title = document.getElementById('promptTitle').value.trim();
            const content = document.getElementById('promptContent').value.trim();
            const editId = document.getElementById('editPromptId').value;
            
            if (!title || !content) {
                showToast('Title and content required!', 'error');
                return;
            }
            
            try {
                const formData = new FormData();
                formData.append('action', editId ? 'update_prompt' : 'save_prompt');
                formData.append('title', title);
                formData.append('content', content);
                if (editId) formData.append('id', editId);
                
                const response = await fetch('', {
                    method: 'POST',
                    body: formData
                });
                
                const data = await response.json();
                
                if (data.success) {
                    // Record operation speed
                    if (data.operationTime) {
                        addSpeedEntry({
                            time: data.operationTime,
                            type: data.operationType || (editId ? 'UPDATE' : 'ADD'),
                            connection: data.connectionType || currentConnectionType,
                            timestamp: Date.now()
                        });
                        updateSpeedMonitor();
                    }
                    showToast(`${data.message} ⏱️ ${data.operationTime}ms`, 'success');
                    closeModal('saveModal');
                    loadSavedPrompts();
                } else {
                    showToast(data.message || 'Save failed!', 'error');
                }
            } catch (err) {
                showToast('Save error!', 'error');
            }
        }

        // Open Save Template Modal
        function openSaveTemplateModal() {
            const modal = document.getElementById('saveTemplateModal');
            const nameInput = document.getElementById('templateNameInput');
            const contentInput = document.getElementById('templateContentInput');
            
            nameInput.value = '';
            contentInput.value = document.getElementById('promptEditor').value;
            modal.classList.add('active');
            setTimeout(() => nameInput.focus(), 100);
        }

        // Save as Template
        async function saveTemplate() {
            const name = document.getElementById('templateNameInput').value.trim();
            const content = document.getElementById('templateContentInput').value.trim();
            
            if (!name || !content) {
                showToast('Name and content required!', 'error');
                return;
            }
            
            try {
                const formData = new FormData();
                formData.append('action', 'add_template');
                formData.append('name', name);
                formData.append('content', content);
                
                const response = await fetch(window.location.href, {
                    method: 'POST',
                    body: formData
                });
                
                const data = await response.json();
                
                if (data.success) {
                    if (data.operationTime) {
                        addSpeedEntry({
                            time: data.operationTime,
                            type: data.operationType || 'ADD_TEMPLATE',
                            connection: data.connectionType || currentConnectionType,
                            timestamp: Date.now()
                        });
                        updateSpeedMonitor();
                    }
                    showToast(`${data.message} \u23f1\ufe0f ${data.operationTime}ms`, 'success');
                    closeModal('saveTemplateModal');
                    loadPromptTemplates();
                } else {
                    showToast(data.message || 'Save failed!', 'error');
                }
            } catch (err) {
                showToast('Save error!', 'error');
            }
        }

        // Load saved prompts
        async function loadSavedPrompts(search = '') {
            try {
                const formData = new FormData();
                formData.append('action', 'get_prompts');
                formData.append('search', search);
                
                const response = await fetch('', {
                    method: 'POST',
                    body: formData
                });
                
                const data = await response.json();
                const container = document.getElementById('savedList');
                const clearBtn = document.getElementById('savedSearchClear');
                
                // Show/hide clear button
                if (clearBtn) {
                    clearBtn.style.display = search ? 'flex' : 'none';
                }
                
                if (data.success && data.prompts.length > 0) {
                    // Store prompts in the global array
                    savedPromptsList = data.prompts.map(p => ({
                        id: parseInt(p.id),
                        title: p.title,
                        content: p.content,
                        created_at: p.created_at
                    }));
                    
                    renderSavedPrompts(search);
                } else {
                    savedPromptsList = [];
                    container.innerHTML = `
                        <div class="empty-state">
                            <i class="fas fa-inbox"></i>
                            <p>No saved prompts yet</p>
                        </div>
                    `;
                    updateSavedCounter();
                    setTimeout(updateSavedScrollbar, 100);
                }
            } catch (err) {
                console.error('Error loading prompts:', err);
            }
        }
        
        // Render saved prompts with checkbox style (like prompt templates)
        function renderSavedPrompts(searchTerm = '') {
            const container = document.getElementById('savedList');
            const searchLower = searchTerm.toLowerCase().trim();
            
            // Filter prompts based on search
            const filteredPrompts = searchLower 
                ? savedPromptsList.filter(p => 
                    p.title.toLowerCase().includes(searchLower) || 
                    p.content.toLowerCase().includes(searchLower)
                )
                : savedPromptsList;
            
            if (filteredPrompts.length === 0) {
                container.innerHTML = `
                    <div class="empty-state">
                        <i class="fas fa-search"></i>
                        <p>No prompts found</p>
                    </div>
                `;
                updateSavedCounter();
                return;
            }
            
            container.innerHTML = filteredPrompts.map(prompt => {
                const isChecked = activeSavedPrompts.has(prompt.id);
                const highlightedTitle = searchLower 
                    ? highlightText(prompt.title, searchLower)
                    : prompt.title;
                const contentPreview = prompt.content.replace(/\n/g, ' ').substring(0, 50) + '...';
                
                return `
                    <div class="saved-item ${isChecked ? 'checked' : ''}" data-id="${prompt.id}">
                        <div class="saved-item-checkbox" onclick="toggleSavedPrompt(${prompt.id})">
                            <input type="checkbox" ${isChecked ? 'checked' : ''}>
                            <div class="checkbox-box"><i class="fas fa-check"></i></div>
                        </div>
                        <div class="saved-item-content" onclick="openSavedPreview(${prompt.id})">
                            <div class="saved-item-name">${highlightedTitle}</div>
                            <div class="saved-item-preview">${escapeHtmlDisplay(contentPreview)}</div>
                            <div class="saved-item-date">${formatDate(prompt.created_at)}</div>
                        </div>
                        <div class="saved-item-actions">
                            <button type="button" class="saved-action-icon copy" onclick="copySavedPrompt(${prompt.id})" title="Copy">
                                <i class="fas fa-copy"></i>
                            </button>
                            <button type="button" class="saved-action-icon push" onclick="pushToEditor(${prompt.id})" title="Push to Editor">
                                <i class="fas fa-arrow-down"></i>
                            </button>
                            <button type="button" class="saved-action-icon pull" onclick="pullToSavedPrompt(${prompt.id})" title="Pull from Editor">
                                <i class="fas fa-arrow-up"></i>
                            </button>
                            <button type="button" class="saved-action-icon edit" onclick="editSavedPrompt(${prompt.id})" title="Edit">
                                <i class="fas fa-edit"></i>
                            </button>
                            <button type="button" class="saved-action-icon delete" onclick="deletePrompt(${prompt.id})" title="Delete">
                                <i class="fas fa-trash"></i>
                            </button>
                        </div>
                    </div>
                `;
            }).join('');
            
            updateSavedCounter();
            
            // Update scrollbar after content change
            setTimeout(updateSavedScrollbar, 100);
        }
        
        // Escape HTML for display (without breaking newlines)
        function escapeHtmlDisplay(str) {
            if (!str) return '';
            const div = document.createElement('div');
            div.textContent = str;
            return div.innerHTML;
        }
        
        // Toggle saved prompt in editor
        function toggleSavedPrompt(id) {
            const prompt = savedPromptsList.find(p => p.id === id);
            if (!prompt) return;
            
            const savedItem = document.querySelector(`.saved-item[data-id="${id}"]`);
            const editor = document.getElementById('promptEditor');
            
            if (activeSavedPrompts.has(id)) {
                activeSavedPrompts.delete(id);
                if (savedItem) {
                    savedItem.classList.remove('checked');
                    const checkbox = savedItem.querySelector('input[type="checkbox"]');
                    if (checkbox) checkbox.checked = false;
                }
                rebuildEditorFromSaved();
                showToast(`"${prompt.title}" removed`, 'info');
            } else {
                activeSavedPrompts.add(id);
                if (savedItem) {
                    savedItem.classList.add('checked');
                    const checkbox = savedItem.querySelector('input[type="checkbox"]');
                    if (checkbox) checkbox.checked = true;
                }
                
                // Append to editor
                if (editor.value.trim()) {
                    editor.value += '\n\n' + prompt.content;
                } else {
                    editor.value = prompt.content;
                }
                
                showToast(`"${prompt.title}" added`, 'success');
            }
            
            updateCounts();
            updateSavedCounter();
            updateSelectAllSavedCheckbox();
            recordHistoryState(true); // Record saved prompt toggle in history
        }
        
        // Custom Scrollbar for Saved Prompts
        let savedScrollbar = {
            list: null,
            track: null,
            thumb: null,
            isDragging: false,
            startX: 0,
            startScrollLeft: 0
        };
        
        function updateSavedScrollbar() {
            const list = savedScrollbar.list || document.getElementById('savedList');
            const track = savedScrollbar.track || document.getElementById('savedScrollbarTrack');
            const thumb = savedScrollbar.thumb || document.getElementById('savedScrollbarThumb');
            
            if (!list || !track || !thumb) return;
            
            // Store references
            savedScrollbar.list = list;
            savedScrollbar.track = track;
            savedScrollbar.thumb = thumb;
            
            // Wait a frame for proper dimensions
            requestAnimationFrame(() => {
                const listWidth = list.scrollWidth;
                const viewWidth = list.clientWidth;
                const trackWidth = track.clientWidth;
                
                console.log('Scrollbar update:', { listWidth, viewWidth, trackWidth });
                
                // Check if scrolling is needed
                if (listWidth <= viewWidth || listWidth === 0 || trackWidth === 0) {
                    track.style.opacity = '0.3';
                    thumb.style.width = '100%';
                    thumb.style.left = '0px';
                    return;
                }
                
                track.style.opacity = '1';
                
                // Calculate thumb width (proportional to visible area)
                const ratio = viewWidth / listWidth;
                const thumbWidth = Math.max(60, Math.min(trackWidth - 20, ratio * trackWidth));
                thumb.style.width = thumbWidth + 'px';
                
                // Calculate thumb position
                const maxScroll = listWidth - viewWidth;
                const scrollRatio = maxScroll > 0 ? (list.scrollLeft / maxScroll) : 0;
                const maxThumbLeft = trackWidth - thumbWidth;
                const thumbLeft = Math.max(0, Math.min(maxThumbLeft, scrollRatio * maxThumbLeft));
                thumb.style.left = thumbLeft + 'px';
            });
        }
        
        (function initSavedScrollbar() {
            document.addEventListener('DOMContentLoaded', () => {
                const list = document.getElementById('savedList');
                const track = document.getElementById('savedScrollbarTrack');
                const thumb = document.getElementById('savedScrollbarThumb');
                
                if (!list || !track || !thumb) return;
                
                savedScrollbar.list = list;
                savedScrollbar.track = track;
                savedScrollbar.thumb = thumb;
                
                // Sync list scroll when dragging thumb
                function onThumbMouseDown(e) {
                    e.preventDefault();
                    e.stopPropagation();
                    savedScrollbar.isDragging = true;
                    savedScrollbar.startX = e.clientX;
                    savedScrollbar.startScrollLeft = list.scrollLeft;
                    thumb.classList.add('dragging');
                    document.body.style.userSelect = 'none';
                    document.body.style.cursor = 'grabbing';
                }
                
                function onMouseMove(e) {
                    if (!savedScrollbar.isDragging) return;
                    
                    const deltaX = e.clientX - savedScrollbar.startX;
                    const trackWidth = track.clientWidth;
                    const thumbWidth = thumb.clientWidth;
                    const maxThumbLeft = trackWidth - thumbWidth;
                    const listWidth = list.scrollWidth;
                    const viewWidth = list.clientWidth;
                    const maxScroll = listWidth - viewWidth;
                    
                    if (maxThumbLeft > 0) {
                        const scrollDelta = (deltaX / maxThumbLeft) * maxScroll;
                        list.scrollLeft = savedScrollbar.startScrollLeft + scrollDelta;
                    }
                }
                
                function onMouseUp() {
                    if (savedScrollbar.isDragging) {
                        savedScrollbar.isDragging = false;
                        thumb.classList.remove('dragging');
                        document.body.style.userSelect = '';
                        document.body.style.cursor = '';
                    }
                }
                
                // Click on track to jump
                function onTrackClick(e) {
                    if (e.target === thumb) return;
                    
                    const trackRect = track.getBoundingClientRect();
                    const clickX = e.clientX - trackRect.left;
                    const trackWidth = track.clientWidth;
                    const thumbWidth = thumb.clientWidth;
                    const listWidth = list.scrollWidth;
                    const viewWidth = list.clientWidth;
                    const maxScroll = listWidth - viewWidth;
                    
                    if (maxScroll <= 0) return;
                    
                    const targetRatio = Math.max(0, Math.min(1, (clickX - thumbWidth / 2) / (trackWidth - thumbWidth)));
                    const targetScroll = targetRatio * maxScroll;
                    
                    list.scrollTo({
                        left: targetScroll,
                        behavior: 'smooth'
                    });
                }
                
                // Event listeners
                thumb.addEventListener('mousedown', onThumbMouseDown);
                document.addEventListener('mousemove', onMouseMove);
                document.addEventListener('mouseup', onMouseUp);
                track.addEventListener('click', onTrackClick);
                
                // Update on list scroll
                list.addEventListener('scroll', updateSavedScrollbar);
                
                // Update on window resize
                window.addEventListener('resize', updateSavedScrollbar);
                
                // Initial update with delays
                setTimeout(updateSavedScrollbar, 200);
                setTimeout(updateSavedScrollbar, 500);
                setTimeout(updateSavedScrollbar, 1000);
                
                // MutationObserver for content changes
                const observer = new MutationObserver(() => {
                    setTimeout(updateSavedScrollbar, 50);
                });
                observer.observe(list, { childList: true, subtree: true });
            });
        })();
        
        /* ═══════ Static Nodes Scrollbar ═══════ */
        const staticScrollbar = {
            list: null,
            track: null,
            thumb: null,
            isDragging: false,
            startX: 0,
            startScrollLeft: 0
        };
        
        function updateStaticScrollbar() {
