<script>
// ════════════════════════════════════════════════════════════════
// PROJECT MANAGEMENT FUNCTIONS
// ════════════════════════════════════════════════════════════════

let currentProjectId = null;
let selectedProjectToLoad = null;
let projectToDelete = null;

// ════════════════════════════════════════════════════════════════
// PROPAGATE FUNCTIONALITY (Manual sync between pages)
// ════════════════════════════════════════════════════════════════

let propagateChannelPM = null;

try {
    propagateChannelPM = new BroadcastChannel('prompt_manager_propagate');
    
    // Listen for propagate messages from other page
    propagateChannelPM.onmessage = function(event) {
        const data = event.data;
        
        if (data.type === 'propagate' && data.source !== 'prompt_manager') {
            console.log('📡 Received propagate from Design Enhancer:', data);
            
            // Apply the received state
            applyPropagatedDataPM(data);
            
            showToast('✅ Data received from Design Enhancer!', 'success');
        }
    };
    
    console.log('📡 Propagate channel connected');
} catch (e) {
    console.log('BroadcastChannel not supported');
}

// Propagate all data to the other page
function propagateToOtherPagePM() {
    if (!propagateChannelPM) {
        showToast('❌ Sync not available. Make sure Design Enhancer is open.', 'error');
        return;
    }
    
    // Collect all current data from dashboard
    const dashboardData = collectDashboardData();
    
    const propagateData = {
        type: 'propagate',
        source: 'prompt_manager',
        timestamp: Date.now(),
        
        // Project selection
        currentProject: currentProjectId,
        
        // Dashboard items
        backend: dashboardData.backends || [],
        page: dashboardData.pages || [],
        frontend: dashboardData.frontends || [],
        
        // Database selection
        database: {
            selected: dashboardData.database_name || '',
            remoteCredentials: dashboardData.include_remote == 1,
            localhostCredentials: dashboardData.include_localhost == 1
        },
        
        // Prompt editor content
        promptContent: document.getElementById('promptEditor')?.value || ''
    };
    
    // Send to other page
    propagateChannelPM.postMessage(propagateData);
    
    showToast('📤 Data sent to Design Enhancer!', 'success');
    console.log('📤 Propagated data:', propagateData);
}

// Apply received propagate data
function applyPropagatedDataPM(data) {
    // DON'T reset dashboard - just apply the items
    // This preserves the database dropdown
    
    // Clear only the dynamic items (not checkboxes/database)
    if (typeof dynamicItems !== 'undefined') {
        dynamicItems.backend = [];
        dynamicItems.page = [];
        dynamicItems.frontend = [];
    }
    
    // Clear items HTML
    ['backend', 'page', 'frontend'].forEach(type => {
        const grid = document.getElementById(type + 'ItemsGrid');
        if (grid) {
            const emptyStates = {
                'backend': '<div class="dynamic-empty-state" id="backendEmptyState"><i class="fas fa-file-code"></i><p>No backend items</p><small>Click "Add" to create one</small></div>',
                'page': '<div class="dynamic-empty-state" id="pageEmptyState"><i class="fas fa-file-alt"></i><p>No page items</p><small>Click "Add" to create one</small></div>',
                'frontend': '<div class="dynamic-empty-state" id="frontendEmptyState"><i class="fas fa-paint-brush"></i><p>No frontend items</p><small>Click "Add" to create one</small></div>'
            };
            grid.innerHTML = emptyStates[type];
        }
        updateDynamicCount(type);
    });
    
    // Apply project selection
    if (data.currentProject) {
        const selector = document.getElementById('projectSelector');
        if (selector) {
            selector.value = data.currentProject;
            currentProjectId = data.currentProject;
        }
    }
    
    // Apply dashboard items - Backend
    if (data.backend && data.backend.length > 0) {
        data.backend.forEach(item => {
            addDynamicItem('backend', item.name || '', item.prompt || item.desc || '');
        });
    }
    
    // Apply dashboard items - Pages
    if (data.page && data.page.length > 0) {
        data.page.forEach(item => {
            addDynamicItem('page', item.name || '', item.prompt || item.desc || '');
        });
    }
    
    // Apply dashboard items - Frontend
    if (data.frontend && data.frontend.length > 0) {
        data.frontend.forEach(item => {
            addDynamicItem('frontend', item.name || '', item.prompt || item.desc || '');
        });
    }
    
    // Apply prompt editor content
    if (data.promptContent !== undefined) {
        const editor = document.getElementById('promptEditor');
        if (editor) {
            editor.value = data.promptContent;
        }
    }
    
    // Reload projects list
    loadProjectsList();
    
    // Refresh database list to ensure it's visible
    if (typeof loadHostingerDatabases === 'function') {
        loadHostingerDatabases();
    }
}

// ════════════════════════════════════════════════════════════════

// Initialize projects on page load
document.addEventListener('DOMContentLoaded', function() {
    loadProjectsList();
});

// Load all projects into selector
function loadProjectsList() {
    const formData = new FormData();
    formData.append('action', 'get_projects');
    
    fetch(window.location.href, {
        method: 'POST',
        body: formData
    })
    .then(res => res.json())
    .then(data => {
        if (data.success && data.projects) {
            updateProjectSelector(data.projects);
        }
    })
    .catch(err => console.error('Error loading projects:', err));
}

// Update project selector dropdown
function updateProjectSelector(projects) {
    const selector = document.getElementById('projectSelector');
    if (!selector) return;
    
    selector.innerHTML = '<option value="">-- No Project --</option>';
    
    projects.forEach(project => {
        const option = document.createElement('option');
        option.value = project.id;
        option.textContent = project.name;
        if (project.id == currentProjectId) {
            option.selected = true;
        }
        selector.appendChild(option);
    });
}

// Open new project popup
function openNewProjectPopup() {
    // Reset current project ID
    currentProjectId = null;
    
    // Reset the project selector dropdown
    const selector = document.getElementById('projectSelector');
    if (selector) selector.value = '';
    
    // Reset the dashboard to empty state
    resetDashboardItems();
    
    // Clear popup fields
    document.getElementById('projectEditId').value = '';
    document.getElementById('projectNameInput').value = '';
    document.getElementById('projectDescInput').value = '';
    document.getElementById('projectPopupTitle').textContent = 'New Project';
    
    // Show popup
    const popup = document.getElementById('newProjectPopup');
    popup.classList.add('active');
    document.getElementById('projectNameInput').focus();
}

// Close popup
function closeProjectPopup(popupId) {
    const popup = document.getElementById(popupId);
    popup.classList.remove('active');
}

// Save project from popup
function saveProjectFromPopup() {
    const id = document.getElementById('projectEditId').value;
    const name = document.getElementById('projectNameInput').value.trim();
    const description = document.getElementById('projectDescInput').value.trim();
    
    if (!name) {
        showToast('Please enter a project name', 'error');
        document.getElementById('projectNameInput').focus();
        return;
    }
    
    // Collect current dashboard data
    const projectData = collectDashboardData();
    projectData.id = id;
    projectData.name = name;
    projectData.description = description;
    
    saveProject(projectData);
}

// Save as new project — opens popup for user to enter a name, keeps dashboard data intact
function saveAsNewProject() {
    // Get current project name as suggestion
    const selector = document.getElementById('projectSelector');
    const selectedOption = selector.options[selector.selectedIndex];
    const baseName = (selectedOption && selectedOption.value) ? selectedOption.textContent.trim() : '';

    // Open popup in "Save New" mode — empty ID so it creates a new project
    document.getElementById('projectEditId').value = '';
    document.getElementById('projectNameInput').value = baseName ? baseName + ' (Copy)' : '';
    document.getElementById('projectDescInput').value = '';
    document.getElementById('projectPopupTitle').textContent = 'Save as New Project';

    const popup = document.getElementById('newProjectPopup');
    popup.classList.add('active');
    
    // Select the name text so user can easily overwrite
    const nameInput = document.getElementById('projectNameInput');
    nameInput.focus();
    nameInput.select();
}

// Rename current project — opens popup to change name only
function renameCurrentProject() {
    if (!currentProjectId) {
        showToast('⚠️ No project selected to rename', 'warning');
        return;
    }

    // Get current project name
    const selector = document.getElementById('projectSelector');
    const selectedOption = selector.options[selector.selectedIndex];
    const currentName = (selectedOption && selectedOption.value) ? selectedOption.textContent.trim() : '';

    // Open popup in "Rename" mode — keep the ID so it updates
    document.getElementById('projectEditId').value = currentProjectId;
    document.getElementById('projectNameInput').value = currentName;
    document.getElementById('projectDescInput').value = '';
    document.getElementById('projectPopupTitle').textContent = 'Rename Project';

    const popup = document.getElementById('newProjectPopup');
    popup.classList.add('active');

    const nameInput = document.getElementById('projectNameInput');
    nameInput.focus();
    nameInput.select();
}

// Save current project (quick save)
function saveCurrentProject() {
    if (!currentProjectId) {
        openNewProjectPopup();
        return;
    }
    
    const projectData = collectDashboardData();
    projectData.id = currentProjectId;
    
    // Get current project name
    const selector = document.getElementById('projectSelector');
    const selectedOption = selector.options[selector.selectedIndex];
    projectData.name = selectedOption ? selectedOption.textContent : 'Untitled Project';
    
    saveProject(projectData);
}

// Collect all data from dashboard
function collectDashboardData() {
    const data = {
        // Database info
        database_id: '',
        database_name: document.getElementById('dbDropdown')?.value || '',
        database_host: '',
        database_user: '',
        database_pass: '',
        database_port: '3306',
        include_remote: document.getElementById('remoteCheckbox')?.checked ? 1 : 0,
        include_localhost: document.getElementById('localhostCheckbox')?.checked ? 1 : 0,
        
        // Project notes
        project_notes: getProjectNotes(),
        
        // Language settings
        language_settings: JSON.stringify(appLanguageSettings),
        
        // Folder template data
        folder_data: ftSerializeFolderStore(),
        
        // Items - use dynamicItems object which has all the data including prompts and files
        backends: [],
        pages: [],
        frontends: []
    };
    
    // Use the dynamicItems object which properly stores name, prompt, and files
    if (typeof dynamicItems !== 'undefined') {
        // Collect backend items from dynamicItems object
        data.backends = dynamicItems.backend.map(item => ({
            id: item.id,
            name: item.name || '',
            prompt: item.prompt || '',
            files: (item.files || []).map(f => {
                // Handle both File objects and file info objects
                if (f instanceof File) {
                    return { name: f.name, size: f.size, type: f.type };
                }
                return f;
            })
        }));
        
        // Collect page items from dynamicItems object
        data.pages = dynamicItems.page.map(item => ({
            id: item.id,
            name: item.name || '',
            prompt: item.prompt || '',
            files: (item.files || []).map(f => {
                if (f instanceof File) {
                    return { name: f.name, size: f.size, type: f.type };
                }
                return f;
            })
        }));
        
        // Collect frontend items from dynamicItems object
        data.frontends = dynamicItems.frontend.map(item => ({
            id: item.id,
            name: item.name || '',
            prompt: item.prompt || '',
            files: (item.files || []).map(f => {
                if (f instanceof File) {
                    return { name: f.name, size: f.size, type: f.type };
                }
                return f;
            })
        }));
    }
    
    console.log('📦 Collected dashboard data:', data);
    return data;
}

// Save project to database
function saveProject(projectData) {
    const formData = new FormData();
    formData.append('action', 'save_project');
    formData.append('id', projectData.id || '');
    formData.append('name', projectData.name);
    formData.append('description', projectData.description || '');
    formData.append('database_id', projectData.database_id || '');
    formData.append('database_name', projectData.database_name || '');
    formData.append('database_host', projectData.database_host || '');
    formData.append('database_user', projectData.database_user || '');
    formData.append('database_pass', projectData.database_pass || '');
    formData.append('database_port', projectData.database_port || '3306');
    formData.append('include_remote', projectData.include_remote || 0);
    formData.append('include_localhost', projectData.include_localhost || 0);
    formData.append('backends', JSON.stringify(projectData.backends || []));
    formData.append('pages', JSON.stringify(projectData.pages || []));
    formData.append('frontends', JSON.stringify(projectData.frontends || []));
    formData.append('project_notes', projectData.project_notes || '');
    formData.append('language_settings', projectData.language_settings || JSON.stringify(appLanguageSettings));
    formData.append('folder_data', projectData.folder_data || '[]');
    // Include prompt editor content
    const promptEditor = document.getElementById('promptEditor');
    formData.append('prompt_content', promptEditor ? promptEditor.value : '');
    
    fetch(window.location.href, {
        method: 'POST',
        body: formData
    })
    .then(res => res.json())
    .then(data => {
        if (data.success) {
            currentProjectId = data.id;
            showToast(data.message, 'success');
            closeProjectPopup('newProjectPopup');
            loadProjectsList();
            
            // Log operation time to speed monitor
            if (data.operationTime) {
                addSpeedEntry({ 
                    time: parseFloat(data.operationTime), 
                    type: data.operationType, 
                    connection: data.connectionType, 
                    timestamp: Date.now() 
                });
                updateSpeedMonitor();
            }
        } else {
            showToast(data.message || 'Error saving project', 'error');
        }
    })
    .catch(err => {
        console.error('Error saving project:', err);
        showToast('Error saving project', 'error');
    });
}

// Open load project popup
function openLoadProjectPopup() {
    const formData = new FormData();
    formData.append('action', 'get_projects');
    
    fetch(window.location.href, {
        method: 'POST',
        body: formData
    })
    .then(res => res.json())
    .then(data => {
        const container = document.getElementById('projectListContainer');
        container.innerHTML = '';
        selectedProjectToLoad = null;
        document.getElementById('loadProjectBtn').disabled = true;
        
        if (data.success && data.projects && data.projects.length > 0) {
            data.projects.forEach(project => {
                const item = document.createElement('div');
                item.className = 'project-list-item';
                item.dataset.id = project.id;
                item.onclick = () => selectProjectToLoad(project.id, item);
                
                const date = new Date(project.updated_at);
                const dateStr = date.toLocaleDateString('en-US', { 
                    month: 'short', day: 'numeric', year: 'numeric' 
                });
                
                item.innerHTML = `
                    <div class="project-list-info">
                        <div class="project-list-name">${escapeHtml(project.name)}</div>
                        <div class="project-list-date">Updated: ${dateStr}</div>
                    </div>
                `;
                container.appendChild(item);
            });
        } else {
            container.innerHTML = `
                <div class="project-list-empty">
                    <i class="fas fa-folder-open"></i>
                    <p>No projects saved yet</p>
                </div>
            `;
        }
        
        document.getElementById('loadProjectPopup').classList.add('active');
    })
    .catch(err => {
        console.error('Error loading projects:', err);
        showToast('Error loading projects', 'error');
    });
}

// Select project to load
function selectProjectToLoad(id, element) {
    document.querySelectorAll('.project-list-item').forEach(item => {
        item.classList.remove('selected');
    });
    element.classList.add('selected');
    selectedProjectToLoad = id;
    document.getElementById('loadProjectBtn').disabled = false;
}

// Load selected project
function loadSelectedProject() {
    if (!selectedProjectToLoad) return;
    
    const formData = new FormData();
    formData.append('action', 'get_project');
    formData.append('id', selectedProjectToLoad);
    
    fetch(window.location.href, {
        method: 'POST',
        body: formData
    })
    .then(res => res.json())
    .then(data => {
        if (data.success && data.project) {
            applyProjectToDashboard(data.project);
            currentProjectId = data.project.id;
            closeProjectPopup('loadProjectPopup');
            showToast('Project loaded successfully!', 'success');
            
            // Update selector
            loadProjectsList();
        } else {
            showToast(data.message || 'Error loading project', 'error');
        }
    })
    .catch(err => {
        console.error('Error loading project:', err);
        showToast('Error loading project', 'error');
    });
}

// Apply project data to dashboard
function applyProjectToDashboard(project) {
    console.log('📥 Applying project to dashboard:', project);
    
    // Reset first - clears dynamicItems and HTML
    resetDashboardItems();
    
    // Set database
    if (project.database_name) {
        const dbDropdown = document.getElementById('dbDropdown');
        if (dbDropdown) {
            // Try to find and select the matching option
            for (let i = 0; i < dbDropdown.options.length; i++) {
                if (dbDropdown.options[i].value === project.database_name) {
                    dbDropdown.selectedIndex = i;
                    break;
                }
            }
        }
    }
    
    // Set checkboxes
    const remoteChk = document.getElementById('remoteCheckbox');
    const localChk = document.getElementById('localhostCheckbox');
    if (remoteChk) remoteChk.checked = project.include_remote == 1;
    if (localChk) localChk.checked = project.include_localhost == 1;
    
    // Parse backends, pages, frontends if they are strings
    let backends = project.backends;
    let pages = project.pages;
    let frontends = project.frontends;
    
    if (typeof backends === 'string') {
        try { backends = JSON.parse(backends); } catch(e) { backends = []; }
    }
    if (typeof pages === 'string') {
        try { pages = JSON.parse(pages); } catch(e) { pages = []; }
    }
    if (typeof frontends === 'string') {
        try { frontends = JSON.parse(frontends); } catch(e) { frontends = []; }
    }
    
    // Add backend items - use 'prompt' field (not 'desc')
    if (backends && backends.length > 0) {
        backends.forEach(item => {
            const id = addDynamicItemWithData('backend', {
                id: item.id,
                name: item.name || '',
                prompt: item.prompt || item.desc || '', // Support both 'prompt' and legacy 'desc'
                files: item.files || []
            });
        });
    }
    
    // Add page items - use 'prompt' field (not 'desc')
    if (pages && pages.length > 0) {
        pages.forEach(item => {
            addDynamicItemWithData('page', {
                id: item.id,
                name: item.name || '',
                prompt: item.prompt || item.desc || '',
                files: item.files || []
            });
        });
    }
    
    // Add frontend items - use 'prompt' field (not 'desc')
    if (frontends && frontends.length > 0) {
        frontends.forEach(item => {
            addDynamicItemWithData('frontend', {
                id: item.id,
                name: item.name || '',
                prompt: item.prompt || item.desc || '',
                files: item.files || []
            });
        });
    }
    
    // Load project notes/prompts
    if (project.project_notes !== undefined) {
        setProjectNotes(project.project_notes || '');
    }
    
    // Load language settings
    if (project.language_settings) {
        try {
            let langSettings = project.language_settings;
            if (typeof langSettings === 'string') {
                langSettings = JSON.parse(langSettings);
            }
            
            // Apply language settings
            if (langSettings.language) {
                appLanguageSettings.language = langSettings.language;
                appLanguageSettings.defaultLanguage = langSettings.defaultLanguage || 'english';
                appLanguageSettings.multiLanguages = langSettings.multiLanguages || [];
                
                // Update UI - remove active class from all options
                document.querySelectorAll('.lang-option').forEach(opt => {
                    opt.classList.remove('active');
                });
                
                // Add active class to selected option
                const selectedOption = document.querySelector(`.lang-option.${appLanguageSettings.language}`);
                if (selectedOption) {
                    selectedOption.classList.add('active');
                }
                
                // Show/hide default selector (for 'both')
                const defaultSelector = document.getElementById('defaultLangSelector');
                if (appLanguageSettings.language === 'both') {
                    defaultSelector.classList.add('visible');
                } else {
                    defaultSelector.classList.remove('visible');
                }
                
                // Update default language buttons for 'both'
                document.querySelectorAll('.default-lang-btn').forEach(btn => {
                    btn.classList.remove('selected');
                });
                const selectedDefaultBtn = document.querySelector(`.default-lang-btn[data-default="${appLanguageSettings.defaultLanguage}"]`);
                if (selectedDefaultBtn) {
                    selectedDefaultBtn.classList.add('selected');
                }
                
                // Show/hide multi-language selector
                const multiSelector = document.getElementById('multiLangSelector');
                if (appLanguageSettings.language === 'multi') {
                    multiSelector.classList.add('visible');
                    updateMultiLangUI();
                } else {
                    multiSelector.classList.remove('visible');
                }
                
                // Save to localStorage as well
                saveLanguageSettings();
                
                console.log('📌 Language settings loaded from project:', appLanguageSettings);
            }
        } catch (e) {
            console.warn('Could not parse language settings:', e);
        }
    }
    
    // Restore folder template data
    if (project.folder_data) {
        ftDeserializeFolderStore(project.folder_data);
    } else {
        // Clear folder template if no folder data in project
        ftFolderStore.clear();
        ftIdToName.clear();
        ftRenderAll();
    }
    
    // NOTE: We do NOT load prompt_content into the main editor automatically
    // The user must click Generate to populate the Prompt Editor
    // This prevents unwanted content appearing in the editor on project select
    
    showToast('Project data loaded to dashboard', 'success');
}

// On project select from dropdown
function onProjectSelect() {
    const selector = document.getElementById('projectSelector');
    const selectedId = selector.value;
    
    if (!selectedId) {
        currentProjectId = null;
        return;
    }
    
    const formData = new FormData();
    formData.append('action', 'get_project');
    formData.append('id', selectedId);
    
    fetch(window.location.href, {
        method: 'POST',
        body: formData
    })
    .then(res => res.json())
    .then(data => {
        if (data.success && data.project) {
            applyProjectToDashboard(data.project);
            currentProjectId = data.project.id;
            showToast('Project "' + data.project.name + '" loaded', 'info');
        }
    })
    .catch(err => console.error('Error:', err));
}

// Delete current project
function deleteCurrentProject() {
    const selector = document.getElementById('projectSelector');
    const selectedId = selector.value;
    
    if (!selectedId) {
        showToast('Please select a project to delete', 'warning');
        return;
    }
    
    const selectedOption = selector.options[selector.selectedIndex];
    projectToDelete = {
        id: selectedId,
        name: selectedOption.textContent
    };
    
    document.getElementById('deleteProjectName').textContent = '"' + projectToDelete.name + '"';
    document.getElementById('deleteProjectPopup').classList.add('active');
}

// Confirm delete project
function confirmDeleteProject() {
    if (!projectToDelete) return;
    
    const deletedId = projectToDelete.id;
    
    const formData = new FormData();
    formData.append('action', 'delete_project');
    formData.append('id', deletedId);
    
    fetch(window.location.href, {
        method: 'POST',
        body: formData
    })
    .then(res => res.json())
    .then(data => {
        if (data.success) {
            if (currentProjectId == deletedId) {
                currentProjectId = null;
            }
            closeProjectPopup('deleteProjectPopup');
            showToast('Project deleted successfully!', 'success');
            loadProjectsList();
            resetDashboardProject();
            
            if (data.operationTime) {
                addSpeedEntry({ 
                    time: parseFloat(data.operationTime), 
                    type: data.operationType, 
                    connection: data.connectionType, 
                    timestamp: Date.now() 
                });
                updateSpeedMonitor();
            }
        } else {
            showToast(data.message || 'Error deleting project', 'error');
        }
    })
    .catch(err => {
        console.error('Error:', err);
        showToast('Error deleting project', 'error');
    });
}

// Reset dashboard project
function resetDashboardProject() {
    currentProjectId = null;
    document.getElementById('projectSelector').value = '';
    resetDashboardItems();
    clearProjectNotes();
    showToast('Dashboard reset to empty state', 'info');
}

// ── Dashboard Section Checkboxes ──────────────────────────────
function toggleDashMasterCheck() {
    const master = document.getElementById('dashMasterCheckbox');
    master.checked = !master.checked;
    const all = document.querySelectorAll('.dash-sec-cb');
    all.forEach(cb => { cb.checked = master.checked; });
    updateDashMasterCount();
}

function onDashSectionCheckChange() {
    updateDashMasterCount();
}

function updateDashMasterCount() {
    const all = document.querySelectorAll('.dash-sec-cb');
    const checked = document.querySelectorAll('.dash-sec-cb:checked');
    const master = document.getElementById('dashMasterCheckbox');
    const countEl = document.getElementById('dashMasterCount');
    if (countEl) countEl.textContent = checked.length + '/' + all.length;
    if (master) {
        master.checked = checked.length === all.length;
        master.indeterminate = checked.length > 0 && checked.length < all.length;
    }
}

// Project Notes Functions
function toggleProjectNotes() {
    const body = document.getElementById('projectNotesBody');
    const icon = document.getElementById('notesCollapseIcon');
    
    if (body.classList.contains('collapsed')) {
        body.classList.remove('collapsed');
        icon.classList.remove('fa-chevron-down');
        icon.classList.add('fa-chevron-up');
    } else {
        body.classList.add('collapsed');
        icon.classList.remove('fa-chevron-up');
        icon.classList.add('fa-chevron-down');
    }
}

function clearProjectNotes() {
    const textarea = document.getElementById('projectNotesTextarea');
    if (textarea) {
        textarea.value = '';
        saveProjectNotesToStorage();
    }
}

function onProjectNotesChange() {
    saveProjectNotesToStorage();
}

function saveProjectNotesToStorage() {
    const textarea = document.getElementById('projectNotesTextarea');
    if (textarea) {
        localStorage.setItem('project_notes_temp', textarea.value);
    }
}

function loadProjectNotesFromStorage() {
    const textarea = document.getElementById('projectNotesTextarea');
    const saved = localStorage.getItem('project_notes_temp');
    if (textarea && saved) {
        textarea.value = saved;
    }
}

function getProjectNotes() {
    const textarea = document.getElementById('projectNotesTextarea');
    return textarea ? textarea.value.trim() : '';
}

function setProjectNotes(notes) {
    const textarea = document.getElementById('projectNotesTextarea');
    if (textarea) {
        textarea.value = notes || '';
        saveProjectNotesToStorage();
    }
}

// Notes File Picker Functions
let notesSelectedFiles = [];

function onNotesFileSelect() {
    const input = document.getElementById('notesFilePicker');
    const container = document.getElementById('notesSelectedFiles');
    const pushBtn = document.getElementById('notesPushBtn');
    
    if (!input || !input.files || input.files.length === 0) return;
    
    // Add new files to the selection (avoid duplicates)
    Array.from(input.files).forEach(file => {
        if (!notesSelectedFiles.some(f => f.name === file.name)) {
            notesSelectedFiles.push(file);
        }
    });
    
    // Update display
    renderNotesSelectedFiles();
    
    // Show push button if files selected
    if (pushBtn) {
        pushBtn.style.display = notesSelectedFiles.length > 0 ? 'flex' : 'none';
    }
    
    // Reset input so same files can be selected again
    input.value = '';
}

function renderNotesSelectedFiles() {
    const container = document.getElementById('notesSelectedFiles');
    if (!container) return;
    
    if (notesSelectedFiles.length === 0) {
        container.innerHTML = '';
        return;
    }
    
    container.innerHTML = notesSelectedFiles.map((file, index) => `
        <span class="notes-file-tag">
            <i class="fas fa-file"></i>
            <span>${escapeHtml(file.name)}</span>
            <i class="fas fa-times remove-file" onclick="removeNotesFile(${index})" title="Remove"></i>
        </span>
    `).join('');
}

function removeNotesFile(index) {
    notesSelectedFiles.splice(index, 1);
    renderNotesSelectedFiles();
    
    const pushBtn = document.getElementById('notesPushBtn');
    if (pushBtn) {
        pushBtn.style.display = notesSelectedFiles.length > 0 ? 'flex' : 'none';
    }
}

function pushFileNamesToNotes() {
    if (notesSelectedFiles.length === 0) return;
    
    const textarea = document.getElementById('projectNotesTextarea');
    if (!textarea) return;
    
    // Build file names as numbered list
    const fileNames = notesSelectedFiles.map((f, i) => `${i + 1}. ${f.name}`);
    const fileNamesText = '📎 Files:\n' + fileNames.join('\n');
    
    // Append to textarea
    if (textarea.value.trim()) {
        textarea.value = textarea.value.trimEnd() + '\n\n' + fileNamesText;
    } else {
        textarea.value = fileNamesText;
    }
    
    // Save and clear selection
    saveProjectNotesToStorage();
    
    // Show toast
    showToast(`📎 Added ${fileNames.length} file name${fileNames.length > 1 ? 's' : ''} to notes`, 'success');
    
    // Clear selection
    notesSelectedFiles = [];
    renderNotesSelectedFiles();
    
    const pushBtn = document.getElementById('notesPushBtn');
    if (pushBtn) pushBtn.style.display = 'none';
}

// Push Project Prompts content to Main Prompt Editor
function pushNotesToPrompt() {
    const notes = getProjectNotes();
    
    if (!notes) {
        showToast('⚠️ Project Prompts is empty', 'warning');
        return;
    }
    
    const editor = document.getElementById('promptEditor');
    if (!editor) return;
    
    // Append notes to prompt editor
    if (editor.value.trim()) {
        editor.value = editor.value.trimEnd() + '\n\n' + notes;
    } else {
        editor.value = notes;
    }
    
    // Update counts and history
    if (typeof updateCounts === 'function') updateCounts();
    if (typeof recordHistoryState === 'function') recordHistoryState(true);
    
    showToast('📝 Notes pushed to Prompt Editor', 'success');
}

// Initialize resizable notes
function initNotesResize() {
    const resizeHandle = document.getElementById('notesResizeHandle');
    const textarea = document.getElementById('projectNotesTextarea');
    const notesBody = document.getElementById('projectNotesBody');
    
    if (!resizeHandle || !textarea) {
        console.log('Notes resize: elements not found');
        return;
    }
    
    let isResizing = false;
    let startY = 0;
    let startHeight = 0;
    
    // Flag to disable auto-expand after manual resize
    window._notesManuallyResized = false;
    
    // Get max height from CSS (80vh) or use window height as fallback
    const getMaxHeight = () => Math.floor(window.innerHeight * 0.8);
    const minHeight = 0; // Allow collapsing to zero
    
    // Mouse events
    resizeHandle.addEventListener('mousedown', startResize);
    document.addEventListener('mousemove', doResize);
    document.addEventListener('mouseup', stopResize);
    
    // Touch events for mobile
    resizeHandle.addEventListener('touchstart', startResizeTouch, { passive: false });
    document.addEventListener('touchmove', doResizeTouch, { passive: false });
    document.addEventListener('touchend', stopResize);
    
    function startResize(e) {
        e.preventDefault();
        e.stopPropagation();
        isResizing = true;
        startY = e.clientY;
        startHeight = textarea.offsetHeight;
        document.body.style.cursor = 'ns-resize';
        document.body.style.userSelect = 'none';
        resizeHandle.style.color = '#fbbf24';
    }
    
    function startResizeTouch(e) {
        e.preventDefault();
        isResizing = true;
        startY = e.touches[0].clientY;
        startHeight = textarea.offsetHeight;
        resizeHandle.style.color = '#fbbf24';
    }
    
    function doResize(e) {
        if (!isResizing) return;
        e.preventDefault();
        const diff = e.clientY - startY;
        const newHeight = Math.min(Math.max(startHeight + diff, minHeight), getMaxHeight());
        textarea.style.height = newHeight + 'px';
    }
    
    function doResizeTouch(e) {
        if (!isResizing) return;
        e.preventDefault();
        const diff = e.touches[0].clientY - startY;
        const newHeight = Math.min(Math.max(startHeight + diff, minHeight), getMaxHeight());
        textarea.style.height = newHeight + 'px';
    }
    
    function stopResize() {
        if (isResizing) {
            isResizing = false;
            document.body.style.cursor = '';
            document.body.style.userSelect = '';
            resizeHandle.style.color = '';
            // Mark as manually resized so auto-expand won't override
            window._notesManuallyResized = true;
            // Ensure scroll works after manual resize
            textarea.style.overflowY = 'auto';
            // No longer persist height — resets on refresh
        }
    }
    
    // Always start collapsed to one line on page load
    const oneLineHeight = Math.ceil(parseFloat(getComputedStyle(textarea).lineHeight) + parseFloat(getComputedStyle(textarea).paddingTop) + parseFloat(getComputedStyle(textarea).paddingBottom));
    textarea.style.height = oneLineHeight + 'px';
    textarea.style.overflowY = 'hidden';
    window._notesManuallyResized = true;
    localStorage.removeItem('projectNotesHeight');
    
    console.log('Notes resize initialized');
}

// Auto-expand textarea based on content
function autoExpandTextarea(textarea, minHeight = 150, maxHeight = null) {
    if (!textarea) return;
    
    // Get max height (80vh or specified)
    const effectiveMaxHeight = maxHeight || Math.floor(window.innerHeight * 0.8);
    
    // Reset height to auto to get the correct scrollHeight
    textarea.style.height = 'auto';
    
    // Calculate new height
    let newHeight = textarea.scrollHeight;
    
    // Apply constraints
    if (newHeight < minHeight) {
        newHeight = minHeight;
    } else if (newHeight > effectiveMaxHeight) {
        newHeight = effectiveMaxHeight;
        textarea.style.overflowY = 'auto'; // Enable scroll when max reached
    } else {
        textarea.style.overflowY = 'hidden'; // Hide scroll when not needed
    }
    
    textarea.style.height = newHeight + 'px';
}

// Initialize auto-expand for both textareas
function initAutoExpand() {
    const promptEditor = document.getElementById('promptEditor');
    const projectNotes = document.getElementById('projectNotesTextarea');
    
    // Prompt Editor auto-expand
    if (promptEditor) {
        // Initial adjustment
        autoExpandTextarea(promptEditor, 200);
        
        // On input
        promptEditor.addEventListener('input', function() {
            autoExpandTextarea(this, 200);
        });
        
        // On paste (with slight delay to get pasted content)
        promptEditor.addEventListener('paste', function() {
            setTimeout(() => autoExpandTextarea(this, 200), 10);
        });
        
        // On value change (programmatic)
        const originalPromptSetter = Object.getOwnPropertyDescriptor(HTMLTextAreaElement.prototype, 'value').set;
        Object.defineProperty(promptEditor, 'value', {
            set: function(val) {
                originalPromptSetter.call(this, val);
                setTimeout(() => autoExpandTextarea(this, 200), 10);
            },
            get: function() {
                return Object.getOwnPropertyDescriptor(HTMLTextAreaElement.prototype, 'value').get.call(this);
            }
        });
    }
    
    // Project Notes auto-expand (skip if manually resized)
    if (projectNotes) {
        // Initial adjustment (only if not manually resized)
        if (!window._notesManuallyResized) {
            autoExpandTextarea(projectNotes, 150);
        }
        
        // On input — only auto-expand if not manually resized
        projectNotes.addEventListener('input', function() {
            if (!window._notesManuallyResized) {
                autoExpandTextarea(this, 150);
            }
        });
        
        // On paste
        projectNotes.addEventListener('paste', function() {
            if (!window._notesManuallyResized) {
                setTimeout(() => autoExpandTextarea(this, 150), 10);
            }
        });
        
        // On value change (programmatic)
        const originalNotesSetter = Object.getOwnPropertyDescriptor(HTMLTextAreaElement.prototype, 'value').set;
        Object.defineProperty(projectNotes, 'value', {
            set: function(val) {
                originalNotesSetter.call(this, val);
                if (!window._notesManuallyResized) {
                    setTimeout(() => autoExpandTextarea(this, 150), 10);
                }
            },
            get: function() {
                return Object.getOwnPropertyDescriptor(HTMLTextAreaElement.prototype, 'value').get.call(this);
            }
        });
    }
    
    console.log('Auto-expand initialized for textareas');
}

// Initialize notes on page load
document.addEventListener('DOMContentLoaded', function() {
    loadProjectNotesFromStorage();
    initNotesResize();
    initAutoExpand();
});

// Reset only the items (not the project selection)
function resetDashboardItems() {
    // IMPORTANT: Clear the dynamicItems arrays first!
    if (typeof dynamicItems !== 'undefined') {
        dynamicItems.backend = [];
        dynamicItems.page = [];
        dynamicItems.frontend = [];
        saveDynamicItems(); // Save cleared state
    }
    
    // Clear backend items HTML
    const backendGrid = document.getElementById('backendItemsGrid');
    if (backendGrid) {
        backendGrid.innerHTML = `
            <div class="dynamic-empty-state" id="backendEmptyState">
                <i class="fas fa-file-code"></i>
                <p>No backend items</p>
                <small>Click "Add" to create one</small>
            </div>
        `;
    }
    updateDynamicCount('backend');
    
    // Clear page items HTML
    const pageGrid = document.getElementById('pageItemsGrid');
    if (pageGrid) {
        pageGrid.innerHTML = `
            <div class="dynamic-empty-state" id="pageEmptyState">
                <i class="fas fa-file-alt"></i>
                <p>No page items</p>
                <small>Click "Add" to create one</small>
            </div>
        `;
    }
    updateDynamicCount('page');
    
    // Clear frontend items HTML
    const frontendGrid = document.getElementById('frontendItemsGrid');
    if (frontendGrid) {
        frontendGrid.innerHTML = `
            <div class="dynamic-empty-state" id="frontendEmptyState">
                <i class="fas fa-paint-brush"></i>
                <p>No frontend items</p>
                <small>Click "Add" to create one</small>
            </div>
        `;
    }
    updateDynamicCount('frontend');
    
    // Reset checkboxes
    const remoteChk = document.getElementById('remoteCheckbox');
    const localChk = document.getElementById('localhostCheckbox');
    if (remoteChk) remoteChk.checked = false;
    if (localChk) localChk.checked = false;
    
    // Reset database dropdown
    const dbDropdown = document.getElementById('dbDropdown');
    if (dbDropdown) dbDropdown.selectedIndex = 0;
    
    // Clear folder template
    if (typeof ftFolderStore !== 'undefined') {
        ftFolderStore.clear();
        ftIdToName.clear();
        ftRenderAll();
    }
}

// Helper: Escape HTML
function escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// Close popups on Escape key
document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape') {
        document.querySelectorAll('.project-popup-overlay.active').forEach(popup => {
            popup.classList.remove('active');
        });
    }
});

// Close popup when clicking outside
document.querySelectorAll('.project-popup-overlay').forEach(overlay => {
    overlay.addEventListener('click', function(e) {
        if (e.target === this) {
            this.classList.remove('active');
        }
    });
});
</script>
<!-- End Project Management Popups -->

<!-- Draggable Resizable Iframe Popup -->
<div class="iframe-popup-overlay" id="iframePopupOverlay">
    <div class="iframe-popup-container" id="iframePopupContainer">
        <div class="iframe-popup-header" id="iframePopupHeader">
            <div class="iframe-popup-title">
                <i class="fas fa-rocket"></i>
                <span>Prompt Studio</span>
            </div>
            <div class="iframe-popup-actions">
                <button type="button" class="iframe-popup-btn" onclick="resetIframePopupSize()" title="Reset Size">
                    <i class="fas fa-compress-arrows-alt"></i>
                </button>
                <button type="button" class="iframe-popup-btn close-btn" onclick="closeIframePopup()" title="Close">
                    <i class="fas fa-times"></i>
                </button>
            </div>
        </div>
        <div class="iframe-popup-body">
            <div class="iframe-popup-loading" id="iframeLoading">
                <i class="fas fa-spinner"></i>
                <span>Loading Prompt Studio...</span>
            </div>
            <iframe id="iframePopupFrame" src="" style="display: none;"></iframe>
        </div>
        <div class="iframe-resize-handle right" data-resize="right"></div>
        <div class="iframe-resize-handle bottom" data-resize="bottom"></div>
        <div class="iframe-resize-handle corner" data-resize="corner"></div>
    </div>
</div>

<script>
// Iframe Popup Functionality
(function() {
    const overlay = document.getElementById('iframePopupOverlay');
    const container = document.getElementById('iframePopupContainer');
    const header = document.getElementById('iframePopupHeader');
    const iframe = document.getElementById('iframePopupFrame');
    const loading = document.getElementById('iframeLoading');
    const btn = document.getElementById('dashIframeBtn');
    
    let isDragging = false;
    let isResizing = false;
    let resizeDirection = '';
    let startX, startY, startWidth, startHeight, startLeft, startTop;
    
    const defaultWidth = 900;
    const defaultHeight = 600;
    
    // ══════════════════════════════════════════════════════════════════
    // NEW TAB - Open or Switch to Design Enhancer
    // ══════════════════════════════════════════════════════════════════
    
    // Using named window - browser remembers window by name
    const DESIGN_ENHANCER_WINDOW_NAME = 'DesignEnhancerWindow';
    const DESIGN_ENHANCER_URL = 'index1.php';
    
    window.openOrSwitchToDesignEnhancer = function() {
        // Try to open/switch to the named window
        // If window with this name exists, it will focus on it
        // If not, it will open a new window with this name
        const win = window.open(DESIGN_ENHANCER_URL, DESIGN_ENHANCER_WINDOW_NAME);
        
        if (win) {
            win.focus();
            showToast('🔄 Design Enhancer tab opened/switched', 'success');
        } else {
            // Popup blocker might have prevented opening
            showToast('⚠️ Please allow popups to open Design Enhancer', 'warning');
        }
    };
    
    // Toggle popup
    window.toggleIframePopup = function() {
        if (overlay.classList.contains('active')) {
            closeIframePopup();
        } else {
            openIframePopup();
        }
    };
    
    // Open popup
    window.openIframePopup = function() {
        overlay.classList.add('active');
        btn.classList.add('active');
        
        // Center the popup
        container.style.left = '50%';
        container.style.top = '50%';
        container.style.transform = 'translate(-50%, -50%)';
        container.style.width = defaultWidth + 'px';
        container.style.height = defaultHeight + 'px';
        
        // Load iframe
        loading.style.display = 'flex';
        iframe.style.display = 'none';
        iframe.src = 'index1.php';
        
        iframe.onload = function() {
            loading.style.display = 'none';
            iframe.style.display = 'block';
        };
    };
    
    // Close popup
    window.closeIframePopup = function() {
        overlay.classList.remove('active');
        btn.classList.remove('active');
        iframe.src = '';
    };
    
    // Reset size
    window.resetIframePopupSize = function() {
        container.style.width = defaultWidth + 'px';
        container.style.height = defaultHeight + 'px';
        container.style.left = '50%';
        container.style.top = '50%';
        container.style.transform = 'translate(-50%, -50%)';
    };
    
    // Dragging functionality
    header.addEventListener('mousedown', function(e) {
        if (e.target.closest('.iframe-popup-btn')) return;
        
        isDragging = true;
        
        // Remove transform and convert to absolute positioning
        const rect = container.getBoundingClientRect();
        container.style.transform = 'none';
        container.style.left = rect.left + 'px';
        container.style.top = rect.top + 'px';
        
        startX = e.clientX - rect.left;
        startY = e.clientY - rect.top;
        
        document.body.style.cursor = 'move';
        document.body.style.userSelect = 'none';
    });
    
    // Resize functionality
    document.querySelectorAll('.iframe-resize-handle').forEach(handle => {
        handle.addEventListener('mousedown', function(e) {
            e.preventDefault();
            e.stopPropagation();
            
            isResizing = true;
            resizeDirection = this.dataset.resize;
            
            const rect = container.getBoundingClientRect();
            container.style.transform = 'none';
            container.style.left = rect.left + 'px';
            container.style.top = rect.top + 'px';
            
            startX = e.clientX;
            startY = e.clientY;
            startWidth = rect.width;
            startHeight = rect.height;
            startLeft = rect.left;
            startTop = rect.top;
            
            document.body.style.userSelect = 'none';
            
            // Disable pointer events on iframe during resize
            iframe.style.pointerEvents = 'none';
        });
    });
    
    document.addEventListener('mousemove', function(e) {
        if (isDragging) {
            const newX = e.clientX - startX;
            const newY = e.clientY - startY;
            
            // Keep within viewport
            const maxX = window.innerWidth - container.offsetWidth;
            const maxY = window.innerHeight - container.offsetHeight;
            
            container.style.left = Math.max(0, Math.min(newX, maxX)) + 'px';
            container.style.top = Math.max(0, Math.min(newY, maxY)) + 'px';
        }
        
        if (isResizing) {
            const dx = e.clientX - startX;
            const dy = e.clientY - startY;
            
            if (resizeDirection === 'right' || resizeDirection === 'corner') {
                const newWidth = Math.max(400, startWidth + dx);
                container.style.width = Math.min(newWidth, window.innerWidth - startLeft - 20) + 'px';
            }
            
            if (resizeDirection === 'bottom' || resizeDirection === 'corner') {
                const newHeight = Math.max(300, startHeight + dy);
                container.style.height = Math.min(newHeight, window.innerHeight - startTop - 20) + 'px';
            }
        }
    });
    
    document.addEventListener('mouseup', function() {
        isDragging = false;
        isResizing = false;
        resizeDirection = '';
        document.body.style.cursor = '';
        document.body.style.userSelect = '';
        iframe.style.pointerEvents = '';
    });
    
    // ESC key to close (optional shortcut)
    document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape' && overlay.classList.contains('active')) {
            closeIframePopup();
        }
    });
})();
</script>

<!-- Branding Tool Script -->
<script>
// ═══════════════════════════════════════════════════════════════════
// 👑 BRANDING TOOL - Right Panel
// ═══════════════════════════════════════════════════════════════════

// Branding State
let brandingLogoFile = null;
let brandingLogoDataUrl = null;
let brandingLogoFileName = ''; // Track filename separately for auto-detected logos

// Handle Logo Upload
function handleBrandingLogoUpload(input) {
    const file = input.files[0];
    if (!file) return;
    
    // Validate file type
    const validTypes = ['image/png', 'image/jpeg', 'image/jpg', 'image/svg+xml', 'image/x-icon', 'image/ico'];
    if (!validTypes.includes(file.type) && !file.name.endsWith('.ico')) {
        showToast('⚠️ Invalid file type. Use PNG, JPG, SVG, or ICO', 'warning');
        return;
    }
    
    brandingLogoFile = file;
    brandingLogoFileName = file.name;
    
    // Read and display preview
    const reader = new FileReader();
    reader.onload = function(e) {
        brandingLogoDataUrl = e.target.result;
        
        // Show preview
        const preview = document.getElementById('brandingLogoPreview');
        const prompt = document.getElementById('brandingUploadPrompt');
        const img = document.getElementById('brandingLogoImg');
        const name = document.getElementById('brandingLogoName');
        const zone = document.getElementById('brandingLogoZone');
        
        if (preview && prompt && img && name && zone) {
            img.src = brandingLogoDataUrl;
            name.textContent = file.name;
            preview.style.display = 'flex';
            prompt.style.display = 'none';
            zone.classList.add('has-logo');
        }
        
        updateBrandingBadge();
        saveBrandingState();
        showToast('✅ Logo uploaded successfully', 'success');
    };
    reader.readAsDataURL(file);
}

// Clear Logo
function clearBrandingLogo() {
    brandingLogoFile = null;
    brandingLogoDataUrl = null;
    brandingLogoFileName = '';
    
    const preview = document.getElementById('brandingLogoPreview');
    const prompt = document.getElementById('brandingUploadPrompt');
    const zone = document.getElementById('brandingLogoZone');
    const input = document.getElementById('brandingLogoInput');
    
    if (preview) preview.style.display = 'none';
    if (prompt) prompt.style.display = 'block';
    if (zone) zone.classList.remove('has-logo');
    if (input) input.value = '';
    
    updateBrandingBadge();
    saveBrandingState();
}

// Update Title Preview
function updateBrandingTitlePreview() {
    const input = document.getElementById('brandingTitleInput');
    const preview = document.getElementById('brandingTitleText');
    
    if (input && preview) {
        preview.textContent = input.value || 'Preview will appear here';
        saveBrandingState();
    }
}

// Toggle Branding Option
function toggleBrandingOptionItem(element) {
    const checkbox = element.querySelector('input[type="checkbox"]');
    if (checkbox) {
        checkbox.checked = !checkbox.checked;
        element.classList.toggle('checked', checkbox.checked);
    }
    
    updateBrandingBadge();
    saveBrandingState();
}

// Update Badge Count
function updateBrandingBadge() {
    const favicon = document.getElementById('brandingFavicon')?.checked ? 1 : 0;
    const logoPages = document.getElementById('brandingLogoPages')?.checked ? 1 : 0;
    const titlePages = document.getElementById('brandingTitlePages')?.checked ? 1 : 0;
    
    const count = favicon + logoPages + titlePages;
    const badge = document.getElementById('brandingBadge');
    if (badge) {
        badge.textContent = count;
        badge.style.opacity = count > 0 ? '1' : '0.5';
    }
}

// Save Branding State to localStorage
function saveBrandingState() {
    const state = {
        logoDataUrl: brandingLogoDataUrl,
        logoFileName: brandingLogoFileName || brandingLogoFile?.name || '',
        title: document.getElementById('brandingTitleInput')?.value || '',
        favicon: document.getElementById('brandingFavicon')?.checked ?? false,
        logoPages: document.getElementById('brandingLogoPages')?.checked ?? false,
        titlePages: document.getElementById('brandingTitlePages')?.checked ?? false,
        customInstructions: document.getElementById('brandingCustomPrompt')?.value || '',
        _checkboxMigrated: true
    };
    localStorage.setItem('branding_state', JSON.stringify(state));
}

// Load Branding State from localStorage
function loadBrandingState() {
    const saved = localStorage.getItem('branding_state');
    if (!saved) return;
    
    try {
        const state = JSON.parse(saved);
        
        // Restore logo
        if (state.logoDataUrl) {
            brandingLogoDataUrl = state.logoDataUrl;
            brandingLogoFileName = state.logoFileName || '';
            const preview = document.getElementById('brandingLogoPreview');
            const prompt = document.getElementById('brandingUploadPrompt');
            const img = document.getElementById('brandingLogoImg');
            const name = document.getElementById('brandingLogoName');
            const zone = document.getElementById('brandingLogoZone');
            
            if (preview && prompt && img && name && zone) {
                img.src = brandingLogoDataUrl;
                name.textContent = state.logoFileName || 'logo';
                preview.style.display = 'flex';
                prompt.style.display = 'none';
                zone.classList.add('has-logo');
            }
        }
        
        // Restore title
        const titleInput = document.getElementById('brandingTitleInput');
        if (titleInput && state.title) {
            titleInput.value = state.title;
            updateBrandingTitlePreview();
        }
        
        // Restore checkboxes
        const faviconChk = document.getElementById('brandingFavicon');
        const logoPagesChk = document.getElementById('brandingLogoPages');
        const titlePagesChk = document.getElementById('brandingTitlePages');
        
        if (faviconChk) {
            faviconChk.checked = state.favicon ?? false;
            faviconChk.closest('.branding-option-item')?.classList.toggle('checked', faviconChk.checked);
        }
        if (logoPagesChk) {
            logoPagesChk.checked = state.logoPages ?? false;
            logoPagesChk.closest('.branding-option-item')?.classList.toggle('checked', logoPagesChk.checked);
        }
        if (titlePagesChk) {
            titlePagesChk.checked = state.titlePages ?? false;
            titlePagesChk.closest('.branding-option-item')?.classList.toggle('checked', titlePagesChk.checked);
        }
        
        // Restore custom instructions
        const customPrompt = document.getElementById('brandingCustomPrompt');
        if (customPrompt && state.customInstructions) {
            customPrompt.value = state.customInstructions;
        }
        
        updateBrandingBadge();
        
    } catch (e) {
        console.error('Error loading branding state:', e);
    }
}

// Push Branding to Project Prompts
function pushBrandingToNotes() {
    const title = document.getElementById('brandingTitleInput')?.value || '';
    const favicon = document.getElementById('brandingFavicon')?.checked;
    const logoPages = document.getElementById('brandingLogoPages')?.checked;
    const titlePages = document.getElementById('brandingTitlePages')?.checked;
    const customInstructions = document.getElementById('brandingCustomPrompt')?.value || '';
    
    // Build prompt text
    let promptText = '═══════════════════════════════════════════════════════════════════\n';
    promptText += '👑 BRANDING & LOGO INSTRUCTIONS\n';
    promptText += '═══════════════════════════════════════════════════════════════════\n\n';
    
    if (brandingLogoDataUrl) {
        promptText += '📷 LOGO:\n';
        promptText += '   • Logo file has been uploaded and should be used for branding\n';
        promptText += '   • Logo filename: ' + (document.getElementById('brandingLogoName')?.textContent || 'logo') + '\n\n';
    } else {
        promptText += '📷 LOGO: No logo uploaded\n\n';
    }
    
    if (title) {
        promptText += '📝 PAGE TITLE: "' + title + '"\n\n';
    }
    
    promptText += '⚙️ BRANDING OPTIONS:\n';
    promptText += '   ' + (favicon ? '✅' : '⬜') + ' Set logo as favicon for all pages\n';
    promptText += '   ' + (logoPages ? '✅' : '⬜') + ' Add logo to every page header/navigation\n';
    promptText += '   ' + (titlePages ? '✅' : '⬜') + ' Update <title> tag in all pages\n\n';
    
    if (customInstructions.trim()) {
        promptText += '📋 CUSTOM INSTRUCTIONS:\n';
        customInstructions.split('\n').forEach(line => {
            if (line.trim()) promptText += '   ' + line + '\n';
        });
        promptText += '\n';
    }
    
    promptText += '═══════════════════════════════════════════════════════════════════\n';
    
    // Push to Project Prompts textarea
    const notesTextarea = document.getElementById('projectNotesTextarea');
    if (notesTextarea) {
        if (notesTextarea.value.trim()) {
            notesTextarea.value = notesTextarea.value.trimEnd() + '\n\n' + promptText;
        } else {
            notesTextarea.value = promptText;
        }
        
        // Save to localStorage
        localStorage.setItem('project_notes_temp', notesTextarea.value);
        
        // Show success
        showToast('👑 Branding pushed to Project Prompts', 'success');
    } else {
        showToast('⚠️ Project Prompts not found', 'error');
    }
}

// Reset Branding to Default
function resetBranding(skipToast = false) {
    
    // Clear logo
    brandingLogoFile = null;
    brandingLogoDataUrl = null;
    
    const preview = document.getElementById('brandingLogoPreview');
    const prompt = document.getElementById('brandingUploadPrompt');
    const zone = document.getElementById('brandingLogoZone');
    const logoInput = document.getElementById('brandingLogoInput');
    
    if (preview) preview.style.display = 'none';
    if (prompt) prompt.style.display = 'block';
    if (zone) zone.classList.remove('has-logo');
    if (logoInput) logoInput.value = '';
    
    // Clear title
    const titleInput = document.getElementById('brandingTitleInput');
    if (titleInput) titleInput.value = '';
    updateBrandingTitlePreview();
    
    // Reset checkboxes to unchecked (default)
    const options = [
        { id: 'brandingFavicon', default: false },
        { id: 'brandingLogoPages', default: false },
        { id: 'brandingTitlePages', default: false }
    ];
    
    options.forEach(opt => {
        const checkbox = document.getElementById(opt.id);
        if (checkbox) {
            checkbox.checked = opt.default;
            const item = checkbox.closest('.branding-option-item');
            if (item) item.classList.toggle('checked', opt.default);
        }
    });
    
    // Clear custom instructions
    const customPrompt = document.getElementById('brandingCustomPrompt');
    if (customPrompt) customPrompt.value = '';
    
    // Update badge
    updateBrandingBadge();
    
    // Clear localStorage
    localStorage.removeItem('branding_state');
    
    if (!skipToast) {
        showToast('🔄 Branding reset to default', 'info');
    }
    console.log('✅ Branding reset to default');
}

// Clear & Reset Branding (called from the Clear & Reset button inside Custom Instructions)
function brandingClearAndReset() {
    resetBranding(true);
    showToast('🧹 Branding cleared & reset to default', 'info');
}

// Initialize Branding on DOM ready
document.addEventListener('DOMContentLoaded', function() {
    loadBrandingState();
    
    // Initialize collapsed state arrows
    initCollapsedArrows();
});

// Initialize arrows for collapsed sections on page load
function initCollapsedArrows() {
    const collapsedSections = document.querySelectorAll('.de-tool-section.collapsed');
    collapsedSections.forEach(section => {
        const arrow = section.querySelector('.de-tool-arrow');
        if (arrow) {
            arrow.style.transform = 'rotate(-90deg)';
        }
    });
}
</script>

<!-- Pages Creator Tool Script -->
<script>
