// Collapse All Tool Sections
function deCollapseAll() {
    const sections = document.querySelectorAll('.de-tool-section');
    sections.forEach(section => {
        section.classList.add('collapsed');
        const arrow = section.querySelector('.de-tool-arrow');
        if (arrow) {
            arrow.style.transform = 'rotate(-90deg)';
        }
    });
    showToast('All sections collapsed', 'info');
}

// Expand (Uncollapse) All Tool Sections
function deUncollapseAll() {
    const sections = document.querySelectorAll('.de-tool-section');
    sections.forEach(section => {
        section.classList.remove('collapsed');
        const arrow = section.querySelector('.de-tool-arrow');
        if (arrow) {
            arrow.style.transform = 'rotate(0)';
        }
    });
    showToast('All sections expanded', 'info');
}

// Reset All Tool Sections to Default
async function deResetAll() {
    const confirmed = await deConfirm({
        title: 'Reset All Tools',
        subtitle: 'Design Enhancer',
        message: 'Are you sure you want to reset all Design Enhancer tools to their default state?',
        warning: 'All your branding settings, page selections, custom instructions, and style types will be cleared.',
        confirmText: 'Reset All',
        icon: 'fa-undo'
    });
    
    if (!confirmed) return;
    
    // ═══════════════════════════════════════════
    // Suppress toasts & confirmations during reset
    // ═══════════════════════════════════════════
    const _origShowToast = window.showToast;
    const _origDeConfirm = window.deConfirm;
    window.showToast = function() {};
    window.deConfirm = function() { return Promise.resolve(true); };
    
    // ═══════════════════════════════════════════
    // STEP 1: Click each tool's internal button
    // Priority: Clear & Reset > Clear > Reset > X (direct function)
    // ═══════════════════════════════════════════
    
    // 1. Project Files Upload — no internal button, call X function directly
    if (typeof ufResetAll === 'function') ufResetAll(true);
    else if (typeof ufClearAll === 'function') ufClearAll();
    
    // 2. File Exclusion — no internal button, call X function directly
    if (typeof exResetAll === 'function') exResetAll(true);
    
    // 3. Logo & Branding — click "Clear & Reset" internal button
    if (typeof brandingClearAndReset === 'function') brandingClearAndReset();
    else if (typeof resetBranding === 'function') resetBranding(true);
    
    // 4. Pages Creator — click "Clear Custom Pages" button (clears custom pages + unchecks all)
    if (typeof pcCustomPages !== 'undefined') {
        pcCustomPages = [];
        const _pcList = document.getElementById('pcCustomPagesList');
        if (_pcList) _pcList.innerHTML = '';
        if (typeof savePCState === 'function') savePCState();
        if (typeof updatePCCounts === 'function') updatePCCounts();
        if (typeof pcUncheckAll === 'function') pcUncheckAll();
    } else if (typeof resetPagesCreator === 'function') {
        resetPagesCreator(true);
    }
    
    // 5. Custom Instructions — click "Clear" button (clears textarea)
    const _ciTextarea = document.getElementById('ciTextarea');
    if (_ciTextarea) {
        _ciTextarea.value = '';
        if (typeof ciUpdateCharCount === 'function') ciUpdateCharCount();
    }
    if (typeof resetCustomInstructions === 'function') resetCustomInstructions(true);
    
    // 6. Enhanced Style Types — click internal "Reset" button
    if (typeof stResetAll === 'function') stResetAll();
    
    // 7. Design Themes — click internal "Reset" button (dtResetSelection)
    if (typeof dtResetSelection === 'function') dtResetSelection();
    else if (typeof dtResetAll === 'function') dtResetAll(true);
    
    // 8. Page Layout Structure — click internal "Reset" button
    if (typeof plResetAll === 'function') plResetAll();
    
    // 9. Execution Mode — no internal button, call X function directly
    if (typeof emResetAll === 'function') emResetAll(true);
    
    // 10. Design Focus Areas — no internal button, call X function directly
    if (typeof dfResetAll === 'function') dfResetAll(true);
    
    // 11. Enhancement Level — no internal button, call X function directly
    if (typeof elResetAll === 'function') elResetAll(true);
    
    // 12. Task Breakdown — no internal button, call X function directly
    if (typeof tbResetAll === 'function') tbResetAll(true);
    
    // 13. Homepage Configuration — no internal button, call X function directly
    if (typeof hpResetAll === 'function') hpResetAll(true);
    
    // 15. Documentation Integration — no internal button, call X function directly
    if (typeof diResetAll === 'function') diResetAll(true);
    
    // 16. Design Templates — no internal button, call X function directly
    if (typeof dtTemplateResetAll === 'function') dtTemplateResetAll(true);
    
    // ═══════════════════════════════════════════
    // STEP 2: Clear all Design Enhancer related
    // localStorage keys to prevent reload of old state
    // ═══════════════════════════════════════════
    const deStorageKeys = [
        'branding_state',
        'pcSelectedPages', 'pcCustomPages', 'pc_predefined_pages', 'pc_custom_pages',
        'ci_content',
        'st_data', 'st_notes',
        'dtSelectedThemes', 'dtNotes',
        'plSelectedLayouts', 'plNotes',
        'em_data',
        'df_data',
        'el_data',
        'tb_data',
        'hpCreateNew', 'hpNewPageName', 'hpTargetFileName', 'hpExistingFileName', 'hpNotes',
        'ufFileStorage', 'ufDetectedHomepage', 'ufDetectedFeatured', 'ufDetectedDoc', 'ufNotes', 'ufRootFolder',
        'exExcludedFiles', 'exNotes',
        'diEnableDoc', 'diIntegrationMode',
        'diFileContent', 'diFileName', 'diNotes', 'diPageName', 'diInjectionFiles'
    ];
    deStorageKeys.forEach(key => localStorage.removeItem(key));
    
    // ═══════════════════════════════════════════
    // STEP 3: Restore toasts & confirmations,
    // collapse all, and show final toast
    // ═══════════════════════════════════════════
    window.showToast = _origShowToast;
    window.deConfirm = _origDeConfirm;
    
    // Collapse all sections after reset
    window.showToast = function() {};
    deCollapseAll();
    window.showToast = _origShowToast;
    
    showToast('✨ All tools reset to default!', 'success');
    console.log('✅ Design Enhancer: All 16 tools fully reset');
}

// ═══════════════════════════════════════════════════════════════════
// ✅ DESIGN ENHANCER TOOL CHECKBOXES
// ═══════════════════════════════════════════════════════════════════

function deToggleToolCheck(toolId) {
    const checkbox = document.getElementById('deCheck_' + toolId);
    if (!checkbox) return;
    checkbox.checked = !checkbox.checked;
    deUpdateMasterCheck();
}

function deToggleMasterCheck(event) {
    if (event) event.stopPropagation();
    const master = document.getElementById('deMasterCheckbox');
    if (!master) return;
    master.checked = !master.checked;
    const allChecks = document.querySelectorAll('.de-tool-check input[type="checkbox"]');
    allChecks.forEach(cb => { cb.checked = master.checked; });
    deUpdateMasterCheck();
}

function deUpdateMasterCheck() {
    const allChecks = document.querySelectorAll('.de-tool-check input[type="checkbox"]');
    const total = allChecks.length;
    const checked = Array.from(allChecks).filter(cb => cb.checked).length;
    const master = document.getElementById('deMasterCheckbox');
    const countSpan = document.getElementById('deSelectCount');
    if (master) {
        master.checked = (checked === total);
        master.indeterminate = (checked > 0 && checked < total);
    }
    if (countSpan) {
        countSpan.textContent = checked + ' / ' + total;
    }
}

// ═══════════════════════════════════════════════════════════════════
// 🎯 DRAG & DROP TOOL REORDERING SYSTEM
// ═══════════════════════════════════════════════════════════════════

let deDraggedTool = null;
let deDragStartedFromHandle = false;

// Initialize Drag & Drop
function initToolDragDrop() {
    const container = document.getElementById('deToolsContainer');
    if (!container) {
        console.log('Tools container not found');
        return;
    }
    
    console.log('Initializing drag and drop...');
    
    const tools = container.querySelectorAll('.de-tool-section[draggable="true"]');
    console.log('Found tools:', tools.length);
    
    tools.forEach(tool => {
        const handle = tool.querySelector('.de-drag-handle');
        
        // Track when drag starts from handle
        if (handle) {
            handle.addEventListener('mousedown', function(e) {
                deDragStartedFromHandle = true;
                e.stopPropagation(); // Prevent header click
            });
        }
        
        // Reset flag on mouseup anywhere
        document.addEventListener('mouseup', function() {
            setTimeout(() => { deDragStartedFromHandle = false; }, 100);
        });
        
        // Drag start
        tool.addEventListener('dragstart', function(e) {
            if (!deDragStartedFromHandle) {
                e.preventDefault();
                return false;
            }
            
            deDraggedTool = this;
            
            // Create a custom drag image showing only the tool header
            const toolTitle = this.querySelector('.de-tool-title span');
            const toolIcon = this.querySelector('.de-tool-title i');
            
            // Create minimal ghost element
            const ghost = document.createElement('div');
            ghost.className = 'de-drag-ghost';
            ghost.innerHTML = `
                <i class="${toolIcon ? toolIcon.className : 'fas fa-grip-vertical'}"></i>
                <span>${toolTitle ? toolTitle.textContent : 'Tool'}</span>
            `;
            ghost.style.cssText = `
                position: fixed;
                top: -1000px;
                left: -1000px;
                padding: 10px 16px;
                background: linear-gradient(135deg, #6366f1 0%, #8b5cf6 100%);
                color: white;
                border-radius: 8px;
                font-size: 13px;
                font-weight: 600;
                display: flex;
                align-items: center;
                gap: 8px;
                box-shadow: 0 8px 32px rgba(99, 102, 241, 0.4);
                z-index: 99999;
                pointer-events: none;
                white-space: nowrap;
            `;
            document.body.appendChild(ghost);
            
            // Set as drag image
            e.dataTransfer.setDragImage(ghost, 20, 20);
            
            // Remove ghost after a short delay
            setTimeout(() => ghost.remove(), 50);
            
            // Add dragging class after drag image is captured
            setTimeout(() => {
                this.classList.add('dragging');
            }, 0);
            
            e.dataTransfer.effectAllowed = 'move';
            e.dataTransfer.setData('text/plain', this.id);
            
            console.log('Drag started:', this.id);
        });
        
        // Drag end
        tool.addEventListener('dragend', function(e) {
            this.classList.remove('dragging');
            deDraggedTool = null;
            deDragStartedFromHandle = false;
            
            // Remove all drag-over classes
            container.querySelectorAll('.de-tool-section').forEach(t => {
                t.classList.remove('drag-over', 'drag-over-bottom');
            });
            
            console.log('Drag ended');
        });
        
        // Drag over - MUST prevent default to allow drop
        tool.addEventListener('dragover', function(e) {
            e.preventDefault();
            e.stopPropagation();
            
            if (!deDraggedTool || this === deDraggedTool) return;
            
            e.dataTransfer.dropEffect = 'move';
            
            // Determine position
            const rect = this.getBoundingClientRect();
            const midY = rect.top + rect.height / 2;
            
            // Remove classes from all tools first
            container.querySelectorAll('.de-tool-section').forEach(t => {
                if (t !== this) {
                    t.classList.remove('drag-over', 'drag-over-bottom');
                }
            });
            
            // Add appropriate class
            this.classList.remove('drag-over', 'drag-over-bottom');
            if (e.clientY < midY) {
                this.classList.add('drag-over');
            } else {
                this.classList.add('drag-over-bottom');
            }
        });
        
        // Drag enter
        tool.addEventListener('dragenter', function(e) {
            e.preventDefault();
        });
        
        // Drag leave
        tool.addEventListener('dragleave', function(e) {
            // Only remove if leaving the element entirely
            const rect = this.getBoundingClientRect();
            if (e.clientX < rect.left || e.clientX > rect.right || 
                e.clientY < rect.top || e.clientY > rect.bottom) {
                this.classList.remove('drag-over', 'drag-over-bottom');
            }
        });
        
        // Drop
        tool.addEventListener('drop', function(e) {
            e.preventDefault();
            e.stopPropagation();
            
            console.log('Drop event on:', this.id);
            
            if (!deDraggedTool || this === deDraggedTool) {
                console.log('Invalid drop - same element or no dragged tool');
                return;
            }
            
            const rect = this.getBoundingClientRect();
            const midY = rect.top + rect.height / 2;
            
            // Determine where to insert
            if (e.clientY < midY) {
                container.insertBefore(deDraggedTool, this);
                console.log('Inserted before:', this.id);
            } else {
                container.insertBefore(deDraggedTool, this.nextSibling);
                console.log('Inserted after:', this.id);
            }
            
            // Remove drag classes
            this.classList.remove('drag-over', 'drag-over-bottom');
            
            // Save new order to database
            saveToolOrderToDatabase();
        });
    });
    
    // Also allow drop on container itself (for dropping at the end)
    container.addEventListener('dragover', function(e) {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';
    });
    
    container.addEventListener('drop', function(e) {
        // Only handle if drop is on container, not on a tool
        if (e.target === container && deDraggedTool) {
            e.preventDefault();
            container.appendChild(deDraggedTool);
            saveToolOrderToDatabase();
        }
    });
    
    // Load order from database on init
    loadToolOrderFromDatabase();
    
    console.log('Drag and drop initialized successfully');
}

// Save tool order to database
async function saveToolOrderToDatabase() {
    const container = document.getElementById('deToolsContainer');
    if (!container) return;
    
    const tools = container.querySelectorAll('.de-tool-section[draggable="true"]');
    const order = Array.from(tools).map(tool => tool.id);
    
    console.log('Saving order:', order);
    
    // Save to localStorage immediately as backup
    try { localStorage.setItem('de_tool_order', JSON.stringify(order)); } catch(e) {}
    
    // Show saving indicator
    const indicator = document.createElement('div');
    indicator.className = 'de-saving-indicator';
    indicator.innerHTML = '<i class="fas fa-sync-alt"></i> Saving order...';
    document.body.appendChild(indicator);
    
    try {
        const formData = new FormData();
        formData.append('action', 'save_tool_order');
        formData.append('tool_order', JSON.stringify(order));
        
        const response = await fetch(window.location.href.split('?')[0], {
            method: 'POST',
            body: formData,
            cache: 'no-store'
        });
        
        const result = await response.json();
        
        if (result.success) {
            indicator.innerHTML = '<i class="fas fa-check"></i> Order saved!';
            indicator.style.background = 'linear-gradient(135deg, #10b981 0%, #059669 100%)';
            console.log('Order saved successfully');
        } else {
            indicator.innerHTML = '<i class="fas fa-times"></i> Save failed';
            indicator.style.background = 'linear-gradient(135deg, #ef4444 0%, #dc2626 100%)';
            console.error('Save failed:', result.message);
        }
    } catch (error) {
        indicator.innerHTML = '<i class="fas fa-times"></i> Error saving';
        indicator.style.background = 'linear-gradient(135deg, #ef4444 0%, #dc2626 100%)';
        console.error('Error saving tool order:', error);
    }
    
    // Remove indicator after delay
    setTimeout(() => {
        indicator.style.animation = 'slideInUp 0.3s ease reverse';
        setTimeout(() => indicator.remove(), 300);
    }, 1500);
}

// Load tool order from database
async function loadToolOrderFromDatabase() {
    // Apply localStorage order immediately for instant response
    try {
        const cached = localStorage.getItem('de_tool_order');
        if (cached) {
            const cachedOrder = JSON.parse(cached);
            if (Array.isArray(cachedOrder) && cachedOrder.length > 0) {
                applyToolOrder(cachedOrder);
                console.log('Applied cached order from localStorage');
            }
        }
    } catch(e) {}
    
    // Then fetch from database (source of truth) and apply
    try {
        const formData = new FormData();
        formData.append('action', 'load_tool_order');
        
        const response = await fetch(window.location.href.split('?')[0], {
            method: 'POST',
            body: formData,
            cache: 'no-store'
        });
        
        const result = await response.json();
        
        if (result.success && result.tool_order && Array.isArray(result.tool_order)) {
            console.log('Loaded order from database:', result.tool_order);
            applyToolOrder(result.tool_order);
            // Update localStorage with DB truth
            try { localStorage.setItem('de_tool_order', JSON.stringify(result.tool_order)); } catch(e) {}
        }
    } catch (error) {
        console.error('Error loading tool order:', error);
    }
}

// Apply tool order to DOM
function applyToolOrder(order) {
    const container = document.getElementById('deToolsContainer');
    if (!container) return;
    
    order.forEach(toolId => {
        const tool = document.getElementById(toolId);
        if (tool) {
            container.appendChild(tool);
        }
    });
    
    // Append any tools not in the saved order (new tools)
    const allTools = container.querySelectorAll('.de-tool-section[draggable="true"]');
    allTools.forEach(tool => {
        if (!order.includes(tool.id)) {
            container.appendChild(tool);
        }
    });
    
    console.log('Order applied to DOM');
}

// Initialize on page load
document.addEventListener('DOMContentLoaded', function() {
    // Apply cached order immediately (no delay) for instant visual response
    try {
        const cached = localStorage.getItem('de_tool_order');
        if (cached) {
            const cachedOrder = JSON.parse(cached);
            if (Array.isArray(cachedOrder) && cachedOrder.length > 0) {
                applyToolOrder(cachedOrder);
            }
        }
    } catch(e) {}
    
    // Then initialize drag-drop and load from DB
    setTimeout(initToolDragDrop, 300);
    
    // Load DE presets dropdown
    setTimeout(depLoadPresets, 500);
});

// ═══════════════════════════════════════════════════════════════════
// 💾 DESIGN ENHANCER PRESETS SYSTEM
// Save/Load full DE configuration presets
// ═══════════════════════════════════════════════════════════════════

let depCurrentPresetId = null;
let depCurrentPresetName = '';

// All localStorage keys that represent DE tool state
const DEP_STORAGE_KEYS = [
    'branding_state',
    'pcSelectedPages', 'pcCustomPages', 'pc_predefined_pages', 'pc_custom_pages',
    'pc_file_extension', 'pc_general_notes',
    'ci_content',
    'st_data', 'st_notes', 'st_selected_styles',
    'dtSelectedThemes', 'dtNotes',
    'plSelectedLayouts', 'plNotes',
    'em_data',
    'df_data',
    'el_data',
    'tb_data',
    'hpCreateNew', 'hpNewPageName', 'hpTargetFileName', 'hpExistingFileName', 'hpNotes',
    'ufFileStorage', 'ufDetectedHomepage', 'ufDetectedFeatured', 'ufDetectedDoc', 'ufNotes', 'ufRootFolder',
    'exExcludedFiles', 'exNotes',
    'diEnableDoc', 'diIntegrationMode',
    'diFileContent', 'diFileName', 'diNotes', 'diPageName', 'diInjectionFiles',
    'de_tool_order'
];

// ─── Capture the full DE state ───
function depCaptureState() {
    const state = {};
    
    // 1) localStorage data for each tool
    state.localStorage = {};
    DEP_STORAGE_KEYS.forEach(key => {
        const val = localStorage.getItem(key);
        if (val !== null) state.localStorage[key] = val;
    });
    
    // 2) Tool order from DOM
    const container = document.getElementById('deToolsContainer');
    if (container) {
        const tools = container.querySelectorAll('.de-tool-section[draggable="true"]');
        state.toolOrder = Array.from(tools).map(t => t.id);
    }
    
    // 3) Checkbox states for each tool
    state.checkboxes = {};
    const allChecks = document.querySelectorAll('.de-tool-check input[type="checkbox"]');
    allChecks.forEach(cb => {
        state.checkboxes[cb.id] = cb.checked;
    });
    
    // 4) Active design templates
    if (typeof activeDesignTemplates !== 'undefined') {
        state.activeDesignTemplates = Array.from(activeDesignTemplates);
    }
    
    // 5) Collapsed/expanded state of tool sections
    state.collapsed = {};
    const sections = document.querySelectorAll('.de-tool-section[draggable="true"]');
    sections.forEach(sec => {
        const body = sec.querySelector('.de-tool-body');
        if (body) {
            state.collapsed[sec.id] = (body.style.display === 'none');
        }
    });
    
    // 6) Homepage Configuration state (explicit capture from JS variables + DOM)
    state.homepageConfig = {
        createNew: (typeof hpCreateNew !== 'undefined') ? !!hpCreateNew : false,
        newPageName: (typeof hpNewPageName !== 'undefined') ? (hpNewPageName || 'index') : 'index',
        targetFileName: (typeof hpTargetFileName !== 'undefined') ? (hpTargetFileName || null) : null,
        existingFileName: (typeof hpExistingFileName !== 'undefined') ? (hpExistingFileName || null) : null,
        notes: (document.getElementById('hpNotesTextarea') || {}).value || ''
    };
    
    // 7) Page Creator state (explicit capture from JS variables + DOM)
    state.pageCreator = {
        selectedPredefined: (typeof pcSelectedPredefined !== 'undefined') ? [...pcSelectedPredefined] : [],
        customPages: (typeof pcCustomPages !== 'undefined') ? JSON.parse(JSON.stringify(pcCustomPages)) : [],
        fileExtension: (document.getElementById('pcFileExtension') || {}).value || '.html',
        generalNotes: (document.getElementById('pcGeneralNotes') || {}).value || ''
    };
    
    // 8) Task Breakdown state (explicit capture from JS variables + DOM)
    state.taskBreakdown = {
        parts: (typeof tbParts !== 'undefined') ? tbParts : 3,
        optimizeToken: (typeof tbOptimizeToken !== 'undefined') ? !!tbOptimizeToken : true,
        executionMode: (typeof tbExecutionMode !== 'undefined') ? (tbExecutionMode || 'step-by-step') : 'step-by-step',
        notes: (document.getElementById('tbNotesTextarea') || {}).value || ''
    };
    
    // 9) File Exclusion state (explicit capture from JS variables + DOM)
    state.fileExclusion = {
        excludedFiles: (typeof exExcludedFiles !== 'undefined') ? [...exExcludedFiles] : [],
        notes: (document.getElementById('exNotesTextarea') || {}).value || ''
    };
    
    // 10) Documentation Integration state (explicit capture from JS variables + DOM)
    state.documentationConfig = {
        enableDoc: (typeof diEnableDoc !== 'undefined') ? !!diEnableDoc : false,
        fileName: (typeof diFileName !== 'undefined') ? (diFileName || null) : null,
        fileContent: (typeof diFileContent !== 'undefined') ? (diFileContent || null) : null,
        integrationMode: (typeof diIntegrationMode !== 'undefined') ? (diIntegrationMode || 'ai-decision') : 'ai-decision',
        pageName: (typeof diPageName !== 'undefined') ? (diPageName || 'documentation') : 'documentation',
        injectionFiles: (typeof diInjectionFiles !== 'undefined') ? [...diInjectionFiles] : [],
        notes: (document.getElementById('diNotesTextarea') || {}).value || ''
    };
    
    return state;
}

// ─── Restore full DE state from preset data ───
async function depRestoreState(stateData) {
    let state;
    try {
        state = typeof stateData === 'string' ? JSON.parse(stateData) : stateData;
    } catch (e) {
        showToast('Failed to parse preset data', 'error');
        return false;
    }
    
    // Suppress toasts during restore
    const _origShowToast = window.showToast;
    const _origDeConfirm = window.deConfirm;
    window.showToast = function() {};
    window.deConfirm = function() { return Promise.resolve(true); };
    
    // ── STEP 1: Reset all tools to default first ──
    if (typeof ufResetAll === 'function') ufResetAll(true);
    if (typeof exResetAll === 'function') exResetAll(true);
    if (typeof brandingClearAndReset === 'function') brandingClearAndReset();
    if (typeof pcSelectedPredefined !== 'undefined') pcSelectedPredefined = [];
    if (typeof pcCustomPages !== 'undefined') pcCustomPages = [];
    if (typeof renderPredefinedPages === 'function') renderPredefinedPages();
    if (typeof renderCustomPages === 'function') renderCustomPages();
    if (typeof updatePCCounts === 'function') updatePCCounts();
    const _pcExtSel = document.getElementById('pcFileExtension');
    if (_pcExtSel) _pcExtSel.value = '.html';
    const _pcNotesTA = document.getElementById('pcGeneralNotes');
    if (_pcNotesTA) _pcNotesTA.value = '';
    const _ciTextarea = document.getElementById('ciTextarea');
    if (_ciTextarea) _ciTextarea.value = '';
    if (typeof stResetAll === 'function') stResetAll();
    if (typeof dtResetSelection === 'function') dtResetSelection();
    if (typeof plResetAll === 'function') plResetAll();
    if (typeof emResetAll === 'function') emResetAll(true);
    if (typeof dfResetAll === 'function') dfResetAll(true);
    if (typeof elResetAll === 'function') elResetAll(true);
    if (typeof tbResetAll === 'function') tbResetAll(true);
    if (typeof hpResetAll === 'function') hpResetAll(true);
    if (typeof diResetAll === 'function') diResetAll(true);
    if (typeof dtTemplateResetAll === 'function') dtTemplateResetAll(true);
    
    // Clear all DE storage keys
    DEP_STORAGE_KEYS.forEach(key => localStorage.removeItem(key));
    
    // ── STEP 2: Restore localStorage keys from preset ──
    if (state.localStorage) {
        Object.entries(state.localStorage).forEach(([key, val]) => {
            localStorage.setItem(key, val);
        });
    }
    
    // ── STEP 3: Reload each tool's state from localStorage ──
    if (typeof loadBrandingState === 'function') loadBrandingState();
    
    // ── Page Creator: Explicit restore from saved state ──
    if (state.pageCreator) {
        if (typeof pcSelectedPredefined !== 'undefined') pcSelectedPredefined = state.pageCreator.selectedPredefined || [];
        if (typeof pcCustomPages !== 'undefined') pcCustomPages = state.pageCreator.customPages || [];
        const _pcExtRestore = document.getElementById('pcFileExtension');
        if (_pcExtRestore) _pcExtRestore.value = state.pageCreator.fileExtension || '.html';
        const _pcNotesRestore = document.getElementById('pcGeneralNotes');
        if (_pcNotesRestore) _pcNotesRestore.value = state.pageCreator.generalNotes || '';
        // Sync to localStorage for consistency
        if (typeof savePCState === 'function') savePCState();
        localStorage.setItem('pc_file_extension', state.pageCreator.fileExtension || '.html');
        localStorage.setItem('pc_general_notes', state.pageCreator.generalNotes || '');
        // Render UI
        if (typeof renderPredefinedPages === 'function') renderPredefinedPages();
        if (typeof renderCustomPages === 'function') renderCustomPages();
        if (typeof updatePCCounts === 'function') updatePCCounts();
    } else {
        // Fallback for older presets without explicit pageCreator data
        if (typeof pcSelectedPredefined !== 'undefined') pcSelectedPredefined = [];
        if (typeof pcCustomPages !== 'undefined') pcCustomPages = [];
        if (typeof initPagesCreator === 'function') initPagesCreator();
        if (typeof pcLoadExtension === 'function') pcLoadExtension();
        if (typeof pcLoadGeneralNotes === 'function') pcLoadGeneralNotes();
    }
    
    if (typeof ciLoadFromStorage === 'function') ciLoadFromStorage();
    if (typeof stLoadFromStorage === 'function') stLoadFromStorage();
    if (typeof stLoadNotesFromStorage === 'function') stLoadNotesFromStorage();
    if (typeof stUpdateUI === 'function') stUpdateUI();
    if (typeof dtLoadFromStorage === 'function') dtLoadFromStorage();
    if (typeof dtLoadNotesFromStorage === 'function') dtLoadNotesFromStorage();
    if (typeof dtUpdateUI === 'function') dtUpdateUI();
    if (typeof plLoadFromStorage === 'function') plLoadFromStorage();
    if (typeof plLoadNotesFromStorage === 'function') plLoadNotesFromStorage();
    if (typeof plUpdateUI === 'function') plUpdateUI();
    if (typeof emLoadFromStorage === 'function') emLoadFromStorage();
    if (typeof emUpdateUI === 'function') emUpdateUI();
    if (typeof dfLoadFromStorage === 'function') dfLoadFromStorage();
    if (typeof dfUpdateUI === 'function') dfUpdateUI();
    if (typeof elLoadFromStorage === 'function') elLoadFromStorage();
    if (typeof elUpdateUI === 'function') elUpdateUI();
    // ── Task Breakdown: Explicit restore from saved state ──
    if (state.taskBreakdown) {
        if (typeof tbParts !== 'undefined') tbParts = state.taskBreakdown.parts || 3;
        if (typeof tbOptimizeToken !== 'undefined') tbOptimizeToken = state.taskBreakdown.optimizeToken !== false;
        if (typeof tbExecutionMode !== 'undefined') tbExecutionMode = state.taskBreakdown.executionMode || 'step-by-step';
        const _tbNotes = document.getElementById('tbNotesTextarea');
        if (_tbNotes) _tbNotes.value = state.taskBreakdown.notes || '';
        if (typeof tbSaveToStorage === 'function') tbSaveToStorage();
    } else {
        if (typeof tbLoadFromStorage === 'function') tbLoadFromStorage();
    }
    if (typeof tbUpdateUI === 'function') tbUpdateUI();
    // ── Homepage Configuration: Explicit restore from saved state ──
    if (state.homepageConfig) {
        if (typeof hpCreateNew !== 'undefined') hpCreateNew = !!state.homepageConfig.createNew;
        if (typeof hpNewPageName !== 'undefined') hpNewPageName = state.homepageConfig.newPageName || 'index';
        if (typeof hpTargetFileName !== 'undefined') hpTargetFileName = state.homepageConfig.targetFileName || null;
        if (typeof hpExistingFileName !== 'undefined') hpExistingFileName = state.homepageConfig.existingFileName || null;
        const _hpNotes = document.getElementById('hpNotesTextarea');
        if (_hpNotes) {
            _hpNotes.value = state.homepageConfig.notes || '';
            localStorage.setItem('hpNotes', _hpNotes.value);
        }
        if (typeof hpSaveToStorage === 'function') hpSaveToStorage();
    } else {
        if (typeof hpLoadFromStorage === 'function') hpLoadFromStorage();
        if (typeof hpLoadNotesFromStorage === 'function') hpLoadNotesFromStorage();
    }
    if (typeof hpUpdateUI === 'function') hpUpdateUI();
    if (typeof ufLoadFromStorage === 'function') ufLoadFromStorage();
    // ── File Exclusion: Explicit restore from saved state ──
    if (state.fileExclusion) {
        if (typeof exExcludedFiles !== 'undefined') exExcludedFiles = state.fileExclusion.excludedFiles || [];
        const _exNotes = document.getElementById('exNotesTextarea');
        if (_exNotes) _exNotes.value = state.fileExclusion.notes || '';
        if (typeof exSaveToStorage === 'function') exSaveToStorage();
        if (typeof exSaveNotesToStorage === 'function') exSaveNotesToStorage();
    } else {
        if (typeof exLoadFromStorage === 'function') exLoadFromStorage();
    }
    if (typeof exUpdateUI === 'function') exUpdateUI();
    // ── Documentation Integration: Explicit restore from saved state ──
    if (state.documentationConfig) {
        if (typeof diEnableDoc !== 'undefined') diEnableDoc = !!state.documentationConfig.enableDoc;
        if (typeof diFileName !== 'undefined') diFileName = state.documentationConfig.fileName || null;
        if (typeof diFileContent !== 'undefined') diFileContent = state.documentationConfig.fileContent || null;
        if (typeof diIntegrationMode !== 'undefined') diIntegrationMode = state.documentationConfig.integrationMode || 'ai-decision';
        if (typeof diPageName !== 'undefined') diPageName = state.documentationConfig.pageName || 'documentation';
        if (typeof diInjectionFiles !== 'undefined') diInjectionFiles = state.documentationConfig.injectionFiles || [];
        const _diNotes = document.getElementById('diNotesTextarea');
        if (_diNotes) {
            _diNotes.value = state.documentationConfig.notes || '';
            localStorage.setItem('diNotes', _diNotes.value);
        }
        if (typeof diSaveToStorage === 'function') diSaveToStorage();
        localStorage.setItem('diPageName', diPageName);
        localStorage.setItem('diInjectionFiles', JSON.stringify(diInjectionFiles));
    } else {
        if (typeof diLoadFromStorage === 'function') diLoadFromStorage();
        if (typeof diLoadNotesFromStorage === 'function') diLoadNotesFromStorage();
    }
    if (typeof diUpdateUI === 'function') diUpdateUI();
    
    // ── STEP 4: Apply tool order ──
    if (state.toolOrder && Array.isArray(state.toolOrder)) {
        if (typeof applyToolOrder === 'function') applyToolOrder(state.toolOrder);
    }
    
    // ── STEP 5: Restore checkbox states ──
    if (state.checkboxes) {
        Object.entries(state.checkboxes).forEach(([id, checked]) => {
            const cb = document.getElementById(id);
            if (cb) cb.checked = checked;
        });
        if (typeof deUpdateMasterCheck === 'function') deUpdateMasterCheck();
    }
    
    // ── STEP 6: Restore active design templates ──
    if (state.activeDesignTemplates && typeof activeDesignTemplates !== 'undefined') {
        activeDesignTemplates.clear();
        state.activeDesignTemplates.forEach(id => activeDesignTemplates.add(id));
        if (typeof dtRenderList === 'function') dtRenderList();
    }
    
    // ── STEP 7: Restore collapsed state ──
    if (state.collapsed) {
        Object.entries(state.collapsed).forEach(([secId, isCollapsed]) => {
            const sec = document.getElementById(secId);
            if (!sec) return;
            const body = sec.querySelector('.de-tool-body');
            const arrow = sec.querySelector('.de-tool-arrow');
            if (body) body.style.display = isCollapsed ? 'none' : '';
            if (arrow) arrow.style.transform = isCollapsed ? 'rotate(-90deg)' : 'rotate(0)';
        });
    }
    
    // Restore toast & confirm
    window.showToast = _origShowToast;
    window.deConfirm = _origDeConfirm;
    
    return true;
}

// ─── API helper ───
async function depApi(action, data = {}) {
    const formData = new FormData();
    formData.append('action', action);
    Object.entries(data).forEach(([k, v]) => formData.append(k, v));
    
    const response = await fetch(window.location.href.split('?')[0], {
        method: 'POST',
        body: formData,
        cache: 'no-store'
    });
    return response.json();
}

// ─── Load presets list into dropdown ───
async function depLoadPresets() {
    try {
        const result = await depApi('get_de_presets');
        const select = document.getElementById('depSelect');
        if (!select) return;
        
        // Save current value
        const prevVal = select.value;
        
        // Rebuild options
        select.innerHTML = '<option value="">-- No Preset --</option>';
        if (result.success && result.presets) {
            result.presets.forEach(p => {
                const opt = document.createElement('option');
                opt.value = p.id;
                opt.textContent = p.name;
                opt.title = 'Updated: ' + (p.updated_at || p.created_at || '');
                select.appendChild(opt);
            });
        }
        
        // Restore previous selection if still exists
        if (prevVal && select.querySelector(`option[value="${prevVal}"]`)) {
            select.value = prevVal;
        }
        
        depUpdateUI();
    } catch (e) {
        console.error('Failed to load DE presets:', e);
    }
}

// ─── Update button states based on selection ───
function depUpdateUI() {
    const select = document.getElementById('depSelect');
    const saveBtn = document.getElementById('depSaveBtn');
    const loadBtn = document.getElementById('depLoadBtn');
    const renameBtn = document.getElementById('depRenameBtn');
    const deleteBtn = document.getElementById('depDeleteBtn');
    const wrapper = select?.closest('.dep-select-wrapper');
    
    const hasPreset = select && select.value !== '';
    
    if (saveBtn) saveBtn.disabled = !hasPreset;
    if (loadBtn) loadBtn.disabled = !hasPreset;
    if (renameBtn) renameBtn.disabled = !hasPreset;
    if (deleteBtn) deleteBtn.disabled = !hasPreset;
    
    if (wrapper) {
        wrapper.classList.toggle('has-preset', hasPreset);
    }
    
    if (hasPreset) {
        depCurrentPresetId = select.value;
        depCurrentPresetName = select.options[select.selectedIndex]?.textContent || '';
    } else {
        depCurrentPresetId = null;
        depCurrentPresetName = '';
    }
}

// ─── On dropdown selection change — load the preset ───
async function depOnSelectChange() {
    const select = document.getElementById('depSelect');
    depUpdateUI();
    
    if (!select || !select.value) return;
    
    const presetId = select.value;
    
    try {
        depSetLoading(true);
        const result = await depApi('load_de_preset', { preset_id: presetId });
        
        if (result.success && result.preset) {
            const ok = await depRestoreState(result.preset.state_data);
            if (ok) {
                showToast(`Preset "${result.preset.name}" loaded`, 'success');
            }
        } else {
            showToast(result.message || 'Failed to load preset', 'error');
        }
    } catch (e) {
        showToast('Error loading preset', 'error');
        console.error(e);
    } finally {
        depSetLoading(false);
    }
}

// ─── Load (re-load currently selected preset) ───
async function depLoad() {
    if (!depCurrentPresetId) return;
    
    const confirmed = await deConfirm({
        title: 'Re-load Preset',
        subtitle: depCurrentPresetName,
        message: `Restore all settings from "${depCurrentPresetName}"?`,
        warning: 'Any unsaved changes will be lost.',
        confirmText: 'Load',
        icon: 'fa-download'
    });
    if (!confirmed) return;
    
    const btn = document.getElementById('depLoadBtn');
    try {
        depBtnSaving(btn, true);
        depSetLoading(true);
        const result = await depApi('load_de_preset', { preset_id: depCurrentPresetId });
        
        if (result.success && result.preset) {
            const ok = await depRestoreState(result.preset.state_data);
            if (ok) {
                showToast(`Preset "${result.preset.name}" re-loaded`, 'success');
            }
        } else {
            showToast(result.message || 'Failed to load preset', 'error');
        }
    } catch (e) {
        showToast('Error loading preset', 'error');
        console.error(e);
    } finally {
        depBtnSaving(btn, false);
        depSetLoading(false);
    }
}

// ─── Save (overwrite current preset) ───
async function depSave() {
    if (!depCurrentPresetId) return;
    
    const confirmed = await deConfirm({
        title: 'Overwrite Preset',
        subtitle: depCurrentPresetName,
        message: `Save current DE state to "${depCurrentPresetName}"?`,
        warning: 'This will overwrite the existing preset data.',
        confirmText: 'Save',
        icon: 'fa-save'
    });
    if (!confirmed) return;
    
    const btn = document.getElementById('depSaveBtn');
    try {
        depBtnSaving(btn, true);
        const stateData = JSON.stringify(depCaptureState());
        const result = await depApi('update_de_preset', {
            preset_id: depCurrentPresetId,
            state_data: stateData
        });
        
        if (result.success) {
            showToast(`Preset "${depCurrentPresetName}" saved`, 'success');
        } else {
            showToast(result.message || 'Save failed', 'error');
        }
    } catch (e) {
        showToast('Error saving preset', 'error');
        console.error(e);
    } finally {
        depBtnSaving(btn, false);
    }
}

// ─── Save As (new preset) ───
async function depSaveAs() {
    const name = await dePrompt({
        title: 'Save New Preset',
        subtitle: 'Design Enhancer Presets',
        message: 'Choose a name for your new preset configuration:',
        placeholder: 'e.g. My Portfolio Theme',
        confirmText: 'Save Preset',
        icon: 'fa-copy',
        hint: 'This will save all current Design Enhancer settings as a new reusable preset.'
    });
    if (!name) return;
    
    const btn = document.querySelector('.dep-btn.dep-save-as');
    try {
        depBtnSaving(btn, true);
        const stateData = JSON.stringify(depCaptureState());
        const result = await depApi('save_de_preset', {
            preset_name: name.trim(),
            state_data: stateData
        });
        
        if (result.success) {
            showToast(`Preset "${name.trim()}" created`, 'success');
            await depLoadPresets();
            // Select the newly created preset
            const select = document.getElementById('depSelect');
            if (select && result.id) {
                select.value = result.id;
                depUpdateUI();
            }
        } else {
            showToast(result.message || 'Save failed', 'error');
        }
    } catch (e) {
        showToast('Error creating preset', 'error');
        console.error(e);
    } finally {
        depBtnSaving(btn, false);
    }
}

// ─── Rename current preset ───
async function depRename() {
    if (!depCurrentPresetId) return;
    
    const newName = await dePrompt({
        title: 'Rename Preset',
        subtitle: 'Design Enhancer Presets',
        message: 'Enter a new name for this preset:',
        placeholder: 'New preset name...',
        defaultValue: depCurrentPresetName,
        confirmText: 'Rename',
        icon: 'fa-pen',
        hint: 'The preset configuration will remain unchanged — only the name will be updated.'
    });
    if (!newName || newName === depCurrentPresetName) return;
    
    try {
        const result = await depApi('rename_de_preset', {
            preset_id: depCurrentPresetId,
            preset_name: newName.trim()
        });
        
        if (result.success) {
            showToast(`Preset renamed to "${newName.trim()}"`, 'success');
            await depLoadPresets();
            const select = document.getElementById('depSelect');
            if (select) {
                select.value = depCurrentPresetId;
                depUpdateUI();
            }
        } else {
            showToast(result.message || 'Rename failed', 'error');
        }
    } catch (e) {
        showToast('Error renaming preset', 'error');
        console.error(e);
    }
}

// ─── Delete current preset ───
async function depDelete() {
    if (!depCurrentPresetId) return;
    
    const confirmed = await deConfirm({
        title: 'Delete Preset',
        subtitle: depCurrentPresetName,
        message: `Are you sure you want to delete "${depCurrentPresetName}"?`,
        warning: 'This action cannot be undone.',
        confirmText: 'Delete',
        icon: 'fa-trash-alt'
    });
    if (!confirmed) return;
    
    try {
        const result = await depApi('delete_de_preset', {
            preset_id: depCurrentPresetId
        });
        
        if (result.success) {
            showToast(`Preset "${depCurrentPresetName}" deleted`, 'success');
            depCurrentPresetId = null;
            depCurrentPresetName = '';
            await depLoadPresets();
            const select = document.getElementById('depSelect');
            if (select) select.value = '';
            depUpdateUI();
        } else {
            showToast(result.message || 'Delete failed', 'error');
        }
    } catch (e) {
        showToast('Error deleting preset', 'error');
        console.error(e);
    }
}

// ─── UI helpers ───
function depSetLoading(loading) {
    const select = document.getElementById('depSelect');
    if (select) select.disabled = loading;
}

function depBtnSaving(btn, saving) {
    if (!btn) return;
    if (saving) {
        btn.classList.add('dep-saving');
        btn.querySelector('i').className = 'fas fa-spinner';
    } else {
        btn.classList.remove('dep-saving');
        // Restore original icon
        if (btn.classList.contains('dep-save')) {
            btn.querySelector('i').className = 'fas fa-save';
        } else if (btn.classList.contains('dep-save-as')) {
            btn.querySelector('i').className = 'fas fa-copy';
        }
    }
}

// Reset Pages Creator to Default
function resetPagesCreator(skipToast = false) {
    // Uncheck all predefined pages
    const predefinedItems = document.querySelectorAll('.pc-page-item');
    predefinedItems.forEach(item => {
        item.classList.remove('selected');
    });
    pcSelectedPages.clear();
    
    // Clear custom pages
    pcCustomPages = [];
    const customList = document.getElementById('pcCustomPagesList');
    if (customList) {
        customList.innerHTML = '';
    }
    
    // Clear inputs
    const searchInput = document.getElementById('pcTemplateSearch');
    if (searchInput) searchInput.value = '';
    
    const nameInput = document.getElementById('pcCustomPageName');
    if (nameInput) nameInput.value = '';
    
    const descInput = document.getElementById('pcCustomPageDesc');
    if (descInput) descInput.value = '';
    
    // Hide template results
    const templateResults = document.getElementById('pcTemplateResults');
    if (templateResults) templateResults.classList.remove('active');
    
    // Update counts
    pcUpdateSelectedCount();
    const customBadge = document.getElementById('pcCustomBadge');
    if (customBadge) {
        customBadge.textContent = '0';
        customBadge.style.display = 'none';
    }
    
    // Clear localStorage
    localStorage.removeItem('pcSelectedPages');
    localStorage.removeItem('pcCustomPages');
    localStorage.removeItem('pc_predefined_pages');
    localStorage.removeItem('pc_custom_pages');
    
    if (!skipToast) {
        showToast('🔄 Pages Creator reset to default', 'info');
    }
    console.log('✅ Pages Creator reset to default');
}

// Template Search
let pcSearchTimeout = null;
function pcSearchTemplates(query) {
    clearTimeout(pcSearchTimeout);
    pcSearchTimeout = setTimeout(() => {
        const results = document.getElementById('pcTemplateResults');
        if (!results) return;
        
        const q = query.toLowerCase().trim();
        if (!q) {
            results.classList.remove('active');
            return;
        }
        
        const matches = Object.entries(pcPageTemplates)
            .filter(([id, t]) => 
                t.name.toLowerCase().includes(q) || 
                t.desc.toLowerCase().includes(q) ||
                id.includes(q)
            )
            .slice(0, 15);
        
        if (matches.length === 0) {
            results.innerHTML = '<div class="pc-template-item"><span class="name">No templates found</span></div>';
        } else {
            results.innerHTML = matches.map(([id, t]) => `
                <div class="pc-template-item" onclick="pcSelectTemplate('${id}')">
                    <div class="name">${t.name}</div>
                    <div class="desc">${t.desc}</div>
                </div>
            `).join('');
        }
        
        results.classList.add('active');
    }, 150);
}

function pcShowTemplateResults() {
    const input = document.getElementById('pcTemplateSearch');
    if (input && input.value.trim()) {
        pcSearchTemplates(input.value);
    }
}

// Select Template
function pcSelectTemplate(templateId) {
    const template = pcPageTemplates[templateId];
    if (!template) return;
    
    const nameInput = document.getElementById('pcCustomPageName');
    const descInput = document.getElementById('pcCustomPageDesc');
    const results = document.getElementById('pcTemplateResults');
    const searchInput = document.getElementById('pcTemplateSearch');
    
    if (nameInput) nameInput.value = template.name;
    if (descInput) descInput.value = template.desc;
    if (results) results.classList.remove('active');
    if (searchInput) searchInput.value = '';
    
    if (typeof showToast === 'function') {
        showToast(`✨ "${template.name}" template applied`, 'success');
    }
}

// Add Custom Page
function pcAddCustomPage() {
    const nameInput = document.getElementById('pcCustomPageName');
    const descInput = document.getElementById('pcCustomPageDesc');
    
    const name = nameInput ? nameInput.value.trim() : '';
    const desc = descInput ? descInput.value.trim() : '';
    
    if (!name) {
        if (typeof showToast === 'function') showToast('⚠️ Please enter a page name', 'warning');
        return;
    }
    
    // Check duplicate
    const id = name.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');
    if (pcCustomPages.some(p => p.id === id) || pcPredefinedPages.some(p => p.id === id)) {
        if (typeof showToast === 'function') showToast('⚠️ Page already exists', 'warning');
        return;
    }
    
    pcCustomPages.push({
        id: id,
        name: name,
        desc: desc,
        checked: true
    });
    
    renderCustomPages();
    savePCState();
    updatePCCounts();
    
    // Clear inputs
    if (nameInput) nameInput.value = '';
    if (descInput) descInput.value = '';
    
    if (typeof showToast === 'function') showToast(`✅ "${name}" page added`, 'success');
}

// Render Custom Pages
function renderCustomPages() {
    const list = document.getElementById('pcCustomPagesList');
    if (!list) return;
    
    if (pcCustomPages.length === 0) {
        list.innerHTML = '';
        return;
    }
    
    list.innerHTML = pcCustomPages.map(page => `
        <div class="pc-custom-item ${page.checked ? 'checked' : ''}" data-id="${page.id}">
            <span class="pc-check" onclick="pcToggleCustom('${page.id}')"><i class="fas fa-check"></i></span>
            <span class="name" title="${page.desc || ''}">${page.name}</span>
            <button class="delete-btn" onclick="pcDeleteCustom('${page.id}')" title="Remove">
                <i class="fas fa-times"></i>
            </button>
        </div>
    `).join('');
}

// Toggle Custom Page
function pcToggleCustom(pageId) {
    const page = pcCustomPages.find(p => p.id === pageId);
    if (page) {
        page.checked = !page.checked;
        renderCustomPages();
        savePCState();
        updatePCCounts();
    }
}

// Delete Custom Page
function pcDeleteCustom(pageId) {
    pcCustomPages = pcCustomPages.filter(p => p.id !== pageId);
    renderCustomPages();
    savePCState();
    updatePCCounts();
}

// Save State to localStorage
function savePCState() {
    localStorage.setItem('pc_predefined_pages', JSON.stringify(pcSelectedPredefined));
    localStorage.setItem('pc_custom_pages', JSON.stringify(pcCustomPages));
}

// Push to Project Notes
function pcPushToNotes() {
    const selectedPredefined = pcSelectedPredefined.map(id => {
        const page = pcPredefinedPages.find(p => p.id === id);
        return page ? { id: page.id, name: page.name, isCustom: false } : null;
    }).filter(Boolean);
    
    const selectedCustom = pcCustomPages.filter(p => p.checked).map(p => ({
        id: p.id,
        name: p.name,
        desc: p.desc,
        isCustom: true
    }));
    
    const allSelected = [...selectedPredefined, ...selectedCustom];
    
    if (allSelected.length === 0) {
        if (typeof showToast === 'function') showToast('⚠️ No pages selected', 'warning');
        return;
    }
    
    // Build the prompt text
    let promptText = `📄 PAGES TO CREATE:\n${'═'.repeat(50)}\n\n`;
    
    allSelected.forEach((page, idx) => {
        promptText += `${idx + 1}. **${page.name}** (${page.id}${pcGetExtension()})\n`;
        
        // Generate page-specific instructions
        const pagePrompt = generatePagePrompt(page);
        promptText += `   ${pagePrompt}\n\n`;
    });
    
    promptText += `${'═'.repeat(50)}\n`;
    promptText += `Total: ${allSelected.length} page${allSelected.length > 1 ? 's' : ''} to create\n`;
    
    // Push to Project Notes
    const notesTextarea = document.getElementById('projectNotesTextarea');
    if (notesTextarea) {
        if (notesTextarea.value.trim()) {
            notesTextarea.value = notesTextarea.value.trimEnd() + '\n\n' + promptText;
        } else {
            notesTextarea.value = promptText;
        }
        
        // Save to localStorage
        if (typeof saveProjectNotesToStorage === 'function') {
            saveProjectNotesToStorage();
        }
        
        if (typeof showToast === 'function') {
            showToast(`📄 ${allSelected.length} page${allSelected.length > 1 ? 's' : ''} pushed to Project Prompts`, 'success');
        }
    } else {
        if (typeof showToast === 'function') showToast('⚠️ Project Prompts not found', 'error');
    }
}

// Generate Page-Specific Prompt
function generatePagePrompt(page) {
    const pagePrompts = {
        // Standard Pages
        'home': 'Create an engaging homepage with hero section, key features, testimonials, and call-to-action.',
        'about': 'Create an About Us page with company story, mission, vision, team introduction, and values.',
        'contact': 'Create a Contact page with contact form, map integration, contact details, and office hours.',
        'services': 'Create a Services page listing all services with descriptions, pricing options, and CTAs.',
        'products': 'Create a Products page with product grid, filtering, sorting, and quick view functionality.',
        'shop': 'Create a Shop page with product catalog, categories, search, and add-to-cart functionality.',
        'portfolio': 'Create a Portfolio page showcasing projects with filters, lightbox gallery, and case study links.',
        'gallery': 'Create a Gallery page with image grid, categories, lightbox, and lazy loading.',
        'blog': 'Create a Blog page with article listings, categories, search, pagination, and sidebar.',
        'news': 'Create a News page with latest updates, press releases, and company announcements.',
        'team': 'Create a Team page displaying team members with photos, roles, bios, and social links.',
        'testimonials': 'Create a Testimonials page with customer reviews, ratings, and video testimonials.',
        'pricing': 'Create a Pricing page with pricing tables, feature comparisons, and subscription options.',
        'features': 'Create a Features page highlighting product/service features with icons and descriptions.',
        'faq': 'Create an FAQ page with accordion-style questions, categories, and search functionality.',
        'careers': 'Create a Careers page with job listings, application form, benefits, and company culture.',
        'support': 'Create a Support page with help center, knowledge base links, ticket system, and live chat.',
        'privacy': 'Create a Privacy Policy page with data handling practices, user rights, and compliance info.',
        'terms': 'Create a Terms of Service page with legal terms, usage policies, and user agreements.',
        'login': 'Create a Login page with secure authentication, remember me, and forgot password options.',
        'register': 'Create a Registration page with signup form, validation, and social login options.',
        '404': 'Create a 404 Error page with helpful message, search, navigation links, and back button.',
        'coming-soon': 'Create a Coming Soon page with countdown timer, email signup, and social links.',
        'sitemap': 'Create a Sitemap page listing all site pages organized by category with links.'
    };
    
    // Check if it's a predefined page
    if (pagePrompts[page.id]) {
        return pagePrompts[page.id];
    }
    
    // For custom pages, use description or generate generic prompt
    if (page.isCustom && page.desc) {
        return `Create a "${page.name}" page: ${page.desc}`;
    }
    
    // Check templates
    if (pcPageTemplates[page.id]) {
        return `Create a "${page.name}" page: ${pcPageTemplates[page.id].desc}`;
    }
    
    // Generic prompt for unknown pages
    return `Create a "${page.name}" page with appropriate content, layout, and functionality.`;
}

