};

// Smart classify: looks up the map, falls back to keyword heuristics for custom pages
function pcClassifyPage(pageId, pageName) {
    // Direct map lookup
    if (pcPageClassification[pageId]) {
        return pcPageClassification[pageId];
    }

    // Keyword-based heuristics for custom / template pages
    const lowerName = (pageName || pageId).toLowerCase();
    const lowerID   = pageId.toLowerCase();

    const backendKeywords = [
        'login', 'register', 'signup', 'sign-up', 'auth', 'admin', 'dashboard',
        'profile', 'account', 'settings', 'password', 'cart', 'checkout',
        'order', 'payment', 'invoice', 'billing', 'subscription', 'booking',
        'appointment', 'ticket', 'api', 'webhook', 'cron', 'migration',
        'notification', 'message', 'inbox', 'wishlist', 'return', 'refund',
        'shipping', 'tracking', 'backend', 'server', 'database', 'upload'
    ];

    const frontendKeywords = [
        'home', 'landing', 'hero', 'gallery', 'portfolio', 'showcase',
        'coming-soon', 'under-construction', 'maintenance', '404', 'error',
        'sitemap', 'splash', 'intro', 'welcome', 'preview', 'demo',
        'frontend', 'ui', 'animation', 'visual'
    ];

    for (const kw of backendKeywords) {
        if (lowerID.includes(kw) || lowerName.includes(kw)) return 'backend';
    }
    for (const kw of frontendKeywords) {
        if (lowerID.includes(kw) || lowerName.includes(kw)) return 'frontend';
    }

    // Default to 'page' (normal content page)
    return 'page';
}

// Push selected pages into the Project Folder Template under the root of the detected folder
function pcPushToDashboard() {
    // Gather all selected pages
    const selectedPredefined = pcSelectedPredefined.map(id => {
        const page = pcPredefinedPages.find(p => p.id === id);
        return page ? { id: page.id, name: page.name, isCustom: false } : null;
    }).filter(Boolean);

    const selectedCustom = pcCustomPages.filter(p => p.checked).map(p => ({
        id: p.id,
        name: p.name,
        desc: p.desc,
        isCustom: true
    }));

    const allSelected = [...selectedPredefined, ...selectedCustom];

    if (allSelected.length === 0) {
        if (typeof showToast === 'function') showToast('⚠️ No pages selected', 'warning');
        return;
    }

    // Check folder template functions exist
    if (typeof ftFolderStore === 'undefined' || typeof ftAddFolderCard !== 'function') {
        if (typeof showToast === 'function') showToast('⚠️ Project Folder Template not found', 'error');
        return;
    }

    // ── Detect target folder from Project File Uploader ──
    let targetFolderName = null;

    // 1. Try root folder from Project File Uploader
    if (typeof ufRootFolder !== 'undefined' && ufRootFolder && ufRootFolder.name) {
        targetFolderName = '📁 ' + ufRootFolder.name;
    }
    // 2. Try first folder in ufFileStorage
    else if (typeof ufFileStorage !== 'undefined' && ufFileStorage.folders && ufFileStorage.folders.length > 0) {
        targetFolderName = '📁 ' + ufFileStorage.folders[0].name;
    }

    // 3. If not found in ftFolderStore, try any existing folder card (not DB)
    if (!targetFolderName || !ftFolderStore.has(targetFolderName)) {
        let foundFolder = null;
        ftFolderStore.forEach((data, name) => {
            if (!foundFolder && !name.startsWith('🗄️ DB: ')) {
                foundFolder = name;
            }
        });
        if (foundFolder) {
            targetFolderName = foundFolder;
        }
    }

    // 4. If still no folder found, create a new one
    if (!targetFolderName || !ftFolderStore.has(targetFolderName)) {
        targetFolderName = '📁 Project Pages';
    }

    // ── Get general notes from Pages Creator textarea ──
    const pcNotesTA = document.getElementById('pcGeneralNotes');
    const pcNotesContent = pcNotesTA ? pcNotesTA.value.trim() : '';

    // ── Build page nodes using selected file extension ──
    const pcExt = pcGetExtension();
    const pageNodes = allSelected.map(page => {
        const desc = generatePagePrompt(page);
        return {
            name: page.name + pcExt,
            type: 'file',
            description: '🆕 New Page — ' + desc,
            children: []
        };
    });

    // ── Add pages under root of existing folder or create new card ──
    const sid = ftGetSafeId(targetFolderName);

    if (ftFolderStore.has(targetFolderName)) {
        const data = ftFolderStore.get(targetFolderName);

        if (data.treeData && Array.isArray(data.treeData)) {
            // Add page nodes directly under root, avoiding duplicates
            pageNodes.forEach(pn => {
                if (!data.treeData.some(existing => existing.name === pn.name && existing.type === 'file')) {
                    data.treeData.push(pn);
                }
            });
        } else {
            data.treeData = [...pageNodes];
        }

        // Append general notes to folder card notes
        if (pcNotesContent) {
            const existing = (data.notes || '').trim();
            data.notes = existing ? existing + '\n\n' + pcNotesContent : pcNotesContent;
        }

        // Update tree text
        data.treeText = buildTreeDiagram(targetFolderName, data.treeData);
        data._dirty = false;

        // Re-render the card
        ftClearNodeMapForSid(sid);
        const cardEl = document.getElementById('ftCard_' + sid);
        if (cardEl) {
            cardEl.outerHTML = ftRenderCard(targetFolderName);
            requestAnimationFrame(() => {
                ftInitAutoResize(sid);
                // Sync notes textarea in the rendered card
                const notesEl = document.getElementById('ftNotes_' + sid);
                if (notesEl) notesEl.value = data.notes || '';
            });
        } else {
            ftAddFolderCard(targetFolderName);
        }
    } else {
        // No folder exists — create a new card with just the pages
        const treeData = [...pageNodes];
        const treeText = buildTreeDiagram(targetFolderName, treeData);

        ftFolderStore.set(targetFolderName, {
            path: 'Pages Creator',
            treeText: treeText,
            treeData: treeData,
            notes: pcNotesContent,
            addedAt: Date.now(),
            _dirty: false
        });
        ftIdToName.set(sid, targetFolderName);
        knownFolders.set(targetFolderName, { addedAt: Date.now(), path: 'Pages Creator' });
        ftAddFolderCard(targetFolderName);
    }

    ftUpdateContainer();

    // Success feedback
    const shortName = targetFolderName.replace('📁 ', '');
    if (typeof showToast === 'function') {
        showToast(`🚀 ${allSelected.length} page${allSelected.length > 1 ? 's' : ''} pushed under "${shortName}" folder`, 'success');
    }
}

// Hide template results when clicking outside
document.addEventListener('click', function(e) {
    const results = document.getElementById('pcTemplateResults');
    const searchWrap = document.querySelector('.pc-template-search');
    if (results && searchWrap && !searchWrap.contains(e.target)) {
        results.classList.remove('active');
    }
});

// Initialize on DOM ready
document.addEventListener('DOMContentLoaded', function() {
    initPagesCreator();
});
</script>

<!-- Custom Instructions Tool Script -->
<script>
// ═══════════════════════════════════════════════════════════════════
// 📝 CUSTOM INSTRUCTIONS TOOL - Right Panel
// ═══════════════════════════════════════════════════════════════════

// Template definitions for quick add
const ciTemplates = {
    colors: '• Use a consistent color scheme throughout\n• Primary color: [specify color]\n• Secondary color: [specify color]\n• Accent color: [specify color]',
    animations: '• Add smooth scroll behavior\n• Include hover animations on buttons and cards\n• Add page transition effects\n• Use subtle loading animations',
    responsive: '• Ensure fully responsive design (mobile, tablet, desktop)\n• Mobile-first approach\n• Touch-friendly elements\n• Adaptive images and layouts',
    accessibility: '• Follow WCAG 2.1 AA standards\n• Add proper ARIA labels\n• Ensure keyboard navigation\n• Include skip links\n• High contrast text',
    darkmode: '• Add dark mode support with toggle\n• Use CSS variables for theme colors\n• Persist user preference\n• Smooth theme transitions',
    performance: '• Optimize images (lazy loading, WebP)\n• Minimize CSS/JS bundles\n• Implement code splitting\n• Add loading states\n• Cache static assets'
};

// Update character count
function ciUpdateCharCount() {
    const textarea = document.getElementById('ciTextarea');
    const counter = document.getElementById('ciCharCount');
    const badge = document.getElementById('ciBadge');
    
    if (textarea && counter) {
        const count = textarea.value.length;
        counter.textContent = `${count} chars`;
        counter.classList.toggle('has-content', count > 0);
        
        // Update badge
        if (badge) {
            if (count > 0) {
                badge.style.display = 'inline';
                badge.textContent = count > 999 ? '999+' : count;
            } else {
                badge.style.display = 'none';
            }
        }
        
        // Save to localStorage
        ciSaveToStorage();
    }
}

// Add template text
function ciAddTemplate(templateKey) {
    const textarea = document.getElementById('ciTextarea');
    if (!textarea || !ciTemplates[templateKey]) return;
    
    const template = ciTemplates[templateKey];
    const currentValue = textarea.value.trim();
    
    if (currentValue) {
        textarea.value = currentValue + '\n\n' + template;
    } else {
        textarea.value = template;
    }
    
    ciUpdateCharCount();
    
    if (typeof showToast === 'function') {
        showToast(`✨ Added ${templateKey} template`, 'success');
    }
}

// Push to Project Notes
function ciPushToNotes() {
    const textarea = document.getElementById('ciTextarea');
    const content = textarea ? textarea.value.trim() : '';
    
    if (!content) {
        if (typeof showToast === 'function') showToast('⚠️ No instructions to push', 'warning');
        return;
    }
    
    // Build the prompt text
    let promptText = `📝 CUSTOM INSTRUCTIONS:\n${'═'.repeat(50)}\n\n`;
    promptText += content;
    promptText += `\n\n${'═'.repeat(50)}\n`;
    
    // Push to Project Notes
    const notesTextarea = document.getElementById('projectNotesTextarea');
    if (notesTextarea) {
        if (notesTextarea.value.trim()) {
            notesTextarea.value = notesTextarea.value.trimEnd() + '\n\n' + promptText;
        } else {
            notesTextarea.value = promptText;
        }
        
        // Save to localStorage
        if (typeof saveProjectNotesToStorage === 'function') {
            saveProjectNotesToStorage();
        }
        
        if (typeof showToast === 'function') {
            showToast('📝 Instructions pushed to Project Prompts', 'success');
        }
    } else {
        if (typeof showToast === 'function') showToast('⚠️ Project Prompts not found', 'error');
    }
}

// Reset Custom Instructions
function resetCustomInstructions(skipToast = false) {
    const textarea = document.getElementById('ciTextarea');
    if (textarea) {
        textarea.value = '';
    }
    
    ciUpdateCharCount();
    localStorage.removeItem('ci_content');
    
    if (!skipToast && typeof showToast === 'function') {
        showToast('🔄 Instructions cleared', 'info');
    }
    console.log('✅ Custom Instructions reset');
}

// Save to localStorage
function ciSaveToStorage() {
    const textarea = document.getElementById('ciTextarea');
    if (textarea) {
        localStorage.setItem('ci_content', textarea.value);
    }
}

// Load from localStorage
function ciLoadFromStorage() {
    const saved = localStorage.getItem('ci_content');
    if (saved) {
        const textarea = document.getElementById('ciTextarea');
        if (textarea) {
            textarea.value = saved;
            ciUpdateCharCount();
        }
    }
}

// Get Custom Instructions content (for prompt generation)
function getCustomInstructions() {
    const textarea = document.getElementById('ciTextarea');
    return textarea ? textarea.value.trim() : '';
}

// Initialize on DOM ready
document.addEventListener('DOMContentLoaded', function() {
    ciLoadFromStorage();
});
</script>

