// Push to Project Prompts
function dtPushToNotes() {
    const projectNotesTextarea = document.getElementById('projectNotesTextarea');
    if (!projectNotesTextarea) return;
    
    const notesContent = document.getElementById('dtNotesTextarea')?.value.trim() || '';
    
    if (dtSelectedThemes.length === 0 && !notesContent) {
        showToast('⚠️ No themes selected or notes to push', 'warning');
        return;
    }
    
    // Theme descriptions
    const themeDescriptions = {
        'ai-decision': 'Let AI analyze and choose the perfect theme automatically based on content and purpose',
        'minimalist': 'Clean, simple design with plenty of white space and focus on content',
        'vibrant': 'Bold colors, energetic gradients, and eye-catching creative design',
        'dark-elegant': 'Sophisticated dark mode with subtle contrasts and premium feel',
        'glassmorphism': 'Frosted glass effect with backdrop blur and modern transparency',
        'gradient-waves': 'Flowing gradients with animated wave effects for dynamic appearance',
        'corporate': 'Business-oriented with trustworthy colors and structured layout',
        'retro': 'Nostalgic design with warm colors and classic aesthetics',
        'neon-cyberpunk': 'Futuristic neon with cyan, magenta creating high-tech atmosphere',
        'sunset-paradise': 'Warm sunset colors with orange, pink, purple creating paradise vibe',
        'ocean-breeze': 'Fresh aqua blues, turquoise, and sea green for calming feel',
        'forest-nature': 'Natural earth tones with deep greens for organic atmosphere',
        'berry-blast': 'Rich berry colors with raspberry, violet, fuchsia for vibrant look',
        'candy-pop': 'Pastel candy colors with bubblegum pink, sky blue, mint green',
        'fire-ice': 'Contrasting hot reds and oranges with cool icy blues for dramatic impact',
        'royal-luxury': 'Opulent gold, royal purple, deep blue for premium luxurious experience',
        'tropical-vibes': 'Lush tropical greens, mango orange, coral pink for exotic energy',
        'midnight-aurora': 'Mystical northern lights with deep blue, aurora green, celestial pink',
        'earthy-terracotta': 'Warm earth tones with terracotta clay, burnt orange, sandy beige',
        'pastel-dreams': 'Soft pastel palette with blush pink, baby blue, lavender for dreamy aesthetic',
        'electric-energy': 'High-voltage neon yellows, electric greens, hot pinks for maximum energy',
        'cherry-blossom': 'Delicate sakura pink, white blossoms, soft green for serene Japanese feel',
        'desert-sunset': 'Warm desert sands, sunset orange, adobe red for southwestern vibe'
    };
    
    let promptContent = `\n\n🎨 DESIGN THEME SELECTION\n`;
    promptContent += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
    
    const hasAI = dtSelectedThemes.includes('ai-decision');
    const otherThemes = dtSelectedThemes.filter(t => t !== 'ai-decision');
    
    // Case 1: ONLY AI Decision selected
    if (hasAI && otherThemes.length === 0) {
        promptContent += `**Mode: AI Creative Freedom**\n\n`;
        promptContent += `🤖 **AI DECISION - FULL CREATIVE CONTROL**\n`;
        promptContent += `The AI has complete creative freedom to design the theme from its own imagination.\n\n`;
        promptContent += `**Instructions for AI:**\n`;
        promptContent += `- Analyze the website content, purpose, and target audience\n`;
        promptContent += `- Create a unique, custom theme that best fits the application\n`;
        promptContent += `- Design original color palettes, typography, and visual elements\n`;
        promptContent += `- Consider modern design trends while ensuring usability\n`;
        promptContent += `- Generate complete CSS variables and styling rules\n`;
    }
    // Case 2: AI Decision + Other Themes selected
    else if (hasAI && otherThemes.length > 0) {
        promptContent += `**Mode: AI Selection from Provided Themes**\n\n`;
        promptContent += `🤖 **AI DECISION + THEME OPTIONS**\n\n`;
        
        promptContent += `**CRITICAL - Before selecting a theme, the AI MUST:**\n`;
        promptContent += `1. **Read and analyze all uploaded files thoroughly** to understand the website content\n`;
        promptContent += `2. **Study the functionality and features** of the website (forms, navigation, interactivity)\n`;
        promptContent += `3. **Understand the environment and purpose** (e-commerce, portfolio, dashboard, blog, etc.)\n`;
        promptContent += `4. **Analyze the structure and code organization** to determine the appropriate visual approach\n`;
        promptContent += `5. **Consider the objectives and target audience** based on the content analysis\n\n`;
        
        promptContent += `**After comprehensive analysis, the AI should:**\n`;
        promptContent += `- SELECT the most appropriate theme from the ${otherThemes.length} option(s) below\n`;
        promptContent += `- Ensure the selected theme is compatible with the website's functionality and objectives\n`;
        promptContent += `- You may blend elements from multiple themes if it better serves the website's purpose\n`;
        promptContent += `- Apply the selected theme's CSS variables and styling\n\n`;
        
        promptContent += `**Available Theme Options (${otherThemes.length}):**\n`;
        promptContent += `─────────────────────────────────\n\n`;
        
        otherThemes.forEach((theme, index) => {
            const themeName = theme.replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
            promptContent += `**${index + 1}. ${themeName}**\n`;
            promptContent += `📝 ${themeDescriptions[theme] || 'Custom theme'}\n\n`;
            if (dtThemeCSS[theme]) {
                promptContent += `\`\`\`css\n/* ${themeName} Theme CSS */\n${dtThemeCSS[theme]}\n\`\`\`\n\n`;
            }
        });
        
        promptContent += `**AI Final Instruction:** Based on your comprehensive analysis of the uploaded content, website functionality, structure, and environment, select the theme that is most compatible with the website's objectives and provides the best user experience.\n`;
    }
    // Case 3: Only specific themes selected (no AI)
    else if (otherThemes.length > 0) {
        if (otherThemes.length === 1) {
            promptContent += `**Mode: Single Theme Application**\n\n`;
            promptContent += `Apply the following theme exactly as specified:\n\n`;
        } else {
            promptContent += `**Mode: Multi-Theme Blend**\n\n`;
            promptContent += `Blend the following ${otherThemes.length} themes intelligently:\n\n`;
        }
        
        otherThemes.forEach((theme, index) => {
            const themeName = theme.replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
            promptContent += `**${index + 1}. ${themeName}**\n`;
            promptContent += `📝 ${themeDescriptions[theme] || 'Custom theme'}\n\n`;
            if (dtThemeCSS[theme]) {
                promptContent += `\`\`\`css\n/* ${themeName} Theme CSS */\n${dtThemeCSS[theme]}\n\`\`\`\n\n`;
            }
        });
        
        if (otherThemes.length > 1) {
            promptContent += `**IMPORTANT - Multi-Theme Instructions:**\n`;
            promptContent += `- Intelligently blend elements from all ${otherThemes.length} selected themes\n`;
            promptContent += `- Create a cohesive design that incorporates the best aspects of each\n`;
            promptContent += `- Ensure color harmonization and visual consistency\n`;
            promptContent += `- The final design should feel unified, not fragmented\n`;
        }
    }
    
    // Additional notes
    if (notesContent) {
        promptContent += `\n**Additional Theme Instructions:**\n${notesContent}\n`;
    }
    
    // Append to Project Prompts
    const currentContent = projectNotesTextarea.value;
    projectNotesTextarea.value = currentContent + promptContent;
    
    // Trigger auto-resize
    if (typeof autoResizeTextarea === 'function') {
        autoResizeTextarea(projectNotesTextarea);
    }
    
    // Save
    localStorage.setItem('projectPrompts', projectNotesTextarea.value);
    
    const modeText = hasAI && otherThemes.length === 0 ? 'AI Creative Mode' : 
                     hasAI && otherThemes.length > 0 ? `AI Selection (${otherThemes.length} options)` :
                     `${otherThemes.length} theme(s)`;
    showToast(`🎨 ${modeText} pushed to Project Prompts`, 'success');
}

// Save to storage
function dtSaveToStorage() {
    localStorage.setItem('dtSelectedThemes', JSON.stringify(dtSelectedThemes));
}

// Load from storage
function dtLoadFromStorage() {
    try {
        const stored = localStorage.getItem('dtSelectedThemes');
        if (stored) {
            dtSelectedThemes = JSON.parse(stored);
        }
        dtLoadNotesFromStorage();
    } catch (e) {
        console.error('Error loading design theme state:', e);
    }
}

// Save notes to storage
function dtSaveNotesToStorage() {
    const textarea = document.getElementById('dtNotesTextarea');
    if (textarea) {
        localStorage.setItem('dtNotes', textarea.value);
    }
}

// Load notes from storage
function dtLoadNotesFromStorage() {
    const textarea = document.getElementById('dtNotesTextarea');
    const stored = localStorage.getItem('dtNotes');
    if (textarea && stored) {
        textarea.value = stored;
        dtUpdateCharCount();
    }
}

// Reset all
function dtResetAll(skipToast = false) {
    dtSelectedThemes = ['ai-decision'];
    
    // Clear notes
    const notesTextarea = document.getElementById('dtNotesTextarea');
    if (notesTextarea) {
        notesTextarea.value = '';
        dtUpdateCharCount();
    }
    
    // Clear search
    dtClearSearch();
    
    // Clear storage
    localStorage.removeItem('dtSelectedThemes');
    localStorage.removeItem('dtNotes');
    
    // Update UI
    dtUpdateUI();
    
    if (!skipToast) {
        showToast('🎨 Design themes reset', 'info');
    }
}

// Confirm reset
async function confirmResetDesignTheme() {
    if (typeof deConfirm === 'function') {
        const confirmed = await deConfirm({
            title: 'Reset Design Themes',
            subtitle: 'Design Enhancer',
            message: 'Are you sure you want to reset theme selection to default (AI Decision)?',
            warning: 'All selected themes and notes will be cleared.',
            confirmText: 'Reset',
            icon: 'fa-palette'
        });
        if (confirmed) {
            dtResetAll();
        }
    } else {
        if (confirm('Reset theme selection?')) {
            dtResetAll();
        }
    }
}

// Initialize on load
document.addEventListener('DOMContentLoaded', dtInit);
</script>

<!-- ═══════════════════════════════════════════════════════════════════
     🏗️ PAGE LAYOUT STRUCTURE TOOL - JavaScript
     ═══════════════════════════════════════════════════════════════════ -->
<script>
// Page Layout state
let plSelectedLayouts = ['ai-decision'];

// Layout descriptions for prompt generation
const plLayoutDescriptions = {
    'ai-decision': {
        name: 'AI Decision',
        description: 'Let AI analyze your content and automatically choose the best layout structure based on your application\'s needs',
        css: '/* AI will determine the optimal layout based on content analysis */'
    },
    'single-page': {
        name: 'Single Page',
        description: 'One continuous scrolling page with all content in sequential sections',
        css: `/* Single Page Layout */
.page-container { max-width: 1200px; margin: 0 auto; }
.section { padding: 4rem 2rem; }
.hero-section { min-height: 100vh; display: flex; align-items: center; }
.content-section { border-bottom: 1px solid var(--border-color); }`
    },
    'multi-section': {
        name: 'Multi-Section',
        description: 'Classic header, multiple content sections, and footer layout',
        css: `/* Multi-Section Layout */
.page-wrapper { display: flex; flex-direction: column; min-height: 100vh; }
header { position: sticky; top: 0; z-index: 100; }
main { flex: 1; }
footer { background: var(--footer-bg); padding: 2rem; }
.section { padding: 3rem 2rem; }`
    },
    'sidebar': {
        name: 'Sidebar Layout',
        description: 'Persistent sidebar navigation with main content area',
        css: `/* Sidebar Layout */
.app-container { display: grid; grid-template-columns: 250px 1fr; min-height: 100vh; }
.sidebar { position: sticky; top: 0; height: 100vh; overflow-y: auto; background: var(--sidebar-bg); }
.main-content { padding: 2rem; overflow-y: auto; }
@media (max-width: 768px) { .app-container { grid-template-columns: 1fr; } .sidebar { display: none; } }`
    },
    'masonry': {
        name: 'Grid Masonry',
        description: 'Pinterest-style grid with variable height cards',
        css: `/* Grid Masonry Layout */
.masonry-container { columns: 3; column-gap: 1.5rem; padding: 2rem; }
.masonry-item { break-inside: avoid; margin-bottom: 1.5rem; border-radius: 12px; overflow: hidden; }
@media (max-width: 1024px) { .masonry-container { columns: 2; } }
@media (max-width: 640px) { .masonry-container { columns: 1; } }`
    },
    'magazine': {
        name: 'Magazine Style',
        description: 'Featured hero area with main content and sidebar sections',
        css: `/* Magazine Style Layout */
.magazine-layout { display: grid; grid-template-columns: 2fr 1fr; gap: 2rem; padding: 2rem; }
.featured-hero { grid-column: span 2; height: 60vh; border-radius: 16px; overflow: hidden; }
.main-articles { display: flex; flex-direction: column; gap: 1.5rem; }
.sidebar-content { position: sticky; top: 2rem; }`
    },
    'dashboard': {
        name: 'Dashboard',
        description: 'Data-focused layout with cards, charts, and metrics',
        css: `/* Dashboard Layout */
.dashboard-container { display: grid; grid-template-columns: repeat(12, 1fr); gap: 1.5rem; padding: 1.5rem; }
.dashboard-nav { grid-column: span 12; }
.metric-card { grid-column: span 3; padding: 1.5rem; border-radius: 12px; background: var(--card-bg); }
.chart-container { grid-column: span 6; min-height: 300px; }
@media (max-width: 1024px) { .metric-card { grid-column: span 6; } .chart-container { grid-column: span 12; } }`
    },
    'landing': {
        name: 'Landing Page',
        description: 'Hero section with feature blocks and clear call-to-action',
        css: `/* Landing Page Layout */
.landing-hero { min-height: 80vh; display: flex; align-items: center; justify-content: center; text-align: center; }
.hero-cta { display: flex; gap: 1rem; justify-content: center; margin-top: 2rem; }
.features-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 2rem; padding: 4rem 2rem; }
.feature-card { text-align: center; padding: 2rem; border-radius: 16px; }`
    }
};

// Initialize Page Layout
function plInit() {
    plLoadFromStorage();
    plUpdateUI();
}

// Toggle layout selection
function plToggleLayout(layoutValue, cardElement) {
    const index = plSelectedLayouts.indexOf(layoutValue);
    
    if (index > -1) {
        // Remove from selection
        plSelectedLayouts.splice(index, 1);
        cardElement.classList.remove('selected');
    } else {
        // Add to selection
        plSelectedLayouts.push(layoutValue);
        cardElement.classList.add('selected');
    }
    
    // Update UI
    plUpdateUI();
    plSaveToStorage();
    
    // Show notification
    const layoutName = plLayoutDescriptions[layoutValue]?.name || layoutValue;
    if (index > -1) {
        showToast(`Layout removed: ${layoutName}`, 'info');
    } else {
        showToast(`🏗️ Layout added: ${layoutName}`, 'success');
    }
}

// Update UI elements
function plUpdateUI() {
    // Update badge
    const badge = document.getElementById('plBadge');
    if (badge) {
        badge.textContent = plSelectedLayouts.length > 0 
            ? `${plSelectedLayouts.length} layout${plSelectedLayouts.length > 1 ? 's' : ''}` 
            : '0';
        badge.style.display = plSelectedLayouts.length > 0 ? 'inline-flex' : 'none';
    }
    
    // Update count info
    const countText = document.getElementById('plCountText');
    const countBadge = document.getElementById('plCountBadge');
    if (countText && countBadge) {
        if (plSelectedLayouts.length > 0) {
            countText.textContent = `${plSelectedLayouts.length} layout${plSelectedLayouts.length > 1 ? 's' : ''} selected`;
        } else {
            countText.textContent = 'Select layouts for your design';
        }
        countBadge.textContent = plSelectedLayouts.length;
    }
    
    // Update mix indicator
    plUpdateMixIndicator();
    
    // Update card selections
    document.querySelectorAll('.pl-layout-card').forEach(card => {
        const layoutValue = card.getAttribute('data-layout');
        if (plSelectedLayouts.includes(layoutValue)) {
            card.classList.add('selected');
        } else {
            card.classList.remove('selected');
        }
    });
}

// Update mix indicator
function plUpdateMixIndicator() {
    const indicator = document.getElementById('plMixIndicator');
    const mixText = document.getElementById('plMixText');
    
    if (indicator && mixText) {
        if (plSelectedLayouts.length > 1) {
            indicator.classList.add('visible');
            
            const hasAI = plSelectedLayouts.includes('ai-decision');
            if (hasAI) {
                mixText.innerHTML = `<strong style="color: #f97316;">🤖 AI-Powered Structural Fusion:</strong> AI will intelligently combine ${plSelectedLayouts.length} layouts`;
                indicator.style.borderColor = 'rgba(249, 115, 22, 0.5)';
                indicator.style.background = 'rgba(249, 115, 22, 0.15)';
            } else {
                const percentage = Math.round(100 / plSelectedLayouts.length);
                mixText.innerHTML = `<strong style="color: #10b981;">⚖️ Balanced Hybrid:</strong> ${plSelectedLayouts.length} layouts @ ~${percentage}% each`;
                indicator.style.borderColor = 'rgba(16, 185, 129, 0.5)';
                indicator.style.background = 'rgba(16, 185, 129, 0.15)';
            }
        } else {
            indicator.classList.remove('visible');
        }
    }
}

// Push to Project Prompts
function plPushToNotes() {
    const projectNotesTextarea = document.getElementById('projectNotesTextarea');
    if (!projectNotesTextarea) return;
    
    const notesContent = document.getElementById('plNotesTextarea')?.value.trim() || '';
    
    if (plSelectedLayouts.length === 0 && !notesContent) {
        showToast('⚠️ No layouts selected or notes to push', 'warning');
        return;
    }
    
    let promptContent = `\n\n🏗️ PAGE LAYOUT STRUCTURE\n`;
    promptContent += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
    
    if (plSelectedLayouts.length > 0) {
        const hasAI = plSelectedLayouts.includes('ai-decision');
        const otherLayouts = plSelectedLayouts.filter(l => l !== 'ai-decision');
        
        promptContent += `**Selected Layout${plSelectedLayouts.length > 1 ? 's' : ''} (${plSelectedLayouts.length}):**\n\n`;
        
        // Handle AI Decision logic (similar to Design Theme)
        if (hasAI && otherLayouts.length > 0) {
            // AI with other layouts - AI selects from the listed layouts
            promptContent += `**🤖 AI Decision Mode + Specific Layouts:**\n\n`;
            promptContent += `**IMPORTANT - Before selecting a layout, the AI MUST:**\n`;
            promptContent += `1. **Read and analyze all uploaded files thoroughly** to understand the website content\n`;
            promptContent += `2. **Study the functionality and features** of the website (forms, navigation, interactivity)\n`;
            promptContent += `3. **Understand the environment and purpose** (e-commerce, portfolio, dashboard, blog, etc.)\n`;
            promptContent += `4. **Analyze the structure and code organization** to determine the best layout approach\n`;
            promptContent += `5. **Consider the objectives and target audience** based on the content analysis\n\n`;
            promptContent += `After thorough analysis, select the most appropriate layout from the following options that best serves the website's functionality and objectives:\n\n`;
            
            plSelectedLayouts.forEach((layout, index) => {
                const layoutInfo = plLayoutDescriptions[layout];
                if (layoutInfo) {
                    promptContent += `${index + 1}. **${layoutInfo.name}**\n`;
                    promptContent += `   → ${layoutInfo.description}\n`;
                    if (layout !== 'ai-decision') {
                        promptContent += `   CSS Reference:\n\`\`\`css\n${layoutInfo.css}\n\`\`\`\n`;
                    }
                }
            });
            
            promptContent += `\n**AI Instruction:** Based on your comprehensive analysis of the uploaded content, website functionality, structure, and environment, select the most suitable layout from the options above that is fully compatible with the website's objectives and user experience goals. You may also create an intelligent hybrid combining the best structural elements from multiple layouts if it better serves the website's purpose.\n`;
        } else if (hasAI && otherLayouts.length === 0) {
            // Only AI Decision - AI creates layout from imagination
            promptContent += `**🤖 Full AI Decision:**\n`;
            promptContent += `The AI should analyze the uploaded content and determine the optimal page layout structure from its own expertise. Consider:\n`;
            promptContent += `- Content type and purpose\n`;
            promptContent += `- User flow and navigation patterns\n`;
            promptContent += `- Responsive design requirements\n`;
            promptContent += `- Industry best practices\n`;
            promptContent += `\nCreate the most suitable layout structure based on your analysis.\n`;
        } else {
            // No AI - use selected layouts directly
            plSelectedLayouts.forEach((layout, index) => {
                const layoutInfo = plLayoutDescriptions[layout];
                if (layoutInfo) {
                    promptContent += `${index + 1}. **${layoutInfo.name}**\n`;
                    promptContent += `   → ${layoutInfo.description}\n`;
                    promptContent += `   CSS Reference:\n\`\`\`css\n${layoutInfo.css}\n\`\`\`\n`;
                }
            });
            
            if (plSelectedLayouts.length > 1) {
                promptContent += `\n**IMPORTANT:** Multiple layouts selected. Intelligently blend these layouts, taking the best structural elements from each to create a cohesive design.\n`;
            }
        }
    }
    
    // Additional notes
    if (notesContent) {
        promptContent += `\n**Additional Layout Instructions:**\n${notesContent}\n`;
    }
    
    // Append to Project Prompts
    const currentContent = projectNotesTextarea.value;
    projectNotesTextarea.value = currentContent + promptContent;
    
    // Trigger auto-resize
    if (typeof autoResizeTextarea === 'function') {
        autoResizeTextarea(projectNotesTextarea);
    }
    
    // Save
    localStorage.setItem('projectPrompts', projectNotesTextarea.value);
    
    showToast(`🏗️ ${plSelectedLayouts.length} layout(s) pushed to Project Prompts`, 'success');
}

// Update character count
function plUpdateCharCount() {
    const textarea = document.getElementById('plNotesTextarea');
    const charCount = document.getElementById('plCharCount');
    if (textarea && charCount) {
        charCount.textContent = `${textarea.value.length} characters`;
        plSaveNotesToStorage();
    }
}

// Save notes to storage
function plSaveNotesToStorage() {
    const textarea = document.getElementById('plNotesTextarea');
    if (textarea) {
        localStorage.setItem('plNotes', textarea.value);
    }
}

// Load notes from storage
function plLoadNotesFromStorage() {
    const saved = localStorage.getItem('plNotes');
    if (saved) {
        const textarea = document.getElementById('plNotesTextarea');
        if (textarea) {
            textarea.value = saved;
            plUpdateCharCount();
        }
    }
}

// Save to storage
function plSaveToStorage() {
    localStorage.setItem('plSelectedLayouts', JSON.stringify(plSelectedLayouts));
}

// Load from storage
function plLoadFromStorage() {
    const saved = localStorage.getItem('plSelectedLayouts');
    if (saved) {
        try {
            plSelectedLayouts = JSON.parse(saved);
        } catch (e) {
            plSelectedLayouts = ['ai-decision'];
        }
    }
    plLoadNotesFromStorage();
}

// Reset all
function plResetAll(skipToast = false) {
    plSelectedLayouts = ['ai-decision'];
    
    // Reset textarea
    const textarea = document.getElementById('plNotesTextarea');
    if (textarea) {
        textarea.value = '';
    }
    
    // Update UI
    plUpdateUI();
    plUpdateCharCount();
    plSaveToStorage();
    localStorage.removeItem('plNotes');
    
    if (!skipToast) {
        showToast('🔄 Layouts reset to AI Decision', 'info');
    }
}

// Confirm reset
function confirmResetLayout() {
    if (typeof deConfirm === 'function') {
        deConfirm('Reset layout selection to AI Decision?', () => {
            plResetAll();
        });
    } else {
        if (confirm('Reset layout selection?')) {
            plResetAll();
        }
    }
}

// Initialize on load
document.addEventListener('DOMContentLoaded', plInit);
</script>

<!-- ═══════════════════════════════════════════════════════════════════
     🚀 EXECUTION MODE TOOL - JavaScript
     ═══════════════════════════════════════════════════════════════════ -->
<script>
// Execution Mode state
let currentExecutionMode = 'read-before';

// Initialize Execution Mode
function emInit() {
    emLoadFromStorage();
    emUpdateUI();
}

// Update mode when dropdown changes
function emUpdateMode() {
    const select = document.getElementById('emSelect');
    if (!select) return;
    
    currentExecutionMode = select.value;
    
    // Update descriptions
    const readBeforeDesc = document.getElementById('emReadBeforeDesc');
    const defaultProcessDesc = document.getElementById('emDefaultProcessDesc');
    
    if (currentExecutionMode === 'read-before') {
        if (readBeforeDesc) readBeforeDesc.classList.add('active');
        if (defaultProcessDesc) defaultProcessDesc.classList.remove('active');
    } else {
        if (readBeforeDesc) readBeforeDesc.classList.remove('active');
        if (defaultProcessDesc) defaultProcessDesc.classList.add('active');
    }
    
    emUpdateBadge();
    emSaveToStorage();
}

// Update badge display
function emUpdateBadge() {
    const badge = document.getElementById('emBadge');
    if (!badge) return;
    
    if (currentExecutionMode === 'read-before') {
        badge.textContent = 'Read First';
        badge.style.background = 'linear-gradient(135deg, #22c55e 0%, #16a34a 100%)';
    } else {
        badge.textContent = 'Fast Mode';
        badge.style.background = 'linear-gradient(135deg, #f59e0b 0%, #d97706 100%)';
    }
}

// Update character count
function emUpdateCharCount() {
    const textarea = document.getElementById('emNotesTextarea');
    const countEl = document.getElementById('emCharCount');
    if (textarea && countEl) {
        const count = textarea.value.length;
        countEl.textContent = `${count} character${count !== 1 ? 's' : ''}`;
        emSaveToStorage();
    }
}

// Update UI from state
function emUpdateUI() {
    const select = document.getElementById('emSelect');
    if (select) {
        select.value = currentExecutionMode;
    }
    emUpdateMode();
    emUpdateCharCount();
}

// Push to Project Prompts
function emPushToNotes() {
    const notesTextarea = document.getElementById('emNotesTextarea');
    const additionalNotes = notesTextarea ? notesTextarea.value.trim() : '';
    
    // Build prompt text
    let promptText = `## 🚀 EXECUTION MODE\n\n`;
    
    if (currentExecutionMode === 'read-before') {
        promptText += `**📖 Mode: Read Before Executing (Recommended)**\n\n`;
        promptText += `⚠️ **CRITICAL INSTRUCTION:**\n`;
        promptText += `Before making ANY design decisions or code changes, you MUST:\n\n`;
        promptText += `1. **Read and analyze ALL uploaded files completely**\n`;
        promptText += `2. Understand the application's purpose, structure, and existing patterns\n`;
        promptText += `3. Identify the tech stack, frameworks, and design system in use\n`;
        promptText += `4. Note any existing color schemes, typography, and component styles\n`;
        promptText += `5. Only THEN proceed with context-aware, tailored enhancements\n\n`;
        promptText += `This ensures your changes are consistent with the existing codebase and design language.\n\n`;
    } else {
        promptText += `**⚡ Mode: Default Process (Faster)**\n\n`;
        promptText += `You may proceed at your own discretion:\n`;
        promptText += `- Read files as needed during execution\n`;
        promptText += `- Not required to analyze everything first\n`;
        promptText += `- Best suited for quick modifications\n`;
        promptText += `- Use your judgment on what needs reading\n\n`;
    }
    
    // Add additional notes if present
    if (additionalNotes) {
        promptText += `---\n\n### 📝 ADDITIONAL EXECUTION INSTRUCTIONS:\n\n`;
        promptText += `${additionalNotes}\n\n`;
        promptText += `---\n\n`;
    }
    
    // Push to Project Notes
    const projectNotesTextarea = document.getElementById('projectNotesTextarea');
    if (projectNotesTextarea) {
        if (projectNotesTextarea.value.trim()) {
            projectNotesTextarea.value = projectNotesTextarea.value.trimEnd() + '\n\n' + promptText;
        } else {
            projectNotesTextarea.value = promptText;
        }
        
        if (typeof saveProjectNotesToStorage === 'function') {
            saveProjectNotesToStorage();
        }
        
        const notesInfo = additionalNotes ? ' + custom instructions' : '';
        if (typeof showToast === 'function') {
            const modeName = currentExecutionMode === 'read-before' ? 'Read First' : 'Fast Mode';
            showToast(`🚀 Execution mode (${modeName})${notesInfo} pushed to Project Prompts`, 'success');
        }
    } else {
        if (typeof showToast === 'function') showToast('⚠️ Project Prompts not found', 'error');
    }
}

// Save to localStorage
function emSaveToStorage() {
    const data = {
        mode: currentExecutionMode,
        notes: document.getElementById('emNotesTextarea')?.value || ''
    };
    localStorage.setItem('em_data', JSON.stringify(data));
}

// Load from localStorage
function emLoadFromStorage() {
    const saved = localStorage.getItem('em_data');
    if (saved) {
        try {
            const data = JSON.parse(saved);
            currentExecutionMode = data.mode || 'read-before';
            const textarea = document.getElementById('emNotesTextarea');
            if (textarea && data.notes) {
                textarea.value = data.notes;
            }
        } catch (e) {
            currentExecutionMode = 'read-before';
        }
    }
}

// Reset execution mode
function emResetAll(skipToast = false) {
    currentExecutionMode = 'read-before';
    const textarea = document.getElementById('emNotesTextarea');
    if (textarea) {
        textarea.value = '';
    }
    emUpdateUI();
    localStorage.removeItem('em_data');
    
    if (!skipToast && typeof showToast === 'function') {
        showToast('🔄 Execution mode reset to default', 'info');
    }
}

// Confirm reset
async function confirmResetExecutionMode() {
    if (typeof deConfirm === 'function') {
        const confirmed = await deConfirm({
            title: 'Reset Execution Mode',
            subtitle: 'Design Enhancer',
            message: 'Are you sure you want to reset the execution mode?',
            warning: 'Mode will be set to "Read Before Executing" and notes will be cleared.',
            confirmText: 'Reset',
            icon: 'fa-rocket'
        });
        if (confirmed) {
            emResetAll();
        }
    } else if (confirm('Reset execution mode to default?')) {
        emResetAll();
    }
}

// Get execution mode (for external access)
function getExecutionMode() {
    return {
        mode: currentExecutionMode,
        notes: document.getElementById('emNotesTextarea')?.value.trim() || ''
    };
}

// Initialize on DOM ready
document.addEventListener('DOMContentLoaded', function() {
    emInit();
});
</script>

<!-- ═══════════════════════════════════════════════════════════════════
     🎨 DESIGN FOCUS AREAS TOOL - JavaScript
     ═══════════════════════════════════════════════════════════════════ -->
<script>
// Design Focus state
let dfSelectedOptions = {
    layout: true,
    colors: true,
    animations: true,
    responsive: true,
    modern: true,
    seo: true
};

// Option descriptions for prompt generation
const dfOptionDetails = {
    layout: {
        name: 'Layout & Structure',
        desc: 'Grid systems, flexbox, responsive design, spacing'
    },
    colors: {
        name: 'Colors & Typography',
        desc: 'Color schemes, fonts, text styling, readability'
    },
    animations: {
        name: 'Animations & Transitions',
        desc: 'Smooth transitions, hover effects, micro-interactions'
    },
    responsive: {
        name: 'Mobile Responsiveness',
        desc: 'Media queries, mobile-first design, touch optimization'
    },
    modern: {
        name: 'Modern CSS Features',
        desc: 'CSS Grid, variables, backdrop-filter, modern properties'
    },
    seo: {
        name: 'SEO & Marketing Keywords',
        desc: 'Auto-generate SEO meta tags, keywords, and descriptions for all pages'
    }
};

// Initialize Design Focus
function dfInit() {
    dfLoadFromStorage();
    dfUpdateUI();
}

// Toggle option
function dfToggleOption(label) {
    const option = label.getAttribute('data-option');
    const checkbox = label.querySelector('input[type="checkbox"]');
    
    // Toggle state
    dfSelectedOptions[option] = !dfSelectedOptions[option];
    checkbox.checked = dfSelectedOptions[option];
    
    // Update visual state
    if (dfSelectedOptions[option]) {
        label.classList.add('checked');
    } else {
        label.classList.remove('checked');
    }
    
    dfUpdateBadge();
    dfSaveToStorage();
}

// Update badge
function dfUpdateBadge() {
    const badge = document.getElementById('dfBadge');
    if (!badge) return;
    
    const total = Object.keys(dfSelectedOptions).length;
    const selected = Object.values(dfSelectedOptions).filter(v => v).length;
    badge.textContent = `${selected}/${total}`;
    
    // Change badge color based on selection
    if (selected === 0) {
        badge.style.background = 'linear-gradient(135deg, #64748b 0%, #475569 100%)';
    } else if (selected === total) {
        badge.style.background = 'linear-gradient(135deg, #a855f7 0%, #7c3aed 100%)';
    } else {
        badge.style.background = 'linear-gradient(135deg, #8b5cf6 0%, #6d28d9 100%)';
    }
}

// Update character count
function dfUpdateCharCount() {
    const textarea = document.getElementById('dfNotesTextarea');
    const countEl = document.getElementById('dfCharCount');
    if (textarea && countEl) {
        const count = textarea.value.length;
        countEl.textContent = `${count} character${count !== 1 ? 's' : ''}`;
        dfSaveToStorage();
    }
}

// Update UI from state
function dfUpdateUI() {
    Object.keys(dfSelectedOptions).forEach(option => {
        const checkbox = document.getElementById(`df_${option}`);
        const label = document.querySelector(`.df-checkbox-item[data-option="${option}"]`);
        
        if (checkbox) checkbox.checked = dfSelectedOptions[option];
        if (label) {
            if (dfSelectedOptions[option]) {
                label.classList.add('checked');
            } else {
                label.classList.remove('checked');
            }
        }
    });
    
    dfUpdateBadge();
    dfUpdateCharCount();
}

// Push to Project Prompts
function dfPushToNotes() {
    const selectedOptions = Object.keys(dfSelectedOptions).filter(k => dfSelectedOptions[k]);
    const notesTextarea = document.getElementById('dfNotesTextarea');
    const additionalNotes = notesTextarea ? notesTextarea.value.trim() : '';
    
    if (selectedOptions.length === 0 && !additionalNotes) {
        if (typeof showToast === 'function') showToast('⚠️ No focus areas selected and no notes to push', 'warning');
        return;
    }
    
    let promptText = `## 🎨 DESIGN FOCUS AREAS\n\n`;
    promptText += `**Selected Enhancement Areas (CSS/HTML):**\n\n`;
    
    if (selectedOptions.length > 0) {
        selectedOptions.forEach((option, index) => {
            const details = dfOptionDetails[option];
            promptText += `${index + 1}. **${details.name}**\n`;
            promptText += `   - ${details.desc}\n\n`;
        });
        
        // Special SEO section
        if (dfSelectedOptions.seo) {
            promptText += `### 🔍 SEO Requirements:\n`;
            promptText += `- Generate appropriate meta keywords for each page\n`;
            promptText += `- Create compelling meta descriptions\n`;
            promptText += `- Add Open Graph tags for social sharing\n`;
            promptText += `- Include Twitter Card metadata\n\n`;
        }
    } else {
        promptText += `No specific areas selected - AI will use general best practices.\n\n`;
    }
    
    // Add additional notes if present
    if (additionalNotes) {
        promptText += `---\n\n### 📝 ADDITIONAL DESIGN INSTRUCTIONS:\n\n`;
        promptText += `${additionalNotes}\n\n`;
        promptText += `---\n\n`;
    }
    
    // Push to Project Notes
    const projectNotesTextarea = document.getElementById('projectNotesTextarea');
    if (projectNotesTextarea) {
        if (projectNotesTextarea.value.trim()) {
            projectNotesTextarea.value = projectNotesTextarea.value.trimEnd() + '\n\n' + promptText;
        } else {
            projectNotesTextarea.value = promptText;
        }
        
        if (typeof saveProjectNotesToStorage === 'function') {
            saveProjectNotesToStorage();
        }
        
        const notesInfo = additionalNotes ? ' + custom notes' : '';
        if (typeof showToast === 'function') {
            showToast(`🎨 ${selectedOptions.length} focus area(s)${notesInfo} pushed to Project Prompts`, 'success');
        }
    } else {
        if (typeof showToast === 'function') showToast('⚠️ Project Prompts not found', 'error');
    }
}

// Save to localStorage
function dfSaveToStorage() {
    const data = {
        options: dfSelectedOptions,
        notes: document.getElementById('dfNotesTextarea')?.value || ''
    };
    localStorage.setItem('df_data', JSON.stringify(data));
}

// Load from localStorage
function dfLoadFromStorage() {
    const saved = localStorage.getItem('df_data');
    if (saved) {
        try {
            const data = JSON.parse(saved);
            if (data.options) {
                dfSelectedOptions = { ...dfSelectedOptions, ...data.options };
            }
            const textarea = document.getElementById('dfNotesTextarea');
            if (textarea && data.notes) {
                textarea.value = data.notes;
            }
        } catch (e) {
            console.error('Error loading design focus data:', e);
        }
    }
}

// Reset design focus
function dfResetAll(skipToast = false) {
    dfSelectedOptions = {
        layout: true,
        colors: true,
        animations: true,
        responsive: true,
        modern: true,
        seo: true
    };
    
    const textarea = document.getElementById('dfNotesTextarea');
    if (textarea) {
        textarea.value = '';
    }
    
    dfUpdateUI();
    localStorage.removeItem('df_data');
    
    if (!skipToast && typeof showToast === 'function') {
        showToast('🔄 Design focus areas reset to default', 'info');
    }
}

// Confirm reset
async function confirmResetDesignFocus() {
    if (typeof deConfirm === 'function') {
        const confirmed = await deConfirm({
            title: 'Reset Design Focus',
            subtitle: 'Design Enhancer',
            message: 'Are you sure you want to reset the design focus areas?',
            warning: 'All options will be re-enabled and notes will be cleared.',
            confirmText: 'Reset',
            icon: 'fa-palette'
        });
        if (confirmed) {
            dfResetAll();
        }
    } else if (confirm('Reset design focus areas to default?')) {
        dfResetAll();
    }
}

// Get selected options (for external access)
function getDesignFocusOptions() {
    return {
        options: { ...dfSelectedOptions },
        notes: document.getElementById('dfNotesTextarea')?.value.trim() || ''
    };
}

// Initialize on DOM ready
document.addEventListener('DOMContentLoaded', function() {
    dfInit();
});
</script>

<!-- ═══════════════════════════════════════════════════════════════════
     📊 ENHANCEMENT LEVEL TOOL - JavaScript
     ═══════════════════════════════════════════════════════════════════ -->
<script>
// Enhancement Level state
let elSelectedLevel = 'preserve';
let elVrImages = []; // Array of {name, dataUrl, size}

// Level details for prompt generation
const elLevelDetails = {
    preserve: {
        name: 'Preserve Design',
        icon: '🛡️',
        desc: 'Keep current design intact, only fix bugs and add functionality',
        instructions: 'Do NOT change the existing design. Focus only on fixing bugs, improving performance, and adding new functionality without modifying the visual appearance.'
    },
    subtle: {
        name: 'Subtle Enhancement',
        icon: '🔹',
        desc: 'Minor improvements, keep existing design mostly intact',
        instructions: 'Make minor visual improvements while maintaining the existing design language. Small refinements to spacing, colors, and typography are acceptable but keep the overall look consistent.'
    },
    moderate: {
        name: 'Moderate Enhancement',
        icon: '⭐',
        desc: 'Balanced improvements, modern look while preserving structure',
        instructions: 'Apply balanced design improvements that modernize the look while preserving the overall structure. Update colors, add subtle animations, improve spacing, and use modern CSS techniques.'
    },
    aggressive: {
        name: 'Aggressive Enhancement',
        icon: '🚀',
        desc: 'Complete design overhaul with cutting-edge modern CSS',
        instructions: 'Perform a complete design overhaul using cutting-edge modern CSS. Reimagine the visual design with bold new styles, advanced animations, glassmorphism, gradients, and the latest CSS features. Be creative and dramatic.'
    },
    visual_reference: {
        name: 'Take Visual Reference',
        icon: '🎨',
        desc: 'Use the current design as a visual reference and rebuild with a fresh modern approach',
        instructions: 'Use the existing design only as a visual reference — do not replicate it. Study the layout, color palette, and overall vibe, then rebuild the UI from scratch with a fresh, modern approach. Apply best practices in UX/UI, use contemporary frameworks and design patterns, and aim for a polished, production-ready result that feels inspired by the original but clearly elevated.'
    }
};

// Initialize Enhancement Level
function elInit() {
    elLoadFromStorage();
    elUpdateUI();
}

// Select level
function elSelectLevel(level) {
    elSelectedLevel = level;
    
    // Update visual state
    document.querySelectorAll('.el-radio-item').forEach(item => {
        item.classList.remove('selected');
        const radio = item.querySelector('input[type="radio"]');
        if (radio) radio.checked = false;
    });
    
    const selectedItem = document.querySelector(`.el-radio-item[data-level="${level}"]`);
    if (selectedItem) {
        selectedItem.classList.add('selected');
        const radio = selectedItem.querySelector('input[type="radio"]');
        if (radio) radio.checked = true;
    }
    
    elUpdateBadge();
    elSaveToStorage();

    // Show/hide visual reference image picker
    const vrSection = document.getElementById('elVisualRefSection');
    if (vrSection) {
        if (level === 'visual_reference') {
            vrSection.classList.add('visible');
        } else {
            vrSection.classList.remove('visible');
        }
    }
}

// ── Visual Reference Image Picker ──
function elVrDragOver(e) {
    e.preventDefault();
    e.stopPropagation();
    document.getElementById('elVrDropzone')?.classList.add('dragover');
}
function elVrDragLeave(e) {
    e.preventDefault();
    e.stopPropagation();
    document.getElementById('elVrDropzone')?.classList.remove('dragover');
}
function elVrDrop(e) {
    e.preventDefault();
    e.stopPropagation();
    document.getElementById('elVrDropzone')?.classList.remove('dragover');
    const files = e.dataTransfer?.files;
    if (files && files.length) elVrFilesSelected(files);
}

function elVrFilesSelected(files) {
    if (!files || !files.length) return;
    const validTypes = ['image/png','image/jpeg','image/jpg','image/gif','image/webp','image/svg+xml','image/bmp'];
    let added = 0;
    Array.from(files).forEach(file => {
        if (!validTypes.includes(file.type)) return;
        if (elVrImages.some(img => img.name === file.name && img.size === file.size)) return; // skip duplicates
        const reader = new FileReader();
        reader.onload = function(ev) {
            elVrImages.push({ name: file.name, dataUrl: ev.target.result, size: file.size });
            added++;
            elVrRenderPreviews();
            elSaveToStorage();
        };
        reader.readAsDataURL(file);
    });
    // Reset file input so the same file can be re-selected
    const input = document.getElementById('elVrFileInput');
    if (input) input.value = '';
}

function elVrRenderPreviews() {
    const grid = document.getElementById('elVrPreviewGrid');
    const countWrap = document.getElementById('elVrCount');
    const countText = document.getElementById('elVrCountText');
    if (!grid) return;

    grid.innerHTML = elVrImages.map((img, i) => `
        <div class="el-vr-preview-item" title="${img.name}">
            <img src="${img.dataUrl}" alt="${img.name}">
            <button type="button" class="el-vr-preview-remove" onclick="event.stopPropagation();elVrRemove(${i})" title="Remove">
                <i class="fas fa-times"></i>
            </button>
            <div class="el-vr-preview-name">${img.name}</div>
        </div>
    `).join('');

    if (countWrap) countWrap.style.display = elVrImages.length ? 'inline-flex' : 'none';
    if (countText) countText.textContent = `${elVrImages.length} image${elVrImages.length !== 1 ? 's' : ''}`;
}

function elVrRemove(index) {
    elVrImages.splice(index, 1);
    elVrRenderPreviews();
    elSaveToStorage();
}

function elVrClearAll() {
    elVrImages = [];
    elVrRenderPreviews();
    elSaveToStorage();
    if (typeof showToast === 'function') showToast('🗑️ All reference images removed', 'info');
}

// Update badge
function elUpdateBadge() {
    const badge = document.getElementById('elBadge');
    if (!badge) return;
    
    const details = elLevelDetails[elSelectedLevel];
    badge.textContent = details.name.replace(/^[^\s]+\s/, ''); // Remove emoji
    
    // Change badge color based on level
    const colors = {
        preserve: 'linear-gradient(135deg, #22c55e 0%, #16a34a 100%)',
        subtle: 'linear-gradient(135deg, #3b82f6 0%, #2563eb 100%)',
        moderate: 'linear-gradient(135deg, #f59e0b 0%, #d97706 100%)',
        aggressive: 'linear-gradient(135deg, #ef4444 0%, #dc2626 100%)',
        visual_reference: 'linear-gradient(135deg, #a855f7 0%, #8b5cf6 100%)'
    };
    badge.style.background = colors[elSelectedLevel] || colors.moderate;
}

// Update character count
function elUpdateCharCount() {
    const textarea = document.getElementById('elNotesTextarea');
    const countEl = document.getElementById('elCharCount');
    if (textarea && countEl) {
        const count = textarea.value.length;
        countEl.textContent = `${count} character${count !== 1 ? 's' : ''}`;
        elSaveToStorage();
    }
}

// Update UI from state
function elUpdateUI() {
    elSelectLevel(elSelectedLevel);
    elUpdateCharCount();
}

// Push to Project Prompts
function elPushToNotes() {
    const notesTextarea = document.getElementById('elNotesTextarea');
    const additionalNotes = notesTextarea ? notesTextarea.value.trim() : '';
    const details = elLevelDetails[elSelectedLevel];
    
    let promptText = `## 📊 ENHANCEMENT LEVEL\n\n`;
    promptText += `**${details.icon} Level: ${details.name}**\n\n`;
    promptText += `**Description:** ${details.desc}\n\n`;
    promptText += `**Instructions:**\n${details.instructions}\n\n`;

    // Add visual reference images info if applicable
    if (elSelectedLevel === 'visual_reference' && elVrImages.length > 0) {
        promptText += `### 🖼️ VISUAL REFERENCE IMAGES:\n\n`;
        promptText += `**${elVrImages.length} reference image(s) attached.**\n`;
        promptText += `Use these images as visual inspiration for the new design. Study the layout, colors, typography, and overall aesthetic, then build a fresh modern version.\n\n`;
        elVrImages.forEach((img, i) => {
            promptText += `${i + 1}. **${img.name}**\n`;
        });
        promptText += `\n`;
    }
    
    // Add additional notes if present
    if (additionalNotes) {
        promptText += `---\n\n### 📝 ADDITIONAL ENHANCEMENT INSTRUCTIONS:\n\n`;
        promptText += `${additionalNotes}\n\n`;
        promptText += `---\n\n`;
    }
    
    // Push to Project Notes
    const projectNotesTextarea = document.getElementById('projectNotesTextarea');
    if (projectNotesTextarea) {
        if (projectNotesTextarea.value.trim()) {
            projectNotesTextarea.value = projectNotesTextarea.value.trimEnd() + '\n\n' + promptText;
        } else {
            projectNotesTextarea.value = promptText;
        }
        
        if (typeof saveProjectNotesToStorage === 'function') {
            saveProjectNotesToStorage();
        }
        
        const imgInfo = (elSelectedLevel === 'visual_reference' && elVrImages.length > 0) ? ` + ${elVrImages.length} image(s)` : '';
        const notesInfo = additionalNotes ? ' + custom notes' : '';
        if (typeof showToast === 'function') {
            showToast(`📊 Enhancement level (${details.name})${notesInfo}${imgInfo} pushed to Project Prompts`, 'success');
        }
    } else {
        if (typeof showToast === 'function') showToast('⚠️ Project Prompts not found', 'error');
    }
}

// Save to localStorage
function elSaveToStorage() {
    const data = {
        level: elSelectedLevel,
        notes: document.getElementById('elNotesTextarea')?.value || '',
        vrImages: elVrImages
    };
    try {
        localStorage.setItem('el_data', JSON.stringify(data));
    } catch (e) {
        // If storage quota exceeded (large images), save without images
        const fallback = { level: data.level, notes: data.notes, vrImages: [] };
        localStorage.setItem('el_data', JSON.stringify(fallback));
        if (typeof showToast === 'function') showToast('⚠️ Images too large for local storage — they will not persist after reload', 'warning');
    }
}

// Load from localStorage
function elLoadFromStorage() {
    const saved = localStorage.getItem('el_data');
    if (saved) {
        try {
            const data = JSON.parse(saved);
            elSelectedLevel = data.level || 'preserve';
            const textarea = document.getElementById('elNotesTextarea');
            if (textarea && data.notes) {
                textarea.value = data.notes;
            }
            if (Array.isArray(data.vrImages)) {
                elVrImages = data.vrImages;
                elVrRenderPreviews();
            }
        } catch (e) {
            elSelectedLevel = 'preserve';
        }
    }
}

// Reset enhancement level
function elResetAll(skipToast = false) {
    elSelectedLevel = 'preserve';
    const textarea = document.getElementById('elNotesTextarea');
    if (textarea) {
        textarea.value = '';
    }
    elVrImages = [];
    elVrRenderPreviews();
    elUpdateUI();
    localStorage.removeItem('el_data');
    
    if (!skipToast && typeof showToast === 'function') {
        showToast('🔄 Enhancement level reset to Preserve Design', 'info');
    }
}

// Clear button: clear textarea + reset level to Preserve Design
function elClearAndReset() {
    const textarea = document.getElementById('elNotesTextarea');
    if (textarea) textarea.value = '';
    elSelectedLevel = 'preserve';
    elVrImages = [];
    elVrRenderPreviews();
    elUpdateUI();
    elSaveToStorage();
    if (typeof showToast === 'function') {
        showToast('🧹 Instructions cleared & level reset to Preserve Design', 'info');
    }
}

// Confirm reset
async function confirmResetEnhancementLevel() {
    if (typeof deConfirm === 'function') {
        const confirmed = await deConfirm({
            title: 'Reset Enhancement Level',
            subtitle: 'Design Enhancer',
            message: 'Are you sure you want to reset the enhancement level?',
            warning: 'Level will be set to "Preserve Design" and notes will be cleared.',
            confirmText: 'Reset',
            icon: 'fa-sliders-h'
        });
        if (confirmed) {
            elResetAll();
        }
    } else if (confirm('Reset enhancement level to default?')) {
        elResetAll();
    }
}

// Get enhancement level (for external access)
function getEnhancementLevel() {
    return {
        level: elSelectedLevel,
        details: elLevelDetails[elSelectedLevel],
        notes: document.getElementById('elNotesTextarea')?.value.trim() || '',
        vrImages: elVrImages
    };
}

// Initialize on DOM ready
document.addEventListener('DOMContentLoaded', function() {
    elInit();
});
</script>

<!-- ═══════════════════════════════════════════════════════════════════
     📋 TASK BREAKDOWN TOOL - JavaScript
     ═══════════════════════════════════════════════════════════════════ -->
<script>
// Task Breakdown state
let tbParts = 3;
let tbOptimizeToken = true;
let tbExecutionMode = 'step-by-step';

// Initialize Task Breakdown
function tbInit() {
    tbLoadFromStorage();
    tbUpdateUI();
}

// Update parts value
function tbUpdateParts(value) {
    tbParts = parseInt(value);
    const valueEl = document.getElementById('tbPartsValue');
    if (valueEl) valueEl.textContent = tbParts;
    tbUpdateBadge();
    tbSaveToStorage();
}

// Toggle optimize token
function tbToggleOptimize() {
    const checkbox = document.getElementById('tbOptimizeToken');
    if (checkbox) {
        tbOptimizeToken = checkbox.checked;
        tbSaveToStorage();
    }
}

// Select execution mode
function tbSelectMode(mode) {
    tbExecutionMode = mode;
    
    // Update visual state
    document.querySelectorAll('.tb-radio-option').forEach(option => {
        option.classList.remove('selected');
        const radio = option.querySelector('input[type="radio"]');
        if (radio) radio.checked = false;
    });
    
    const selectedOption = document.querySelector(`.tb-radio-option[data-mode="${mode}"]`);
    if (selectedOption) {
        selectedOption.classList.add('selected');
        const radio = selectedOption.querySelector('input[type="radio"]');
        if (radio) radio.checked = true;
    }
    
    tbSaveToStorage();
}

// Update badge
function tbUpdateBadge() {
    const badge = document.getElementById('tbBadge');
    if (!badge) return;
    badge.textContent = `${tbParts} Part${tbParts > 1 ? 's' : ''}`;
}

// Update character count
function tbUpdateCharCount() {
    const textarea = document.getElementById('tbNotesTextarea');
    const countEl = document.getElementById('tbCharCount');
    if (textarea && countEl) {
        const count = textarea.value.length;
        countEl.textContent = `${count} character${count !== 1 ? 's' : ''}`;
        tbSaveToStorage();
    }
}

// Update UI from state
function tbUpdateUI() {
    // Update slider
    const slider = document.getElementById('tbPartsSlider');
    const valueEl = document.getElementById('tbPartsValue');
    if (slider) slider.value = tbParts;
    if (valueEl) valueEl.textContent = tbParts;
    
    // Update optimize checkbox
    const optimizeCheckbox = document.getElementById('tbOptimizeToken');
    if (optimizeCheckbox) optimizeCheckbox.checked = tbOptimizeToken;
    
    // Update execution mode
    tbSelectMode(tbExecutionMode);
    
    tbUpdateBadge();
    tbUpdateCharCount();
}

// Push to Project Prompts
function tbPushToNotes() {
    const notesTextarea = document.getElementById('tbNotesTextarea');
    const additionalNotes = notesTextarea ? notesTextarea.value.trim() : '';
    
    let promptText = `## 📋 TASK BREAKDOWN & EXECUTION\n\n`;
    promptText += `**Number of Parts:** ${tbParts}\n\n`;
    
    if (tbOptimizeToken) {
        promptText += `**🔧 Token Optimization:** ENABLED\n`;
        promptText += `Each task will fully utilize the maximum allowed token/memory limit of the IDE without exceeding it.\n\n`;
    }
    
    promptText += `**Execution Mode:** ${tbExecutionMode === 'step-by-step' ? '⏱️ Step-by-Step' : '⚡ Automatic Sequential'}\n\n`;
    
    if (tbExecutionMode === 'step-by-step') {
        promptText += `**Instructions:**\n`;
        promptText += `- Complete each part and wait for user review before proceeding\n`;
        promptText += `- Allow user to provide feedback between steps\n`;
        promptText += `- Maintain controlled progression through all ${tbParts} parts\n\n`;
    } else {
        promptText += `**Instructions:**\n`;
        promptText += `- Complete all ${tbParts} parts automatically in succession\n`;
        promptText += `- Do not wait for feedback between parts\n`;
        promptText += `- Maintain continuous workflow until completion\n\n`;
    }
    
    // Add additional notes if present
    if (additionalNotes) {
        promptText += `---\n\n### 📝 ADDITIONAL TASK INSTRUCTIONS:\n\n`;
        promptText += `${additionalNotes}\n\n`;
        promptText += `---\n\n`;
    }
    
    // Push to Project Notes
    const projectNotesTextarea = document.getElementById('projectNotesTextarea');
    if (projectNotesTextarea) {
        if (projectNotesTextarea.value.trim()) {
            projectNotesTextarea.value = projectNotesTextarea.value.trimEnd() + '\n\n' + promptText;
        } else {
            projectNotesTextarea.value = promptText;
        }
        
        if (typeof saveProjectNotesToStorage === 'function') {
            saveProjectNotesToStorage();
        }
        
        const modeText = tbExecutionMode === 'step-by-step' ? 'Step-by-Step' : 'Automatic';
        const notesInfo = additionalNotes ? ' + custom notes' : '';
        if (typeof showToast === 'function') {
            showToast(`📋 Task breakdown (${tbParts} parts, ${modeText})${notesInfo} pushed to Project Prompts`, 'success');
        }
    } else {
        if (typeof showToast === 'function') showToast('⚠️ Project Prompts not found', 'error');
    }
}

// Save to localStorage
function tbSaveToStorage() {
    const data = {
        parts: tbParts,
        optimizeToken: tbOptimizeToken,
        executionMode: tbExecutionMode,
        notes: document.getElementById('tbNotesTextarea')?.value || ''
    };
    localStorage.setItem('tb_data', JSON.stringify(data));
}

// Load from localStorage
function tbLoadFromStorage() {
    const saved = localStorage.getItem('tb_data');
    if (saved) {
        try {
            const data = JSON.parse(saved);
            tbParts = data.parts || 3;
            tbOptimizeToken = data.optimizeToken !== false;
            tbExecutionMode = data.executionMode || 'step-by-step';
            const textarea = document.getElementById('tbNotesTextarea');
            if (textarea && data.notes) {
                textarea.value = data.notes;
            }
        } catch (e) {
            console.error('Error loading task breakdown data:', e);
        }
    }
}

// Reset task breakdown
function tbResetAll(skipToast = false) {
    tbParts = 3;
    tbOptimizeToken = true;
    tbExecutionMode = 'step-by-step';
    
    const textarea = document.getElementById('tbNotesTextarea');
    if (textarea) {
        textarea.value = '';
    }
    
    tbUpdateUI();
    localStorage.removeItem('tb_data');
    
    if (!skipToast && typeof showToast === 'function') {
        showToast('🔄 Task breakdown reset to default', 'info');
    }
}

// Confirm reset
async function confirmResetTaskBreakdown() {
    if (typeof deConfirm === 'function') {
        const confirmed = await deConfirm({
            title: 'Reset Task Breakdown',
            subtitle: 'Design Enhancer',
            message: 'Are you sure you want to reset the task breakdown settings?',
            warning: 'Parts will be set to 3, token optimization enabled, and notes cleared.',
            confirmText: 'Reset',
            icon: 'fa-tasks'
        });
        if (confirmed) {
            tbResetAll();
        }
    } else if (confirm('Reset task breakdown to default?')) {
        tbResetAll();
    }
}

// Get task breakdown settings (for external access)
function getTaskBreakdown() {
    return {
        parts: tbParts,
        optimizeToken: tbOptimizeToken,
        executionMode: tbExecutionMode,
        notes: document.getElementById('tbNotesTextarea')?.value.trim() || ''
    };
}

// Initialize on DOM ready
document.addEventListener('DOMContentLoaded', function() {
    tbInit();
});
</script>

<!-- ═══════════════════════════════════════════════════════════════════
     🏠 HOMEPAGE CONFIGURATION JAVASCRIPT
     ═══════════════════════════════════════════════════════════════════ -->
<script>
// Homepage Configuration state
let hpCreateNew = false;
let hpTargetFileName = null;
let hpNewPageName = 'index';
let hpExistingFileName = null;

// Initialize Homepage Configuration
function hpInit() {
    hpLoadFromStorage();
    hpUpdateUI();
    
    // Reverse sync: If Project Files Uploader already detected pages, pull them in
    // (short delay to ensure uploader state is loaded first)
    setTimeout(() => {
        hpSyncFromUploader();
    }, 300);
}

// Reverse sync: Pull detected pages from Project Files Uploader into Homepage Config
function hpSyncFromUploader() {
    // Only sync if the uploader has detected pages and HP hasn't been manually configured
    if (typeof ufDetectedHomepage === 'undefined') return;
    
    // If user manually configured, don't override
    const userManuallySetExisting = localStorage.getItem('hpExistingFileName');
    const userManuallySetNew = localStorage.getItem('hpCreateNew') === 'true';
    
    // If homepage detected and no existing file has been manually set
    if (ufDetectedHomepage && !userManuallySetExisting && !userManuallySetNew) {
        // Uploader detected a homepage — set it as existing landing page
        hpCreateNew = false;
        hpExistingFileName = ufDetectedHomepage;
        
        hpSaveToStorage();
        hpUpdateUI();
        console.log('🔄 HP reverse-sync: Existing page ←', ufDetectedHomepage);
    }
    
    // If featured page detected and no target file has been set
    if (ufDetectedFeatured && !hpTargetFileName) {
        hpTargetFileName = ufDetectedFeatured;
        hpSaveToStorage();
        hpUpdateUI();
        console.log('🔄 HP reverse-sync: Target page ←', ufDetectedFeatured);
    }
}

// Toggle create new homepage checkbox
function hpToggleCreateHomepage(event) {
    const checkbox = document.getElementById('hpCreateNewHomepage');
    
    // If click was NOT on the checkbox itself, toggle it manually
    if (event.target.tagName !== 'INPUT') {
        event.preventDefault();
        checkbox.checked = !checkbox.checked;
    }
    
    hpCreateNew = checkbox.checked;
    
    const label = checkbox.closest('.hp-checkbox-label');
    label.classList.toggle('checked', checkbox.checked);
    
    // Show/hide new page section (with name input and target picker)
    const newPageSection = document.getElementById('hpNewPageSection');
    const existingPageSection = document.getElementById('hpExistingPageSection');
    
    if (checkbox.checked) {
        newPageSection.classList.add('show');
        existingPageSection.classList.add('hide');
    } else {
        newPageSection.classList.remove('show');
        existingPageSection.classList.remove('hide');
    }
    
    // Toggle info boxes
    const infoUnchecked = document.getElementById('hpInfoUnchecked');
    const infoChecked = document.getElementById('hpInfoChecked');
    
    if (checkbox.checked) {
        infoUnchecked.classList.add('hide');
        infoChecked.classList.add('show');
    } else {
        infoUnchecked.classList.remove('hide');
        infoChecked.classList.remove('show');
    }
    
    hpSaveToStorage();
    hpUpdateBadge();
}

// Handle target file selection
function hpHandleTargetFile(event) {
    const file = event.target.files[0];
    if (!file) return;
    
    hpTargetFileName = file.name;
    
    // Update display
    const fileDisplay = document.getElementById('hpFileDisplay');
    const fileNameSpan = document.getElementById('hpTargetFileName');
    const clearBtn = document.getElementById('hpClearBtn');
    
    fileNameSpan.textContent = file.name;
    fileDisplay.classList.add('has-file');
    clearBtn.classList.add('show');
    
    hpSaveToStorage();
    hpUpdateBadge();
    hpSyncToUploader();
    showToast(`📄 Target page selected: ${file.name}`, 'success');
}

// Clear target file
function hpClearTargetFile() {
    hpTargetFileName = null;
    
    const fileInput = document.getElementById('hpTargetFile');
    const fileDisplay = document.getElementById('hpFileDisplay');
    const fileNameSpan = document.getElementById('hpTargetFileName');
    const clearBtn = document.getElementById('hpClearBtn');
    
    fileInput.value = '';
    fileNameSpan.textContent = 'No file selected (will use current homepage)';
    fileDisplay.classList.remove('has-file');
    clearBtn.classList.remove('show');
    
    hpSaveToStorage();
    hpUpdateBadge();
    hpSyncToUploader();
}

// Save new page name
function hpSaveNewPageName() {
    const input = document.getElementById('hpNewPageName');
    if (input) {
        hpNewPageName = input.value.trim() || 'index';
        localStorage.setItem('hpNewPageName', hpNewPageName);
        hpUpdateBadge();
    }
}

// Handle existing file selection
function hpHandleExistingFile(event) {
    const file = event.target.files[0];
    if (!file) return;
    
    hpExistingFileName = file.name;
    
    // Update display
    const fileDisplay = document.getElementById('hpExistingFileDisplay');
    const fileNameSpan = document.getElementById('hpExistingFileName');
    const clearBtn = document.getElementById('hpExistingClearBtn');
    
    fileNameSpan.textContent = file.name;
    fileDisplay.classList.add('has-file');
    clearBtn.classList.add('show');
    
    hpSaveToStorage();
    hpUpdateBadge();
    hpSyncToUploader();
    showToast(`📄 Existing page selected: ${file.name}`, 'success');
}

// Clear existing file
function hpClearExistingFile() {
    hpExistingFileName = null;
    
    const fileInput = document.getElementById('hpExistingFile');
    const fileDisplay = document.getElementById('hpExistingFileDisplay');
    const fileNameSpan = document.getElementById('hpExistingFileName');
    const clearBtn = document.getElementById('hpExistingClearBtn');
    
    fileInput.value = '';
    fileNameSpan.textContent = 'No file selected (will enhance default homepage)';
    fileDisplay.classList.remove('has-file');
    clearBtn.classList.remove('show');
    
    hpSaveToStorage();
    hpUpdateBadge();
    hpSyncToUploader();
}

// Update badge
function hpUpdateBadge() {
    const badge = document.getElementById('hpBadge');
    if (badge) {
        if (hpCreateNew) {
            badge.style.display = 'inline-flex';
            badge.style.background = 'linear-gradient(135deg, #10b981 0%, #059669 100%)';
            const pageName = hpNewPageName || 'index';
            badge.textContent = hpTargetFileName ? `New: ${pageName}` : `New: ${pageName}`;
        } else if (hpExistingFileName) {
            badge.style.display = 'inline-flex';
            badge.style.background = 'linear-gradient(135deg, #3b82f6 0%, #2563eb 100%)';
            badge.textContent = 'Enhance';
        } else {
            badge.style.display = 'none';
        }
    }
}

// Update UI from state
function hpUpdateUI() {
    // Checkbox
    const checkbox = document.getElementById('hpCreateNewHomepage');
    if (checkbox) {
        checkbox.checked = hpCreateNew;
        const label = checkbox.closest('.hp-checkbox-label');
        if (label) label.classList.toggle('checked', hpCreateNew);
    }
    
    // New page section visibility
    const newPageSection = document.getElementById('hpNewPageSection');
    const existingPageSection = document.getElementById('hpExistingPageSection');
    if (newPageSection) newPageSection.classList.toggle('show', hpCreateNew);
    if (existingPageSection) existingPageSection.classList.toggle('hide', hpCreateNew);
    
    // New page name input
    const newPageNameInput = document.getElementById('hpNewPageName');
    if (newPageNameInput) {
        newPageNameInput.value = hpNewPageName || 'index';
    }
    
    // Info boxes
    const infoUnchecked = document.getElementById('hpInfoUnchecked');
    const infoChecked = document.getElementById('hpInfoChecked');
    if (infoUnchecked) infoUnchecked.classList.toggle('hide', hpCreateNew);
    if (infoChecked) infoChecked.classList.toggle('show', hpCreateNew);
    
    // Target file display (for new landing)
    {
        const fileDisplay = document.getElementById('hpFileDisplay');
        const fileNameSpan = document.getElementById('hpTargetFileName');
        const clearBtn = document.getElementById('hpClearBtn');
        if (hpTargetFileName) {
            if (fileNameSpan) fileNameSpan.textContent = hpTargetFileName;
            if (fileDisplay) fileDisplay.classList.add('has-file');
            if (clearBtn) clearBtn.classList.add('show');
        } else {
            if (fileNameSpan) fileNameSpan.textContent = 'No file selected (will use current homepage)';
            if (fileDisplay) fileDisplay.classList.remove('has-file');
            if (clearBtn) clearBtn.classList.remove('show');
        }
    }
    
    // Existing file display (for enhancement)
    {
        const fileDisplay = document.getElementById('hpExistingFileDisplay');
        const fileNameSpan = document.getElementById('hpExistingFileName');
        const clearBtn = document.getElementById('hpExistingClearBtn');
        if (hpExistingFileName) {
            if (fileNameSpan) fileNameSpan.textContent = hpExistingFileName;
            if (fileDisplay) fileDisplay.classList.add('has-file');
            if (clearBtn) clearBtn.classList.add('show');
        } else {
            if (fileNameSpan) fileNameSpan.textContent = 'No file selected (will enhance default homepage)';
            if (fileDisplay) fileDisplay.classList.remove('has-file');
            if (clearBtn) clearBtn.classList.remove('show');
        }
    }
    
    // Load notes
    hpLoadNotesFromStorage();
    
    // Update badge
    hpUpdateBadge();
}

// Push to Project Prompts
function hpPushToNotes() {
    const projectNotesTextarea = document.getElementById('projectNotesTextarea');
    if (!projectNotesTextarea) return;
    
    const notesContent = document.getElementById('hpNotesTextarea')?.value.trim() || '';
    
    // Build prompt content
    let promptContent = '';
    
    if (hpCreateNew) {
        // Creating NEW landing page
        const pageName = hpNewPageName || 'index';
        
        promptContent += `\n\n🏠 HOMEPAGE CONFIGURATION\n`;
        promptContent += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
        promptContent += `• Mode: Create New Landing Homepage\n`;
        promptContent += `• Landing Page Name: ${pageName}\n`;
        
        if (hpTargetFileName) {
            promptContent += `• Target Page (After Landing): ${hpTargetFileName}\n\n`;
            promptContent += `INSTRUCTIONS: Create a stunning new landing page named "${pageName}" with a modern design. Include a prominent call-to-action that directs users to "${hpTargetFileName}". The landing page should:\n`;
        } else {
            promptContent += `• Target Page: Main content (default)\n\n`;
            promptContent += `INSTRUCTIONS: Create a stunning new landing page named "${pageName}" with a modern design. Include a prominent call-to-action that directs users to the main content. The landing page should:\n`;
        }
        
        promptContent += `- Have a hero section with compelling headline\n`;
        promptContent += `- Feature key benefits/features\n`;
        promptContent += `- Include clear navigation path\n`;
        promptContent += `- Be fully responsive and mobile-friendly\n`;
        promptContent += `- Match the overall site theme\n`;
    } else {
        // Enhancing EXISTING landing page
        promptContent += `\n\n🏠 HOMEPAGE CONFIGURATION\n`;
        promptContent += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
        promptContent += `• Mode: Enhance Existing Homepage\n`;
        
        if (hpExistingFileName) {
            promptContent += `• Target File: ${hpExistingFileName}\n\n`;
            promptContent += `INSTRUCTIONS: Enhance and improve the existing landing page "${hpExistingFileName}". Modernize the styling, improve UX, and add better visual appeal while maintaining its core structure and content.\n`;
        } else {
            promptContent += `• Target: Default homepage\n\n`;
            promptContent += `INSTRUCTIONS: Enhance and improve the existing homepage design. Modernize the styling, improve UX, and add better visual appeal while maintaining its core structure and content.\n`;
        }
    }
    
    // Additional notes
    if (notesContent) {
        promptContent += `\nAdditional Instructions:\n${notesContent}\n`;
    }
    
    if (!promptContent.trim()) {
        showToast('⚠️ No homepage configuration to push', 'warning');
        return;
    }
    
    // Append to Project Prompts
    const currentContent = projectNotesTextarea.value;
    projectNotesTextarea.value = currentContent + promptContent;
    
    // Trigger auto-resize
    if (typeof autoResizeTextarea === 'function') {
        autoResizeTextarea(projectNotesTextarea);
    }
    
    // Save
    localStorage.setItem('projectPrompts', projectNotesTextarea.value);
    
    showToast('🏠 Homepage configuration pushed to Project Prompts', 'success');
}

// Character count
function hpUpdateCharCount() {
    const textarea = document.getElementById('hpNotesTextarea');
    const charCount = document.getElementById('hpCharCount');
    if (textarea && charCount) {
        charCount.textContent = `${textarea.value.length} characters`;
        hpSaveNotesToStorage();
    }
}

// Save notes to storage
function hpSaveNotesToStorage() {
    const textarea = document.getElementById('hpNotesTextarea');
    if (textarea) {
        localStorage.setItem('hpNotes', textarea.value);
    }
}

// Load notes from storage
function hpLoadNotesFromStorage() {
    const savedNotes = localStorage.getItem('hpNotes');
    const textarea = document.getElementById('hpNotesTextarea');
    if (savedNotes && textarea) {
        textarea.value = savedNotes;
        hpUpdateCharCount();
    }
}

// Save to localStorage
// Reverse sync: Homepage Configuration → Project File Uploader
function hpSyncToUploader() {
    const homepageSelect = document.getElementById('ufHomepageSelect');
    if (!homepageSelect) return;
    
    if (hpExistingFileName) {
        // Check if the filename exists as an option in the UF dropdown
        const options = Array.from(homepageSelect.options);
        const matchingOption = options.find(opt => opt.value === hpExistingFileName);
        
        if (matchingOption) {
            // Select it in the dropdown
            homepageSelect.value = hpExistingFileName;
        } else {
            // Add it as a new option and select it
            const newOpt = document.createElement('option');
            newOpt.value = hpExistingFileName;
            newOpt.textContent = hpExistingFileName + ' (from Homepage Config)';
            homepageSelect.appendChild(newOpt);
            homepageSelect.value = hpExistingFileName;
        }
        
        // Update UF state without triggering reverse sync back
        if (typeof ufDetectedHomepage !== 'undefined') {
            ufDetectedHomepage = hpExistingFileName;
            
            const homepageBadge = document.getElementById('ufHomepageBadge');
            if (homepageBadge) {
                homepageBadge.textContent = 'Set';
                homepageBadge.className = 'uf-page-badge set';
            }
            
            // Enable featured select and disable the homepage option in it
            const featuredSelect = document.getElementById('ufFeaturedSelect');
            if (featuredSelect) {
                featuredSelect.disabled = false;
                Array.from(featuredSelect.options).forEach(option => {
                    option.disabled = (option.value === hpExistingFileName);
                });
            }
            
            if (typeof ufSaveToStorage === 'function') ufSaveToStorage();
        }
        
        console.log('🔄 HP → UF sync: Homepage set to', hpExistingFileName);
    } else {
        // Clear UF homepage selection
        homepageSelect.value = '';
        
        if (typeof ufDetectedHomepage !== 'undefined') {
            ufDetectedHomepage = '';
            
            const homepageBadge = document.getElementById('ufHomepageBadge');
            if (homepageBadge) {
                homepageBadge.textContent = 'Not Set';
                homepageBadge.className = 'uf-page-badge not-set';
            }
            
            const featuredSelect = document.getElementById('ufFeaturedSelect');
            if (featuredSelect) {
                featuredSelect.disabled = true;
                featuredSelect.value = '';
            }
            
            const featuredBadge = document.getElementById('ufFeaturedBadge');
            if (featuredBadge) {
                featuredBadge.textContent = 'Not Set';
                featuredBadge.className = 'uf-page-badge not-set';
            }
            
            if (typeof ufSaveToStorage === 'function') ufSaveToStorage();
        }
        
        console.log('🔄 HP → UF sync: Homepage cleared');
    }
    
    // ─── Target page → Featured page sync ───
    const featuredSelect = document.getElementById('ufFeaturedSelect');
    if (!featuredSelect) return;
    
    if (hpTargetFileName) {
        const featOptions = Array.from(featuredSelect.options);
        const matchFeat = featOptions.find(opt => opt.value === hpTargetFileName);
        
        if (matchFeat) {
            featuredSelect.value = hpTargetFileName;
        } else {
            const newOpt = document.createElement('option');
            newOpt.value = hpTargetFileName;
            newOpt.textContent = hpTargetFileName + ' (from Homepage Config)';
            featuredSelect.appendChild(newOpt);
            featuredSelect.value = hpTargetFileName;
        }
        
        if (typeof ufDetectedFeatured !== 'undefined') {
            ufDetectedFeatured = hpTargetFileName;
            
            const featuredBadge = document.getElementById('ufFeaturedBadge');
            if (featuredBadge) {
                featuredBadge.textContent = 'Set';
                featuredBadge.className = 'uf-page-badge set';
            }
            
            if (typeof ufSaveToStorage === 'function') ufSaveToStorage();
        }
        
        console.log('🔄 HP → UF sync: Featured/Target set to', hpTargetFileName);
    } else {
        featuredSelect.value = '';
        
        if (typeof ufDetectedFeatured !== 'undefined') {
            ufDetectedFeatured = '';
            
            const featuredBadge = document.getElementById('ufFeaturedBadge');
            if (featuredBadge) {
                featuredBadge.textContent = 'Not Set';
                featuredBadge.className = 'uf-page-badge not-set';
            }
            
            if (typeof ufSaveToStorage === 'function') ufSaveToStorage();
        }
        
        console.log('🔄 HP → UF sync: Featured/Target cleared');
    }
}

function hpSaveToStorage() {
    localStorage.setItem('hpCreateNew', hpCreateNew);
    localStorage.setItem('hpNewPageName', hpNewPageName || 'index');
    
    if (hpTargetFileName) {
        localStorage.setItem('hpTargetFileName', hpTargetFileName);
    } else {
        localStorage.removeItem('hpTargetFileName');
    }
    
    if (hpExistingFileName) {
        localStorage.setItem('hpExistingFileName', hpExistingFileName);
    } else {
        localStorage.removeItem('hpExistingFileName');
    }
}

// Load from localStorage
function hpLoadFromStorage() {
    hpCreateNew = localStorage.getItem('hpCreateNew') === 'true';
    hpNewPageName = localStorage.getItem('hpNewPageName') || 'index';
    hpTargetFileName = localStorage.getItem('hpTargetFileName') || null;
    hpExistingFileName = localStorage.getItem('hpExistingFileName') || null;
}

// Reset all
function hpResetAll(skipToast = false) {
    hpCreateNew = false;
    hpTargetFileName = null;
    hpNewPageName = 'index';
    hpExistingFileName = null;
    
    // Clear UI - Checkbox
    const checkbox = document.getElementById('hpCreateNewHomepage');
    if (checkbox) {
        checkbox.checked = false;
        const label = checkbox.closest('.hp-checkbox-label');
        if (label) label.classList.remove('checked');
    }
    
    // Clear new page section
    const newPageSection = document.getElementById('hpNewPageSection');
    if (newPageSection) newPageSection.classList.remove('show');
    
    const newPageNameInput = document.getElementById('hpNewPageName');
    if (newPageNameInput) newPageNameInput.value = 'index';
    
    // Clear existing page section
    const existingPageSection = document.getElementById('hpExistingPageSection');
    if (existingPageSection) existingPageSection.classList.remove('hide');
    
    // Clear target file (for new landing)
    const fileInput = document.getElementById('hpTargetFile');
    if (fileInput) fileInput.value = '';
    
    const fileDisplay = document.getElementById('hpFileDisplay');
    if (fileDisplay) fileDisplay.classList.remove('has-file');
    
    const fileNameSpan = document.getElementById('hpTargetFileName');
    if (fileNameSpan) fileNameSpan.textContent = 'No file selected (will use current homepage)';
    
    const clearBtn = document.getElementById('hpClearBtn');
    if (clearBtn) clearBtn.classList.remove('show');
    
    // Clear existing file (for enhancement)
    const existingFileInput = document.getElementById('hpExistingFile');
    if (existingFileInput) existingFileInput.value = '';
    
    const existingFileDisplay = document.getElementById('hpExistingFileDisplay');
    if (existingFileDisplay) existingFileDisplay.classList.remove('has-file');
    
    const existingFileNameSpan = document.getElementById('hpExistingFileName');
    if (existingFileNameSpan) existingFileNameSpan.textContent = 'No file selected (will enhance default homepage)';
    
    const existingClearBtn = document.getElementById('hpExistingClearBtn');
    if (existingClearBtn) existingClearBtn.classList.remove('show');
    
    // Info boxes
    const infoUnchecked = document.getElementById('hpInfoUnchecked');
    if (infoUnchecked) infoUnchecked.classList.remove('hide');
    
    const infoChecked = document.getElementById('hpInfoChecked');
    if (infoChecked) infoChecked.classList.remove('show');
    
    // Clear notes
    const notesTextarea = document.getElementById('hpNotesTextarea');
    if (notesTextarea) {
        notesTextarea.value = '';
        hpUpdateCharCount();
    }
    
    // Clear storage
    localStorage.removeItem('hpCreateNew');
    localStorage.removeItem('hpNewPageName');
    localStorage.removeItem('hpTargetFileName');
    localStorage.removeItem('hpExistingFileName');
    localStorage.removeItem('hpNotes');
    
    hpUpdateBadge();
    hpSyncToUploader();
    
    if (!skipToast) {
        showToast('🏠 Homepage settings reset', 'info');
    }
}

// Confirm reset
async function confirmResetHomepage() {
    if (typeof deConfirm === 'function') {
        const confirmed = await deConfirm({
            title: 'Reset Homepage',
            subtitle: 'Design Enhancer',
            message: 'This will clear all homepage configuration settings and notes.',
            warning: 'This action cannot be undone.',
            confirmText: 'Reset',
            icon: 'fa-home'
        });
        if (confirmed) {
            hpResetAll();
        }
    } else {
        if (confirm('Reset all homepage settings?')) {
            hpResetAll();
        }
    }
}

// Initialize on load
document.addEventListener('DOMContentLoaded', hpInit);
</script>

<!-- ═══════════════════════════════════════════════════════════════════
     🚫 FILE EXCLUSION MANAGER JAVASCRIPT
     ═══════════════════════════════════════════════════════════════════ -->
<script>
// ═══════════════════════════════════════════════════════════════════
// 📁 UNIFIED FILE UPLOAD ZONE
// ═══════════════════════════════════════════════════════════════════

// Category configuration
const ufCategoryConfig = {
    folders: { title: 'Folders', icon: 'fa-folder', gradient: 'linear-gradient(135deg, #f59e0b 0%, #d97706 100%)', extensions: [], isFolder: true },
    html: { title: 'HTML', icon: 'fa-html5', gradient: 'linear-gradient(135deg, #e34c26 0%, #f06529 100%)', extensions: ['html', 'htm'] },
    css: { title: 'CSS', icon: 'fa-css3-alt', gradient: 'linear-gradient(135deg, #264de4 0%, #2965f1 100%)', extensions: ['css', 'scss', 'sass', 'less'] },
    javascript: { title: 'JavaScript', icon: 'fa-js', gradient: 'linear-gradient(135deg, #f7df1e 0%, #f0db4f 100%)', extensions: ['js', 'jsx', 'ts', 'tsx'] },
    php: { title: 'PHP', icon: 'fa-php', gradient: 'linear-gradient(135deg, #777bb3 0%, #8892bf 100%)', extensions: ['php', 'phtml'] },
    images: { title: 'Images', icon: 'fa-images', gradient: 'linear-gradient(135deg, #00bcd4 0%, #4dd0e1 100%)', extensions: ['png', 'jpg', 'jpeg', 'gif', 'svg', 'webp', 'ico'] },
    other: { title: 'Other', icon: 'fa-file', gradient: 'linear-gradient(135deg, #9e9e9e 0%, #bdbdbd 100%)', extensions: [] }
};

// File storage
let ufFileStorage = {
    folders: [], html: [], css: [], javascript: [], php: [], images: [], other: []
};

// Page detection
let ufDetectedHomepage = '';
let ufDetectedFeatured = '';
let ufDetectedDoc = '';

// Root folder storage
let ufRootFolder = null;

// Initialize unified file upload
function ufInit() {
    ufLoadFromStorage();
    ufSetupRootSelector();
    ufSetupDropZone();
    ufDisplayCategories();
    ufUpdateBadge();
}

// Setup root folder selector (now uses PHP folder browser — click opens modal)
function ufSetupRootSelector() {
    const rootDrop = document.getElementById('ufRootDrop');
    
    if (!rootDrop) {
        console.log('Root selector elements not found');
        return;
    }
    
    console.log('Setting up root selector (PHP folder browser mode)...');
    
    // Click handler is set inline via onclick="openDeFolderBrowser()"
    // Also support drag & drop of folders onto the root drop area
    rootDrop.addEventListener('dragenter', (e) => { 
        e.preventDefault(); 
        e.stopPropagation();
        rootDrop.style.borderColor = '#fbbf24';
        rootDrop.style.background = 'rgba(251, 191, 36, 0.1)';
    });
    rootDrop.addEventListener('dragover', (e) => { 
        e.preventDefault(); 
        e.stopPropagation();
        e.dataTransfer.dropEffect = 'copy'; 
    });
    rootDrop.addEventListener('dragleave', (e) => { 
        e.preventDefault(); 
        e.stopPropagation();
        rootDrop.style.borderColor = '';
        rootDrop.style.background = '';
    });
    rootDrop.addEventListener('drop', async (e) => {
        e.preventDefault();
        e.stopPropagation();
        rootDrop.style.borderColor = '';
        rootDrop.style.background = '';
        
        console.log('Drop on root', e.dataTransfer.items);
        
        // Accept dropped folders and read their structure
        if (e.dataTransfer.items && e.dataTransfer.items.length > 0) {
            const items = Array.from(e.dataTransfer.items);
            const folders = [];
            
            showToast('📁 Processing folders...', 'info');
            
            for (const item of items) {
                if (item.webkitGetAsEntry) {
                    const entry = item.webkitGetAsEntry();
                    if (entry && entry.isDirectory) {
                        const folderData = await ufReadFolderStructure(entry);
                        folders.push({
                            name: entry.name,
                            type: 'folder',
                            children: folderData.children || [],
                            fileCount: folderData.fileCount || 0,
                            folderCount: folderData.folderCount || 0
                        });
                    }
                }
            }
            
            if (folders.length > 0) {
                ufHandleFoldersStructure(folders);
                
                // Update root display
                const rootSelectedDiv = document.getElementById('ufRootSelected');
                const rootNameSpan = document.getElementById('ufRootName');
                if (rootSelectedDiv && rootNameSpan) {
                    const folderNames = folders.map(f => f.name).join(', ');
                    const totalFiles = folders.reduce((sum, f) => sum + (f.fileCount || 0), 0);
                    rootDrop.style.display = 'none';
                    rootSelectedDiv.style.display = 'flex';
                    rootNameSpan.textContent = `${folders.length} folder(s): ${folderNames} (${totalFiles} files)`;
                }
                showToast(`📁 ${folders.length} folder(s) added to Project Structure`, 'success');
            } else {
                showToast('⚠️ No folders detected. Please drop folders, not files.', 'warning');
            }
        }
    });
}

// Update root display
function ufUpdateRootDisplay() {
    const dropDiv = document.getElementById('ufRootDrop');
    const selectedDiv = document.getElementById('ufRootSelected');
    const nameSpan = document.getElementById('ufRootName');
    
    if (ufRootFolder) {
        if (dropDiv) dropDiv.style.display = 'none';
        if (selectedDiv) selectedDiv.style.display = 'flex';
        if (nameSpan) nameSpan.textContent = `${ufRootFolder.name} (${ufRootFolder.fileCount} files)`;
    } else {
        if (dropDiv) dropDiv.style.display = 'flex';
        if (selectedDiv) selectedDiv.style.display = 'none';
    }
}

// Clear root folder (resets the Project Routes display)
function ufClearRoot() {
    ufRootFolder = null;
    ufUpdateRootDisplay();
    localStorage.removeItem('ufRootFolder');
    
    // Also reset the root drop zone display
    const dropDiv = document.getElementById('ufRootDrop');
    const selectedDiv = document.getElementById('ufRootSelected');
    if (dropDiv) dropDiv.style.display = 'flex';
    if (selectedDiv) selectedDiv.style.display = 'none';
    
    showToast('Project routes cleared', 'info');
}

// Save root to storage
function ufSaveRootToStorage() {
    if (ufRootFolder) {
        localStorage.setItem('ufRootFolder', JSON.stringify({
            name: ufRootFolder.name,
            fileCount: ufRootFolder.fileCount,
            folderCount: ufRootFolder.folderCount || 0
        }));
    }
}

// Load root from storage
function ufLoadRootFromStorage() {
    try {
        const stored = localStorage.getItem('ufRootFolder');
        if (stored) {
            ufRootFolder = JSON.parse(stored);
            ufUpdateRootDisplay();
        }
    } catch (e) {}
}

// Build structure from file list (names only, no content)
function ufBuildStructureFromFiles(files, rootName) {
    const structure = {
        name: rootName,
        type: 'folder',
        children: [],
        fileCount: 0,
        folderCount: 0
    };
    
    const folderMap = new Map();
    folderMap.set('', structure);
    
    files.forEach(file => {
        const path = file.webkitRelativePath || file.name;
        const parts = path.split('/');
        
        // Skip root folder name
        const startIndex = parts[0] === rootName ? 1 : 0;
        
        let currentPath = '';
        let currentFolder = structure;
        
        for (let i = startIndex; i < parts.length; i++) {
            const part = parts[i];
            const isFile = i === parts.length - 1;
            
            if (isFile) {
                // Add file (name only, no content)
                currentFolder.children.push({
                    name: part,
                    type: 'file',
                    path: path
                });
                structure.fileCount++;
            } else {
                // Create/get folder
                const folderPath = currentPath ? currentPath + '/' + part : part;
                
                if (!folderMap.has(folderPath)) {
                    const newFolder = {
                        name: part,
                        type: 'folder',
                        children: [],
                        fileCount: 0,
                        folderCount: 0
                    };
                    currentFolder.children.push(newFolder);
                    folderMap.set(folderPath, newFolder);
                    structure.folderCount++;
                }
                
                currentFolder = folderMap.get(folderPath);
                currentPath = folderPath;
            }
        }
    });
    
    return structure;
}

// Read folder structure from entry (names only, no file content)
async function ufReadFolderStructure(entry, path = '') {
    return new Promise((resolve) => {
        const folderData = {
            name: entry.name,
            path: path ? path + '/' + entry.name : entry.name,
            type: 'folder',
            children: [],
            fileCount: 0,
            folderCount: 0
        };
        
        const reader = entry.createReader();
        const allEntries = [];
        
        const readBatch = () => {
            reader.readEntries(async (entries) => {
                if (entries.length === 0) {
                    // Process all entries
                    for (const e of allEntries) {
                        if (e.isDirectory) {
                            const subFolder = await ufReadFolderStructure(e, folderData.path);
                            folderData.children.push(subFolder);
                            folderData.folderCount += 1 + subFolder.folderCount;
                            folderData.fileCount += subFolder.fileCount;
                        } else {
                            // Store only name and path, no file content
                            folderData.children.push({ 
                                name: e.name, 
                                type: 'file', 
                                path: folderData.path + '/' + e.name 
                            });
                            folderData.fileCount++;
                        }
                    }
                    resolve(folderData);
                } else {
                    allEntries.push(...entries);
                    readBatch();
                }
            }, (error) => {
                console.error('Error reading directory:', error);
                resolve(folderData);
            });
        };
        readBatch();
    });
}

// Setup drop zone events
function ufSetupDropZone() {
    const dropZone = document.getElementById('ufDropZone');
    const fileInput = document.getElementById('ufFileInput');
    
    if (!dropZone || !fileInput) {
        console.log('Drop zone elements not found');
        return;
    }
    
    console.log('Setting up drop zone...');
    
    // File input change
    fileInput.addEventListener('change', (e) => {
        console.log('File input changed', e.target.files);
        if (e.target.files && e.target.files.length > 0) {
            const files = Array.from(e.target.files);
            // Convert to structure info (names only, no content)
            const fileInfos = files.map(file => ({
                name: file.name,
                size: file.size,
                type: 'file'
            }));
            ufHandleFilesStructure(fileInfos);
            
            // Check for logo files among the dropped files (we have File objects here)
            ufCheckDroppedFilesForLogo(files);
            
            e.target.value = ''; // Reset
        }
    });
    
    // Drag enter
    dropZone.addEventListener('dragenter', (e) => {
        e.preventDefault();
        e.stopPropagation();
        dropZone.style.borderColor = '#6366f1';
        dropZone.style.background = 'rgba(99, 102, 241, 0.1)';
    });
    
    // Drag over
    dropZone.addEventListener('dragover', (e) => {
        e.preventDefault();
        e.stopPropagation();
        e.dataTransfer.dropEffect = 'copy';
    });
    
    // Drag leave
    dropZone.addEventListener('dragleave', (e) => {
        e.preventDefault();
        e.stopPropagation();
        dropZone.style.borderColor = '';
        dropZone.style.background = '';
    });
    
    // Drop (Files Only — folders are handled via the PHP folder browser)
    dropZone.addEventListener('drop', async (e) => {
        e.preventDefault();
        e.stopPropagation();
        dropZone.style.borderColor = '';
        dropZone.style.background = '';
        
        console.log('Drop event on main zone (files only)', e.dataTransfer.items);
        
        if (e.dataTransfer.items && e.dataTransfer.items.length > 0) {
            const items = Array.from(e.dataTransfer.items);
            const fileInfos = [];
            const actualFiles = []; // Keep File objects for logo detection
            let foldersSkipped = 0;
            
            for (const item of items) {
                if (item.webkitGetAsEntry) {
                    const entry = item.webkitGetAsEntry();
                    if (entry) {
                        if (entry.isDirectory) {
                            // Skip folders — they should be added via the Project Routes picker
                            foldersSkipped++;
                        } else if (entry.isFile) {
                            const file = item.getAsFile();
                            if (file) {
                                fileInfos.push({
                                    name: file.name,
                                    size: file.size,
                                    type: 'file'
                                });
                                actualFiles.push(file);
                            }
                        }
                    }
                } else {
                    const file = item.getAsFile();
                    if (file) {
                        fileInfos.push({
                            name: file.name,
                            size: file.size,
                            type: 'file'
                        });
                        actualFiles.push(file);
                    }
                }
            }
            
            // Process files
            if (fileInfos.length > 0) {
                ufHandleFilesStructure(fileInfos);
                // Check dropped files for logo images
                ufCheckDroppedFilesForLogo(actualFiles);
            }
            
            if (foldersSkipped > 0) {
                showToast(`⚠️ ${foldersSkipped} folder(s) skipped — use "Project Routes" to add folders`, 'warning');
            }
            
            if (fileInfos.length === 0 && foldersSkipped === 0) {
                showToast('⚠️ No files detected', 'warning');
            }
        }
    });
}

// Read folder entry recursively
async function ufReadFolderEntry(entry, path = '') {
    return new Promise((resolve) => {
        const folderData = {
            name: entry.name,
            path: path ? path + '/' + entry.name : entry.name,
            type: 'folder',
            children: [],
            fileCount: 0,
            folderCount: 0
        };
        
        const reader = entry.createReader();
        const readAllEntries = async () => {
            const allEntries = [];
            const readBatch = () => {
                reader.readEntries(async (entries) => {
                    if (entries.length === 0) {
                        // Process all entries
                        for (const e of allEntries) {
                            if (e.isDirectory) {
                                const subFolder = await ufReadFolderEntry(e, folderData.path);
                                folderData.children.push(subFolder);
                                folderData.folderCount += 1 + subFolder.folderCount;
                                folderData.fileCount += subFolder.fileCount;
                            } else {
                                folderData.children.push({ name: e.name, type: 'file', path: folderData.path + '/' + e.name });
                                folderData.fileCount++;
                            }
                        }
                        resolve(folderData);
                    } else {
                        allEntries.push(...entries);
                        readBatch();
                    }
                });
            };
            readBatch();
        };
        readAllEntries();
    });
}

// Handle folders (legacy)
function ufHandleFolders(folders) {
    ufHandleFoldersStructure(folders);
}

// Handle folders structure (names only, no content)
function ufHandleFoldersStructure(folders) {
    if (!folders || folders.length === 0) return;
    
    console.log('Processing folders:', folders);
    
    folders.forEach(folder => {
        // Check if folder already exists
        const exists = ufFileStorage.folders.some(f => f.name === folder.name);
        if (!exists) {
            ufFileStorage.folders.push({
                name: folder.name,
                type: 'folder',
                children: folder.children || [],
                fileCount: folder.fileCount || 0,
                folderCount: folder.folderCount || 0,
                _serverPath: folder._serverPath || '' // Full server path for PHP file access
            });
        }
    });
    
    ufDisplayCategories();
    ufSaveToStorage();
    ufUpdateBadge();
    
    document.getElementById('ufCategories')?.classList.add('show');
    
    const totalFolders = folders.length;
    const totalFilesInFolders = folders.reduce((sum, f) => sum + (f.fileCount || 0), 0);
    showToast(`📁 ${totalFolders} folder(s) with ${totalFilesInFolders} files added`, 'success');
    
    // Auto-detect logo from newly added folders (short delay to ensure storage is settled)
    setTimeout(() => { ufAutoDetectLogo(); }, 100);
}

// Handle files structure (names only, no content)
function ufHandleFilesStructure(fileInfos) {
    if (!fileInfos || fileInfos.length === 0) return;
    
    console.log('Processing files:', fileInfos);
    
    fileInfos.forEach(fileInfo => {
        const category = ufCategorizeFileByName(fileInfo.name);
        // Check if file already exists
        const exists = ufFileStorage[category]?.some(f => f.name === fileInfo.name);
        if (!exists && ufFileStorage[category]) {
            ufFileStorage[category].push({
                name: fileInfo.name,
                size: fileInfo.size || 0,
                type: 'file'
            });
        }
    });
    
    ufDisplayCategories();
    ufSaveToStorage();
    ufUpdateBadge();
    
    document.getElementById('ufCategories')?.classList.add('show');
    
    showToast(`✅ ${fileInfos.length} file(s) added`, 'success');
    
    // Auto-detect logo from newly added files (short delay to ensure storage is settled)
    setTimeout(() => { ufAutoDetectLogo(); }, 100);
}

// Categorize file by name (extension)
function ufCategorizeFileByName(filename) {
    const extension = filename.toLowerCase().split('.').pop();
    
    for (const [category, config] of Object.entries(ufCategoryConfig)) {
        if (config.extensions && config.extensions.includes(extension)) {
            return category;
        }
    }
    return 'other';
}

// Handle uploaded files
function ufHandleFiles(files) {
    if (!files || files.length === 0) {
        showToast('No files selected', 'warning');
        return;
    }
    
    // Categorize files
    Array.from(files).forEach(file => {
        const category = ufCategorizeFile(file);
        // Check if file already exists
        const exists = ufFileStorage[category].some(f => f.name === file.name);
        if (!exists) {
            ufFileStorage[category].push(file);
        }
    });
    
    // Display and save
    ufDisplayCategories();
    ufSaveToStorage();
    ufUpdateBadge();
    
    // Show categories section
    document.getElementById('ufCategories').classList.add('show');
    
    showToast(`✅ ${files.length} file(s) processed`, 'success');
}

// Categorize file by extension
function ufCategorizeFile(file) {
    const extension = file.name.toLowerCase().split('.').pop();
    
    for (const [category, config] of Object.entries(ufCategoryConfig)) {
        if (config.extensions.includes(extension)) {
            return category;
        }
    }
    return 'other';
}

// Display categorized files
function ufDisplayCategories() {
    const treeContainer = document.getElementById('ufStructureTree');
    if (!treeContainer) return;
    
    // Calculate total stats
    let totalFolders = 0;
    let totalFiles = 0;
    
    // Count from folders category
    ufFileStorage.folders.forEach(folder => {
        totalFolders += 1 + (folder.folderCount || 0);
        totalFiles += folder.fileCount || 0;
    });
    
    // Count standalone files
    Object.entries(ufFileStorage).forEach(([category, items]) => {
        if (category !== 'folders') {
            totalFiles += items.length;
        }
    });
    
    // Update stats
    document.getElementById('ufStatFolders').textContent = totalFolders;
    document.getElementById('ufStatFiles').textContent = totalFiles;
    
    // Check if we have any content
    const hasFolders = ufFileStorage.folders.length > 0;
    const hasFiles = Object.entries(ufFileStorage).some(([cat, items]) => cat !== 'folders' && items.length > 0);
    
    if (!hasFolders && !hasFiles) {
        treeContainer.innerHTML = `
            <div class="uf-structure-empty">
                <i class="fas fa-folder-open"></i>
                <p>Drop files or folders to see the project structure</p>
            </div>
        `;
        return;
    }
    
    let html = '';
    
    // Render folders first (with their children)
    ufFileStorage.folders.forEach((folder, index) => {
        html += ufRenderStructureNode(folder, 'folders', index);
    });
    
    // Render standalone files (not in any folder)
    const standaloneFiles = [];
    Object.entries(ufFileStorage).forEach(([category, items]) => {
        if (category !== 'folders') {
            items.forEach((file, fileIndex) => {
                standaloneFiles.push({ file, category, index: fileIndex });
            });
        }
    });
    
    if (standaloneFiles.length > 0) {
        html += `<div class="uf-root-files">
            <div class="uf-root-files-title">📄 Root Files</div>
            ${standaloneFiles.map(({ file, category, index }) => ufRenderFileNode(file, category, index)).join('')}
        </div>`;
    }
    
    treeContainer.innerHTML = html;
    
    // Update page detection
    ufPopulatePageDetection();
}

// Render a structure node (folder or file)
function ufRenderStructureNode(node, category, index, level = 0) {
    if (!node) return '';
    
    const isFolder = node.type === 'folder' || node.children;
    const hasChildren = isFolder && node.children && node.children.length > 0;
    
    if (isFolder) {
        const childCount = (node.fileCount || 0) + (node.folderCount || 0);
        return `
            <div class="uf-node is-folder" data-category="${category}" data-index="${index}">
                <div class="uf-node-header" onclick="ufToggleNode(this)">
                    <i class="fas fa-chevron-right uf-node-arrow ${hasChildren ? '' : 'hidden'}"></i>
                    <i class="fas fa-folder uf-node-icon folder"></i>
                    <span class="uf-node-name">${ufEscapeHtml(node.name)}</span>
                    ${childCount > 0 ? `<span class="uf-node-count">${childCount} items</span>` : ''}
                    <button class="uf-file-remove" onclick="event.stopPropagation(); ufRemoveFile('${category}', ${index})" title="Remove">
                        <i class="fas fa-times"></i>
                    </button>
                </div>
                ${hasChildren ? `
                    <div class="uf-node-children collapsed">
                        ${ufRenderChildren(node.children)}
                    </div>
                ` : ''}
            </div>
        `;
    } else {
        return ufRenderFileNode(node, category, index);
    }
}

// Render children of a folder
function ufRenderChildren(children) {
    if (!children || children.length === 0) return '';
    
    // Sort: folders first, then files
    const sorted = [...children].sort((a, b) => {
        const aIsFolder = a.type === 'folder' || a.children;
        const bIsFolder = b.type === 'folder' || b.children;
        if (aIsFolder === bIsFolder) return a.name.localeCompare(b.name);
        return aIsFolder ? -1 : 1;
    });
    
    return sorted.map((child, i) => {
        const isFolder = child.type === 'folder' || child.children;
        if (isFolder) {
            const hasChildren = child.children && child.children.length > 0;
            const childCount = (child.fileCount || 0) + (child.folderCount || 0);
            return `
                <div class="uf-node is-folder">
                    <div class="uf-node-header" onclick="ufToggleNode(this)">
                        <i class="fas fa-chevron-right uf-node-arrow ${hasChildren ? '' : 'hidden'}"></i>
                        <i class="fas fa-folder uf-node-icon folder"></i>
                        <span class="uf-node-name">${ufEscapeHtml(child.name)}</span>
                        ${childCount > 0 ? `<span class="uf-node-count">${childCount}</span>` : ''}
                    </div>
                    ${hasChildren ? `
                        <div class="uf-node-children collapsed">
                            ${ufRenderChildren(child.children)}
                        </div>
                    ` : ''}
                </div>
            `;
        } else {
            return ufRenderFileNode(child);
        }
    }).join('');
}

// Render a file node
function ufRenderFileNode(file, category, index) {
    const ext = file.name.split('.').pop().toLowerCase();
    const iconClass = ufGetFileIconColorClass(ext);
    const badgeClass = ufGetBadgeClass(ext);
    const badgeText = ufGetBadgeText(ext);
    
    return `
        <div class="uf-node is-file" ${category ? `data-category="${category}" data-index="${index}"` : ''}>
            <div class="uf-node-header">
                <i class="fas fa-chevron-right uf-node-arrow hidden"></i>
                <i class="${ufGetFileIcon(ext)} uf-node-icon ${iconClass}"></i>
                <span class="uf-node-name">${ufEscapeHtml(file.name)}</span>
                <span class="uf-node-badge ${badgeClass}">${badgeText}</span>
                ${category ? `
                    <button class="uf-file-remove" onclick="event.stopPropagation(); ufRemoveFile('${category}', ${index})" title="Remove">
                        <i class="fas fa-times"></i>
                    </button>
                ` : ''}
            </div>
        </div>
    `;
}

// Get file icon
function ufGetFileIcon(ext) {
    const icons = {
        'php': 'fab fa-php',
        'html': 'fab fa-html5',
        'htm': 'fab fa-html5',
        'css': 'fab fa-css3-alt',
