// Populate page detection dropdowns
function ufPopulatePageDetection() {
    const homepageSelect = document.getElementById('ufHomepageSelect');
    const featuredSelect = document.getElementById('ufFeaturedSelect');
    const docSelect = document.getElementById('ufDocSelect');
    const detectionSection = document.getElementById('ufPageDetection');
    
    if (!homepageSelect || !featuredSelect) return;
    
    // Get all HTML and PHP files — from standalone files AND from inside folders
    const pageFiles = [
        ...ufFileStorage.html.map(f => ({ name: f.name, type: 'HTML', source: 'standalone' })),
        ...ufFileStorage.php.map(f => ({ name: f.name, type: 'PHP', source: 'standalone' }))
    ];
    
    // Also extract HTML/PHP files from inside folder trees (recursive)
    function extractPagesFromChildren(children, folderPath) {
        if (!children || !Array.isArray(children)) return;
        children.forEach(child => {
            if (child.type === 'folder' && child.children) {
                extractPagesFromChildren(child.children, folderPath + '/' + child.name);
            } else if (child.type === 'file') {
                const ext = child.name.split('.').pop().toLowerCase();
                if (['html', 'htm'].includes(ext)) {
                    pageFiles.push({ name: child.name, type: 'HTML', source: folderPath, fullLabel: `${child.name} (${folderPath})` });
                } else if (ext === 'php') {
                    pageFiles.push({ name: child.name, type: 'PHP', source: folderPath, fullLabel: `${child.name} (${folderPath})` });
                }
            }
        });
    }
    
    ufFileStorage.folders.forEach(folder => {
        if (folder.children) {
            extractPagesFromChildren(folder.children, folder.name);
        }
    });
    
    // Remove duplicates by name (keep first occurrence)
    const seen = new Set();
    const uniquePageFiles = pageFiles.filter(f => {
        if (seen.has(f.name)) return false;
        seen.add(f.name);
        return true;
    });
    
    // ─── Collect documentation files (.txt only) ───
    const docExts = ['txt'];
    const docFiles = [];
    
    // From all standalone file categories
    Object.values(ufFileStorage).forEach(arr => {
        if (!Array.isArray(arr)) return;
        arr.forEach(f => {
            if (!f.name || f.children) return; // skip folders
            if (f.name.toLowerCase() === 'prompt.txt') return; // always exclude prompt.txt
            const ext = f.name.split('.').pop().toLowerCase();
            if (docExts.includes(ext)) {
                docFiles.push({ name: f.name, type: ext.toUpperCase(), source: 'standalone' });
            }
        });
    });
    
    // From inside folder trees (recursive)
    function extractDocsFromChildren(children, folderPath) {
        if (!children || !Array.isArray(children)) return;
        children.forEach(child => {
            if (child.type === 'folder' && child.children) {
                extractDocsFromChildren(child.children, folderPath + '/' + child.name);
            } else if (child.type === 'file') {
                if (child.name.toLowerCase() === 'prompt.txt') return; // always exclude prompt.txt
                const ext = child.name.split('.').pop().toLowerCase();
                if (docExts.includes(ext)) {
                    docFiles.push({ name: child.name, type: ext.toUpperCase(), source: folderPath, fullLabel: `${child.name} (${folderPath})` });
                }
            }
        });
    }
    
    ufFileStorage.folders.forEach(folder => {
        if (folder.children) {
            extractDocsFromChildren(folder.children, folder.name);
        }
    });
    
    // De-duplicate doc files
    const seenDocs = new Set();
    const uniqueDocFiles = docFiles.filter(f => {
        if (seenDocs.has(f.name)) return false;
        seenDocs.add(f.name);
        return true;
    });
    
    // Show/hide detection section (show if we have pages OR doc files)
    if (uniquePageFiles.length > 0 || uniqueDocFiles.length > 0) {
        detectionSection.style.display = 'block';
    } else {
        detectionSection.style.display = 'none';
        ufDetectedHomepage = '';
        ufDetectedFeatured = '';
        ufDetectedDoc = '';
        // No pages found → sync to Homepage Config as "Create New"
        ufSyncToHomepageConfig();
        return;
    }
    
    // Save current selections
    const currentHomepage = homepageSelect.value;
    const currentFeatured = featuredSelect.value;
    const currentDoc = docSelect ? docSelect.value : '';
    
    // Repopulate dropdowns
    homepageSelect.innerHTML = '<option value="">-- Select Homepage --</option>';
    featuredSelect.innerHTML = '<option value="">-- Select Featured Page --</option>';
    
    uniquePageFiles.forEach(file => {
        const label = file.fullLabel || `${file.name} (${file.type})`;
        
        const option1 = document.createElement('option');
        option1.value = file.name;
        option1.textContent = label;
        homepageSelect.appendChild(option1);
        
        const option2 = document.createElement('option');
        option2.value = file.name;
        option2.textContent = label;
        featuredSelect.appendChild(option2);
    });
    
    // Populate documentation dropdown
    if (docSelect) {
        docSelect.innerHTML = '<option value="">-- No documentation available --</option>';
        uniqueDocFiles.forEach(file => {
            const label = file.fullLabel || `${file.name} (${file.type})`;
            const option = document.createElement('option');
            option.value = file.name;
            option.textContent = label;
            docSelect.appendChild(option);
        });
    }
    
    // ═══════════════════════════════════════════
    // SMART AUTO-DETECTION — Educated Guess
    // ═══════════════════════════════════════════
    
    // Try to restore previous selections first
    let homepageRestored = false;
    let featuredRestored = false;
    let docRestored = false;
    
    if (currentHomepage && uniquePageFiles.some(f => f.name === currentHomepage)) {
        homepageSelect.value = currentHomepage;
        ufHandleHomepageDetection();
        homepageRestored = true;
    }
    if (currentFeatured && uniquePageFiles.some(f => f.name === currentFeatured)) {
        featuredSelect.value = currentFeatured;
        ufHandleFeaturedDetection();
        featuredRestored = true;
    }
    if (docSelect && currentDoc && uniqueDocFiles.some(f => f.name === currentDoc)) {
        docSelect.value = currentDoc;
        ufHandleDocDetection();
        docRestored = true;
    }
    
    // If no previous selection, run auto-detection
    if (!homepageRestored || !ufDetectedHomepage) {
        const guessedHomepage = ufGuessHomepage(uniquePageFiles);
        if (guessedHomepage) {
            homepageSelect.value = guessedHomepage;
            ufHandleHomepageDetection();
            console.log('🏠 Auto-detected Homepage:', guessedHomepage);
        }
    }
    
    if (!featuredRestored || !ufDetectedFeatured) {
        const guessedFeatured = ufGuessFeaturedPage(uniquePageFiles, ufDetectedHomepage);
        if (guessedFeatured) {
            featuredSelect.value = guessedFeatured;
            ufHandleFeaturedDetection();
            console.log('⭐ Auto-detected Featured Page:', guessedFeatured);
        }
    }
    
    // Auto-detect documentation file
    if (docSelect && (!docRestored || !ufDetectedDoc)) {
        const guessedDoc = ufGuessDocumentation(uniqueDocFiles);
        if (guessedDoc) {
            docSelect.value = guessedDoc;
            ufHandleDocDetection();
            console.log('📄 Auto-detected Documentation:', guessedDoc);
        }
    }
}

// ═══════════════════════════════════════════
// SMART PAGE DETECTION — Educated Guess Logic
// ═══════════════════════════════════════════

// Guess the homepage from a list of page files (priority-based matching)
function ufGuessHomepage(pageFiles) {
    if (!pageFiles || pageFiles.length === 0) return '';
    
    const names = pageFiles.map(f => f.name.toLowerCase());
    
    // Priority list for homepage detection (most common → least common)
    const homepagePatterns = [
        // Exact matches (highest priority)
        'index.html', 'index.php', 'index.htm',
        'home.html', 'home.php', 'home.htm',
        'default.html', 'default.php', 'default.htm',
        'main.html', 'main.php', 'main.htm',
        'welcome.html', 'welcome.php', 'welcome.htm',
        'landing.html', 'landing.php', 'landing.htm',
        'homepage.html', 'homepage.php', 'homepage.htm',
        'front.html', 'front.php', 'front.htm',
        'app.html', 'app.php', 'app.htm',
    ];
    
    // Check exact matches first
    for (const pattern of homepagePatterns) {
        const match = pageFiles.find(f => f.name.toLowerCase() === pattern);
        if (match) return match.name;
    }
    
    // Partial matches — file name contains "index", "home", etc.
    const partialPatterns = ['index', 'home', 'main', 'landing', 'default', 'welcome', 'front'];
    for (const keyword of partialPatterns) {
        const match = pageFiles.find(f => f.name.toLowerCase().includes(keyword));
        if (match) return match.name;
    }
    
    // Last resort: pick the first HTML file, then first PHP file
    const firstHtml = pageFiles.find(f => f.type === 'HTML');
    if (firstHtml) return firstHtml.name;
    
    const firstPhp = pageFiles.find(f => f.type === 'PHP');
    if (firstPhp) return firstPhp.name;
    
    return '';
}

// Guess the featured/secondary page (priority-based, excluding homepage)
function ufGuessFeaturedPage(pageFiles, homepage) {
    if (!pageFiles || pageFiles.length === 0) return '';
    
    // Filter out the homepage
    const candidates = pageFiles.filter(f => f.name !== homepage);
    if (candidates.length === 0) return '';
    
    // Priority list for featured page detection
    const featuredPatterns = [
        // About pages (very common as "second page")
        'about.html', 'about.php', 'about.htm',
        'about-us.html', 'about-us.php', 'about-us.htm',
        'aboutus.html', 'aboutus.php', 'aboutus.htm',
        'who-we-are.html', 'who-we-are.php',
        // Services / Products
        'services.html', 'services.php', 'services.htm',
        'products.html', 'products.php', 'products.htm',
        'features.html', 'features.php', 'features.htm',
        'solutions.html', 'solutions.php',
        'offerings.html', 'offerings.php',
        // Portfolio / Work
        'portfolio.html', 'portfolio.php', 'portfolio.htm',
        'projects.html', 'projects.php',
        'work.html', 'work.php',
        'gallery.html', 'gallery.php',
        'showcase.html', 'showcase.php',
        // Contact
        'contact.html', 'contact.php', 'contact.htm',
        'contact-us.html', 'contact-us.php',
        'contactus.html', 'contactus.php',
        // Blog
        'blog.html', 'blog.php', 'blog.htm',
        'news.html', 'news.php',
        'articles.html', 'articles.php',
        // Pricing
        'pricing.html', 'pricing.php',
        'plans.html', 'plans.php',
        // Team
        'team.html', 'team.php',
        'our-team.html', 'our-team.php',
        // FAQ
        'faq.html', 'faq.php',
        'help.html', 'help.php',
    ];
    
    // Check exact matches
    for (const pattern of featuredPatterns) {
        const match = candidates.find(f => f.name.toLowerCase() === pattern);
        if (match) return match.name;
    }
    
    // Partial keyword matches
    const partialPatterns = ['about', 'service', 'product', 'feature', 'portfolio', 'contact', 'blog', 'pricing', 'team', 'work', 'gallery'];
    for (const keyword of partialPatterns) {
        const match = candidates.find(f => f.name.toLowerCase().includes(keyword));
        if (match) return match.name;
    }
    
    // Last resort: pick the first non-homepage candidate
    return candidates[0]?.name || '';
}

// ═══════════════════════════════════════════
// SMART DOCUMENTATION FILE DETECTION
// ═══════════════════════════════════════════

// Guess the documentation file from all files (priority-based matching)
function ufGuessDocumentation(docFiles) {
    if (!docFiles || docFiles.length === 0) return '';
    
    // Only .txt files are considered documentation (exclude prompt.txt)
    const txtOnly = docFiles.filter(f => f.name.toLowerCase().endsWith('.txt') && f.name.toLowerCase() !== 'prompt.txt');
    if (txtOnly.length === 0) return '';
    
    // Exact filename matches (highest priority) — common doc .txt names
    const exactPatterns = [
        // Project-specific documentation (always top priority)
        '_Final Version - Genetic Invent Report.txt',
        'readme.txt', 'README.txt',
        'documentation.txt', 'docs.txt', 'doc.txt',
        'guide.txt', 'manual.txt', 'help.txt',
        'instructions.txt', 'howto.txt', 'how-to.txt',
        'getting-started.txt', 'quickstart.txt', 'quick-start.txt',
        'setup.txt', 'install.txt', 'installation.txt',
        'changelog.txt', 'CHANGELOG.txt', 'changes.txt',
        'release-notes.txt', 'history.txt',
        'license.txt', 'LICENSE.txt',
        'contributing.txt', 'CONTRIBUTING.txt',
        'api.txt', 'api-docs.txt', 'reference.txt',
        'notes.txt', 'info.txt', 'about.txt',
        'faq.txt', 'todo.txt', 'TODO.txt',
    ];
    
    // Check exact matches (case-insensitive)
    for (const pattern of exactPatterns) {
        const match = txtOnly.find(f => f.name.toLowerCase() === pattern.toLowerCase());
        if (match) return match.name;
    }
    
    // Keyword-based partial matching (still only .txt files)
    // Files starting with _ are often priority documentation (e.g. _Final Version...)
    const underscoreDoc = txtOnly.find(f => f.name.startsWith('_'));
    if (underscoreDoc) return underscoreDoc.name;
    
    const docKeywords = ['report', 'final', 'readme', 'documentation', 'docs', 'guide', 'manual', 'help', 
                         'instruction', 'howto', 'how-to', 'changelog', 'release', 
                         'getting-started', 'quickstart', 'setup', 'install', 'license',
                         'contributing', 'api-doc', 'reference', 'notes', 'faq', 'todo',
                         'spec', 'description', 'overview', 'summary'];
    
    for (const keyword of docKeywords) {
        const match = txtOnly.find(f => f.name.toLowerCase().includes(keyword));
        if (match) return match.name;
    }
    
    // Fallback: first .txt file available
    return txtOnly[0]?.name || '';
}

// Handle documentation file detection change
function ufHandleDocDetection() {
    const docSelect = document.getElementById('ufDocSelect');
    const docBadge = document.getElementById('ufDocBadge');
    
    ufDetectedDoc = docSelect.value;
    
    if (ufDetectedDoc) {
        docBadge.textContent = 'Set';
        docBadge.className = 'uf-page-badge set';
    } else {
        docBadge.textContent = 'Not Set';
        docBadge.className = 'uf-page-badge not-set';
    }
    
    ufSaveToStorage();
    
    // Sync with Documentation Integration tool
    if (ufDetectedDoc) {
        setTimeout(() => { ufSyncToDocumentationTool(); }, 200);
    } else {
        // Clear Documentation Integration tool when doc is deselected
        if (typeof diFileName !== 'undefined' && diFileName) {
            diFileContent = null;
            diFileName = null;
            diEnableDoc = false;
            
            const docCheckbox = document.getElementById('diEnableDoc');
            if (docCheckbox) {
                docCheckbox.checked = false;
                const label = docCheckbox.closest('.di-checkbox-item');
                if (label) label.classList.remove('checked');
            }
            
            document.getElementById('diUploadSection')?.classList.remove('show');
            document.getElementById('diFileInfo')?.classList.remove('show');
            document.getElementById('diModeSection')?.classList.remove('show');
            
            const fileInput = document.getElementById('diFileInput');
            if (fileInput) fileInput.value = '';
            
            if (typeof diSaveToStorage === 'function') diSaveToStorage();
            if (typeof diUpdateBadge === 'function') diUpdateBadge();
            
            console.log('🔄 UF → DI sync: Documentation cleared');
        }
    }
}

// ═══════════════════════════════════════════
// SYNC: Documentation File → Documentation Integration Tool
// ═══════════════════════════════════════════

async function ufSyncToDocumentationTool() {
    // Only sync if a documentation file is detected
    if (!ufDetectedDoc) return;
    
    // Skip if the Documentation tool already has a file loaded with the same name
    if (typeof diFileName !== 'undefined' && diFileName === ufDetectedDoc) {
        console.log('📚 Doc tool already has this file:', ufDetectedDoc);
        return;
    }
    
    // Try to find the file's server path for PHP reading
    let serverPath = '';
    const appDir = '<?php echo str_replace("\\", "/", dirname(__FILE__)); ?>';
    
    // Check standalone files first — they don't have server paths, try common locations
    const standaloneMatch = Object.values(ufFileStorage).flat().find(f => 
        f.name === ufDetectedDoc && !f.children
    );
    
    if (standaloneMatch) {
        // Try the app directory and common locations
        const pathsToTry = [
            appDir + '/' + ufDetectedDoc,
        ];
        
        // Also check if file was found inside a folder with _serverPath
        ufFileStorage.folders.forEach(folder => {
            if (folder._serverPath) {
                pathsToTry.push(folder._serverPath + '/' + ufDetectedDoc);
                // Recursive search in children
                function findInChildren(children, basePath) {
                    if (!children || !Array.isArray(children)) return;
                    children.forEach(child => {
                        if (child.type === 'file' && child.name === ufDetectedDoc) {
                            pathsToTry.unshift(basePath + '/' + child.name);
                        } else if (child.type === 'folder' && child.children) {
                            findInChildren(child.children, basePath + '/' + child.name);
                        }
                    });
                }
                findInChildren(folder.children, folder._serverPath);
            }
        });
        
        // Try each path via PHP
        for (const tryPath of pathsToTry) {
            try {
                const formData = new FormData();
                formData.append('action', 'read_file_text');
                formData.append('path', tryPath);
                
                const response = await fetch('', { method: 'POST', body: formData });
                const data = await response.json();
                
                if (data.success && data.content) {
                    serverPath = tryPath;
                    
                    // Set the Documentation Integration tool state
                    diFileContent = data.content;
                    diFileName = data.fileName;
                    diEnableDoc = true;
                    
                    // Update UI — checkbox
                    const checkbox = document.getElementById('diEnableDoc');
                    if (checkbox) {
                        checkbox.checked = true;
                        const label = checkbox.closest('.di-checkbox-item');
                        if (label) label.classList.add('checked');
                    }
                    
                    // Show upload section
                    const uploadSection = document.getElementById('diUploadSection');
                    if (uploadSection) uploadSection.classList.add('show');
                    
                    // Show file info
                    const fileInfo = document.getElementById('diFileInfo');
                    const fileNameEl = document.getElementById('diFileName');
                    const fileSizeEl = document.getElementById('diFileSize');
                    if (fileNameEl) fileNameEl.textContent = data.fileName + ' (auto-detected)';
                    if (fileSizeEl) fileSizeEl.textContent = typeof formatFileSize === 'function' ? formatFileSize(data.size || 0) : (data.size || 0) + ' bytes';
                    if (fileInfo) fileInfo.classList.add('show');
                    
                    // Show mode section
                    const modeSection = document.getElementById('diModeSection');
                    if (modeSection) modeSection.classList.add('show');
                    
                    // Initialize mode UI
                    if (typeof diSelectMode === 'function') diSelectMode(diIntegrationMode);
                    
                    // Save and update badge
                    if (typeof diSaveToStorage === 'function') diSaveToStorage();
                    if (typeof diUpdateBadge === 'function') diUpdateBadge();
                    
                    console.log('📚 Synced documentation to tool:', data.fileName, '(' + (data.size || 0) + ' bytes)');
                    showToast(`📚 Documentation auto-loaded: ${data.fileName}`, 'success');
                    return;
                }
            } catch (err) {
                continue;
            }
        }
    }
    
    // If file came from a folder tree, search in folder server paths
    for (const folder of ufFileStorage.folders) {
        if (!folder._serverPath || !folder.children) continue;
        
        function findDocPath(children, basePath) {
            for (const child of children) {
                if (child.type === 'file' && child.name === ufDetectedDoc) {
                    return basePath + '/' + child.name;
                }
                if (child.type === 'folder' && child.children) {
                    const found = findDocPath(child.children, basePath + '/' + child.name);
                    if (found) return found;
                }
            }
            return null;
        }
        
        const docPath = findDocPath(folder.children, folder._serverPath);
        if (docPath) {
            try {
                const formData = new FormData();
                formData.append('action', 'read_file_text');
                formData.append('path', docPath);
                
                const response = await fetch('', { method: 'POST', body: formData });
                const data = await response.json();
                
                if (data.success && data.content) {
                    diFileContent = data.content;
                    diFileName = data.fileName;
                    diEnableDoc = true;
                    
                    const checkbox = document.getElementById('diEnableDoc');
                    if (checkbox) {
                        checkbox.checked = true;
                        const label = checkbox.closest('.di-checkbox-item');
                        if (label) label.classList.add('checked');
                    }
                    
                    const uploadSection = document.getElementById('diUploadSection');
                    if (uploadSection) uploadSection.classList.add('show');
                    
                    const fileInfo = document.getElementById('diFileInfo');
                    const fileNameEl = document.getElementById('diFileName');
                    const fileSizeEl = document.getElementById('diFileSize');
                    if (fileNameEl) fileNameEl.textContent = data.fileName + ' (auto-detected)';
                    if (fileSizeEl) fileSizeEl.textContent = typeof formatFileSize === 'function' ? formatFileSize(data.size || 0) : (data.size || 0) + ' bytes';
                    if (fileInfo) fileInfo.classList.add('show');
                    
                    const modeSection = document.getElementById('diModeSection');
                    if (modeSection) modeSection.classList.add('show');
                    
                    if (typeof diSelectMode === 'function') diSelectMode(diIntegrationMode);
                    if (typeof diSaveToStorage === 'function') diSaveToStorage();
                    if (typeof diUpdateBadge === 'function') diUpdateBadge();
                    
                    console.log('📚 Synced documentation to tool (from folder):', data.fileName);
                    showToast(`📚 Documentation auto-loaded: ${data.fileName}`, 'success');
                    return;
                }
            } catch (err) {
                continue;
            }
        }
    }
    
    console.log('📚 Documentation file detected but could not be read from server:', ufDetectedDoc);
}

// ═══════════════════════════════════════════
// SMART LOGO AUTO-DETECTION
// ═══════════════════════════════════════════

// Auto-detect logo from uploaded files and folder trees
async function ufAutoDetectLogo() {
    // Skip if a logo is already set
    if (brandingLogoDataUrl) {
        console.log('🎨 Logo already set, skipping auto-detection');
        return;
    }
    
    const imageExts = ['png', 'jpg', 'jpeg', 'svg', 'ico', 'webp', 'gif'];
    
    // Priority list for logo file name patterns (most likely → least likely)
    const logoPatterns = [
        // Exact logo names (highest priority)
        'logo.png', 'logo.svg', 'logo.jpg', 'logo.jpeg', 'logo.webp', 'logo.ico',
        'logo-dark.png', 'logo-dark.svg', 'logo-light.png', 'logo-light.svg',
        'logo-white.png', 'logo-black.png',
        'logo-main.png', 'logo-main.svg',
        'logo-full.png', 'logo-full.svg',
        'logo-horizontal.png', 'logo-vertical.png',
        'site-logo.png', 'site-logo.svg',
        'brand-logo.png', 'brand-logo.svg',
        // Favicon (common fallback)
        'favicon.png', 'favicon.ico', 'favicon.svg', 'favicon-32x32.png', 'favicon-16x16.png',
        'apple-touch-icon.png', 'apple-icon.png',
        // Brand / icon names
        'brand.png', 'brand.svg', 'brand.jpg',
        'icon.png', 'icon.svg', 'icon.ico',
        'symbol.png', 'symbol.svg',
        'mark.png', 'mark.svg',
        'emblem.png', 'emblem.svg',
        'badge.png', 'badge.svg',
    ];
    
    // Partial keywords for broader matching
    const logoKeywords = ['logo', 'brand', 'favicon', 'icon', 'emblem', 'symbol', 'mark', 'badge'];
    
    // Collect all image files: {name, path (if from folder), source}
    let allImages = [];
    
    // 1. From standalone image files (drop zone)
    if (ufFileStorage.images) {
        ufFileStorage.images.forEach(f => {
            allImages.push({ name: f.name, path: '', source: 'standalone' });
        });
    }
    
    // 2. From folder trees (recursive) — these have full paths via PHP
    function extractImagesFromTree(children, basePath) {
        if (!children || !Array.isArray(children)) return;
        children.forEach(child => {
            if (child.type === 'folder' && child.children) {
                extractImagesFromTree(child.children, basePath + '/' + child.name);
            } else if (child.type === 'file') {
                const ext = child.name.split('.').pop().toLowerCase();
                if (imageExts.includes(ext)) {
                    allImages.push({ name: child.name, path: basePath + '/' + child.name, source: 'folder' });
                }
            }
        });
    }
    
    ufFileStorage.folders.forEach(folder => {
        if (folder.children) {
            extractImagesFromTree(folder.children, folder.name);
        }
    });
    
    if (allImages.length === 0) {
        console.log('🎨 No image files found for logo detection');
        ufHideLogoProgress();
        return;
    }
    
    console.log('🎨 Scanning', allImages.length, 'images for logo...');
    ufShowLogoProgress('🔍 Scanning ' + allImages.length + ' images...');
    
    // Try exact pattern matches first
    let bestMatch = null;
    for (const pattern of logoPatterns) {
        const match = allImages.find(img => img.name.toLowerCase() === pattern);
        if (match) {
            bestMatch = match;
            break;
        }
    }
    
    // Try partial keyword matches
    if (!bestMatch) {
        for (const keyword of logoKeywords) {
            const match = allImages.find(img => img.name.toLowerCase().includes(keyword));
            if (match) {
                bestMatch = match;
                break;
            }
        }
    }
    
    if (!bestMatch) {
        console.log('🎨 No logo file detected');
        ufHideLogoProgress();
        return;
    }
    
    console.log('🎨 Logo detected:', bestMatch.name, 'from', bestMatch.source);
    
    // Show progress indicator on branding zone
    ufShowLogoProgress('🔍 Detecting logo...');
    
    // ─── FAST PATH: Try loading via web URL first (instant, no PHP call) ───
    // Since we're on localhost, files in the app directory are accessible via URL
    const webUrlsToTry = [
        bestMatch.name,                         // Same directory as page
        'uploads/' + bestMatch.name,             // Common upload dirs
        'assets/' + bestMatch.name,
        'images/' + bestMatch.name,
        'img/' + bestMatch.name,
        'static/' + bestMatch.name,
        'public/' + bestMatch.name,
        'media/' + bestMatch.name
    ];
    
    // If from a folder tree, also try the relative folder path
    if (bestMatch.path) {
        webUrlsToTry.unshift(bestMatch.path);
    }
    
    // Try web URLs — use Image element to test if accessible
    for (const url of webUrlsToTry) {
        const found = await new Promise(resolve => {
            const testImg = new Image();
            testImg.onload = function() {
                // Image loaded! Convert to canvas → dataURL
                try {
                    const canvas = document.createElement('canvas');
                    canvas.width = testImg.naturalWidth;
                    canvas.height = testImg.naturalHeight;
                    const ctx = canvas.getContext('2d');
                    ctx.drawImage(testImg, 0, 0);
                    const dataUrl = canvas.toDataURL('image/png');
                    resolve(dataUrl);
                } catch (e) {
                    resolve(null); // CORS or other error
                }
            };
            testImg.onerror = () => resolve(null);
            // Set a timeout to not wait forever
            setTimeout(() => resolve(null), 2000);
            testImg.crossOrigin = 'anonymous';
            testImg.src = url;
        });
        
        if (found) {
            ufShowLogoProgress('✅ Logo loaded!');
            setTimeout(() => {
                ufSetBrandingLogo(found, bestMatch.name);
                showToast(`🎨 Logo auto-detected: ${bestMatch.name}`, 'success');
            }, 600);
            return;
        }
    }
    
    // Update progress for slow path
    ufShowLogoProgress('🔄 Loading logo via server...');
    
    // ─── SLOW PATH: Try PHP file read as fallback ───
    let fullServerPath = '';
    
    if (bestMatch.source === 'folder') {
        for (const folder of ufFileStorage.folders) {
            const folderRootName = bestMatch.path.split('/')[0];
            if (folder.name === folderRootName && folder._serverPath) {
                const subPath = bestMatch.path.substring(folderRootName.length);
                fullServerPath = folder._serverPath + subPath;
                break;
            }
        }
    }
    
    let phpPathsToTry = [];
    if (fullServerPath) {
        phpPathsToTry.push(fullServerPath);
    }
    
    const appDir = '<?php echo str_replace('\\', '/', dirname(__FILE__)); ?>';
    phpPathsToTry.push(appDir + '/' + bestMatch.name);
    
    const commonDirs = ['assets', 'images', 'img', 'static', 'public', 'media', 'uploads', 'resources'];
    commonDirs.forEach(dir => {
        phpPathsToTry.push(appDir + '/' + dir + '/' + bestMatch.name);
    });
    
    for (const tryPath of phpPathsToTry) {
        try {
            const formData = new FormData();
            formData.append('action', 'read_file_base64');
            formData.append('path', tryPath);
            
            const response = await fetch('', { method: 'POST', body: formData });
            const data = await response.json();
            
            if (data.success && data.dataUrl) {
                ufShowLogoProgress('✅ Logo loaded!');
                setTimeout(() => {
                    ufSetBrandingLogo(data.dataUrl, bestMatch.name);
                    showToast(`🎨 Logo auto-detected: ${bestMatch.name}`, 'success');
                }, 600);
                return;
            }
        } catch (err) {
            continue;
        }
    }
    
    // Hide progress if detection fails
    ufHideLogoProgress();
    console.log('🎨 Logo file detected but could not be read:', bestMatch.name);
}

// Show logo detection progress indicator on the branding zone
function ufShowLogoProgress(message) {
    const zone = document.getElementById('brandingLogoZone');
    if (!zone) return;
    
    // Create or update progress overlay
    let overlay = document.getElementById('brandingLogoProgress');
    if (!overlay) {
        overlay = document.createElement('div');
        overlay.id = 'brandingLogoProgress';
        overlay.style.cssText = 'position:absolute;top:0;left:0;right:0;bottom:0;display:flex;flex-direction:column;align-items:center;justify-content:center;background:rgba(15,15,25,0.9);border-radius:12px;z-index:10;gap:0.5rem;transition:opacity 0.3s;';
        zone.style.position = 'relative';
        zone.appendChild(overlay);
    }
    
    overlay.innerHTML = `<i class="fas fa-spinner fa-spin" style="color:#fbbf24;font-size:1.4rem;"></i><span style="color:#fbbf24;font-size:0.75rem;font-weight:600;">${message}</span>`;
    overlay.style.opacity = '1';
    overlay.style.display = 'flex';
}

// Hide logo detection progress
function ufHideLogoProgress() {
    const overlay = document.getElementById('brandingLogoProgress');
    if (overlay) {
        overlay.style.opacity = '0';
        setTimeout(() => { 
            if (overlay.parentNode) overlay.parentNode.removeChild(overlay); 
        }, 300);
    }
}

// Set a logo image programmatically in the Branding section
function ufSetBrandingLogo(dataUrl, fileName) {
    brandingLogoDataUrl = dataUrl;
    brandingLogoFile = null; // No File object, we have dataUrl directly
    brandingLogoFileName = fileName || '';
    
    // Hide progress indicator
    ufHideLogoProgress();
    
    const preview = document.getElementById('brandingLogoPreview');
    const prompt = document.getElementById('brandingUploadPrompt');
    const img = document.getElementById('brandingLogoImg');
    const name = document.getElementById('brandingLogoName');
    const zone = document.getElementById('brandingLogoZone');
    
    if (preview && prompt && img && name && zone) {
        img.src = dataUrl;
        name.textContent = fileName + ' (auto-detected)';
        preview.style.display = 'flex';
        prompt.style.display = 'none';
        zone.classList.add('has-logo');
    }
    
    if (typeof updateBrandingBadge === 'function') updateBrandingBadge();
    if (typeof saveBrandingState === 'function') saveBrandingState();
}

// Check dropped File objects for logo images (has access to content at drop time)
function ufCheckDroppedFilesForLogo(files) {
    // Skip if logo is already set
    if (brandingLogoDataUrl) return;
    
    const imageTypes = ['image/png', 'image/jpeg', 'image/jpg', 'image/svg+xml', 'image/x-icon', 'image/vnd.microsoft.icon', 'image/webp', 'image/gif'];
    const logoKeywords = ['logo', 'brand', 'favicon', 'icon', 'emblem', 'symbol', 'mark', 'badge', 'crest', 'seal'];
    
    // Filter to only image files
    const imageFiles = files.filter(f => 
        imageTypes.includes(f.type) || 
        f.type.startsWith('image/') ||
        f.name.match(/\.(png|jpg|jpeg|svg|ico|webp|gif|bmp)$/i)
    );
    
    console.log('🎨 Checking', imageFiles.length, 'image files for logo among', files.length, 'total files');
    
    if (imageFiles.length === 0) return;
    
    // Find the best logo candidate
    let bestMatch = null;
    
    // Exact name patterns (highest priority)
    const exactPatterns = [
        'logo.png', 'logo.svg', 'logo.jpg', 'logo.jpeg', 'logo.webp', 'logo.ico',
        'logo-dark.png', 'logo-dark.svg', 'logo-light.png', 'logo-light.svg',
        'logo-white.png', 'logo-black.png', 'logo-main.png', 'logo-main.svg',
        'site-logo.png', 'site-logo.svg', 'brand-logo.png', 'brand-logo.svg',
        'favicon.ico', 'favicon.png', 'favicon.svg', 'favicon-32x32.png',
        'apple-touch-icon.png', 'apple-icon.png',
        'brand.png', 'brand.svg', 'icon.png', 'icon.svg'
    ];
    
    for (const pattern of exactPatterns) {
        const match = imageFiles.find(f => f.name.toLowerCase() === pattern);
        if (match) { bestMatch = match; break; }
    }
    
    // Partial keyword match
    if (!bestMatch) {
        for (const keyword of logoKeywords) {
            const match = imageFiles.find(f => f.name.toLowerCase().includes(keyword));
            if (match) { bestMatch = match; break; }
        }
    }
    
    // Last resort: if there's only 1 image file, it's likely the logo
    if (!bestMatch && imageFiles.length === 1) {
        bestMatch = imageFiles[0];
    }
    
    // Another fallback: if there are few image files (≤3), pick the first PNG or SVG
    if (!bestMatch && imageFiles.length <= 3) {
        bestMatch = imageFiles.find(f => f.name.match(/\.(png|svg)$/i)) || imageFiles[0];
    }
    
    if (!bestMatch) return;
    
    console.log('🎨 Logo detected in dropped files:', bestMatch.name);
    
    // Show progress on branding zone
    ufShowLogoProgress('🔍 Detecting logo...');
    
    // Read the file as DataURL and set as branding logo
    const reader = new FileReader();
    reader.onload = function(e) {
        ufShowLogoProgress('✅ Logo loaded!');
        setTimeout(() => {
            ufSetBrandingLogo(e.target.result, bestMatch.name);
            showToast(`🎨 Logo auto-detected: ${bestMatch.name}`, 'success');
        }, 600);
    };
    reader.onerror = function() {
        ufHideLogoProgress();
    };
    reader.readAsDataURL(bestMatch);
}

// Handle homepage detection
function ufHandleHomepageDetection() {
    const homepageSelect = document.getElementById('ufHomepageSelect');
    const featuredSelect = document.getElementById('ufFeaturedSelect');
    const homepageBadge = document.getElementById('ufHomepageBadge');
    
    ufDetectedHomepage = homepageSelect.value;
    
    if (ufDetectedHomepage) {
        homepageBadge.textContent = 'Set';
        homepageBadge.className = 'uf-page-badge set';
        featuredSelect.disabled = false;
        
        // Remove homepage from featured options
        Array.from(featuredSelect.options).forEach(option => {
            if (option.value === ufDetectedHomepage) {
                option.disabled = true;
            } else {
                option.disabled = false;
            }
        });
    } else {
        homepageBadge.textContent = 'Not Set';
        homepageBadge.className = 'uf-page-badge not-set';
        featuredSelect.disabled = true;
        featuredSelect.value = '';
        ufDetectedFeatured = '';
        document.getElementById('ufFeaturedBadge').textContent = 'Not Set';
        document.getElementById('ufFeaturedBadge').className = 'uf-page-badge not-set';
    }
    
    ufSaveToStorage();
    
    // Sync with Homepage Configuration tool
    ufSyncToHomepageConfig();
}

// Handle featured page detection
function ufHandleFeaturedDetection() {
    const featuredSelect = document.getElementById('ufFeaturedSelect');
    const featuredBadge = document.getElementById('ufFeaturedBadge');
    
    ufDetectedFeatured = featuredSelect.value;
    
    if (ufDetectedFeatured) {
        featuredBadge.textContent = 'Set';
        featuredBadge.className = 'uf-page-badge set';
    } else {
        featuredBadge.textContent = 'Not Set';
        featuredBadge.className = 'uf-page-badge not-set';
    }
    
    ufSaveToStorage();
    
    // Sync with Homepage Configuration tool
    ufSyncToHomepageConfig();
}

// ═══════════════════════════════════════════════════════════════════
// SYNCHRONIZATION: Project Files Uploader ↔ Homepage Configuration
// ═══════════════════════════════════════════════════════════════════

function ufSyncToHomepageConfig() {
    // Only sync if Homepage Configuration functions are available
    if (typeof hpUpdateUI !== 'function') return;
    
    const checkbox = document.getElementById('hpCreateNewHomepage');
    if (!checkbox) return;
    
    // ─── CASE 1: Homepage detected → Existing landing page mode ───
    if (ufDetectedHomepage) {
        // Uncheck "Create New" if it was checked
        if (hpCreateNew) {
            hpCreateNew = false;
            checkbox.checked = false;
            const label = checkbox.closest('.hp-checkbox-label');
            if (label) label.classList.remove('checked');
            
            // Toggle sections
            const newPageSection = document.getElementById('hpNewPageSection');
            const existingPageSection = document.getElementById('hpExistingPageSection');
            if (newPageSection) newPageSection.classList.remove('show');
            if (existingPageSection) existingPageSection.classList.remove('hide');
            
            // Toggle info boxes
            const infoUnchecked = document.getElementById('hpInfoUnchecked');
            const infoChecked = document.getElementById('hpInfoChecked');
            if (infoUnchecked) infoUnchecked.classList.remove('hide');
            if (infoChecked) infoChecked.classList.remove('show');
        }
        
        // Set the existing landing page to the detected homepage
        hpExistingFileName = ufDetectedHomepage;
        
        const existingFileDisplay = document.getElementById('hpExistingFileDisplay');
        const existingFileNameSpan = document.getElementById('hpExistingFileName');
        const existingClearBtn = document.getElementById('hpExistingClearBtn');
        
        if (existingFileNameSpan) existingFileNameSpan.textContent = ufDetectedHomepage + ' (auto-detected)';
        if (existingFileDisplay) existingFileDisplay.classList.add('has-file');
        if (existingClearBtn) existingClearBtn.classList.add('show');
        
        console.log('🔄 Synced to Homepage Config: Existing →', ufDetectedHomepage);
    }
    // ─── CASE 2: No homepage detected → Create New mode ───
    else {
        if (!hpCreateNew) {
            hpCreateNew = true;
            checkbox.checked = true;
            const label = checkbox.closest('.hp-checkbox-label');
            if (label) label.classList.add('checked');
            
            // Toggle sections
            const newPageSection = document.getElementById('hpNewPageSection');
            const existingPageSection = document.getElementById('hpExistingPageSection');
            if (newPageSection) newPageSection.classList.add('show');
            if (existingPageSection) existingPageSection.classList.add('hide');
            
            // Toggle info boxes
            const infoUnchecked = document.getElementById('hpInfoUnchecked');
            const infoChecked = document.getElementById('hpInfoChecked');
            if (infoUnchecked) infoUnchecked.classList.add('hide');
            if (infoChecked) infoChecked.classList.add('show');
        }
        
        // Clear existing file since no homepage was detected
        hpExistingFileName = null;
        const existingFileDisplay = document.getElementById('hpExistingFileDisplay');
        const existingFileNameSpan = document.getElementById('hpExistingFileName');
        const existingClearBtn = document.getElementById('hpExistingClearBtn');
        
        if (existingFileNameSpan) existingFileNameSpan.textContent = 'No file selected (will enhance default homepage)';
        if (existingFileDisplay) existingFileDisplay.classList.remove('has-file');
        if (existingClearBtn) existingClearBtn.classList.remove('show');
        
        console.log('🔄 Synced to Homepage Config: Create New Landing Page');
    }
    
    // ─── Featured page → Target page (for new landing) ───
    if (ufDetectedFeatured) {
        hpTargetFileName = ufDetectedFeatured;
        
        const targetFileDisplay = document.getElementById('hpFileDisplay');
        const targetFileNameSpan = document.getElementById('hpTargetFileName');
        const targetClearBtn = document.getElementById('hpClearBtn');
        
        if (targetFileNameSpan) targetFileNameSpan.textContent = ufDetectedFeatured + ' (auto-detected)';
        if (targetFileDisplay) targetFileDisplay.classList.add('has-file');
        if (targetClearBtn) targetClearBtn.classList.add('show');
        
        console.log('🔄 Synced Target Page →', ufDetectedFeatured);
    } else {
        hpTargetFileName = null;
        
        const targetFileDisplay = document.getElementById('hpFileDisplay');
        const targetFileNameSpan = document.getElementById('hpTargetFileName');
        const targetClearBtn = document.getElementById('hpClearBtn');
        
        if (targetFileNameSpan) targetFileNameSpan.textContent = 'No file selected (will use current homepage)';
        if (targetFileDisplay) targetFileDisplay.classList.remove('has-file');
        if (targetClearBtn) targetClearBtn.classList.remove('show');
        
        console.log('🔄 Synced Target Page → cleared');
    }
    
    // Save and update badge
    if (typeof hpSaveToStorage === 'function') hpSaveToStorage();
    if (typeof hpUpdateBadge === 'function') hpUpdateBadge();
}

// Update badge
function ufUpdateBadge() {
    const badge = document.getElementById('ufBadge');
    const totalBadge = document.getElementById('ufTotalBadge');
    
    const totalFiles = Object.values(ufFileStorage).reduce((sum, arr) => sum + arr.length, 0);
    
    if (badge) {
        if (totalFiles > 0) {
            badge.style.display = 'inline-flex';
            badge.textContent = totalFiles;
        } else {
            badge.style.display = 'none';
        }
    }
    
    if (totalBadge) {
        totalBadge.textContent = totalFiles;
    }
}

// Update character count
function ufUpdateCharCount() {
    const textarea = document.getElementById('ufNotesTextarea');
    const counter = document.getElementById('ufCharCount');
    if (textarea && counter) {
        counter.textContent = `${textarea.value.length} characters`;
        ufSaveNotesToStorage();
    }
}

// Save notes to storage
function ufSaveNotesToStorage() {
    const textarea = document.getElementById('ufNotesTextarea');
    if (textarea) {
        localStorage.setItem('ufNotes', textarea.value);
    }
}

// Load notes from storage
function ufLoadNotesFromStorage() {
    const textarea = document.getElementById('ufNotesTextarea');
    const stored = localStorage.getItem('ufNotes');
    if (textarea && stored) {
        textarea.value = stored;
        ufUpdateCharCount();
    }
}

// Push to Project Prompts
function ufPushToNotes() {
    const projectNotesTextarea = document.getElementById('projectNotesTextarea');
    if (!projectNotesTextarea) return;
    
    // Count totals
    const totalFolders = ufFileStorage.folders.length;
    const totalStandaloneFiles = Object.entries(ufFileStorage).reduce((sum, [cat, arr]) => cat !== 'folders' ? sum + arr.length : sum, 0);
    const totalFolderFiles = ufFileStorage.folders.reduce((sum, f) => sum + (f.fileCount || 0), 0);
    const totalItems = totalFolders + totalStandaloneFiles;
    const notesContent = document.getElementById('ufNotesTextarea')?.value.trim() || '';
    
    if (totalItems === 0 && !notesContent) {
        showToast('⚠️ No files, folders, or notes to push', 'warning');
        return;
    }
    
    let promptContent = `\n\n📁 PROJECT FILES OVERVIEW\n`;
    promptContent += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
    
    // Summary line
    const summaryParts = [];
    if (totalFolders > 0) summaryParts.push(`${totalFolders} folder(s) with ${totalFolderFiles} files`);
    if (totalStandaloneFiles > 0) summaryParts.push(`${totalStandaloneFiles} standalone file(s)`);
    if (summaryParts.length > 0) {
        promptContent += `**${summaryParts.join(' + ')}**\n\n`;
    }
    
    // ═══════════════════════════════════════════
    // FOLDERS — Full tree diagram (all levels)
    // ═══════════════════════════════════════════
    if (totalFolders > 0) {
        promptContent += `📂 PROJECT ROUTES (FOLDER STRUCTURE)\n`;
        promptContent += `────────────────────────────────────\n\n`;
        
        ufFileStorage.folders.forEach(folder => {
            promptContent += ufBuildFolderTreeText(folder.name, folder.children || []);
            promptContent += `\n\n`;
        });
    }
    
    // ═══════════════════════════════════════════
    // STANDALONE FILES — Listed by category
    // ═══════════════════════════════════════════
    if (totalStandaloneFiles > 0) {
        promptContent += `📄 STANDALONE FILES\n`;
        promptContent += `────────────────────────────────────\n\n`;
        
        Object.entries(ufCategoryConfig).forEach(([category, config]) => {
            const files = ufFileStorage[category];
            if (files && files.length > 0) {
                promptContent += `**${config.title} Files (${files.length}):**\n`;
                files.forEach((file, index) => {
                    const ext = file.name.split('.').pop().toLowerCase();
                    let icon = '📄';
                    if (['jpg','jpeg','png','gif','svg','webp','ico'].includes(ext)) icon = '🖼️';
                    else if (['js','ts','jsx','tsx'].includes(ext)) icon = '📜';
                    else if (['php'].includes(ext)) icon = '🐘';
                    else if (['css','scss','sass','less'].includes(ext)) icon = '🎨';
                    else if (['html','htm'].includes(ext)) icon = '🌐';
                    else if (['json','xml','yaml','yml'].includes(ext)) icon = '📋';
                    else if (['md','txt','log'].includes(ext)) icon = '📝';
                    promptContent += `  ${icon} ${file.name}\n`;
                });
                promptContent += `\n`;
            }
        });
    }
    
    // Page detection info
    if (ufDetectedHomepage) {
        promptContent += `**🏠 Homepage:** ${ufDetectedHomepage}\n`;
    }
    if (ufDetectedFeatured) {
        promptContent += `**⭐ Featured Page:** ${ufDetectedFeatured}\n`;
    }
    if (ufDetectedDoc) {
        promptContent += `**📄 Documentation File:** ${ufDetectedDoc}\n`;
    }
    
    if (totalItems > 0) {
        promptContent += `\n**NOTE:** These files and folders represent the current project structure. Please consider them when making changes.\n`;
    }
    
    // Add notes content
    if (notesContent) {
        if (totalItems === 0) {
            promptContent = `\n\n📁 PROJECT NOTES\n`;
            promptContent += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
        } else {
            promptContent += `\n**Additional Project Instructions:**\n`;
        }
        promptContent += `${notesContent}\n`;
    }
    
    // Append to Project Prompts
    const currentContent = projectNotesTextarea.value;
    projectNotesTextarea.value = currentContent + promptContent;
    
    // Trigger auto-resize
    if (typeof autoResizeTextarea === 'function') {
        autoResizeTextarea(projectNotesTextarea);
    }
    
    // Save
    localStorage.setItem('projectPrompts', projectNotesTextarea.value);
    
    showToast('📁 Project structure pushed to Project Prompts', 'success');
}

// ═══════════════════════════════════════════════════════════════════
// 🚀 PUSH TO DEVELOPMENT DASHBOARD (File Upload → Backend/Pages/Frontend)
// ═══════════════════════════════════════════════════════════════════

// Classify a folder name into backend / page / frontend
function ufClassifyFolder(folderName) {
    const lower = (folderName || '').toLowerCase();

    const backendKw = [
        'api', 'server', 'backend', 'config', 'database', 'db', 'migrations',
        'models', 'controllers', 'routes', 'middleware', 'services', 'helpers',
        'utils', 'lib', 'core', 'admin', 'auth', 'cron', 'jobs', 'queue',
        'storage', 'logs', 'vendor', 'node_modules', 'php', 'laravel',
        'express', 'nest', 'django', 'flask', 'spring', 'includes', 'classes'
    ];

    const frontendKw = [
        'css', 'styles', 'scss', 'sass', 'less', 'js', 'javascript', 'scripts',
        'assets', 'images', 'img', 'icons', 'fonts', 'media', 'static',
        'public', 'dist', 'build', 'components', 'ui', 'frontend', 'views',
        'layouts', 'partials', 'templates', 'theme', 'themes', 'resources',
        'src', 'app'
    ];

    const pageKw = [
        'pages', 'page', 'html', 'views', 'screens', 'sections'
    ];

    for (const kw of backendKw)  { if (lower === kw || lower.includes(kw)) return 'backend'; }
    for (const kw of pageKw)     { if (lower === kw || lower.includes(kw)) return 'page'; }
    for (const kw of frontendKw) { if (lower === kw || lower.includes(kw)) return 'frontend'; }

    return 'page'; // default folders go to Pages
}

// Push uploaded files/folders into the Project Folder Template as interactive tree
function ufPushToDashboard() {
    // Check folder template functions exist
    if (typeof ftFolderStore === 'undefined' || typeof ftAddFolderCard !== 'function') {
        showToast('⚠️ Project Folder Template not found', 'error');
        return;
    }

    const totalFolders = ufFileStorage.folders.length;
    const totalStandaloneFiles = Object.entries(ufFileStorage).reduce(
        (sum, [cat, arr]) => cat !== 'folders' ? sum + arr.length : sum, 0
    );

    if (totalFolders === 0 && totalStandaloneFiles === 0) {
        showToast('⚠️ No files or folders to push', 'warning');
        return;
    }

    // Determine project name from root folder or first folder
    let projectName = 'Uploaded Project';
    if (ufRootFolder && ufRootFolder.name) {
        projectName = ufRootFolder.name;
    } else if (totalFolders > 0) {
        projectName = ufFileStorage.folders[0].name;
    }
    const folderName = '📁 ' + projectName;

    // ── Build unified treeData from all uploaded content ──
    const treeData = [];

    // 1. Add folders (already have correct {name, type, children} structure)
    ufFileStorage.folders.forEach(folder => {
        treeData.push({
            name: folder.name,
            type: 'folder',
            description: (folder.fileCount ? folder.fileCount + ' files' : '') +
                         (folder.folderCount ? (folder.fileCount ? ' · ' : '') + folder.folderCount + ' subfolders' : ''),
            children: ufNormalizeChildren(folder.children || [])
        });
    });

    // 2. Add standalone files grouped by category as folders
    const categories = [
        { key: 'php',        label: 'PHP',        desc: 'Backend scripts' },
        { key: 'html',       label: 'HTML',       desc: 'Page templates' },
        { key: 'css',        label: 'CSS',        desc: 'Stylesheets' },
        { key: 'javascript', label: 'JavaScript', desc: 'Scripts' },
        { key: 'images',     label: 'Images',     desc: 'Assets' },
        { key: 'other',      label: 'Other',      desc: 'Miscellaneous files' }
    ];

    let standaloneFiles = [];
    categories.forEach(cat => {
        const files = ufFileStorage[cat.key];
        if (!files || files.length === 0) return;
        files.forEach(f => {
            standaloneFiles.push({
                name: f.name,
                type: 'file',
                description: cat.label,
                children: []
            });
        });
    });

    // If there are standalone files alongside folders, group them under a "Files" folder
    if (standaloneFiles.length > 0 && treeData.length > 0) {
        // Sort standalone files alphabetically
        standaloneFiles.sort((a, b) => a.name.localeCompare(b.name));
        treeData.push({
            name: 'Root Files',
            type: 'folder',
            description: standaloneFiles.length + ' standalone files',
            children: standaloneFiles
        });
    } else if (standaloneFiles.length > 0) {
        // Only standalone files, no folders — add them directly at root
        standaloneFiles.sort((a, b) => a.name.localeCompare(b.name));
        treeData.push(...standaloneFiles);
    }

    if (treeData.length === 0) {
        showToast('⚠️ No file structure to push', 'warning');
        return;
    }

    // ── Store in ftFolderStore and render card ──
    const treeText = buildTreeDiagram(folderName, treeData);
    const sid = ftGetSafeId(folderName);

    // If already exists, update it
    if (ftFolderStore.has(folderName)) {
        ftClearNodeMapForSid(sid);
    }

    // Get notes from the Project File Uploader textarea
    const ufNotes = (document.getElementById('ufNotesTextarea')?.value || '').trim();

    ftFolderStore.set(folderName, {
        path: projectName,
        treeText: treeText,
        treeData: treeData,
        notes: ufNotes,
        addedAt: Date.now(),
        _dirty: false
    });
    ftIdToName.set(sid, folderName);
    knownFolders.set(folderName, { addedAt: Date.now(), path: projectName });

    const existingCard = document.getElementById('ftCard_' + sid);
    if (existingCard) {
        existingCard.outerHTML = ftRenderCard(folderName);
        requestAnimationFrame(() => ftInitAutoResize(sid));
    } else {
        ftAddFolderCard(folderName);
    }

    // Sync the notes into the card's textarea
    const notesEl = document.getElementById('ftNotes_' + sid);
    if (notesEl && ufNotes) notesEl.value = ufNotes;
    ftUpdateContainer();

    // Count stats
    let folderCount = 0, fileCount = 0;
    function countNodes(items) {
        if (!items) return;
        items.forEach(item => {
            if (item.type === 'folder') { folderCount++; countNodes(item.children); }
            else { fileCount++; }
        });
    }
    countNodes(treeData);

    showToast(`🌳 Project tree pushed: ${folderCount} folders, ${fileCount} files`, 'success');
}

// Normalize children to ensure consistent {name, type, children, description} structure
function ufNormalizeChildren(children) {
    if (!children || !Array.isArray(children)) return [];
    return children.map(child => {
        const isFolder = child.type === 'folder' || (child.children && child.children.length > 0);
        return {
            name: child.name || 'unnamed',
            type: isFolder ? 'folder' : 'file',
            description: child.description || '',
            children: isFolder ? ufNormalizeChildren(child.children || []) : []
        };
    });
}

// Build a full ASCII tree diagram for a folder and ALL its descendants (unlimited depth)
function ufBuildFolderTreeText(folderName, children) {
    let lines = [`📁 ${folderName}/`];
    
    function renderNode(items, prefix) {
        if (!items || !Array.isArray(items) || items.length === 0) return;
        
        // Sort: folders first, then files
        const sorted = [...items].sort((a, b) => {
            const aIsFolder = a.type === 'folder' || a.children;
            const bIsFolder = b.type === 'folder' || b.children;
            if (aIsFolder === bIsFolder) return (a.name || '').localeCompare(b.name || '');
            return aIsFolder ? -1 : 1;
        });
        
        for (let i = 0; i < sorted.length; i++) {
            const item = sorted[i];
            const isLast = (i === sorted.length - 1);
            const connector = isLast ? '└── ' : '├── ';
            const childPrefix = isLast ? '    ' : '│   ';
            
            const isFolder = item.type === 'folder' || item.children;
            
            if (isFolder) {
                lines.push(prefix + connector + '📂 ' + item.name + '/');
                if (item.children && Array.isArray(item.children) && item.children.length > 0) {
                    renderNode(item.children, prefix + childPrefix);
                }
            } else {
                // File — pick icon based on extension
                const ext = (item.name || '').split('.').pop().toLowerCase();
                let icon = '📄';
                if (['jpg','jpeg','png','gif','svg','webp','ico'].includes(ext)) icon = '🖼️';
                else if (['js','ts','jsx','tsx'].includes(ext)) icon = '📜';
                else if (['php'].includes(ext)) icon = '🐘';
                else if (['css','scss','sass','less'].includes(ext)) icon = '🎨';
                else if (['html','htm'].includes(ext)) icon = '🌐';
                else if (['json','xml','yaml','yml'].includes(ext)) icon = '📋';
                else if (['md','txt','log'].includes(ext)) icon = '📝';
                else if (['py'].includes(ext)) icon = '🐍';
                else if (['sql','db','sqlite'].includes(ext)) icon = '🗃️';
                else if (['zip','rar','tar','gz'].includes(ext)) icon = '📦';
                else if (['env','gitignore','htaccess'].includes(ext) || (item.name || '').startsWith('.')) icon = '⚙️';
                
                lines.push(prefix + connector + icon + ' ' + item.name);
            }
        }
    }
    
    renderNode(children, '');
    return lines.join('\n');
}

// Clear all files
function ufClearAll() {
    Object.keys(ufFileStorage).forEach(key => ufFileStorage[key] = []);
    ufDetectedHomepage = '';
    ufDetectedFeatured = '';
    ufDetectedDoc = '';
    
    // Clear root folder / project routes
    ufRootFolder = null;
    ufUpdateRootDisplay();
    localStorage.removeItem('ufRootFolder');
    
    // Reset project routes display
    const ufDropDiv = document.getElementById('ufRootDrop');
    const ufSelectedDiv = document.getElementById('ufRootSelected');
    if (ufDropDiv) ufDropDiv.style.display = 'flex';
    if (ufSelectedDiv) ufSelectedDiv.style.display = 'none';
    
    // Reset UI
    document.getElementById('ufFileInput').value = '';
    document.getElementById('ufCategories').classList.remove('show');
    
    // Reset dropdowns
    const homepageSelect = document.getElementById('ufHomepageSelect');
    const featuredSelect = document.getElementById('ufFeaturedSelect');
    if (homepageSelect) homepageSelect.value = '';
    if (featuredSelect) {
        featuredSelect.value = '';
        featuredSelect.disabled = true;
    }
    
    // Reset doc dropdown
    const docSelect = document.getElementById('ufDocSelect');
    if (docSelect) {
        docSelect.value = '';
        docSelect.innerHTML = '<option value="">-- No documentation available --</option>';
    }
    
    // Reset badges
    document.getElementById('ufHomepageBadge').textContent = 'Not Set';
    document.getElementById('ufHomepageBadge').className = 'uf-page-badge not-set';
    document.getElementById('ufFeaturedBadge').textContent = 'Not Set';
    document.getElementById('ufFeaturedBadge').className = 'uf-page-badge not-set';
    const docBadge = document.getElementById('ufDocBadge');
    if (docBadge) {
        docBadge.textContent = 'Not Set';
        docBadge.className = 'uf-page-badge not-set';
    }
    
    // Clear notes
    const notesTextarea = document.getElementById('ufNotesTextarea');
    if (notesTextarea) {
        notesTextarea.value = '';
        ufUpdateCharCount();
    }
    
    ufDisplayCategories();
    ufUpdateBadge();
    
    // Clear storage
    localStorage.removeItem('ufFileStorage');
    localStorage.removeItem('ufDetectedHomepage');
    localStorage.removeItem('ufDetectedFeatured');
    localStorage.removeItem('ufDetectedDoc');
    localStorage.removeItem('ufNotes');
    
    showToast('🗑️ All files cleared', 'info');
}

// Confirm reset
async function confirmResetFileUpload() {
    const totalFiles = Object.values(ufFileStorage).reduce((sum, arr) => sum + arr.length, 0);
    
    if (totalFiles === 0) {
        showToast('⚠️ No files to clear', 'warning');
        return;
    }
    
    if (typeof deConfirm === 'function') {
        const confirmed = await deConfirm({
            title: 'Clear All Files',
            subtitle: 'Project Files Upload',
            message: `Are you sure you want to clear all ${totalFiles} uploaded file(s)?`,
            warning: 'This action cannot be undone.',
            confirmText: 'Clear All',
            icon: 'fa-cloud-upload-alt'
        });
        if (confirmed) {
            ufClearAll();
        }
    } else {
        if (confirm(`Clear all ${totalFiles} files?`)) {
            ufClearAll();
        }
    }
}

// Save to storage
function ufSaveToStorage() {
    // Store file/folder data (can't store File objects)
    const storageData = {};
    Object.entries(ufFileStorage).forEach(([category, items]) => {
        storageData[category] = items.map(f => ({
            name: f.name,
            size: f.size,
            type: f.type,
            fileCount: f.fileCount,
            folderCount: f.folderCount,
            children: f.children,
            _serverPath: f._serverPath || ''
        }));
    });
    localStorage.setItem('ufFileStorage', JSON.stringify(storageData));
    localStorage.setItem('ufDetectedHomepage', ufDetectedHomepage);
    localStorage.setItem('ufDetectedFeatured', ufDetectedFeatured);
    localStorage.setItem('ufDetectedDoc', ufDetectedDoc);
}

// Load from storage
function ufLoadFromStorage() {
    try {
        // Load root folder
        ufLoadRootFromStorage();
        
        const stored = localStorage.getItem('ufFileStorage');
        if (stored) {
            const data = JSON.parse(stored);
            // Restore as pseudo-file objects (for display only)
            Object.entries(data).forEach(([category, files]) => {
                if (ufFileStorage[category]) {
                    ufFileStorage[category] = files.map(f => ({ 
                        name: f.name, 
                        size: f.size,
                        fileCount: f.fileCount,
                        folderCount: f.folderCount,
                        children: f.children,
                        _serverPath: f._serverPath || '',
                        type: f.type || (f.children ? 'folder' : 'file')
                    }));
                }
            });
            document.getElementById('ufCategories')?.classList.add('show');
        }
        
        ufDetectedHomepage = localStorage.getItem('ufDetectedHomepage') || '';
        ufDetectedFeatured = localStorage.getItem('ufDetectedFeatured') || '';
        ufDetectedDoc = localStorage.getItem('ufDetectedDoc') || '';
        
        // Restore page detection UI
        if (ufDetectedHomepage) {
            const homepageSelect = document.getElementById('ufHomepageSelect');
            const homepageBadge = document.getElementById('ufHomepageBadge');
            if (homepageSelect) homepageSelect.value = ufDetectedHomepage;
            if (homepageBadge) {
                homepageBadge.textContent = 'Set';
                homepageBadge.className = 'uf-page-badge set';
            }
            const featuredSelect = document.getElementById('ufFeaturedSelect');
            if (featuredSelect) featuredSelect.disabled = false;
        }
        if (ufDetectedFeatured) {
            const featuredSelect = document.getElementById('ufFeaturedSelect');
            const featuredBadge = document.getElementById('ufFeaturedBadge');
            if (featuredSelect) featuredSelect.value = ufDetectedFeatured;
            if (featuredBadge) {
                featuredBadge.textContent = 'Set';
                featuredBadge.className = 'uf-page-badge set';
            }
        }
        if (ufDetectedDoc) {
            const docSelect = document.getElementById('ufDocSelect');
            const docBadge = document.getElementById('ufDocBadge');
            if (docSelect) docSelect.value = ufDetectedDoc;
            if (docBadge) {
                docBadge.textContent = 'Set';
                docBadge.className = 'uf-page-badge set';
            }
        }
        
        // Load notes
        ufLoadNotesFromStorage();
        
        // Auto-detect logo if not already set (short delay to ensure branding state loads first)
        setTimeout(() => {
            ufAutoDetectLogo();
        }, 200);
        
        // Sync documentation to Documentation Integration tool
        setTimeout(() => {
            if (ufDetectedDoc) ufSyncToDocumentationTool();
        }, 500);
        
        // Re-render the file/folder tree UI and update badge after restoring data
        ufDisplayCategories();
        ufUpdateBadge();
    } catch (e) {
        console.error('Error loading file upload state:', e);
    }
}

// Reset function for deResetAll
function ufResetAll(skipToast = false) {
    ufClearAll();
    if (!skipToast) {
        showToast('📁 File upload cleared', 'info');
    }
}

// Initialize on load
document.addEventListener('DOMContentLoaded', ufInit);

// ═══════════════════════════════════════════════════════════════════
// 🚫 FILE EXCLUSION MANAGER
// ═══════════════════════════════════════════════════════════════════

// File Exclusion Manager state
let exExcludedFiles = [];

// Initialize File Exclusion Manager
function exInit() {
    exLoadFromStorage();
    exUpdateUI();
    
    // Setup file picker
    const filePicker = document.getElementById('exFilePicker');
    const fileInput = document.getElementById('exFileInput');
    
    if (filePicker && fileInput) {
        filePicker.addEventListener('click', () => {
            fileInput.click();
        });
        
        fileInput.addEventListener('change', (e) => {
            exHandleFiles(e.target.files);
        });
    }
}

// Handle file selection
function exHandleFiles(files) {
    const htmlPhpFiles = Array.from(files).filter(file =>
        file.name.endsWith('.html') || file.name.endsWith('.php') || file.name.endsWith('.htm')
    );
    
    if (htmlPhpFiles.length === 0) {
        showToast('⚠️ Please select HTML or PHP files only', 'warning');
        return;
    }
    
    htmlPhpFiles.forEach(file => {
        // Check if file already excluded
        const exists = exExcludedFiles.includes(file.name);
        if (!exists) {
            exExcludedFiles.push(file.name);
        }
    });
    
    exUpdateFilesList();
    exSaveToStorage();
    exUpdateBadge();
    showToast(`✅ ${htmlPhpFiles.length} file(s) added to exclusion list`, 'success');
}

// Update excluded files list display
function exUpdateFilesList() {
    const container = document.getElementById('exFilesContainer');
    const list = document.getElementById('exFilesList');
    
    if (exExcludedFiles.length > 0) {
        list.classList.add('show');
        
        container.innerHTML = exExcludedFiles.map((fileName, index) => {
            return `
                <div class="ex-file-item">
                    <div class="ex-file-header">
                        <div class="ex-file-name">
                            <i class="fas fa-file-code"></i>
                            <span>${fileName}</span>
                            <span class="ex-status both-excluded"><i class="fas fa-ban"></i> Fully Excluded</span>
                        </div>
                        <button class="ex-file-remove" onclick="exRemoveFile(${index})">
                            <i class="fas fa-times"></i>
                        </button>
                    </div>
                </div>
            `;
        }).join('');
    } else {
        list.classList.remove('show');
    }
}

// Remove excluded file
function exRemoveFile(index) {
    const fileName = exExcludedFiles[index];
    exExcludedFiles.splice(index, 1);
    exUpdateFilesList();
    exSaveToStorage();
    exUpdateBadge();
    showToast(`🗑️ ${fileName} removed from exclusion list`, 'info');
}

// Update badge
function exUpdateBadge() {
    const badge = document.getElementById('exBadge');
    if (badge) {
        if (exExcludedFiles.length > 0) {
            badge.style.display = 'inline-flex';
            badge.textContent = `${exExcludedFiles.length} file${exExcludedFiles.length > 1 ? 's' : ''}`;
        } else {
            badge.style.display = 'none';
        }
    }
}

// Update UI from state
function exUpdateUI() {
    exUpdateFilesList();
    exLoadNotesFromStorage();
    exUpdateBadge();
}

// Push to Project Prompts
function exPushToNotes() {
    const projectNotesTextarea = document.getElementById('projectNotesTextarea');
    if (!projectNotesTextarea) return;
    
    const notesContent = document.getElementById('exNotesTextarea')?.value.trim() || '';
    
    // Build prompt content
    let promptContent = '';
    
    if (exExcludedFiles.length > 0) {
        promptContent += `\n\n🚫 EXCLUDED FILES - DO NOT MODIFY\n`;
        promptContent += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
        promptContent += `**⚠️ CRITICAL: The following files are COMPLETELY EXCLUDED from this request.**\n\n`;
        promptContent += `**DO NOT touch, modify, edit, or change ANY part of these files:**\n`;
        promptContent += `- No HTML changes\n`;
        promptContent += `- No CSS/styling changes\n`;
        promptContent += `- No JavaScript changes\n`;
        promptContent += `- No functionality changes\n`;
        promptContent += `- No structure changes\n\n`;
        
        promptContent += `**EXCLUDED FILES (${exExcludedFiles.length}):**\n`;
        exExcludedFiles.forEach((fileName, index) => {
            promptContent += `${index + 1}. ⛔ ${fileName}\n`;
        });
        
        promptContent += `\n**IMPORTANT:** These files must remain EXACTLY as they are. Skip them entirely in your modifications.\n`;
    }
    
    // Additional notes
    if (notesContent) {
        if (!promptContent) {
            promptContent += `\n\n🚫 FILE EXCLUSION NOTES\n`;
            promptContent += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
        } else {
            promptContent += `\nAdditional Exclusion Instructions:\n`;
        }
        promptContent += `${notesContent}\n`;
    }
    
    if (!promptContent) {
        showToast('⚠️ No exclusions or notes to push', 'warning');
        return;
    }
    
    // Append to Project Prompts
    const currentContent = projectNotesTextarea.value;
    projectNotesTextarea.value = currentContent + promptContent;
    
    // Trigger auto-resize
    if (typeof autoResizeTextarea === 'function') {
        autoResizeTextarea(projectNotesTextarea);
    }
    
    // Save
    localStorage.setItem('projectPrompts', projectNotesTextarea.value);
    
    showToast('🚫 File exclusions pushed to Project Prompts', 'success');
}

// Character count
function exUpdateCharCount() {
    const textarea = document.getElementById('exNotesTextarea');
    const charCount = document.getElementById('exCharCount');
    if (textarea && charCount) {
        charCount.textContent = `${textarea.value.length} characters`;
        exSaveNotesToStorage();
    }
}

// Save notes to storage
function exSaveNotesToStorage() {
    const textarea = document.getElementById('exNotesTextarea');
    if (textarea) {
        localStorage.setItem('exNotes', textarea.value);
    }
}

// Load notes from storage
function exLoadNotesFromStorage() {
    const savedNotes = localStorage.getItem('exNotes');
    const textarea = document.getElementById('exNotesTextarea');
    if (savedNotes && textarea) {
        textarea.value = savedNotes;
        exUpdateCharCount();
    }
}

// Save to localStorage
function exSaveToStorage() {
    try {
        localStorage.setItem('exExcludedFiles', JSON.stringify(exExcludedFiles));
    } catch (e) {
        console.warn('Failed to save exclusions:', e);
    }
}

// Load from localStorage
function exLoadFromStorage() {
    const saved = localStorage.getItem('exExcludedFiles');
    if (saved) {
        try {
            exExcludedFiles = JSON.parse(saved);
        } catch (e) {
            console.warn('Failed to load exclusions:', e);
            exExcludedFiles = [];
        }
    }
}

// Reset all
function exResetAll(skipToast = false) {
    exExcludedFiles = [];
    
    // Clear UI
    exUpdateFilesList();
    
    const fileInput = document.getElementById('exFileInput');
    if (fileInput) fileInput.value = '';
    
    // Clear notes
    const notesTextarea = document.getElementById('exNotesTextarea');
    if (notesTextarea) {
        notesTextarea.value = '';
        exUpdateCharCount();
    }
    
    // Clear storage
    localStorage.removeItem('exExcludedFiles');
    localStorage.removeItem('exNotes');
    
    exUpdateBadge();
    
    if (!skipToast) {
        showToast('🚫 All exclusions cleared', 'info');
    }
}

// Confirm reset
async function confirmResetExclusions() {
    if (exExcludedFiles.length === 0) {
        showToast('⚠️ No files to clear', 'warning');
        return;
    }
    
    if (typeof deConfirm === 'function') {
        const confirmed = await deConfirm({
            title: 'Clear All Exclusions',
            subtitle: 'Design Enhancer',
            message: `Are you sure you want to remove all ${exExcludedFiles.length} excluded file(s)?`,
            warning: 'This action cannot be undone.',
            confirmText: 'Clear All',
            icon: 'fa-ban'
        });
        if (confirmed) {
            exResetAll();
        }
    } else {
        if (confirm(`Clear all ${exExcludedFiles.length} exclusions?`)) {
            exResetAll();
        }
    }
}

// Initialize on load
document.addEventListener('DOMContentLoaded', exInit);
</script>

<!-- ═══════════════════════════════════════════════════════════════════
     📚 DOCUMENTATION INTEGRATION JAVASCRIPT
     ═══════════════════════════════════════════════════════════════════ -->
<script>
// Documentation Integration state
let diFileContent = null;
let diFileName = null;
let diIntegrationMode = 'ai-decision';
let diEnableDoc = false;
let diPageName = 'documentation';
let diInjectionFiles = [];

// Initialize Documentation Integration
function diInit() {
    diLoadFromStorage();
    diUpdateUI();
}

// Toggle documentation checkbox
function diToggleDocCheckbox(event) {
    const checkbox = document.getElementById('diEnableDoc');
    
    // If click was NOT on the checkbox itself, toggle it manually
    if (event.target.tagName !== 'INPUT') {
        event.preventDefault();
        checkbox.checked = !checkbox.checked;
    }
    
    // Update state
    diEnableDoc = checkbox.checked;
    
    const label = checkbox.closest('.di-checkbox-item');
    label.classList.toggle('checked', checkbox.checked);
    
    const uploadSection = document.getElementById('diUploadSection');
    if (checkbox.checked) {
        uploadSection.classList.add('show');
    } else {
        uploadSection.classList.remove('show');
        diRemoveFile();
    }
    
    diSaveToStorage();
    diUpdateBadge();
}

// Handle file upload
function diHandleFile(event) {
    const file = event.target.files[0];
    if (!file) return;
    
    diFileName = file.name;
    const fileSize = formatFileSize(file.size);
    
    // Display file info (name and size only - no content preview)
    document.getElementById('diFileName').textContent = file.name;
    document.getElementById('diFileSize').textContent = fileSize;
    
    // Read file content (stored but not displayed)
    const reader = new FileReader();
    reader.onload = function(e) {
        diFileContent = e.target.result;
        
        // Show file info display
        document.getElementById('diFileInfo').classList.add('show');
        
        // Show integration mode section
        document.getElementById('diModeSection').classList.add('show');
        
        // Initialize mode selection UI
        diSelectMode(diIntegrationMode);
        
        diSaveToStorage();
        diUpdateBadge();
        diSyncToUploader();
        showToast('📄 Documentation file loaded!', 'success');
    };
    
    reader.onerror = function() {
        showToast('❌ Error reading file', 'error');
    };
    
    reader.readAsText(file);
}

// Remove file
function diRemoveFile() {
    diFileContent = null;
    diFileName = null;
    
    // Clear file input
    document.getElementById('diFileInput').value = '';
    
    // Hide file info display
    document.getElementById('diFileInfo').classList.remove('show');
    
    // Hide integration mode section
    document.getElementById('diModeSection').classList.remove('show');
    
    diSaveToStorage();
    diUpdateBadge();
    diSyncToUploader();
}

// Select integration mode (called from radio onchange)
function diSelectMode(mode) {
    diIntegrationMode = mode;
    
    // Update UI
    document.querySelectorAll('.di-mode-option').forEach(option => {
        option.classList.remove('checked');
    });
    
    const selectedOption = document.querySelector(`.di-mode-option[data-mode="${mode}"]`);
    if (selectedOption) {
        selectedOption.classList.add('checked');
    }
    
    // Show/hide page name input for "create" mode
    const createPageInput = document.getElementById('diCreatePageInput');
    if (createPageInput) {
        if (mode === 'create') {
            createPageInput.classList.add('show');
        } else {
            createPageInput.classList.remove('show');
        }
    }
    
    // Show/hide injection files picker for "injection" mode
    const injectionFiles = document.getElementById('diInjectionFiles');
    if (injectionFiles) {
        if (mode === 'injection') {
            injectionFiles.classList.add('show');
        } else {
            injectionFiles.classList.remove('show');
        }
    }
    
    localStorage.setItem('diIntegrationMode', mode);
}

// Select integration mode by clicking on label content
function diSelectModeByClick(mode) {
    const radio = document.querySelector(`input[name="di_mode"][value="${mode}"]`);
    if (radio) {
        radio.checked = true;
        diSelectMode(mode);
    }
}

// Save page name for create mode
function diSavePageName() {
    const input = document.getElementById('diPageName');
    if (input) {
        diPageName = input.value.trim() || 'documentation';
        localStorage.setItem('diPageName', diPageName);
    }
}

// Handle injection files selection
function diHandleInjectionFiles(event) {
    const files = event.target.files;
    if (!files || files.length === 0) return;
    
    // Add new files to the list
    for (let i = 0; i < files.length; i++) {
        const fileName = files[i].name;
        // Avoid duplicates
        if (!diInjectionFiles.includes(fileName)) {
            diInjectionFiles.push(fileName);
        }
    }
    
    // Update display
    diUpdateInjectionList();
    
    // Save to storage
    localStorage.setItem('diInjectionFiles', JSON.stringify(diInjectionFiles));
    
    // Clear input for re-selection
    event.target.value = '';
    
    diUpdateBadge();
    showToast(`📂 ${files.length} file(s) selected for injection`, 'success');
}

// Update injection files list display
function diUpdateInjectionList() {
    const listContainer = document.getElementById('diInjectionList');
    if (!listContainer) return;
    
    if (diInjectionFiles.length === 0) {
        listContainer.innerHTML = '';
        return;
    }
    
    listContainer.innerHTML = diInjectionFiles.map((fileName, index) => `
        <div class="di-injection-file-item">
            <div class="di-injection-file-name">
                <i class="fas fa-file-code"></i>
                <span>${fileName}</span>
            </div>
            <button type="button" class="di-injection-file-remove" onclick="diRemoveInjectionFile(${index})" title="Remove file">
                <i class="fas fa-times"></i>
            </button>
        </div>
    `).join('');
}

// Remove injection file
function diRemoveInjectionFile(index) {
    diInjectionFiles.splice(index, 1);
    diUpdateInjectionList();
    localStorage.setItem('diInjectionFiles', JSON.stringify(diInjectionFiles));
    diUpdateBadge();
}

// Update badge
function diUpdateBadge() {
    const badge = document.getElementById('diBadge');
    if (badge) {
        const hasDoc = diEnableDoc && diFileContent;
        
        if (hasDoc) {
            badge.textContent = 'Doc';
            badge.style.display = 'flex';
        } else {
            badge.style.display = 'none';
        }
    }
}

// Update UI from state
function diUpdateUI() {
    // Documentation checkbox
    const docCheckbox = document.getElementById('diEnableDoc');
    if (docCheckbox) {
        docCheckbox.checked = diEnableDoc;
        const docLabel = docCheckbox.closest('.di-checkbox-item');
        if (docLabel) docLabel.classList.toggle('checked', diEnableDoc);
    }
    
    // Upload section visibility
    const uploadSection = document.getElementById('diUploadSection');
    if (uploadSection) {
        uploadSection.classList.toggle('show', diEnableDoc);
    }
    
    // File info display
    if (diFileName && diFileContent) {
        const fnEl = document.getElementById('diFileName');
        if (fnEl) fnEl.textContent = diFileName;
        const fsEl = document.getElementById('diFileSize');
        if (fsEl && typeof formatFileSize === 'function') fsEl.textContent = formatFileSize(new Blob([diFileContent]).size);
        const fiEl = document.getElementById('diFileInfo');
        if (fiEl) fiEl.classList.add('show');
        const msEl = document.getElementById('diModeSection');
        if (msEl) msEl.classList.add('show');
    } else {
        const fnEl = document.getElementById('diFileName');
        if (fnEl) fnEl.textContent = '';
        const fsEl = document.getElementById('diFileSize');
        if (fsEl) fsEl.textContent = '';
        const fiEl = document.getElementById('diFileInfo');
        if (fiEl) fiEl.classList.remove('show');
        const msEl = document.getElementById('diModeSection');
        if (msEl) msEl.classList.remove('show');
        const cpEl = document.getElementById('diCreatePageInput');
        if (cpEl) cpEl.classList.remove('show');
        const ijEl = document.getElementById('diInjectionFiles');
        if (ijEl) ijEl.classList.remove('show');
    }
    
    // Mode selection
    diSelectMode(diIntegrationMode);
    
    // Page name input
    const pageNameInput = document.getElementById('diPageName');
    if (pageNameInput) {
        pageNameInput.value = diPageName || 'documentation';
    }
    
    // Injection files list
    diUpdateInjectionList();
    
    // Notes textarea (prefer current state, fallback to localStorage)
    const _diNotesTA = document.getElementById('diNotesTextarea');
    if (_diNotesTA) {
        const savedNotes = localStorage.getItem('diNotes');
        if (savedNotes !== null) {
            _diNotesTA.value = savedNotes;
        }
        if (typeof diUpdateCharCount === 'function') diUpdateCharCount();
    }
    
    // Update badge
    diUpdateBadge();
}

// Push to Project Prompts
function diPushToNotes() {
    const projectNotesTextarea = document.getElementById('projectNotesTextarea');
    if (!projectNotesTextarea) return;
    
    const notesContent = document.getElementById('diNotesTextarea')?.value.trim() || '';
    
    // Build prompt content
    let promptContent = '';
    
    // Documentation Integration
    if (diEnableDoc && diFileContent && diFileName) {
        const modeNames = {
            'create': 'Create New Pages',
            'injection': 'Injection',
            'integration': 'Integration (Smart Merge)',
            'ai-decision': 'AI Decision (Recommended)'
        };
        
        promptContent += `\n\n📚 DOCUMENTATION INTEGRATION\n`;
        promptContent += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
        promptContent += `• File: ${diFileName}\n`;
        promptContent += `• Mode: ${modeNames[diIntegrationMode] || diIntegrationMode}\n`;
        
        if (diIntegrationMode === 'create') {
            // Get page name (default to 'documentation')
            const pageName = diPageName || 'documentation';
            promptContent += `• Page Name: ${pageName}\n\n`;
            promptContent += `INSTRUCTIONS: Create a new page named "${pageName}" based on the documentation file. Build the page from scratch with proper structure, styling, and content.\n`;
        } else if (diIntegrationMode === 'injection') {
            // Include injection files list
            if (diInjectionFiles.length > 0) {
                promptContent += `• Target Files for Injection:\n`;
                diInjectionFiles.forEach((file, index) => {
                    promptContent += `  ${index + 1}. ${file}\n`;
                });
            }
            promptContent += `\nINSTRUCTIONS: Inject the documentation content into the specified target files. Integrate the content naturally within the existing file structure.\n`;
        } else if (diIntegrationMode === 'integration') {
            promptContent += `\nINSTRUCTIONS: Integrate missing documentation content into existing pages AND create any missing pages that should exist. Smart merge approach - don't duplicate existing content.\n`;
        } else {
            promptContent += `\nINSTRUCTIONS: Analyze the situation and choose the best approach (create, inject, or integrate) automatically based on the existing project structure.\n`;
        }
    }
    
    // Additional notes
    if (notesContent) {
        if (!promptContent) {
            promptContent += `\n\n📚 DOCUMENTATION NOTES\n`;
            promptContent += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
        } else {
            promptContent += `\nAdditional Instructions:\n`;
        }
        promptContent += `${notesContent}\n`;
    }
    
    if (!promptContent) {
        showToast('⚠️ No documentation or settings to push', 'warning');
        return;
    }
    
    // Append to Project Prompts
    const currentContent = projectNotesTextarea.value;
    projectNotesTextarea.value = currentContent + promptContent;
    
    // Trigger auto-resize
    if (typeof autoResizeTextarea === 'function') {
        autoResizeTextarea(projectNotesTextarea);
    }
    
    // Save
    localStorage.setItem('projectPrompts', projectNotesTextarea.value);
    
    showToast('📚 Documentation settings pushed to Project Prompts', 'success');
}

// Character count for notes
function diUpdateCharCount() {
    const textarea = document.getElementById('diNotesTextarea');
    const countEl = document.getElementById('diCharCount');
    
    if (textarea && countEl) {
        const count = textarea.value.length;
        countEl.textContent = `${count} character${count !== 1 ? 's' : ''}`;
        diSaveNotesToStorage();
    }
}

// Save notes to storage
function diSaveNotesToStorage() {
    const textarea = document.getElementById('diNotesTextarea');
    if (textarea) {
        localStorage.setItem('diNotes', textarea.value);
    }
}

// Load notes from storage
function diLoadNotesFromStorage() {
    const savedNotes = localStorage.getItem('diNotes');
    const textarea = document.getElementById('diNotesTextarea');
    
    if (savedNotes && textarea) {
        textarea.value = savedNotes;
        diUpdateCharCount();
    }
}

// Reverse sync: Documentation Integration → Project File Uploader
function diSyncToUploader() {
    const docSelect = document.getElementById('ufDocSelect');
    if (!docSelect) return;
    
    if (diFileName && diEnableDoc) {
        // Check if the filename exists as an option in the UF dropdown
        const options = Array.from(docSelect.options);
        const matchingOption = options.find(opt => opt.value === diFileName);
        
        if (matchingOption) {
            docSelect.value = diFileName;
        } else {
            // Add it as a new option and select it
            const newOpt = document.createElement('option');
            newOpt.value = diFileName;
            newOpt.textContent = diFileName + ' (from Documentation tool)';
            docSelect.appendChild(newOpt);
            docSelect.value = diFileName;
        }
        
        // Update UF state
        if (typeof ufDetectedDoc !== 'undefined') {
            ufDetectedDoc = diFileName;
            
            const docBadge = document.getElementById('ufDocBadge');
            if (docBadge) {
                docBadge.textContent = 'Set';
                docBadge.className = 'uf-page-badge set';
            }
            
            if (typeof ufSaveToStorage === 'function') ufSaveToStorage();
        }
        
        console.log('🔄 DI → UF sync: Documentation set to', diFileName);
    } else {
        // Clear UF doc selection
        docSelect.value = '';
        
        if (typeof ufDetectedDoc !== 'undefined') {
            ufDetectedDoc = '';
            
            const docBadge = document.getElementById('ufDocBadge');
            if (docBadge) {
                docBadge.textContent = 'Not Set';
                docBadge.className = 'uf-page-badge not-set';
            }
            
            if (typeof ufSaveToStorage === 'function') ufSaveToStorage();
        }
        
        console.log('🔄 DI → UF sync: Documentation cleared');
    }
}

// Save to localStorage
function diSaveToStorage() {
    localStorage.setItem('diEnableDoc', diEnableDoc);
    localStorage.setItem('diIntegrationMode', diIntegrationMode);
    
    if (diFileContent && diFileName) {
        try {
            localStorage.setItem('diFileContent', diFileContent);
            localStorage.setItem('diFileName', diFileName);
        } catch (e) {
            console.warn('Failed to save documentation file:', e);
            if (e.name === 'QuotaExceededError') {
                showToast('⚠️ File too large for storage', 'warning');
            }
        }
    } else {
        localStorage.removeItem('diFileContent');
        localStorage.removeItem('diFileName');
    }
}

// Load from localStorage
function diLoadFromStorage() {
    diEnableDoc = localStorage.getItem('diEnableDoc') === 'true';
    diIntegrationMode = localStorage.getItem('diIntegrationMode') || 'ai-decision';
    diPageName = localStorage.getItem('diPageName') || 'documentation';
    
    // Load injection files
    const savedInjectionFiles = localStorage.getItem('diInjectionFiles');
    if (savedInjectionFiles) {
        try {
            diInjectionFiles = JSON.parse(savedInjectionFiles);
        } catch (e) {
            diInjectionFiles = [];
        }
    }
    
    const savedContent = localStorage.getItem('diFileContent');
    const savedName = localStorage.getItem('diFileName');
    
    if (savedContent && savedName) {
        diFileContent = savedContent;
        diFileName = savedName;
    }
}

// Reset all
function diResetAll(skipToast = false) {
    diFileContent = null;
    diFileName = null;
    diIntegrationMode = 'ai-decision';
    diEnableDoc = false;
    diPageName = 'documentation';
    diInjectionFiles = [];
    
    // Clear UI
    const docCheckbox = document.getElementById('diEnableDoc');
    if (docCheckbox) {
        docCheckbox.checked = false;
        const label = docCheckbox.closest('.di-checkbox-item');
        if (label) label.classList.remove('checked');
    }
    
    // Reset page name input
    const pageNameInput = document.getElementById('diPageName');
    if (pageNameInput) pageNameInput.value = 'documentation';
    
    // Clear injection files list
    const injectionList = document.getElementById('diInjectionList');
    if (injectionList) injectionList.innerHTML = '';
    
    document.getElementById('diUploadSection')?.classList.remove('show');
    document.getElementById('diFileInfo')?.classList.remove('show');
    document.getElementById('diModeSection')?.classList.remove('show');
    document.getElementById('diCreatePageInput')?.classList.remove('show');
    document.getElementById('diInjectionFiles')?.classList.remove('show');
    
    const fileInput = document.getElementById('diFileInput');
    if (fileInput) fileInput.value = '';
    
    const injectionFileInput = document.getElementById('diInjectionFileInput');
    if (injectionFileInput) injectionFileInput.value = '';
    
    // Reset mode selection
    diSelectMode('ai-decision');
    
    // Clear notes
    const notesTextarea = document.getElementById('diNotesTextarea');
    if (notesTextarea) {
        notesTextarea.value = '';
        diUpdateCharCount();
    }
    
    // Clear storage
    localStorage.removeItem('diEnableDoc');
    localStorage.removeItem('diIntegrationMode');
    localStorage.removeItem('diFileContent');
    localStorage.removeItem('diFileName');
    localStorage.removeItem('diNotes');
    localStorage.removeItem('diPageName');
    localStorage.removeItem('diInjectionFiles');
    
    diUpdateBadge();
    diSyncToUploader();
    
    if (!skipToast) {
        showToast('📚 Documentation settings reset', 'info');
    }
}

// Confirm reset
async function confirmResetDocumentation() {
    if (typeof deConfirm === 'function') {
        const confirmed = await deConfirm({
            title: 'Reset Documentation',
            subtitle: 'Design Enhancer',
            message: 'This will clear all documentation files, settings, and notes.',
            warning: 'This action cannot be undone.',
            confirmText: 'Reset',
            icon: 'fa-book'
        });
        if (confirmed) {
            diResetAll();
        }
    } else if (confirm('Reset documentation settings to default?')) {
        diResetAll();
    }
}

// Helper function for file size formatting
function formatFileSize(bytes) {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
}

// Get documentation settings (for external access)
function getDocumentation() {
    return {
        enabled: diEnableDoc,
        fileContent: diFileContent,
        fileName: diFileName,
        mode: diIntegrationMode,
        notes: document.getElementById('diNotesTextarea')?.value.trim() || ''
    };
}

// Initialize on DOM ready
document.addEventListener('DOMContentLoaded', function() {
    diInit();
});
</script>

