    let content = '\n\n🎨 DESIGN TEMPLATES\n';
    content += '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n';
    
    activeDesignTemplates.forEach(id => {
        const template = designTemplates.find(t => t.id === id);
