        showToast('🔄 Design Templates reset', 'info');
    }
}

// ============ UTILITY ============

function dtEscapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

function dtHighlightText(text, searchTerm) {
    if (!searchTerm) return dtEscapeHtml(text);
    const escaped = searchTerm.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const regex = new RegExp(`(${escaped})`, 'gi');
    return dtEscapeHtml(text).replace(regex, '<span class="highlight">$1</span>');
}

// ============ ADMIN CREDENTIALS SYSTEM ============

// Get processed content with admin credentials replaced
function dtGetProcessedContent(content, templateId) {
    let processed = content;
    
    // Handle static_2: Multi-Level Tree Node System (dynamic content)
    if (templateId === 'static_2' && content === '__TREE_DYNAMIC__') {
        processed = dtBuildTreePrompt();
    }
    // Handle static_1: Registration System — use edited prompt if saved, else apply credentials
    else if (templateId === 'static_1') {
        const editedPrompt = localStorage.getItem('dtRegPromptEdited');
        if (editedPrompt) {
            processed = editedPrompt;
        } else {
            const savedCreds = localStorage.getItem('dtAdminCredentials');
            if (savedCreds) {
                try {
                    const creds = JSON.parse(savedCreds);
                    if (creds.username && creds.email && creds.password) {
                        processed = processed.replace(
                            /Create initial super_admin account \([^)]+\)/g,
                            `Create initial super_admin account (username: ${creds.username}, email: ${creds.email}, password: ${creds.password})`
                        );
                    }
                    if (creds.email) {
                        processed = processed.replace(/admin@site\.com/g, creds.email);
                    }
                    if (creds.password) {
                        processed = processed.replace(/ChangeMe123!/g, creds.password);
                    }
                } catch (e) {
                    console.warn('Failed to parse admin credentials:', e);
                }
            }
        }
    }
    // Handle other templates: apply credentials generically
    else {
        const savedCreds = localStorage.getItem('dtAdminCredentials');
        if (savedCreds) {
            try {
                const creds = JSON.parse(savedCreds);
                if (creds.username && creds.email && creds.password) {
                    processed = processed.replace(
                        /Create initial super_admin account \([^)]+\)/g,
                        `Create initial super_admin account (username: ${creds.username}, email: ${creds.email}, password: ${creds.password})`
                    );
                }
                if (creds.email) {
                    processed = processed.replace(/admin@site\.com/g, creds.email);
                }
                if (creds.password) {
                    processed = processed.replace(/ChangeMe123!/g, creds.password);
                }
            } catch (e) {
                console.warn('Failed to parse admin credentials:', e);
            }
        }
    }
    
    // Append per-template extra instructions (works for ALL templates)
    if (templateId) {
        const extraInstr = localStorage.getItem(dtInstrKey(templateId));
        if (extraInstr) {
            processed += `\n\n📝 ADDITIONAL INSTRUCTIONS\n──────────────────────────\n${extraInstr}`;
        }
    }
    
    return processed;
}

// ============ TREE NODE SYSTEM - DYNAMIC PROMPT BUILDER ============

// Default calibration settings
const DT_TREE_DEFAULTS = {
    maxDepth: 5,
    infiniteDepth: false,
    nodeTypes: 'folder,file,category,tag,bookmark',
    dbTable: 'tree_nodes',
    rootLabel: 'Root',
    features: {
        dragDrop: true,
        search: true,
        contextMenu: true,
        lazyLoad: true,
        multiSelect: true,
        breadcrumb: true,
        icons: true,
        badges: true
    },
    uiStyle: 'modern',
    expandBehavior: 'click',
    sortable: true,
    apiPrefix: '/api/tree'
};

// Build the full tree prompt dynamically from calibration data
function dtBuildTreePrompt() {
    let cfg = {...DT_TREE_DEFAULTS, features: {...DT_TREE_DEFAULTS.features}};
    
    const saved = localStorage.getItem('dtTreeCalibration');
    if (saved) {
        try {
            const parsed = JSON.parse(saved);
            cfg = {
                ...cfg,
                ...parsed,
                features: {...cfg.features, ...(parsed.features || {})}
            };
        } catch(e) {
            console.warn('Failed to parse tree calibration:', e);
        }
    }
    
    const nodeTypesArr = cfg.nodeTypes.split(',').map(s => s.trim()).filter(Boolean);
    const featuresList = Object.entries(cfg.features).filter(([k,v]) => v).map(([k]) => k);
    
    let prompt = `🌳 MULTI-LEVEL TREE NODE SYSTEM
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

Build a complete, production-ready multi-level tree node system with full CRUD operations, drag-and-drop reordering, and a rich interactive UI. The system must support unlimited nesting depth with optimized database queries and a responsive, accessible frontend.

📋 CONFIGURATION
─────────────────
- Maximum Depth: ${cfg.infiniteDepth ? 'Unlimited (no restriction)' : cfg.maxDepth + ' levels'}
- Node Types: ${nodeTypesArr.join(', ')}
- Database Table: ${cfg.dbTable}
- Root Label: "${cfg.rootLabel}"
- UI Style: ${cfg.uiStyle}
- Expand Behavior: ${cfg.expandBehavior}
- Sortable: ${cfg.sortable ? 'Yes' : 'No'}
- API Prefix: ${cfg.apiPrefix}

📊 DATABASE SCHEMA
─────────────────
CREATE TABLE \`${cfg.dbTable}\` (
    id              INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    parent_id       INT UNSIGNED NULL DEFAULT NULL,
    node_type       ENUM('${nodeTypesArr.join("','")}') NOT NULL DEFAULT '${nodeTypesArr[0]}',
    name            VARCHAR(255) NOT NULL,
    slug            VARCHAR(255) NOT NULL,
    description     TEXT NULL,
    icon            VARCHAR(100) NULL DEFAULT NULL,
    color           VARCHAR(7) NULL DEFAULT NULL,
    sort_order      INT NOT NULL DEFAULT 0,
    depth           TINYINT UNSIGNED NOT NULL DEFAULT 0,
    path            VARCHAR(1000) NOT NULL DEFAULT '',
    is_expanded     TINYINT(1) NOT NULL DEFAULT 0,
    is_locked       TINYINT(1) NOT NULL DEFAULT 0,
    metadata        JSON NULL DEFAULT NULL,
    created_at      TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at      TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    
    FOREIGN KEY (parent_id) REFERENCES \`${cfg.dbTable}\`(id) ON DELETE CASCADE,
    INDEX idx_parent (parent_id),
    INDEX idx_depth (depth),
    INDEX idx_path (path(255)),
    INDEX idx_sort (parent_id, sort_order),
    UNIQUE INDEX idx_slug_parent (parent_id, slug)
);

-- Seed root node
INSERT INTO \`${cfg.dbTable}\` (parent_id, node_type, name, slug, depth, path)
VALUES (NULL, '${nodeTypesArr[0]}', '${cfg.rootLabel}', '${cfg.rootLabel.toLowerCase().replace(/\s+/g, '-')}', 0, '/');

🖥️ BACKEND API ENDPOINTS
─────────────────────────
Build RESTful API endpoints with the prefix: ${cfg.apiPrefix}

| Method | Endpoint                          | Description                              |
|--------|-----------------------------------|------------------------------------------|
| GET    | ${cfg.apiPrefix}/nodes            | Get all nodes (flat or nested)           |
| GET    | ${cfg.apiPrefix}/nodes/:id        | Get single node with children            |
| GET    | ${cfg.apiPrefix}/nodes/:id/path   | Get breadcrumb path to node              |
| POST   | ${cfg.apiPrefix}/nodes            | Create new node                          |
| PUT    | ${cfg.apiPrefix}/nodes/:id        | Update node (name, type, icon, etc.)     |
| DELETE | ${cfg.apiPrefix}/nodes/:id        | Delete node and all descendants          |
| PATCH  | ${cfg.apiPrefix}/nodes/:id/move   | Move node to new parent                  |
| PATCH  | ${cfg.apiPrefix}/nodes/reorder    | Reorder sibling nodes                    |
| GET    | ${cfg.apiPrefix}/nodes/search     | Search nodes by name/type                |
| GET    | ${cfg.apiPrefix}/nodes/:id/descendants | Get all descendants count/list     |`;

    // Conditional features section
    prompt += `

🎨 FRONTEND REQUIREMENTS
─────────────────────────
UI Style: ${cfg.uiStyle === 'modern' ? 'Modern glassmorphism with smooth animations, rounded corners, and subtle shadows' : cfg.uiStyle === 'minimal' ? 'Clean minimal design with simple lines and flat colors' : 'Classic tree view with traditional expand/collapse arrows'}

Enabled Features:`;

    if (cfg.features.dragDrop) {
        prompt += `
  ✅ Drag & Drop — Allow nodes to be dragged and dropped to reorder or reparent. Show visual drop indicators (above, below, inside). Enforce max depth of ${cfg.maxDepth}. Prevent dropping a parent into its own children.`;
    }
    if (cfg.features.search) {
        prompt += `
  ✅ Search & Filter — Real-time search with highlighting. Filter by node type. Show matching nodes with their parent path expanded. Debounced input (300ms).`;
    }
    if (cfg.features.contextMenu) {
        prompt += `
  ✅ Context Menu — Right-click any node to show options: Add Child, Rename, Duplicate, Move To, Change Type, Change Icon, Delete. Use a floating menu with icons and keyboard shortcuts.`;
    }
    if (cfg.features.lazyLoad) {
        prompt += `
  ✅ Lazy Loading — Only load children when a node is expanded. Show loading spinner during fetch. Cache loaded children to avoid redundant requests.`;
    }
    if (cfg.features.multiSelect) {
        prompt += `
  ✅ Multi-Select — Hold Ctrl/Cmd to select multiple nodes. Hold Shift for range selection. Show a bulk actions toolbar (move, delete, change type). Highlight selected nodes with a distinct color.`;
    }
    if (cfg.features.breadcrumb) {
        prompt += `
  ✅ Breadcrumb Navigation — Show the full path from root to the currently focused node. Each breadcrumb segment is clickable to navigate to that level.`;
    }
    if (cfg.features.icons) {
        prompt += `
  ✅ Custom Icons — Each node type has a default icon. Users can override the icon per node. Support Font Awesome or emoji icons. Show icons in the tree and breadcrumb.`;
    }
    if (cfg.features.badges) {
        prompt += `
  ✅ Badges & Counts — Show children count badge on each parent node. Show node type indicator. Optional status badges (locked, new, etc.).`;
    }

    prompt += `

⚙️ CORE BEHAVIORS
──────────────────
1. **Expand/Collapse**: Trigger on ${cfg.expandBehavior === 'click' ? 'single click on the node row' : cfg.expandBehavior === 'arrow' ? 'clicking the expand arrow icon only' : 'double-clicking the node row'}
2. **Auto Path Update**: When a node is moved, automatically recalculate the \`path\` and \`depth\` columns for the moved node and ALL its descendants recursively
3. **Slug Generation**: Auto-generate URL-safe slugs from node names. Ensure uniqueness within the same parent
4. **Sort Order**: Maintain sort_order for sibling nodes. When reordering, update all affected siblings in a single transaction
5. **Depth Enforcement**: ${cfg.infiniteDepth ? 'No depth restriction — allow unlimited nesting levels. Do NOT enforce any maximum depth limit.' : `Never allow nesting beyond ${cfg.maxDepth} levels. Show a warning if a drag-drop or move operation would exceed the max depth`}
6. **Optimistic UI**: Update the frontend immediately on user action, then sync with the backend. Roll back on failure with an error toast

🔒 VALIDATION RULES
────────────────────
- Node name: Required, 1-255 characters, no special characters except: - _ . ( )
- Node type: Must be one of: ${nodeTypesArr.join(', ')}
- Parent: Must exist and be a valid node (or NULL for root)
- Depth: ${cfg.infiniteDepth ? 'No limit (infinite nesting allowed)' : `Must not exceed ${cfg.maxDepth}`}
- Slug: Auto-generated, unique per parent, URL-safe
- Sort order: Non-negative integer
- Prevent circular references (a node cannot be moved into its own subtree)

🎯 TREE NODE UI COMPONENT
──────────────────────────
Each tree node row must display:
  - Expand/collapse indicator (▶/▼) for parent nodes
  - Node type icon (customizable)
  - Node name (editable on double-click for inline rename)
  - Children count badge (for parent nodes)
  - Action buttons on hover: Add Child, Edit, Delete
  - Drag handle (if drag & drop is enabled)
  - Checkbox (if multi-select is enabled)
  - Indentation: ${cfg.uiStyle === 'modern' ? '24px' : '20px'} per level with connecting lines

📱 RESPONSIVE DESIGN
─────────────────────
- Collapse tree into a hamburger-style panel on mobile (< 768px)
- Touch-friendly: larger tap targets, long-press for context menu
- Swipe gestures for expand/collapse on mobile
- Horizontal scroll with sticky node names for deep trees

♿ ACCESSIBILITY
────────────────
- Full keyboard navigation: Arrow keys to navigate, Enter to expand/collapse, Space to select
- ARIA attributes: role="tree", role="treeitem", aria-expanded, aria-level, aria-selected
- Screen reader announcements for state changes
- Focus management after add/delete/move operations
- High contrast mode support

IMPORTANT: Implement all of the above in clean, modular, well-documented code. Use prepared statements for all database queries. Follow recursive tree algorithms with proper cycle detection. Ensure all move/reorder operations are wrapped in database transactions for data integrity.`;

    return prompt;
}

// ============ REGISTRATION PROMPT EDITOR POPUP ============

// Track if the prompt has been user-edited
let _dtRegIsEdited = false;
let _dtRegOriginalContent = '';

// Open the Registration Prompt Editor popup
function dtOpenCredentialsModal() {
    let overlay = document.getElementById('dtRegOverlay');
    if (!overlay) {
        dtCreateRegEditorModal();
        overlay = document.getElementById('dtRegOverlay');
    }
    
    // Load credentials into the input fields
    const savedCreds = localStorage.getItem('dtAdminCredentials');
    if (savedCreds) {
        try {
            const creds = JSON.parse(savedCreds);
            document.getElementById('dtRegUsername').value = creds.username || '';
            document.getElementById('dtRegEmail').value = creds.email || '';
            document.getElementById('dtRegPassword').value = creds.password || '';
        } catch (e) {}
    }
    
    // Load the prompt content: user-edited version OR default with credentials applied
    const textarea = document.getElementById('dtRegTextarea');
    if (textarea) {
        const savedEdited = localStorage.getItem('dtRegPromptEdited');
        if (savedEdited) {
            textarea.value = savedEdited;
            _dtRegIsEdited = true;
        } else {
            textarea.value = dtRegBuildProcessedPrompt();
            _dtRegIsEdited = false;
        }
        _dtRegOriginalContent = textarea.value;
    }
    
    // Restore Roles & RBAC toggle state
    const rolesToggle = document.getElementById('dtRegRolesToggle');
    const toggleItem = document.getElementById('dtRegRolesToggleItem');
    const savedRolesState = localStorage.getItem('dtRegIncludeRoles');
    if (rolesToggle) {
        const include = savedRolesState !== '0'; // default ON
        rolesToggle.checked = include;
        if (toggleItem) toggleItem.classList.toggle('active', include);
        // If roles were toggled off, strip them from the loaded content
        if (!include && textarea) {
            textarea.value = dtRegStripRoles(textarea.value);
        }
    }
    
    dtRegUpdateEditBadge();
    dtRegUpdateCharCount();
    overlay.classList.add('show');
    
    setTimeout(() => {
        if (textarea) textarea.focus();
    }, 200);
}

// Close the popup
function dtCloseCredentialsModal() {
    const overlay = document.getElementById('dtRegOverlay');
    if (overlay) overlay.classList.remove('show');
}

// Build the processed prompt content with credentials replaced
function dtRegBuildProcessedPrompt() {
    const staticTemplate = DT_STATIC_TEMPLATES.find(t => t.id === 'static_1');
    if (!staticTemplate) return '';
    
    let content = staticTemplate.content;
    
    // Apply credentials
    const savedCreds = localStorage.getItem('dtAdminCredentials');
    if (savedCreds) {
        try {
            const creds = JSON.parse(savedCreds);
            if (creds.username && creds.email && creds.password) {
                content = content.replace(
                    /Create initial super_admin account \([^)]+\)/g,
                    `Create initial super_admin account (username: ${creds.username}, email: ${creds.email}, password: ${creds.password})`
                );
            }
            if (creds.email) content = content.replace(/admin@site\.com/g, creds.email);
            if (creds.password) content = content.replace(/ChangeMe123!/g, creds.password);
        } catch (e) {}
    }
    
    // Append extra instructions if any
    const extraInstr = localStorage.getItem(dtInstrKey('static_1'));
    if (extraInstr) {
        content += `\n\n📝 ADDITIONAL INSTRUCTIONS\n──────────────────────────\n${extraInstr}`;
    }
    
    return content;
}

// ============ ROLES & RBAC TOGGLE ============

// Toggle roles sections in the registration prompt
function dtRegToggleRoles() {
    const toggle = document.getElementById('dtRegRolesToggle');
    const textarea = document.getElementById('dtRegTextarea');
    const toggleItem = document.getElementById('dtRegRolesToggleItem');
    if (!toggle || !textarea) return;
    
    const include = toggle.checked;
    localStorage.setItem('dtRegIncludeRoles', include ? '1' : '0');
    
    if (toggleItem) {
        toggleItem.classList.toggle('active', include);
    }
    
    if (!include) {
        textarea.value = dtRegStripRoles(textarea.value);
    } else {
        textarea.value = dtRegAddRoles(textarea.value);
    }
    
    dtRegOnTextChange();
    dtRegUpdateCharCount();
    showToast(include ? '🔐 Roles & RBAC sections added' : '🔓 Roles & RBAC sections removed', 'info');
}

// Strip all roles-related content from the prompt text
function dtRegStripRoles(text) {
    // 1. Remove roles-related database tables (roles, permissions, role_permissions, user_roles, page_access_control)
    text = text.replace(/\n*▶ TABLE: roles\n[\s\S]*?(?=▶ TABLE: user_sessions)/, '\n');
    
    // 2. Remove Section 7: RBAC (entire section including header)
    text = text.replace(/\n*═+\n7\. ROLE-BASED ACCESS CONTROL \(RBAC\)\n═+\n[\s\S]*?(?=\n═+\n8\.)/, '');
    
    // 3. Remove seed data roles lines
    text = text.replace(/\n- Roles:[^\n]*\n- Permissions:[^\n]*\n- Assign all permissions[^\n]*\n- Set 'user' role[^\n]*/g, '');
    
    // 4. Remove role API endpoints
    text = text.replace(/\nGET  \/admin\/roles[^\n]*\nPOST \/admin\/roles[^\n]*\nPUT  \/admin\/roles[^\n]*\nDELETE \/admin\/roles[^\n]*\nPOST \/admin\/users\/:id\/roles[^\n]*\nDELETE \/admin\/users\/:id\/roles\/:roleId[^\n]*/g, '');
    
    // 5. Remove "Auto-assign default role" line
    text = text.replace(/\n- Auto-assign default role[^\n]*/g, '');
    
    // 6. Modify intro line: remove "and role-based access control"
    text = text.replace(
        /registration, login, and role-based access control system\. The implementation must cover database schema, backend logic, frontend pages, session management, and admin controls\./g,
        'registration and login system. The implementation must cover database schema, backend logic, frontend pages, and session management.'
    );
    
    // 7. Strip role references from Admin User Management section
    text = text.replace(/roles \(badges\), /g, '');
    text = text.replace(/- Filter by role, status,/g, '- Filter by status,');
    text = text.replace(/, assign role/g, '');
    text = text.replace(/, role assignments,/g, ',');
    
    // 8. Remove page_access_control seed data line (contains role-based routing)
    text = text.replace(/\n- Define page_access_control entries[^\n]*/g, '');
    
    // Clean up triple+ newlines
    text = text.replace(/\n{3,}/g, '\n\n');
    
    return text;
}

// Re-add roles content from the default template at anchor positions
function dtRegAddRoles(text) {
    const tmpl = DT_STATIC_TEMPLATES.find(t => t.id === 'static_1');
    if (!tmpl) return text;
    const src = tmpl.content;
    
    // 1. Re-insert roles tables before user_sessions table
    if (!text.includes('TABLE: roles')) {
        const m = src.match(/(▶ TABLE: roles[\s\S]*?)(?=▶ TABLE: user_sessions)/);
        if (m && text.includes('▶ TABLE: user_sessions')) {
            text = text.replace('▶ TABLE: user_sessions', m[1] + '▶ TABLE: user_sessions');
        }
    }
    
    // 2. Re-insert RBAC section before section 8
    if (!text.includes('ROLE-BASED ACCESS CONTROL')) {
        const m = src.match(/(═+\n7\. ROLE-BASED ACCESS CONTROL[\s\S]*?\n)\n(═+\n8\.)/);
        if (m) {
            const anchor = text.match(/═+\n8\./);
            if (anchor) {
                text = text.replace(anchor[0], '\n' + m[1] + '\n' + anchor[0]);
            }
        }
    }
    
    // 3. Re-insert seed data roles lines before super_admin account line
    if (!text.includes('Roles: super_admin')) {
        const m = src.match(/(- Roles:[^\n]*\n- Permissions:[^\n]*\n- Assign all permissions[^\n]*\n- Set 'user' role[^\n]*\n)/);
        if (m && text.includes('Create initial super_admin account')) {
            text = text.replace(/- Create initial super_admin account/, m[1] + '- Create initial super_admin account');
        }
    }
    
    // 4. Re-insert role API endpoints before IMPORTANT line
    if (!text.includes('/admin/roles')) {
        const m = src.match(/(GET  \/admin\/roles[^\n]*\nPOST \/admin\/roles[^\n]*\nPUT  \/admin\/roles[^\n]*\nDELETE \/admin\/roles[^\n]*\nPOST \/admin\/users\/:id\/roles[^\n]*\nDELETE \/admin\/users\/:id\/roles\/:roleId[^\n]*\n)/);
        if (m && text.includes('\nIMPORTANT:')) {
            text = text.replace('\nIMPORTANT:', '\n' + m[1] + '\nIMPORTANT:');
        }
    }
    
    // 5. Re-insert "Auto-assign default role" line
    if (!text.includes('Auto-assign default role')) {
        if (text.includes('- Store hashed password only')) {
            text = text.replace('- Store hashed password only', "- Auto-assign default role ('user') upon registration\n- Store hashed password only");
        }
    }
    
    // 6. Restore intro line with role-based access control
    if (!text.includes('role-based access control')) {
        text = text.replace(
            /registration and login system\. The implementation must cover database schema, backend logic, frontend pages, and session management\./g,
            'registration, login, and role-based access control system. The implementation must cover database schema, backend logic, frontend pages, session management, and admin controls.'
        );
    }
    
    // 7. Restore role references in Admin User Management section
    if (!text.includes('roles (badges)')) {
        text = text.replace(/avatar, name, email, status/g, 'avatar, name, email, roles (badges), status');
    }
    if (!text.includes('Filter by role')) {
        text = text.replace(/- Filter by status, registration date/g, '- Filter by role, status, registration date');
    }
    if (!text.includes('assign role')) {
        text = text.replace(/activate, deactivate, delete\n/g, 'activate, deactivate, delete, assign role\n');
    }
    if (!text.includes('role assignments')) {
        text = text.replace(/full profile info, login history/g, 'full profile info, role assignments, login history');
    }
    
    // 8. Restore page_access_control seed data line
    if (!text.includes('page_access_control entries')) {
        if (text.includes('Create initial super_admin account')) {
            text = text.replace(
                /- Create initial super_admin account/,
                "- Define page_access_control entries for: /dashboard (user+), /admin (admin+), /settings (admin+), /users (moderator+), /reports (editor+), /profile (user+), /login (public), /register (public)\n- Create initial super_admin account"
            );
        }
    }
    
    return text;
}

// Save everything: credentials + prompt text
function dtRegSaveAll() {
    // Save credentials
    const username = document.getElementById('dtRegUsername').value.trim();
    const email = document.getElementById('dtRegEmail').value.trim();
    const password = document.getElementById('dtRegPassword').value.trim();
    
    if (username || email || password) {
        localStorage.setItem('dtAdminCredentials', JSON.stringify({ username, email, password }));
    }
    
    // Save the edited prompt text
    const textarea = document.getElementById('dtRegTextarea');
    if (textarea) {
        const currentText = textarea.value.trim();
        const defaultText = dtRegBuildProcessedPrompt().trim();
        
        if (currentText && currentText !== defaultText) {
            localStorage.setItem('dtRegPromptEdited', currentText);
            _dtRegIsEdited = true;
        } else {
            localStorage.removeItem('dtRegPromptEdited');
            _dtRegIsEdited = false;
        }
    }
    
    dtRegUpdateEditBadge();
    dtUpdateInputButtons();
    showToast('✅ Registration prompt & credentials saved', 'success');
}

// Apply credentials to the prompt (refresh from default + credentials)
function dtRegApplyCredentials() {
    const textarea = document.getElementById('dtRegTextarea');
    if (!textarea) return;
    
    // Rebuild from default template with new credentials applied
    const username = document.getElementById('dtRegUsername').value.trim();
    const email = document.getElementById('dtRegEmail').value.trim();
    const password = document.getElementById('dtRegPassword').value.trim();
    
    // Temporarily save creds so the builder uses them
    if (username || email || password) {
        localStorage.setItem('dtAdminCredentials', JSON.stringify({ username, email, password }));
    }
    
    textarea.value = dtRegBuildProcessedPrompt();
    _dtRegIsEdited = false;
    localStorage.removeItem('dtRegPromptEdited');
    dtRegUpdateEditBadge();
    dtRegUpdateCharCount();
    showToast('🔄 Credentials applied to prompt', 'info');
}

// Reset to default prompt (remove all edits)
function dtRegResetPrompt() {
    const textarea = document.getElementById('dtRegTextarea');
    if (!textarea) return;
    
    // Clear saved edits
    localStorage.removeItem('dtRegPromptEdited');
    localStorage.removeItem('dtAdminCredentials');
    
    // Clear credential fields
    document.getElementById('dtRegUsername').value = '';
    document.getElementById('dtRegEmail').value = '';
    document.getElementById('dtRegPassword').value = '';
    
    // Reset textarea to original default
    textarea.value = DT_STATIC_TEMPLATES.find(t => t.id === 'static_1')?.content || '';
    _dtRegIsEdited = false;
    
    dtRegUpdateEditBadge();
    dtRegUpdateCharCount();
    dtUpdateInputButtons();
    showToast('🗑️ Reset to default prompt', 'info');
}

// Copy prompt content
function dtRegCopyPrompt() {
    const textarea = document.getElementById('dtRegTextarea');
    if (!textarea || !textarea.value.trim()) return;
    
    navigator.clipboard.writeText(textarea.value).then(() => {
        showToast('📋 Prompt copied to clipboard', 'success');
    }).catch(() => {
        textarea.select();
        document.execCommand('copy');
        showToast('📋 Prompt copied to clipboard', 'success');
    });
}

// Push prompt to Prompt Editor textarea
function dtRegPushToNotes() {
    const textarea = document.getElementById('dtRegTextarea');
    if (!textarea || !textarea.value.trim()) {
        showToast('⚠️ No prompt content to push', 'warning');
        return;
    }
    
    const promptEditor = document.getElementById('promptEditor');
    if (!promptEditor) return;
    
    let content = '\n\n🔐 REGISTRATION SYSTEM\n';
    content += '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n';
    content += textarea.value;
    
    promptEditor.value = promptEditor.value + content;
    promptEditor.dispatchEvent(new Event('input', { bubbles: true }));
    
    if (typeof autoResizeTextarea === 'function') {
        autoResizeTextarea(promptEditor);
    }
    
    dtCloseCredentialsModal();
    showToast('🔐 Registration prompt pushed to Prompt Editor', 'success');
    
    promptEditor.scrollTop = promptEditor.scrollHeight;
    setTimeout(() => promptEditor.scrollIntoView({ behavior: 'smooth', block: 'center' }), 150);
}

// Update the edit badge indicator
function dtRegUpdateEditBadge() {
    const badge = document.getElementById('dtRegEditBadge');
    if (!badge) return;
    
    if (_dtRegIsEdited || localStorage.getItem('dtRegPromptEdited')) {
        badge.classList.add('visible');
    } else {
        badge.classList.remove('visible');
    }
}

// Update character/line count
function dtRegUpdateCharCount() {
    const textarea = document.getElementById('dtRegTextarea');
    const counter = document.getElementById('dtRegCharInfo');
    if (!textarea || !counter) return;
    
    const chars = textarea.value.length;
    const lines = textarea.value.split('\n').length;
    counter.textContent = `${chars.toLocaleString()} chars · ${lines} lines`;
}

// Handle text change in the prompt textarea
function dtRegOnTextChange() {
    dtRegUpdateCharCount();
    const textarea = document.getElementById('dtRegTextarea');
    if (textarea) {
        const currentText = textarea.value.trim();
        const defaultText = dtRegBuildProcessedPrompt().trim();
        _dtRegIsEdited = (currentText !== defaultText);
        dtRegUpdateEditBadge();
    }
}

// Update Input button appearance across all static templates
function dtUpdateInputButtons() {
    const hasData = localStorage.getItem('dtAdminCredentials') || localStorage.getItem('dtRegPromptEdited');
    document.querySelectorAll('.dt-input-btn').forEach(btn => {
        if (hasData) {
            btn.classList.add('has-data');
        } else {
            btn.classList.remove('has-data');
        }
    });
}

