// Open explain modal
function dtOpenExplainModal(templateId) {
    const template = designTemplates.find(t => t.id === templateId);
    if (!template) return;
    
    const explanation = DT_TEMPLATE_EXPLANATIONS[templateId];
    if (!explanation) {
        showToast('ℹ️ No explanation available for this template', 'info');
        return;
    }
    
    // Stop any ongoing TTS when reopening
    dtStopAllTTS();
    
    // Create modal if it doesn't exist yet
    let overlay = document.getElementById('dtExplainOverlay');
    if (!overlay) {
        dtCreateExplainModal();
        overlay = document.getElementById('dtExplainOverlay');
    }
    
    // Store current explanation for TTS Read All
    window._dtCurrentExplanation = explanation;
    
    // Populate content
    const titleEl = overlay.querySelector('.dt-explain-title span');
    const summaryEl = overlay.querySelector('.dt-explain-summary');
    const featuresEl = overlay.querySelector('.dt-explain-features');
    const noteEl = overlay.querySelector('.dt-explain-note');
    
    if (titleEl) titleEl.innerHTML = explanation.title;
    
    if (summaryEl) {
        const plainSummary = explanation.summary.replace(/<[^>]*>/g, '');
        summaryEl.innerHTML = `
            <div class="dt-explain-summary-wrap">
                <button type="button" class="dt-tts-btn" onclick="event.stopPropagation(); dtSpeakText('${dtEscapeForAttr(plainSummary)}', this)" title="Read aloud">
                    <i class="fas fa-volume-up"></i>
                </button>
                <div class="dt-explain-summary-text">${explanation.summary}</div>
            </div>`;
    }
    
    if (featuresEl) {
        featuresEl.innerHTML = explanation.features.map(f => {
            const plainText = f.text.replace(/<[^>]*>/g, '');
            return `<div class="dt-explain-feature">
                <button type="button" class="dt-tts-btn" onclick="event.stopPropagation(); dtSpeakText('${dtEscapeForAttr(plainText)}', this)" title="Read aloud">
                    <i class="fas fa-volume-up"></i>
                </button>
                <i class="fas ${f.icon}"></i>
                <span>${f.text}</span>
            </div>`;
        }).join('');
    }
    
    if (noteEl) {
        const plainNote = explanation.note.replace(/<[^>]*>/g, '');
        noteEl.innerHTML = `
            <div class="dt-explain-note-wrap">
                <button type="button" class="dt-tts-btn" onclick="event.stopPropagation(); dtSpeakText('${dtEscapeForAttr(plainNote)}', this)" title="Read aloud">
                    <i class="fas fa-volume-up"></i>
                </button>
                <div class="dt-explain-note-content">
                    <i class="fas fa-lightbulb"></i>
                    <span>${explanation.note}</span>
                </div>
            </div>`;
    }
    
    // Reset Read All button
    const readAllBtn = overlay.querySelector('.dt-tts-all-btn');
    if (readAllBtn) {
        readAllBtn.classList.remove('speaking');
        readAllBtn.innerHTML = '<i class="fas fa-volume-up"></i> Read All';
    }
    
    overlay.classList.add('show');
}

// Close explain modal
function dtCloseExplainModal() {
    dtStopAllTTS();
    const overlay = document.getElementById('dtExplainOverlay');
    if (overlay) overlay.classList.remove('show');
}

// ============ TTS ENGINE (British Female Voice) ============

// Escape text for safe use in onclick attributes
function dtEscapeForAttr(text) {
    return text.replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/"/g, '&quot;').replace(/\n/g, ' ');
}

// Get the best British female voice
function dtGetBritishFemaleVoice() {
    const voices = speechSynthesis.getVoices();
    
    // Priority list for British female voices
    const preferred = [
        'Google UK English Female',
        'Microsoft Hazel',
        'Microsoft Susan',
        'en-GB',
        'Fiona',
        'Kate',
        'Serena',
        'Martha'
    ];
    
    // First try: exact name match for known female voices
    for (const name of preferred) {
        const voice = voices.find(v => v.name.includes(name) && v.lang.startsWith('en'));
        if (voice) return voice;
    }
    
    // Second try: any en-GB voice (prefer female if we can detect from name)
    const gbVoices = voices.filter(v => v.lang === 'en-GB');
    if (gbVoices.length > 0) {
        // Try to find a female one
        const female = gbVoices.find(v => /female|woman|fiona|kate|serena|hazel|susan|martha|zira/i.test(v.name));
        if (female) return female;
        return gbVoices[0]; // Fallback to any GB voice
    }
    
    // Third try: any English voice
    const enVoices = voices.filter(v => v.lang.startsWith('en'));
    if (enVoices.length > 0) {
        const female = enVoices.find(v => /female|woman|zira|samantha|karen|moira|tessa/i.test(v.name));
        if (female) return female;
        return enVoices[0];
    }
    
    return null;
}

// Speak a single text, highlight the button
function dtSpeakText(text, btnElement) {
    // If this button is already speaking, stop it
    if (btnElement && btnElement.classList.contains('speaking')) {
        dtStopAllTTS();
        return;
    }
    
    // Stop any current speech
    dtStopAllTTS();
    
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.rate = 0.92;
    utterance.pitch = 1.05;
    utterance.volume = 1;
    
    const voice = dtGetBritishFemaleVoice();
    if (voice) {
        utterance.voice = voice;
        utterance.lang = voice.lang;
    } else {
        utterance.lang = 'en-GB';
    }
    
    // Highlight
    if (btnElement) btnElement.classList.add('speaking');
    
    utterance.onend = () => {
        if (btnElement) btnElement.classList.remove('speaking');
    };
    utterance.onerror = () => {
        if (btnElement) btnElement.classList.remove('speaking');
    };
    
    window._dtCurrentUtterance = utterance;
    speechSynthesis.speak(utterance);
}

// Stop all TTS
function dtStopAllTTS() {
    speechSynthesis.cancel();
    window._dtReadAllQueue = null;
    
    // Remove all speaking classes
    document.querySelectorAll('.dt-tts-btn.speaking, .dt-tts-all-btn.speaking').forEach(btn => {
        btn.classList.remove('speaking');
    });
    
    // Reset Read All button
    const readAllBtn = document.querySelector('.dt-tts-all-btn');
    if (readAllBtn) {
        readAllBtn.innerHTML = '<i class="fas fa-volume-up"></i> Read All';
    }
}

// Read All - sequential reading of every section
function dtReadAll(btnElement) {
    // If already reading, stop
    if (btnElement.classList.contains('speaking')) {
        dtStopAllTTS();
        return;
    }
    
    dtStopAllTTS();
    
    const explanation = window._dtCurrentExplanation;
    if (!explanation) return;
    
    // Build the full queue of texts
    const queue = [];
    
    // Summary
    const plainSummary = explanation.summary.replace(/<[^>]*>/g, '');
    queue.push({ text: plainSummary, selector: '.dt-explain-summary .dt-tts-btn' });
    
    // Features
    explanation.features.forEach((f, i) => {
        const plainText = f.text.replace(/<[^>]*>/g, '');
        queue.push({ text: plainText, selector: `.dt-explain-feature:nth-child(${i + 1}) .dt-tts-btn` });
    });
    
    // Note
    const plainNote = explanation.note.replace(/<[^>]*>/g, '');
    queue.push({ text: plainNote, selector: '.dt-explain-note .dt-tts-btn' });
    
    // Update button to Stop mode
    btnElement.classList.add('speaking');
    btnElement.innerHTML = '<i class="fas fa-stop"></i> Stop';
    
    // Start sequential playback
    window._dtReadAllQueue = queue;
    dtPlayNextInQueue(0, btnElement);
}

// Play next item in the Read All queue
function dtPlayNextInQueue(index, readAllBtn) {
    const queue = window._dtReadAllQueue;
    if (!queue || index >= queue.length) {
        // Done
        dtStopAllTTS();
        return;
    }
    
    const item = queue[index];
    const overlay = document.getElementById('dtExplainOverlay');
    const itemBtn = overlay ? overlay.querySelector(item.selector) : null;
    
    const utterance = new SpeechSynthesisUtterance(item.text);
    utterance.rate = 0.92;
    utterance.pitch = 1.05;
    utterance.volume = 1;
    
    const voice = dtGetBritishFemaleVoice();
    if (voice) {
        utterance.voice = voice;
        utterance.lang = voice.lang;
    } else {
        utterance.lang = 'en-GB';
    }
    
    // Highlight current item button
    if (itemBtn) itemBtn.classList.add('speaking');
    
    utterance.onend = () => {
        if (itemBtn) itemBtn.classList.remove('speaking');
        // Small pause between sections
        setTimeout(() => dtPlayNextInQueue(index + 1, readAllBtn), 250);
    };
    
    utterance.onerror = () => {
        if (itemBtn) itemBtn.classList.remove('speaking');
        dtStopAllTTS();
    };
    
    speechSynthesis.speak(utterance);
}

// Preload voices
if (typeof speechSynthesis !== 'undefined') {
    speechSynthesis.getVoices();
    speechSynthesis.onvoiceschanged = () => speechSynthesis.getVoices();
}

// Create the explain modal HTML dynamically
function dtCreateExplainModal() {
    const overlay = document.createElement('div');
    overlay.id = 'dtExplainOverlay';
    overlay.className = 'dt-explain-overlay';
    overlay.onclick = function(e) { if (e.target === this) dtCloseExplainModal(); };
    
    overlay.innerHTML = `
        <div class="dt-explain-modal">
            <div class="dt-explain-header">
                <div class="dt-explain-title">
                    <i class="fas fa-lightbulb"></i>
                    <span></span>
                </div>
                <div style="display:flex; align-items:center; gap:8px;">
                    <button type="button" class="dt-tts-all-btn" onclick="event.stopPropagation(); dtReadAll(this)" title="Read all sections aloud">
                        <i class="fas fa-volume-up"></i> Read All
                    </button>
                    <button class="dt-explain-close" onclick="dtCloseExplainModal()">
                        <i class="fas fa-times"></i>
                    </button>
                </div>
            </div>
            
            <div class="dt-explain-summary"></div>
            
            <div class="dt-explain-features"></div>
            
            <div class="dt-explain-note"></div>
        </div>
    `;
    
    document.body.appendChild(overlay);
}

// Initialize on DOM ready
document.addEventListener('DOMContentLoaded', function() {
    dtLoadTemplates();
});
</script>

<!-- ═══════════════════════════════════════════════════════════════════
     🚀 GENERAL PUSH ALL - Design Enhancer
     ═══════════════════════════════════════════════════════════════════ -->
<script>
// Map each tool element ID → { display name, push function }
const dePushMap = {
    'fileUploadTool':        { name: 'Project Files Upload',    fn: function() { ufPushToNotes(); } },
    'exclusionTool':         { name: 'File Exclusion',          fn: function() { exPushToNotes(); } },
    'brandingTool':          { name: 'Logo & Branding',         fn: function() { pushBrandingToNotes(); } },
    'pagesCreatorTool':      { name: 'Pages Creator',           fn: function() { pcPushToNotes(); } },
    'customInstructionsTool':{ name: 'Custom Instructions',     fn: function() { ciPushToNotes(); } },
    'styleTypesTool':        { name: 'Enhanced Style Types',    fn: function() { stPushToNotes(); } },
    'designThemeTool':       { name: 'Design Theme',            fn: function() { dtPushToNotes(); } },
    'layoutTool':            { name: 'Page Layout Structure',   fn: function() { plPushToNotes(); } },
    'executionModeTool':     { name: 'Execution Mode',          fn: function() { emPushToNotes(); } },
    'designFocusTool':       { name: 'Design Focus Areas',      fn: function() { dfPushToNotes(); } },
    'enhancementLevelTool':  { name: 'Enhancement Level',       fn: function() { elPushToNotes(); } },
    'taskBreakdownTool':     { name: 'Task Breakdown',          fn: function() { tbPushToNotes(); } },
    'homepageTool':          { name: 'Homepage Configuration',  fn: function() { hpPushToNotes(); } },
    'documentationTool':     { name: 'Documentation',           fn: function() { diPushToNotes(); } },
    'designTemplateTool':    { name: 'Design Templates',        fn: function() { dtTemplatePushToNotes(); } },
};

// Push All tools to Project Prompts in their current visual DOM order
async function dePushAll() {
    const btn = document.getElementById('dePushAllBtn');
    if (!btn || btn.classList.contains('pushing')) return;
    
    // Read current DOM order of tools from the container
    const container = document.getElementById('deToolsContainer');
    if (!container) return;
    
    const toolElements = container.querySelectorAll('.de-tool-section');
    const pushQueue = [];
    
    toolElements.forEach(el => {
        const entry = dePushMap[el.id];
        if (!entry) return;
        // Skip unchecked tools
        const cb = document.getElementById('deCheck_' + el.id);
        if (cb && !cb.checked) return;
        pushQueue.push({ id: el.id, name: entry.name, fn: entry.fn });
    });
    
    if (pushQueue.length === 0) {
        if (typeof showToast === 'function') showToast('No tools selected — check at least one tool', 'warning');
        return;
    }
    
    // Enter pushing state
    const originalHTML = btn.innerHTML;
    btn.classList.add('pushing');
    
    let pushed = 0;
    const total = pushQueue.length;
    
    // Update button text to show progress
    function updateProgress(current, label) {
        btn.innerHTML = `<i class="fas fa-spinner fa-spin"></i> <span>Pushing ${current}/${total}...</span> <span class="de-push-all-progress">${label}</span>`;
    }
    
    // Yield to browser — requestAnimationFrame + setTimeout ensures DOM flush
    function yieldToBrowser() {
        return new Promise(resolve => {
            requestAnimationFrame(() => {
                setTimeout(resolve, 120);
            });
        });
    }
    
    // Execute each push sequentially in DOM order with a yield between each
    for (let i = 0; i < pushQueue.length; i++) {
        const item = pushQueue[i];
        
        updateProgress(i + 1, item.name);
        
        // Yield BEFORE each push so the progress UI updates
        await yieldToBrowser();
        
        try {
            item.fn();
            pushed++;
        } catch (err) {
            console.warn(`⚠️ Push failed for ${item.name}:`, err);
        }
    }
    
    // Final yield to let last push settle
    await yieldToBrowser();
    
    // Done — show success state
    btn.classList.remove('pushing');
    btn.classList.add('push-done');
    btn.innerHTML = `<i class="fas fa-check-circle"></i> <span>Pushed ${pushed} Tool${pushed !== 1 ? 's' : ''} Successfully</span>`;
    
    if (typeof showToast === 'function') {
        showToast(`🚀 All ${pushed} tool(s) pushed to Project Prompts`, 'success');
    }
    
    // Reset button after 2.5 seconds
    await new Promise(r => setTimeout(r, 2500));
    btn.classList.remove('push-done');
    btn.innerHTML = originalHTML;
}

// Dashboard-specific overrides for Push All + Dashboard button
const dePushMapDashboardOverrides = {
    'fileUploadTool':   { name: 'Project Files Upload',  fn: function() { ufPushToDashboard(); } },
    'pagesCreatorTool': { name: 'Pages Creator',          fn: function() { pcPushToDashboard(); } }
};

// Push All + Dashboard: same as dePushAll but file upload & pages creator go to Dashboard
async function dePushAllDashboard() {
    const btn = document.getElementById('dePushAllDashboardBtn');
    if (!btn || btn.classList.contains('pushing')) return;
    
    const container = document.getElementById('deToolsContainer');
    if (!container) return;
    
    const toolElements = container.querySelectorAll('.de-tool-section');
    const pushQueue = [];
    
    toolElements.forEach(el => {
        // Use dashboard override if available, otherwise use default map
        const entry = dePushMapDashboardOverrides[el.id] || dePushMap[el.id];
        if (!entry) return;
        // Skip unchecked tools
        const cb = document.getElementById('deCheck_' + el.id);
        if (cb && !cb.checked) return;
        pushQueue.push({ id: el.id, name: entry.name, fn: entry.fn });
    });
    
    if (pushQueue.length === 0) {
        if (typeof showToast === 'function') showToast('No tools selected — check at least one tool', 'warning');
        return;
    }
    
    const originalHTML = btn.innerHTML;
    btn.classList.add('pushing');
    
    let pushed = 0;
    const total = pushQueue.length;
    
    function updateProgress(current, label) {
        btn.innerHTML = `<i class="fas fa-spinner fa-spin"></i> <span>Pushing ${current}/${total}...</span> <span class="de-push-all-progress">${label}</span>`;
    }
    
    function yieldToBrowser() {
        return new Promise(resolve => {
            requestAnimationFrame(() => { setTimeout(resolve, 120); });
        });
    }
    
    for (let i = 0; i < pushQueue.length; i++) {
        const item = pushQueue[i];
        updateProgress(i + 1, item.name);
        await yieldToBrowser();
        
        try {
            item.fn();
            pushed++;
        } catch (err) {
            console.warn(`⚠️ Push failed for ${item.name}:`, err);
        }
    }
    
    await yieldToBrowser();
    
    btn.classList.remove('pushing');
    btn.classList.add('push-done');
    btn.innerHTML = `<i class="fas fa-check-circle"></i> <span>Pushed ${pushed} Tool${pushed !== 1 ? 's' : ''} Successfully</span>`;
    
    if (typeof showToast === 'function') {
        showToast(`🚀 All ${pushed} tool(s) pushed (Files & Pages → Dashboard)`, 'success');
    }
    
    await new Promise(r => setTimeout(r, 2500));
    btn.classList.remove('push-done');
    btn.innerHTML = originalHTML;
}
</script>

<!-- Theme Toggle Script -->
<script>
// Theme Toggle Function
function toggleTheme() {
    const body = document.body;
    const icon = document.getElementById('themeIcon');
    const currentTheme = body.getAttribute('data-theme');
    
    if (currentTheme === 'light') {
        body.removeAttribute('data-theme');
        if (icon) {
            icon.classList.remove('fa-moon');
            icon.classList.add('fa-sun');
        }
        localStorage.setItem('pm-theme', 'dark');
    } else {
        body.setAttribute('data-theme', 'light');
        if (icon) {
            icon.classList.remove('fa-sun');
            icon.classList.add('fa-moon');
        }
        localStorage.setItem('pm-theme', 'light');
    }
}

// Load saved theme on page load
(function() {
    const savedTheme = localStorage.getItem('pm-theme');
    const icon = document.getElementById('themeIcon');
    
    if (savedTheme === 'light') {
        document.body.setAttribute('data-theme', 'light');
        if (icon) {
            icon.classList.remove('fa-sun');
            icon.classList.add('fa-moon');
        }
    }
})();
</script>

