<script>
// ============================================
// FOLDER BROWSER - Hybrid: PHP on localhost, File System Access API on remote
// ============================================
(function() {
    console.log('📁 Folder Browser IIFE initializing...');
    
    // ── Shared state ──
    let fbCurrentPath = '';
    let fbParentPath = '';
    let fbSelectedFolders = new Map(); // folderName → folderPath (PHP) or '' (client)
    let fbMode = 'prompt'; // 'prompt' | 'enhancer'
    const fbDefaultFallback = 'C:/';
    const fbAppDir = '<?php echo str_replace('\\', '/', dirname(__FILE__)); ?>';
    
    // ── Client-side mode state (File System Access API for remote hosts) ──
    let fbClientMode = false;
    let fbClientHandles = new Map();    // current view's subfolder name → FileSystemDirectoryHandle
    let fbClientNavStack = [];          // [{handle, name}] for "Go Up" navigation
    let fbCurrentHandle = null;         // FileSystemDirectoryHandle of directory being viewed
    const fbSkipDirs = new Set(['.git', 'node_modules', 'vendor', '__pycache__', '.next', '.nuxt', 'dist', 'build', '.svn', '.idea', '.vscode', '.cache', '.output']);
    
    // ── Detect localhost vs remote host ──
    function fbIsLocalhost() {
        const h = window.location.hostname;
        return h === 'localhost' || h === '127.0.0.1' || h === '::1' || h.endsWith('.local') || h.endsWith('.test');
    }

    // ── Resolve start path (PHP mode only) ──
    async function fbResolveStartPath() {
        const lastPath = localStorage.getItem('fbLastBrowsedPath');
        if (lastPath) {
            console.log('📁 Folder browser: using saved path →', lastPath);
            return lastPath;
        }
        
        const promptFolderName = localStorage.getItem('promptFolderName');
        if (promptFolderName) {
            try {
                const formData = new FormData();
                formData.append('action', 'resolve_folder_path');
                formData.append('folder_name', promptFolderName);
                
                const response = await fetch('', { method: 'POST', body: formData });
                const data = await response.json();
                
                if (data.success && data.path) {
                    localStorage.setItem('fbLastBrowsedPath', data.path);
                    console.log('📁 Folder browser: resolved prompt folder →', data.path);
                    return data.path;
                }
            } catch (err) {
                console.log('📁 Could not resolve prompt folder name:', err.message);
            }
        }
        
        console.log('📁 Folder browser: using default fallback → C:/');
        return fbDefaultFallback;
    }

    // ════════════════════════════════════════════════════════════════
    // OPEN / CLOSE
    // ════════════════════════════════════════════════════════════════

    // Open folder browser (Prompt Editor — left panel)
    window.openFolderBrowser = async function() {
        fbMode = 'prompt';
        fbSelectedFolders = new Map();
        fbUpdateSelectedCount();
        
        if (fbIsLocalhost()) {
            // PHP mode — browse server filesystem
            fbClientMode = false;
            const overlay = document.getElementById('folderBrowserOverlay');
            overlay.classList.add('active');
            const startPath = await fbResolveStartPath();
            fbNavigate(startPath);
        } else {
            // Client mode — use File System Access API to browse user's PC
            fbClientMode = true;
            try {
                const handle = await window.showDirectoryPicker({ mode: 'read' });
                fbCurrentHandle = handle;
                fbClientNavStack = [];
                fbClientHandles = new Map();
                
                const overlay = document.getElementById('folderBrowserOverlay');
                overlay.classList.add('active');
                await fbNavigateClient(handle, handle.name);
            } catch (err) {
                if (err.name !== 'AbortError') {
                    console.error('Folder picker error:', err);
                    showToast('Could not open folder picker: ' + err.message, 'error');
                }
            }
        }
    };
    console.log('✅ openFolderBrowser registered on window');

    // Open folder browser (Design Enhancer — right panel)
    window.openDeFolderBrowser = async function() {
        fbMode = 'enhancer';
        fbSelectedFolders = new Map();
        fbUpdateSelectedCount();
        
        if (fbIsLocalhost()) {
            fbClientMode = false;
            const overlay = document.getElementById('folderBrowserOverlay');
            overlay.classList.add('active');
            const startPath = await fbResolveStartPath();
            fbNavigate(startPath);
        } else {
            fbClientMode = true;
            try {
                const handle = await window.showDirectoryPicker({ mode: 'read' });
                fbCurrentHandle = handle;
                fbClientNavStack = [];
                fbClientHandles = new Map();
                
                const overlay = document.getElementById('folderBrowserOverlay');
                overlay.classList.add('active');
                await fbNavigateClient(handle, handle.name);
            } catch (err) {
                if (err.name !== 'AbortError') {
                    console.error('Folder picker error:', err);
                    showToast('Could not open folder picker: ' + err.message, 'error');
                }
            }
        }
    };

    // Close the folder browser modal
    window.closeFolderBrowser = function() {
        const overlay = document.getElementById('folderBrowserOverlay');
        overlay.classList.remove('active');
        fbSelectedFolders = new Map();
        fbClientHandles = new Map();
        fbClientNavStack = [];
        fbCurrentHandle = null;
        fbClientMode = false;
        fbMode = 'prompt';
        fbUpdateSelectedCount();
        // Restore path input for next open
        const pathInput = document.getElementById('fbPathInput');
        if (pathInput) { pathInput.readOnly = false; pathInput.title = ''; }
    };

    // ════════════════════════════════════════════════════════════════
    // PHP MODE — Navigate server filesystem (localhost)
    // ════════════════════════════════════════════════════════════════

    window.fbNavigate = async function(path) {
        if (fbClientMode) return; // ignore in client mode
        if (!path) return;
        
        const listContainer = document.getElementById('fbFolderList');
        const pathInput = document.getElementById('fbPathInput');
        
        listContainer.innerHTML = '<div class="fb-loading"><i class="fas fa-spinner fa-spin"></i> Loading folders...</div>';
        
        try {
            const formData = new FormData();
            formData.append('action', 'list_folders');
            formData.append('path', path);
            
            const response = await fetch('', {
                method: 'POST',
                body: formData
            });
            
            const data = await response.json();
            
            if (data.success) {
                fbCurrentPath = data.currentPath;
                fbParentPath = data.parentPath;
                pathInput.value = data.currentPath;
                
                localStorage.setItem('fbLastBrowsedPath', data.currentPath);
                
                fbRenderFolders(data.folders);
            } else {
                listContainer.innerHTML = '<div class="fb-empty"><i class="fas fa-exclamation-triangle"></i><p>' + (data.message || 'Cannot access this directory') + '</p></div>';
            }
        } catch (err) {
            listContainer.innerHTML = '<div class="fb-empty"><i class="fas fa-exclamation-triangle"></i><p>Error loading folders</p></div>';
            console.error('Folder browser error:', err);
        }
    };

    // ════════════════════════════════════════════════════════════════
    // CLIENT MODE — Navigate via File System Access API (remote host)
    // ════════════════════════════════════════════════════════════════

    async function fbNavigateClient(dirHandle, pathLabel) {
        const listContainer = document.getElementById('fbFolderList');
        const pathInput = document.getElementById('fbPathInput');
        
        listContainer.innerHTML = '<div class="fb-loading"><i class="fas fa-spinner fa-spin"></i> Reading folder...</div>';
        pathInput.value = pathLabel || dirHandle.name;
        pathInput.readOnly = true;
        pathInput.title = 'Client-side mode — navigate using folder entries';
        fbCurrentHandle = dirHandle;
        fbClientHandles = new Map();
        
        try {
            const subdirs = [];
            const fileEntries = [];
            for await (const entry of dirHandle.values()) {
                if (entry.name.startsWith('.') || fbSkipDirs.has(entry.name)) continue;
                if (entry.kind === 'directory') {
                    subdirs.push(entry);
                    fbClientHandles.set(entry.name, entry);
                } else if (entry.kind === 'file') {
                    fileEntries.push(entry);
                }
            }
            
            subdirs.sort((a, b) => a.name.localeCompare(b.name, undefined, { sensitivity: 'base' }));
            fileEntries.sort((a, b) => a.name.localeCompare(b.name, undefined, { sensitivity: 'base' }));
            
            const folders = subdirs.map(entry => ({
                name: entry.name,
                path: '',
                hasSubdirs: true,
                itemType: 'folder'
            }));
            
            const files = fileEntries.map(entry => ({
                name: entry.name,
                path: '',
                hasSubdirs: false,
                itemType: 'file'
            }));
            
            // Pass both folders and files — folders first, then files
            fbRenderClientItems(folders, files);
        } catch (err) {
            listContainer.innerHTML = '<div class="fb-empty"><i class="fas fa-exclamation-triangle"></i><p>Cannot read directory. Permission may have been revoked.</p></div>';
            console.error('Client folder read error:', err);
        }
    }

    // Enter a subfolder (client mode) — called from render onclick
    window.fbEnterFolder = function(folderName) {
        const handle = fbClientHandles.get(folderName);
        if (!handle) return;
        
        // Push current directory onto nav stack
        fbClientNavStack.push({ handle: fbCurrentHandle, name: fbCurrentHandle.name });
        
        // Build path label from stack
        const pathLabel = fbClientNavStack.map(p => p.name).join(' / ') + ' / ' + folderName;
        fbNavigateClient(handle, pathLabel);
    };

    // ════════════════════════════════════════════════════════════════
    // SHARED — Go Up, Render, Select, Add
    // ════════════════════════════════════════════════════════════════

    // Go up one directory
    window.fbGoUp = function() {
        if (fbClientMode) {
            if (fbClientNavStack.length > 0) {
                const parent = fbClientNavStack.pop();
                const pathLabel = fbClientNavStack.length > 0
                    ? fbClientNavStack.map(p => p.name).join(' / ') + ' / ' + parent.name
                    : parent.name;
                fbNavigateClient(parent.handle, pathLabel);
            }
        } else {
            if (fbParentPath && fbParentPath !== fbCurrentPath) {
                fbNavigate(fbParentPath);
            }
        }
    };

    // Render folder list (PHP mode only — unchanged)
    function fbRenderFolders(folders) {
        const listContainer = document.getElementById('fbFolderList');
        
        if (folders.length === 0) {
            listContainer.innerHTML = '<div class="fb-empty"><i class="fas fa-folder-open"></i><p>No subfolders found</p></div>';
            return;
        }
        
        let html = '';
        for (const folder of folders) {
            const isSelected = fbSelectedFolders.has(folder.name);
            const escapedName = folder.name.replace(/'/g, "\\'").replace(/"/g, '&quot;');
            const escapedPath = (folder.path || '').replace(/'/g, "\\'").replace(/"/g, '&quot;');
            
            let enterBtn = '';
            if (folder.hasSubdirs) {
                enterBtn = `<button class="fb-folder-enter" onclick="event.stopPropagation(); fbNavigate('${escapedPath}')" title="Open folder"><i class="fas fa-arrow-right"></i></button>`;
            }
            
            html += `
            <div class="fb-folder-item ${isSelected ? 'selected' : ''}" data-name="${folder.name}" data-path="${escapedPath}" onclick="fbToggleFolder('${escapedName}', '${escapedPath}', this)">
                <div class="fb-folder-checkbox"><i class="fas fa-check"></i></div>
                <i class="fas fa-folder fb-folder-icon"></i>
                <span class="fb-folder-name">${folder.name}</span>
                ${enterBtn}
            </div>`;
        }
        
        listContainer.innerHTML = html;
    }

    // Render client-mode items: selectable folders + display-only files
    function fbRenderClientItems(folders, files) {
        const listContainer = document.getElementById('fbFolderList');
        
        if (folders.length === 0 && files.length === 0) {
            listContainer.innerHTML = '<div class="fb-empty"><i class="fas fa-folder-open"></i><p>Empty folder</p></div>';
            return;
        }
        
        let html = '';
        
        // Folders section — selectable, with enter arrow
        if (folders.length > 0) {
            html += `<div class="fb-section-label" style="padding:6px 12px;font-size:11px;color:var(--text-muted,#888);text-transform:uppercase;letter-spacing:1px;border-bottom:1px solid rgba(255,255,255,0.06);display:flex;align-items:center;gap:6px;"><i class="fas fa-folder" style="color:#fbbf24;"></i> Folders (${folders.length})</div>`;
            for (const folder of folders) {
                const isSelected = fbSelectedFolders.has(folder.name);
                const escapedName = folder.name.replace(/'/g, "\\'").replace(/"/g, '&quot;');
                
                html += `
                <div class="fb-folder-item ${isSelected ? 'selected' : ''}" data-name="${folder.name}" data-path="" onclick="fbToggleFolder('${escapedName}', '', this)">
                    <div class="fb-folder-checkbox"><i class="fas fa-check"></i></div>
                    <i class="fas fa-folder fb-folder-icon"></i>
                    <span class="fb-folder-name">${folder.name}</span>
                    <button class="fb-folder-enter" onclick="event.stopPropagation(); fbEnterFolder('${escapedName}')" title="Browse inside"><i class="fas fa-arrow-right"></i></button>
                </div>`;
            }
        }
        
        // Files section — display only, not selectable
        if (files.length > 0) {
            html += `<div class="fb-section-label" style="padding:6px 12px;font-size:11px;color:var(--text-muted,#888);text-transform:uppercase;letter-spacing:1px;border-bottom:1px solid rgba(255,255,255,0.06);margin-top:4px;display:flex;align-items:center;gap:6px;"><i class="fas fa-file" style="color:#60a5fa;"></i> Files (${files.length})</div>`;
            for (const file of files) {
                const icon = fbGetFileIcon(file.name);
                html += `
                <div class="fb-folder-item fb-file-item" style="opacity:0.7;cursor:default;pointer-events:none;">
                    <div class="fb-folder-checkbox" style="visibility:hidden;"><i class="fas fa-check"></i></div>
                    <i class="${icon.cls}" style="color:${icon.color};font-size:14px;width:20px;text-align:center;"></i>
                    <span class="fb-folder-name" style="color:var(--text-muted,#aaa);">${file.name}</span>
                </div>`;
            }
        }
        
        listContainer.innerHTML = html;
    }

    // Get file icon based on extension
    function fbGetFileIcon(filename) {
        const ext = filename.split('.').pop().toLowerCase();
        const map = {
            html: { cls: 'fab fa-html5', color: '#e44d26' },
            htm:  { cls: 'fab fa-html5', color: '#e44d26' },
            css:  { cls: 'fab fa-css3-alt', color: '#264de4' },
            js:   { cls: 'fab fa-js-square', color: '#f7df1e' },
            ts:   { cls: 'fab fa-js-square', color: '#3178c6' },
            jsx:  { cls: 'fab fa-react', color: '#61dafb' },
            tsx:  { cls: 'fab fa-react', color: '#61dafb' },
            vue:  { cls: 'fab fa-vuejs', color: '#42b883' },
            php:  { cls: 'fab fa-php', color: '#777bb3' },
            py:   { cls: 'fab fa-python', color: '#3776ab' },
            json: { cls: 'fas fa-cog', color: '#fbbf24' },
            xml:  { cls: 'fas fa-code', color: '#f97316' },
            md:   { cls: 'fab fa-markdown', color: '#ffffff' },
            txt:  { cls: 'fas fa-file-alt', color: '#9ca3af' },
            svg:  { cls: 'fas fa-bezier-curve', color: '#ff6b9d' },
            png:  { cls: 'fas fa-image', color: '#10b981' },
            jpg:  { cls: 'fas fa-image', color: '#10b981' },
            jpeg: { cls: 'fas fa-image', color: '#10b981' },
            gif:  { cls: 'fas fa-image', color: '#10b981' },
            webp: { cls: 'fas fa-image', color: '#10b981' },
            ico:  { cls: 'fas fa-image', color: '#10b981' },
            pdf:  { cls: 'fas fa-file-pdf', color: '#ef4444' },
            zip:  { cls: 'fas fa-file-archive', color: '#a855f7' },
            env:  { cls: 'fas fa-key', color: '#fbbf24' },
            sql:  { cls: 'fas fa-database', color: '#06b6d4' },
            sh:   { cls: 'fas fa-terminal', color: '#22c55e' },
            yml:  { cls: 'fas fa-cog', color: '#f97316' },
            yaml: { cls: 'fas fa-cog', color: '#f97316' },
        };
        return map[ext] || { cls: 'fas fa-file', color: '#6b7280' };
    }

    // Toggle folder selection
    window.fbToggleFolder = function(folderName, folderPath, element) {
        if (fbSelectedFolders.has(folderName)) {
            fbSelectedFolders.delete(folderName);
            element.classList.remove('selected');
        } else {
            fbSelectedFolders.set(folderName, folderPath);
            element.classList.add('selected');
        }
        fbUpdateSelectedCount();
    };

    // Select all visible folders
    window.fbSelectAll = function() {
        document.querySelectorAll('.fb-folder-item').forEach(item => {
            const name = item.dataset.name;
            const path = item.dataset.path || '';
            fbSelectedFolders.set(name, path);
            item.classList.add('selected');
        });
        fbUpdateSelectedCount();
    };

    // Deselect all
    window.fbDeselectAll = function() {
        fbSelectedFolders.clear();
        document.querySelectorAll('.fb-folder-item').forEach(item => {
            item.classList.remove('selected');
        });
        fbUpdateSelectedCount();
    };

    // Update selected count display
    function fbUpdateSelectedCount() {
        const count = fbSelectedFolders.size;
        const countEl = document.getElementById('fbSelectedCount');
        const addCountEl = document.getElementById('fbAddCount');
        const addBtn = document.getElementById('fbAddBtn');
        if (countEl) countEl.textContent = count + ' selected';
        if (addCountEl) addCountEl.textContent = count;
        if (addBtn) addBtn.disabled = count === 0;
    }

    // ════════════════════════════════════════════════════════════════
    // ADD SELECTED — routes to Prompt Editor or Design Enhancer
    // ════════════════════════════════════════════════════════════════

    window.fbAddSelected = async function() {
        if (fbSelectedFolders.size === 0) return;
        
        if (fbClientMode) {
            // ── Client mode: build trees from FileSystemDirectoryHandles ──
            await fbAddSelectedClient();
        } else {
            // ── PHP mode: use server paths ──
            const folderInfos = [];
            fbSelectedFolders.forEach((path, name) => {
                folderInfos.push({ name, path });
            });
            
            if (fbMode === 'enhancer') {
                await fbSendToDesignEnhancerPHP(folderInfos);
            } else {
                if (typeof handleFolders === 'function') {
                    handleFolders(folderInfos);
                }
            }
        }
        
        closeFolderBrowser();
    };

    // ── Client mode: add selected folders ──
    async function fbAddSelectedClient() {
        const selectedNames = Array.from(fbSelectedFolders.keys());
        
        if (fbMode === 'enhancer') {
            // Design Enhancer: build tree for each, convert to uf format
            await fbSendToDesignEnhancerClient(selectedNames);
        } else {
            // Prompt Editor: build ONE unified tree from all selected folders
            // Root = current directory name, children = selected folders with full recursive trees
            const rootName = fbCurrentHandle ? fbCurrentHandle.name : 'Project';
            const unifiedTree = [];
            
            for (const name of selectedNames) {
                const handle = fbClientHandles.get(name);
                if (handle) {
                    try {
                        const children = await window.buildClientSideTree(handle);
                        unifiedTree.push({
                            name: name,
                            type: 'folder',
                            children: children
                        });
                    } catch (err) {
                        console.warn('Could not build tree for', name, err.message);
                        unifiedTree.push({ name: name, type: 'folder', children: [] });
                    }
                } else {
                    unifiedTree.push({ name: name, type: 'folder', children: [] });
                }
            }
            
            // Also read files from the current directory and append sorted after folders
            if (fbCurrentHandle) {
                try {
                    const rootFiles = [];
                    for await (const entry of fbCurrentHandle.values()) {
                        if (entry.kind === 'file' && !entry.name.startsWith('.')) {
                            rootFiles.push({ name: entry.name, type: 'file' });
                        }
                    }
                    rootFiles.sort((a, b) => a.name.localeCompare(b.name, undefined, { sensitivity: 'base' }));
                    unifiedTree.push(...rootFiles);
                } catch (e) { /* ignore */ }
            }
            
            // Cache as ONE unified entry
            window.clientTreeCache.set(rootName, unifiedTree);
            if (fbCurrentHandle) {
                window.clientHandleCache.set(rootName, fbCurrentHandle);
            }
            
            // Send as ONE folder to handleFolders → creates ONE card in the editor
            if (typeof handleFolders === 'function') {
                handleFolders([{ name: rootName, path: '' }]);
            }
        }
    }

    // ════════════════════════════════════════════════════════════════
    // DESIGN ENHANCER — Send folder trees
    // ════════════════════════════════════════════════════════════════

    // PHP mode: fetch trees from server
    async function fbSendToDesignEnhancerPHP(folderInfos) {
        const folders = [];
        
        for (const info of folderInfos) {
            try {
                const formData = new FormData();
                formData.append('action', 'get_folder_tree');
                formData.append('path', info.path);
                formData.append('max_depth', '0');
                
                const response = await fetch('', {
                    method: 'POST',
                    body: formData
                });
                const data = await response.json();
                
                if (data.success && data.tree) {
                    const converted = fbConvertTreeToUfFormat(info.name, data.tree);
                    converted._serverPath = info.path;
                    folders.push(converted);
                } else {
                    folders.push({ name: info.name, type: 'folder', children: [], fileCount: 0, folderCount: 0, _serverPath: info.path });
                }
            } catch (err) {
                console.error('Error fetching tree for', info.name, err);
                folders.push({ name: info.name, type: 'folder', children: [], fileCount: 0, folderCount: 0, _serverPath: info.path });
            }
        }
        
        fbSendToDesignEnhancerUI(folders);
    }

    // Client mode: build trees from FileSystemDirectoryHandles
    async function fbSendToDesignEnhancerClient(selectedNames) {
        const folders = [];
        
        for (const name of selectedNames) {
            const handle = fbClientHandles.get(name);
            if (handle) {
                try {
                    const treeData = await window.buildClientSideTree(handle);
                    const converted = fbConvertClientTreeToUfFormat(name, treeData);
                    folders.push(converted);
                } catch (err) {
                    console.error('Error building tree for', name, err);
                    folders.push({ name, type: 'folder', children: [], fileCount: 0, folderCount: 0 });
                }
            } else {
                folders.push({ name, type: 'folder', children: [], fileCount: 0, folderCount: 0 });
            }
        }
        
        fbSendToDesignEnhancerUI(folders);
    }

    // Shared: push folders to Design Enhancer UI
    function fbSendToDesignEnhancerUI(folders) {
        if (folders.length > 0 && typeof ufHandleFoldersStructure === 'function') {
            ufHandleFoldersStructure(folders);
            
            const rootSelectedDiv = document.getElementById('ufRootSelected');
            const rootDropDiv = document.getElementById('ufRootDrop');
            const rootNameSpan = document.getElementById('ufRootName');
            
            if (rootSelectedDiv && rootDropDiv && rootNameSpan) {
                const folderNames = folders.map(f => f.name).join(', ');
                const totalFiles = folders.reduce((sum, f) => sum + (f.fileCount || 0), 0);
                rootDropDiv.style.display = 'none';
                rootSelectedDiv.style.display = 'flex';
                rootNameSpan.textContent = `${folders.length} folder(s): ${folderNames} (${totalFiles} files)`;
            }
        }
    }

    // ════════════════════════════════════════════════════════════════
    // TREE FORMAT CONVERTERS
    // ════════════════════════════════════════════════════════════════

    // Convert PHP tree format → uf format (recursive)
    function fbConvertTreeToUfFormat(name, tree) {
        let fileCount = 0;
        let folderCount = 0;
        
        function convertChildren(items) {
            const children = [];
            for (const item of items) {
                if (item.type === 'folder') {
                    folderCount++;
                    const subChildren = item.children ? convertChildren(item.children) : [];
                    children.push({
                        name: item.name,
                        type: 'folder',
                        children: subChildren,
                        fileCount: subChildren.filter(c => c.type === 'file').length,
                        folderCount: subChildren.filter(c => c.type === 'folder').length
                    });
                } else {
                    fileCount++;
                    children.push({
                        name: item.name,
                        type: 'file',
                        size: 0,
                        path: name + '/' + item.name
                    });
                }
            }
            return children;
        }
        
        const children = convertChildren(tree);
        
        return {
            name: name,
            type: 'folder',
            children: children,
            fileCount: fileCount,
            folderCount: folderCount
        };
    }

    // Convert client-side tree (from buildClientSideTree) → uf format
    function fbConvertClientTreeToUfFormat(name, tree) {
        let fileCount = 0;
        let folderCount = 0;
        
        function convertChildren(items, parentPath) {
            const children = [];
            for (const item of items) {
                if (item.type === 'folder') {
                    folderCount++;
                    const subChildren = item.children ? convertChildren(item.children, parentPath + '/' + item.name) : [];
                    children.push({
                        name: item.name,
                        type: 'folder',
                        children: subChildren,
                        fileCount: subChildren.filter(c => c.type === 'file').length,
                        folderCount: subChildren.filter(c => c.type === 'folder').length
                    });
                } else {
                    fileCount++;
                    children.push({
                        name: item.name,
                        type: 'file',
                        size: 0,
                        path: parentPath + '/' + item.name
                    });
                }
            }
            return children;
        }
        
        const children = convertChildren(tree, name);
        
        return {
            name: name,
            type: 'folder',
            children: children,
            fileCount: fileCount,
            folderCount: folderCount
        };
    }

    // ════════════════════════════════════════════════════════════════
    // EVENT LISTENERS
    // ════════════════════════════════════════════════════════════════

    // Close on overlay click
    document.getElementById('folderBrowserOverlay').addEventListener('click', function(e) {
        if (e.target === this) {
            closeFolderBrowser();
        }
    });

    // Close on Escape key
    document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape' && document.getElementById('folderBrowserOverlay').classList.contains('active')) {
            closeFolderBrowser();
        }
    });
})();
</script>

<script>
// ═══════════════════════════════════════════════════════════════
// TABLE DESIGNER TEMPLATE (TDT)
// ═══════════════════════════════════════════════════════════════

let tdtActive = false;
let tdtSavedTables = []; // [{id, name, engine, charset, collation, comment, columns:[...]}]
let tdtEditingId = null;
let tdtColumns = [];    // current form columns
let tdtColIdCounter = 0;
const TDT_MARKER_START = '<!-- TDT:TABLE_DESIGNER -->';
const TDT_MARKER_END = '<!-- /TDT:TABLE_DESIGNER -->';
const TDT_STORAGE_KEY = 'tdt_saved_tables';
const TDT_ACTIVE_KEY = 'tdt_active';

// ── SQL Data Types with smart hints ──
const TDT_DATA_TYPES = [
    { value: 'INT', hint: 'Whole numbers', category: 'Numeric' },
    { value: 'BIGINT', hint: 'Large integers', category: 'Numeric' },
    { value: 'SMALLINT', hint: 'Small integers', category: 'Numeric' },
    { value: 'TINYINT', hint: 'Tiny integers / boolean', category: 'Numeric' },
    { value: 'MEDIUMINT', hint: 'Medium integers', category: 'Numeric' },
