        }
        
        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(20px); }
            to { opacity: 1; transform: translateY(0); }
        }
        
        .title {
            font-size: 1.5rem;
            color: #1e293b;
            margin-bottom: 20px;
            font-weight: 700;
        }
        
        .question {
            font-size: 1.25rem;
            line-height: 1.8;
            color: #334155;
            margin-bottom: 24px;
        }
        
        .hint {
            padding: 16px 20px;
            background: linear-gradient(135deg, #f0f9ff, #e0f2fe);
            border-radius: 12px;
            color: #0369a1;
