- Performance considerations if applicable
- Accessibility and cross-browser/cross-platform notes
- Complete code examples with detailed comments

### ⚠️ TOKEN LIMIT HANDLING:
**If the content exceeds the session token limit:**
- Divide the response into clearly numbered parts (Part 1/3, Part 2/3, etc.)
- End each part with "Continue to Part X for [next topic]..."
- Ensure each part is self-contained but flows logically to the next
- Prioritize completing the Quick Overview in Part 1 before starting the In-Depth Guide

**Make this tutorial the most comprehensive resource on this topic!**`;

// ── Build content with filename & phrase ──
function stgBuildContent(filename, phrase) {
    return STG_PROMPT_TEMPLATE
        .replace(/\{\{FILENAME\}\}/g, filename)
        .replace(/\{\{PHRASE\}\}/g, phrase || '');
}

// ── Image file handling (names only, no upload) ──
function stgHandleImageFiles(fileList) {
    Array.from(fileList).forEach(f => {
        if (f.type.startsWith('image/') && !stgImageNames.includes(f.name)) {
            stgImageNames.push(f.name);
        }
    });
    stgRenderImageList();
}

function stgRenderImageList() {
    const list = document.getElementById('stgImageList');
    if (!stgImageNames.length) { list.innerHTML = ''; return; }
    let html = '';
    stgImageNames.forEach((name, i) => {
        html += `<div class="stg-image-item">
            <i class="fas fa-image"></i>
            <span class="stg-image-item-name" title="${name}">${name}</span>
            <button class="stg-image-item-remove" onclick="event.stopPropagation(); stgRemoveImage(${i})" title="Remove">
                <i class="fas fa-times"></i>
            </button>
        </div>`;
    });
    html += `<div class="stg-image-count">
        <i class="fas fa-images"></i> ${stgImageNames.length} image${stgImageNames.length > 1 ? 's' : ''} selected
        <button class="stg-clear-images" onclick="event.stopPropagation(); stgClearImages()">Clear all</button>
    </div>`;
    list.innerHTML = html;
}

function stgRemoveImage(index) {
    stgImageNames.splice(index, 1);
    stgRenderImageList();
}

function stgClearImages() {
    stgImageNames = [];
    stgRenderImageList();
}

// ── Open modal ──
function stgOpenModal() {
    const overlay = document.getElementById('stgModalOverlay');
    const input   = document.getElementById('stgFilenameInput');
    input.value = '';
    const phraseEl = document.getElementById('stgPhraseInput');
    if (phraseEl) phraseEl.value = '';
    stgImageNames = [];
    stgRenderImageList();
    overlay.classList.add('active');
    setTimeout(() => input.focus(), 150);
}

// ── Close modal ──
function stgCloseModal() {
    document.getElementById('stgModalOverlay').classList.remove('active');
}

// ── Confirm & push ──
function stgConfirmPush() {
    const raw = document.getElementById('stgFilenameInput').value.trim();
    if (!raw) {
        showToast('Please enter a filename', 'error');
        document.getElementById('stgFilenameInput').focus();
        return;
    }
    const filename = raw.replace(/\.html$/i, '');
    const phraseEl = document.getElementById('stgPhraseInput');
    const phrase = phraseEl ? phraseEl.value.trim() : '';
    let content = stgBuildContent(filename, phrase);

    // Append image filenames if any were selected
    if (stgImageNames.length > 0) {
        content += '\n\n## 📷 ATTACHED IMAGE FILES:\n\n';
        stgImageNames.forEach((name, i) => {
            content += `${i + 1}. \`${name}\`\n`;
        });
        content += '\n> **Note:** These image files are already available in the project root directory. Reference them by filename in the tutorial.';
    }

    const block = '\n\n' + STG_MARKER_START + '\n' + content + '\n' + STG_MARKER_END;

    const editor = document.getElementById('promptEditor');
    // Remove existing block first
    stgRemoveFromEditor();
    editor.value = editor.value.replace(/\n+$/, '') + block + '\n';

    stgActive = true;
    document.getElementById('stgContainer').classList.add('checked');
    document.getElementById('stgCheckbox').checked = true;
    updatePromptCounter();
    stgCloseModal();
    showToast('Image Course prompt pushed!', 'success');
    if (typeof saveEditorContent === 'function') saveEditorContent();
}

// ── Toggle directly (checkbox) ──
function stgToggleDirect() {
    if (stgActive) {
        stgRemoveFromEditor();
        stgActive = false;
        document.getElementById('stgContainer').classList.remove('checked');
        document.getElementById('stgCheckbox').checked = false;
        updatePromptCounter();
        showToast('Image Course removed from editor', 'info');
        if (typeof saveEditorContent === 'function') saveEditorContent();
    } else {
        stgOpenModal();
    }
}

// ── Remove from editor ──
function stgRemoveFromEditor() {
    const editor   = document.getElementById('promptEditor');
    const startIdx = editor.value.indexOf(STG_MARKER_START);
    const endIdx   = editor.value.indexOf(STG_MARKER_END);
    if (startIdx !== -1 && endIdx !== -1) {
        const before = editor.value.substring(0, startIdx).replace(/\n+$/, '');
        const after  = editor.value.substring(endIdx + STG_MARKER_END.length).replace(/^\n+/, '');
        editor.value = before + (after ? '\n\n' + after : '');
    }
}

// ── Copy prompt ──
function stgCopyPrompt() {
    const text = STG_PROMPT_TEMPLATE
        .replace(/\{\{FILENAME\}\}/g, '(enter-filename)')
        .replace(/\{\{PHRASE\}\}/g, '(enter-phrase-or-code)');
    navigator.clipboard.writeText(text).then(() => {
        showToast('Image Course prompt copied!', 'success');
    });
}

// ── Close modal on Escape ──
document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape') {
        const overlay = document.getElementById('stgModalOverlay');
        if (overlay && overlay.classList.contains('active')) stgCloseModal();
    }
});

// ── Submit on Enter ──
document.addEventListener('DOMContentLoaded', function() {
    const inp = document.getElementById('stgFilenameInput');
    if (inp) inp.addEventListener('keydown', function(e) {
        if (e.key === 'Enter') { e.preventDefault(); stgConfirmPush(); }
    });
});
</script>

